const r={name:"Äpple",icon:"apple",category:"frukt",family:"Rosväxter",familyLatin:"Rosaceae",perennial:!0,lifespan:"50-100+ år",difficulty:"Medel",difficultyWhy:"Kräver årlig beskärning och viss sjukdomskontroll, men ett etablerat äppelträd ger skörd i decennier. De första åren handlar om tålamod - sedan tar trädet över.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:null},days:"Skörd år 3-5",spacing:"3-5 m",spacingNote:"Beroende på grundstam (dvärg-halvstam-stam)",rowSpacing:"4-6 m",depth:"Ympstället 10 cm ovan mark",depthNote:"Kritiskt - planterar du ympstället under jord tar ädelsorten egna rötter och du förlorar dvärgeffekten",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Äppelträd vill ha minst 6 timmars direkt sol. Ju mer sol, desto sötare och mer färgade äpplen. En sydvänd, skyddad plats är drömmen."},temperature:{min:-25,max:35,ideal:"18-25°C",detail:"Behöver vinterkyla (minst 800-1000 kylltimmar under 7°C) för att bryta vila och blomma ordentligt. De flesta svenska sorter tål -25°C i vila, men sena vårfroster är den riktiga fienden."},wind:{level:"Vindkänslig",detail:"Vindskydd är viktigt - stark vind skadar blommor, minskar pollinering och kan ge vindfall av frukt. Plantera gärna i lä av byggnad eller häck."}},watering:{need:"Medel",icon:"water",summary:"Etablerade äppelträd klarar sig ofta på regnvatten, men nyplanterade träd och träd med frukt behöver extra vatten under torra perioder.",phases:[{phase:"Vår (blomning)",need:"Medel",tip:"Vattna vid torka under blomning - vattenstress nu ger blomfall och dålig fruktansättning."},{phase:"Sommar (fruktutveckling)",need:"Medel-Hög",tip:"Juni-droppet (naturligt fall av småfrukter) är normalt. Vattna jämnt under frukttillväxten - ojämn vattning ger sprickor i skalet."},{phase:"Mognad (aug-okt)",need:"Medel",tip:"Minska vattningen något mot mognad. Lite vattenstress nu kan faktiskt ge sötare äpplen med mer smak."},{phase:"Vinter",need:"Ingen",tip:"Trädet vilar. Ingen vattning behövs."}],mistakes:["Glömmer att vattna nyplanterade träd första 2-3 somrarna","Ojämn vattning under fruktutveckling - ger sprickor och korkrost","Vattnar sent på hösten - stimulerar sen tillväxt som inte hinner mogna före frost"],tip:"Mulcha med gräsklipp eller kompost i en ring runt trädet (inte intill stammen!) - det håller fukt, matar jorden och minskar ogräs. Lämna 10 cm fritt runt stammen."},soil:"Äppelträd trivs i djup, väldränerad, lagom näringsrik jord. De klarar de flesta jordtyper utom extrem lera eller ren sand. En nyanlagd planteringsgrop med inblandad kompost ger den bästa starten.",soilTips:["Gräv en grop dubbelt så bred som rotklumpen, men inte djupare","Blanda in kompost i den uppgrävda jorden (max 1/3)","På lerjord: plantera upphöjt så att ympstället hamnar högt","Undvik att lägga gödsel direkt i planteringsgropen - det kan bränna rötterna"],timeline:{1:[{phase:"Beskärning",months:"Mars-april",icon:"scissors"},{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Junifall",months:"Juni",icon:"growth"},{phase:"Fruktmognad",months:"Aug-sept",icon:"harvest"},{phase:"Höstplantering",months:"Okt",icon:"seedling"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}],4:[{phase:"Beskärning",months:"Feb-mars",icon:"scissors"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Junifall",months:"Juni",icon:"growth"},{phase:"Fruktmognad",months:"Aug-okt",icon:"harvest"},{phase:"Höstplantering",months:"Okt-nov",icon:"seedling"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}],6:[{phase:"Beskärning",months:"Feb-mars",icon:"scissors"},{phase:"Blomning",months:"April-maj",icon:"bloom"},{phase:"Junifall",months:"Juni",icon:"growth"},{phase:"Fruktmognad",months:"Juli-okt",icon:"harvest"},{phase:"Höstplantering",months:"Okt-nov",icon:"seedling"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}]},nutritionData:[{month:"Mar",N:2,P:1,K:1},{month:"Apr",N:5,P:3,K:2},{month:"Maj",N:7,P:5,K:3},{month:"Jun",N:8,P:6,K:5,label:"Fruktsättning"},{month:"Jul",N:5,P:5,K:7},{month:"Aug",N:3,P:3,K:8,label:"Mognad"},{month:"Sep",N:1,P:2,K:5}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge kompost eller brunnen naturgödsel runt trädets droppzon. Äppelträd är inte extremt näringskrävande - lagom räcker."},{timing:"Blomning (maj)",tip:"En liten giva kaliumrik gödsel (vedaska fungerar utmärkt) stärker blomning och fruktansättning."},{timing:"Efter junifall",tip:"Ingen extra gödsel behövs. Övergödsling ger frodiga blad men dålig frukt och ökad sjukdomsrisk."},{timing:"Höst",tip:"Mulcha med löv eller kompost. Ingen kvävegödsling efter midsommar - nya skott ska hinna mogna före vintern."}],companions:{good:[{name:"Kaprifol",icon:"flower",why:"Lockar pollinatörer tidigt på våren, precis när äppleträden behöver dem som mest."},{name:"Ringblomma",icon:"flower",why:"Avskräcker bladlöss och lockar nyttoinsekter. Perfekt som underplantering."},{id:"graslok",name:"Gräslök",icon:"herb",why:"Traditionellt planterad runt äppelträd för att motverka skorv. Vetenskapligt belagt? Kanske inte, men det skadar inte!"},{name:"Klöver",icon:"flower",why:"Fixerar kväve, täcker marken och lockar humlor. Perfekt som marktäckare under fruktträd."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Potatis under äppelträd ökar risken för Phytophthora (rotröta) som kan skada trädets rötter."},{name:"Vallmo",icon:"flower",why:"Kan sprida äppelbladvecklare. Undvik nära fruktträd."}]},rotation:{avoid:[{name:"Äpple"},{name:"Päron"},{name:"Plommon"},{name:"Körsbär"}],avoidWhy:'Plantera aldrig ett nytt äppelträd exakt där ett gammalt stått - "trötthetssjuka" (replant disease). Sjukdomsorganismer och näringsbrister i jorden gör att det nya trädet aldrig riktigt trivs. Vänta minst 5 år eller välj en annan plats.',goodBefore:[{name:"Gräsmatta"},{name:"Gröngödsling"}],goodBeforeWhy:"Mark som legat som gräsmatta eller gröngödslats i flera år ger den bästa starten för ett fruktträd.",goodAfter:[{name:"Gröngödsling"},{name:"Baljväxter"}],goodAfterWhy:"Om ett gammalt träd tas bort, gröngödsla marken i minst 3-5 år innan du planterar ett nytt fruktträd på samma plats."},varieties:[{name:"Transparente Blanche",zones:[1,2,3,4,5,6],note:"Sommaräpple. Extremt tidig (mitten aug), genomskinligt gult, sötsyrlig. SLU Grönt kulturarv-sort. Äts direkt - håller bara 1-2 veckor."},{name:"Rescue",zones:[1,2,3,4,5,6],note:'Sommaräpple. Litet, rött "barnäpple". Kanadensisk sort, extremt härdig. Lapplands landskapsäpple. Bra val där andra sorter fryser bort.'},{name:"Discovery",zones:[1,2,3,4],note:"Sent sommaräpple (sept). Rött, syrligt-sött. Friskt träd med lite skorvproblem. Bra nybörjarsort."},{name:"Alice",zones:[1,2,3,4,5],note:"Tidigt höstäpple. Rött, sött, skorvresistent. Svensk sort från Balsgård. Passar ekologisk odling."},{name:"Katja",zones:[1,2,3,4,5],note:"Tidigt höstäpple. Saftigt, aromatiskt. Svensk korsning (James Grieve x Worcester Pearmain) från Balsgård. Mycket odlingsvärd."},{name:"Gravensteiner",zones:[1,2,3],note:"Höstäpple. Mycket aromatisk, saftig. Gammal sort (1600-talet). Triploid - behöver två pollinatörer! Känslig sort, kräver bra läge."},{name:"Oranie",zones:[1,2,3,4,5],note:"Höstäpple. Rött, söt smak. Dalslands landskapsäpple, odlat i Sverige i 200+ år. SLU Grönt kulturarv-sort. Bra pollinatör."},{name:"Aroma",zones:[1,2,3,4],note:"Höstäpple. Stor, grönröd, utmärkt smak. Svensk sort från Alnarp 1947. Skånes landskapsäpple. Lagras till mars."},{name:"Wealthy",zones:[1,2,3,4,5,6],note:"Sent höstäpple. Rött, syrligt. Amerikansk sort som blev nordisk klassiker efter 1940-talets kalla vintrar. Lagras till jul."},{name:"Ingrid Marie",zones:[1,2,3,4],note:"Vinteräpple. Mörkröd, söt, saftig. Dansk klassiker från 1910. Bäst smak i november. Känslig för skorv i fuktiga lägen."},{name:"Cox Orange",zones:[1,2,3],note:'Vinteräpple. Komplex, aromatisk smak med pärontoner - "äpplenas kung". Plockas okt, bäst nov-dec. Kräver bästa läget.'},{name:"Frida",zones:[1,2,3],note:"Vinteräpple. Röd, söt, skorvresistent. Svensk sort från Balsgård (Aroma-korsning). Plockas okt, eftermognar."},{name:"Åkerö",zones:[1,2,3,4],note:"Vinteräpple. Grönt-gult, fast, håller till feb. Klassiskt svenskt lagringsäpple med lång historia. Bäst smak i oktober."},{name:"Antonovka",zones:[1,2,3,4,5,6],note:"Vinteräpple. Stor, grön, syrlig. Rysk kulturarvssort, extremt härdig. Mycket pektin - perfekt till mos, gelé och matlagning."},{name:"Kaniker",zones:[1,2,3,4,5],note:"Höstäpple. Liten, söt, röd. Regionalt namn för Oranie i Småland/Skåne. Lagras till december."}],problems:[{name:"Äppleskorv (Venturia inaequalis)",symptom:"Olivgröna-svarta fläckar på blad och frukt. Frukten spricker och blir korkaktig. Värst i fuktiga somrar.",fix:"Välj skorvresistenta sorter (Alice, Frida, Aroma). Raka ihop och kompostera nedfallna löv på hösten. God luftcirkulation genom beskärning."},{name:"Fruktträdskräfta (Neonectria ditissima)",symptom:"Insjunkna, döda barkfläckar som sprider sig. Infekterade grenar svullnar och barken flagar.",fix:"Skär bort angripna grenar minst 20 cm under skadan. Desinficera verktygen. Undvik att beskära i regnväder."},{name:"Äppelvecklare (Cydia pomonella)",symptom:"Maskhål i äpplena med brunaktig larvgång. Larven äter sig in till kärnhuset.",fix:"Häng feromonfällor i maj-juni. Korrugerad papp runt stammen på hösten fångar övervintrande larver. Plocka upp fallfrukt."},{name:"Bladlöss",symptom:"Ihopkrullade blad, klibbigt honungsdagg. Skottspetsarna deformeras. Ofta tidigt på säsongen.",fix:"Locka nyckelpigor och parasitsteklar genom att ha blommande växter intill. Spola av med vattenslang. I de flesta fall sköter naturen balansen."}],pollination:{selfFertile:!1,description:"De flesta äppelsorter är självsterila - du behöver minst två olika sorter som blommar samtidigt, inom ca 50 meters avstånd. Bin och humlor sköter jobbet, men de måste kunna flyga mellan träden. Triploida sorter (Gravensteiner, Belle de Boskoop) producerar dåligt pollen och behöver TVÅ andra pollinatörer.",groups:[{name:"Grupp 1-2: Tidig blomning",varieties:["Transparente Blanche","Gravensteiner","Åkerö","Alice","Rescue"]},{name:"Grupp 3: Mellanblommande",varieties:["Discovery","Katja","Cox Orange","Oranie","Antonovka","Wealthy"]},{name:"Grupp 4: Medelsen blomning",varieties:["Aroma","Ingrid Marie","Frida"]},{name:"Triploida (behöver 2 pollinatörer)",varieties:["Gravensteiner"]}],tip:"Prydnadsäpple (Malus) är den ultimata pollinatören - de blommar länge och rikligt. Ett enda prydnadsäpple kan pollinera hela kvarteret! Om du bara har plats för ett träd, kolla om grannarna har äppelträd. Annars: ympa en gren av en annan sort direkt på ditt träd."},establishment:{description:"De första åren avgör trädets hela framtid. Ett äppelträd som får rätt start de första 3-5 åren ger decennier av skörd. Slarvar du här märks det i 30 år.",years:[{year:"År 1",tasks:["Vattna 20-30 liter per vecka hela första sommaren - rötterna har inget förråd","Plocka bort ALL frukt som sätts - trädet ska bygga rötter, inte bära frukt","Kontrollera att bindningen till stödpålen sitter lagom löst (inte stryper stammen)","Mulcha med gräsklipp eller kompost i 1 meters radie (inte intill stammen)"]},{year:"År 2",tasks:["Första uppbyggnadsbeskärningen: välj 3-4 huvudgrenar jämnt fördelade runt stammen","Fortsätt vattna vid torka (mindre kritiskt än år 1, men fortfarande viktigt)","Tillåt några frukter men tunna till max 5-10 stycken","Gödsla försiktigt med kompost på våren"]},{year:"År 3-5",tasks:["Årlig vinterbeskärning för att forma kronan (öppet, luftigt, ljust)","Öka antalet tillåtna frukter gradvis - full skörd först år 4-5 (dvärgträd) eller 6-8 (halvstam)","Börja sommarbeskärning: bryt vattenskott, gallra fruktklungor","Trädet blir alltmer självgående - minska vattningen om det inte är extrem torka"]}],protection:["Stamskydd mot gnagare (nät eller spiral runt stammen) - MÅSTE finnas första vintrarna, kaniner och sorkar gnager bark","Viltskydd om rådjur finns i området - de älskar unga fruktträd","Stammskydd mot solbränna (vit latex/kalkmjölk) på sydvästra sidan vintertid","Vindskydd vid utsatta lägen - ett ungt träd behöver lä"],tip:"Det bästa du kan göra för ett nyplanterat äppelträd: vattna, vattna, vattna. Det låter tråkigt, men 90% av alla misslyckanden med nya fruktträd beror på vattenbrist det första året. Sätt en påminnelse i telefonen."},ripeningGuide:{description:"Äpplen mognar från augusti till november beroende på sort. Sommaräpplen äts direkt - de håller bara dagar. Höstäpplen kan lagras veckor till månader. Vinteräpplen förbättras faktiskt efter lagring och håller till våren. Tiderna gäller zon 1-3 (södra Sverige) - räkna 2-4 veckor senare i norr.",entries:[{variety:"Transparente Blanche",from:"aug",to:"aug",type:"Sommaräpple"},{variety:"Rescue",from:"aug",to:"aug",type:"Sommaräpple"},{variety:"Discovery",from:"aug",to:"sep",type:"Sommaräpple"},{variety:"Alice",from:"sep",to:"sep",type:"Höstäpple"},{variety:"Katja",from:"sep",to:"sep",type:"Höstäpple"},{variety:"Gravensteiner",from:"sep",to:"okt",type:"Höstäpple"},{variety:"Oranie",from:"sep",to:"okt",type:"Höstäpple"},{variety:"Aroma",from:"sep",to:"okt",type:"Höstäpple"},{variety:"Wealthy",from:"sep",to:"okt",type:"Höstäpple"},{variety:"Ingrid Marie",from:"sep",to:"okt",type:"Vinteräpple"},{variety:"Cox Orange",from:"okt",to:"okt",type:"Vinteräpple"},{variety:"Frida",from:"okt",to:"okt",type:"Vinteräpple"},{variety:"Åkerö",from:"sep",to:"okt",type:"Vinteräpple"},{variety:"Antonovka",from:"sep",to:"okt",type:"Vinteräpple"}],tip:"Bästa testet: lyft äpplet lätt och vrid - lossnar det enkelt är det moget. Kärnan ska vara mörkbrun. Smaka! Sommaräpplen ska ätas inom dagar, höstäpplen inom veckor, och vinteräpplen läggs direkt i kallförvar och smakar bäst efter 4-8 veckors lagring."},goodToKnow:[{icon:"warning",title:"Ympstället - livsviktigt",text:"Den knöl du ser på stammen nere vid marken är ympstället. Plantera ALDRIG ympstället under marknivå - då tar ädelsorten egna rötter och du förlorar dvärgeffekten. Ympstället ska vara minst 10 cm ovan jord.",severity:"warning"},{icon:"tip",title:"Grundstam bestämmer storleken",text:"M9 ger ett litet träd (2-3 m) som bär frukt redan år 2-3. M26 ger halvstorlek (3-4 m). Frösådd/A2 ger fullstort träd (6-8 m) som lever i 100+ år. Fråga plantskolan vilken grundstam du köper!",severity:"tip"},{icon:"tip",title:"Tunna frukten",text:'I juni faller naturligt en del småfrukter (junifall). Tunna gärna ut ytterligare till 1-2 frukter per fruktklunga. Det känns brutalt, men det ger större, godare äpplen och förhindrar att trädet tar "viloår".',severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Äppelträd planteras som ympade träd. Barrotade träd planteras på hösten (okt-nov) eller tidig vår. Krukodlade kan planteras hela säsongen.",steps:["Gräv en grop dubbelt så bred som rotsystemet men lika djup","Slå ner en stödpåle INNAN du sätter trädet (så du inte skadar rötterna)","Sätt trädet med ympstället 10 cm ovan mark","Fyll igen med uppgrävd jord blandat med kompost","Packa jorden försiktigt runt rötterna - inte för hårt","Vattna rikligt - minst 20-30 liter","Bind stammen löst mot stödpålen med mjuk bindning","Mulcha en cirkel på 1 meters radie runt stammen"],tips:["Höstplantering ger bäst etablering - rötterna växer hela vintern","Barrotade träd är billigare och ofta bättre kvalitet än krukodlade","Tänk på att du behöver minst två sorter för pollinering!"],indoorWeeks:null},seedSaving:{difficulty:"Avancerad",type:"Ympning",biennial:!1,description:"Äppelträd förökas genom ympning - att fästa en kvist (ymp) från önskad sort på en grundstam. Att så kärnor ger inte samma sort tillbaka, utan ett helt nytt träd med okända egenskaper.",steps:["Samla ympkvistar i jan-feb (vilande, ettåriga skott)","Förvara i fuktig tidning i kylskåp till april","Välj grundstam (M9 för dvärg, M26 för halvstam)","Utför kopulationsympning eller ögonympning","Skydda ympstället med ympvax","Vänta 2-3 år på första skörd"],isolation:"Ympning klonar sorten exakt - ingen korspollinering relevant.",storageYears:"Ympkvistar håller 2-3 månader i kylskåp",tip:"Gå en ympkurs! Svenska trädgårdsföreningar och Riksförbundet Svensk Trädgård anordnar kurser varje vår. Det är lättare än du tror och fantastiskt givande att ympa sitt eget träd."},storage:{shelfLife:"1 vecka - 6 månader (beroende på sort)",methods:[{method:"Kallförvar",icon:"cellar",duration:"2-6 månader",description:"Det klassiska sättet. Lagra vinteräpplen (Åkerö, Antonovka) i ett svalt utrymme (2-4°C), hög luftfuktighet. Kontrollera regelbundet och plocka bort rötna äpplen.",best:!0},{method:"Torkning",icon:"sun",duration:"6+ månader",description:"Skiva äpplena tunt och torka i ugn (50°C, 6-8 timmar) eller torkmaskin. Fantastiskt gott som snacks och i müsli.",best:!1},{method:"Mos/juice",icon:"storage",duration:"1+ år",description:"Koka äppelmos utan socker och fyll på steriliserade burkar. Äppeljuice pastöriseras vid 72°C. Perfekt för överskottsskörd!",best:!1},{method:"Frysning",icon:"snowflake",duration:"10-12 månader",description:"Skala, kärna ur och skiva. Frys i påsar med lite citronjuice (mot brunfärgning). Perfekt för pajfyllning.",best:!1}],tips:["Lagra bara felfria äpplen - en rutten smittar snabbt","Sommaräpplen (Transparente Blanche) håller bara 1-2 veckor - ät direkt eller gör mos","Vinteräpplen (Åkerö, Antonovka) förbättras faktiskt i smak efter lagring","Äpplen avger etylen - förvara inte tillsammans med andra frukter"]},harvestCalc:{minPerSqm:2,maxPerSqm:8,unit:"kg per träd (år 5+)"},pruning:{label:"Beskärning",types:{winter:{name:"Vinterbeskärning (uppbyggnad)",when:"Februari-mars, medan trädet vilar",description:'Huvudbeskärningen som formar trädet och ger ljus och luft till frukten. Beskär innan knopparna svällt men efter den värsta kylan. Sitt inte bara och tänk - ta sekaktören och våga! Varje snitt ger två nya skott, så tänk "öppet, luftigt, ljust".',steps:["Ta bort döda, sjuka och korsande grenar först","Ta bort vattenskott (rakt uppåtväxande skott)","Glesa ur kronan så ljus når de inre grenarna","Korta in toppskottet för att begränsa höjden","Klipp snett strax ovanför en utåtriktad knopp","Ta inte bort mer än 1/3 av kronvolymen per år"]},summer:{name:"Sommarbeskärning",when:"Juli-augusti",description:"Kompletterande klipp som lugnar en för frodigt träd. Ta bort vattenskott och skott som skuggar frukten. Sommarbeskärning bromsar tillväxt och gynnar fruktknoppar till nästa år.",steps:["Bryt bort vattenskott som nått 15-20 cm","Ta bort skott som skuggar mognande frukt","Korta in årets sidoskott till 3-4 blad ovanför fruktklasen"]}}},propagation:{difficulty:"Avancerad",methods:[{method:"Ympning",description:"Den vanligaste metoden. En kvist (ymp) från önskad sort fästs på en utvald grundstam. Kopulationsympning på våren eller ögonympning i augusti. Kräver lite övning men är oerhört givande.",icon:"seedling"},{method:"Frösådd (experiment)",description:"Stratifiera äppelkärnor i kylskåp i 8 veckor, så i kruka. Du får ett unikt träd, men det tar 8-15 år till skörd och frukten blir inte samma som föräldrasorten. Spännande experiment!",icon:"seed"}],tip:"Ympkurser arrangeras av lokala trädgårdsföreningar varje vår. Ett perfekt sätt att lära sig tekniken och få tillgång till ympkvistar av kulturarvssorter som inte finns i handeln."}},Vr=Object.freeze(Object.defineProperty({__proto__:null,apple:r},Symbol.toStringTag,{value:"Module"})),a={name:"Aronia",icon:"aronia",category:"bär",family:"Rosväxter",familyLatin:"Rosaceae",perennial:!0,lifespan:"20-30+ år",difficulty:"Enkel",difficultyWhy:"Aronia är en av de mest lättskötta bärbuskarna som finns. Extremt härdig, tål all svensk vinter, angrips sällan av skadedjur och ger pålitlig skörd år efter år. Enda nackdelen? Bären är ganska sträva att äta färska - men processade är de fantastiska.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:null},days:"Skörd år 2-3, full skörd år 4-5",spacing:"100-150 cm",rowSpacing:"250-300 cm",depth:"Något djupare än i krukan",depthNote:"Plantera 3-5 cm djupare än busken stod i krukan - det stimulerar nya basalskott.",ph:{min:5,max:7,ideal:6},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Aronia ger bäst skörd i full sol men klarar halvskugga förvånansvärt bra. I skuggigare lägen blir bären färre men höstfärgen blir nästan ännu mer spektakulär. Minst 4-5 timmar sol per dag för ordentlig bärsättning."},temperature:{min:-35,max:35,ideal:"15-25°C",detail:"En av de härdigaste bärbuskarna - tål ner till -35°C utan vinterskydd. Ursprungligen från Nordamerikas kalla regioner och anpassad till skandinaviskt klimat. Klarar alla svenska odlingszoner utan problem."},wind:{level:"Tålig",detail:"Kompakt, stabil buske som klarar vind bra. Har inga långa rankande skott som kan knäckas. Fungerar faktiskt utmärkt som vindskyddshäck."}},watering:{need:"Låg-Medel",icon:"water",summary:"Aronia är anspråkslös och torktålig när den väl etablerats. Under de första åren behöver hon regelbunden vattning, men en etablerad buske klarar sig med minimal hjälp de flesta svenska somrar.",phases:[{phase:"Etablering (år 1-2)",need:"Medel",tip:"Vattna regelbundet första och andra sommaren. Busken bygger upp sitt rotsystem och behöver jämn fukt för att komma igång ordentligt."},{phase:"Blomning (maj-juni)",need:"Medel",tip:"Jämn fukt under blomningen ger bättre fruktsättning. Aronia är delvis självfertil men pollinatörer hjälper - vattenstress kan minska pollineringsviljan."},{phase:"Bärmognad (juli-aug)",need:"Låg-Medel",tip:"Etablerade buskar klarar sig oftast själva. Vid extrem torka (2+ veckor utan regn) ger en djup vattning större och saftigare bär."},{phase:"Höst/vinter",need:"Låg",tip:"Minska vattningen. Busken klarar sig själv och förbereder sin spektakulära höstfärg."}],mistakes:["Vattnar för mycket - aronia avskyr vattensjuk jord","Glömmer nyplanterade buskar de första somrarna - de behöver hjälp att etablera sig","Övervattnar i tung lerjord utan dränering"],tip:"Mulcha med bark eller gräsklipp runt busken - det håller fukten jämn och minskar ogräs. En etablerad aronia med bra mulch klarar sig nästan helt utan extra vattning."},soil:"Aronia trivs i de flesta jordtyper och är remarkabelt anpassningsbar. Hon föredrar fukthållande, humusrik jord men klarar allt från sandjord till lerjord. Undvik bara extremt vattensjuk mark.",soilTips:["Blanda in kompost vid plantering - aronia uppskattar en näringsrik start","Klarar lerjord bättre än de flesta bärbuskar - bara dräneringen är okej","Sandjord? Blanda in kompost och mulcha rikligt för att hålla fukten","Tolererar ett brett pH-spann (5.0-7.0) - funkar i de flesta svenska trädgårdar utan justering","Mulcha årligen med bark eller gräsklipp"],timeline:{1:[{phase:"Plantering",months:"Okt-nov eller april-maj",icon:"seedling"},{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Skörd",months:"Aug-sept",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (mars)",icon:"scissors"},{phase:"Höstfärg",months:"Sept-okt",icon:"bloom"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],4:[{phase:"Plantering",months:"Okt eller april-maj",icon:"seedling"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Skörd",months:"Aug-sept",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (feb-mars)",icon:"scissors"},{phase:"Höstfärg",months:"Sept-okt",icon:"bloom"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],6:[{phase:"Plantering",months:"Okt-nov eller mars-april",icon:"seedling"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Skörd",months:"Aug",icon:"harvest"},{phase:"Beskärning",months:"Sen vinter (feb-mars)",icon:"scissors"},{phase:"Höstfärg",months:"Okt",icon:"bloom"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:3,P:2,K:2},{month:"Maj",N:4,P:3,K:3},{month:"Jun",N:3,P:4,K:4},{month:"Jul",N:2,P:3,K:5},{month:"Aug",N:2,P:2,K:4},{month:"Sep",N:1,P:1,K:2}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge en giva kompost eller brunnen gödsel runt busken. Aronia är inte speciellt hungrig men uppskattar en vårstart med näring."},{timing:"Blomning (maj)",tip:"En giva kaliumrik gödsel stärker blomning och bärkvalitet. Vedaska fungerar utmärkt och är gratis."},{timing:"Höst",tip:"Lägg ett lager kompost som höstmulch. Det bryts ner under vintern och matar busken lagom till vårstarten."}],companions:{good:[{id:"ringblomma",name:"Ringblomma",icon:"flower",why:"Lockar pollinatörer som förbättrar bärsättningen. Aronia gynnas av korspollinering trots att hon är delvis självfertil."},{name:"Andra aroniasorter",icon:"berry",why:"Korspollinering mellan olika sorter ger betydligt bättre skörd och större bär. Plantera gärna Viking och Hugin tillsammans."},{id:"graslok",name:"Gräslök",icon:"herb",why:"Doften avskräcker bladlöss. Tidig blomning lockar pollinatörer. Fint marktäckande under buskarna."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Risk för delad verticillium-svamp. Håll bra avstånd."}]},rotation:{avoid:[{name:"Aronia"},{name:"Andra Rosaceae (äpple, päron, hallon)"}],avoidWhy:"Rosväxter kan dela svampsjukdomar. Plantera inte ny aronia där gammal stått - vänta minst 4-5 år.",goodBefore:[{name:"Solig, öppen plats"},{name:"Gräsmatta"}],goodBeforeWhy:"En plats som inte odlats med rosväxter nyligen. Gräsmattejord är ofta perfekt - frisk och ogödslad.",goodAfter:[{name:"Gröngödsling"},{name:"Baljväxter"}],goodAfterWhy:"Efter 20+ år med aronia kan jorden behöva förnyelse. Gröngödsling eller baljväxter bygger upp den."},varieties:[{name:"Viking",zones:[1,2,3,4,5],note:"Den vanligaste sorten i Sverige och Norden. Stora bär i rikliga klasar. Upprätt, kraftig buske (1.5-2 m). Pålitlig och lättskörd. Ryskt ursprung (Mitchurin), namngiven i Finland."},{name:"Hugin",zones:[1,2,3,4,5],note:"E-planta! Utvald vid SLU Alnarp från vilt material från Kanada. Kompaktare buske (1-1.5 m), perfekt för mindre trädgårdar. Stora bär och fin höstfärg. Rekommenderas varmt."},{name:"Nero",zones:[1,2,3,4,5],note:"Ryskt ursprung (Mitchurin), spridd via Östeuropa. Extra stora bär. Något lägre buske (1-1.5 m). Hög bärproduktion och mild smak jämfört med Viking. Populär i kommersiell odling."},{name:"Aron",zones:[1,2,3,4,5,6],note:"Populär i dansk odling. Kompakt växtsätt. Stora, fasta bär. Bra val för häck eller begränsade utrymmen. Fin höstfärg."}],problems:[{name:"Fåglar",symptom:"Bären försvinner innan du hinner skörda. Trastar och starar är de vanligaste bovarna.",fix:"Nät är det enda pålitliga skyddet. Sätt upp nät när bären börjar färgas (juli-aug). Aronia ger rikligt - det finns oftast gott om bär till alla om du har flera buskar."},{name:"Mjöldagg",symptom:"Vitt, mjöligt belägg på bladen, främst i slutet av säsongen. Vanligare i fuktiga, varma somrar.",fix:"God luftcirkulation genom gallring. Aronia drabbas lindrigare än många andra Rosaceae. Sällan allvarligt - busken klarar sig bra ändå."},{name:"Bladfläcksjuka",symptom:"Bruna eller mörkröda fläckar på bladen. Kan orsaka tidigt bladfall vid kraftigt angrepp.",fix:"Rensa bort nedfallna löv som kan sprida smitta. God luftcirkulation. Aronia är generellt motståndskraftig - problemet är sällan allvarligt."}],goodToKnow:[{icon:"tip",title:"Antioxidant-bomben",text:"Aroniabär har bland de allra högsta antioxidantnivåerna av alla bär - högre än blåbär, acai och granatäpple. De mörka bären är fullpackade med antocyaniner. Ät dem processade (juice, sylt, torkade) för bäst effekt.",severity:"tip"},{icon:"warning",title:"Sträva färska",text:"Aroniabär smakar intensivt sträva/adstringerande färska - munnen drar ihop sig. Det är helt normalt och beror på de höga tanninerna. Processa dem istället: juice, sylt, torkade eller i smoothies. Smaken förvandlas helt!",severity:"warning"},{icon:"tip",title:"Spektakulär höstfärg",text:"Aronia har en av trädgårdens absolut vackraste höstfärger. Bladen exploderar i eldröda, orange och karmosinröda toner i september-oktober. Plantera henne synligt - hon är minst lika mycket prydnadsbuske som nyttobuske.",severity:"tip"},{icon:"tip",title:"Perfekt häckväxt",text:"Aronia fungerar fantastiskt som friväxande häck. Kompakt växtsätt, vacker blomning på våren, bär på sommaren och eldröd höstfärg. Dessutom extremt härdig och lättskött. Vad mer kan man be om?",severity:"tip"},{icon:"tip",title:"Nästan inga skadedjur",text:"Aronia är ovanligt resistent mot sjukdomar och skadedjur. De sträva bären verkar avskräcka de flesta insekter. Fåglar är det enda riktiga hotet - och det löser du med nät.",severity:"tip"},{icon:"warning",title:"Rotskott kan sprida sig",text:"Aronia bildar rotskott, men inte lika aggressivt som hallon eller havtorn. Håll koll och klipp bort oönskade skott. I en häck är det en fördel - busken fyller ut naturligt.",severity:"warning"}],sowing:{method:"direct",label:"Plantering",description:"Aronia planteras som barrotade buskar (höst eller tidig vår) eller krukodlade plantor. Höstplantering ger bäst etablering. Busken är anspråkslös och ställer inga konstiga krav.",steps:["Gräv en grop dubbelt så bred som rotklumpen och lika djup plus 5 cm","Blanda in kompost i jorden - aronia uppskattar en näringsrik start","Plantera 3-5 cm djupare än busken stod i krukan","Vattna rikligt - riktigt genomblött","Mulcha med bark eller gräsklipp runt busken (inte intill stammen)","Klipp ner till 20-30 cm vid plantering för att stimulera nya basalskott"],tips:["Höstplantering (okt-nov) ger bäst resultat - rötterna etablerar sig i fred","Plantera gärna 2+ sorter för bättre korspollinering och större skörd","Fungerar utmärkt som häck med 80-100 cm avstånd","Första ordentliga skörden kommer år 3, full skörd från år 4-5"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Aronia förökas enkelt med rotskott, sticklingar eller delning. Busken bildar naturligt rotskott som kan grävas upp och planteras om. Frösådd fungerar men ger viss variation.",steps:["Rotskott (enklast): gräv försiktigt upp rotskott med egna rötter på hösten","Plantera om rotskottet direkt på sin nya plats eller i kruka","Vedartade sticklingar: klipp 15-20 cm bitar av årets mogna ved i november","Sätt sticklingarna i fuktig jord utomhus med 2-3 knoppar ovan mark","Delning: gräv upp en etablerad buske och dela med spade. Plantera om delarna direkt."],isolation:"Vegetativ förökning ger exakta kloner av moderplantan.",storageYears:"Ej tillämpligt",tip:"Rotskott är enklast och ger identiska kopior av moderplantan. Gräv upp dem på hösten och ge bort till odlarkompisar - aronia förtjänar att spridas!"},storage:{shelfLife:"2-4 veckor (färska i kylskåp)",methods:[{method:"Frysning",icon:"snowflake",duration:"12+ månader",description:"Bästa och enklaste metoden. Aroniabär fryser utmärkt och behåller alla nyttigheter. Frys direkt i påsar - bären klumpar inte ihop sig lika lätt som andra bär. Perfekt bas för juice och smoothies.",best:!0},{method:"Juice/must",icon:"storage",duration:"6-12 månader (pastöriserad)",description:"Aroniajuice är intensivt mörk och nyttig. Safta med ångsaftare eller koka och sila. Blanda gärna med äpple eller aronia-äpple 50/50 för bättre smak.",best:!1},{method:"Torkning",icon:"sun",duration:"12+ månader",description:"Torkade aroniabär blir söta, russsinlika och förlorar mycket av strävan. Torka i ugn på 50-60°C i 8-12 timmar. Fantastiska i müsli, bakning och som snacks.",best:!1},{method:"Sylt/marmelad",icon:"storage",duration:"1+ år",description:"Aroniasylt med lite citron har en djup, komplex smak. Koka med socker och citronjuice. Blanda gärna med äpple för bättre konsistens och smak.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"2-4 veckor",description:"Aroniabär har förvånansvärt lång hållbarhet färska. Fasta bär med högt tannininnehåll gör att de håller sig bättre än de flesta bär. Förvara torrt och svalt.",best:!1}],tips:["Skörda när bären är helt svarta och mjuka vid tryck - de mognar inte efter plockning","Hela klasar kan klippas av med sax - enklare och snabbare än att plocka bär för bär","Torkade aroniabär liknar russin och är mycket godare än färska","Aronia + äpple är den magiska kombinationen - oavsett om det är juice, sylt eller smoothie","Bären innehåller naturligt konserverande ämnen och håller sig längre än de flesta bär"]},harvestCalc:{minPerSqm:1,maxPerSqm:3,unit:"kg"},pruning:{label:"Beskärning",types:{maintenance:{name:"Underhållsbeskärning",when:"Tidig vår (feb-mars) innan knopparna svällt",description:"Aronia kräver minimal beskärning. Busken sköter sig i stort sett själv, men årlig gallring håller den produktiv och luftig. Aronia bär bäst på 2-5 år gamla grenar - ta bort de äldsta för att ge plats åt nya.",steps:["Ta bort döda, skadade och sjuka grenar","Ta bort grenar som är 5-6+ år gamla vid basen","Gallra svaga, korsande skott i mitten av busken","Spara 8-12 starka grenar i blandade åldrar","Klipp bort oönskade rotskott"]},rejuvenation:{name:"Föryngringsbeskärning",when:"Tidig vår",description:"Gammal, förvuxen aroniabuske? Hon tål hård beskärning utmärkt. Klipp ner till 20-30 cm och busken skjuter nya, friska skott från basen. Skörd igen om 2-3 år.",steps:["Klipp ner hela busken till 20-30 cm ovan mark","Nya skott dyker upp inom veckor","Välj ut 8-10 starka skott och ta bort resten","Gödsla med kompost och vattna ordentligt","Ny skörd från år 2-3"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Rotskott",description:"Enklaste metoden. Aronia bildar naturligt rotskott runt busken. Gräv upp med rötter på hösten och plantera om direkt. Ger identiska kloner av moderplantan.",icon:"seedling"},{method:"Vedartade sticklingar",description:"Klipp 15-20 cm bitar av årets mogna skott i november. Sätt i fuktig jord utomhus. Rotar sig under vintern. Bra lyckandefrekvens.",icon:"scissors"},{method:"Delning",description:"Gräv upp en etablerad buske och dela med spade i 2-3 delar med rötter och skott. Plantera om direkt. Bäst på tidig vår eller sen höst.",icon:"scissors"}],tip:"Rotskott är enklast - aronia producerar dem gärna. Om du inte har en moderplanta att ta från, fungerar vedartade sticklingar i november utmärkt med hög lyckandefrekvens."}},Lr=Object.freeze(Object.defineProperty({__proto__:null,aronia:a},Symbol.toStringTag,{value:"Module"})),e={name:"Ärtor",icon:"artor",family:"Baljväxter",familyLatin:"Fabaceae",difficulty:"Enkel",difficultyWhy:"Direktsås utomhus, fixar sitt eget kväve, och ger skörd redan efter 60 dagar. Perfekt nybörjargröda.",zones:{outdoor:[1,2,3,4,5,6,7],indoor:null,greenhouse:null},days:"60-75",spacing:"5-8 cm",rowSpacing:"30-40 cm",depth:"3-5 cm",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Minst 6 timmar sol per dag. Klarar halvskugga men ger då mindre skörd. I söder kan lite skugga mitt på dagen faktiskt vara bra - ärtor gillar inte extrem hetta."},temperature:{min:5,max:25,ideal:"13-18°C",detail:"Gror redan vid 5°C och trivs i sval, svensk sommar. Över 25°C slutar hon blomma och sätta baljor - hon tycker helt enkelt att det är för varmt."},wind:{level:"Skyddat",detail:"Behöver stöd (nät, pinnar, ärtstöd) redan från 20 cm höjd. Vinden kan knäcka de späda stammarna."}},watering:{need:"Medel",icon:"water",summary:"Ärtor är ganska tåliga mot torka i början, men under blomning och baljesättning är vatten helt avgörande. Torka då = tomma baljor.",phases:[{phase:"Groning (0-2 veckor)",need:"Medel",tip:"Vattna vid sådd och håll fuktig tills plantorna kommit upp. Fröna sväller och behöver fukt för att spricka."},{phase:"Tillväxt (2-6 veckor)",need:"Låg",tip:"Ärtor klarar sig rätt bra på egen hand nu. Vattna bara om det är riktigt torrt - lite stress gör att rötterna söker sig djupare."},{phase:"Blomning (6-8 veckor)",need:"Hög",tip:"Kritisk period! Vattenstress nu ger att blommorna faller av utan att sätta baljor. Vattna ordentligt varannan dag om det inte regnar."},{phase:"Baljesättning (8+ veckor)",need:"Medel-Hög",tip:"Fortsätt vattna regelbundet. Baljorna fylls med vatten och socker - torka nu ger torra, mjöliga ärtor."}],mistakes:["Glömmer vattna under blomning - den absolut viktigaste perioden","Övervattnar i början - kan ge rotröta i kall, blöt jord","Vattnar ovanifrån sent på dagen - fuktiga blad över natten bjuder in mjöldagg"],tip:"Mulcha runt plantorna med gräsklipp eller halm - det håller fukten jämn och jorden sval, precis som ärtor vill ha det."},soil:"De flesta jordtyper funkar - ärtor är inte kräsna. Undvik dock blöt, kompakt lera. Lös, väldränerad jord ger bäst resultat.",soilTips:["Kalka om pH är under 6 - ärtor gillar inte sur jord","Gräv inte ner gödsel - ärtor fixar sitt eget kväve via bakterier på rötterna","Blanda in lite sand om du har tung lerjord"],timeline:{1:[{phase:"Direktså",months:"Mar-Apr",icon:"seedling"},{phase:"Sätt stöd",months:"Apr",icon:"support"},{phase:"Blomning",months:"Maj-Jun",icon:"flower"},{phase:"Skörd",months:"Jun-Jul",icon:"harvest"},{phase:"Andra omgången",months:"Jul-Aug",icon:"seedling"}],4:[{phase:"Direktså",months:"Apr-Maj",icon:"seedling"},{phase:"Sätt stöd",months:"Maj",icon:"support"},{phase:"Blomning",months:"Jun-Jul",icon:"flower"},{phase:"Skörd",months:"Jul-Aug",icon:"harvest"}],6:[{phase:"Direktså",months:"Maj-Jun",icon:"seedling"},{phase:"Sätt stöd",months:"Jun",icon:"support"},{phase:"Blomning",months:"Jul",icon:"flower"},{phase:"Skörd",months:"Aug",icon:"harvest"}]},nutritionData:[{month:"Apr",N:10,P:15,K:10,label:"Groning"},{month:"Maj",N:15,P:25,K:20,label:"Tillväxt"},{month:"Jun",N:20,P:40,K:35,label:"Blomning"},{month:"Jul",N:15,P:50,K:55,label:"Baljesättning"},{month:"Aug",N:10,P:35,K:45,label:"Skörd"}],nutritionTips:[{timing:"Vid sådd",tip:"Inget extra kväve! Ärtor fixar sitt eget via Rhizobium-bakterier på rötterna. Ge lite benmjöl för fosfor."},{timing:"Blomning",tip:"En lätt giva kaliumrik gödsel (vedaska eller alggödsel) stärker blomningen och baljesättningen."},{timing:"Under säsongen",tip:"Ärtor är anspråkslösa - de behöver knappt gödslas alls. Det är en av deras bästa egenskaper."},{timing:"Efter skörd",tip:"Klipp av plantorna vid markytan men LÅT RÖTTERNA SITTA KVAR. Kvävebakterierna på rötterna gödslar jorden åt nästa gröda."}],companions:{good:[{id:"morot",name:"Morot",icon:"morot",why:"Morötter luckrar jorden på djupet medan ärtor fixar kväve i ytan - de kompletterar varandra perfekt"},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Sallat trivs i halvskuggan under ärtorna och drar nytta av det kväve de fixar"},{id:"radisa",name:"Rädisa",icon:"vegetable",why:"Snabb skörd innan ärtorna behöver platsen - perfekt mellankultur"},{id:"gurka",name:"Gurka",icon:"vegetable",why:"Gurkorna klättrar åt andra hållet och drar nytta av ärtornas kväve"}],bad:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökväxter hämmar ärtornas tillväxt och stör kvävefixeringen - de pratar helt enkelt olika språk"},{id:"vitlok",name:"Vitlök",icon:"vegetable",why:"Samma problem som lök - alliumväxter och baljväxter trivs inte ihop"}]},rotation:{avoid:[{id:"bondbona",name:"Bondböna"},{id:"brytbona",name:"Brytböna"},{id:"storbona",name:"Störböna"}],avoidWhy:"Alla baljväxter delar sjukdomar som ärtrotröta och gråmögel. Vänta minst 4 år innan du sår baljväxter på samma plats.",goodBefore:[{id:"potatis",name:"Potatis"},{id:"lok",name:"Lök"},{name:"Kål"}],goodBeforeWhy:"Potatisens luckring och lökens sanering gör jorden redo. Kål efter lök fungerar också bra.",goodAfter:[{name:"Kål"},{id:"sallat",name:"Sallat"},{id:"squash",name:"Squash"}],goodAfterWhy:"Kvävehungriga grödor som kål, sallat och squash älskar jorden efter baljväxter - den är fullpumpad med kväve."},varieties:[{name:"Kelvedon Wonder",zones:[1,2,3,4,5,6,7],note:"Klassikern bland märgärtor. Låg, kompakt, ger bra i alla zoner."},{name:"Norli",zones:[1,2,3,4,5,6,7],note:"Sockerärt (mange tout) - populär nordisk sort. Tidig (54 dagar) och pålitlig, perfekt för kortare säsonger."},{name:"Alderman",zones:[1,2,3,4,5],note:"Hög klätterart (1,5-2 m). Stora baljor med fantastisk smak. Behöver ordentligt stöd. Kulturarvssort från 1891."},{name:"Brytsockerärt Delikett",zones:[1,2,3,4,5,6],note:"Brytsockerärt (snap pea) - du äter hela den knubbiga baljan. Söt och krispig direkt från busken."}],problems:[{name:"Mjöldagg",symptom:"Vitt, mjölaktigt belägg på bladen, oftast sent i säsongen",fix:"Vattna vid roten, aldrig ovanifrån. God luftcirkulation - inte för tätt. Drabbade blad kan tas bort."},{name:"Ärtrotröta",symptom:"Plantorna gulnar underifrån, vissnar, rötterna mörknar",fix:"Växtföljd (4 år minst). Finns ingen bot - dra upp och släng. Välj resistenta sorter."},{name:"Ärtbladlöss",symptom:"Kolonier av gröna/svarta löss på skottspetsar och baljor",fix:"Spruta av med stark vattenstråle. Nyckelpigorna är dina bästa vänner - locka dem med blommande kryddväxter intill."},{name:"Fågelskador",symptom:"Fåglar (speciellt duvor) äter upp fröna och unga plantor",fix:"Skyddsnät eller fiberduk tills plantorna är 10 cm. Gammalt trick: lägg ris/kvistar över sådden."}],goodToKnow:[{icon:"leaf",title:"Kvävefixerare - gratis gödsel",text:"Ärtor samarbetar med Rhizobium-bakterier som fångar kväve ur luften och binder det i jorden. Klipp av plantan vid skörd men lämna rötterna kvar - nästa gröda tackar dig.",severity:"tip"},{icon:"warning",title:"Lök och vitlök är fiender",text:"Alla lökväxter hämmar ärtornas kvävefixering. Håll dem åtskilda i odlingen - annars förlorar du ärtornas bästa superkraft.",severity:"warning"},{icon:"harvest",title:"Skörda ofta - det ger MER",text:"Ju oftare du plockar, desto fler baljor sätter plantan. Sluta plocka = plantan slutar blomma. Skörda varannan dag under högsäsong.",severity:"tip"},{icon:"warning",title:"Stöd behövs tidigt",text:"Sätt stöd redan vid sådd - inte när plantorna börjar falla omkull. Då är det försent och du riskerar att skada rötterna.",severity:"warning"},{icon:"snowflake",title:"Tål frost - en av de tidigaste",text:"Ärtor gror redan vid 5°C och klarar lätt frost ner till -4°C. Du kan så dem bland de allra första på våren, redan i mars i södra Sverige.",severity:"tip"},{icon:"seedling",title:"Så i omgångar",text:"Så med 2-3 veckors mellanrum så får du färska ärtor hela sommaren istället för allt på en gång. Första omgången i april, sista i juni.",severity:"tip"}],sowing:{method:"direct",label:"Direktsådd",description:"Ärtor sås direkt på friland - de ogillar att bli omplanterade och gror snabbt i sval jord.",steps:["Blötlägg fröna i vatten 8-12 timmar innan sådd - de gror snabbare och jämnare","Dra ett spår 3-5 cm djupt med en krattrygg eller pinne","Lägg fröna med 5-8 cm avstånd i spåret","Täck med jord och tryck till lätt med handen eller en krattrygg","Vattna försiktigt men ordentligt","Sätt stöd direkt - nät, pinnar eller ris","Skydda med nät mot fåglar tills plantorna är 10 cm"],tips:["Så i dubbla rader med 10 cm mellanrum och stödet i mitten - effektivt och snyggt","Rulla fröna i Rhizobium-preparat om du sår ärtor för första gången på platsen - kickstartar kvävefixeringen","Så en omgång till efter 2-3 veckor för längre skördeperiod"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Självpollinerare",biennial:!1,description:"Ärtor är självpollinerare och bland de enklaste grödorna att spara frö från. Låt baljorna torka på plantan.",steps:["Välj de finaste plantorna och märk dem tidigt - plocka INTE från dessa","Låt baljorna sitta kvar på plantan tills de är helt torra och bruna","Skaka plantan - om det rasslar inuti baljorna är de redo","Klipp av hela plantan och häng den upp och ner inomhus om vädret inte tillåter torkning utomhus","Bryt upp de torra baljorna och plocka ut ärtorna","Torka ärtorna ytterligare en vecka på tidningspapper inomhus","Förvara i papperspåse eller glasburk på sval, torr plats"],isolation:"Självpollinerare - olika sorter kan odlas nära varandra utan problem. Minst 3-5 m avstånd rekommenderas för att undvika att humlor korsar sorterna.",storageYears:"3-4 år",tip:"Sparade ärtfrön håller sig längre än de flesta grödors frön. Perfekt nybörjarfrö att börja spara!"},storage:{shelfLife:"1-2 veckor (färska)",methods:[{method:"Färska i kylskåp",icon:"snowflake",duration:"3-5 dagar",description:"Skörda på morgonen och lägg direkt i kylskåp i plastpåse. Ät så fort som möjligt - sockret börjar omvandlas till stärkelse direkt efter skörd.",best:!0},{method:"Frysa (bästa långtidslagring)",icon:"snowflake",duration:"8-12 månader",description:"Skala, blanchera 1-2 minuter, kyl i isvatten, torka och frys in på plåt. Flytta till påse när frysta. Behåller smak och färg fantastiskt bra.",best:!1},{method:"Torka",icon:"sun",duration:"1-2 år",description:"Låt baljorna torka på plantan eller torka skalade ärtor i ugn på 50°C. Torkade ärtor blötläggs och kokas - perfekt för ärtsoppa!",best:!1},{method:"Sockerärtor i kylskåp",icon:"snowflake",duration:"5-7 dagar",description:"Sockerärtor (äts med balja) håller lite längre. Lägg i plastpåse med hål. Ät helst inom en vecka.",best:!1}],tips:["Ät färska ärtor samma dag som du skördar - smaken är HELT annorlunda mot köpta","Sockret i ärtor börjar omvandlas till stärkelse inom timmar efter skörd - skynda dig!","Frys in inom 2 timmar efter skörd för bäst smak","Torkade ärtor till ärtsoppa är en svensk klassiker - och helt gratis om du odlar själv"]},harvestCalc:{minPerSqm:.5,maxPerSqm:1,unit:"kg"}},Ar=Object.freeze(Object.defineProperty({__proto__:null,artor:e},Symbol.toStringTag,{value:"Module"})),t={name:"Basilika",icon:"basilika",category:"kryddor",family:"Kransblommiga",familyLatin:"Lamiaceae",perennial:!1,difficulty:"Medel",difficultyWhy:"Kräver förodling inomhus i Sverige, är köldkänslig och vill ha värme. Inte svår - men kräver rätt tajming och omtanke.",zones:{outdoor:[1,2,3,4],indoor:[1,2,3,4,5,6,7,8],greenhouse:[1,2,3,4,5,6]},days:"50-70",spacing:"20-25 cm",rowSpacing:"30 cm",depth:"0.5 cm",depthNote:"Ljusgroddare - så ytligt",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Basilika kräver minst 6-8 timmars sol per dag. I halvskugga blir smaken svagare och tillväxten långsam. Söderläge är perfekt."},temperature:{min:10,max:35,ideal:"20-25°C",detail:"Tropisk växt som HATAR kyla. Dör vid frost. Sätts ut först när nätterna stabilt håller 10°C+. I norra Sverige bäst i växthus eller fönsterkarmen."},wind:{level:"Känslig",detail:"Vindkänslig med tunna blad som torkar ut snabbt. Skyddat, varmt läge är a och o. Perfekt i en sydvänd mur- eller huslycka."}},watering:{need:"Medel",icon:"water",summary:"Basilikan älskar fukt men HATAR att stå blöt - hon är lite bortskämd men värd varje droppe. Vattna alltid vid basen, aldrig ovanifrån.",phases:[{phase:"Plantor inomhus",need:"Låg-Medel",tip:"Vattna underifrån - ställ krukan i vatten 10 minuter och låt den dricka. Sen vill basilikan nästan torka ut innan nästa vattning. Hon gillar inte att ha blöta fötter hela tiden."},{phase:"Utplantering (juni)",need:"Medel",tip:"Ge en rejäl välkomstdricka vid utplantering! Håll jämnt fuktigt första veckan - plantan behöver tid att landa i sin nya jord."},{phase:"Tillväxt (juli-aug)",need:"Medel",tip:"Vattna 2-3 gånger i veckan vid torrt väder. Morgonvattning är bäst - bladen hinner torka under dagen."}],mistakes:["Vattnar ovanifrån - blöta blad ger svampsjukdomar och bruna fläckar","Övervattning - basilika ruttnar lätt i för blöt jord, särskilt i kruka","Vattnar med kallt vatten - chockar den tropiska plantan"],tip:"Ställ ett glas vatten i solen på morgonen - vattna med det ljumma vattnet på kvällen. Basilikan älskar det!"},soil:"Basilika vill ha rik, lucker jord som andas - tänk trädgårdsjord blandad med kompost. I kruka behöver hon extra dränering, annars ruttnar rötterna snabbare än du hinner blinka.",soilTips:["Blanda in kompost - basilika är hungrig och vill ha bra mat från start","I kruka: blanda ungefär 7 delar planteringsjord med 3 delar perlit - hon måste kunna andas","Undvik tung lerjord - basilikans rötter klarar inte att kämpa sig igenom kompakt jord","Mulcha gärna med ett tunt lager gräsklipp - håller fukten och värmen precis som hon vill ha det"],timeline:{1:[{phase:"Förodling inomhus",months:"April",icon:"indoor"},{phase:"Härdning",months:"Maj",icon:"hardening"},{phase:"Utplantering",months:"Slutet av maj-juni",icon:"seedling"},{phase:"Skörd (plocka löpande)",months:"Juni-sept",icon:"harvest"},{phase:"Ta eget frö",months:"Sept",icon:"seed"}],4:[{phase:"Förodling inomhus",months:"April-maj",icon:"indoor"},{phase:"Härdning",months:"Slutet av maj",icon:"hardening"},{phase:"Utplantering",months:"Juni",icon:"seedling"},{phase:"Skörd (plocka löpande)",months:"Juli-sept",icon:"harvest"},{phase:"Ta eget frö",months:"Sept",icon:"seed"}],6:[{phase:"Förodling inomhus",months:"Maj",icon:"indoor"},{phase:"Utplantering (växthus)",months:"Juni",icon:"indoor"},{phase:"Skörd",months:"Juli-aug",icon:"harvest"}]},nutritionData:[{month:"Maj",N:3,P:2,K:2},{month:"Jun",N:6,P:4,K:4},{month:"Jul",N:8,P:5,K:5},{month:"Aug",N:6,P:4,K:4},{month:"Sep",N:2,P:2,K:2}],nutritionTips:[{timing:"Vid utplantering",tip:"Blanda in kompost i jorden - basilika vill ha en rik start. Men överdriva inte, hon klarar sig fint med en normal giva."},{timing:"Varje 3:e vecka (juli-aug)",tip:"Ge lite flytande näring (nässelvatten är perfekt!) utspädd till halv styrka. Övergödsla inte - det ger stora blad men smaken blir helt platt."},{timing:"Obs!",tip:"Syntetisk gödsel med mycket kväve? Glöm det. Basilikan växer som tokig men tappar sin fantastiska smak - det är eteriska oljorna som lider."}],companions:{good:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Det klassiska drömpar! Basilika sägs förbättra tomatens smak, och avskräcker bladlöss och vitfjäril. Plus att de trivs under exakt samma förhållanden - sol och värme."},{id:"paprika",name:"Paprika",icon:"vegetable",why:"Samma värmebehov, och basilikan lockar pollinatörer som hjälper paprika sätta frukt. De samsas fint."},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Basilikan ger välbehövlig skugga åt sallat i högsommarvärmen, och sallaten håller marken sval och fuktig. Ett perfekt par!"}],bad:[{id:"salvia",name:"Salvia",icon:"herb",why:"Bägge producerar starka eteriska oljor som bråkar med varandra. Salvia vill dessutom ha det torrt - raka motsatsen till basilika."},{id:"timjan",name:"Timjan",icon:"herb",why:"Timjan trivs i mager, torr jord. Basilika vill ha rik, fuktig jord. De pratar helt enkelt olika språk."}]},rotation:{avoid:[{id:"basilika",name:"Basilika"},{id:"mynta",name:"Mynta"},{id:"salvia",name:"Salvia"}],avoidWhy:"Kransblommiga (Lamiaceae) delar en del jordburna sjukdomar. Vänta 2-3 år innan du odlar basilika på samma plats.",goodBefore:[{name:"Baljväxter"},{id:"lok",name:"Lök"},{name:"Rotsaker"}],goodBeforeWhy:"Baljväxter berikar jorden med kväve som basilika uppskattar. Lök och rotsaker lämnar ren jord.",goodAfter:[{id:"lok",name:"Lök"},{name:"Rotsaker"},{name:"Kål"}],goodAfterWhy:"Basilikans aromatiska rester i jorden kan ha mild desinficerande effekt. Bra föregångare för grönsaker som är känsliga för jordburna sjukdomar."},varieties:[{name:"Genovese",zones:[1,2,3,4],note:"Klassisk italiensk med stor, kupig blad. Bäst för pesto. DEN basilika de flesta tänker på."},{name:"Thai-basilika",zones:[1,2,3,4],note:"Anissmak, lila stjälkar. Lite mer värmetålig än Genovese. Perfekt för asiatisk matlagning."},{name:"Citronbasilika",zones:[1,2,3,4],note:"Fräsch citronsmak. Kompakt växt, bra i kruka. Fin till fisk och sallader."},{name:"Dark Opal",zones:[1,2,3,4],note:"Mörkt purpur blad. Vacker i trädgården. Något mildare smak. Fantastisk i vinäger."}],problems:[{name:"Bladlöss",symptom:"Klibbiga blad, deformerad tillväxt, löss synliga på undersidan av blad.",fix:"Såpvatten räddar läget (1 msk flytande tvål per liter). Spruta var 3:e dag. Har du tur hittar nyckelpige-larver dem först - de älskar bladlöss."},{name:"Vishnesjuka (Fusarium)",symptom:"Plantan vissnar plötsligt trots vattning. Bruna strimmor i stjälken.",fix:"Tyvärr ingen bot. Dra upp och förstör plantan. Odla inte basilika på samma plats igen på 3 år. Sorten 'Nufar' har viss resistens mot vishnesjuka."},{name:"Kyla-skador",symptom:"Svarta fläckar på blad, slappe blad efter kall natt.",fix:"Förebygg! Ta in krukodlad basilika så fort nattemperaturen kryper under 10°C. Frilandsodlad? Fiberduk under kalla nätter kan rädda henne."}],goodToKnow:[{icon:"warning",title:"Knip topparna - annars ger hon upp",text:"Basilika måste toppas regelbundet, det är nyckeln till en bubbig, produktiv planta. Klipp ovanför ett bladpar så växer två nya grenar ut. Låter du henne blomma tappar bladen smak och plantan ger snabbt upp - hon tycker att jobbet är klart.",severity:"warning"},{icon:"warning",title:"Köldkänslig - noll tolerans",text:"Basilika dör vid minsta frost och börjar må dåligt redan under 10°C. Sätt aldrig ut henne för tidigt - bättre att vänta en vecka extra än att börja om. I norra Sverige (zon 5+) är växthus eller fönsterkarmen enda alternativet.",severity:"warning"},{icon:"tip",title:"Bäst smak före blomning",text:"Skörda alltid innan blommorna dyker upp - det är då smaken är som allra starkast. Ser du blomknoppar? Knip av dem direkt, så fortsätter plantan producera blad istället.",severity:"tip"},{icon:"tip",title:"Perfekt i kruka på balkongen",text:"Har du ingen trädgård? Basilika är räddningen. En 5-liters kruka, bra jord och ett soligt läge - det är allt hon behöver. Många tycker faktiskt att krukodlad basilika ger bäst resultat.",severity:"tip"}],sowing:{method:"indoor",label:"Förodling & sådd",description:"I Sverige måste basilika förodlas inomhus - hon är en tropisk själ som inte tål vår vår. Fröna vill ha värme (20-25°C) och ljus för att vakna. Så ytligt på ytan och håll fuktigt - de gror på 5-10 dagar.",steps:["Fyll krukor/brätten med fuktig såjord","Lägg fröna på ytan - tryck fast lätt men täck INTE (behöver ljus för groning)","Täck med plastfolie eller lock för att hålla fukt - avlägsna dagligen för att vädra","Ställ varmt (20-25°C) och ljust - fönsterbänk i söder eller växtbelysning","Groning på 5-10 dagar. Ta bort plastfolie vid uppkomst","Gallra till 1 planta per kruka vid 2 örtblad","Härda av i 1 vecka innan utplantering (ställ ut dagtid, in på natten)","Plantera ut när natttemp stabilt 10°C+ (juni i mellansverige)"],tips:["Dra flera omgångar med 2 veckors mellanrum för skörd hela sommaren","Basilika HATAR kall jord - vänta hellre en vecka extra med utplanteringen","Köp-basilika från mataffären kan planteras ut men är ofta svag - egna plantor ger 10x bättre resultat"],indoorWeeks:"6-8 veckor före utplantering"},seedSaving:{difficulty:"Enkel",type:"Insektspollinerad",biennial:!1,description:"Låt några plantor blomma i slutet av säsongen. Fröna bildas i de torkade blommorna. Enkelt och ger massor av frö.",steps:["Låt 2-3 plantor blomma ut helt (sluta knipa dem i aug)","Vänta tills blommorna torkat och blivit bruna","Klipp av blomstjälkarna och lägg i en papperspåse","Skaka - de små svarta fröna faller ut","Rensa bort skräp och låt fröna eftertorka några dagar","Förvara svalt och torrt i märkt kuvert"],isolation:"Basilika pollineras främst av insekter och korspollerar med andra basilikasorter. Håll 45+ meters avstånd mellan sorter om du vill ha sortrena frön.",storageYears:"3-5 år",tip:"En enda planta kan ge hundratals frön - mer än tillräckligt för flera år. Dela med odlarkompisar!"},storage:{shelfLife:"5-7 dagar (färsk)",methods:[{method:"Frysning (bäst!)",icon:"snowflake",duration:"6+ månader",description:"Blanchera snabbt (2 sek), isbad, torka, frys i påse. Eller mixa med lite olivolja och frys i isbitsfack. Behåller smaken fantastiskt.",best:!0},{method:"I glas med vatten",icon:"water",duration:"7-10 dagar",description:"Ställ stjälkarna i ett glas vatten som en bukett. Rumstemperatur - INTE i kylen (kyla ger svarta blad). Byt vatten varannan dag.",best:!1},{method:"Saltkonservering",icon:"storage",duration:"6+ månader",description:"Varva blad med havssalt i en burk. Saltet drar ut fukten och konserverar. Skölj av salt innan användning.",best:!1}],tips:["Lägg ALDRIG basilika i kylen - hon blir svart och ledsen av kyla (tropisk själ, minns du?)","Frys i isbitsfack med olivolja - perfekta portioner att slänga i grytan","Skörda på morgonen efter att daggen torkat - då är eteriska oljorna starkast"]},harvestCalc:{minPerSqm:.3,maxPerSqm:.8,unit:"kg"},harvest:{label:"Skörd & användning",method:"Plocka löpande, knip ovanför ett bladpar",description:"Skörda genom att knipa av toppskottet ovanför ett bladpar. Två nya grenar växer ut - plantan blir buskigare och ger mer. Börja plocka när plantan har 6+ bladpar.",uses:[{use:"Färsk",tip:"Tillsätt SIST i matlagningen - värme förstör smaken. Riv med händerna istället för att skära (minskar oxidering)."},{use:"Pesto",tip:"Klassisk Genovese-pesto: basilika, pinjenötter, parmesan, vitlök, olivolja. Frys i isbitsfack för portioner."},{use:"Infused olja",tip:"Blanchera blad 5 sek, isbad, mixa med olivolja. Silknätsila. Hållbar 1-2 veckor i kyl."},{use:"Torkad",tip:"Torka i ugn (50°C, 2-4 tim) eller hängtorka. OBS: torkad basilika tappar mycket smak. Frys hellre."}]}},Hr=Object.freeze(Object.defineProperty({__proto__:null,basilika:t},Symbol.toStringTag,{value:"Module"})),n={name:"Björnbär",icon:"bjornbar",category:"bär",family:"Rosväxter",familyLatin:"Rosaceae",perennial:!0,lifespan:"15-25 år",difficulty:"Enkel",difficultyWhy:"Kraftig och livskraftig buske som klarar sig med minimal skötsel. Björnbäret är en av de mest tacksamma bärbuskarna - hon växer villigt, ger riklig skörd och ställer få krav. Enda utmaningen är att hålla henne i schack.",zones:{outdoor:[1,2,3,4],indoor:null,greenhouse:null},days:"60-80",spacing:"200-300 cm",rowSpacing:"250-350 cm",depth:"Plantera i samma djup som i krukan",ph:{min:5.5,max:7,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Björnbär älskar sol och ger sötast bär i fullt solljus. Men hon klarar halvskugga bättre än de flesta - i naturen växer hon ju gärna i skogsbryn. I södra Sverige uppskattar hon lite eftermiddagsskugga under hettan."},temperature:{min:-20,max:35,ideal:"18-25°C",detail:"Härdig och tålig. De flesta sorter klarar -15 till -20°C i vintervila. I zon 3-4 kan det vara värt att lägga ner rankorna och täcka inför vintern. Blommar i juni-juli, så sent frostskador är sällsynta."},wind:{level:"Måttligt känslig",detail:"De långa rankorna kan piska och skadas i kraftig vind. Spaljering mot en mur eller staket ger bäst resultat - busken får vindskydd och solens värme reflekteras från väggen. En drömsituation för björnbäret!"}},watering:{need:"Medel",icon:"water",summary:"Björnbär har djupare rötter än hallon och klarar torka bättre, men för riktigt stora och saftiga bär vill hon ha jämn fukt under blomning och mognad.",phases:[{phase:"Vår (utbrytning)",need:"Medel",tip:"Vattna vid torka när de nya skotten skjuter i höjden. Mulcha runt basen för att hålla fukten - björnbär uppskattar det."},{phase:"Blomning (juni-juli)",need:"Hög",tip:"Kritisk period! Vattenstress nu ger små, torra bär. Vattna djupt 2 gånger i veckan om det inte regnar. Hon tackar med stora bär."},{phase:"Mognad (juli-sept)",need:"Medel-Hög",tip:"Fortsätt vattna regelbundet. Minska något precis innan skörd - det koncentrerar smaken och minskar mögel."},{phase:"Höst (efter skörd)",need:"Låg",tip:"Minska vattningen. Busken förbereder sig för vintervila. De nya skotten som ska bära frukt nästa år behöver mogna ordentligt."}],mistakes:["Glömmer vattna under blomning - ger halvstora, torra bär","Vattnar ovanifrån under mognad - bären möglar snabbare","Försummar nyplanterade buskar första sommaren - de behöver extra omsorg tills rötterna etablerat sig"],tip:"Droppbevattning vid basen är perfekt för björnbär. Hål bladen torra minskar mögel och svampsjukdomar. En rejäl mulching med bark eller halm sparar dessutom massor av vattning."},soil:"Björnbär trivs i näringsrik, väldränerad jord med bra mullhalt. Hon anpassar sig till de flesta jordtyper men HATAR stående vatten - då ruttnar rötterna. På tung lerjord: plantera upphöjt.",soilTips:["Blanda in rikligt med kompost vid plantering - björnbär är hungriga buskar","På lerjord: plantera upphöjt 15-20 cm och blanda i grov sand eller perlite","Mulcha årligen med bark, halm eller löv - hon älskar en mjuk filt av organiskt material","Undvik mark där det stått hallon, jordgubbar eller potatis senaste 4-5 åren"],timeline:{1:[{phase:"Plantering",months:"Maj-juni",icon:"seedling"},{phase:"Blomning",months:"Juli",icon:"bloom"},{phase:"Skörd",months:"Aug-sept",icon:"harvest"},{phase:"Beskärning",months:"Sept-okt (efter skörd)",icon:"scissors"},{phase:"Vintervila",months:"Nov-apr",icon:"snowflake"}],4:[{phase:"Plantering",months:"Maj",icon:"seedling"},{phase:"Blomning",months:"Juni-juli",icon:"bloom"},{phase:"Skörd",months:"Aug-sept",icon:"harvest"},{phase:"Beskärning",months:"Sept (efter skörd)",icon:"scissors"},{phase:"Vintervila",months:"Okt-apr",icon:"snowflake"}],6:[{phase:"Plantering",months:"Apr-maj",icon:"seedling"},{phase:"Blomning",months:"Juni",icon:"bloom"},{phase:"Skörd",months:"Juli-sept",icon:"harvest"},{phase:"Beskärning",months:"Sept (efter skörd)",icon:"scissors"},{phase:"Vintervila",months:"Nov-mar",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:3,P:2,K:2},{month:"Maj",N:6,P:3,K:3},{month:"Jun",N:5,P:5,K:4},{month:"Jul",N:4,P:5,K:7},{month:"Aug",N:3,P:4,K:6},{month:"Sep",N:1,P:2,K:3}],nutritionTips:[{timing:"Tidig vår (april)",tip:"Ge kompost eller brunnen gödsel runt basen. Björnbär är näringshungriga och en generös vårstart ger kraftiga skott och riklig blomning."},{timing:"Blomning (juni-juli)",tip:"En giva kaliumrik gödsel (tomatgödsel fungerar utmärkt) främjar blomning och bärutveckling. Kalium ger sötare bär!"},{timing:"Efter skörd (sept)",tip:"Ingen gödsel efter augusti. De nya skotten ska mogna och härda inför vintern - inte fortsätta växa."}],companions:{good:[{id:"ringblomma",name:"Ringblomma",icon:"flower",why:"Lockar pollinatörer som björnbäret behöver för god sättning. Dessutom avskräcker den vissa skadeinsekter."},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Fixerar kväve i jorden som björnbäret gärna snor åt sig. En perfekt granne som ger utan att ta."},{id:"vitlok",name:"Vitlök",icon:"vegetable",why:"Avskräcker bladlöss och kvalster med sin starka doft. Plantera vitlök i raden bredvid."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Bägge är känsliga för verticillium-svamp. Håll god distans - minst 3 meter."},{id:"hallon",name:"Hallon",icon:"berry",why:"Nära släktingar som delar sjukdomar (gråmögel, virus). Plantera i separata rabatter, gärna med minst 3-5 meters avstånd."},{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Samma familj, samma sjukdomar. Verticillium och rotröta sprids lätt mellan dem."}]},rotation:{avoid:[{id:"hallon",name:"Hallon"},{id:"bjornbar",name:"Björnbär"},{id:"jordgubbar",name:"Jordgubbar"},{id:"potatis",name:"Potatis"},{id:"tomat",name:"Tomat"}],avoidWhy:"Alla Rubus-arter och Solanaceae delar sjukdomar (verticillium, rotröta, virus). Vänta minst 4-5 år innan du planterar björnbär där det tidigare stått hallon, jordgubbar eller potatis.",goodBefore:[{name:"Gräsmatta"},{name:"Baljväxter"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Mark som legat som gräsmatta i flera år är idealisk - fri från typiska Rubus-sjukdomar. Baljväxter berikar jorden med kväve som björnbäret uppskattar.",goodAfter:[{id:"gronkal",name:"Grönkål"},{id:"artor",name:"Ärtor"},{name:"Gröngödsling"}],goodAfterWhy:"Efter att busken tagits bort (15+ år) är jorden utarmad och behöver byggas upp. Baljväxter och gröngödsling återställer strukturen och näringen."},varieties:[{name:"Loch Ness",zones:[1,2],note:"Taggfri! Den mest populära sorten i Sverige. Upprätt växtsätt, stora söta bär. Ger skörd redan andra året. Behöver skyddad, varm plats."},{name:"Chester",zones:[1,2,3],note:"Taggfri och den härdigaste av de taggfria sorterna. Kraftig buske med riklig skörd. Lite senare mognad."},{name:"Black Satin",zones:[1,2,3,4],note:"Taggfri med halvupprätt växtsätt. Mycket stora, glänsande bär. Behöver bra stöd."},{name:"Navaho",zones:[1,2],note:"Taggfri, upprätt buske som nästan klarar sig utan spaljering. Söta bär med bra lagringskvalitet. Vill ha varmt läge."},{name:"Triple Crown",zones:[1,2,3],note:"Taggfri storvuxen sort med fantastisk smak. Namnet syftar på smak, produktivitet och vigor - kronan bland björnbär!"}],problems:[{name:"Gråmögel (Botrytis)",symptom:"Gråludet mögel på mogna bär, speciellt i fuktigt väder. Bären blir mjuka och grötiga.",fix:"God luftcirkulation genom gallring och spaljering. Plocka bär ofta och lämna aldrig övermogna. Vattna vid basen, inte ovanifrån. Ta bort angripna bär direkt."},{name:"Björnbärsrost",symptom:"Orangegula pustlar på bladens undersida, gula fläckar ovanpå. Bladen kan falla tidigt vid kraftigt angrepp.",fix:"Ta bort och förstör angripna blad. God luftcirkulation genom gallring och spaljering. Undvik att vattna bladen ovanifrån."},{name:"Hallonänger (Byturus tomentosus)",symptom:"Larver i bären - vita maskar ~5 mm som dyker upp när bäret öppnas. Otrevligt men ofarligt.",fix:"Feromonfällor i maj-juni. Fin maska-nät under blomning. Plocka och släng angripna bär. Björnbär drabbas oftast mildare än hallon."}],goodToKnow:[{icon:"warning",title:"Björnbär kan ta över hela trädgården",text:"Hon är en kraftfull klättrare och utbredare. Rankor som nuddar marken rotar sig (bågning). Utan spaljering och beskärning kan en enda buske bilda ett ogenomträngligt snår på några år. Planera var hon ska vara - och var hon INTE ska vara.",severity:"warning"},{icon:"warning",title:"Bär på tvååriga skott - blanda inte ihop dem",text:"Björnbär bär frukt på fjolårets skott (floricanes). Nya gröna skott (primocanes) växer i år och bär frukt nästa år. Klipper du fel skott förlorar du skörden! Märk gärna de fruktbärande skotten.",severity:"warning"},{icon:"tip",title:"Spaljera för maximal skörd",text:"Ett enkelt trådsystem med 3 trådar (60, 100 och 150 cm höjd) är perfekt. Bind fjolårets skott åt ena hållet och nya skott åt andra. Då är det kristallklart vilka som ska klippas efter skörd.",severity:"tip"},{icon:"tip",title:"Bären mognar inte samtidigt",text:"Björnbär mognar successivt under 4-6 veckor. Ett moget bär är svart, mjukt och lossnar lätt. Om du behöver dra - vänta en dag till. Omogna bär är sura och blir aldrig söta efter plockning.",severity:"tip"},{icon:"tip",title:"Taggfria sorter finns!",text:"Var inte rädd för björnbär bara för att du tänker på vilda taggiga buskar. Alla moderna sorter (Loch Ness, Chester, Triple Crown) är taggfria och mycket lättare att hantera.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Björnbär planteras som krukodlade eller barrotade plantor, helst på våren eller tidig höst. Välj en solig, skyddad plats med bra dränering.",steps:["Gräv en grop dubbelt så bred och lika djup som rotklumpen","Blanda in 5-10 liter kompost i planteringsjorden","Plantera i samma djup som i krukan - inte djupare","Vattna rikligt vid plantering - genomblöt!","Mulcha med 5-10 cm bark eller halm runt basen","Sätt upp spaljering direkt - trådar på 60, 100 och 150 cm höjd","Korta plantans skott till 25-30 cm för att stimulera tillväxt"],tips:["Plantera gärna mot en södervägg - värmen gör bären sötare och busken härdigare","Håll 200-300 cm mellan plantorna - björnbär blir stora","Nyplanterade buskar ger full skörd först år 2-3, men det är värt väntan"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Björnbär förökas enklast vegetativt. Den klassiska metoden är bågning (tip layering) - björnbärets egna naturliga sätt att sprida sig. Rankspetsar som nuddar marken rotar sig spontant.",steps:["Välj en frisk, kraftig ranka i augusti-september","Böj ner rankspetsen och gräv ner den 10 cm djupt i jorden","Fäst med en jordklämma eller sten","Vattna regelbundet - rötter bildas under hösten","Klipp av från moderplantan nästa vår när rötterna är starka","Plantera om den nya plantan på sin permanenta plats"],isolation:"Vegetativ förökning - klon av moderplantan. Ingen korspollinering relevant.",storageYears:"Ej tillämpligt",tip:"Bågning är så lätt att björnbäret gör det av sig självt om du inte passar dig. Välj alltid förökningsmaterial från friska, sjukdomsfria buskar."},storage:{shelfLife:"3-5 dagar (färska)",methods:[{method:"Frysning",icon:"snowflake",duration:"10-12 månader",description:"Bästa sättet att ta vara på skörden. Lägg bären i ett lager på bakplåtspapper, frys 2 timmar, flytta till påse. Behåller form och smak utmärkt.",best:!0},{method:"Sylt & gelé",icon:"storage",duration:"1+ år",description:"Björnbärssylt är en klassiker. Bären har naturligt pektin som ger bra konsistens. Sila bort kärnorna om du föredrar gelé.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"3-5 dagar",description:"Lägg bären i ett lager på hushållspapper i en skål. Tvätta INTE förrän du ska äta dem - fukt ger mögel direkt.",best:!1},{method:"Torkning",icon:"sun",duration:"6+ månader",description:"Torka i ugn på 50°C i 10-14 timmar eller i torkmaskin. Blir söta och intensiva. Perfekt i müsli och bakning.",best:!1}],tips:["Plocka torra bär - vänta tills daggen torkat på morgonen","Sortera direkt - ett mögligt bär smittar snabbt de andra","Björnbär tål lagring lite bättre än hallon tack vare tjockare skal"]},harvestCalc:{minPerSqm:.5,maxPerSqm:2,unit:"kg"},pruning:{label:"Beskärning",types:{maintenance:{name:"Årlig beskärning",when:"Direkt efter skörd (sept-okt) + tidig vår",description:"Björnbär bär frukt på fjolårets skott. Efter skörd klipper du bort alla skott som burit frukt (gamla, vedartade) vid marknivå. Nya gröna skott som vuxit under sommaren sparas - de bär frukt nästa år. På våren kortar du sidoskotten till 30-40 cm.",steps:["Klipp bort ALLA skott som burit frukt - vid marknivå","Spara 5-7 av de starkaste nya skotten per buske","Ta bort svaga, skadade eller sjuka skott","Bind upp de kvarvarande skotten mot spaljen","På våren: korta sidoskotten till 30-40 cm","Toppa nya skott vid 150-180 cm för att stimulera förgrening"]},rejuvenation:{name:"Föryngringsbeskärning",when:"Tidig vår (mars-april) vid behov",description:"Om busken blivit för stor, förvuxen eller ger dålig skörd kan du göra en rejäl föryngring. Klipp ner allt till marknivå - björnbäret är otroligt livskraftigt och skjuter nya friska skott. Du förlorar ett års skörd men får en ny, vital buske.",steps:["Klipp ner ALLA skott till 10 cm ovan mark","Rensa bort allt avklippt material - bränn om det finns sjukdom","Ge en ordentlig giva kompost runt basen","Nya skott dyker upp - välj ut de 5-7 starkaste","Bind upp mot spaljen - skörd igen året efter"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Bågning (tip layering)",description:"Det naturligaste sättet - björnbäret gör det spontant! Böj ner en rankspets och gräv ner den 10 cm i jorden i aug-sept. Rötter bildas under hösten. Klipp av från moderplantan nästa vår.",icon:"seedling"},{method:"Sticklingar",description:"Klipp 15-20 cm bitar av friska skott i november. Sätt i fukthållen jord utomhus. De rotar sig under vintern och kan planteras ut på våren.",icon:"scissors"},{method:"Rotskott",description:"Vissa sorter bildar rotskott precis som hallon. Gräv upp med rot och plantera om på våren. Enklast av allt, men inte alla sorter gör det.",icon:"plant"}],tip:"Bågning är den klassiska metoden och fungerar nästan alltid. Välj friska, kraftiga buskar som förökningsmaterial - sjukdomar följer med till den nya plantan."}},Gr=Object.freeze(Object.defineProperty({__proto__:null,bjornbar:n},Symbol.toStringTag,{value:"Module"})),i={name:"Blåbär (odlade)",icon:"blabar",category:"bär",family:"Ljungväxter",familyLatin:"Ericaceae",perennial:!0,lifespan:"20-30+ år",difficulty:"Medel",difficultyWhy:"Odlade blåbär är inte svåra i sig - men de kräver sur jord (pH 4.0-5.5) som de flesta svenska trädgårdar INTE har. Lyckas du med jorden är resten ganska enkelt. Misslyckas du med jorden går det inte alls.",zones:{outdoor:[1,2,3,4],indoor:null,greenhouse:[1,2,3,4,5,6]},days:"Skörd efter 2-3 år, full skörd 4-5 år",spacing:"100-150 cm",rowSpacing:"200-250 cm",depth:"Något djupare än krukan",depthNote:"Plantera 3-5 cm djupare än busken stod i krukan - stimulerar nya skott från basen.",ph:{min:4,max:5.5,ideal:4.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Blåbär vill ha full sol för bästa skörd och sötaste bär. Halvskugga går, men du tappar skörd och smak. Minst 6 timmar direkt sol per dag - hon tackar dig med rikligt med bär."},temperature:{min:-30,max:30,ideal:"15-25°C",detail:"Nordliga sorter som Northblue och Northcountry tål ner till -30°C. Busken behöver vinterkyla (minst 800-1000 kyltimmar under 7°C) för att blomma ordentligt - det är sällan ett problem i Sverige."},wind:{level:"Måttligt känslig",detail:"Vindskydd förbättrar pollinering och skyddar blommorna från sen vårfrost. Blommorna sitter exponerat och stark vind kan skaka loss dem. Ett lä-läge intill en häck eller husvägg är perfekt."}},watering:{need:"Hög",icon:"water",summary:"Blåbär har väldigt grunda rötter och klarar inte uttorkning. De vill ha jämn fukt hela säsongen - men aldrig stående vatten. Tänk skogsbotten: fuktig, men luftig. Vattna gärna med regnvatten - kranvatten i kalkrika områden kan höja pH över tid.",phases:[{phase:"Vår (knoppsprickning)",need:"Medel",tip:"Våren är ofta fuktig nog, men håll koll vid tidig torka. Busken vaknar och sätter igång - hon behöver fukt för att dra igång blommorna."},{phase:"Blomning (maj-juni)",need:"Hög",tip:"Kritisk period! Vattenstress nu ger dålig fruktsättning. Vattna djupt 2-3 ggr/vecka vid torka. Regnvatten är perfekt - det är naturligt surt."},{phase:"Bärmognad (juli-aug)",need:"Hög",tip:"Jämn fukt ger stora, saftiga bär. Ojämn vattning kan ge att bären spricker eller blir små och torra."},{phase:"Höst (efter skörd)",need:"Medel",tip:"Minska vattningen gradvis men låt inte busken torka ut helt. Hon lägger redan nu grunden för nästa års blomknoppar."}],mistakes:["Vattnar med kalkrikt kranvatten - höjer pH sakta men säkert och busken börjar gula","Låter busken torka ut - de grunda rötterna klarar inte ens kortare torka","Stående vatten - rötterna drunknar snabbt. Dränering är lika viktigt som fukt","Glömmer nyplanterade buskar - de första 2 åren är busken extra känslig för uttorkning"],tip:"Mulcha med barkmull, tallbarr eller sågspån (barrträd) - det håller fukten, sänker pH och ger den skogskänsla blåbär längtar efter. 10-15 cm tjockt lager är perfekt. Fyll på årligen."},soil:"Blåbär kräver SUR jord - pH 4.0-5.5. Det är icke-förhandlingsbart. Vanlig trädgårdsjord i Sverige ligger ofta på pH 6-7 och fungerar inte alls. Blanda egen surjord med torvmull, barkmull och sågspån, eller köp färdig rhododendronjord. Hon vill ha lucker, humusrik jord som håller fukt men släpper igenom överskottsvatten.",soilTips:["Gräv ur en stor grop (80x80x40 cm) och fyll med surjordblandning: 50% torvmull + 30% barkmull + 20% sågspån (barrträd)","Testa pH med en billig testare innan plantering OCH varje vår - det är den viktigaste mätningen du gör","Tillsätt trädgårdssvavel (elementärt svavel) om pH börjar krypa uppåt - det tar 2-3 månader att verka","Mulcha årligen med tallbarr, barkmull eller sågspån - det håller pH nere naturligt","Plantera ALDRIG i kalkrik lerjord utan att först byta ut jorden helt","Regnvatten är bäst för vattning - kranvatten i kalkrika områden höjer pH långsamt"],timeline:{1:[{phase:"Plantering",months:"April-maj",icon:"seedling"},{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Skörd",months:"Juli-sept",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (mars-april)",icon:"scissors"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],4:[{phase:"Plantering",months:"April-maj",icon:"seedling"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Skörd",months:"Juli-aug",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (feb-mars)",icon:"scissors"},{phase:"Vintervila",months:"Okt-mars",icon:"snowflake"}],6:[{phase:"Plantering",months:"Maj-juni",icon:"seedling"},{phase:"Blomning",months:"Juni",icon:"bloom"},{phase:"Skörd",months:"Aug-sept",icon:"harvest"},{phase:"Beskärning",months:"Sen vinter (mars-april)",icon:"scissors"},{phase:"Vintervila",months:"Okt-april",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:3,P:2,K:2},{month:"Maj",N:5,P:3,K:3},{month:"Jun",N:4,P:4,K:5},{month:"Jul",N:3,P:4,K:7},{month:"Aug",N:2,P:3,K:5},{month:"Sep",N:1,P:2,K:3}],nutritionTips:[{timing:"Tidig vår (april)",tip:"Ge en giva surjordsgödsel (rododendrongödsel) eller surt organiskt material. Blåbär är INTE hungriga buskar - de vill ha lite näring i sur form. Övergödsla inte!"},{timing:"Blomning (maj-juni)",tip:"En liten giva kaliumrik gödsel stärker blomning och bärsättning. Undvik vanlig NPK-gödsel som kan innehålla kalk - det förstör pH-balansen."},{timing:"Sommar",tip:"Toppdressing med sågspån eller tallbarr ger långsam näring i rätt pH. Det är blåbärets favoritkost."},{timing:"Höst",tip:"Ingen gödsling efter juli. Busken ska förbereda sig för vinter. Lägg på ett tjockt lager barkmulch som bryts ner sakta."}],companions:{good:[{name:"Rhododendron",icon:"flower",why:"Delar samma krav på sur jord. Perfekta grannar som trivs i samma jordtyp utan att konkurrera."},{name:"Lingon",icon:"berry",why:"Samma familj (Ericaceae) och älskar samma sura jord. Fint markskydd under blåbärsbuskarna."},{name:"Ljung",icon:"flower",why:"Trivs i samma sura jord och lockar pollinatörer tidigt på säsongen. Vackert marktäckande."}],bad:[{name:"Kalkälskande växter",icon:"flower",why:"Allt som vill ha kalkrik jord (lavendel, rosmarin) hör inte hemma bredvid blåbär. Ni har helt olika pH-krav."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Helt olika jordkrav - tomater vill ha neutral till svagt sur jord. Dessutom risk för verticillium-svamp."},{name:"Valnöt",icon:"vegetable",why:"Valnötsträd utsöndrar juglone som hämmar blåbärstillväxt. Håll bra avstånd."}]},rotation:{avoid:[{name:"Blåbär"},{name:"Lingon"},{name:"Rhododendron"}],avoidWhy:"Alla Ericaceae-växter delar potentiella rotsjukdomar (Phytophthora). Plantera inte nya blåbär där gamla stått - vänta minst 5 år och byt ut jorden.",goodBefore:[{name:"Öppen, solig plats"},{name:"Gräsmatta"}],goodBeforeWhy:"En plats utan tidigare Ericaceae-växter och utan kalktillskott. Gräsmattejord är ofta mer sur än trädgårdsland som gödslats med kalk.",goodAfter:[{name:"Gröngödsling"},{name:"Surjordsväxter"}],goodAfterWhy:"Efter 20+ år med blåbär är jorden sur och utarmad. Gröngödsling och kalkspridning krävs innan du odlar grönsaker här."},varieties:[{name:"Northblue",zones:[1,2,3,4,5],note:"Halvhög sort (50-70 cm). Extremt härdig - klarar -35°C. Stora, mörkblå bär med fin smak. Pålitlig producent. Bästa valet för norrlandsodlare."},{name:"Northcountry",zones:[1,2,3,4,5],note:"Halvhög sort (40-60 cm). Mycket härdig och kompakt. Ljusblå, söta bär. Fantastisk höstfärg. Perfekt för mindre trädgårdar och krukor."},{name:"Patriot",zones:[1,2,3,4],note:"Högbuskblåbär (120-150 cm). Stora bär med utmärkt smak. Tidig mognad (juli). Tål våtare förhållanden bättre än de flesta. God härdighet till zon 4."},{name:"Duke",zones:[1,2,3,4],note:"Högbuskblåbär (120-180 cm). Mycket tidig mognad - bland de första att mogna. Stora, fasta bär. Blommar sent men mognar tidigt, vilket minskar frostrisk."},{name:"Bluecrop",zones:[1,2,3],note:"Den mest odlade sorten i världen. Högbuske (120-180 cm). Stora, ljusblå bär med klassisk blåbärssmak. Rik skörd men behöver milt klimat i Sverige."},{name:"Polaris",zones:[1,2,3,4,5],note:"Halvhög sort (60-120 cm). Utvecklad i Minnesota för kallt klimat. Söta bär med intensiv smak. Mycket härdig och produktiv."}],problems:[{name:"Klorosförgulning (järnbrist)",symptom:"Bladen gulnar mellan nerverna medan nerverna förblir gröna. Börjar på yngsta bladen. Busken ser sjuk och blek ut.",fix:"Nästan alltid orsakat av för högt pH - kolla pH först! Sänk med trädgårdssvavel. Akut: ge järnchelat (EDDHA-järn) som bladspray. Lös orsaken - inte bara symptomen."},{name:"Fågelskador",symptom:"Bären försvinner mystiskt innan du hinner skörda. Koltrastar och starar är de värsta bovarna.",fix:"Nät över buskarna är enda pålitliga skyddet. Sätt upp nät när bären börjar färgas (juni-juli). Fågelskrämmor hjälper tillfälligt men fåglarna vänjer sig snabbt."},{name:"Grå mögel (Botrytis)",symptom:"Gråludna belägg på blommor och mogna bär. Värst i fuktigt, svalt väder under blomning.",fix:"God luftcirkulation genom beskärning. Undvik övervattning uppifrån. Plocka bort angripna bär och blommor direkt. Bästa förebyggandet: öppen, luftig buske."},{name:"Rotröta (Phytophthora)",symptom:"Busken vissnar trots vattning. Bladen blir röda/bruna i förtid. Rötterna är brunfärgade och mjuka.",fix:"Förebygg med god dränering - blåbär hatar stående vatten. Plantera aldrig i vattensjuk jord. Svårt att bota en gång det satt in - ta bort angripna buskar och byt jord."},{name:"Mjöldagg",symptom:"Vitt, mjölaktigt belägg på bladens ovansida. Vanligast vid torra, varma dagar med svala nätter.",fix:"Välj resistenta sorter. God luftcirkulation genom beskärning. Vattna vid basen, aldrig ovanifrån. Angripna blad kan klippas bort."}],goodToKnow:[{icon:"warning",title:"pH är ALLT",text:"Blåbär kräver sur jord (pH 4.0-5.5) och vanlig trädgårdsjord i Sverige ligger ofta på 6-7. Utan rätt pH kan busken inte ta upp järn och andra näringsämnen - oavsett hur mycket du gödslar. Testa pH varje vår och justera med svavel vid behov.",severity:"warning"},{icon:"warning",title:"Kranvatten kan vara fienden",text:"I områden med kalkrikt vatten höjer varje vattning pH lite. Samla regnvatten! Det är naturligt surt (pH 5-6) och perfekt för blåbär. En regnvattentunna vid blåbärsrabatten är en av de bästa investeringarna.",severity:"warning"},{icon:"warning",title:"Fåglarna väntar inte",text:"Koltrastar och starar kan plundra dina blåbärsbuskar på en dag. Nät är det enda som fungerar på riktigt. Sätt upp nät i god tid innan bären börjar färgas.",severity:"warning"},{icon:"tip",title:"Inte samma som skogsblåbär",text:"Odlade blåbär (Vaccinium corymbosum) och svenska skogsblåbär (Vaccinium myrtillus) är olika arter. Odlade blåbär har vitt fruktkött, är större och håller längre - men skogsblåbäret har djupare smak och färgar hela munnen blå.",severity:"tip"},{icon:"tip",title:"Fantastisk höstfärg",text:"Blåbärsbuskar har bland de vackraste höstfärgerna i trädgården. Bladen blir eldröda, orange och karmosinröda i september-oktober. Northcountry är extra spektakulär. Odla dem synligt!",severity:"tip"},{icon:"tip",title:"Funkade i kruka",text:"Blåbär är perfekta för krukodling! Du kontrollerar jorden helt, vilket löser pH-problemet. Använd stor kruka (minst 50 liter), rhododendronjord och vattna med regnvatten. Halvhöga sorter som Northcountry passar bäst.",severity:"tip"},{icon:"tip",title:"Tålamod lönar sig",text:"De första 2-3 åren ger busken lite bär. Nip gärna bort blommorna år 1-2 så att energin går till rotbildning istället. Från år 4-5 ger en etablerad buske 2-5 kg per säsong i 20+ år. Det är en investering som betalar sig!",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Odlade blåbär planteras som krukodlade plantor (vår eller tidig höst). Barrotade plantor finns sällan. Förbered jorden noggrant innan plantering - det är det viktigaste steget.",steps:["Gräv en stor grop (80x80x40 cm) - blåbär har ytliga men utbredda rötter","Fyll med surjordsblandning: 50% torvmull + 30% barkmull + 20% sågspån från barrträd","Testa att pH är 4.0-5.5 innan du sätter plantan - annars justera med trädgårdssvavel","Plantera 3-5 cm djupare än plantan stod i krukan","Vattna rikligt med regnvatten (helst) vid plantering","Mulcha med 10-15 cm tallbarr, barkmull eller sågspån runt busken","Nip bort alla blomknoppar första året - låt busken bygga rötter istället"],tips:["Vårplantering (april-maj) ger busken hela säsongen att etablera sig","Plantera 2+ buskar - korspollinering ger betydligt bättre skörd och större bär","Halvhöga sorter (Northblue, Polaris) är härdigast och bäst i zon 4-6","I zon 5-6: testa krukodling med surjord om trädgårdsjorden inte fungerar"],indoorWeeks:null},seedSaving:{difficulty:"Medel",type:"Vegetativ förökning",biennial:!1,description:"Blåbär förökas bäst vegetativt med sticklingar. Fröförökning ger inte samma sort (heterozygot) och det tar 5+ år till skörd. Sticklingar ger identiska kopior av moderplantan.",steps:["Klipp 10-15 cm halvmogna sticklingar (mjukt grönt skott med lite ved i basen) i juni-juli","Ta bort de nedersta bladen och behåll 2-3 blad i toppen","Doppa i rotningshormon - blåbär rotar sig trögt utan","Sätt i sur, fuktig blandning av torvmull och perlit (1:1)","Håll under fukthuv eller i miniväxthus - hög luftfuktighet är avgörande","Rotning tar 2-3 månader. Ha tålamod!","Plantera ut nästa vår efter acklimatisering"],isolation:"Vegetativ förökning - kloner av moderplantan. Ingen korspollinering relevant.",storageYears:"Ej tillämpligt",tip:"Sticklingsförökning av blåbär kräver lite mer fingertoppskänsla än andra bärbuskar. Om du bara vill ha en extra planta: fråga en granne med en fin buske om du får böja ner en gren (marklager). Det är enklare och säkrare."},storage:{shelfLife:"1-2 veckor (färska)",methods:[{method:"Kylskåp",icon:"snowflake",duration:"1-2 veckor",description:"Blåbär håller sig förvånansvärt länge i kylen - mycket bättre än hallon och jordgubbar. Lägg i en skål med hushållspapper i botten. Tvätta inte förrän du ska äta.",best:!0},{method:"Frysning",icon:"snowflake",duration:"12+ månader",description:"Perfekt frysbär! Lägg ut i ett lager på bakplåtspapper, frys, flytta sedan till påse. Frysta blåbär funkar direkt i smoothies, pannkakor och bakning.",best:!1},{method:"Sylt och mos",icon:"storage",duration:"1+ år",description:"Blåbärssylt med lite citron är en klassiker. Koka med socker och en skvätt citronjuice. Pektinhalten är måttlig - tillsätt ev. extra gelatin eller pektin.",best:!1},{method:"Torkning",icon:"sun",duration:"6+ månader",description:"Torka i ugn på 50-60°C i 10-14 timmar eller i torkmaskin. Blir sega och intensivt söta. Fantastiskt i müsli, bakat bröd och som snacks.",best:!1},{method:"Saft",icon:"storage",duration:"1+ år",description:"Safta blåbär med ångssaftare eller koka och sila. Fantastisk färg och smak. Blanda med äpple för extra sötma.",best:!1}],tips:["Plocka torra bär - vänta tills daggen torkat. Fuktiga bär möglar snabbare","Blåbär mognar inte efter plockning - skörda bara fullt mogna bär","Bäret ska lossa lätt med en mjuk rullning - om du måste dra väntar du en dag till","Frysta blåbär tappar lite struktur men behåller smak och näring helt"]},harvestCalc:{minPerSqm:.8,maxPerSqm:2.5,unit:"kg"},pruning:{label:"Beskärning",types:{maintenance:{name:"Underhållsbeskärning",when:"Tidig vår (feb-mars) innan knopparna svällt",description:"Blåbär bär bäst på 2-5 år gammal ved. Busken ska ha en öppen, vasformad struktur med god luftcirkulation. De första 2-3 åren: beskär minimalt - bara ta bort svaga skott. Från år 4: börja gallra systematiskt.",steps:["Ta bort döda, skadade och sjuka grenar (alltid, oavsett ålder)","Ta bort grenar som är 6+ år gamla (tjock, grå bark, minskad produktion)","Ta bort svaga, korta skott som inte bär ordentligt","Öppna upp buskens mitt för ljus och luft","Spara 5-8 starka huvudgrenar i blandade åldrar (2-5 år)","Korta gärna alltför långa grenar - klipp tillbaka till en stark sidogren"]},rejuvenation:{name:"Föryngringsbeskärning",when:"Tidig vår",description:"Gammal, förvuxen blåbärsbuske med minskande skörd? Ta bort en tredjedel av de äldsta grenarna varje år i tre år. Det ger busken tid att ersätta med nytt frukbärande trä utan att du förlorar hela skörden.",steps:["År 1: Ta bort en tredjedel av de äldsta, grövsta grenarna vid basen","År 2: Ta bort ytterligare en tredjedel av de gamla grenarna","År 3: Ta bort sista tredjedelen - nu har busken förnyats helt","Gödsla med surjordsgödsel och mulcha rikligt efter varje beskärningsomgång","Full skörd igen efter 2-3 år"]}}},propagation:{difficulty:"Medel",methods:[{method:"Halvmogna sticklingar",description:"Klipp 10-15 cm sticklingar av halvmogna skott (juni-juli). Ta bort nedre blad, doppa i rotningshormon, sätt i sur torvmull-perlit-blandning under fukthuv. Rotning tar 2-3 månader. Kräver tålamod men ger identiska kloner.",icon:"scissors"},{method:"Nedböjning (marklager)",description:"Böj ner en låg gren och fäst mot marken med bygel. Täck med sur jord. Grenen rotar sig under säsongen och klipps loss nästa vår. Enklare än sticklingar men kräver en lågt sittande gren.",icon:"seedling"}],tip:"Blåbär är svårare att föröka än de flesta bärbuskar. Halvmogna sticklingar i juni-juli med rotningshormon och fukthuv ger bäst resultat. Marklager är enklare om du har en lämplig låg gren. Köp hellre nya plantor om du bara behöver 1-2 till."}},Dr=Object.freeze(Object.defineProperty({__proto__:null,blabar:i},Symbol.toStringTag,{value:"Module"})),l={name:"Blomkål",icon:"blomkal",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Avancerad",difficultyWhy:"Blomkål är kålväxternas absoluta diva. Hon kräver perfekt temperatur, jämn fukt, rätt timing OCH att du aktivt skyddar huvudet med bladen. Minsta lilla stress och hon ger dig en liten, missfärgad knopp istället för ett vackert vitt huvud.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:[1,2,3,4,5,6,7]},days:"60-100",spacing:"50-60 cm",rowSpacing:"60-70 cm",depth:"1-2 cm",ph:{min:6,max:7.5,ideal:6.8},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmar sol per dag för att bygga ordentliga huvuden. I halvskugga blir huvudena små och lösa. Men akta - för stark hetta stressar henne, så lite eftermiddagsskugga i zon 1-2 kan vara en fördel."},temperature:{min:-2,max:25,ideal:"15-18°C",detail:"Blomkål är extremt temperaturkänslig. Hon vill ha svala, jämna 15-18°C - inte för varmt, inte för kallt. Över 25°C stressar hon och bildar små, lösa huvuden. Under -2°C kan huvudet skadas. Hon är kälkålingarnas kälkåling."},wind:{level:"Skyddat",detail:"Blomkål har stora blad som fångar vind som segel. I blåsiga lägen torkar hon ut snabbare och riskerar att välta. Ge henne ett skyddat, soligt läge - gärna bakom en häck eller mur."}},watering:{need:"Hög",icon:"water",summary:'Blomkål kräver jämn, riklig fukt hela säsongen. Hon är mer vattenkrävande än broccoli och reagerar med dåliga huvuden på minsta torka. Tänk "ständigt fuktig men aldrig dränkt".',phases:[{phase:"Förodling (0-4 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig. Kålfrön gror snabbt (5-10 dagar) om de får fukt och 18-20°C. Låt aldrig jorden torka ut helt."},{phase:"Etablering (4-7 veckor)",need:"Hög",tip:'Nyutplanterade plantor behöver daglig vattning i varmt väder. Rötterna måste etablera sig snabbt - stress nu ger "buttoning" senare.'},{phase:"Tillväxt (7-12 veckor)",need:"Hög",tip:"Djupvattna 3-4 gånger i veckan. Hon bygger sitt enorma bladverk nu och behöver konstant fukt. Mulcha rejält!"},{phase:"Huvudbildning och skörd",need:"Mycket hög",tip:'Kritisk period! Ojämn vattning nu ger missfärgade, lösa eller "håriga" huvuden. Vattna regelbundet och rikligt - det här är allt eller inget.'}],mistakes:["Ojämn vattning - torka följt av storvattning ger bruna fläckar och lösa huvuden","Vattna för lite under huvudbildningen - det är som att sluta vattna en orkide under blomningen","Tro att blomkål klarar sig med samma vatten som grönkål - hon behöver MYCKET mer","Fuktiga blad över natten - vattna på morgonen vid roten, aldrig ovanifrån"],tip:"Mulcha med ett 5-7 cm tjockt lager gräsklipp eller halm runt plantorna. Det håller jorden jämnt fuktig och sval - exakt vad blomkålens diva-temperament kräver."},soil:"Mycket näringsrik, djup, kalkrik jord med utmärkt dränering. Blomkål är den hungrigaste av alla kålväxter - hon vill ha den bästa matjorden du kan erbjuda.",soilTips:["Blanda in rikligt med brunnen kompost, gärna ett halvt spadtags djup. Hon är en storätare av rang.","Kalka ordentligt på hösten om pH är under 6.5 - blomkål vill ha kalkrik jord och det skyddar mot klumprotsjuka","Jorden måste vara djupt bearbetad och lucker - kompakt jord ger kompakta (dvs dåliga) huvuden","Undvik nyligen gödslad jord med färsk gödsel - hon vill ha brunnen kompost, inte rått material"],timeline:{1:[{phase:"Förodla inomhus",months:"Feb-Mar",icon:"seedling"},{phase:"Plantera ut",months:"Apr-Maj",icon:"leaf"},{phase:"Gödsla",months:"Maj-Jun",icon:"water"},{phase:"Blanchera (täck huvudet)",months:"Jun-Jul",icon:"leaf"},{phase:"Skörd",months:"Jul-Aug",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj",icon:"leaf"},{phase:"Gödsla",months:"Jun",icon:"water"},{phase:"Blanchera (täck huvudet)",months:"Jul",icon:"leaf"},{phase:"Skörd",months:"Jul-Aug",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Plantera ut",months:"Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Blanchera (täck huvudet)",months:"Jul-Aug",icon:"leaf"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:20,P:15,K:10,label:"Förodling"},{month:"Maj",N:50,P:25,K:15,label:"Utplantering"},{month:"Jun",N:85,P:40,K:25,label:"Kraftig tillväxt"},{month:"Jul",N:95,P:50,K:45,label:"Huvudbildning"},{month:"Aug",N:70,P:45,K:55,label:"Mognad/skörd"},{month:"Sep",N:20,P:20,K:30,label:"Sen skörd"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla generöst med brunnen kompost och hornmjöl. Blomkål behöver en kraftfull start - hon är hungrigare än broccoli och vill ha kväve från dag ett."},{timing:"Tre veckor efter utplantering",tip:"Ge flytande nässelvatten eller alggödsel. Nu ska bladverket växa explosionsartat och hon behöver bränsle för att bygga de stora blad som ska skydda huvudet."},{timing:"Vid huvudbildning",tip:'Extra kaliumrik gödsel (vedaska eller alggödsel). Kalium ger fasta, vita huvuden med fin textur. Brist syns som bruna kanter och lösa "ris".'},{timing:"Under hela säsongen",tip:"Ge bor (borax i vatten) en gång under säsongen. Borbrist ger ihåliga stjälkar och bruna fläckar i huvudet - vanligare i blomkål än andra kålväxter."}],companions:{good:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft förvirrar kålfjärilen - blomkåls allra värsta fiende. Klasskamrater sedan urminnes tider."},{id:"dill",name:"Dill",icon:"herb",why:"Lockar parasitsteklar som äter kålfjärilens larver. Dill är blomkåls flitigaste livvakt."},{name:"Selleri",icon:"vegetable",why:"Selleris starka doft maskerar kåldoften och förvirrar skadedjur. Dessutom tar de näring från olika djup."}],bad:[{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Jordgubbar hämmas rejält av kålväxter. Håll dem långt ifrån varandra."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Båda är extrema storätare. Sätter du dem ihop svälter de varandra - ingen blir nöjd."},{name:"Andra kålväxter",icon:"vegetable",why:"Aldrig blomkål bredvid annan kål! De delar skadedjur och sjukdomar och förstärker varandras problem. Kålfjärilarna får julafton."}]},rotation:{avoid:[{id:"broccoli",name:"Broccoli"},{id:"gronkal",name:"Grönkål"},{id:"vitkal",name:"Vitkål"},{id:"rodkal",name:"Rödkål"},{id:"brysselkal",name:"Brysselkål"},{id:"kalrabbi",name:"Kålrabbi"},{id:"radisa",name:"Rädisa"},{id:"pak-choi",name:"Pak choi"}],avoidWhy:"Alla tillhör korsblommiga och delar sjukdomar som klumprotsjuka och kålbråck. Vänta minst 4 år - helst längre - innan du odlar kål på samma plats igen!",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"potatis",name:"Potatis"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden - gratis lyxgödsel för hungriga blomkål. Potatis och lök lämnar ren, bearbetad jord som blomkål älskar.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"sallat",name:"Sallat"},{id:"rodbeta",name:"Rödbeta"}],goodAfterWhy:"Rotgrönsaker trivs i den djupt bearbetade, näringsrika restjorden. Sallat utnyttjar kvävet som blomkål lämnar kvar."},varieties:[{name:"Snowball",zones:[1,2,3,4,5],note:'Klassisk OP-sort med vita, fasta huvuden. Tidig och tålig - det närmaste du kommer en "enkel" blomkål. Finns hos Runåbergs och Wexthuset.'},{name:"Igloo",zones:[2,3,4,5],note:"Tidig sort med kompakta huvuden. Bra för kortare säsonger. Hon klarar lite mer kyla än de flesta - namnet ljuger inte."},{name:"Erfurt",zones:[1,2,3,4],note:"Den klassiska europeiska sorten som odlats i generationer. Fina, vita huvuden med mild smak. Kräver lång, sval säsong."},{name:"Romanesco",zones:[1,2,3,4],note:"Gröna, fantastiska fraktalmönster-huvuden! Faktiskt lättare att odla än vanlig blomkål och behöver inte blancheras. Kräver mer plats (70-80 cm) och 75-100 dagar till skörd. En matematisk skönhet på tallriken."},{name:"Graffiti F1",zones:[1,2,3,4],note:"Spektakulärt lila F1-blomkål som behåller färgen vid tillagning! Rikare på antioxidanter. Behöver lång säsong men WOW-faktorn är enorm. Finns hos Impecta. OBS: F1 - ger inte sortäkta frö."}],problems:[{name:"Kålfjäril",symptom:"Gröna larver som tuggar sig genom bladen. Gröna spillningshögar överallt.",fix:"Fiberduk från dag ett - det är det enda 100% säkra skyddet! Handplocka larver. Spruta med Bacillus thuringiensis (Bt). Samodla med dill och lök."},{name:"Klumprotsjuka",symptom:"Plantan stannar i tillväxt och vissnar trots vattning. Rötterna har klumpiga, svullna utväxter.",fix:"Ingen bot - dra upp och bränn! Kalka jorden ordentligt (pH över 7). Odla inte kål på samma plats på minst 7 år. Allvarlig svampsjukdom som lever kvar."},{name:"Buttoning (dvärgblomning)",symptom:"Plantan bildar ett pyttelitet, för tidigt huvud - ibland bara en liten knopp. Uppstår vid stress.",fix:"Förebyggande: undvik kall chock, ojämn vattning och näringsbrist. Plantera inte ut för tidigt i kall jord. Härda av plantorna ordentligt."},{name:"Lösa/håriga huvuden",symptom:'Huvudet blir löst, grynigt eller "risbukettartat" istället för slätt och kompakt.',fix:"Orsakas oftast av för hög temperatur under huvudbildningen, ojämn vattning eller borbrist. Välj värmetåliga sorter i södra Sverige."},{name:"Missfärgade huvuden",symptom:"Huvudet blir gult, grönt eller brunfläckigt istället för kritvitt.",fix:"Blanchera! Vik de yttre bladen över huvudet så snart det är synligt (2-3 cm). Solljus orsakar missfärgning. Romanesco och Graffiti behöver dock inte blancheras."}],goodToKnow:[{icon:"leaf",title:"Blanchering - blomkåls stora hemlighet",text:"För att få kritvita huvuden måste du blanchera: vik de yttre bladen över det växande huvudet och fäst med en pinne eller gummiband. Utan blanchering blir huvudet gult och lite bittert. Självblancherande sorter finns men ger sällan lika fina resultat.",severity:"tip"},{icon:"warning",title:"Divan bland kålväxter",text:"Blomkål är den svåraste kålväxten att odla. Hon HATAR temperatursvängningar, reagerar på minsta stress med dåliga huvuden och förlåter inga misstag. Men lyckas du? Då har du odlarens stoltaste ögonblick i handen.",severity:"warning"},{icon:"temperature",title:"Temperaturstress = katastrof",text:"Temperaturer över 25°C eller under -2°C under huvudbildningen kan förstöra hela skörden. I södra Sverige kan sensommar-odling (utplantering juni) vara smartare, så huvudbildningen sker i svala september.",severity:"warning"},{icon:"warning",title:"Buttoning - den fruktade dvärgblomningen",text:'Om unga plantor utsätts för kyla (under 10°C i flera dagar) kan de gå i "buttoning" - bildar ett pyttelitet huvud i förtid. Därför: plantera aldrig ut för tidigt! Vänta tills nätterna stadigt är över 8°C.',severity:"warning"},{icon:"harvest",title:"Skörda i rätt ögonblick",text:'Blomkål har ett kort skördefönster. Skörda när huvudet är fast, kompakt och 15-20 cm i diameter - INNAN knopparna börjar separera. Väntar du en dag för länge börjar "riset" synas och texturen blir grov.',severity:"tip"},{icon:"tip",title:"Romanesco - nybörjarens genväg",text:"Vill du odla blomkål men är nervös? Börja med Romanesco! Hon är tåligare, behöver inte blancheras och belönar dig med de mest spektakulära fraktalmönstren i trädgården. Dessutom smakar hon fantastiskt.",severity:"tip"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Blomkål förodlas ALLTID inomhus för att få maximal kontroll över de kritiska tidiga veckorna. Direktsådd fungerar i princip inte - hon behöver en trygg, kontrollerad start för att inte stressa.",steps:["Så 1-2 cm djupt i djupa celler eller krukor, 6-8 veckor före planerad utplantering","Håll jorden runt 18-20°C för snabb groning (5-10 dagar)","Flytta till svalare plats (15-18°C) och starkt ljus direkt när plantorna kommit upp","Gallra till en planta per cell - välj den kraftigaste","Gödsla svagt med flytande gödsel efter 3 veckor (halv dos)","Härda av NOGGRANT i 10-14 dagar före utplantering - blomkål tål inte chock","Plantera ut med 50-60 cm avstånd när plantan har 4-6 riktiga blad och nätterna är över 8°C","Tryck till jorden ordentligt, vattna rikligt och täck gärna med fiberduk direkt"],tips:["Förodla i djupa celler - blomkål gör långa rötter tidigt och trivs inte i grunda krukor","Plantera ALDRIG ut för tidigt! Kyla triggar buttoning (dvärgblomning) och då är säsongen förstörd","Sätt kålkragar runt stjälken vid utplantering för att stoppa kålfluga","Fiberduk är din bästa vän - den skyddar mot både kålfjäril och temperatursvängningar"],indoorWeeks:"6-8 veckor"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Blomkål är tvåårig och måste övervintra för att blomma och sätta frö - en utmaning i Sverige! Hon korsar sig dessutom med ALL annan kål. Frötagning kräver tålamod och planering.",steps:["Välj den finaste plantan med bäst huvud och markera den","Gräv upp plantan med stor jordklump före första hårda frosten","Förvara svalt (0-5°C) över vintern - i jordkällare, garage eller liknande","Plantera ut igen tidigt på våren - hon skjuter en blomstjälk ur det gamla huvudet","Gula korsblomster pollineras av insekter - se till att BARA EN kålsort blommar i närheten","Låt fröskidorna mogna och torka på plantan tills de är bruna och spröda","Klipp av blomstjälkarna och eftertorka i papperspåsar","Krossa skidorna försiktigt och blås bort agnarna"],isolation:"Korsar med ALLA andra Brassica oleracea (broccoli, grönkål, vitkål, brysselkål, kålrabbi). Odla bara en sort för frö, eller isolera med minst 500 m (helst 1 km+).",storageYears:"4-5 år",tip:"De flesta blomkålssorter i handeln är F1-hybrider vars frön INTE ger samma sort. För seriös frötagning, välj öppet pollinerade sorter som Erfurt."},storage:{shelfLife:"1-2 veckor (färsk), upp till 12 månader (fryst)",methods:[{method:"Kylskåp",icon:"snowflake",duration:"1-2 veckor",description:"Förvara hela huvudet i en perforerad plastpåse i grönsakslådan. Tvätta INTE förrän du ska använda. Lämna gärna några yttre blad kvar - de skyddar mot uttorkning.",best:!0},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Dela i buketter, blanchera 3 minuter i saltat vatten, kyl i isvatten. Torka av ordentligt och frys in i portionspåsar. Perfekt för gratänger, soppor och puréer hela vintern.",best:!1},{method:"Pickla",icon:"storage",duration:"3-6 månader",description:"Dela i buketter och lägg i ättikslag med kryddor (senapsfrön, gurkmeja, dill). Picklad blomkål är en fantastisk tillbehörstjärna och håller sig länge i kylskåp.",best:!1},{method:"Torka",icon:"storage",duration:"6-12 månader",description:"Blanchera, skär i småbitar och torka i ugn på 50°C eller i torkmaskin. Bra för soppor och pulver, men texturen blir aldrig som färsk.",best:!1}],tips:["Skörda tidigt på morgonen och lägg direkt i kylskåp - blomkål förlorar kvalitet snabbt i värme","Bruna fläckar på bukettytorna = för gammal eller solskadad. Skär bort och använd resten snabbt.","Blanchera ALLTID före frysning - oblanscherad blomkål förlorar färg, smak och textur","Hela huvudet håller sig bättre än uppdelat - dela först när du ska använda"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3,unit:"kg"}},Nr=Object.freeze(Object.defineProperty({__proto__:null,blomkal:l},Symbol.toStringTag,{value:"Module"})),s={name:"Bondböna",icon:"bondbona",family:"Baljväxter",familyLatin:"Fabaceae",difficulty:"Enkel",difficultyWhy:"Direktsås utomhus, fixar sitt eget kväve, tål frost och kräver minimal omvårdnad. Odlingens arbetshäst.",zones:{outdoor:[1,2,3,4,5,6,7],indoor:null,greenhouse:null},days:"80-100",spacing:"15-20 cm",rowSpacing:"45-60 cm",depth:"5-8 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmar sol per dag. Bondbönan vill ha ljus men gillar inte stekande hetta - hon trivs bäst i sval svensk sommar."},temperature:{min:4,max:25,ideal:"12-18°C",detail:"Gror redan vid 4-5°C och tål frost ner till -5°C. Hon ÄLSKAR kyla och kan sås bland de allra första på våren. Över 25°C stressar hon och tappar blommor."},wind:{level:"Skyddat",detail:"Plantorna blir 80-120 cm höga och tunga av baljor. Utan vindskydd eller stöd faller de omkull - speciellt när baljorna börjar tyngas."}},watering:{need:"Medel",icon:"water",summary:"Bondbönan är ganska torktålig tack vare sin djupa pålrot, men under blomning och baljesättning behöver hon ordentligt med vatten.",phases:[{phase:"Groning (0-2 veckor)",need:"Medel",tip:"Vattna ordentligt vid sådd - de stora fröna behöver mycket fukt för att svälla och gro. Håll jorden fuktig men inte dränkt."},{phase:"Tillväxt (2-6 veckor)",need:"Låg",tip:"Bondbönan klarar sig bra på naturlig nederbörd nu. Pålroten söker sig djupt och hittar vatten på egen hand."},{phase:"Blomning (6-10 veckor)",need:"Hög",tip:"Kritisk period! Vattenstress nu betyder att blommorna faller av utan att sätta baljor. Vattna djupt 2-3 gånger i veckan om det inte regnar."},{phase:"Baljesättning (10+ veckor)",need:"Medel",tip:"Fortsätt vattna regelbundet. Baljorna fyller på med stora bönor - de behöver vatten och näring för att bli tjocka och fina."}],mistakes:["Glömmer vattna under blomning - den absolut viktigaste perioden för skörd","Övervattnar tidigt i kall jord - kan ge rotröta innan plantan kommit igång","Vattnar ovanifrån sent på dagen - fuktiga blad inbjuder chokladfläcksjuka"],tip:"Mulcha runt plantorna med gräsklipp eller halm efter uppkomst. Det håller fukten jämn, håller jorden sval och minskar ogräs - tre flugor i en smäll."},soil:"Trivs i de flesta jordtyper - lera, sand, mylla. Viktigast är att jorden inte är vattensjuk. Gillar kalkrik jord.",soilTips:["Kalka om pH är under 6 - bondbönan vill ha neutral till svagt basisk jord","Inget extra kväve behövs - hon fixar sitt eget via Rhizobium-bakterier på rötterna","Tung lerjord funkar faktiskt bra - bondbönan har kraft att ta sig igenom"],timeline:{1:[{phase:"Direktså",months:"Mar-Apr",icon:"seedling"},{phase:"Stöd/kupa",months:"Maj",icon:"support"},{phase:"Blomning",months:"Maj-Jun",icon:"flower"},{phase:"Toppa (mot bladlöss)",months:"Jun",icon:"scissors"},{phase:"Skörd färska",months:"Jul",icon:"harvest"},{phase:"Skörd torra",months:"Aug-Sep",icon:"harvest"}],4:[{phase:"Direktså",months:"Apr-Maj",icon:"seedling"},{phase:"Stöd/kupa",months:"Maj-Jun",icon:"support"},{phase:"Blomning",months:"Jun-Jul",icon:"flower"},{phase:"Toppa (mot bladlöss)",months:"Jul",icon:"scissors"},{phase:"Skörd färska",months:"Aug",icon:"harvest"},{phase:"Skörd torra",months:"Sep",icon:"harvest"}],6:[{phase:"Direktså",months:"Maj",icon:"seedling"},{phase:"Stöd/kupa",months:"Jun",icon:"support"},{phase:"Blomning",months:"Jul",icon:"flower"},{phase:"Toppa (mot bladlöss)",months:"Jul",icon:"scissors"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:5,P:15,K:10,label:"Groning"},{month:"Maj",N:10,P:25,K:20,label:"Tillväxt"},{month:"Jun",N:10,P:45,K:35,label:"Blomning"},{month:"Jul",N:8,P:55,K:60,label:"Baljesättning"},{month:"Aug",N:5,P:35,K:50,label:"Mognad"},{month:"Sep",N:3,P:20,K:30,label:"Skörd"}],nutritionTips:[{timing:"Vid sådd",tip:"Inget kväve! Bondbönan fixar sitt eget via Rhizobium-bakterier. Ge lite benmjöl eller stenfosfat för fosfor."},{timing:"Blomning",tip:"En lätt giva kaliumrik gödsel (vedaska eller alggödsel) stärker blomningen och hjälper baljorna att fyllas."},{timing:"Under säsongen",tip:"Bondbönan är extremt anspråkslös - hon ger mer till jorden än hon tar. Det är hennes superkraft."},{timing:"Efter skörd",tip:"Klipp av plantan vid markytan men LÅT RÖTTERNA SITTA KVAR. Kvävebakterierna fortsätter gödsla jorden åt nästa gröda - gratis!"}],companions:{good:[{id:"potatis",name:"Potatis",icon:"potatis",why:"Potatisen älskar det kväve bondbönan fixar i jorden - de är drömgrannar"},{id:"morot",name:"Morot",icon:"morot",why:"Morötter luckrar jorden nedåt medan bondbönan ger kväve - perfekt samarbete"},{id:"squash",name:"Squash",icon:"squash",why:"Squash breder ut sig vid marken och håller fukten medan bondbönan växer rakt upp - de delar utrymmet smart"}],bad:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökväxter hämmar bönornas kvävefixering - de saboterar bondbönans bästa superkraft"},{id:"vitlok",name:"Vitlök",icon:"vegetable",why:"Samma problem som lök - alliumväxter och baljväxter trivs inte ihop"}]},rotation:{avoid:[{id:"artor",name:"Ärtor"},{id:"brytbona",name:"Brytböna"},{id:"storbona",name:"Störböna"}],avoidWhy:"Alla baljväxter delar sjukdomar som chokladfläcksjuka och rotröta. Vänta minst 4 år innan du sår baljväxter på samma plats.",goodBefore:[{id:"potatis",name:"Potatis"},{id:"squash",name:"Squash"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Potatisens luckring och lökens sanering gör jorden redo. Squash efter potatis fungerar också bra.",goodAfter:[{name:"Kål"},{id:"sallat",name:"Sallat"},{id:"squash",name:"Squash"}],goodAfterWhy:"Kvävehungriga grödor som kål, sallat och squash älskar jorden efter bondböna - den är fullpumpad med kväve."},varieties:[{name:"Witkiem",zones:[1,2,3,4,5,6,7],note:"Tidig sort, perfekt för kortare säsonger. Ger skörd redan efter 9-11 veckor."},{name:"Hangdown Grünkernig",zones:[1,2,3,4,5,6,7],note:"Klassikern. Pålitlig, hög avkastning, gröna kärnor som behåller färgen vid tillagning. Kulturarvssort."},{name:"Karmazyn",zones:[1,2,3,4,5,6],note:"Polsk sort med vackert rosa bönor som mörknar till rödbrunt vid torkning. Ovanlig och dekorativ."},{name:"Superaguadulce",zones:[1,2,3,4,5],note:"Medelhavsjätte - mycket stora baljor med 5-7 bönor per balja. Tidig och härdig."}],problems:[{name:"Svarta bladlöss",symptom:"Massiva kolonier av svarta löss på toppskott och unga baljor",fix:"Klipp bort de översta 10 cm av plantan när de nedersta baljorna börjat sätta - det tar bort lössens favoritställe OCH ger bättre skörd. Klassiskt bondetrick!"},{name:"Chokladfläcksjuka",symptom:"Bruna-svarta fläckar på blad och stjälkar, kan sprida sig till baljorna",fix:"God luftcirkulation - inte för tätt. Ta bort drabbade blad. Växtföljd (4 år). Undvik att vattna ovanifrån."},{name:"Bönsmyg",symptom:"Små hål i torkade bönor, larver inuti",fix:"Frys torkade bönor i 48 timmar innan lagring - det dödar ägg och larver. Samodla med kryddväxter som avskräcker."},{name:"Rost",symptom:"Orange-bruna pustlar på bladens undersida",fix:"Ta bort drabbade blad. Se till att plantorna har god ventilation. Vanligast sent i säsongen - baljorna hinner oftast mogna ändå."}],goodToKnow:[{icon:"leaf",title:"Kvävefixerare - gratis gödsel",text:"Bondbönan är odlingens arbetshäst - hon fixar sitt eget kväve OCH ger fantastisk mat. Klipp av plantan vid skörd men lämna rötterna kvar i jorden. Nästa gröda tackar dig.",severity:"tip"},{icon:"scissors",title:"Toppa mot bladlöss",text:"Svarta bladlöss är bondbönans eviga följeslagare. Det klassiska tricket: klipp av de översta 10 cm när de nedersta baljorna satt frukt. Du tar bort lössen OCH skickar energin till baljorna. Topparna kan du äta som grönsak!",severity:"tip"},{icon:"snowflake",title:"En av de allra tidigaste",text:"Bondbönan gror redan vid 4-5°C och tål frost ner till -5°C. I zon 1 kan du så redan i mars - hon bryr sig inte om att det fortfarande är vinter.",severity:"tip"},{icon:"flower",title:"Blommorna är magiska",text:"Bondbönans svartvita blommor doftar fantastiskt och humlorna ÄLSKAR dem. En av de bästa pollineringsvännerna du kan ha i trädgården.",severity:"tip"},{icon:"warning",title:"Lök och vitlök är fiender",text:"Alla lökväxter hämmar bondbönans kvävefixering. Håll dem åtskilda i odlingen - annars förlorar du bondbönans bästa superkraft.",severity:"warning"},{icon:"warning",title:"Höga plantor behöver stöd",text:"Bondbönan kan bli över en meter hög och tyngs av tunga baljor. Kupa jord runt basen och sätt stöd (käppar med snöre) när plantorna är 30 cm. Annars ligger de platt efter första regnet.",severity:"warning"}],sowing:{method:"direct",label:"Direktsådd",description:"Bondbönan sås direkt på friland - hon har en kraftig pålrot som inte vill bli störd. De stora fröna är lätthanterliga och gör sådd till en barnlek.",steps:["Blötlägg fröna i vatten över natten (8-12 timmar) - de gror snabbare och jämnare","Gör hål 5-8 cm djupa med en pinne eller planteringspinne (ja, de ska djupt!)","Lägg ett frö per hål med 15-20 cm avstånd","Täck med jord och tryck till ordentligt","Vattna genomgående - de stora fröna behöver mycket fukt","Sätt stöd (käppar med snöre) redan nu eller när plantorna är 20-30 cm"],tips:["Så i dubbla rader med 20 cm mellanrum och stödet emellan - stabilt och platseffektivt","De stora fröna är perfekta för barn att så - lätt att hantera och snabb groning","I zon 1-3 kan du så redan i mars om marken inte är frusen - bondbönan bryr sig inte om kylan"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Delvis självpollinerare",biennial:!1,description:"Bondbönan är delvis självpollinerare men humlor hjälper gärna till med korspollination. Enkel att spara frö från - låt baljorna torka på plantan.",steps:["Välj de finaste plantorna och märk dem tidigt - plocka INTE baljor från dessa","Låt baljorna sitta kvar tills de är helt svarta och torra på plantan","Bryt av baljorna och lägg dem på tidningspapper inomhus i en vecka","Bryt upp baljorna och plocka ut bönorna","Frys bönorna i 48 timmar för att döda eventuella bönsmygslarver","Torka ytterligare en vecka och förvara i papperspåse eller glasburk"],isolation:"Delvis självpollinerare men humlor korsar gärna olika sorter. Odla bara en sort för frö, eller isolera med minst 500 m.",storageYears:"3-5 år",tip:"Torkade bondbönor håller sig fantastiskt länge. Förvara svalt och torrt - de är som en liten fröbank i din garderob."},storage:{shelfLife:"3-5 dagar (färska) / flera år (torkade)",methods:[{method:"Färska i kylskåp",icon:"snowflake",duration:"3-5 dagar",description:"Skörda när baljorna är fyllda men bönorna fortfarande gröna och mjuka. Lägg i plastpåse i kylskåp. Ät så snart som möjligt - smaken är bäst dagsfärsk.",best:!0},{method:"Frysa (bästa långtidslagring)",icon:"snowflake",duration:"8-12 månader",description:"Skala ur baljorna, blanchera 2-3 minuter, kyl i isvatten. Klam av det tunna skinnet (det vita skalet runt varje böna) och frys in. Skinnet gör dem bittra.",best:!1},{method:"Torka",icon:"sun",duration:"2-5 år",description:"Låt baljorna torka helt på plantan tills de är svarta och skramlar. Plocka ur bönorna och torka ytterligare. Torkade bondbönor håller i åratal och är perfekta till soppor och grytor.",best:!1},{method:"Torka och mala",icon:"storage",duration:"1-2 år",description:"Torkade bondbönor kan malas till mjöl - bondbönsmjöl. Proteinrikt och glutenfritt. Blanda med vanligt mjöl i bröd.",best:!1}],tips:["Färska bondbönor är en HELT annan grönsak än torkade - pröva båda!","Det tunna vita skinnet runt varje böna kan skalas bort - det ger en mildare, len smak och vackert grön färg","Torkade bönor behöver blötläggas 12 timmar och kokas 45-60 minuter","Frys torkade bönor i 48 timmar innan långtidslagring - det dödar eventuella bönsmygslarver"]},harvestCalc:{minPerSqm:1,maxPerSqm:2,unit:"kg"}},Jr=Object.freeze(Object.defineProperty({__proto__:null,bondbona:s},Symbol.toStringTag,{value:"Module"})),o={name:"Broccoli",icon:"broccoli",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Medel",difficultyWhy:"Broccoli kräver rätt timing - du måste skörda huvudet innan blommorna öppnar sig, annars är det kört. Hon vill ha jämn fukt, mycket näring och trivs inte i hetta.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:[1,2,3,4,5,6,7,8]},days:"60-90",spacing:"40-50 cm",rowSpacing:"50-60 cm",depth:"1-2 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmar sol per dag. I halvskugga blir huvudena mindre och lösare. Broccoli vill ha ordentligt med ljus för att bygga fina, täta buketter."},temperature:{min:-3,max:25,ideal:"15-20°C",detail:"Broccoli är en sval dam - hon gillar temperaturer runt 15-20°C allra bäst. Över 25°C stressar hon och börjar blomma i panik. Tål lätt frost ner till -3°C, men unga plantor bör skyddas."},wind:{level:"Skyddat",detail:"Broccoli har tunga huvuden på relativt klena stjälkar. I blåsiga lägen kan plantorna luta sig eller till och med knäckas. Ge henne lite vindskydd eller kupa jord runt stambasen."}},watering:{need:"Medel-Hög",icon:"water",summary:'Broccoli vill ha jämn fukt hela säsongen. Ojämn vattning ger små, lösa huvuden eller gör att hon börjar blomma i förtid. Tänk "aldrig torrt, aldrig sjö".',phases:[{phase:"Groning/förodling (0-3 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig men inte blöt. Kålfrön gror snabbt (5-8 dagar) om de får fukt och värme."},{phase:"Etablering (3-6 veckor)",need:"Hög",tip:"Nyutplanterade plantor behöver extra omsorg. Vattna dagligen i varmt väder tills rötterna etablerat sig."},{phase:"Tillväxt (6-10 veckor)",need:"Medel-Hög",tip:"Djupvattna 2-3 gånger i veckan. Nu bygger hon huvudet och varje dag utan vatten syns i resultatet."},{phase:"Huvudbildning och skörd",need:"Hög",tip:"Kritisk period! Jämn fukt nu är avgörande. Ojämn vattning ger ihåliga stjälkar och lösa, gryniga huvuden."}],mistakes:["Ojämn vattning - torka följt av storvattning ger ihåliga stjälkar och lösa huvuden","Vattna ovanifrån sent på dagen - fuktiga blad över natten bjuder in svampsjukdomar","Tro att broccoli klarar sig som grönkål - hon behöver faktiskt mer vatten","Glömma att vattna under huvudbildningen - det är som att sluta gödsla tomater när de sätter frukt"],tip:"Mulcha ordentligt runt plantorna med gräsklipp eller halm. Det håller jorden jämnt fuktig och sval - precis som broccoli vill ha det. En 5 cm tjock mulch gör underverk."},soil:"Näringsrik, kalkrik jord med bra dränering. Broccoli är en storätare som vill ha ordentlig matjord - tänk kompostrik, lucker och inte för sur.",soilTips:["Blanda in rikligt med brunnen kompost och gärna lite hönsgödsel innan plantering","Kalka på hösten om pH är under 6.0 - broccoli gillar kalkrik jord och det skyddar mot klumprotsjuka","Undvik packad lerjord - luckra djupt och blanda in sand eller kompost för bättre struktur"],timeline:{1:[{phase:"Förodla inomhus",months:"Feb-Mar",icon:"seedling"},{phase:"Plantera ut",months:"Apr-Maj",icon:"leaf"},{phase:"Gödsla",months:"Maj-Jun",icon:"water"},{phase:"Huvudskörd",months:"Jun-Jul",icon:"harvest"},{phase:"Sidoskott",months:"Jul-Sep",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj",icon:"leaf"},{phase:"Gödsla",months:"Jun",icon:"water"},{phase:"Huvudskörd",months:"Jul-Aug",icon:"harvest"},{phase:"Sidoskott",months:"Aug-Sep",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Maj",icon:"seedling"},{phase:"Plantera ut",months:"Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Huvudskörd",months:"Aug-Sep",icon:"harvest"},{phase:"Sidoskott",months:"Sep-Okt",icon:"harvest"}]},nutritionData:[{month:"Apr",N:25,P:15,K:10,label:"Förodling"},{month:"Maj",N:50,P:25,K:15,label:"Utplantering"},{month:"Jun",N:80,P:35,K:25,label:"Kraftig tillväxt"},{month:"Jul",N:90,P:45,K:40,label:"Huvudbildning"},{month:"Aug",N:60,P:40,K:50,label:"Skörd/sidoskott"},{month:"Sep",N:30,P:25,K:35,label:"Sena sidoskott"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla med brunnen kompost och hornmjöl. Broccoli vill ha kväverik start för att bygga bladmassa."},{timing:"Tre veckor efter utplantering",tip:"Ge flytande nässelvatten eller alggödsel. Hon ska vara i full gång nu och behöver bränsle."},{timing:"Vid huvudbildning",tip:"Extra giva med kaliumrik gödsel (vedaska eller alggödsel). Nu bygger hon buketterna och behöver kalium för täthet och smak."},{timing:"Efter huvudskörd",tip:"Ge en lätt kvävegiva för att putta igång sidoskotten. Nässelvatten varannan vecka räcker."}],companions:{good:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft förvirrar kålfjärilen - broccolis värsta fiende. Ett klassiskt försvar."},{id:"dill",name:"Dill",icon:"herb",why:"Lockar parasitsteklar som äter kålfjärilens larver. Dill är broccolis personliga livvakt."},{id:"rodbeta",name:"Rödbeta",icon:"vegetable",why:"Tar näring från ett annat djup i jorden - de konkurrerar inte, utan kompletterar varandra."},{id:"persilja",name:"Persilja",icon:"herb",why:"Doften avskräcker flera skadedjur och persiljan trivs i broccolis halvskugga."}],bad:[{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Jordgubbar hämmas av kålväxter. De trivs inte alls ihop - håll dem åtskilda."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Båda är storätare som slåss om samma näring. Ingen av dem blir glad."},{name:"Andra kålväxter",icon:"vegetable",why:"Odla inte broccoli bredvid annan kål - de delar skadedjur och sjukdomar och förstärker problemen."}]},rotation:{avoid:[{id:"gronkal",name:"Grönkål"},{id:"blomkal",name:"Blomkål"},{id:"vitkal",name:"Vitkål"},{id:"rodkal",name:"Rödkål"},{id:"brysselkal",name:"Brysselkål"},{id:"kalrabbi",name:"Kålrabbi"},{id:"radisa",name:"Rädisa"},{id:"pak-choi",name:"Pak choi"}],avoidWhy:"Alla tillhör korsblommiga och delar sjukdomar som klumprotsjuka och kålbråck. Vänta minst 4 år innan du odlar kål på samma plats igen!",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"potatis",name:"Potatis"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden - gratis gödsel för hungriga broccoli. Potatis och lök lämnar ren, bearbetad jord.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"sallat",name:"Sallat"},{id:"rodbeta",name:"Rödbeta"}],goodAfterWhy:"Rotgrönsaker trivs i den djupt bearbetade, näringsrika restjorden. Sallat gillar kvävet som kål lämnar efter sig."},varieties:[{name:"Ramoso Calabrese",zones:[1,2,3,4,5],note:"Den klassiska italienska sorten. Öppenpollinerad med rikliga sidoskott - skördar i veckor! Finns hos Impecta och Lindbloms."},{name:"Rasmus",zones:[1,2,3,4,5,6],note:"OP-sort (Kultursaat, Tyskland) med stora huvuden (~20 cm) och ihålighetsfria stjälkar. Rikliga sidoskott långt in på hösten. Ekofrö hos Runåbergs."},{name:"De Cicco",zones:[1,2,3,4,5],note:"Gammal italiensk kulturarvssort, introducerad i USA 1890. Många sidoskott och öppenpollinerad - perfekt för frösparing."},{name:"Marathon F1",zones:[1,2,3,4,5,6],note:"F1-hybrid som är tålig och sjukdomsresistent. Perfekt för den som vill ha ett säkert kort. Kompakta, fina huvuden."},{name:"Atlantis F1",zones:[1,2,3,4,5,6],note:"F1-hybrid med stora huvuden och bra sidoskott efter huvudskörd. Finns hos Wexthuset."}],problems:[{name:"Kålfjäril",symptom:"Gröna larver som maler genom bladen. Gröna spillningshögar på och runt bladen.",fix:"Fiberduk från dag ett! Handplocka larver. Spruta med Bacillus thuringiensis (Bt). Samodla med dill och lök för att förvirra fjärilarna."},{name:"Kålfluga",symptom:"Plantan vissnar trots vattning, rötterna är angripna av vita larver.",fix:"Kålkragar runt stjälken vid utplantering - de hindrar flugan från att lägga ägg. Fiberduk hjälper också."},{name:"Klumprotsjuka",symptom:"Plantan stannar i tillväxt och vissnar. Rötterna har klumpiga, svullna utväxter.",fix:"Ingen bot - dra upp och bränn! Kalka jorden ordentligt. Odla inte kål på samma plats på minst 7 år. Allvarlig svampsjukdom."},{name:"Lösa/gryniga huvuden",symptom:"Huvudet blir löst, ojämnt eller grynigt istället för tätt och fint.",fix:"Ofta orsakat av ojämn vattning, näringsbrist eller för hög temperatur. Håll jämn fukt och gödsla regelbundet. Välj sorter anpassade för din zon."}],goodToKnow:[{icon:"warning",title:"Skörda INNAN blommorna öppnas!",text:"Det här är broccolis gyllene regel. När de gula blommorna börjar synas i buketterna är det för sent - smaken blir bitter och texten grov. Skörda när knopparna fortfarande är tätt slutna.",severity:"warning"},{icon:"harvest",title:"Sidoskotten är bonusen",text:"Skär huvudet snett (så vatten rinner av) och lämna plantan kvar. Inom en-två veckor dyker mindre sidoskott upp i bladvecken. De kan ge skörd i veckor!",severity:"tip"},{icon:"warning",title:"Broccoli hatar hetta",text:'Temperaturer över 25°C stressar broccoli och hon kan gå i blom i panik - så kallad "bolting". I södra Sverige kan det vara smart att odla som höstgröda med plantering i juni-juli.',severity:"warning"},{icon:"leaf",title:"Stjälken är också mat!",text:"Släng aldrig stjälken! Skala bort det yttre hårda lagret och du hittar ett krispigt, milt hjärta inuti. Strimla tunt och ät rå i sallad eller stek i wok.",severity:"tip"},{icon:"seedling",title:"Morgonskörd ger bäst kvalitet",text:"Skörda broccoli tidigt på morgonen medan det fortfarande är svalt. Huvudena är då fyllda med vatten och håller sig fräscha mycket längre. Lägg direkt i kylskåp.",severity:"tip"},{icon:"warning",title:"Klumprotsjuka - kålens mardröm",text:"Odla aldrig kålväxter på samma plats oftare än var 4:e år. Klumprotsjuka lever i jorden i 7+ år och det finns inget botemedel. Kalka ordentligt - svampen trivs i sur jord.",severity:"warning"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Broccoli förodlas nästan alltid inomhus för att få ett försprång. Direktsådd fungerar i zon 1-3 men ger sen skörd. Förodling ger dig kontroll över timingen - och timing är allt med broccoli.",steps:["Så 1-2 cm djupt i celler eller krukor, 5-6 veckor före planerad utplantering","Håll jorden runt 18-20°C för snabb groning (5-8 dagar)","Flytta till svalare plats (15°C) och starkt ljus när plantorna kommit upp","Gallra till en planta per cell om du sått flera frön","Härda av plantorna 7-10 dagar innan utplantering - ställ ut dagtid, in på natten","Plantera ut med 40-50 cm avstånd när plantan har 4-6 riktiga blad","Tryck till jorden ordentligt och vattna rikligt vid utplantering"],tips:["Förodla i djupa celler - broccoli gör långa rötter och trivs inte i grunda krukor","Plantera inte ut för tidigt! Kyla kan trigga tidig blomning. Vänta tills nätterna stadigt är över 5°C.","Sätt kålkragar runt stjälken direkt vid utplantering för att skydda mot kålfluga"],indoorWeeks:"5-6 veckor"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!0,description:"Broccoli är en svag tvååring - i Sverige behöver hon oftast övervintra för att sätta frö. I mildare zoner kan hon ibland slutföra cykeln på en säsong om du startar tidigt. Hon korsar sig med ALL annan kål!",steps:["Välj den finaste, friskaste plantan och låt den stå kvar efter skörd","Sidoskotten utvecklar gula blommor - insekter pollinerar dem","Se till att bara EN sort av kål blommar i närheten","Låt fröskidorna mogna och torka på plantan tills de är bruna och spröda","Klipp av hela blomstjälkarna och lägg dem i en papperspåse för eftertorkning","Krossa skidorna försiktigt och blås bort agnarna","Förvara i märkta påsar, svalt och torrt"],isolation:"Korsar med ALLA andra Brassica oleracea (grönkål, blomkål, vitkål, brysselkål, kålrabbi). Odla bara en sort för frö, eller isolera med minst 500 m (helst 1 km+).",storageYears:"3-4 år",tip:"De flesta populära broccolisorter är F1-hybrider - deras frön ger INTE samma sort. För frötagning, välj öppet pollinerade sorter som Ramoso Calabrese, De Cicco eller Rasmus."},storage:{shelfLife:"3-5 dagar (färsk), upp till 12 månader (fryst)",methods:[{method:"Kylskåp",icon:"snowflake",duration:"3-5 dagar",description:"Lägg i en plastpåse med några hål i grönsakslådan. Tvätta INTE förrän du ska använda - fukt på buketterna gör att de ruttnar snabbare. Skörda på morgonen för bäst hållbarhet.",best:!0},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Dela i buketter, blanchera 2-3 minuter, kyl i isvatten. Torka av ordentligt och frys in i portionspåsar. Perfekt för grytor, wok och soppor hela vintern.",best:!1},{method:"Torka",icon:"storage",duration:"6-12 månader",description:"Blanchera, skär i småbitar och torka i ugn på 50°C eller i torkmaskin. Blir knaprigt och kompakt. Bra för soppor och pulver.",best:!1},{method:"Fermentera",icon:"storage",duration:"2-6 månader",description:"Dela i buketter, lägg i saltlake (2% salt). Fermenterad broccoli är oväntat god och full av nyttiga bakterier. Prova det!",best:!1}],tips:["Skörda på morgonen och lägg direkt i kylskåp - broccoli förlorar näring och smak snabbt i värme","Gula fläckar på buketterna = blommorna börjar öppnas. Ät genast, den väntar inte!","Blanchera ALLTID före frysning. Oblanscherad broccoli förlorar färg, smak och näring i frysen.","Stjälken håller sig längre än buketterna - skala och förvara den separat"]},harvestCalc:{minPerSqm:.8,maxPerSqm:1.5,unit:"kg"}},Rr=Object.freeze(Object.defineProperty({__proto__:null,broccoli:o},Symbol.toStringTag,{value:"Module"})),d={name:"Brysselkål",icon:"brysselkal",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Medel",difficultyWhy:"Brysselkål kräver tålamod - hon tar sin tid (120-180 dagar!) och vill ha näringsrik jord, stadigt stöd och jämn fukt. Men ger du henne det belönar hon dig med de godaste små kålhuvudena du kan tänka dig, särskilt efter första frosten.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:null},days:"120-180",spacing:"50-60 cm",rowSpacing:"60-70 cm",depth:"1 cm",ph:{min:6.5,max:7.5,ideal:7},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmar sol per dag. I halvskugga blir skotten lösa och små - brysselkål vill ha ordentligt med ljus för att bygga täta, fina små huvuden längs stammen."},temperature:{min:-10,max:25,ideal:"15-18°C",detail:"Brysselkål är en riktig nordbo som trivs bäst i svalka, runt 15-18°C. Hon är extremt frosttålig - ner till -10°C! - och smaken blir faktiskt BÄTTRE efter frost. Över 25°C stressar hon och skotten blir lösa och bittra."},wind:{level:"Skyddat",detail:"Brysselkål blir en hög planta (60-90 cm) med tung last av skott längs stammen. Ge henne vindskydd eller en stödkäpp så hon inte blåser omkull när höststormarna drar in."}},watering:{need:"Medel-Hög",icon:"water",summary:"Brysselkål vill ha jämn fukt hela den långa säsongen. Ojämn vattning ger lösa, dåliga skott - och det vill vi inte efter månader av väntan.",phases:[{phase:"Förodling (0-6 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig men inte blöt. Kålfrön gror snabbt (5-10 dagar) vid rumstemperatur."},{phase:"Etablering (utplantering)",need:"Hög",tip:"Vattna rikligt vid utplantering och dagligen den första veckan. Tryck till jorden ordentligt runt stammen - hon ska stå stadigt!"},{phase:"Tillväxt och stambildning",need:"Medel-Hög",tip:"Djupvattna 2-3 gånger i veckan. Nu bygger hon den långa stammen och alla bladveck där skotten ska bildas."},{phase:"Skottbildning (sensommar-höst)",need:"Hög",tip:"Kritisk period! Jämn fukt nu avgör om skotten blir täta och fina. Sluta inte vattna bara för att hösten kommer - hon behöver det ända till skörd."}],mistakes:["Ojämn vattning - torka följt av storvattning ger lösa, dåliga skott. Brysselkål vill ha jämn fukt hela vägen.","Ge upp vattningen på hösten - hon bildar skott ända in i november och behöver fukt hela tiden","Vattna ovanifrån sent på kvällen - fuktiga blad i mörkret bjuder in svampsjukdomar","Tro att hon klarar sig själv bara för att hon ser stor och tålig ut - speciellt under skottbildningen är hon känslig"],tip:"Mulcha ordentligt med gräsklipp eller halm runt stambasen. Det håller jorden fuktig och sval under den långa odlingssäsongen, och minskar ogräset som annars tar näring från din hungriga brysselkål."},soil:"Näringsrik, kalkrik, fast jord. Brysselkål vill ha stadigt fäste - inte för lös jord! Hon blir hög och tung, så jorden måste hålla henne på plats.",soilTips:["Kalka på hösten om pH är under 6.5 - brysselkål ÄLSKAR kalkrik jord och det skyddar mot klumprotsjuka","Blanda in rikligt med brunnen kompost och gärna hönsgödsel. Brysselkål är en storätare som ska växa i 5-6 månader.","Undvik för lös, nygrävd jord - hon behöver fast mark att stå i. Trampa gärna till lite runt plantan efter utplantering."],timeline:{1:[{phase:"Förodla inomhus",months:"Mar",icon:"seedling"},{phase:"Plantera ut",months:"Maj",icon:"leaf"},{phase:"Gödsla",months:"Maj-Jul",icon:"water"},{phase:"Toppa plantan",months:"Aug-Sep",icon:"leaf"},{phase:"Skörd",months:"Sep-Nov",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj-Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Toppa plantan",months:"Sep",icon:"leaf"},{phase:"Skörd",months:"Okt-Dec",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Plantera ut",months:"Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Aug",icon:"water"},{phase:"Toppa plantan",months:"Sep-Okt",icon:"leaf"},{phase:"Skörd",months:"Okt-Dec",icon:"harvest"}]},nutritionData:[{month:"Mar",N:15,P:10,K:10,label:"Förodling"},{month:"Apr",N:25,P:15,K:10,label:"Tillväxtstart"},{month:"Maj",N:55,P:25,K:20,label:"Utplantering"},{month:"Jun",N:75,P:35,K:25,label:"Stamtillväxt"},{month:"Jul",N:85,P:40,K:35,label:"Kraftig tillväxt"},{month:"Aug",N:70,P:35,K:45,label:"Skottbildning startar"},{month:"Sep",N:50,P:30,K:50,label:"Skotten mognar"},{month:"Okt",N:25,P:20,K:40,label:"Skörd nedifrån"},{month:"Nov",N:10,P:10,K:25,label:"Sista skörden"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla med brunnen kompost och hornmjöl. Brysselkål ska växa i 5-6 månader och behöver en kväverik start för att bygga en kraftig stam."},{timing:"Tre veckor efter utplantering",tip:"Ge flytande nässelvatten eller alggödsel. Nu ska hon börja bygga höjd och bladmassa på allvar."},{timing:"Midsommar",tip:"En extra giva med allroundgödsel. Nu ökar tempot och hon behöver bränsle för alla de små skott som snart ska bildas i bladvecken."},{timing:"Sensommar (skottbildning)",tip:"Extra kalium (vedaska eller alggödsel) stärker skotten och förbättrar smaken. Minska kvävet nu - för mycket kväve ger lösa skott."}],companions:{good:[{id:"selleri",name:"Selleri",icon:"vegetable",why:"Sellerins starka doft maskerar brysselkålen för kålfjärilen. De trivs bra ihop och kompletterar varandra fint."},{id:"dill",name:"Dill",icon:"herb",why:"Lockar parasitsteklar som äter kålfjärilens larver. Dillen jobbar som brysselkålens personliga livvakt."},{id:"rodbeta",name:"Rödbeta",icon:"vegetable",why:"Tar näring från ett annat djup i jorden - de konkurrerar inte utan kompletterar varandra."},{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft förvirrar kålfjärilen. Ett klassiskt och beprövat kompanjonskap."}],bad:[{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Jordgubbar hämmas av kålväxter. De trivs verkligen inte ihop - håll dem åtskilda."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Båda är storätare som slåss om samma näring. Ingen av dem blir nöjd med den dealen."},{name:"Andra kålväxter",icon:"vegetable",why:"Odla inte brysselkål bredvid annan kål - de delar skadedjur och sjukdomar och förstärker problemen."}]},rotation:{avoid:[{id:"vitkal",name:"Vitkål"},{id:"gronkal",name:"Grönkål"},{id:"blomkal",name:"Blomkål"},{id:"broccoli",name:"Broccoli"},{id:"rodkal",name:"Rödkål"},{id:"kalrabbi",name:"Kålrabbi"},{id:"radisa",name:"Rädisa"},{id:"pak-choi",name:"Pak choi"}],avoidWhy:"Alla tillhör korsblommiga och delar sjukdomar som klumprotsjuka. Vänta minst 6 år innan du odlar kål på samma plats igen. Klumprotsjuka lever kvar i jorden extremt länge.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden - gratis gödsel för hungriga brysselkål! Perfekt förfrukt.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"sallat",name:"Sallat"}],goodAfterWhy:"Rotgrönsaker trivs i den djupt bearbetade, näringsrika restjorden efter kål. Sallat gillar kvävet som brysselkålen lämnar efter sig."},varieties:[{name:"Groninger",zones:[1,2,3,4,5],note:"Klassisk OP-sort med pålitlig skörd och fin smak. Blir gärna 70-80 cm hög med jämna, fasta skott. Ekofrö hos Runåbergs."},{name:"Long Island",zones:[1,2,3,4,5],note:"Kompakt OP-kultursort från 1890. Passar bra i mindre trädgårdar med tätt sittande skott. Finns hos Impecta."},{name:"Rubine",zones:[1,2,3,4],note:"Vacker röd/lila OP-kultursort som ger färg på tallriken. Unik smak och hög i antocyaniner. Kan stå ute hela vintern under snötäcke. Runåbergs."},{name:"Igor F1",zones:[1,2,3,4,5],note:"F1-hybrid med mycket jämna skott och god sjukdomsresistens. Bra val i tuffa zoner där du behöver lite extra säkerhet. Finns hos Nelson Garden. OBS: F1 - ger inte äkta avkomma vid frötagning."}],problems:[{name:"Kålfjäril",symptom:"Gröna larver som tuggar hål i bladen. Lämnar gröna spillningshögar och kan förstöra bladverket som plantan behöver för att bygga skott.",fix:"Fiberduk från dag ett - det enda helt säkra skyddet! Handplocka larver regelbundet. Spruta med Bacillus thuringiensis (Bt) mot larverna. Samodla med dill och lök för att förvirra fjärilarna."},{name:"Kålfluga",symptom:"Plantan vissnar trots vattning. Rötterna är fulla av vita larver som äter sig igenom rotsystemet.",fix:"Kålkragar runt stjälken vid utplantering - hindrar flugan från att lägga ägg vid stambasen. Fiberduk hjälper också. Kraftiga plantor klarar lättare angrepp."},{name:"Klumprotsjuka",symptom:"Plantan stannar i tillväxt och vissnar i värme. Rötterna har fula, klumpiga svullnader. Kålodlarens mardröm.",fix:"Ingen bot - dra upp och bränn angripna plantor! Kalka jorden ordentligt (pH över 7). Odla inte kål på samma plats på minst 6 år. Svampen överlever i jorden extremt länge."},{name:"Lösa skott",symptom:"Skotten blir lösa och bladiga istället för täta och fasta. Ser ut som små öppna rosor istället för miniatyrkålhuvuden.",fix:"Oftast orsakat av för hög värme eller för lite ljus. Se till att plantan står i full sol. Toppa plantan (knip av toppen) i september - det tvingar energin ner i skotten. Minska kväve och öka kalium under skottbildningen."},{name:"Kålmal och jordloppor",symptom:"Kålmalen gör små hål i bladen, jordloppor gnager runda hål i unga plantor. Värst i varmt, torrt väder.",fix:"Fiberduk är bästa skyddet. Håll jorden fuktig - jordloppor avskyr fukt. Pudra med stenmjöl eller vedaska. Starka, välgödda plantor klarar angrepp bättre."}],goodToKnow:[{icon:"harvest",title:"Frost gör henne GODARE",text:"Brysselkål är extremt frosttålig (ner till -10°C!) och smaken blir faktiskt fantastiskt mycket bättre efter frost. Stärkelseinnehållet omvandlas till socker i kylan. Vänta med skörden till efter första frostnatten - du kommer inte ångra det.",severity:"tip"},{icon:"leaf",title:"Skörda nedifrån och uppåt",text:"Skotten mognar nedifrån och uppåt längs stammen. Börja skörda de nedersta när de är 2-3 cm i diameter och fasta. Bryt av bladen under skotten du skördar - det ger de övre skotten mer ljus och energi.",severity:"tip"},{icon:"seedling",title:"Toppa plantan i september",text:"Knip av toppskottet i september (zon 1-4) eller oktober (zon 5-6). Det stoppar höjdtillväxten och tvingar all energi ner i skotten som redan bildats. Ett avgörande trick för täta, fina skott.",severity:"tip"},{icon:"warning",title:"Kalka - klumprotsjukans fiende",text:"Det absolut viktigaste du kan göra för kålväxter är att kalka jorden. Klumprotsjuka trivs i sur jord och finns den väl i marken stannar den i 6+ år. Kalka på hösten, sikta på pH runt 7.",severity:"warning"},{icon:"warning",title:"Fiberduk hela säsongen",text:"Kålfjärilen flyger från maj till september. Lägg fiberduk vid utplantering och ta inte bort den förrän du skördar. Brysselkålens långa säsong gör henne extra utsatt.",severity:"warning"},{icon:"warning",title:"Stöd höga plantor",text:"Brysselkål kan bli 60-90 cm hög med en tung last av skott. Sätt en stödkäpp vid plantering eller kupa jord runt stambasen. En planta som blåser omkull i oktober efter 5 månaders väntan - det vill du undvika.",severity:"warning"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Brysselkål förodlas alltid inomhus - den långa säsongen (120-180 dagar) kräver tidig start. Så i mars-april beroende på zon. Direktsådd fungerar inte i Sverige - säsongen räcker helt enkelt inte till.",steps:["Så 1-2 cm djupt i krukor eller celler, 5-6 veckor före planerad utplantering","Håll jorden runt 18-20°C för snabb groning (5-10 dagar)","Flytta till svalare plats (12-15°C) och starkt ljus så snart plantorna är uppe - det ger kompakta, starka plantor","Gallra till en planta per cell om du sått flera frön","Härda av plantorna 7-10 dagar innan utplantering - ställ ut dagtid, in på natten","Plantera ut med 50-60 cm avstånd när plantan har 4-6 riktiga blad","Tryck till jorden ORDENTLIGT runt stammen - hon ska stå stadigt i 5-6 månader. Vattna rikligt och sätt kålkragar + fiberduk direkt"],tips:["Brysselkål behöver tidig start - förodla redan i mars (zon 1-3) eller april (zon 4-6) för att hinna mogna","Stram, kompakt planta vid utplantering är viktigare än stor planta - ge starkt ljus under förodlingen","Kålkragar runt stjälken vid utplantering skyddar mot kålfluga - gör dem av kartong, filt eller köp färdiga"],indoorWeeks:"5-6 veckor"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Brysselkål är tvåårig och sätter frö först andra året. Hela plantan med stam och skott måste övervintras och planteras ut igen. En rejäl utmaning - men för den som vill bevara sorter som Groninger är det värt mödan.",steps:["Välj den finaste, friskaste plantan med täta, jämna skott","Gräv upp hela plantan med roten på senhösten","Förvara svalt (0-5°C) över vintern - jordkällare eller ouppvärmt garage","Plantera ut igen på våren med intakt rot och stam","Skotten spricker upp och blomstjälkar växer ut ur dem","Gula blommor pollineras av insekter - se till att bara EN sort av Brassica oleracea blommar","Låt fröskidorna mogna och torka på plantan tills de är bruna och spröda","Klipp av blomstjälkarna och eftertorka i papperspåse","Krossa skidorna försiktigt och blås bort agnarna. Förvara svalt och torrt."],isolation:"Korsar med ALLA andra Brassica oleracea (vitkål, grönkål, broccoli, blomkål, rödkål, kålrabbi). Odla bara en sort för frö, eller isolera med minst 1 km.",storageYears:"4-5 år",tip:"Frötagning av brysselkål är bland de svåraste - du måste förvara en hel planta (60-90 cm!) över vintern. Men för OP-sorter som Groninger och Rubine är det enda sättet att bevara dem. F1-hybrider som Igor ger inte äkta avkomma."},storage:{shelfLife:"3-4 veckor (på stammen i kylskåp), 8-12 månader (fryst)",methods:[{method:"På stammen (bäst!)",icon:"storage",duration:"3-4 veckor",description:"Klipp av hela stammen och ställ i kylskåp. Skotten håller sig mycket längre på stammen än lösa. Gammalt knep som fungerar fantastiskt.",best:!0},{method:"Kylskåp (lösa)",icon:"snowflake",duration:"1-2 veckor",description:"Lösa skott i plastpåse med några hål i grönsakslådan. Håller sämre än på stammen men funkar för kortare lagring.",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Halvera stora skott, blanchera 3-4 minuter, kyl i isvatten och frys i portionspåsar. Perfekt för grytor, gratänger och wok. Texturen mjuknar men smaken består fint.",best:!1},{method:"Stående i trädgården",icon:"storage",duration:"Till -10°C",description:'Brysselkål tål rejäl frost. Låt henne stå kvar i trädgården och skörda efter behov. Det bästa "lagret" som finns - levande färskvaruförråd rakt ut genom dörren!',best:!1}],tips:["Låt brysselkålen stå kvar i trädgården så länge det går - hon tål frost ner till -10°C och smaken bara blir bättre","Skörda hela stammen och ställ i ett kallt garage eller jordkällare - skotten håller sig i veckor","Frysta brysselkål är utmärkt i grytor och gratänger - blanchera alltid före frysning","Skörda nedifrån och uppåt - ta de nedersta skotten först så får de övre mer tid att växa till sig","Små, täta skott håller bättre och smakar godare än stora, lösa. Skörda när de är 2-3 cm i diameter."]},harvestCalc:{minPerSqm:.8,maxPerSqm:1.5,unit:"kg"}},Er=Object.freeze(Object.defineProperty({__proto__:null,brysselkal:d},Symbol.toStringTag,{value:"Module"})),m={name:"Brytböna",icon:"vegetable",family:"Baljväxter",familyLatin:"Fabaceae",difficulty:"Enkel",difficultyWhy:"Direktsås utomhus, fixar sitt eget kväve, kräver inget stöd och ger massiv skörd. Enklare blir det inte.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:[7,8]},days:"50-65",spacing:"8-10 cm",rowSpacing:"40-50 cm",depth:"3-5 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmar sol per dag. Brytbönan vill ha värme och ljus - hon är en riktig solälskare som belönar dig med fler baljor ju mer sol hon får."},temperature:{min:10,max:30,ideal:"18-25°C",detail:"Gror inte under 10°C i jorden - ha tålamod och vänta tills marken verkligen värmt upp sig. Hon trivs bäst i 18-25°C och slutar växa om det blir kallare än 12°C. Frost är döden - inte en chans."},wind:{level:"Normalt",detail:"Kompakta buskar som klarar normal vind utan stöd. Det är hennes stora fördel jämfört med störböna - inga käppar, inga nät, bara så och skörda."}},watering:{need:"Medel",icon:"water",summary:"Brytbönan klarar sig hyfsat på egen hand, men under blomning och baljesättning vill hon ha ordentligt med vatten. Torka då = tomma baljor och sega bönor.",phases:[{phase:"Groning (0-2 veckor)",need:"Medel",tip:"Vattna väl vid sådd - fröna behöver fukt för att svälla och gro. Jorden ska vara jämnt fuktig men inte dränkt."},{phase:"Tillväxt (2-5 veckor)",need:"Låg",tip:"Brytbönan bygger sin buske nu och klarar sig bra på naturlig nederbörd. Lite lagom törst får rötterna att söka sig djupare."},{phase:"Blomning (5-7 veckor)",need:"Hög",tip:"Kritisk period! Vattenstress nu gör att blommorna faller av utan att sätta baljor. Vattna djupt 2-3 gånger i veckan vid torrt väder."},{phase:"Baljesättning (7+ veckor)",need:"Medel-Hög",tip:"Fortsätt vattna jämnt. Baljorna växer snabbt nu och behöver vatten för att bli spröda och saftiga istället för sega och trådiga."}],mistakes:["Sår för tidigt i kall jord - fröna ruttnar istället för att gro","Glömmer vattna under blomning - den absolut viktigaste perioden för skörd","Vattnar ovanifrån sent på dagen - fuktiga blad bjuder in svampsjukdomar"],tip:"Mulcha runt plantorna med gräsklipp eller halm. Det håller fukten jämn, jorden varm och ogräset borta - tre flugor i en smäll."},soil:"Trivs i de flesta jordtyper bara jorden är väldränerad och inte vattensjuk. Lös, varm, mullrik jord ger bäst resultat.",soilTips:["Inget extra kväve behövs - brytbönan fixar sitt eget via Rhizobium-bakterier på rötterna","Jobba in lite kompost på hösten före - det ger den mullrika, luftiga jord som bönor älskar","Undvik att gödsla med stallgödsel samma år - för mycket kväve ger massor av blad men få baljor"],timeline:{1:[{phase:"Direktså",months:"Maj",icon:"seedling"},{phase:"Blomning",months:"Jun-Jul",icon:"flower"},{phase:"Skörd",months:"Jul-Aug",icon:"harvest"},{phase:"Andra omgången",months:"Jun",icon:"seedling"}],4:[{phase:"Direktså",months:"Maj-Jun",icon:"seedling"},{phase:"Blomning",months:"Jul",icon:"flower"},{phase:"Skörd",months:"Jul-Sep",icon:"harvest"}],6:[{phase:"Direktså (växthus)",months:"Jun",icon:"seedling"},{phase:"Blomning",months:"Jul",icon:"flower"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Maj",N:5,P:15,K:10,label:"Groning"},{month:"Jun",N:10,P:30,K:20,label:"Tillväxt"},{month:"Jul",N:10,P:45,K:40,label:"Blomning"},{month:"Aug",N:8,P:50,K:55,label:"Baljesättning"},{month:"Sep",N:5,P:30,K:40,label:"Skörd"}],nutritionTips:[{timing:"Vid sådd",tip:"Inget kväve! Brytbönan fixar sitt eget via Rhizobium-bakterier. En liten giva benmjöl eller stenfosfat för fosfor räcker gott."},{timing:"Blomning",tip:"En lätt giva kaliumrik gödsel (vedaska eller alggödsel) stärker blomningen och hjälper baljorna att fylla på."},{timing:"Under säsongen",tip:"Brytbönan är anspråkslös - hon ger mer till jorden än hon tar. Övergödsla med kväve och du får en frodig buske utan baljor."},{timing:"Efter skörd",tip:"Klipp av plantan vid markytan men LÅT RÖTTERNA SITTA KVAR. Kvävebakterierna fortsätter gödsla jorden åt nästa gröda - helt gratis."}],companions:{good:[{id:"morot",name:"Morot",icon:"morot",why:"Morötter luckrar jorden på djupet medan brytbönan fixar kväve - drömgrannar som hjälper varandra"},{id:"gurka",name:"Gurka",icon:"vegetable",why:"Gurkorna breder ut sig vid marken och håller fukten medan bönorna växer uppåt - smart samarbete"},{id:"potatis",name:"Potatis",icon:"potatis",why:"Potatisen älskar det kväve bönan fixar och deras rötter stör inte varandra"},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Sallat trivs i halvskuggan under bönbuskarna och njuter av det kväverika sällskapet"},{name:"Majs",icon:"vegetable",why:"Klassiskt trio-odling med squash - majs ger skugga och stöd, bönan ger kväve, squash täcker marken"}],bad:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökväxter anses kunna hämma bönans kvävefixering via sina svavelhaltiga ämnen - bäst att hålla dem åtskilda"},{id:"vitlok",name:"Vitlök",icon:"vegetable",why:"Samma problem som lök - allicin i vitlök kan påverka Rhizobium-bakterierna negativt"}]},rotation:{avoid:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{name:"Störböna"}],avoidWhy:"Alla baljväxter delar sjukdomar som rotröta och bönflugor. Vänta minst 4 år innan du sår baljväxter på samma plats.",goodBefore:[{id:"potatis",name:"Potatis"},{id:"lok",name:"Lök"},{id:"squash",name:"Squash"}],goodBeforeWhy:"Potatisens luckring och lökens sanering gör jorden redo. Squash bryter också sjukdomscykler bra.",goodAfter:[{id:"gronkal",name:"Grönkål",category:"grönsaker"},{id:"sallat",name:"Sallat"},{id:"squash",name:"Squash"}],goodAfterWhy:"Kvävehungriga grödor som kål, sallat och squash älskar jorden efter brytböna - den är fullpumpad med kväve."},varieties:[{name:"Maxi",zones:[1,2,3,4,5,6],note:"Pålitlig OP-sort med raka, mörkt gröna baljor. Tidig och rikbärande - en säker favorit. Finns hos Impecta och Lindbloms."},{name:"Ferrari",zones:[1,2,3,4,5,6],note:"Haricots verts-typ med extra tunna, eleganta baljor. Smaken är en klass för sig - perfekt för den som vill odla finbönor. Finns hos Nelson Garden."},{name:"Purple Teepee",zones:[1,2,3,4,5,6],note:"Purpurböna med lila baljor som byter till grönt vid tillagning. Skördevänlig - baljorna sitter ovanför bladverket och syns tydligt. Finns hos Impecta."},{name:"Provider",zones:[1,2,3,4,5,6],note:"Mycket tidig OP-sort (50 dagar) med bra köldhärdighet. Pålitlig och produktiv - ett säkert val i hela landet."},{name:"Rocdor",zones:[1,2,3,4,5],note:"Vaxböna med gula baljor och smörmjuk smak. Mognar tidigt - perfekt för korta säsonger. Finns hos Runåbergs och Lindbloms."}],problems:[{name:"Bönflugan",symptom:"Fröna gror dåligt eller inte alls - larverna äter fröna inifrån",fix:"Så i varm jord (minst 12°C) så att fröna gror snabbt förbi det känsliga stadiet. Täck med fiberduk de första veckorna."},{name:"Gråmögel (Botrytis)",symptom:"Gråbrunt ludd på blad, stjälkar och baljor, speciellt i fuktigt väder",fix:"Luftig plantering (inte för tätt), vattna vid roten och aldrig ovanifrån. Ta bort drabbade delar direkt."},{name:"Mjöldagg",symptom:"Vitt, mjölaktigt belägg på bladen, oftast sent i säsongen",fix:"God luftcirkulation och vatten vid roten. Drabbade blad kan tas bort. Mjölkspray (1 del mjölk, 9 delar vatten) fungerar förebyggande."},{name:"Bladlöss",symptom:"Kolonier av gröna eller svarta löss på skottspetsar och baljor",fix:"Spruta av med stark vattenstråle. Nyckelpigorna och blomflugor är dina bästa allierade - locka dem med blommande kryddväxter intill."},{name:"Bönrost",symptom:"Bruna-orange pustlar på bladens undersida",fix:"Ta bort drabbade blad. Bra luftcirkulation och växtföljd. Vanligast sent i säsongen - baljorna hinner oftast mogna ändå."}],goodToKnow:[{icon:"harvest",title:"Skörda ofta - det ger MER",text:"Brytbönans bästa hemlighet: ju oftare du plockar, desto fler baljor sätter hon. Sluta plocka och hon slutar blomma. Skörda varannan till var tredje dag under högsäsong - du blir förvånad över hur mycket en liten rad kan ge.",severity:"tip"},{icon:"leaf",title:"Kvävefixerare - gratis gödsel",text:"Precis som sina kusiner ärtorna och bondbönorna fixar brytbönan kväve ur luften via Rhizobium-bakterier på rötterna. Klipp av plantan vid skörd men lämna rötterna kvar i jorden. Nästa gröda får gratis gödsling.",severity:"tip"},{icon:"warning",title:"Frost är döden",text:"Brytbönan tål INGEN frost. Inte ens en lätt nattfrost. Vänta med sådden tills frostrisken verkligen är över och jorden håller minst 10°C. Bättre en vecka för sent än en dag för tidigt.",severity:"warning"},{icon:"tip",title:"Så i omgångar",text:"Så en ny omgång var tredje vecka från maj till mitten av juni (zon 1-3). Då får du färska bönor hela sommaren istället för allt på en gång.",severity:"tip"},{icon:"warning",title:"Rör inte blöta plantor",text:"Gå aldrig bland bönplantorna när de är blöta av regn eller dagg. Svampsjukdomar sprider sig via vattendroppar och dina händer blir budbärare. Vänta tills plantorna torkat upp.",severity:"warning"},{icon:"seedling",title:"Direktså - alltid",text:"Brytbönan HATAR att bli omplanterad. Hennes rötter är ömtåliga och vill inte bli störda. Så alltid direkt på friland - det är enklare för både dig och henne.",severity:"tip"},{icon:"sun",title:"Varm jord är nyckeln",text:"Lägg svart markväv eller plast på såddbädden en vecka innan du sår. Det värmer jorden och ger fröna en flygande start. Speciellt värdefullt i zon 4-5.",severity:"tip"}],sowing:{method:"direct",label:"Direktsådd",description:"Brytbönan sås direkt på friland - hon ogillar att bli omplanterad. Vänta tills jorden verkligen är varm (minst 10°C) - kalla, blöta frön ruttnar fort.",steps:["Vänta tills frostrisken är över och jorden håller minst 10°C (stick ner fingret - den ska kännas ljummen)","Gör spår 3-5 cm djupa med en krattrygg eller pinne","Lägg fröna med 8-10 cm avstånd","Täck med jord och tryck till lätt","Vattna försiktigt men ordentligt","Täck med fiberduk de första veckorna om bönflugan är ett problem i din trädgård"],tips:["Lägg svart plast på såddbädden en vecka innan för att värma jorden - det ger snabbare groning","Så en andra omgång efter 3 veckor för längre skördeperiod","I zon 4-5 kan du förså i torvkrukor inomhus 2-3 veckor före utplantering - men var VÄLDIGT försiktig med rötterna vid utplantering"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Självpollinerare",biennial:!1,description:"Brytbönan är självpollinerare och en av de enklaste grödorna att spara frö från. Låt ett par plantor stå orörda och låt baljorna torka helt på plantan.",steps:["Välj de friskaste och mest produktiva plantorna - märk dem tidigt och PLOCKA INTE baljor från dessa","Låt baljorna sitta kvar tills de är helt torra, gulbruna och skramlar","Plocka de torra baljorna och lägg dem inomhus på tidningspapper i en vecka","Bryt upp baljorna och plocka ut bönorna","Kontrollera att bönorna är hårda och utan fläckar eller hål","Förvara i papperspåse eller glasburk på sval, torr plats"],isolation:"Övervägande självpollinerare men viss korsbefruktning (3-5%) kan förekomma via insekter. 3-6 m avstånd mellan sorter räcker för rimlig sortrenhet.",storageYears:"3-4 år",tip:"Brytböna är perfekt att börja fröspara med. Bönorna är stora, lätthanterliga och håller bra. Runåbergs och Impecta har fina OP-sorter att utgå ifrån."},storage:{shelfLife:"5-7 dagar (färska) / 1-2 år (torkade)",methods:[{method:"Färska i kylskåp",icon:"snowflake",duration:"5-7 dagar",description:"Lägg otvättade bönor i plastpåse i kylskåpet. Tvätta precis innan du lagar dem. Ät helst inom ett par dagar - sprödheten avtar snabbt.",best:!0},{method:"Frysa (bästa långtidslagring)",icon:"snowflake",duration:"8-12 månader",description:"Bryt bönorna i lagom bitar, blanchera 2-3 minuter, kyl i isvatten, torka och frys in på plåt. Flytta till påse. Behåller färg och smak utmärkt.",best:!1},{method:"Inläggning",icon:"storage",duration:"6-12 månader",description:"Klassiskt svenska inlagda bönor i ättikslag med senapsfrön och dill. Perfekt till husmanskost och julbord.",best:!1},{method:"Torka",icon:"sun",duration:"1-2 år",description:"Låt baljorna mogna och torka helt på plantan. De torkade bönorna blötläggs och kokas - nyttig stapelvara till soppor och grytor.",best:!1}],tips:["Färska brytbönor ska brytas med ett tydligt KNÄPP - därav namnet. Böjer de sig utan att brytas är de för gamla.","Blanchera och frys in samma dag du skördar - det ger bäst smak och textur","Gula vaxbönor håller en dag längre i kylskåpet än gröna sorter","Inlagda bönor i ättikslag är en svensk sommarklassiker - recept finns i varenda syltbok"]},harvestCalc:{minPerSqm:1,maxPerSqm:2.5,unit:"kg"}},Cr=Object.freeze(Object.defineProperty({__proto__:null,brytbona:m},Symbol.toStringTag,{value:"Module"})),k={name:"Chili",icon:"vegetable",family:"Potatisväxter",familyLatin:"Solanaceae",difficulty:"Medel",difficultyWhy:"Kräver tidig förodling (8-12 veckor), massor av värme och en lång säsong. I stora delar av Sverige krävs växthus eller kruka inomhus - men lyckas du? Belöningen är enorm.",zones:{outdoor:[1,2,3],indoor:[1,2,3,4,5,6,7,8],greenhouse:[1,2,3,4,5,6,7]},days:"60-150",spacing:"30-50 cm",spacingNote:"I kruka: minst 30 cm diameter",rowSpacing:"50-70 cm",depth:"0,5-1 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 8-10 timmar direkt sol per dag. Chili är en riktig soljunkie - ju mer ljus, desto fler frukter och desto hetare blir de. I halvskugga får du en stor grön buske med knappt en frukt i sikte."},temperature:{min:10,max:35,ideal:"22-28°C",detail:"Chili är ännu värmekärare än paprika. Under 10°C stannar allt och blommorna faller av i protest. Bäst fruktsättning vid 22-28°C. Över 32°C kan pollineringen strula, precis som hos paprika."},wind:{level:"Skyddat",detail:"Vindkänslig med spröda grenar som knäcks lätt när de är tunga av frukt. Plantera invid en södervägg, i växthus eller på en skyddad balkong. En pinne ger stadga när skörden tynger."}},watering:{need:"Medel",icon:"water",summary:"Chili vill ha jämn fukt men hatar blöta fötter. Hon är lite tuffare än paprika och klarar korta torrperioder - men straffar dig med blomfall om du glömmer henne för länge.",phases:[{phase:"Plantor inomhus",need:"Låg-Medel",tip:"Håll jorden lätt fuktig men aldrig vattensjuk. Chiliplantor som unga är känsliga för övervattning - rötterna ruttnar snabbt i blöt jord. Låt ytan torka upp lite mellan vattningarna."},{phase:"Etablering ute (vecka 1-3)",need:"Medel",tip:"Vattna vid plantering och sedan varannan dag. Låt henne torka upp lite mellan vattningarna så rötterna söker sig djupt istället för att ligga lata vid ytan."},{phase:"Blomning",need:"Medel-Hög",tip:"Kritisk period! Vattenstress nu ger blomfall - och varje tappad blomma är en tappad frukt. Vattna jämnt på morgonen och mulcha runt basen."},{phase:"Fruktsättning och mognad",need:"Medel-Hög",tip:"Fortsätt jämn vattning men överdriva inte. En lätt kontrollerad torrstress när frukterna mognar kan faktiskt göra dem hetare - capsaicinproduktionen ökar när plantan stressas lagom."}],mistakes:["Övervattning av småplantor inomhus - rötan går fortare än du tror i blöt jord","Ojämn vattning - ger blomfall, bittra frukter och toppröta","Vattna ovanifrån och blöta bladen - inbjudan till svampsjukdomar, speciellt i växthus","Glömma att vattna i krukor på varm balkong - krukor torkar ut förvånansvärt snabbt"],tip:"Chili i kruka behöver oftare vatten än chili i marken - känn på jorden med fingret. Torr 2-3 cm ner? Då är det dags. Mulcha med gräsklipp även i krukor för att hålla fukten."},soil:"Näringsrik, väldränerad jord med bra struktur. Chili vill ha det varmt och luftigt kring rötterna - kompakt, blöt jord är hennes värsta mardröm.",soilTips:["Blanda in rikligt med kompost och lite perlit eller sand för bra dränering - hon måste kunna andas","Varm jord är halva hemligheten - värm upp med svart markduk eller folie innan utplantering","För krukor: använd bra planteringsjord blandat med perlit. Undvik billig jord som klumpar sig."],timeline:{1:[{phase:"Förodla inomhus",months:"Mar",icon:"indoor"},{phase:"Härda av",months:"Maj",icon:"hardening"},{phase:"Plantera ut",months:"Maj-Jun",icon:"seedling"},{phase:"Blomning",months:"Jun-Jul",icon:"bloom"},{phase:"Gödsla regelbundet",months:"Maj-Sep",icon:"water"},{phase:"Skörd",months:"Jul-Okt",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"indoor"},{phase:"Härda av",months:"Maj",icon:"hardening"},{phase:"Plantera ut (växthus rekm.)",months:"Jun",icon:"seedling"},{phase:"Blomning",months:"Jun-Jul",icon:"bloom"},{phase:"Gödsla regelbundet",months:"Jun-Sep",icon:"water"},{phase:"Skörd",months:"Aug-Okt",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Apr",icon:"indoor"},{phase:"Härda av",months:"Jun",icon:"hardening"},{phase:"Plantera ut (bara växthus/kruka)",months:"Jun",icon:"seedling"},{phase:"Blomning",months:"Jul",icon:"bloom"},{phase:"Gödsla regelbundet",months:"Jun-Aug",icon:"water"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Jan",N:5,P:5,K:3,label:"Grodd"},{month:"Feb",N:12,P:10,K:5,label:"Förodling"},{month:"Mar",N:25,P:15,K:10,label:"Tillväxt inomhus"},{month:"Apr",N:40,P:22,K:15,label:"Kraftig tillväxt"},{month:"Maj",N:60,P:35,K:25,label:"Utplantering"},{month:"Jun",N:70,P:50,K:40,label:"Etablering och blomning"},{month:"Jul",N:50,P:65,K:60,label:"Fruktsättning"},{month:"Aug",N:30,P:70,K:80,label:"Mognad"},{month:"Sep",N:15,P:45,K:55,label:"Sen skörd"}],nutritionTips:[{timing:"Förodling (jan-april)",tip:"Svag näringslösning varannan vecka. Chiliplantor är småätare i barndomen - för mycket gödsel ger långa, spinkiga plantor som faller omkull."},{timing:"Utplantering (maj-juni)",tip:"Blanda kompost och benmjöl i planteringsgropen. Fosfor ger starka rötter som hjälper henne etablera sig snabbt."},{timing:"Blomning (juni-juli)",tip:"Byt till kaliumrik gödsel - tomatgödsel fungerar perfekt även för chili. Kalium hjälper blommorna att sätta frukt och ökar capsaicinproduktionen."},{timing:"Fruktsättning (juli-sep)",tip:"Fortsätt med kaliumrik gödsel varannan vecka. Minska kväve nu - annars får du en vacker grön buske men få frukter."}],companions:{good:[{id:"basilika",name:"Basilika",icon:"herb",why:"Håller bladlöss borta med sin starka doft och trivs i samma värme. Ett klassiskt par - båda älskar sol och skydd."},{id:"morot",name:"Morot",icon:"vegetable",why:"Luckrar jorden djupt med sina rötter, vilket ger chilin bättre tillgång till vatten och näring."},{name:"Tagetes",icon:"flower",why:"Avskräcker nematoder och vita flygare med sin starka doft. Planterad runt chiliplantorna ger den naturligt skadedjursskydd."},{id:"persilja",name:"Persilja",icon:"herb",why:"Lockar nyttiga rovinsekter som äter bladlöss. Bra marktäckare under chiliplantor som håller jorden fuktig."}],bad:[{id:"paprika",name:"Paprika",icon:"vegetable",why:"Samma art (Capsicum annuum) - konkurrerar om exakt samma näring och delar alla sjukdomar. Kan dessutom korsa sig och ge oförutsägbara frukter."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Samma familj (potatisväxter) - delar sjukdomar och konkurrerar om näring. Bladmögel sprider sig glatt mellan dem."},{id:"potatis",name:"Potatis",icon:"vegetable",why:"Också potatisväxter - potatisbladmögel sprider sig gärna vidare till chili. Håll dem på olika bäddar."},{id:"fankal",name:"Fänkål",icon:"herb",why:"Hämmar chilin tillväxt genom allelopati - de pratar helt enkelt olika språk."}]},rotation:{avoid:[{id:"paprika",name:"Paprika"},{id:"tomat",name:"Tomat"},{id:"potatis",name:"Potatis"},{name:"Aubergine"}],avoidWhy:"Alla potatisväxter - delar sjukdomar som fusarium och bladmögel. Vänta minst 3-4 år innan du odlar potatisväxter på samma plats igen.",goodBefore:[{name:"Baljväxter"},{id:"lok",name:"Lök"},{name:"Gröngödsling"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden och lökväxter sanerar mot jordburna sjukdomar. Perfekt förberedelse för en hungrig chiliplanta.",goodAfter:[{name:"Rotgrönsaker"},{name:"Baljväxter"},{id:"sallat",name:"Sallat"}],goodAfterWhy:"Jorden har fortfarande bra struktur och näring kvar efter chili. Rotgrönsaker och sallat utnyttjar det som blir över."},varieties:[{name:"Jalapeño",zones:[1,2,3,4,5],note:"Klassikern bland chilisorter. Medelheta frukter (2 500-8 000 Scoville) som passar till allt från nachos till inlagd. Pålitlig och generös - perfekt förstachili."},{name:"Cayenne",zones:[1,2,3,4,5],note:"Långa, smala frukter med rejäl hetta (30 000-50 000 Scoville). Torkar fantastiskt och ger chiliflingor för hela vintern. OP-sort som funnits i århundraden."},{name:"Padron",zones:[1,2,3,4],note:"Den berömda tapaschilin - mild (500-2 500 Scoville) och ljuvlig, men var tionde frukt biter ifrån! Tidig och rikbärande. Perfekt stekt i olivolja med flingsalt."},{name:"Sibirisk chili",zones:[1,2,3,4,5,6],note:"Otroligt produktiv och busig (~30 000 Scoville). 30-40 frukter per planta är inte ovanligt. Härdig och snabb - ett säkert val för norra Sverige och balkongodling."},{name:"Habanero",zones:[1,2,3],note:"För den som vill ha riktig hetta (100 000-350 000 Scoville). Capsicum chinense - kräver ännu längre säsong än andra chilisorter. Fruktig smak bakom brännandet, bäst i växthus."}],problems:[{name:"Bladlöss",symptom:"Kladdiga blad, krusiga skottspetsar, små gröna eller svarta insekter på bladens undersida",fix:"Spola av med vatten. Samodla med tagetes och basilika. Vid kraftigt angrepp: såpvatten (1 msk flytande såpa per liter vatten). Nyckelpigornas larver är dina bästa vänner."},{name:"Växthusspinnkvalster",symptom:"Små ljusa prickar på bladen som sedan gulnar och vissnar. Fina spindelvävar på undersidan. Vanligt i torr växthusluft.",fix:"Öka luftfuktigheten genom att spraya vatten på bladen. Rovkvalster (Phytoseiulus) är bästa biologiska bekämpningen. Förebygg genom att hålla luftfuktigheten uppe."},{name:"Blomfall",symptom:"Blommor faller av utan att sätta frukt",fix:"Oftast vattenstress, för hög eller låg temperatur, eller näringsbrist. Vattna jämnt, gödsla med kalium och skaka försiktigt på plantorna för att hjälpa pollineringen - speciellt inomhus där det saknas vind och insekter."},{name:"Toppröta (blomändsröta)",symptom:"Svarta, insjunkna fläckar i botten av frukten - ser ut som röta men är näringsbrist",fix:"Kalciumbrist orsakad av ojämn vattning. Vattna jämnt och regelbundet - det är nyckeln. Mulcha för att hålla fukten stabil. Kalka om pH är lågt."},{name:"Ödem (knottriga blad)",symptom:"Små vattenfyllda blåsor på bladens undersida som sedan blir korkaktiga och bruna",fix:"Inte en sjukdom utan ett tecken på att plantan tar upp mer vatten än den kan avdunsta. Minska vattningen, öka luftcirkulationen och ge mer ljus. Vanligt på övervintrande plantor."}],goodToKnow:[{icon:"clock",title:"Starta TIDIGT - chili tar ännu längre tid än paprika",text:"Chili behöver 8-12 veckors förodling inomhus. Börja redan i januari! Heta sorter som habanero behöver ännu längre tid. Har du inte växtbelysning? Investera i det - det är skillnaden mellan framgång och misslyckande.",severity:"warning"},{icon:"indoor",title:"Perfekt krukväxt",text:"Till skillnad från många grönsaker trivs chili utmärkt i kruka på fönsterbrädan, balkongen eller i växthuset. Kompakta sorter som Sibirisk chili är som gjorda för krukodling. Du behöver inte en trädgård för att odla chili!",severity:"tip"},{icon:"sun",title:"Capsaicin - därför är chili het",text:"Hettan sitter i capsaicinet som främst finns i fröfästet (den vita hinnan inuti frukten), inte i fröna som många tror. Vill du mildra hettan? Skrapa bort det vita. Vill du ha mer hetta? Låt plantan torka ut lite mellan vattningarna.",severity:"tip"},{icon:"warning",title:"Skydda händerna vid skörd av heta sorter",text:"Capsaicin är en olja som fastnar på huden och kan svida i timmar. Använd handskar vid skörd av habanero och andra heta sorter. Rör ALDRIG ögonen efter att ha hanterat chili - det är en läxa man bara behöver lära sig en gång.",severity:"warning"},{icon:"leaf",title:"Övervintra dina chiliplantor",text:"Chili är egentligen en flerårig växt i varmare klimat. Klipp ner plantan till 15-20 cm, ställ svalt (10-15°C) och ljust över vintern med minimal vattning. På våren skjuter hon nya skott och ger skörd ännu tidigare år två!",severity:"tip"},{icon:"scissors",title:"Toppa för fler frukter",text:"När plantan är 15-20 cm hög: klipp av toppskottet! Det känns brutalt men tvingar henne att grena ut sig och du får en busigare planta med fler blomställen - och därmed fler frukter.",severity:"tip"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Chili måste förodlas inomhus i Sverige - den extremt långa mognadstiden gör direktsådd utomhus helt omöjlig. Börja tidigt, redan i januari för heta sorter, för att ge henne den tid hon behöver.",steps:["Fyll små krukor eller pluggbrätten med fuktig såjord","Lägg 1-2 frön per kruka, 0,5-1 cm djupt, täck lätt med jord eller vermiculit","Täck med plastfolie eller miniväxthus - chilifrön behöver fukt och värme för att gro","Placera VARMT (25-28°C) - gärna på en värmematta. Chilifrön kan ta 10-25 dagar att gro, ibland ännu längre för heta sorter","När groddarna syns: ta bort plasten och ge maximalt ljus (växtbelysning 14-16 timmar per dag)","Omplantera till större kruka (10-12 cm) när plantan har 4-6 riktiga blad","Toppa plantan när hon är 15-20 cm hög för att få en busigare växt","Härda av 2-3 veckor före utplantering: börja med 1 timme utomhus och öka gradvis","Plantera ut i växthus, kruka eller på varmaste platsen när nätterna håller sig över 10°C"],tips:["Starta 8-12 veckor före planerad utplantering - heta sorter behöver ännu mer tid än milda","Värmematta under krukor gör enorm skillnad - groningen kan halveras i tid","Växtbelysning är nästan ett krav i januari-februari - fönsterbrädan räcker inte när dagarna är så korta"],indoorWeeks:"8-12 veckor"},seedSaving:{difficulty:"Enkel",type:"Självpollinerare",biennial:!1,description:"Chili är huvudsakligen självpollinerare men kan korsa sig med andra Capsicum annuum-sorter (inklusive paprika!) via insekter. Ta frö från fullt mogna, gärna övermogna frukter.",steps:["Välj en fullt mogen frukt från din finaste planta - låt den sitta kvar på plantan så länge som möjligt","Använd HANDSKAR vid heta sorter - capsaicin är inget du vill ha i ögonen","Skär upp frukten och skrapa loss fröna från fröfästet","Skölj fröna lätt i vatten och ta bort allt fruktkött","Lägg fröna på hushållspapper och låt torka helt i rumstemperatur (5-7 dagar)","Förvara i märkt papperspåse på svalt, torrt ställe"],isolation:"Chili korsar sig lätt med andra Capsicum annuum-sorter (inklusive paprika och andra chilisorter). Isolera med minst 50 meter, helst mer, eller täck blommorna med tyll för sortäkta frö. Tyll är enklast för hemmaodlare.",storageYears:"2-5 år",tip:"Vill du bevara en specifik sort? Isolera blommorna med tyll före de öppnar sig. Och kom ihåg - ta aldrig frö från F1-hybrider om du vill ha samma resultat nästa år."},storage:{shelfLife:"1-2 veckor (färsk) / 12 mån (torkad/fryst)",methods:[{method:"Torka",icon:"sun",duration:"12+ månader",description:"DEN klassiska metoden för chili. Trädga upp på snöre och häng på torrt, luftigt ställe. Eller torka i ugn på 60°C i 4-6 timmar. Torkad chili håller i princip hur länge som helst och ger fantastiska chiliflingor.",best:!0},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Frys hela frukter direkt - ingen blanchering behövs! Perfekt för färsk smak i matlagningen. De blir mjuka efter tining men smaken är intakt.",best:!1},{method:"Kylskåp (färsk)",icon:"snowflake",duration:"1-2 veckor",description:"Lägg i grönsakslådan i kylskåpet. Färska chilifrukter håller sig bättre än paprika men inte så länge - gör något av dem inom två veckor.",best:!1},{method:"Inläggning (ättika)",icon:"storage",duration:"6-12 månader",description:"Fermenterad eller ättiksinlagd chilisås - en smakbomb att ha i skafferiet. Jalapeños inlagda i ättika är en klassiker. Sterilisera burkarna ordentligt.",best:!1},{method:"Mala till pulver",icon:"storage",duration:"12+ månader",description:"Torka först, mal sedan i kryddkvarn eller mortel. Hemgjort chilipulver är på en helt annan nivå än köpepulver. Förvara lufttätt och mörkt.",best:!1}],tips:["Tunnväggiga sorter (cayenne, thai) torkar lättare än tjockväggiga (jalapeño, habanero)","Vid torkning i snöre: se till att frukterna inte vidrör varandra - annars risk för mögel","Frysta chilifrukter går att riva direkt från frysen på ett rivjärn - supertrick för snabb matlagning","Rökt chili (chipotle) går att göra hemma i röklåda om du vill lyfta smaken ytterligare","Förvara torkad chili mörkt och torrt - ljus blekar både färg och smak över tid"]},harvestCalc:{minPerSqm:1,maxPerSqm:3,unit:"kg"}},Or=Object.freeze(Object.defineProperty({__proto__:null,chili:k},Symbol.toStringTag,{value:"Module"})),g={name:"Citronmeliss",icon:"citronmeliss",category:"kryddor",family:"Kransblommiga",familyLatin:"Lamiaceae",perennial:!0,lifespan:"5-10 år (sprider sig villigt)",difficulty:"Enkel",difficultyWhy:"Härdig perenn som klarar sig i de flesta svenska zoner med minimal skötsel. Sprider sig gärna - ibland lite för gärna. Det svåra är inte att få den att växa, utan att hindra den från att ta över.",zones:{outdoor:[1,2,3,4],indoor:[1,2,3,4,5,6,7,8],greenhouse:[1,2,3,4,5,6,7,8]},days:"75-120",spacing:"30-40 cm",rowSpacing:"30 cm",depth:"0.2 cm",depthNote:"Ljusgroddare - tryck fast men täck knappt",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Trivs i sol till halvskugga - minst 4-6 timmars sol per dag ger bäst smak. Full sol ger mest eteriska oljor, men halvskugga fungerar utmärkt. Mer flexibel än de flesta kryddor."},temperature:{min:-20,max:35,ideal:"15-25°C",detail:"Härdig perenn som klarar rejäl kyla med snötäcke. Övervintrar utan problem i zon 1-4 och ofta upp till zon 5 med lite granristäckning. Smidig och tålig."},wind:{level:"Tålig",detail:"Kompakt växtsätt och starka stammar gör att citronmeliss klarar vind bra. Inte lika känslig som många andra kryddor."}},watering:{need:"Medel",icon:"water",summary:"Vill ha jämnt fuktig jord men klarar korta torrperioder. Mer vattnig än salvia och timjan, men inte lika kräsen som basilika. Lagom är nyckeln.",phases:[{phase:"Groning/nyplanterad",need:"Hög",tip:"Håll jorden jämnt fuktig tills plantorna etablerat sig. Fröna är små och torkar ut snabbt - täck med plastfolie för jämn fukt."},{phase:"Etablerad planta",need:"Medel",tip:"Vattna när de översta centimetrarna i jorden torkat ut. Tål kortare torka men ger mest blad med jämn fukt."},{phase:"Krukodlad",need:"Medel-Hög",tip:"Krukor torkar snabbare - kontrollera dagligen under varma perioder. Bra dränering i botten, men låt aldrig torka ut helt."}],mistakes:["Övervattning i tung jord - rötterna ruttnar i stående vatten","Glömmer att vattna i kruka under högsommar - plantan hänger med bladen","Vattnar ovanifrån - kan ge mjöldagg, vattna vid basen istället"],tip:"Mulcha runt plantan med kompost eller gräsklipp - håller fukten jämn och minskar ogräs. Perfekt för den som inte orkar vattna varje dag."},soil:"Citronmeliss trivs i de flesta jordar bara de är någorlunda väldränerade. Lucker, mullrik jord med lite kompost är perfekt. Inte alls lika kräsen som rosmarin eller salvia - anpassar sig fint.",soilTips:["Vanlig trädgårdsjord med lite kompost funkar utmärkt - hon är inte kräsen","Undvik vattensjuk mark - lite dränering behövs, men inte medelhavsnivå","I kruka: vanlig planteringsjord räcker - blanda gärna in lite perlit för dränering","Mulcha med kompost på hösten - ger vinterskydd och näring till våren"],timeline:{1:[{phase:"Förodling inomhus",months:"Mar",icon:"indoor"},{phase:"Direktsådd/utplantering",months:"Maj",icon:"seedling"},{phase:"Skörd (löpande)",months:"Jun-okt",icon:"harvest"},{phase:"Storskord för torkning",months:"Jul (före blomning)",icon:"harvest"},{phase:"Ta eget frö",months:"Sep",icon:"seed"}],4:[{phase:"Förodling inomhus",months:"Mar",icon:"indoor"},{phase:"Utplantering",months:"Slutet av maj-jun",icon:"seedling"},{phase:"Skörd (löpande)",months:"Jun-sep",icon:"harvest"},{phase:"Storskord före blomning",months:"Jul-aug",icon:"harvest"}],6:[{phase:"Förodling inomhus",months:"Feb-mar",icon:"indoor"},{phase:"Utplantering",months:"Jun",icon:"seedling"},{phase:"Skörd",months:"Jul-sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:2,P:1,K:1},{month:"Maj",N:3,P:2,K:2},{month:"Jun",N:4,P:3,K:3},{month:"Jul",N:4,P:3,K:3},{month:"Aug",N:3,P:2,K:2},{month:"Sep",N:1,P:1,K:1}],nutritionTips:[{timing:"Vår (april-maj)",tip:"En giva kompost runt plantan på våren räcker gott. Citronmeliss har lågt näringsbehov och mår bra av enkel behandling."},{timing:"Sommar",tip:"Ingen extra gödsling behövs om du lagt kompost på våren. Lite nässelvatten varannan vecka om du vill pusha tillväxten."},{timing:"Obs!",tip:"Övergödsling ger stor planta med svagare citronsmak. Håll det enkelt - citronmeliss är tacksam och anspråkslös."}],companions:{good:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Citronmeliss lockar pollinatörer som hjälper tomaten sätta frukt, och den starka doften avskräcker bladlöss. En vinn-vinn-kombination."},{id:"squash",name:"Squash",icon:"vegetable",why:"Squash behöver pollinerare för att sätta frukt - och citronmeliss är en riktig bimagnet. Perfekt granne."},{id:"timjan",name:"Timjan",icon:"herb",why:"Liknande krav på sol och dränering. Skapar ett fint kryddhörn som dessutom avskräcker skadedjur."},{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Citronmeliss lockar bin som pollinerar jordgubbarna. Plantera i närheten för bättre skörd."}],bad:[{id:"mynta",name:"Mynta",icon:"herb",why:"Två aggressiva spridare tillsammans? Ingen bra idé. De konkurrerar hårt om samma utrymme och myntan vinner oftast."}]},rotation:{avoid:[{id:"citronmeliss",name:"Citronmeliss"},{id:"mynta",name:"Mynta"},{id:"basilika",name:"Basilika"}],avoidWhy:"Kransblommiga (Lamiaceae) delar jordburna sjukdomar. Plantera inte ny citronmeliss där gammal stått - vänta 3 år. Men hon är perenn, så rotation är sällan aktuellt.",goodBefore:[{name:"De flesta grödor"},{id:"sallat",name:"Sallat"}],goodBeforeWhy:"Citronmeliss tar lite näring och lämnar jorden i fint skick.",goodAfter:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodAfterWhy:"Baljväxter berikar jorden med kväve. Men citronmeliss är perenn - rotation gäller mest när du tar bort en gammal planta."},varieties:[{name:"Citronmeliss (standard)",zones:[1,2,3,4],note:"Den klassiska arten. 50-70 cm, härdig och pålitlig. Ekologiskt frö hos Runåbergs och Lindbloms. Den som funkar överallt."},{name:"Citronella",zones:[1,2,3,4],note:"Kompakt sort (ca 25 cm) med extra bra motståndskraft mot mjöldagg. Bra val om du haft problem med svampsjukdomar. Säljs främst som planta."},{name:"Compacta",zones:[1,2,3],note:"Kompakt dvärgform, perfekt för krukor och rabattkanter. Självsår sig inte - steril sort som håller sig i styr. Säljs som planta."},{name:"All Gold",zones:[1,2,3],note:"Guldgula blad som lyser upp i trädgården. Främst dekorativ men med samma goda citronsmak."}],problems:[{name:"Mjöldagg",symptom:"Vitt, pudrigt belägg på bladen, särskilt vid dålig luftcirkulation.",fix:"Klipp bort drabbade delar och ge bättre luft mellan plantorna. Vattna vid basen, inte ovanifrån. Sorten Citronella har bättre motståndskraft."},{name:"Aggressiv spridning",symptom:"Plantan dyker upp överallt i trädgården via självsådd och rotskott.",fix:"Klipp av blomställningar före frösättning. Gräv ner en kruka utan botten för att begränsa rötterna. Eller odla i kruka - säkraste metoden."},{name:"Sniglar",symptom:"Ätna blad, särskilt på unga plantor.",fix:"Snigelgaller, koppband runt krukor eller biologisk bekämpning med nematoder. Etablerade plantor klarar sig bättre."},{name:"Bladlöss",symptom:"Kolonier på nya skott och knoppar.",fix:"Spola av med vatten. Citronmeliss lockar själv nyckelpigor med sina blommor - problemet löser sig ofta av sig själv."}],goodToKnow:[{icon:"tip",title:"Bimagnet - Melissa betyder bi",text:'Namnet Melissa kommer från grekiskans "meli" som betyder honung. Redan de gamla grekerna gnuggade in nya bikupor med citronmelissblad för att locka bisvärmar - tricket fungerar fortfarande! Plantorna surrar av bin och humlor under blomning.',severity:"tip"},{icon:"warning",title:"Sprider sig som rykten",text:"Citronmeliss självsår sig ÖVERALLT om du låter den blomma. Och utlöparna kryper sakta utåt. Klipp av blomställningar före frösättning, eller gräv ner en kruka utan botten för att hålla rötterna i schack. I zon 1-3 kan en enda planta bli ett bestånd på några år.",severity:"warning"},{icon:"tip",title:"Hjärtansfröjd",text:'Det svenska folknamnet "hjärtansfröjd" berättar allt - citronmeliss ansågs stärka hjärtat och lyfta humöret. Hildegard av Bingen använde den mot melankoli redan på 1100-talet. En kopp melisste på kvällen är fortfarande en underbar avslutning.',severity:"tip"},{icon:"tip",title:"Skörda precis före blomning",text:"Smaken och doften är som starkast strax innan blommorna öppnar sig. Då koncentrerar plantan sina eteriska oljor i bladen istället för att locka pollinerare. Tajma storskörden till juli för bästa citronarom.",severity:"tip"},{icon:"tip",title:"Fyrkantig stjälk avslöjar familjen",text:"Som alla kransblommiga växter har citronmeliss fyrkantig stjälk - känn med fingrarna! Det är ett säkert kännetecken för Lamiaceae-familjen (mynta, timjan, oregano, basilika).",severity:"tip"}],sowing:{method:"indoor",label:"Förodling & sådd",description:"Citronmeliss kan förodlas inomhus eller direktsås utomhus. Fröna är ljusgroddare och behöver ljus och värme (15-20°C) för att gro. Groning tar 10-21 dagar. Delning av etablerade plantor är det enklaste sättet att få nya plantor.",steps:["Fyll krukor med fuktig såjord","Strö fröna på ytan och tryck fast lätt - täck inte (ljusgroddare)","Täck med plastfolie för jämn fukt, vädra dagligen","Ställ ljust och varmt (15-20°C)","Groning på 10-21 dagar - tålamod behövs","Ta bort plastfolie vid uppkomst","Gallra eller plantera om vid 3-4 örtblad","Härda av 1 vecka före utplantering","Plantera ut efter sista frost med 30-40 cm avstånd"],tips:["Delning av etablerad planta (vår eller höst) är snabbaste metoden - bara gräv upp, dela och plantera om","Direktsådd utomhus fungerar i zon 1-4 från maj - men ger långsammare start","Fröna är mycket små - blanda med lite sand för jämnare fördelning","Har du en kompis med citronmeliss? Be om en rotklump - det räcker gott!"],indoorWeeks:"6-8 veckor före utplantering"},seedSaving:{difficulty:"Enkel",type:"Insektspollinerad",biennial:!1,description:"Låt blomställningarna torka på plantan och samla fröna när de svartnat. Citronmeliss är en av de enklaste att spara frö från - om du inte gör det sår hon sig själv ändå!",steps:["Låt utvalda plantor blomma ut helt","Vänta tills blomställningarna torkat och fröna svartnat (sep)","Klipp av blomstjälkarna och lägg i papperspåse","Skaka - de små svarta fröna faller ut","Rensa bort skräp och eftertorka några dagar","Förvara i märkt kuvert eller glasburk, svalt och torrt"],isolation:"Citronmeliss korsar sällan med andra arter i hemmaträdgården. Melissa officinalis är den enda vanliga arten i Sverige, så riskerna för korspollinering är minimala.",storageYears:"2-3 år",tip:"Enklast: dela plantan vart 3-4 år istället. Du får identiska kloner och föryngrar plantan på köpet. Alla vinner!"},storage:{shelfLife:"3-5 dagar (färsk)",methods:[{method:"Torkning",icon:"storage",duration:"1 år",description:"Häng knippen upp och ner på varm, luftig plats borta från direkt sol. Bladen är klara när de smulas mellan fingrarna. Förvara i lufttät burk, mörkt. Tappar lite av citrusdoften men funkar utmärkt till te.",best:!0},{method:"Frysning",icon:"snowflake",duration:"3-6 månader",description:"Hacka bladen fint och frys i isbitsfack med vatten. Perfekt för te och matlagning under vintern. Bevarar smaken bättre än torkning.",best:!1},{method:"Färsk (kort lagring)",icon:"water",duration:"3-5 dagar",description:"Linda i fuktigt hushållspapper och lägg i plastpåse i kylen. Eller ställ stjälkar i ett glas vatten som en bukett.",best:!1},{method:"Sirap/saft",icon:"storage",duration:"3-6 månader",description:"Koka citronmelissblad med socker och vatten till en aromatisk sirap. Fantastisk i lemonad, cocktails eller droppat över glass.",best:!1}],tips:["Skörda före blomning för starkaste citronarom - efter blomning tappar bladen kraft","Torka i skugga, aldrig i direkt sol - solen bryter ner de eteriska oljorna","Citronmelisste (färsk eller torkad) - häll kokande vatten på en handfull blad, låt dra 5-10 min",'Frys i isbitsfack som "meliss-kuber" - släng i en kanna vatten för instant smaksatt dryck']},harvestCalc:{minPerSqm:.3,maxPerSqm:1,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp blad och kvistar löpande, storskorda före blomning",description:"Skörda genom att klippa kvistar - plantan skjuter glatt nya skott. Du kan skörda 2-3 gånger per säsong om du klipper ner till 10 cm höjd. Bästa smaken fås strax före blomning i juli.",uses:[{use:"Te",tip:"Klassikern! Häll kokande vatten på en handfull färska eller torkade blad. Låt dra 5-10 minuter. Lugnande, citrusigt och underbart på kvällen."},{use:"Sallad & garnering",tip:"Riv färska blad över sallader, desserter eller frukt. Den milda citronsmaken lyfter allt den rör vid."},{use:"Drycker",tip:"Lägg blad i vattenkanna, lemonad eller cocktails. Meliss-sirap (koka med socker) gör vilken dryck som helst till en fest."},{use:"Fisk & kyckling",tip:"Finhacka och strö över fisk eller kyckling de sista minuterna. Tål inte lång tillagning - tillsätt sent."}]}},zr=Object.freeze(Object.defineProperty({__proto__:null,citronmeliss:g},Symbol.toStringTag,{value:"Module"})),p={name:"Dill",icon:"dill",category:"kryddor",family:"Flockblommiga",familyLatin:"Apiaceae",perennial:!1,difficulty:"Enkel",difficultyWhy:"Direktsås utomhus, gror snabbt, kräver minimal skötsel. Sveriges mest lättodlade krydda - sår du dill en gång har du dill för alltid.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:[1,2,3,4,5,6,7,8],greenhouse:null},days:"40-60",spacing:"15-20 cm",rowSpacing:"25-30 cm",depth:"0.5-1 cm",ph:{min:5.5,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Dill vill ha minst 6 timmars sol per dag för bästa smak och tillväxt. I halvskugga blir plantan ranglig och smaken svagare."},temperature:{min:5,max:28,ideal:"15-22°C",detail:"Gror redan vid 5°C men trivs bäst runt 15-22°C. Går i frö SNABBT i värme över 25°C - då ger hon upp bladproduktionen och fokuserar på nästa generation."},wind:{level:"Skyddat",detail:"Dillens höga, tunna stammar knäcks lätt i vind. Ge henne ett skyddat läge - intill en mur, ett staket eller högre växter. Alternativt: så tätare så stöttar plantorna varandra."}},watering:{need:"Medel",icon:"water",summary:"Jämn fukt ger bäst bladproduktion. Dill är inte kräsen men uppskattar att inte torka ut helt - särskilt under varma perioder då hon annars går i frö i rekordfart.",phases:[{phase:"Groning (0-2 veckor)",need:"Hög",tip:"Håll jorden jämnt fuktig tills plantorna är uppe. Fröet är litet och torkar ut snabbt - vattna försiktigt med stril så det inte sköljs bort."},{phase:"Tillväxt (2-6 veckor)",need:"Medel",tip:"Vattna 2-3 gånger i veckan om det inte regnar. Jämn fukt fördröjer blomningen och ger mer blad - precis vad vi vill."},{phase:"Blomning (6+ veckor)",need:"Låg",tip:"När dillkronorna börjar visa sig behöver du knappt vattna alls. Nu är fokus på frö, inte blad. Låt naturen sköta sitt."}],mistakes:["Låter jorden torka ut helt - plantan går i frö direkt som en stressreaktion","Övervattning i tung jord - rötterna ruttnar snabbt, dill vill ha lucker jord","Vattenstänk ovanifrån i full sol - kan bränna de fina bladen"],tip:"Mulcha runt plantorna med gräsklipp - håller fukten jämn och minskar ogräs. Perfekt för den som glömt att vattna igen."},soil:"Dill trivs i de flesta jordar bara de är luckra och väldränerade. Hon är inte kräsen - en normal trädgårdsjord med lite kompost räcker gott.",soilTips:["Lucker jord är viktigast - dillen har en pålrot som vill kunna gå på djupet utan motstånd","Blanda in lite sand om du har tung lerjord - dill avskyr kompakt jord","Behöver inte särskilt rik jord - för mycket kväve ger stor planta men svag smak","Undvik nygödslad jord - samma princip som för morötter (de är ju släktingar)"],timeline:{1:[{phase:"Första sådd",months:"Apr",icon:"seedling"},{phase:"Omsådd 2",months:"Maj",icon:"seedling"},{phase:"Omsådd 3",months:"Jun",icon:"seedling"},{phase:"Skörd blad",months:"Maj-aug",icon:"harvest"},{phase:"Skörd dillkronor",months:"Jul-aug",icon:"harvest"},{phase:"Ta eget frö",months:"Aug-sep",icon:"seed"}],4:[{phase:"Första sådd",months:"Maj",icon:"seedling"},{phase:"Omsådd 2",months:"Jun",icon:"seedling"},{phase:"Skörd blad",months:"Jun-aug",icon:"harvest"},{phase:"Skörd dillkronor",months:"Jul-aug",icon:"harvest"},{phase:"Ta eget frö",months:"Aug-sep",icon:"seed"}],6:[{phase:"Sådd",months:"Jun",icon:"seedling"},{phase:"Skörd blad",months:"Jul-aug",icon:"harvest"},{phase:"Skörd dillkronor",months:"Aug",icon:"harvest"}]},nutritionData:[{month:"Apr",N:2,P:1,K:1},{month:"Maj",N:4,P:2,K:2},{month:"Jun",N:5,P:3,K:3},{month:"Jul",N:4,P:3,K:3},{month:"Aug",N:2,P:2,K:2}],nutritionTips:[{timing:"Vid sådd",tip:"Grundgödsla med lite kompost - det räcker. Dill är en av de minst näringskrävande växter du kan odla."},{timing:"Tillväxt (juni-juli)",tip:"En lätt giva nässelvatten varannan vecka om du vill pusha tillväxten. Men överkill är värst - för mycket kväve ger hög planta med svag smak."},{timing:"Obs!",tip:"Dill behöver näst intill ingen gödsling. Spara kraften (och gödslet) på dina tomater istället - dillen klarar sig själv."}],companions:{good:[{id:"sallat",name:"Sallat",icon:"vegetable",why:"Sallat trivs i dillens lätta skugga under högsommaren. De samsas fint och tar inte näringen från varandra."},{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft skyddar dillen från skadedjur, och dillen lockar nyttiga insekter som hjälper löken."},{id:"gurka",name:"Gurka",icon:"vegetable",why:"Dill lockar pollinatörer som hjälper gurkan sätta frukt. Plus att du får dill och gurka bredvid varandra - perfekt för inläggning!"},{id:"gronkal",name:"Kålväxter",icon:"vegetable",why:"Dillens blommor lockar parasitsteklar som tar kålfjärilslarver. En fantastisk biologisk bekämpning."}],bad:[{id:"morot",name:"Morot",icon:"vegetable",why:"Samma familj (flockblommiga) - delar skadedjur som morotsflugan. Mogen dill kan dessutom hämma morotens rotutveckling via allelopatiska ämnen."},{id:"fankal",name:"Fänkål",icon:"vegetable",why:"Nära släkting i samma familj. Traditionellt anses de störa varandra - oavsett exakt mekanism bör de hållas åtskilda i odlingen."}]},rotation:{avoid:[{id:"morot",name:"Morot"},{id:"persilja",name:"Persilja"},{id:"selleri",name:"Selleri"},{id:"fankal",name:"Fänkål"},{id:"koriander",name:"Koriander"}],avoidWhy:"Alla tillhör flockblommiga (Apiaceae) - delar sjukdomar och skadedjur. Vänta 2-3 år innan du sår dill på samma plats.",goodBefore:[{name:"De flesta grödor"},{id:"sallat",name:"Sallat"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Dill är snäll föregångare - hon tar lite näring från jorden och lämnar den i bra skick för nästa gröda.",goodAfter:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"potatis",name:"Potatis"}],goodAfterWhy:"Baljväxter berikar jorden med kväve. Potatis lämnar lucker, väldränerad jord - perfekt för dillens pålrot."},varieties:[{name:"Mammut",zones:[1,2,3,4,5,6,7,8],note:"Stora, frodiga blad och sen frösättning - ger längre skörd av bladverket. Populär sort hos Runåbergs."},{name:"Bouquet",zones:[1,2,3,4,5,6,7,8],note:"Kompakt sort som blommar tidigt. Perfekt om du vill ha dillkronor för inläggning. Bra i mindre utrymmen."},{name:"Dukat",zones:[1,2,3,4,5,6,7,8],note:"Bladrikare än genomsnittet med sen frösättning. Aromatisk och välkänd sort hos svenska fröhandlare."}],problems:[{name:"Bladlöss",symptom:"Klibbiga stammar, deformerade blad, små gröna insekter.",fix:"Spruta med såpvatten (1 msk flytande tvål per liter). Eller vänta - dillens blommor lockar nyckelpigor som älskar bladlöss!"},{name:"För tidig blomning (bolting)",symptom:"Plantan skjuter blomstjälk redan efter några veckor, knappt några blad.",fix:"Beror nästan alltid på värmestress eller torka. Så om, håll jämn fukt, och välj en sen sort som Mammut. Successionsådd är bästa försäkringen."},{name:"Svampsjukdomar",symptom:"Bruna eller svarta fläckar på blad och stammar.",fix:"Beror ofta på för tätt stånd och dålig luftcirkulation. Gallra plantorna och undvik att vattna på bladen."}],goodToKnow:[{icon:"tip",title:"Sveriges mest svenska krydda",text:"Midsommar utan dill? Kokt potatis utan dill? Gravlax utan dill? Inlagd gurka utan dill? Otänkbart. Dill är den enda krydda som verkligen definierar svensk matkultur - odla den, och du har halva sommaren avklarad.",severity:"tip"},{icon:"warning",title:"Går i frö blixtsnabbt i värme",text:"När termometern kryper över 25°C tänker dillen bara på en sak: att sätta frö och dö. Så i omgångar med 3 veckors mellanrum för att alltid ha färsk dill. Successionsådd är nyckelordet.",severity:"warning"},{icon:"tip",title:"Självsår som ingen annan",text:"Sår du dill en gång har du dill för alltid. På riktigt. Fröet sprider sig överallt och dyker upp på de mest oförutsägbara platser nästa år. Perfekt om du tycker om överraskningar i trädgården.",severity:"tip"},{icon:"tip",title:"Insekternas favorit",text:"När dillkronorna blommar är det som en nattklubb för nyttiga insekter. Parasitsteklar, nyckelpigor, blomflugor - alla kommer. Låt några plantor blomma ut så får hela trädgården gratis biologisk bekämpning.",severity:"tip"},{icon:"warning",title:"Direktså alltid - flytta aldrig dill",text:"Dill har en djup pålrot och AVSKYR att bli omflyttad. Förodling fungerar dåligt - fröet gror snabbt utomhus ändå. Så direkt på friland, det är enklast och bäst.",severity:"warning"}],sowing:{method:"direct",label:"Direktsådd",description:"Dill sås alltid direkt på friland - hon har en ömtålig pålrot som inte tål omplantering. Fröet gror på 10-14 dagar och redan efter 40 dagar kan du börja skörda blad. Enklare än så blir det inte.",steps:["Luckra jorden och kratta till jämn yta","Dra grunda spår (0.5-1 cm djupa) med 25-30 cm avstånd","Så fröet glest längs raderna - blanda gärna med lite sand för jämnare fördelning","Täck försiktigt med ett tunt lager jord eller vermiculit","Vattna försiktigt med stril - fröet är litet och sköljs lätt bort","Håll jämnt fuktigt tills plantorna är uppe (10-14 dagar)","Gallra till 15-20 cm avstånd när plantorna är 5 cm höga"],tips:["Så i omgångar med 3 veckors mellanrum för färsk dill hela sommaren - det viktigaste tipset!","Kan sås från april (zon 1-3) till juni. Dillfrö gror redan vid 5°C","Sår sig själv kraftigt - låt några plantor gå i frö så har du gratis dill nästa år","Fungerar bra i kruka (minst 5 liter) - välj en kompakt sort som Bouquet för bäst resultat"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Insektspollinerad",biennial:!1,description:"Dill är en av de enklaste växter att spara frö från. Låt dillkronorna torka på plantan, samla in och du har frö för många år framåt.",steps:["Låt några plantor blomma ut helt - dillkronorna ska bli stora och gula","Vänta tills fröet börjar mogna - kronorna får en brunaktig ton","Klipp av hela dillkronan när de första fröna börjar lossna","Lägg kronorna upp och ner i en papperspåse","Låt torka 1-2 veckor på en varm, torr plats","Skaka påsen - fröet faller av självt","Förvara svalt och torrt i märkt kuvert eller glasburk"],isolation:"Dill pollineras av insekter och korsar lätt med andra dillsorter. Håll minst 500 meters avstånd mellan sorter för sortrena frön. Korsar inte med fänkål eller morot trots samma familj.",storageYears:"3-5 år",tip:"Dillkronor med frö är en klassiker i köket också - använd dem för att lägga in gurka innan du sparar resten som utsäde!"},storage:{shelfLife:"3-5 dagar (färsk)",methods:[{method:"Frysning (bäst!)",icon:"snowflake",duration:"6+ månader",description:"Hacka dillen fint, fördela i isbitsfack och fyll på med vatten. Frys. Varje kub är en perfekt portion för soppa, sås eller potatis. Smakar nästan som färsk.",best:!0},{method:"Torkning",icon:"storage",duration:"12+ månader",description:"Häng knippen upp och ner på en luftig plats eller torka i ugn på 40°C. Torkad dill tappar en del smak men fungerar bra i matlagning. Krossa inte förrän du ska använda den.",best:!1},{method:"Dillfrö (dillkronor)",icon:"seed",duration:"Flera år",description:"Torka dillkronorna och förvara fröet i glasburk. Dillfrön är faktiskt godare än bladen i många rätter - oumbärliga för inlagd gurka och bröd.",best:!1},{method:"I vatten (kort lagring)",icon:"water",duration:"5-7 dagar",description:"Ställ stjälkar i ett glas vatten i kylen, täck löst med en plastpåse. Byt vatten varannan dag. Fungerar för någon veckas planering.",best:!1}],tips:["Frys i isbitsfack med vatten - perfekta portioner att slänga direkt i grytan","Skörda på morgonen för bäst smak - de eteriska oljorna är starkast då","Torkad dill tappar smak snabbt efter malning - förvara hel och krossa först vid användning","Dillfrö är minst lika viktigt som dillblad i svensk matlagning - spara alltid lite!"]},harvestCalc:{minPerSqm:.2,maxPerSqm:.5,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp blad efter behov, låt några plantor gå i frö för dillkronor",description:"Skörda dillblad fritt under hela säsongen - klipp stammar när plantan är minst 15 cm hög. Ju mer du klipper desto mer blad bildas (upp till en gräns). Låt alltid några plantor gå i frö för att få dillkronor till inläggning.",uses:[{use:"Färsk",tip:"Tillsätt SIST i matlagningen - värme förstör smaken. Klassisk till kokt potatis, sås, fisk och sallader. Riv med händerna för bäst resultat."},{use:"Fröer (dillkronor)",tip:"Oumbärliga för inlagd gurka, bröd och kryddsnaps. Skörda kronorna när fröet är gulgrönt men inte helt moget - då har de mest smak."},{use:"Torkad",tip:"Häng knippen upp och ner på luftig plats. Tappar en del smak men fungerar bra i matlagning över vintern. Förvara i tät burk."},{use:"Frusen",tip:"Hacka fint och frys i isbitsfack med vatten. Bästa metoden för att bevara smaken. Smakar nästan som färsk även mitt i vintern."}]}},_r=Object.freeze(Object.defineProperty({__proto__:null,dill:p},Symbol.toStringTag,{value:"Module"})),u={name:"Dragon",icon:"dragon",category:"kryddor",family:"Korgblommiga",familyLatin:"Asteraceae",perennial:!0,lifespan:"3-5 år (dela vart tredje år)",difficulty:"Medel",difficultyWhy:"Dragon (den franska sorten) är inte svår att sköta väl etablerad, men kräver lite extra: hon övervintrar inte alltid i svenska jordar, måste förökas vegetativt (inga frön!) och vill ha perfekt dränering. Men belöningen är en av kökets mest raffinerade kryddor.",zones:{outdoor:[1,2,3],indoor:[1,2,3,4,5,6,7,8],greenhouse:[1,2,3,4,5]},days:"60-75 dagar från plantering till första skörd",spacing:"40 cm",rowSpacing:"40 cm",depth:"Krukdjup",depthNote:"Vegetativ förökning - säljs som planta",ph:{min:6.5,max:7.5,ideal:6.8},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Dragon vill ha full sol - minst 6 timmars direkt solljus per dag. I halvskugga blir hon ranglig och aromen svagare. Söderläge mot en varm husvägg? Perfekt - hon suger in värmen precis som rosmarinen."},temperature:{min:-15,max:35,ideal:"18-25°C",detail:"Dragon gillar värme under växtsäsongen men klarar inte svenska vintrar lika bra som man hoppas. Fransk dragon övervintrar ned till ungefär -15 till -20°C - men bara i väldränerad jord. Blöt vinterjord dödar snabbare än kylan."},wind:{level:"Skyddat",detail:"Föredrar ett skyddat, varmt läge. De långa stammarna kan knäckas i hård vind. En skyddad plats i kryddlandet eller nära en varm husvägg är idealiskt."}},watering:{need:"Låg",icon:"water",summary:"Dragon är torktålig och föredrar att vara lite torr framför att stå blöt. Tänk medelhavsväxt - hon vill inte torka ut helt men avskyr våta fötter.",phases:[{phase:"Nyplantering (första veckorna)",need:"Medel",tip:"Håll jämnt fuktigt de första 2-3 veckorna efter plantering eller delning. Rötterna behöver etablera sig."},{phase:"Etablerad planta",need:"Låg",tip:"Låt jorden torka mellan vattningarna. Dragon trivs bättre lite torr än lite blöt. Vattna vid basen, aldrig på bladen."},{phase:"Högsommar",need:"Låg",tip:"Även i värme klarar hon sig bra med sparsam vattning. Väldränerad jord och solsken är viktigare än vatten."}],mistakes:["Övervattnar - den absolut vanligaste dödsorsaken! Rotröta slår till snabbt i blöt jord","Vattnar på bladen - fuktig bladyta bjuder in mjöldagg och svampsjukdomar","Planterar i tung lerjord utan dränering - döden för dragon, speciellt på vintern"],tip:"Känner du dig osäker - vattna mindre! Dragon klarar torka mycket bättre än övervattning. En tumregel: om du tvekar om du ska vattna, vänta en dag till."},soil:"Lätt, väldränerad jord med måttlig näring. Dragon trivs i sandig-lerig jord som aldrig blir vattensjuk. Tung lerjord? Hennes värsta mardröm.",soilTips:["Blanda in rikligt med sand eller grus i tung jord - dränering är livsviktigt","Upphöjd bädd fungerar utmärkt, speciellt i lerig trädgård","Lagom näringsrik - övergödslad dragon växer snabbt men tappar sin karakteristiska smak","I kruka: vanlig planteringsjord blandat med en tredjedel perlit eller sand"],timeline:{1:[{phase:"Delning/plantering",months:"Apr",icon:"seedling"},{phase:"Sticklingar",months:"Maj-jun",icon:"seedling"},{phase:"Skörd löpande",months:"Jun-sep",icon:"harvest"},{phase:"Beskärning inför vinter",months:"Okt-nov",icon:"pruning"},{phase:"Vintervila",months:"Nov-mar",icon:"dormant"}],4:[{phase:"Delning/plantering",months:"Maj",icon:"seedling"},{phase:"Sticklingar",months:"Jun",icon:"seedling"},{phase:"Skörd löpande",months:"Jul-sep",icon:"harvest"},{phase:"Beskärning + vinterskydd",months:"Okt",icon:"pruning"},{phase:"Vintervila",months:"Nov-apr",icon:"dormant"}],6:[{phase:"Plantering (kruka)",months:"Jun",icon:"seedling"},{phase:"Skörd löpande",months:"Jul-aug",icon:"harvest"},{phase:"Ta in kruka",months:"Sep",icon:"indoor"},{phase:"Vintervila inomhus",months:"Okt-maj",icon:"dormant"}]},nutritionData:[{month:"Apr",N:2,P:1,K:1},{month:"Maj",N:3,P:2,K:2},{month:"Jun",N:4,P:2,K:3},{month:"Jul",N:3,P:2,K:3},{month:"Aug",N:2,P:2,K:2},{month:"Sep",N:1,P:1,K:1}],nutritionTips:[{timing:"Tidig vår",tip:"En lätt giva kompost när de nya skotten visar sig. Dragon har modest näringsbehov - lite är mer."},{timing:"Försommar",tip:"Eventuellt en svag giva flytande näring om plantorna ser bleka ut. Men övergödsla inte - mager jord ger faktiskt bättre smak."},{timing:"Obs!",tip:"Aldrig kraftig kvävegödsel! Dragon som överstimuleras växer fort men smaken blir platt och intetsägande. Hellre lite hungrig och aromatisk."}],companions:{good:[{id:"graslok",name:"Gräslök",icon:"herb",why:"Gräslök avskräcker spinnkvalster som ibland angriper dragon. Dessutom trivs båda i soligt läge med liknande skötsel."},{id:"vitlok",name:"Vitlök",icon:"vegetable",why:"Vitlöks starka doft skyddar mot spinnkvalster och andra skadedjur. Dragon sägs dessutom stimulera vitlökens tillväxt."},{id:"koriander",name:"Koriander",icon:"herb",why:"Liknande vattenbehov och koriander lockar nyttiga insekter som håller skadedjur i schack."}],bad:[{id:"dill",name:"Dill",icon:"herb",why:"Dill och dragon konkurrerar och verkar hämma varandra. Håll dem separata i kryddlandet."},{id:"persilja",name:"Persilja",icon:"herb",why:"Dålig granne som inte verkar trivas bredvid dragon. Persiljans fuktigare preferenser krockar med dragons torrtålighet."}]},rotation:{avoid:[{id:"sallat",name:"Sallat"},{name:"Kronärtskocka"},{name:"Solros"}],avoidWhy:"Korgblommiga (Asteraceae) delar en del jordburna sjukdomar. Vänta 2-3 år. Men i praktiken stannar dragon på sin plats i 3-4 år innan hon behöver delas och flyttas.",goodBefore:[{name:"Baljväxter"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter berikar jorden med kväve. Lök lämnar ren jord.",goodAfter:[{id:"morot",name:"Morot"},{id:"rodbeta",name:"Rödbeta"}],goodAfterWhy:"Rotgrönsaker trivs bra efter dragon som lämnat väldränerad, inte alltför näringsrik jord."},varieties:[{name:"Fransk dragon (Artemisia dracunculus var. sativa)",zones:[1,2,3],note:"DEN kulinariska dragonarten. Intensiv anis/lakritssmak, grågröna blanka blad. Kan INTE odlas från frö - måste köpas som planta eller förökas via delning. Köp på Blomsterlandet, Perennfolket eller Klostra (KRAV). OP."},{name:"Rysk dragon (Artemisia dracunculus var. inodora)",zones:[1,2,3,4,5],note:"Mycket härdigare men SVAGARE smak - nästan smaklös jämfört med franska. Kan odlas från frö (Runåbergs, Impecta). Fungerar i norr där franska inte klarar vintern. OP."},{name:"Mexikansk dragon (Tagetes lucida)",zones:[1,2,3],note:"Egentligen inte dragon utan en tagetes - men smaken påminner mer om fransk dragon än rysk gör! Ettårig i Sverige. Frö hos Runåbergs och Lindbloms. Bra alternativ i kruka. OP."}],problems:[{name:"Rotröta",symptom:"Plantan sloknar och gulnar trots att jorden inte verkar torr. Stambasen mörknar. Rötterna är bruna och mjuka.",fix:"Tyvärr ingen bot. Förebygg med perfekt dränering och sparsam vattning. Dragon vill hellre vara lite torr. I tung jord: upphöjd bädd eller kruka."},{name:"Utvintring",symptom:"Plantan kommer inte tillbaka på våren trots att det inte var extremt kallt.",fix:"Ofta orsakat av blöt vinterjord snarare än kyla. Mulcha med halm på hösten, se till att dräneringen är perfekt. I zon 4+: odla i kruka och ta in till ouppvärmt utrymme."},{name:"Spinnkvalster",symptom:"Fina spindelväv mellan bladen, bladen blir bleka och prickiga. Vanligast i torr, varm luft.",fix:"Spola av med vatten regelbundet. Plantera gräslök eller vitlök intill som avskräcker kvalster. I allvarliga fall: insektssåpa."},{name:"Mjöldagg",symptom:"Vitt, pudrigt överdrag på bladen. Vanligast i fuktig luft med dålig cirkulation.",fix:"Plantera luftigt med god avstånd. Vattna vid basen, aldrig på bladen. Klipp bort angripna delar."}],goodToKnow:[{icon:"warning",title:"Frö = rysk dragon!",text:'All "dragonfrö" som säljs är RYSK dragon (nästan smaklös). Äkta fransk dragon sätter inte grobart frö - hon måste köpas som planta eller förökas genom delning. Bli inte lurad!',severity:"warning"},{icon:"warning",title:"Vinterdränering viktigare än köld",text:"Dragon dör oftare av blöt vinterjord än av kyla. Se till att platsen aldrig blir vattensjuk, speciellt under vintern. Upphöjd bädd eller kruka i utsatta lägen.",severity:"warning"},{icon:"tip",title:"Dela var 3-4 år",text:"Dragon tappar kraft och smak efter 3-4 år på samma plats. Gräv upp, dela rotklumpen och plantera om på ny plats. Det föryngrar plantan och du får nya plantor på köpet!",severity:"tip"},{icon:"tip",title:"Bearnaisekungens krydda",text:"Dragon är den hemliga hjälten i bearnaisesås, sauce ravigote och fines herbes. Den anisliknande, lätt peppriga smaken är helt oersättlig i fransk matlagning. Pröva också dragonvinäger!",severity:"tip"},{icon:"tip",title:"Lilla draken",text:'Namnet "dragon" kommer från latinets "dracunculus" - liten drake. Rötterna ansågs likna sammanflätade ormar, och örten användes förr som botemedel mot ormbett. Idag vet vi att den istället är en stjärna i köket.',severity:"tip"},{icon:"tip",title:"Tillsätt SIST i grytan",text:"Dragons delikata arom förstörs av långkok. Tillsätt alltid färsk dragon i slutet av tillagningen, eller använd den rå. Värme tar livet av den fina anissmaken.",severity:"tip"}],sowing:{method:"indoor",label:"Vegetativ förökning (delning/sticklingar)",description:"Fransk dragon kan INTE odlas från frö - blommorna är sterila. Hon förökas genom rotdelning på våren eller sticklingar på försommaren. Enklast: köp en planta och dela den efter 2-3 år.",steps:["DELNING (våren, april-maj): Gräv upp hela rotklumpen försiktigt","Dela med en vass kniv (inte spade - rötterna är sköra) i bitar med 3-5 skott vardera","Plantera omedelbart på samma djup som förut, 40 cm mellanrum","Vattna ordentligt efter plantering, sedan sparsamt","STICKLINGAR (maj-juni): Klipp 10-15 cm skott tidigt på morgonen","Ta bort bladen på nedre tredjedelen, doppa i rotningshormon","Sätt i fuktig såjord, håll varmt och fuktigt i ca 4 veckor tills rötter bildats","KÖP PLANTA: Det enklaste sättet att komma igång - Blomsterlandet, Perennfolket eller Klostra"],tips:["Dela varje 3-4 år för att hålla plantan vital - annars tappar hon kraft och smak","Sticklingar på morgonen när plantan är full av fukt ger bäst resultat","Kontrollera alltid att det verkligen är FRANSK dragon du köper - gnid ett blad och känn efter den starka anisdoften"],indoorWeeks:null},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!1,description:"Fransk dragon sätter inte grobart frö - punkten. Frötagning är inte möjlig. Föröka istället genom delning eller sticklingar, vilket ger exakta kopior av moderplantan.",steps:["Frötagning är inte möjlig för fransk dragon (sterila blommor)","Föröka via rotdelning: gräv upp och dela rotklumpen på våren","Föröka via sticklingar: klipp 10-15 cm skott i maj-juni","Varje delning ger 3-5 nya plantor","Dela moderplantan var 3-4 år för att bibehålla vitalitet"],isolation:"Inte aktuellt - frötagning är inte möjlig.",storageYears:"Inte aktuellt",tip:'Obs! Om du ser "dragonfrö" till salu är det ALLTID rysk dragon (svag smak). Äkta fransk dragon förökas bara vegetativt.'},storage:{shelfLife:"Färsk 1-2 veckor, fryst 6+ månader",methods:[{method:"Frysning (bäst!)",icon:"snowflake",duration:"6+ månader",description:"Frys hela kvistar i fryspåsar eller hacka och frys i isbitsformar med lite vatten. Dragon behåller sin smak fantastiskt bra i frysen - till skillnad från torkning. Perfekt för bearnaise mitt i vintern!",best:!0},{method:"Dragonvinäger",icon:"storage",duration:"6-12 månader",description:"Lägg färska kvistar i flaska med vitvinsvinäger. Dra i 2-4 veckor, sila. En klassiker i franskt kök och ett underbart sätt att fånga smaken.",best:!1},{method:"Färsk i kyl",icon:"water",duration:"1-2 veckor",description:"Linda i fuktigt hushållspapper och lägg i plastpåse i kylen. Dragon håller sig förvånansvärt bra färsk - bättre än de flesta örter.",best:!1},{method:"Torkning",icon:"storage",duration:"6-12 månader",description:"Häng kvistar uppochner på torr, mörk plats. Men varning: fransk dragon tappar mycket av sin fina arom vid torkning. Frysning är klart bättre.",best:!1}],tips:["Frysning bevarar dragons delikata anisarom bäst - överlägset torkning","Dragonvinäger är en gourmetklassiker och ett perfekt sätt att konservera smaken","Torkning funkar i nödfall men räkna med att du förlorar minst hälften av aromen","Skörda på morgonen för bäst smak och hållbarhet i alla konserveringsmetoder"]},harvestCalc:{minPerSqm:.05,maxPerSqm:.15,unit:"kg"},harvest:{label:"Skörd och användning",method:"Nyp av skottspetsar, klipp kvistar - regelbunden skörd gör plantan buskigare",description:"Skörda dragon genom att klippa skottspetsar eller hela kvistar under hela säsongen. Regelbunden skörd stimulerar ny tillväxt och håller plantan kompakt. Skörda aldrig mer än en tredjedel åt gången. Bäst smak precis före eventuell blomning. Tillsätt alltid sist i matlagningen - värme förstör den delikata aromen.",uses:[{use:"Bearnaisesås",tip:"Dragons absoluta paradgren. Reducera dragon med vinäger och schalottenlök som bas. Utan dragon, ingen bearnaise - det är så enkelt."},{use:"Kyckling och fisk",tip:"Lägg hela kvistar under skinnet på kycklingen före stekning, eller strö hackad dragon över grillad fisk. Anissmaken gifter sig magiskt med vita proteiner."},{use:"Dragonvinäger",tip:"Lägg färska kvistar i en flaska vitvinsvinäger. Låt dra i 2-4 veckor. Använd i vinaigretter, såser och marinader - en fransk klassiker."},{use:"Ägg och ost",tip:"En nypa färsk dragon i omeletten eller äggröran lyfter hela rätten. Också fantastisk i örtsmör till bakat bröd."}]}},Ir=Object.freeze(Object.defineProperty({__proto__:null,dragon:u},Symbol.toStringTag,{value:"Module"})),v={name:"Endiv",icon:"endiv",family:"Korgblommiga",familyLatin:"Asteraceae",difficulty:"Medel",difficultyWhy:"Inte svår att odla i sig, men blekningstekniken kräver lite kunnande och timing. Belöningen är en sallad med helt annan karaktär än vanlig sallat - krispig, lätt bitter och elegant.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:[1,2,3,4,5,6,7]},days:"55-100",spacing:"25-30 cm",rowSpacing:"40-50 cm",depth:"0.5-1 cm",depthNote:"Ljusgroddare - tryck fast men täck knappt",ph:{min:6.5,max:7.5,ideal:7},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"partial-sun",detail:"Trivs i sol men uppskattar halvskugga mitt på dagen, särskilt under högsommaren. Stark sol och värme ökar bitterheten och risken för skottskjutning."},temperature:{min:-5,max:24,ideal:"15-18°C",detail:"Klarar lätt frost ner till -3 till -5°C och blir faktiskt mildare i smaken av det! Men över 24°C stressar hon och kan skjuta i blom. Trivs allra bäst i sval höstluft - liknar kinakål i den aspekten."},wind:{level:"Tålig",detail:"Relativt vindtålig tack vare sin kompakta växtstil. Lite vindskydd skadar inte men är inget krav."}},watering:{need:"Medel-Hög",icon:"water",summary:"Endiv vill ha jämn fukt hela säsongen. Torka gör henne bitter och stressad, men stående vatten ger rotröta. Hitta balansen - jämn och lagom.",phases:[{phase:"Groning (1-2 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig. Vattna med kall stril om det är varmt ute - endivfrön gror dåligt i het jord."},{phase:"Tillväxt (3-6 veckor)",need:"Medel-Hög",tip:"Regelbunden vattning 2-3 gånger i veckan. Jämn fukt ger saftiga blad med mildare smak."},{phase:"Huvudbildning",need:"Medel-Hög",tip:"Fortsätt med jämn vattning. Vattenstress nu ökar bitterheten markant."},{phase:"Blekning (1-3 veckor före skörd)",need:"Låg-Medel",tip:"Minska vattningen lite och se till att bladen är TORRA innan du bleker. Fukt + täckning = röta."}],mistakes:["Ojämn vattning ökar bitterheten avsevärt - det vanligaste misstaget","Vattna på bladen under blekning - ger röta och förstör hela plantan","Låta jorden torka ut i värmeböljor - endiv börjar skjuta i blom","Stående vatten vid rötterna, särskilt i tung jord"],tip:"Mulcha med gräsklipp eller halm för att hålla jämn markfukt. Undvik dock mulch nära bladen under blekning."},soil:"Lucker, mullrik och fukthållande jord. Gärna kalkrik - endiv trivs i neutral till svagt basisk mark. Inte så hungrig som kål men vill ha god grund.",soilTips:["Blanda in välbrunnen kompost före sådd - endiv uppskattar mullrik jord men behöver inte lika mycket näring som kål","Kalka om pH ligger under 6.5 - endiv trivs bäst i neutral till svagt basisk jord","Upphöjda bäddar fungerar utmärkt, särskilt i tung jord - bättre dränering och varmare mark"],timeline:{1:[{phase:"Förkultivering vår",months:"Feb-Mar",icon:"seedling"},{phase:"Direktsådd vår",months:"Apr-Maj",icon:"seedling"},{phase:"Tillväxt",months:"Maj-Aug",icon:"leaf"},{phase:"Direktsådd höst",months:"Jun-Aug",icon:"seedling"},{phase:"Blekning",months:"Jul-Okt",icon:"leaf"},{phase:"Skörd",months:"Jun-Nov",icon:"harvest"}],4:[{phase:"Förkultivering",months:"Mar-Apr",icon:"seedling"},{phase:"Direktsådd",months:"Maj-Jul",icon:"seedling"},{phase:"Tillväxt",months:"Jun-Sep",icon:"leaf"},{phase:"Blekning",months:"Aug-Okt",icon:"leaf"},{phase:"Skörd",months:"Jul-Okt",icon:"harvest"}],6:[{phase:"Förkultivering",months:"Apr-Maj",icon:"seedling"},{phase:"Direktsådd",months:"Jun-Jul",icon:"seedling"},{phase:"Tillväxt",months:"Jul-Aug",icon:"leaf"},{phase:"Blekning",months:"Aug-Sep",icon:"leaf"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Maj",N:30,P:15,K:20,label:"Tidig tillväxt"},{month:"Jun",N:50,P:20,K:30,label:"Bladtillväxt"},{month:"Jul",N:45,P:25,K:35,label:"Huvudbildning"},{month:"Aug",N:30,P:20,K:30,label:"Blekning"},{month:"Sep",N:15,P:10,K:20,label:"Skörd"}],nutritionTips:[{timing:"Före sådd",tip:"Grundgödsla med brunnen kompost. Endiv är en måttlig ätare - övergödsla inte med kväve, det ökar bitterheten."},{timing:"Under tidig tillväxt",tip:"En giva flytande kompostvatten när plantorna är 5-10 cm höga, särskilt i mager jord."},{timing:"Vid huvudbildning",tip:"En sista lätt giva kaliumrikt gödsel (vedaska) stärker bladen och ger krispigare textur."},{timing:"Under blekning",tip:"Ingen gödsling under blekningsperioden. Plantan ska lugna ner sig, inte skjuta nya blad."}],companions:{good:[{id:"morot",name:"Morot",icon:"vegetable",why:"Komplementära rotsystem - moroten går djupt, endiv håller sig grunt. Endiv skuggar marken och håller fukten."},{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft avskräcker bladlöss och andra skadedjur som gillar endiv"},{id:"radisa",name:"Rädisa",icon:"vegetable",why:"Snabb skörd som luckrar jorden och frigör plats innan endiv breder ut sig"},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Kvävefixerare som gynnar endivens bladtillväxt"}],bad:[{id:"sallat",name:"Sallat",icon:"vegetable",why:"Samma familj (Asteraceae) - delar sjukdomar som sallatsmögel och bladlöss"},{id:"jordartskocka",name:"Jordärtskocka",icon:"vegetable",why:"Samma familj och skuggar dessutom ut endiv med sina enorma stjälkar"},{id:"pumpa",name:"Pumpa",icon:"vegetable",why:"Konkurrerar aggressivt om näring och utrymme med sina stora blad"}]},rotation:{avoid:[{id:"sallat",name:"Sallat"},{id:"jordartskocka",name:"Jordärtskocka"},{name:"Solros"},{name:"Kronärtskocka"}],avoidWhy:"Alla korgblommiga (Asteraceae) delar sjukdomar som sallatsmögel och sallatsrotlus. Vänta minst 2-3 år innan du odlar endiv där annan korgblommig stått.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter fixerar kväve som gynnar endivens bladtillväxt. Lök lämnar ren jord utan korgblommigssjukdomar.",goodAfter:[{id:"gronkal",name:"Grönkål"},{id:"morot",name:"Morot"},{id:"lok",name:"Lök"}],goodAfterWhy:"Kål, rotgrönsaker och lök tillhör helt andra familjer och påverkas inte av endivens sjukdomshistorik i jorden."},varieties:[{name:"Pancalieri",zones:[1,2,3,4,5,6],note:"Italiensk kulturarvssort sedan 1885. Krusiga, djupt flikiga blad. Självblekande mittdel! Kraftig och härdig. Snabb - 55 dagar. Runåbergs, ekologiskt frö."},{name:"Gigante degli ortolani",zones:[1,2,3,4,5],note:"Bredbladig escarole-typ. Stora, lösa, ljusgröna huvuden med vågiga blad. Självblekande inre. Mildare smak. Frosttålig. Impecta."},{name:"Riccia d'Olivet",zones:[1,2,3,4,5],note:"Frisee-typ med ljusgröna, fint flikiga blad. Dekorativ och mild cikoriasmak. Frosttålig. Impecta."},{name:"Fine de Louviers",zones:[1,2,3,4],note:'Snabbväxande frisee med fint skurna blad "nästan som spets". Frisk, pikant smak. Vacker i salladen. Wexthuset.'},{name:"Nuance",zones:[1,2,3,4,5],note:"Modern sort med bred användning - vår, sommar och höstskörd. Ekologiskt frö. Wexthuset."}],problems:[{name:"Sniglar",symptom:"Hål i blad och slemspår, särskilt på unga plantor och under fuktiga perioder.",fix:"Snigelkorn (järnfosfat), ölfällor, handplockning på kvällen. Var extra vaksam de första veckorna efter utplantering."},{name:"Bladlöss",symptom:"Krusiga blad, honungsdagg och kolonier av bladlöss på undersidan av bladen.",fix:"Spreja med utspädd såpa. Locka nyckelpigor med dill och gurkört. Starka växter tål en liten population."},{name:"Mjöldagg",symptom:"Vitt, puddrigt belägg på bladen. Vanligare sent på säsongen.",fix:"Luftig plantering med rätt avstånd. Vattna vid roten, aldrig på bladen. Klipp bort angripna blad."},{name:"Röta vid blekning",symptom:"Brunaktiga, smetiga blad inuti huvudet under blekningsperioden.",fix:"Bleka BARA när bladen är helt torra. Kontrollera dagligen under blekning. Ta bort förband direkt om du ser röta."}],goodToKnow:[{icon:"tip",title:"Blekning gör magin",text:"Bind ihop yttre bladen med snöre eller täck plantan med en kruka 2-3 veckor före skörd. Ljusbrist gör de inre bladen gula, milda och söta istället för gröna och bittra. Det är endivens hemlighet!",severity:"tip"},{icon:"warning",title:"Bleka bara vid torrt väder",text:"Bladen MÅSTE vara torra innan du binder ihop dem. Fukt inuti det ihopbundna huvudet ger röta snabbare än du tror. Kolla dagligen och avbryt om det börjar regna länge.",severity:"warning"},{icon:"harvest",title:"Sötare efter frost",text:"Precis som grönkål och kinakål blir endiv mildare och sötare efter den första lätta frosten. Plantan omvandlar stärkelse till socker - höstsådd ger bäst smak!",severity:"tip"},{icon:"warning",title:"Inte samma som cikoria",text:"Endiv (Cichorium endivia) och cikoria (Cichorium intybus) är olika arter trots att de är nära släkt. Radicchio och belgisk endiv är cikoria - inte endiv. Förvirrande men viktigt!",severity:"tip"},{icon:"leaf",title:"Cut-and-come-again",text:"Skär 5 cm ovanför marken och lämna rotkronan. Nya blad växer tillbaka inom ett par veckor. Du kan skörda samma planta 2-3 gånger!",severity:"tip"},{icon:"seedling",title:"Successiv sådd ger lång skörd",text:"Så en ny omgång var 2-3 vecka från maj till augusti. Då har du färsk endiv hela säsongen istället för att drunkna i sallad på en gång.",severity:"tip"}],sowing:{method:"both",label:"Direktsådd eller förkultivering",description:"Endiv kan både direktsås och förkultiveras. Direktsådd är enklast men förkultivering ger tidigare skörd och bättre kontroll. Höstsådd (juni-augusti) ger den bästa smaken!",steps:["Direktsådd: Dra ett grunt spår (0.5-1 cm djupt) och strö ut fröna glest. Endivfrö är ljusgroddare - tryck fast men täck knappt","Vattna försiktigt med stril direkt efter sådd. Håll jorden jämnt fuktig tills fröna grott (6-10 dagar)","Gallra till 25-30 cm avstånd när plantorna har 3-4 riktiga blad. Gallringsplantorna kan ätas som babysallad","Förkultivering: Så i pluggbrätte 3-4 veckor före utplantering. Ytligt - knappt täck fröna med jord","Plantera ut på 25-30 cm avstånd. Vattna rikligt vid plantering","Mulcha runt plantorna för att hålla jämn fukt och hindra ogräs","Täck med fiberduk de första veckorna om jordloppor eller sniglar är problem i din trädgård"],tips:["Höstsådd (juni-augusti) ger mildare, sötare endiv än vårsådd - sval höstluft minskar bitterheten","Endivfrön gror dåligt i stark värme - vattna med kallt vatten och skugga om du sår mitt i sommaren","Successiv sådd var 2-3 vecka ger kontinuerlig skörd istället för allt på en gång"],indoorWeeks:"3-4 veckor"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!1,description:"Endiv är en tvåårig växt som blommar andra året, men kan skottskjuta första året vid stress. Insektspollinerad och självfertil - du kan ta frö från en enda planta om du vill. Korsar med andra endivsorter men INTE med cikoria.",steps:["Välj de finaste plantorna med bäst huvudbildning och senast skottskjutning","Låt plantorna övervintra (med skydd i zon 3+) eller stressa en sen planta genom att minska vattning","Andra året skjuter plantan upp blomstjälkar med ljusblå blommor","Låt blommorna falla av och fröhuvudena torka på plantan tills de är bruna","Klipp av blomstjälkarna och torka i papperspåse inomhus en vecka","Gnugga loss fröna och blås bort skal och fjun försiktigt","Torka fröna ytterligare 1-2 veckor på en tallrik","Förvara i märkt papperspåse, svalt och torrt"],isolation:"Endivsorter korsar med varandra (frisee x escarole) men INTE med cikoria (annan art). Isolera minst 500 m mellan sorter, eller använd nätpåsar - endiv är självfertil.",storageYears:"5-8 år",tip:"Alla rekommenderade sorter är OP - perfekta för fröbesparing! Endivfrö håller sig länge vid korrekt förvaring. Tänk bara på att endiv behöver en vinterperiod för att blomma."},storage:{shelfLife:"1-3 veckor",methods:[{method:"Kylskåp",icon:"snowflake",duration:"1-2 veckor",description:"Linda i fuktigt hushållspapper och lägg i plastpåse med hål i grönsakslådan. Tvätta inte förrän du ska använda - fukt ger röta.",best:!0},{method:"Kallare/jordkällare",icon:"storage",duration:"3-4 veckor",description:"Hela plantor med rot. Ställ upprätt i fuktig sand vid 0-5°C och hög luftfuktighet. Kontrollera veckovis.",best:!1},{method:"I marken",icon:"leaf",duration:"Veckor",description:"Lämna plantorna ute med fiberduk som frostskydd. Endiv tål lätt frost och håller sig fräsch längre i odlingen än i kylskåpet.",best:!1}],tips:["Skörda hela plantan med rot för längst hållbarhet","Lagra aldrig tillsammans med äpplen eller tomater - etylengasen påskyndar nedbrytning","Blekta plantor håller sig kortare än oblekta - bleka bara det du planerar att äta snart","Yttre blad som vissnar kan plockas bort - inuti är huvudet ofta fortfarande fräscht"]},harvestCalc:{minPerSqm:2,maxPerSqm:4,unit:"kg"}},Wr=Object.freeze(Object.defineProperty({__proto__:null,endiv:v},Symbol.toStringTag,{value:"Module"})),h={name:"Fänkål",icon:"fankal",family:"Flockblommiga",familyLatin:"Apiaceae",difficulty:"Medel",difficultyWhy:"Knölfänkålen är lite av en diva - hon skjuter i blom vid minsta stress. Men med rätt timing, bra vatten och en skyddad plats belönar hon dig med krispiga, anissmakande knölar.",zones:{outdoor:[1,2,3,4],indoor:null,greenhouse:[5,6]},days:"65-90",spacing:"25-30 cm",rowSpacing:"40-50 cm",depth:"1-2 cm",ph:{min:6,max:7.5,ideal:6.8},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Fänkålen vill ha full sol för att utveckla fina knölar. I halvskugga blir knölarna mindre och smaken svagare."},temperature:{min:-2,max:28,ideal:"15-22°C",detail:"Trivs bäst i sval-varm temperatur. Tål lätt frost ner till -2°C men ogillar kyla under etableringen - det triggar blomning. Temperaturer över 28°C stressar henne och kan också ge skottbildning."},wind:{level:"Skyddat",detail:"Vill stå skyddat. Kall vind stressar och ökar risken för att hon skjuter i blom. En varm, vindskyddad plats är nyckeln till fina knölar."}},watering:{need:"Medel-Hög",icon:"water",summary:"Fänkålen behöver jämn fukt - torka är hennes största fiende. Ojämn vattning leder rakt till blomning istället för fina knölar.",phases:[{phase:"Etablering (0-3 veckor)",need:"Hög",tip:"Håll jämnt fuktig efter utplantering eller direktsådd. Uttorkad jord under etableringen är den vanligaste orsaken till att hon skjuter i blom."},{phase:"Tillväxt (3-8 veckor)",need:"Medel-Hög",tip:"Vattna regelbundet, minst varannan dag vid torrt väder. Mulcha runt plantorna för att hålla fukten jämn."},{phase:"Knölbildning (8+ veckor)",need:"Hög",tip:"Nu svälljer knölen - håll jämnt fuktig. Kupa jord runt knölen för blekning och skydd."}],mistakes:["Låta jorden torka ut - triggar blomning snabbare än något annat","Ojämn vattning som ger sprickor i knölen","Vattna ovanifrån och blöta ner hjärtat - kan ge röta"],tip:"Mulcha ordentligt runt plantorna med gräsklipp eller halmhack. Det håller fukten jämn och minskar stressen - och det är stress som gör att fänkålen blommar istället för att bilda knöl."},soil:"Djup, mullrik, väldränerad jord. Gärna sandblandad lera som håller fukt utan att bli vattensjuk. Fänkålen vill ha det näringsrikt - till skillnad från moroten gillar hon gödslad jord.",soilTips:["Blanda in rikligt med kompost eller brunnen stallgödsel innan plantering","Jorden ska vara lucker och djup - knölen sitter halvt ovanpå marken men rötterna går djupt","Undvik packad lerjord - den ger dålig dränering och stressar plantorna","Kalka om pH är under 6.0 - fänkålen gillar det neutralt"],timeline:{1:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Plantera ut",months:"Apr-Maj",icon:"seedling"},{phase:"Direktså (alternativ)",months:"Apr-Maj",icon:"seedling"},{phase:"Kupa knölar",months:"Jun-Jul",icon:"scissors"},{phase:"Skörd",months:"Jul-Sep",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj-Jun",icon:"seedling"},{phase:"Direktså (alternativ)",months:"Maj-Jun",icon:"seedling"},{phase:"Kupa knölar",months:"Jul-Aug",icon:"scissors"},{phase:"Skörd",months:"Aug-Okt",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Plantera ut (växthus)",months:"Maj-Jun",icon:"seedling"},{phase:"Kupa knölar",months:"Jul-Aug",icon:"scissors"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:20,P:10,K:10,label:"Förodling"},{month:"Maj",N:40,P:20,K:15,label:"Utplantering"},{month:"Jun",N:70,P:30,K:25,label:"Tillväxt"},{month:"Jul",N:80,P:45,K:40,label:"Knölbildning"},{month:"Aug",N:50,P:60,K:60,label:"Knölmognad"},{month:"Sep",N:20,P:40,K:50,label:"Skörd"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla med väl brunnen kompost eller stallgödsel. Fänkålen är mer näringskrävande än moroten - hon vill ha det rejält."},{timing:"Tillväxtfas",tip:"Ge flytande näring (brännässelvatten eller alggödsel) varannan vecka. Kväve driver bladtillväxt som ger energi till knölen."},{timing:"Knölbildning",tip:"Skifta till kaliumrik gödsel (vedaska, stenmjöl) som stöttar knölens utveckling. Minska kvävet gradvis."},{timing:"Kupning",tip:"Kupa jord runt knölen och toppdressera med kompost. Kupningen bleker knölen och gör den mildare och vitare."}],companions:{good:[{id:"sallat",name:"Sallat",icon:"vegetable",why:"Sallaten fungerar som levande marktäckare som håller fukten jämn runt fänkålen"},{id:"gurka",name:"Gurka",icon:"vegetable",why:"Trivs i samma varma, fuktiga miljö och stör inte varandra"},{id:"artor",name:"Ärtor",icon:"vegetable",why:"Fixerar kväve i jorden som fänkålen tacksamt tar emot"}],bad:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Fänkål utsöndrar ämnen som hämmar tomatens tillväxt - håll dem isär"},{id:"dill",name:"Dill",icon:"herb",why:"Kan enligt traditionell odlingskunskap påverka varandras smak vid samodling. Håll dem isär för säkerhets skull. Delar dessutom morotsfluga-risk."},{id:"morot",name:"Morot",icon:"morot",why:"Samma familj - lockar morotsflugan och delar sjukdomar"}]},rotation:{avoid:[{id:"morot",name:"Morot",category:"grönsaker"},{id:"palsternacka",name:"Palsternacka",category:"grönsaker"},{id:"dill",name:"Dill",category:"kryddor"},{id:"persilja",name:"Persilja",category:"kryddor"},{name:"Selleri",category:"grönsaker"}],avoidWhy:"Alla flockblommiga delar sjukdomar och skadedjur som morotsflugan. Vänta minst 3-4 år innan du odlar fänkål på samma plats igen.",goodBefore:[{id:"artor",name:"Ärtor",category:"grönsaker"},{id:"bondbona",name:"Bondböna",category:"grönsaker"},{id:"potatis",name:"Potatis",category:"grönsaker"}],goodBeforeWhy:"Baljväxter fixerar kväve som fänkålen älskar. Potatis luckrar jorden fint med sin jordbearbetning.",goodAfter:[{name:"Kål",category:"grönsaker"},{id:"lok",name:"Lök",category:"grönsaker"},{id:"sallat",name:"Sallat",category:"grönsaker"}],goodAfterWhy:"Fänkålens djupa rötter luckrar jorden bra. Kål och lök drar nytta av den fina strukturen och har helt andra skadedjur."},varieties:[{name:"Zefa Fino",zones:[1,2,3,4,5],note:"Pålitlig OP-sort med kompakta knölar. Snabb mognad och bra motståndskraft mot skottbildning. Finns hos Runåbergs."},{name:"Finale",zones:[1,2,3,4],note:"Sen OP-sort som ger stora, tunga knölar. Passar bäst i södra Sverige där säsongen är längre. Finns hos Impecta."},{name:"Romanesco",zones:[1,2,3,4],note:'Italiensk OP-sort med kraftig anissmak. Perfekt för den som vill ha den "riktiga" fänkålssmaken. Internationella fröhus.'},{name:"Perfection",zones:[1,2,3,4,5],note:"Pålitlig OP-sort med jämna, runda knölar. Utvecklad för kallare, nordligare klimat. Finns hos Runåbergs."}],problems:[{name:"Skottbildning (blomning)",symptom:"Plantan skjuter upp en blomstjälk istället för att bilda knöl",fix:"Det viktigaste problemet att förebygga! Orsaker: torka, kyla vid utplantering, för tidigt utsäde, omplanterings-chock. Förodla i stora krukor och störa inte rötterna. Eller direktså. Jämn fukt och värme är nyckeln."},{name:"Bladlöss",symptom:"Kolonier av gröna eller svarta löss på blad och stammar, klibbig honungsdagg",fix:"Spola av med vatten. Locka nyckelpigor och parasitsteklar med blommande växter i närheten. Såpvatten vid kraftig attack."},{name:"Sniglar",symptom:"Oregelbundna hål i blad, slemspår, unga plantor helt avätna",fix:"Snigelstängsel av kopparband runt odlingen. Ölglas. Kontrollera tidiga morgnar och kvällar. Unga plantor är mest utsatta."},{name:"Morotsflugan",symptom:"Rostbruna gångar i roten, vissna blad",fix:"Fiberduk vid sådd/utplantering. Samodla med lök. Undvik att odla nära morot, palsternacka och dill."}],goodToKnow:[{icon:"warning",title:"Skottbildning - fänkålens stora akilleshäl",text:"Fänkålen skjuter i blom vid minsta stress: torka, kyla, vind, rotskada vid omplantning. Förodla i STORA krukor (minst 8 cm) så rötterna inte störs. Eller direktså och gallra. Jämn fukt och värme i 2-3 veckor efter utplantering är helt avgörande.",severity:"warning"},{icon:"warning",title:"Håll isär från dill",text:"Traditionell odlingskunskap säger att fänkål och dill påverkar varandras smak vid samodling. Botaniskt är det osäkert om de verkligen korsar sig (olika släkten), men håll dem isär för säkerhets skull.",severity:"warning"},{icon:"tip",title:"Kupa för fina vita knölar",text:"När knölen börjar svälla, kupa jord runt den som döljer den nedre halvan. Det bleker knölen och ger en mildare, nötaktigare smak. Samma princip som med purjolök.",severity:"tip"},{icon:"tip",title:"Blasten är också ätbar!",text:"Fänkålens fjäderlika blast har en fin, mild anissmak. Klipp och använd som krydda i sallader, soppor och till fisk. Torka blasten som en exklusiv krydda till vintern.",severity:"tip"},{icon:"tip",title:"Rå fänkål - underskattat gott",text:"Hyvla knölen tunt och blanda med citron, olivolja och parmesan. En fräsch sallad som överraskar alla som tror att fänkål bara är lakrits. Smaken är mildare rå än tillagad.",severity:"tip"},{icon:"calendar",title:"Timing är allt",text:"Fänkålen vill ha det varmt och stabilt. Plantera inte ut för tidigt - vänta tills nätterna håller sig över 8-10°C. En kall natt kan vara allt som behövs för att trigga blomning.",severity:"tip"}],sowing:{method:"both",label:"Förodla eller direktså",description:"Fänkålen kan förodlas inomhus eller direktsås. Förodling ger ett försprång, men kräver försiktighet - rötterna ogillar att störas. Direktsådd undviker omplanterings-chocken helt.",steps:["Förodla: Så i stora krukor (minst 8 cm) 4-5 veckor innan utplantering","Förodla: Håll jämn värme (18-22°C) och fukt under groningen","Förodla: Härda av plantorna gradvis under en vecka innan utplantering","Förodla: Plantera ut försiktigt utan att störa rotklumpen - rotskada triggar blomning","Direktså: Så direkt på friland när jorden är minst 12°C","Direktså: Så 2-3 frön per plats med 25-30 cm avstånd","Direktså: Täck med 1-2 cm jord och vattna försiktigt","Gallra till en planta per plats när de har 3-4 riktiga blad"],tips:["Förodla i torvkrukor eller djupa pluggar som planteras ut direkt - undviker rotskada","Direktsådd i juni ger ofta bäst resultat - jorden är varm och dagarna långa","Vänta med utplantering tills nätterna håller sig över 8-10°C","Blötlägg fröna i ljummet vatten 24 timmar innan sådd för snabbare groning"],indoorWeeks:"4-5 veckor"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!0,description:"Knölfänkålen är biologiskt tvåårig men kan tvingas blomma första året genom stress. Under nordiska förhållanden behöver du oftast övervintra en planta för frösättning - eller utnyttja en stressblommande planta.",steps:["Välj den bästa plantan - sen blomning och fin knöl är önskvärda egenskaper","Låt plantan stå kvar och blomma (gulvita flockar)","Vänta tills fröna blir bruna och börjar lossna","Klipp av hela flocken och torka inomhus i en papperspåse","Gnugga loss fröna och rensa bort skräp","Förvara svalt och torrt i märkt påse"],isolation:"Korsar med andra fänkålstyper (kryddfänkål, vild fänkål). Isolera med minst 500 m för sortrent frö. Traditionellt hålls fänkål och dill isär, men botaniskt är det osäkert om de verkligen korsar sig.",storageYears:"2-3 år",tip:"Fänkålsfrö håller bättre än palsternacksfrö men inte lika bra som morotsfrö. Använd helst inom 2 år. Fröna kan förresten användas som krydda - fin anissmak i bröd och matlagning!"},storage:{shelfLife:"1-2 veckor (färsk), längre bearbetad",methods:[{method:"Kylskåp",icon:"snowflake",duration:"1-2 veckor",description:"Bästa sättet för färsk fänkål. Skär bort blasten (spara den som krydda!), linda in knölen i fuktig hushållspapper och lägg i plastpåse. Håller sig krispig i 1-2 veckor.",best:!0},{method:"Frysa (blancherad)",icon:"snowflake",duration:"6-8 månader",description:"Skär knölen i bitar och blanchera 2-3 minuter. Kyl snabbt och frys in. Perfekt för soppor, gratänger och grytor. Texturen blir mjukare men smaken bevaras fint.",best:!1},{method:"Torka (blast som krydda)",icon:"leaf",duration:"12 månader",description:"Blasten torkas och krossas till en aromatisk krydda med anissmak. Fantastisk till fisk, soppor och bröd. Häng blasten i knippen eller torka i ugn på 40°C.",best:!1}],tips:["Skörda hela knölen genom att skära av strax under jordytan","Spara alltid blasten - den är en krydda värd att ta tillvara","Fänkål tappar crunch snabbt efter skörd - ät den så färsk som möjligt","Skär inte knölen förrän du ska använda den - snittytorna oxiderar och blir bruna"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3,unit:"kg"}},Ur=Object.freeze(Object.defineProperty({__proto__:null,fankal:h},Symbol.toStringTag,{value:"Module"})),c={name:"Fikon",icon:"fikon",category:"frukt",family:"Mullbärsväxter",familyLatin:"Moraceae",perennial:!0,lifespan:"50-100+ år",difficulty:"Medel",difficultyWhy:"Fikonet i sig är lättskött och förvånansvärt problemfritt. Utmaningen i Sverige är vinterskyddet - du måste ha en plan för hur din fikona ska klara vintern. Krukodling löser det elegant.",zones:{outdoor:[1],indoor:null,greenhouse:[1,2,3]},days:"Skörd år 2-3",spacing:"2-3 m",spacingNote:"Friland mot sydvägg. I kruka räcker 40-60 cm krukdiameter.",rowSpacing:"3-4 m",depth:"Rotklumpens djup",depthNote:"Plantera inte djupare än rotklumpen. I kruka: dräneringslager av lecakulor i botten.",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Fikon vill ha minst 8 timmars direkt sol - det är ett absolut krav. Halvskugga ger klena frukter och dålig skörd. Sydvägg eller soligt hörn är drömmen."},temperature:{min:-10,max:40,ideal:"20-35°C",detail:"Fikonet är en riktig solvärmare. Det tål kortvarigt ner mot -10°C (sortkänsligt), men rötterna klarar mer. I Sverige hinner vi normalt med en skörd per säsong - och den kräver minst 3 månader med 15°C+."},wind:{level:"Vindkänslig",detail:"Varm, vindskyddad plats - helst mot en sydvägg eller ett plank. Kall vind stressar växten och bromsar tillväxten rejält."}},watering:{need:"Medel-Hög",icon:"water",summary:"Riklig vattning under tillväxt och fruktbildning. Under mognad: minska vattningen - för mycket vatten ger smaklösa, vattniga frukter.",phases:[{phase:"Vår (uppstart)",need:"Medel",tip:"Börja vattna försiktigt när du ställer ut krukan eller ser nya blad. Öka gradvis."},{phase:"Sommar (tillväxt)",need:"Hög",tip:"Vattna rikligt - en krukodlad fikona kan behöva vatten varje dag i värmen. Torkar den ut kraftigt fäller den frukt."},{phase:"Mognad (aug-okt)",need:"Låg",tip:"Minska vattningen nu! Lite stress ger sötare, smakrikare fikon. För mycket vatten ger vattnig smak och risk för röta."},{phase:"Vinter",need:"Minimal",tip:"Under vintervila i kall källare: vattna bara en gång i månaden, eller inte alls om temperaturen är under 5°C."}],mistakes:["Vattnar för lite under sommaren - fikonet fäller frukt i protest","Vattnar för mycket under mognad - ger smaklösa frukter","Glömmer att kontrollera krukodlade fikon under vintervilan - jordklumpen får aldrig torka helt"],tip:"Fikonet talar om när det är törstigt - bladen hänger och ser slappa ut. Men vänta inte tills dess! Regelbunden vattning ger jämnare skörd."},soil:"Fikonet vill ha väldränerad jord - det HATAR stående vatten. En sandig-lerig blandning med lite grus fungerar utmärkt. I kruka: vanlig blomjord med inblandad perlit.",soilTips:["Dränering är A och O - lecakulor i botten av krukan","Blanda in perlit eller grus i planteringsjorden","Fikonet gillar lätt kalkrik jord - strö lite kalk om pH är lågt","I kruka: byt jord vart 3-4 år, eller rotbeskär och sätt tillbaka"],timeline:{1:[{phase:"Utställning",months:"Maj",icon:"seedling"},{phase:"Tillväxt",months:"Maj-juli",icon:"growth"},{phase:"Fruktmognad",months:"Aug-okt",icon:"harvest"},{phase:"Skörd",months:"Sept-okt",icon:"harvest"},{phase:"Intagning",months:"Nov",icon:"snowflake"},{phase:"Vintervila",months:"Nov-april",icon:"snowflake"}],4:[{phase:"Utställning",months:"Juni",icon:"seedling"},{phase:"Tillväxt",months:"Juni-aug",icon:"growth"},{phase:"Fruktmognad",months:"Aug-sept",icon:"harvest"},{phase:"Skörd",months:"Sept",icon:"harvest"},{phase:"Intagning",months:"Okt",icon:"snowflake"},{phase:"Vintervila",months:"Okt-maj",icon:"snowflake"}],6:[{phase:"Utställning",months:"Juni",icon:"seedling"},{phase:"Tillväxt",months:"Juni-aug",icon:"growth"},{phase:"Fruktmognad",months:"Aug-sept",icon:"harvest"},{phase:"Intagning",months:"Sept",icon:"snowflake"},{phase:"Vintervila",months:"Okt-maj",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:1,P:1,K:1},{month:"Maj",N:4,P:3,K:2},{month:"Jun",N:7,P:5,K:3,label:"Full tillväxt"},{month:"Jul",N:6,P:5,K:5},{month:"Aug",N:3,P:3,K:7,label:"Mognad"},{month:"Sep",N:1,P:2,K:5}],nutritionTips:[{timing:"Vår (maj)",tip:"Ge kompost eller balkonggödsel när du ställer ut fikonet. Starta tillväxten rätt."},{timing:"Sommar (juni-juli)",tip:"Gödsla varannan vecka med flytande gödsel. Fikon är inte extremt näringskrävande - övergödsla inte."},{timing:"Slutet av augusti",tip:"SLUTA gödsla. Fikonet ska börja förbereda sig för vintervila. Sen gödsling ger mjuka skott som inte överlever vintern."},{timing:"Vinter",tip:"Ingen gödsling alls under vintervilan. Fikonet vilar."}],companions:{good:[{name:"Lavendel",icon:"herb",why:"Trivs i samma varma, torra miljö. Lockar pollinatörer och avskräcker bladlöss."},{name:"Rosmarin",icon:"herb",why:"Samma krav på sol och dränering. Vackert ihop i en medelhavsinspirerad plantering."},{name:"Ringblomma",icon:"flower",why:"Lockar nyttoinsekter och ger fin kontrast. Trivs i samma soliga läge."}],bad:[{name:"Skuggväxter",icon:"vegetable",why:"Fikonet kräver full sol - plantera inte skuggivande växter intill."}]},rotation:{avoid:[{name:"Fikon"}],avoidWhy:"Fikonet är inte lika känsligt för trötthetssjuka som stenfrukter, men en ny planta trivs bättre i färsk jord.",goodBefore:[{name:"Gröngödsling"}],goodBeforeWhy:"Näringsrik, väldränerad jord ger den bästa starten.",goodAfter:[{name:"Gröngödsling"}],goodAfterWhy:"Bygg upp jordstrukturen med gröngödsling."},varieties:[{name:"Bornholms Diamant",zones:[1,2,3],note:"Den vanligaste sorten i Sverige. Medelstor, gröngul frukt med underbar smak. Partenokarp (sätter frukt utan pollinering). Friland zon 1, växthus/kruka zon 2-3."},{name:"Brown Turkey",zones:[1,2,3],note:"Stor, brunröd frukt. Riklig bärare med mild, söt smak. Något tåligare köldmässigt. Nybörjarvänlig. Friland zon 1, växthus/kruka zon 2-3."},{name:"Hardy Chicago",zones:[1,2,3],note:"Känd för härdighet i USA - stammar tål -12°C, rötter ner till -29°C. Svårare att hitta i Sverige men värd att leta efter. Friland zon 1, växthus/kruka zon 2-3."},{name:"Negronne",zones:[1,2,3],note:"Liten, mörkviolett frukt med intensiv, rik smak. Kompakt träd - perfekt i kruka. Något känsligare för kyla."}],problems:[{name:"Spinnkvalster",symptom:"Bladen gulnar, fina spindelvävsliknande trådar. Värst i torr luft inomhus under vintern.",fix:"Duscha av hela plantan med ljummet vatten. Öka luftfuktigheten. Inspektera NOGA innan du tar in fikonet på hösten."},{name:"Fikonrost",symptom:"Bruna fläckar på bladens undersida. Vanligt vid hög luftfuktighet.",fix:"Plocka bort angripna blad. Se till att kronan har god luftcirkulation. Vattna aldrig på bladen."},{name:"Fruktfall",symptom:"Omogna frukter ramlar av utan uppenbar anledning.",fix:"Oftast stress: torka, temperatursvängningar eller att krukan flyttats. Håll en stabil miljö - fikonet gillar inte förändringar."},{name:"Inga frukter",symptom:"Frodig, fin planta som aldrig sätter frukt.",fix:"Tre vanliga orsaker: för lite sol (kräver 8+ timmar), för stor kruka (rötterna vill vara lite trängda) eller för mycket kväve (ger blad istället för frukt)."}],pollination:{selfFertile:!0,description:"Alla fikonsorter som säljs i Sverige är partenokarpa - de sätter frukt helt utan pollinering. Du behöver varken en andra planta eller insekter. Det är en av fikonets absoluta fördelar som balkong- och trädgårdsväxt.",groups:[{name:"Partenokarpa (alla säljs i Sverige)",varieties:["Bornholms Diamant","Brown Turkey","Hardy Chicago","Negronne"]}],tip:"Smyrnafikon (som kräver pollinering av fikonstekel) kan INTE odlas i Sverige. Alla sorter du hittar i handeln är partenokarpa och klarar sig helt på egen hand."},establishment:{description:"Fikonet är förvånansvärt snabbt att etablera. En köpt planta kan ge frukt redan andra året. Det viktigaste är att hitta rätt plats och ha en vinterskötselsplan.",years:[{year:"År 1",tasks:["Placera i full sol mot sydvägg eller soligt hörn","Vattna regelbundet - inte för mycket, inte för lite","Gödsla varannan vecka maj-augusti","Planera vinterskyddet redan nu - var ska fikonet stå?"]},{year:"År 2",tasks:["Förvänta dig de första frukterna!","Formklipp på våren: ta bort döda grenar och korsande skott","Pincera (knip av toppen på) långa skott för att stimulera förgrening","Ta bort alla frukter som inte hinner mogna på hösten"]},{year:"År 3+",tasks:["Full skörd: 20-60 frukter per säsong (krukodlad)","Rotbeskär vart 3-4 år om krukan inte kan bli större","Fikonet blir alltmer självgående - du känner rytmen nu"]}],protection:["Vinterskydd: frostfri källare, garage eller kallförråd (0-10°C) under vintervilan","Friland zon 1: linda in med jutesäck + 10-20 cm lövmulch runt rotzonen","Acklimera gradvis på våren - ställ inte direkt i full sol","Plocka bort alla omogna frukter på hösten - de hinner inte och stjäl energi"],tip:"Det bästa med fikon i kruka: rötterna vill faktiskt vara lite trängda! Det stimulerar fruktbildning. En 40-60 cm kruka räcker i decennier om du rotbeskär ibland."},ripeningGuide:{description:"Fikon mognar successivt från augusti till oktober i Sverige. Varje frukt mognar individuellt - du plockar inte alla på en gång utan besöker ditt fikonträd regelbundet under hösten.",entries:[{variety:"Bornholms Diamant",from:"aug",to:"okt",type:"Gröngult fikon"},{variety:"Brown Turkey",from:"aug",to:"okt",type:"Brunrött fikon"},{variety:"Hardy Chicago",from:"aug",to:"sep",type:"Mörkt fikon"},{variety:"Negronne",from:"sep",to:"okt",type:"Violett fikon"}],tip:"Ett moget fikon hänger nedåt, är mjukt vid tryck, har skrynklig yta och en liten droppe vid öppningen. Det lossnar nästan av sig självt. Ät det direkt - hemodlade, solmogna fikon är en helt annan dimension än importerade."},goodToKnow:[{icon:"warning",title:"Vinterskydd - den enda riktiga utmaningen",text:"Allt annat med fikon är enkelt. MEN: du måste ha en plan för vintern. Krukodlat fikon ställs in i frostfri, mörk källare (0-10°C) i november. Vänta tills bladen fallit av sig själva innan du tar in. På friland (zon 1): linda in hela busken med jutesäck och mulcha rotzonen rejält.",severity:"warning"},{icon:"tip",title:"Trängda rötter = mer frukt",text:"Fikonet sätter mer frukt när rötterna är begränsade. Välj INTE en för stor kruka! 40-60 cm diameter räcker utmärkt. På friland kan du gräva ner en gammal kruka eller betongring runt rotzonen för att begränsa tillväxten.",severity:"tip"},{icon:"tip",title:"Sticklingar - löjligt enkelt",text:"Fikon är ett av de enklaste fruktträden att föröka med sticklingar. Ta 15-20 cm långa kvistar på våren, stick ner i fuktig jord, och vänta. De rotar sig nästan alltid. Perfekt present till odlarvänner!",severity:"tip"},{icon:"warning",title:"Plocka bort omogna frukter på hösten",text:"De ärtsorstora frukterna som sitter kvar i september-oktober hinner ALDRIG mogna. Ta bort dem - de stjäl energi som fikonet behöver för vintervilan. Nästa års frukter bildas på nya skott.",severity:"warning"}],sowing:{method:"direct",label:"Plantering",description:"Fikon planteras som färdiga plantor. I Sverige är krukodling den normala formen - ställ ut på sommaren och ta in för vintervila.",steps:["Välj en kruka på 40-60 cm med dräneringshål","Lägg ett lager lecakulor i botten (3-5 cm)","Fyll med blomjord blandat med perlit (20%)","Plantera i krukans mitt, inte djupare än rotklumpen","Vattna rikligt efter plantering","Ställ i fullsol mot sydvägg"],tips:["Krukodling är standard i Sverige - det ger dig full kontroll över vinterskyddet","Välj Bornholms Diamant eller Brown Turkey som första sort - säkrast resultat","Frilandsplantering bara i zon 1 (södra Skåne, Gotland, Öland) i extremt skyddat sydläge"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Sticklingar",biennial:!1,description:"Fikon förökas enklast med sticklingar - det är nästan omöjligt att misslyckas. Att odla från frön ger inte samma sort och tar mycket längre tid.",steps:["Ta 15-20 cm långa kvistar i tidig vår (innan bladen slår ut)","Välj blyertstjocka eller kraftigare grenar","Stick ner i fuktig planteringsjord med perlit","Täck med perforerad plastpåse för att hålla fukten","Håll svalt (15-20°C) och skuggigt","Rötter bildas på 3-6 veckor"],isolation:"Sticklingar ger exakta kloner av moderplantan.",storageYears:"Kvistar kan förvaras i fuktig tidning i kylskåp 2-3 månader",tip:"Ta gärna 3-5 sticklingar åt gången - de rotar sig nästan alla. Perfekt present till odlarvänner som drömmer om egna fikon!"},storage:{shelfLife:"1-3 dagar (färska), 6+ månader (torkade)",methods:[{method:"Färska (direkt)",icon:"cellar",duration:"1-3 dagar",description:"Hemodlade fikon ska ätas direkt! Det är hela poängen. De håller sig max 1-2 veckor i kylskåp men tappar smak för varje dag.",best:!0},{method:"Torkning",icon:"sun",duration:"6+ månader",description:"Halvera och torka i ugn vid 50-60°C i 6-8 timmar. Torkade fikon är fantastiskt goda och håller sig länge i lufttät burk.",best:!1},{method:"Frysning",icon:"snowflake",duration:"10-12 månader",description:"Frysa hela eller halverade fikon. Funkar för sylt, smoothies och bakning - men inte för färskätning.",best:!1},{method:"Sylt",icon:"storage",duration:"1+ år",description:"Fikonsylt med vanilj och citron - en klassiker. Fikonen behöver knappt socker, de är naturligt söta.",best:!1}],tips:["Mogna fikon ska ätas samma dag eller dagen efter - de är extremt färskvaror","Butiksfikonens smaklöshet beror på att de skördas omogna för transport - dina egna är en annan dimension","Torkade fikon i lufttät burk på sval plats håller i månader"]},harvestCalc:{minPerSqm:1,maxPerSqm:4,unit:"kg per planta (år 3+)"},pruning:{label:"Beskärning",types:{spring:{name:"Vårbeskärning (formklipp)",when:"Mars-april (innan knoppsprickning)",description:"Fikonet beskärs på våren för att forma kronan och ta bort vinterskadade grenar. Det tål kraftig beskärning väl - var inte rädd!",steps:["Ta bort döda, skadade och korsande grenar","Skär tillbaka till 3-5 starka huvudgrenar","Pincera (knip av toppen på) långa skott för att stimulera förgrening","Ta bort alla rotskott som växer runt basen"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Sticklingar",description:"Det enklaste sättet. Ta 15-20 cm kvistar i tidig vår, stick ner i fuktig jord. Rotar sig på 3-6 veckor. Nästan omöjligt att misslyckas.",icon:"seedling"},{method:"Luftavläggare",description:"Möjligt men onödigt komplicerat när sticklingar fungerar så bra. Används när man vill ha en stor planta snabbt.",icon:"seed"}],tip:"Fikon är löjligt enkelt att föröka. En enda gren kan ge dig 3-5 nya plantor. Börja med sticklingar - du kommer bli förvånad hur bra det går."}},qr=Object.freeze(Object.defineProperty({__proto__:null,fikon:c},Symbol.toStringTag,{value:"Module"})),b={name:"Gräslök",icon:"graslok",category:"kryddor",family:"Lökväxter",familyLatin:"Amaryllidaceae",perennial:!0,lifespan:"10+ år (dela vart tredje år)",difficulty:"Enkel",difficultyWhy:"En av de allra enklaste kryddväxterna att odla. Härdig som en björk, trivs i nästan alla lägen och klarar vintern ända upp i zon 8. Perfekt förstaval för alla som vill börja odla kryddor.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:[1,2,3,4,5,6,7,8],greenhouse:null},days:"60-90",spacing:"15-20 cm",rowSpacing:"25-30 cm",depth:"0.5-1 cm",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Gräslöken trivs bäst i sol men klarar halvskugga galant - hon blir bara lite glesare i skuggan. I söderläge växer hon som tokig, men även norrsidan av huset funkar fint. Få kryddor är lika anpassningsbara."},temperature:{min:-30,max:30,ideal:"15-22°C",detail:"Gräslöken är en riktig nordbo! Klarar köldknäppar ner till -30°C utan att blinka och övervintrar hela vägen upp till zon 8. Hon vaknar tidigt på våren och är en av de första att skjuta upp gröna strån."},wind:{level:"Tålig",detail:"Gräslökens tunna strån böjer sig med vinden utan att brytas. Ingen vindkänsla alls - hon klarar sig var du än sätter henne."}},watering:{need:"Låg-Medel",icon:"water",summary:"Gräslöken är anspråkslös och klarar sig med ganska lite vatten. Hon vill inte stå torr för länge, men är inte lika känslig som basilika. Jämn fukt ger frodigast tillväxt.",phases:[{phase:"Etablering (vår)",need:"Medel",tip:"Håll jämnt fuktigt den första månaden efter plantering eller delning. Rötterna behöver vatten för att hitta ner i jorden ordentligt."},{phase:"Tillväxt (maj-aug)",need:"Låg-Medel",tip:"Vattna 1-2 gånger i veckan vid torrt väder. Gräslöken klarar en del torka men ger mer och mjukare strån med regelbunden vattning."},{phase:"Efter skörd",need:"Medel",tip:"Ge lite extra vatten efter en rejäl nedklippning - det hjälper henne att skjuta nya strån fortare. En klunk vatten och hon är igång igen."}],mistakes:["Övervattnar i kruka - gräslökens rötter ruttnar i stående vatten, dränering är ett måste","Glömmer att vattna vid torka - gräslöken överlever men stråna blir tunna, torra och smaklösa","Vattnar ovanifrån i stående vatten - det kan ge röta vid basen om vattnet inte rinner undan"],tip:"Mulcha runt tuvorna med gräsklipp eller kompost - det håller fukten och matar henne samtidigt. Gräslöken tackar med frodigare tillväxt."},soil:"Gräslöken är inte kräsen med jorden. Hon trivs i det mesta - från lerjord till sandjord. Men allra bäst växer hon i näringsrik, lucker jord med hyfsad fukt. Tänk vanlig trädgårdsjord med lite kompost, så är hon nöjd.",soilTips:["Blanda in kompost vid plantering - gräslöken uppskattar lite extra näring från start","I kruka: vanlig planteringsjord funkar utmärkt, men se till att krukan har dräneringshål","Hon trivs till och med i tung lerjord om du luckrar upp lite med sand eller kompost","Mulcha med gräsklipp på hösten - det skyddar rötterna och ger näring till våren"],timeline:{1:[{phase:"Förodling inomhus",months:"Feb-mars",icon:"indoor"},{phase:"Direktså utomhus",months:"April",icon:"seed"},{phase:"Skörd löpande",months:"April-okt",icon:"harvest"},{phase:"Blomning",months:"Juni-juli",icon:"flower"},{phase:"Dela tuvor",months:"Mars eller sept",icon:"propagation"}],4:[{phase:"Förodling inomhus",months:"Mars",icon:"indoor"},{phase:"Direktså utomhus",months:"Maj",icon:"seed"},{phase:"Skörd löpande",months:"Maj-sept",icon:"harvest"},{phase:"Blomning",months:"Juni-juli",icon:"flower"},{phase:"Dela tuvor",months:"April eller sept",icon:"propagation"}],6:[{phase:"Förodling inomhus",months:"Mars-april",icon:"indoor"},{phase:"Direktså utomhus",months:"Maj-juni",icon:"seed"},{phase:"Skörd löpande",months:"Juni-sept",icon:"harvest"},{phase:"Blomning",months:"Juli",icon:"flower"},{phase:"Dela tuvor",months:"Maj eller aug",icon:"propagation"}]},nutritionData:[{month:"Apr",N:4,P:2,K:2},{month:"Maj",N:6,P:3,K:3},{month:"Jun",N:7,P:3,K:4},{month:"Jul",N:5,P:3,K:4},{month:"Aug",N:4,P:2,K:3},{month:"Sep",N:2,P:1,K:2}],nutritionTips:[{timing:"Tidig vår",tip:"Ge en giva kompost eller brunnen stallgödsel när gräslöken börjar vakna. Det är som frukost efter en lång vintersömn - hon tackar med kraftig tillväxt."},{timing:"Efter varje skörd",tip:"En skvätt nässelvatten efter nedklippning hjälper henne att komma igång med nya strån. Inte nödvändigt, men hon uppskattar det."},{timing:"Obs!",tip:"Övergödsla inte! Gräslöken är anspråkslös och klarar sig med lite. För mycket kväve ger visserligen massor av strån, men smaken blir plattare."}],companions:{good:[{id:"morot",name:"Morot",icon:"vegetable",why:"Det klassiska paret! Gräslökens starka doft förvirrar morotsflugan som navigerar med luktsinnet. Plantera gräslök runt morotslandet - det är ett av de mest beprövade samplanteringstricken."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Gräslökens lökdoft avskräcker bladlöss och kan minska risken för svampsjukdomar på tomatplantor. Dessutom lockar gräslökens blommor pollinatörer."},{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"En klassisk kombo i många trädgårdar! Gräslöken hjälper till att hålla jordgubbsmögel borta med sin lökdoft, och bägge trivs i liknande jordar."}],bad:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Lökväxter och baljväxter anses traditionellt vara dåliga grannar. Gräslök och ärtor trivs bäst var för sig i odlingen."},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Samma princip som med ärtor - lökväxter och baljväxter hålls bäst åtskilda i odlingen."}]},rotation:{avoid:[{id:"lok",name:"Lök"},{id:"purjolok",name:"Purjolök"},{id:"vitlok",name:"Vitlök"}],avoidWhy:"Alla tillhör Amaryllidaceae (Lökväxter) och delar skadegörare som lökfluga och svampsjukdomar. Vänta 3-4 år innan du planterar gräslök där andra lökväxter stått. Men! Gräslök är perenn och bör stå kvar på samma plats i flera år.",goodBefore:[{id:"morot",name:"Morot"},{id:"sallat",name:"Sallat"},{name:"Kål"}],goodBeforeWhy:"Gräslökens rötter luckrar jorden och hennes lökdoft kan ha mild desinficerande effekt. Bra föregångare för de flesta grönsaker utom andra lökväxter.",goodAfter:[{name:"Baljväxter"},{id:"potatis",name:"Potatis"}],goodAfterWhy:"Baljväxter berikar jorden med kväve som gräslöken uppskattar. Potatis lämnar fin, lucker jord efter kupningen."},varieties:[{name:"Staro",zones:[1,2,3,4,5,6,7,8],note:"Den vanligaste sorten i Sverige. Pålitlig, härdig och smakar precis som gräslök ska smaka. Ett säkert val i alla zoner."},{name:"Polyvit F1",zones:[1,2,3,4,5,6,7,8],note:"Snabbväxande F1-hybrid med kraftiga strån. Lite grövre i karaktären men ger riklig skörd. Populär bland odlare som vill ha mycket gräslök. Fröna kan inte sparas sortrena."},{name:"Prager",zones:[1,2,3,4,5,6,7,8],note:"Tidig sort som vaknar tidigt på våren. Kompakt växtsätt och fin mild smak. Passar bra i kruka på balkongen."},{name:"Nelly",zones:[1,2,3,4,5,6,7,8],note:"Finbladig och kompakt sort med elegant växtsätt. Mild smak. Fin som garnering och i sallader."}],problems:[{name:"Lökfluga",symptom:"Strån gulnar och vissnar. Små vita larver syns vid basen om man gräver upp tuvan. Flugan lägger ägg vid jordytan på våren.",fix:"Täck med insektsnät tidigt på våren innan flugan börjar lägga ägg. Gräv upp och förstör angripna tuvor. Samodla med morötter - dofterna förvirrar varandra."},{name:"Rost (Puccinia allii)",symptom:"Orangebruna pustlar på stråna, speciellt under fuktig sommar. Stråna blir fula men plantan överlever.",fix:"Klipp ner angripna strån till markytan - nya friska strån kommer. Se till att tuvorna inte står för tätt, luften behöver cirkulera. Dela tuvorna om de blivit för täta."},{name:"Bladlöss",symptom:"Klibbia strån, små gröna eller svarta löss vid basen. Tillväxten saktar ner.",fix:"Spola av med hård vattenstråle - bladlöss har svårt att hitta tillbaka. Vid kraftig angrepp funkar såpvatten (1 msk flytande tvål per liter). Gräslökens starka doft brukar dock hålla de flesta löss borta."}],goodToKnow:[{icon:"warning",title:"Dela tuvorna vart 3-4 år",text:"Gräslöken växer i tuvor som blir allt tätare med åren. Till slut konkurrerar stråna med varandra och tillväxten avtar. Gräv upp tuvan, dela i 3-4 bitar med en skarp spade och plantera om. Hon tackar med förnyad kraft!",severity:"warning"},{icon:"warning",title:"Kan sprida sig - men lugnt",text:"Gräslök sprider sig via frö och via tuvan som blir större. Låter du henne blomma och sätta frö kan nya plantor dyka upp lite överallt. Vill du undvika det? Klipp bort blommorna innan de sätter frö. Men ärligt - det finns värre problem i en trädgård.",severity:"warning"},{icon:"tip",title:"Blommorna är ätbara - och fantastiska",text:"Gräslökens lila blommor är inte bara vackra - de är fullt ätbara! Plocka isär dem och strö över sallader för mild löksmak och fantastisk färg. Du kan också göra gräslöksblomvinäger som blir vackert rosa.",severity:"tip"},{icon:"tip",title:"Vaknar tidigt på våren",text:"Gräslöken är en av de allra första kryddväxterna att dyka upp på våren. Redan i mars-april skjuter de gröna stråna upp ur jorden. Efter en lång vinter med fryst kryddskåp - vilken lyx att klippa färsk gräslök!",severity:"tip"},{icon:"tip",title:"Perfekt kantväxt",text:"Gräslökens kompakta tuvor och lila sommarblommor gör henne perfekt som kantväxt runt grönsakslandet. Snygg, nyttig OCH avskräcker skadedjur. Trippelvinst!",severity:"tip"}],sowing:{method:"both",label:"Direktsådd eller förodling",description:"Gräslök kan både sås direkt utomhus och förodlas inomhus. Direktsådd är enklast men tar lite längre tid att etablera. Det allra lättaste sättet att starta? Köp en liten tuva eller be en granne om en delning - gräslöksodlare delar gärna med sig!",steps:["Så fröna 0.5-1 cm djupt i fuktig jord, gärna i rader","Håll jorden jämnt fuktig under groningsperioden (10-14 dagar)","Gallra till 15-20 cm avstånd mellan tuvorna","Vid förodling: så inomhus 6-8 veckor före utplantering","Härda av förodlade plantor en vecka innan de sätts ut","Första året: låt tuvorna etablera sig och skörda försiktigt","Alternativ: dela en befintlig tuva och plantera bitarna direkt - snabbaste vägen till skörd!"],tips:["Så gärna 5-6 frön i klump - gräslök trivs i tuvor från start","Fröna gror bäst i 15-20°C. Kalljord ger långsam eller ingen groning","År ett kan du börja klippa försiktigt när stråna är 15+ cm. År två drar det igång på allvar"],indoorWeeks:"6-8 veckor före utplantering"},seedSaving:{difficulty:"Enkel",type:"Korspollinerare",biennial:!1,description:"Gräslöken blommar rikligt på sommaren och sätter massor av frö. Låt några blomhuvuden stå kvar och torka på plantan - sen är det bara att skaka ut fröna. Enklare blir det inte!",steps:["Låt 3-4 blomhuvuden sitta kvar och mogna (klipp inte av dem som vanligt)","Vänta tills blommorna torkat och frökapslarna blivit bruna (aug-sept)","Klipp av blomstjälkarna och lägg i en papperspåse","Skaka påsen - fröna faller ut ur kapslarna","Rensa bort blomrester och låt fröna eftertorka några dagar","Förvara svalt och torrt i märkt kuvert"],isolation:"Gräslök korspolleras av insekter. Håll 100+ meters avstånd mellan sorter om du vill ha sortrena frön. I praktiken spelar det sällan roll - gräslök är gräslök.",storageYears:"2-3 år",tip:"Delning av tuvor ger identiska plantor och är enklare än frösådd. Men fröna ger dig hundratals nya plantor - perfekt för att anlägga en kant av gräslök runt hela grönsakslandet!"},storage:{shelfLife:"5-7 dagar (färsk)",methods:[{method:"Frysning (bäst!)",icon:"snowflake",duration:"6+ månader",description:"Klipp gräslöken i små ringar, fördela i isbitsfack eller frys löst på bakplåt och häll sedan i påse. Behåller smak och färg alldeles utmärkt. Ska du bara ha en metod - välj denna.",best:!0},{method:"Färsk i glas",icon:"water",duration:"5-7 dagar",description:"Ställ stråna i ett glas med lite vatten i kylen. Täck löst med plastpåse. Byt vatten varannan dag. Håller sig fräsch betydligt längre än liggande i kylen.",best:!1},{method:"Torkning",icon:"storage",duration:"12+ månader",description:"Klipp i ringar och torka i ugn (50°C, 2-3 timmar) eller i matavfuktare. Torkad gräslök tappar en del smak men funkar som bakgrundskrydda i grytor och soppor.",best:!1}],tips:["Frys i isbitsfack med lite olivolja - perfekta smakbitar att slänga i stekpannan","Torkad gräslök tappar mycket av den fina smaken - frys hellre om du kan","Klipp alltid med vass sax eller kniv - trubbiga verktyg krossar stråna och smaken läcker ut","Skörda på morgonen för starkast smak - eteriska oljorna är som mest koncentrerade då"]},harvestCalc:{minPerSqm:.3,maxPerSqm:.8,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp stråna 3-5 cm ovanför marken",description:"Klipp stråna med en vass sax 3-5 cm ovanför marken - lämna alltid en stubbe så plantan kan växa tillbaka. Du kan skörda 3-4 gånger per säsong. Klipp helst de yttre, äldre stråna först och låt de unga innersta växa vidare.",uses:[{use:"Färsk",tip:"DET bästa sättet! Klipp i fina ringar och strö över potatis, sallad, soppa, ägg - allt blir godare. Tillsätt sist, värme tar bort smaken."},{use:"Gräslökssmör",tip:"Blanda finriven gräslök med rumstempererat smör och en gnutta salt. Rulla i plastfolie till en korv och frys. Skär skivor till grillat kött eller nybakat bröd."},{use:"Blomvinäger",tip:"Stoppa gräslöksblommor i en flaska med vit vinäger. Vänta 2 veckor. Vinägern blir vackert rosa och smakar underbart i dressing. Imponerar på middagsgäster."},{use:"Torkad",tip:"Funkar som bakgrundskrydda men tappar mycket smak. Bäst i grytor och bröddegar där den får tid att mjukna."}]}},Yr=Object.freeze(Object.defineProperty({__proto__:null,graslok:b},Symbol.toStringTag,{value:"Module"})),f={name:"Grönkål",icon:"gronkal",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Enkel",difficultyWhy:"Extremt härdig, tål frost ner till -15°C, kräver minimalt med skötsel och trivs i hela Sverige. Odlingens tuffing.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:null},days:"60-80",spacing:"40-50 cm",rowSpacing:"50-60 cm",depth:"1-2 cm",ph:{min:6,max:7.5,ideal:7},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Minst 4 timmar sol per dag. Klarar halvskugga bättre än de flesta kålväxter - bladen blir mörkare och mörare i halvskugga."},temperature:{min:-15,max:25,ideal:"10-20°C",detail:"Grönkål är odlingens tuffing - hon står kvar när allt annat gett upp. Tål frost ner till -15°C och blir faktiskt BÄTTRE av kyla. Stärkelse omvandlas till socker efter frost!"},wind:{level:"Tålig",detail:"Kraftig stjälk som tål det mesta. I mycket utsatta lägen kan stöd behövas för höga sorter, men generellt inga problem."}},watering:{need:"Medel",icon:"water",summary:"Grönkål är inte krävande men vill ha jämn fukt. Torka ger sega, bittra blad. Övervattning är sällan ett problem - hon dricker gärna.",phases:[{phase:"Groning (0-2 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig tills plantorna kommit upp. Kålfrön gror snabbt (5-7 dagar) om de får fukt."},{phase:"Etablering (2-6 veckor)",need:"Medel",tip:"Vattna regelbundet, speciellt om du planterat ut förodlade plantor. Rötterna behöver tid att etablera sig."},{phase:"Tillväxt (6-12 veckor)",need:"Medel",tip:"Djupvattna 1-2 gånger i veckan om det inte regnar. Grönkål med tillräckligt vatten får mjuka, saftiga blad."},{phase:"Höst/vinter",need:"Låg",tip:"Naturen sköter vattningen nu. Grönkålen klarar sig på regn och snö. Sluta vattna - hon behöver gå in i viloläge."}],mistakes:["Torka under tillväxt ger sega, bittra blad som ingen vill äta","Vattna ovanifrån på kvällen - fuktiga blad över natten lockar svampsjukdomar","Glömma att vattna nyutplanterade plantor i sommarvärme"],tip:"Mulcha med gräsklipp eller halm runt plantorna. Det håller fukten och minskar ogräs - grönkål med mulch klarar sig nästan utan extra vattning."},soil:"Näringsrik, kalkrik jord med bra dränering. Grönkål är en storätare som vill ha ordentlig näring.",soilTips:["Blanda in rikligt med brunnen kompost före plantering","Kalka gärna på hösten om du har sur jord - grönkål gillar pH över 6.5","Undvik packad lerjord - luckra ordentligt så rötterna kan sprida sig"],timeline:{1:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj",icon:"leaf"},{phase:"Gödsla",months:"Jun",icon:"water"},{phase:"Tidig skörd (blad)",months:"Jul-Aug",icon:"harvest"},{phase:"Huvudskörd (efter frost)",months:"Okt-Dec",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Direktså/plantera ut",months:"Maj-Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Tidig skörd",months:"Aug",icon:"harvest"},{phase:"Huvudskörd (efter frost)",months:"Okt-Jan",icon:"harvest"}],6:[{phase:"Direktså/plantera ut",months:"Jun",icon:"leaf"},{phase:"Gödsla",months:"Jul",icon:"water"},{phase:"Tidig skörd",months:"Sep",icon:"harvest"},{phase:"Huvudskörd (efter frost)",months:"Nov-Feb",icon:"harvest"}]},nutritionData:[{month:"Maj",N:30,P:15,K:10,label:"Plantering"},{month:"Jun",N:70,P:25,K:20,label:"Bladtillväxt"},{month:"Jul",N:90,P:35,K:30,label:"Kraftig tillväxt"},{month:"Aug",N:80,P:40,K:35,label:"Fortsatt tillväxt"},{month:"Sep",N:50,P:30,K:40,label:"Mognad"},{month:"Okt",N:20,P:15,K:50,label:"Härdig/skörd"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla med brunnen kompost och lite hornmjöl. Grönkål vill ha kväverik start."},{timing:"Tidig tillväxt",tip:"Ge flytande nässelvatten eller alggödsel varannan vecka. Grönkål är en hungrig dam."},{timing:"Midsommar",tip:"Extra kvävegiva (t.ex. hönsgödsel utspädd) ger frodigare blad. Men övergödsla inte - det lockar bladlöss."},{timing:"Höst",tip:"Sluta gödsla. Grönkålen ska hårda av inför vintern, inte producera nytt bladverk."}],companions:{good:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Fixar kväve i jorden - gratis gödsel för den hungriga grönkålen"},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Samma fördel som ärtor - kvävefixerare som grönkål älskar att växa bredvid"},{id:"potatis",name:"Potatis",icon:"vegetable",why:"Bra granne som inte konkurrerar - de tar näring från olika djup"},{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft avskräcker kålfjärilen - en av grönkålens värsta fiender"}],bad:[{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Jordgubbar hämmas av kålväxter - dålig kombination"},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Tomat och kål konkurrerar hårt om näring och utrymme"}]},rotation:{avoid:[{id:"radisa",name:"Rädisa"},{id:"broccoli",name:"Broccoli"},{id:"blomkal",name:"Blomkål"},{id:"vitkal",name:"Vitkål"},{id:"rodkal",name:"Rödkål"},{id:"brysselkal",name:"Brysselkål"},{id:"kalrabbi",name:"Kålrabbi"},{id:"pak-choi",name:"Pak choi"}],avoidWhy:"Alla tillhör korsblommiga och delar sjukdomar som klumprotsjuka. Vänta minst 4 år innan kål odlas på samma plats!",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"potatis",name:"Potatis"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter fixerar kväve som grönkålen behöver. Potatis och lök lämnar en ren, bearbetad jord.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"sallat",name:"Sallat"}],goodAfterWhy:"Rotgrönsaker trivs i den djupt bearbetade jorden. Sallat gillar den kväverika restjorden."},varieties:[{name:"Westlandse Winter",zones:[1,2,3,4,5,6,7,8],note:"Klassikern. Extremt härdig, perfekt för svenska vintrar."},{name:"Halvhög Krusig",zones:[1,2,3,4,5,6,7,8],note:'Krullig och kompakt. Traditionell svensk sort, även känd som "Half Tall". Fin i trädgården och på tallriken.'},{name:"Red Russian",zones:[1,2,3,4,5,6,7,8],note:"Vackert lilaröda stjälkar och grågröna blad. Mildare smak."},{name:"Nero di Toscana",zones:[1,2,3,4,5,6],note:"Svartkål (cavolo nero). Smala, mörkgröna blad. Italiensk favorit som fungerar fint i Sverige."}],problems:[{name:"Kålfjäril",symptom:"Gröna larver som äter stora hål i bladen, grönaktiga spillningshögar",fix:"Fiberduk från maj. Handplocka larver. Spruta med Bacillus thuringiensis (Bt). Samodla med lök och dill."},{name:"Kålmal",symptom:"Små gröna larver som gör gropar i bladen, fönsterliknande skador",fix:"Fiberduk tidigt. Nyttoinsekter (parasitsteklar) hjälper. Spruta Bt vid angrepp."},{name:"Bladlöss",symptom:"Gråvita löss i kluster på bladens undersida, bladen krullar sig",fix:"Spruta av med stark vattenstråle. Locka nyttoinsekter med blommor intill. Nässelvatten som bladspray."},{name:"Klumprotsjuka",symptom:"Plantan vissnar trots vattning, rötterna har klumpiga utväxter",fix:"Ingen bot - dra upp och bränn. Kalka jorden. Odla inte kål på samma plats på 7 år. Allvarlig sjukdom!"}],goodToKnow:[{icon:"snowflake",title:"Bättre efter frost!",text:"Grönkålens bäst bevarade hemlighet: stärkelsen i bladen omvandlas till socker när temperaturen sjunker under noll. Skörda EFTER första frosten för bäst smak. Det är som magi!",severity:"tip"},{icon:"leaf",title:"En av de sista du skördar",text:"När resten av trädgården gett upp för vintern står grönkålen kvar som en grön fyr. Du kan skörda blad ända in i januari i sydligare zoner. I norr överlever hon under snön.",severity:"tip"},{icon:"warning",title:"Klumprotsjuka - kålens mardröm",text:"Odla aldrig kålväxter på samma plats oftare än var 4:e år. Klumprotsjuka lever i jorden i 7+ år och det finns inget botemedel. Kalka gärna - svampen trivs i sur jord.",severity:"warning"},{icon:"harvest",title:"Skörda underifrån",text:"Plocka alltid de nedersta, äldsta bladen först. Låt de innersta bladen sitta kvar och växa vidare. En grönkålsplanta kan ge skörd i månader på det sättet.",severity:"tip"},{icon:"seedling",title:"Supernyttig vintergröna",text:"Grönkål är en av de mest näringsrika grönsakerna som finns. Fullproppad med C-vitamin, järn, kalcium och antioxidanter. Och du kan odla den på vintern när inget annat växer!",severity:"tip"}],sowing:{method:"both",label:"Direktsådd eller förodling",description:"Grönkål kan antingen förodlas inomhus för tidigt försprång eller direktsås utomhus. Förodling rekommenderas i norrland för att hinna med en lång säsong.",steps:["Förodling: Så i krukor inomhus 4-6 veckor före utplantering (mars-april)","Direktsådd: Så på friland när jorden är minst 8°C (maj-juni beroende på zon)","Så 1-2 cm djupt, 2-3 frön per plats","Gallra till en planta per plats när de har 3-4 riktiga blad","Plantera ut förodlade plantor med 40-50 cm avstånd","Tryck till jorden ordentligt runt plantorna - kål vill sitta stadigt"],tips:["Förodla i celler för att störa rötterna minimalt vid utplantering","Härda av förodlade plantor en vecka före utplantering - ställ ut dem dagtid","Grönkål kan direktsås ända till midsommar och ändå hinna ge bra skörd"],indoorWeeks:"4-6 veckor"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!0,description:"Grönkål är tvåårig - hon blommar och sätter frö först andra året. Och hon korsar sig med ALL kål: broccoli, blomkål, vitkål, brysselkål - allt! Så isolering är viktigt.",steps:["Välj de starkaste, friskaste plantorna att spara till frö","Låt plantorna stå kvar över vintern (täck med halm/löv i kallare zoner)","Våren efter skjuter hon blomstjälk med gula blommor","Insekter pollinerar - se till att bara EN kålsort blommar","Låt fröskidorna torka på plantan tills de är bruna och spröda","Klipp av hela blomstjälken och torka inomhus","Krossa skidorna försiktigt och rensa bort skräp"],isolation:"Korsar med ALLA andra Brassica oleracea (vitkål, broccoli, blomkål, brysselkål, kålrabbi). Odla bara en sort av kål för frö, eller isolera med minst 500 m (helst 800 m+).",storageYears:"4 år",tip:"Kålfrö håller sig bra i flera år om du förvarar svalt och torrt. Märk sort och år!"},storage:{shelfLife:"Hela vintern (i landet)",methods:[{method:"I landet (levande)",icon:"leaf",duration:"November till mars",description:"Det bästa sättet! Grönkål överlever vintern utomhus i de flesta zoner. Plocka blad efter behov - fräschare än så kan det inte bli. Täck med fiberduk i de kallaste zonerna.",best:!0},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Tvätta, ta bort tjocka stjälkar, blanchera 2-3 minuter, kyl i isvatten. Torka av och frys in i portionspåsar. Perfekt för smoothies och grytor.",best:!1},{method:"Torka",icon:"storage",duration:"6-12 månader",description:"Tvätta, ta bort stjälkar, torka i ugn på 50°C eller i torkmaskin. Gör fantastiska grönkålschips! Förvara i lufttäta burkar.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"1-2 veckor",description:"Tvätta inte förrän du ska använda. Lägg i plastpåse med några hål. Grönkål håller sig bättre än de flesta bladgrönsaker i kylskåp.",best:!1}],tips:["Grönkål som stått ute i frost behöver inte blancheras lika länge - kylan har redan gjort jobbet","Frysta grönkålsblad är perfekta att krossa rakt ner i smoothien","Grönkålschips: riva bladen i bitar, ringla olivolja, salta, ugn 150°C i 10-15 min","Skörda aldrig alla blad från en planta - lämna minst 5-6 blad så hon överlever vintern"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:2.5,unit:"kg"}},Zr=Object.freeze(Object.defineProperty({__proto__:null,gronkal:f},Symbol.toStringTag,{value:"Module"})),j={name:"Guldvinbär",icon:"guldvinbar",category:"bär",family:"Ripsväxter",familyLatin:"Grossulariaceae",perennial:!0,lifespan:"15-25 år",difficulty:"Enkel",difficultyWhy:"Guldvinbär är en av de mest anspråkslösa bärbuskarna du kan plantera. Torktålig, härdig, sjukdomsresistent och vacker. Hon ger dig doftande blommor på våren, goda bär på sommaren och fantastisk höstfärg. Enda nackdelen? Bären mognar ojämnt.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:null},days:"Skörd år 2-3",spacing:"150-200 cm",rowSpacing:"250-300 cm",depth:"Något djupare än i krukan",ph:{min:5.5,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Guldvinbär är flexibel - full sol ger mest bär och sötast smak, men hon klarar halvskugga utan problem. I skuggiga lägen blir blommorna lika vackra men bären färre. Minst 4 timmar direkt sol per dag."},temperature:{min:-35,max:35,ideal:"15-25°C",detail:"Extremt härdig! Ursprungligen från Nordamerikas prärier och anpassad till både bitande kyla och stekande hetta. Tål ner till -35°C och klarar alla svenska odlingszoner. Torktålig som få bärväxter."},wind:{level:"Tålig",detail:"Upprätt, kraftig buske som klarar vind bra. Från prärieregioner med ständig vind - hon bryr sig inte. Fungerar fint som vindskyddshäck."}},watering:{need:"Låg",icon:"water",summary:"Guldvinbär är remarkabelt torktålig - en av de mest anspråkslösa bärbuskarna när det gäller vatten. Etablerade buskar klarar sig med naturlig nederbörd de flesta somrar. Bara nyplanterade buskar behöver extra uppmärksamhet.",phases:[{phase:"Etablering (år 1-2)",need:"Medel",tip:"Vattna regelbundet första och andra sommaren. Etablerade buskar klarar sig sedan nästan själva."},{phase:"Blomning (april-maj)",need:"Låg-Medel",tip:"Jämn fukt under blomningen ger bättre bärsättning, men guldvinbär klarar en del torka utan problem."},{phase:"Bärmognad (juni-aug)",need:"Låg",tip:"Etablerade buskar behöver sällan extra vatten. Vid extrem torka (3+ veckor) ger en djup vattning saftigare bär."},{phase:"Höst/vinter",need:"Ingen",tip:"Lämna henne i fred. Hon sköter sig själv."}],mistakes:["Vattnar för mycket - guldvinbär avskyr vattensjuk jord","Glömmer nyplanterade buskar det första året"],tip:"Guldvinbär är ett av de bästa valen för den som inte vill tänka på vattning. En mulchad buske i lagom sol klarar sig praktiskt taget utan extra vatten efter etablering."},soil:"Guldvinbär är anmärkningsvärt anspråkslös och trivs i de flesta jordtyper. Hon tolererar allt från sandjord till lerjord, och klarar ett brett pH-spann. Det enda hon verkligen ogillar är stående vatten.",soilTips:["Trivs i allt från sand till lera - remarkabelt flexibel","Tolererar alkalisk jord (upp till pH 7.5) - ovanligt bland bärväxter","Blanda in lite kompost vid plantering men överdriv inte - hon gillar mager jord","God dränering är det enda verkliga kravet","Torr, mager mark? Inget problem - guldvinbär kommer från prärieregioner"],timeline:{1:[{phase:"Plantering",months:"Okt-nov eller april-maj",icon:"seedling"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Skörd",months:"Juli-aug",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (mars)",icon:"scissors"},{phase:"Höstfärg",months:"Sept-okt",icon:"bloom"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],4:[{phase:"Plantering",months:"Okt eller april-maj",icon:"seedling"},{phase:"Blomning",months:"April-maj",icon:"bloom"},{phase:"Skörd",months:"Juli",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (feb-mars)",icon:"scissors"},{phase:"Höstfärg",months:"Sept-okt",icon:"bloom"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}],6:[{phase:"Plantering",months:"Okt-nov eller mars-april",icon:"seedling"},{phase:"Blomning",months:"April-maj",icon:"bloom"},{phase:"Skörd",months:"Juni-juli",icon:"harvest"},{phase:"Beskärning",months:"Sen vinter (feb-mars)",icon:"scissors"},{phase:"Höstfärg",months:"Okt",icon:"bloom"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:2,P:2,K:2},{month:"Maj",N:3,P:3,K:3},{month:"Jun",N:2,P:3,K:4},{month:"Jul",N:2,P:2,K:4},{month:"Aug",N:1,P:2,K:3},{month:"Sep",N:1,P:1,K:2}],nutritionTips:[{timing:"Tidig vår",tip:"En lätt giva kompost eller allroundgödsel räcker gott. Guldvinbär är blygsam ätare och övergödsling ger bara onödiga blad på bekostnad av bär."},{timing:"Blomning",tip:"Lite vedaska runt basen ger extra kalium som stärker blomning och bärsättning."},{timing:"Höst",tip:"Mulcha med löv eller kompost. Det räcker som näring för denna anspråkslösa buske."}],companions:{good:[{id:"ringblomma",name:"Ringblomma",icon:"flower",why:"Lockar pollinatörer. Guldvinbär behöver korspollinering för bäst skörd - humlor och bin behövs!"},{name:"Andra guldvinbärsplantor",icon:"berry",why:"Korspollinering är viktigt! Plantera minst 2 buskar - gärna olika sorter - för ordentlig bärsättning."},{name:"Vildblommor",icon:"flower",why:"Ängsblommor lockar pollinatörer och guldvinbärets doftande blommor lockar ännu fler. Alla vinner på det."}],bad:[{name:"Tallbecksväxt (Ribes)-värdar för tallbarrsrost",icon:"vegetable",why:"Ribes-arter kan vara mellanvärdar för tallbarrsrost (Cronartium ribicola). Undvik att plantera nära fembarriga tallar."}]},rotation:{avoid:[{name:"Guldvinbär"},{id:"svarta-vinbar",name:"Svarta vinbär"},{id:"krusbar",name:"Krusbär"}],avoidWhy:"Ribes-arter delar sjukdomar. Vänta minst 5 år innan du planterar nya vinbär eller krusbär på samma plats.",goodBefore:[{name:"Solig, öppen plats"},{name:"Gräsmatta"}],goodBeforeWhy:"Frisk mark utan tidigare Ribes-växter.",goodAfter:[{name:"Gröngödsling"},{name:"Baljväxter"}],goodAfterWhy:"Jorden behöver återhämta sig efter 15+ år med samma buske."},varieties:[{name:"Gullrips (standard)",zones:[1,2,3,4,5,6],note:"Originalarten (Ribes aureum), säljs även som doftrips. Gula-orangea bär, doftande blommor. Härdig och anspråkslös. Ofta såld utan sortnamn hos plantskolor som prydnadsbuske - men bären är fullt ätbara!"},{name:"Crandall",zones:[1,2,3,4,5,6],note:"Amerikansk sort från 1888 med stora, svarta bär och söt smak utan strävhet. Säljs som doftrips Crandall hos svenska plantskolor. Fin höstfärg. En av de bästa sorterna för ätning färska."}],problems:[{name:"Bladlöss",symptom:"Krusiga blad och klibbig honungsdagg. Guldvinbär drabbas mildare än andra vinbär.",fix:"Spola av med vatten. Locka nyckelpigor och blomflugor. Sällan ett allvarligt problem."},{name:"Tallbarrsrost",symptom:"Orange prickar på bladens undersida. Del av svampens livscykel som alternerar mellan tallar och Ribes.",fix:"Sällan allvarligt för busken. Undvik plantering nära fembarriga tallar (Pinus cembra, P. strobus). Plocka bort angripna blad."},{name:"Fåglar",symptom:"Bären försvinner. Trastar och starar gillar guldvinbär.",fix:"Nät om du vill vara säker. Guldvinbär ger ofta så rikligt att det räcker till dig och fåglarna."}],goodToKnow:[{icon:"tip",title:"Doftande blommor!",text:"Guldvinbärets gula blommor doftar underbart av kryddnejlika (vanilj/klöver). Blomningen i april-maj är en av trädgårdens höjdpunkter. Lockar massor av humlor och bin - en riktigt pollinerarvänlig buske.",severity:"tip"},{icon:"warning",title:"Behöver korspollinering",text:"Guldvinbär sätter betydligt fler bär med korspollinering. Plantera ALLTID minst 2 buskar, helst av olika sorter. Med bara en buske får du vackra blommor men glesa bärklaser.",severity:"warning"},{icon:"tip",title:"Trippelnytta: blommor, bär och höstfärg",text:"Guldvinbär ger dig tre säsonger av njutning: doftande gula blommor på våren, söta bär på sommaren och spektakulär röd-orange höstfärg. Få bärväxter ger så mycket skönhet per kvadratmeter.",severity:"tip"},{icon:"tip",title:"Inte som vanliga vinbär",text:"Guldvinbär (Ribes aureum) är en helt annan art än röda/svarta vinbär (Ribes rubrum/nigrum). Bären sitter inte i klasar utan enskilt eller i korta klasar. Smaken är mildare, sötare och utan den typiska vinbärsstyrkan.",severity:"tip"},{icon:"tip",title:"Perfekt häckväxt",text:"Guldvinbär fungerar utmärkt som friväxande häck. Upprätt, tät buske (150-200 cm) som tål beskärning och vind. Doftande blomning, bär och höstfärg gör den till en av de mest mångsidiga häckväxterna.",severity:"tip"},{icon:"warning",title:"Bären mognar ojämnt",text:"Bären mognar inte samtidigt - du behöver plocka i omgångar under 2-3 veckor. Mogna bär är mjuka och lossnar lätt. Fullmogna bär kan variera i färg från gult till orange till nästan svart beroende på sort.",severity:"warning"}],sowing:{method:"direct",label:"Plantering",description:"Guldvinbär planteras som krukodlade plantor eller barrotade buskar. Höstplantering fungerar bäst. Anspråkslös - hon ställer inga konstiga krav.",steps:["Gräv en grop dubbelt så bred som rotklumpen","Blanda in lite kompost - men överdriv inte, hon gillar mager jord","Plantera något djupare än i krukan","Vattna rikligt vid plantering","Mulcha med bark eller gräsklipp"],tips:["Plantera ALLTID minst 2 buskar för korspollinering - annars får du knappt med bär","Höstplantering (okt-nov) ger bäst resultat","Perfekt val för torra, magra platser där annat inte trivs","Fungerar bra som häck med 100-120 cm avstånd"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Guldvinbär förökas enkelt med vedartade sticklingar, rotskott eller frö. Sticklingar på hösten är standardmetoden och ger identiska kopior av moderplantan.",steps:["Vedartade sticklingar: klipp 20-25 cm av årets mogna skott i november","Ta bort nedre knoppar, behåll 3-4 i toppen","Sätt i fuktig jord utomhus","Rotskott: gräv upp naturliga rotskott med rötter på hösten","Frösådd: möjlig men ger variation. Bären kan mosas och fröna torkas."],isolation:"Vegetativ förökning ger kloner. Frösådd ger variation.",storageYears:"Ej tillämpligt (vegetativ) / 2-3 år (frö)",tip:"Sticklingar på hösten är enklast och pålitligast. Guldvinbär rotar sig bra - räkna med 8 av 10 sticklingar som lyckas."},storage:{shelfLife:"3-5 dagar (färska)",methods:[{method:"Frysning",icon:"snowflake",duration:"12+ månader",description:"Bästa sättet att bevara. Frys direkt i påsar. Frysta guldvinbär fungerar utmärkt i smoothies, bakning och sylt.",best:!0},{method:"Sylt och mos",icon:"storage",duration:"1+ år",description:"Guldvinbärssylt har en mild, unik smak - inte lika skarp som svarta vinbärssylt. Koka med socker och citronjuice. God till ost.",best:!1},{method:"Saft",icon:"storage",duration:"1+ år",description:"Mild, sötfruktig saft. Blanda gärna med äpple eller andra bär för mer karaktär.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"3-5 dagar",description:"Hyfsat hållbara färska. Förvara torrt och svalt.",best:!1}],tips:["Skörda när bären är mjuka och lossnar lätt - de mognar ojämnt så plocka i omgångar","Sorten avgör bärfärgen vid mognad: gula, orange eller nästan svarta","Blanda gärna med andra bär i sylt och saft för mer karaktär"]},harvestCalc:{minPerSqm:.8,maxPerSqm:2.5,unit:"kg"},pruning:{label:"Beskärning",types:{maintenance:{name:"Underhållsbeskärning",when:"Tidig vår (feb-mars)",description:"Guldvinbär kräver minimal beskärning. Ta bort döda och gamla grenar, gallra om det blivit för tätt. Busken bär på 2-5 år gammal ved.",steps:["Ta bort döda, skadade grenar","Ta bort grenar äldre än 5-6 år vid basen","Gallra korsande och svaga skott","Spara 8-12 starka grenar i blandade åldrar","Klipp bort oönskade rotskott"]},rejuvenation:{name:"Föryngringsbeskärning",when:"Tidig vår",description:"Gammal buske? Klipp ner till 20-30 cm. Guldvinbär skjuter kraftigt från basen och är tillbaka inom 2-3 år.",steps:["Klipp ner hela busken till 20-30 cm","Välj ut 8-10 starka nya skott","Gödsla med kompost","Skörd igen från år 2-3"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Vedartade sticklingar",description:"Klipp 20-25 cm av årets mogna skott i november. Sätt i fuktig jord utomhus. Hög lyckandefrekvens (8/10). Standardmetoden.",icon:"scissors"},{method:"Rotskott",description:"Guldvinbär bildar naturligt rotskott. Gräv upp med rötter och plantera om direkt. Enklast!",icon:"seedling"},{method:"Nedböjning",description:"Böj ner en gren och fäst mot marken. Täck med jord. Klipp loss den nya plantan nästa år.",icon:"seedling"}],tip:"Sticklingar på hösten rotar sig utmärkt. Guldvinbär är bland de enklaste Ribes-arterna att föröka."}},Xr=Object.freeze(Object.defineProperty({__proto__:null,guldvinbar:j},Symbol.toStringTag,{value:"Module"})),y={name:"Gurka",icon:"gurka",family:"Gurkväxter",familyLatin:"Cucurbitaceae",difficulty:"Medel",difficultyWhy:"Gurkan är en liten diva som vill ha det varmt, fuktigt och vindstilla. I kallväxthus är hon ganska snäll, men utomhus i Sverige är det en utmaning - framför allt norr om zon 3.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:[1,2,3,4,5,6]},days:"55-75",spacing:"40-60 cm",rowSpacing:"100-120 cm",depth:"1-2 cm",ph:{min:5.8,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6-8 timmar direkt sol per dag. Gurkan vill ha ljus och värme - i skugga blir hon lång och ranglig med klena frukter. I växthus är ljuset sällan ett problem."},temperature:{min:12,max:35,ideal:"22-28°C",detail:"Gurkan är en riktig värmeälskare. Under 12°C slutar hon växa helt och under 5°C kan hon dö. Jordtemperaturen bör vara minst 15°C vid plantering. I växthus trivs hon allra bäst."},wind:{level:"Skyddat",detail:"Rankorna och de stora bladen är ömtåliga. Placera henne i lä, gärna intill en vägg eller häck. I växthus slipper hon vindproblemet helt."}},watering:{need:"Hög",icon:"water",summary:"Gurkan är en av de törstigaste grödorna du kan odla. Hon består till 96% av vatten och varje frukt kräver enorma mängder. Ojämn vattning ger bittra, missformade gurkor.",phases:[{phase:"Grodd och etablering (0-3 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig utan att den blir dränkt. Små plantor har ytliga rötter och torkar fort, men ruttnar lika snabbt om de står blöta."},{phase:"Tillväxt och rankning (3-6 veckor)",need:"Hög",tip:"Nu växer hon på allvar - vattna djupt 3-4 gånger i veckan. Mulcha runt basen för att hålla fukten."},{phase:"Blomning (6-8 veckor)",need:"Hög",tip:"Kritisk period! Vattenstress nu ger att blommorna faller av och du förlorar hela skörden. Vattna vid roten varje dag i värme."},{phase:"Fruktsättning (8+ veckor)",need:"Hög",tip:"Varje gurka behöver otroliga mängder vatten. Minska aldrig nu - ojämn vattning ger bittra och krokiga frukter."}],mistakes:["Vattnar på bladen - bjuder in mjöldagg och svampsjukdomar, speciellt i växthus","Ojämn vattning - gurkan svarar med bitterhet. Bokstavligen. Bittra gurkor beror nästan alltid på vattenstress.","Vattnar med iskallt vatten - gurkan HATAR kyla. Använd tempererat vatten, gärna uppvärmt i solen.","Glömmer att gurkor i växthus torkar ut ännu snabbare än utomhus - den varma luften suger fukt."],tip:"Gräv ner en PET-flaska med hål i botten intill varje planta. Fyll med tempererat vatten - det rinner sakta rakt ner till rötterna utan att stänka på bladen."},soil:"Varm, näringsrik och lucker jord som håller fukt men aldrig blir stående blöt. Gurkan vill ha det som en varm, fuktig dröm under fötterna.",soilTips:["Blanda in rikligt med kompost innan plantering - gurkan är en hungrig gröda som vill ha näringsrik jord","I växthus: använd en blandning av kompost, torv och perlit. Upphöjda bäddar eller säckar fungerar utmärkt.","Mulcha med gräsklipp eller halm - det håller fukten, värmer jorden och håller frukterna rena"],timeline:{1:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Plantera i kallväxthus",months:"Maj (mitten)",icon:"plant"},{phase:"Blomning",months:"Jun",icon:"bloom"},{phase:"Skörd",months:"Jul-Sep",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Apr (slutet)",icon:"seedling"},{phase:"Plantera i kallväxthus",months:"Maj (slutet)-Jun",icon:"plant"},{phase:"Blomning",months:"Jun-Jul",icon:"bloom"},{phase:"Skörd",months:"Jul-Sep",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Maj",icon:"seedling"},{phase:"Plantera i kallväxthus",months:"Jun",icon:"plant"},{phase:"Blomning",months:"Jul",icon:"bloom"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:20,P:15,K:10,label:"Förodling"},{month:"Maj",N:40,P:25,K:20,label:"Etablering"},{month:"Jun",N:75,P:40,K:35,label:"Tillväxt"},{month:"Jul",N:70,P:65,K:55,label:"Blomning"},{month:"Aug",N:45,P:70,K:75,label:"Fruktsättning"},{month:"Sep",N:20,P:40,K:50,label:"Sen skörd"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla med brunnen kompost eller hästgödsel. Gräv ner det ordentligt - gurkans rötter vill hitta näring på djupet."},{timing:"Var 14:e dag under tillväxt",tip:"Ge flytande gödsel som brännässelvatten eller alggödsel. Gurkan äter mycket kväve under tillväxtfasen."},{timing:"Under blomning och fruktsättning",tip:"Byt till kaliumrik gödsel - vedaska eller tomatgödsel stärker blommor och fruktbildning. Benmjöl ger extra fosfor."},{timing:"I växthus",tip:"Växthusodlade gurkor behöver oftare gödsel eftersom vattnet sköljer ut näring snabbare. Ge lite men ofta."}],companions:{good:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Ärtornas kvävefixerande rötter ger gurkan extra näring - som en gratis gödselmaskin bredvid"},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Samma fördel som ärtor - baljväxter fixar kväve som gurkan tacksamt suger upp"},{id:"dill",name:"Dill",icon:"herb",why:"Dill lockar rovsteklar och andra nyttodjur som tar hand om bladlöss. Dessutom - gurka och dill hör ihop på tallriken också!"},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Snabb mellangröda som täcker marken och håller fukten innan gurkan tar över platsen"}],bad:[{id:"potatis",name:"Potatis",icon:"potatis",why:"Potatis konkurrerar om näring och fukt, och kan sprida sjukdomar till gurkan"},{id:"squash",name:"Squash",icon:"squash",why:"Samma familj - delar sjukdomar som mjöldagg och lockar samma skadedjur"},{name:"Aromatiska örter (stark)",icon:"herb",why:"Starkt doftande örter som salvia och mynta kan hämma gurkans tillväxt"}]},rotation:{avoid:[{id:"squash",name:"Squash"},{id:"pumpa",name:"Pumpa"},{id:"melon",name:"Melon"}],avoidWhy:"Alla gurkväxter (Cucurbitaceae) delar sjukdomar som mjöldagg, fusarium och visnesjuka. Vänta minst 3-4 år innan du odlar gurkväxter på samma plats igen.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{name:"Gröngödsling"}],goodBeforeWhy:"Baljväxter och gröngödsling bygger upp kväveförrådet i jorden. Gurkan tackar och tar emot - hon behöver massor av kväve.",goodAfter:[{id:"lok",name:"Lök"},{id:"morot",name:"Morot"},{id:"gronkal",name:"Grönkål"}],goodAfterWhy:"Lättfödda rotgrönsaker och kålväxter trivs efter gurka. Jorden är fortfarande lucker och näringsrik men utan gurkväxtsjukdomar i ytan."},varieties:[{name:"Marketmore 76",zones:[1,2,3,4,5],note:"Klassisk OP-frilandsgurka som trivs utmärkt i nordligt klimat. Sjuktålig, pålitlig och ger raka, fina gurkor."},{name:"Lemon",zones:[1,2,3,4,5],note:"Rund, gul OP-frilandsgurka (även kallad Crystal Apple hos Runåbergs). Mild, fräsch smak - en favorit hos barn."},{name:"Beit Alpha",zones:[1,2,3,4,5,6],note:"Mångsidig OP-gurka med tunna, släta frukter. Fungerar både på friland och i växthus - fantastisk i sallad."},{name:"Passandra (F1)",zones:[1,2,3,4,5,6],note:"Partenokarp växthusgurka (F1), enbart honblommor. Pålitlig och sjuktålig - men spara inte frö."},{name:"Burpless Tasty Green (F1)",zones:[1,2,3,4,5],note:"Lång, slät F1-gurka utan bitterhet. Fungerar både i växthus och på friland i gynnsamt läge."}],problems:[{name:"Mjöldagg",symptom:"Vitt, pudrigt belägg på bladen, börjar ofta sent i säsongen eller vid torr luft",fix:"Vattna vid roten, aldrig på bladen. God luftcirkulation är A och O. Drabbade blad kan klippas bort. Förebygg med mjölk-vatten-blandning (1:9) som sprayas på bladen."},{name:"Gurkbladmögel",symptom:"Gula fläckar på bladens ovansida, grått ludd undertill. Bladen torkar och dör snabbt.",fix:"Svårt att bota - förebygg genom att aldrig vattna på bladen och se till att luften cirkulerar. Ta bort drabbade blad direkt. Odla resistenta sorter."},{name:"Bladlöss",symptom:"Klumpar av gröna eller svarta löss på bladens undersida, klibbiga blad, krulliga skottspetsar",fix:"Spruta av med hård vattenstråle. Nyckelpigors larver är dina bästa vänner. Blanda in dill och gurkört nära plantorna för att locka nyttodjur."},{name:"Bittra gurkor",symptom:"Gurkorna smakar beskt och bittert, speciellt i änden närmast stjälken",fix:"Inte en sjukdom utan stress! Ojämn vattning, kyla eller näringsbrist. Vattna jämnt, skydda mot kyla och gödsla regelbundet. Skär bort den bittra änden - resten kan vara fin."}],goodToKnow:[{icon:"warning",title:"Kallväxthus = bästa valet i Sverige",text:"De flesta svenska odlare kör gurka i kallväxthus - och det med all rätt. Du behöver inget uppvärmt växthus, men skyddet från vind och kalla nätter gör enorm skillnad. Friland funkar i zon 1-4 med frilandssorter, men räkna med ojämnare skörd.",severity:"warning"},{icon:"warning",title:"Frilandssorter och växthussorter - olika behov",text:"Partenokarpa växthusgurkor (som Passandra) klarar inte kyla och vind. Frilandssorter (Marketmore, Lemon) är tåligare men ger mindre skörd i växthus. Beit Alpha är flexibel och fungerar på båda ställen. Välj rätt sort för din odlingsplats.",severity:"warning"},{icon:"warning",title:"Bitterhet = stress",text:"Bittra gurkor beror nästan alltid på ojämn vattning eller kalla nätter. Håll jämn fukt och skydda mot kyla så slipper du problemet.",severity:"warning"},{icon:"harvest",title:"Skörda ofta!",text:"Plocka gurkorna medan de är unga och fasta. Lämnar du dem för länge slutar plantan sätta nya frukter. Skörda varannan dag under högsäsong.",severity:"tip"},{icon:"leaf",title:"Klätterväxt - spaljera!",text:"Gurkan klättrar naturligt med klängen. Led henne uppåt på spaljé eller nät - det sparar plats, ger renare frukter och bättre luftcirkulation.",severity:"tip"},{icon:"warning",title:"Pollinering i växthus",text:"Växthusgurkor av moderna sorter sätter frukt utan pollinering (partenokarpa). Men frilandssorter behöver bin! Sätt blommor intill för att locka pollinerare.",severity:"warning"},{icon:"leaf",title:"Ät blommorna",text:"Precis som hos squash är gurkblommorna ätbara. Hanblommorna kan plockas utan att det påverkar skörden - perfekt i sallad eller friterade.",severity:"tip"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Förodla alltid gurka inomhus - hon behöver värme och tid. I kallväxthus (det vanligaste för hemmaodlare) planterar du ut när växthuset håller minst 12-15°C på natten, oftast inte förrän mitten av maj i söder och juni i norr. Räkna 4-5 veckor bakåt för sådd.",steps:["Så 1-2 frön per kruka, 1-2 cm djupt, i stor kruka (minst 8 cm). Gurkan hatar att bli omskollad, så gärna direkt i nedbrytbar kruka.","Håll varmt (22-25°C) - fröna gror på 4-7 dagar. En fönsterbräda ovanför ett element fungerar perfekt.","Ge massor av ljus efter uppkomst - annars blir plantorna långa och sladdriga. Sänk temperaturen något till 18-20°C.","Gallra till en planta per kruka när de fått första riktiga bladen.","Plantera ut i kallväxthuset när natttemperaturen håller sig över 12°C. Känn på jorden - den ska vara handvarm.","Sätt upp spaljé eller nät direkt vid plantering - att göra det senare skadar rötterna."],tips:["Så INTE för tidigt! 4-5 veckor innan utplantering räcker. Gurkplantor som väntar för länge inomhus blir stressade och ger sämre skörd.","Blötlägg fröna 12-24 timmar före sådd - det snabbar upp groningen märkbart","I kallväxthus planterar du ut i mitten av maj (zon 1-2), slutet av maj (zon 3-4) eller juni (zon 5-6)","Frilandsodling funkar i zon 1-3 med frilandssorter (Marketmore, Lemon) - men kallväxthus ger alltid bättre resultat i Sverige"],indoorWeeks:"4-5 veckor"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!1,description:"Gurkor korspolleras av insekter. Om du odlar flera sorter nära varandra kommer de korsa sig. Välj en sort eller isolera med nätpåsar.",steps:["Välj en fin, frisk frukt från en stark planta och märk den","Låt gurkan sitta kvar på plantan tills hon blir stor, gul och mjuk - långt förbi ätbart stadium","Skär upp den mogna gurkan och skrapa ut fröna med gelé och allt","Lägg fröna i en burk med vatten och låt dem jäsa 2-3 dagar - geléet löses upp","Skölj fröna ordentligt - de som sjunker är bra, de som flyter är tomma","Torka fröna på tidningspapper eller bakplåtspapper i 1-2 veckor på en torr plats","Förvara i papperskuvert eller glasburk på en sval, torr plats"],isolation:"Korspollinerare via insekter. Odla bara en sort för rent frö, eller isolera blommor med nätpåsar och handpollera.",storageYears:"5-6 år",tip:"Gurkfrö håller sig oväntat länge! Men om du odlar F1-hybrider (som Passandra) - spara inte frö. Avkomman blir oförutsägbar."},storage:{shelfLife:"1-3 veckor",methods:[{method:"Kylskåp",icon:"snowflake",duration:"1-2 veckor",description:"Lägg gurkan i en plastpåse med hål eller lindad i en handduk. Inte för kallt - grönsakslådan är perfekt. Gurkan ogillar temperaturer under 10°C.",best:!0},{method:"Rumstemperatur",icon:"storage",duration:"2-4 dagar",description:"Fungerar i ett par dagar om det inte är för varmt. Gurkan tappar snabbt spänst i rumstemperatur, men smakar faktiskt bäst när den inte är iskall.",best:!1},{method:"Inlagd (ättiksgurka)",icon:"storage",duration:"6-12 månader",description:"Det klassiska sättet att ta vara på gurkskörden! Små gurkor i ättikslag med dill, senapsfrön och pepparrot. Sveriges mest älskade konserv.",best:!1},{method:"Saltgurka",icon:"storage",duration:"3-6 månader",description:"Mjölksyrajäs gurkor i saltlag (2 msk salt per liter vatten) med dill, vitlök och svarta vinbärsblad. Probiotisk bonus!",best:!1},{method:"Frysa (riven)",icon:"snowflake",duration:"6-8 månader",description:"Riv gurkan och frys i portionspåsar. Konsistensen blir mjuk men funkar fint i tzatziki, smoothies och kalla soppor.",best:!1}],tips:["Gurka ska aldrig förvaras bredvid tomater, äpplen eller bananer - de avger etylen som påskyndar nedbrytningen","Hela gurkor håller längre än skurna - skär bara det du behöver och linda snittytan med plastfolie","Små, fasta gurkor är bäst för inläggning - stora gurkor blir mjuka och svampiga","Skörda på morgonen för bäst hållbarhet - gurkor som plockas i hettan tappar spänst snabbare"]},harvestCalc:{minPerSqm:3,maxPerSqm:8,unit:"kg"}},Qr=Object.freeze(Object.defineProperty({__proto__:null,gurka:y},Symbol.toStringTag,{value:"Module"})),S={name:"Hallon",icon:"hallon",category:"bär",family:"Rosväxter",familyLatin:"Rosaceae",perennial:!0,lifespan:"10-15 år",difficulty:"Enkel",difficultyWhy:"Härdig buske som sprider sig villigt. Kräver årlig beskärning men är i övrigt tacksam och lättskött.",zones:{outdoor:[1,2,3,4,5,6,7],indoor:null,greenhouse:null},days:"Skörd år 2+",spacing:"40-50 cm",rowSpacing:"150-200 cm",depth:"Plantera i samma djup som i krukan",ph:{min:5.5,max:6.5,ideal:6},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Full sol ger sötast bär och rikligast skörd, men hallon klarar halvskugga bättre än de flesta bärbuskar. I södra Sverige kan lite eftermiddagsskugga vara bra för att undvika uttorkning."},temperature:{min:-30,max:30,ideal:"18-24°C",detail:"Extremt härdig - tål ner till -30°C i vila. Trivs bäst runt 20°C under växtsäsongen. Blommar sent (juni) så frostskador på blommor är ovanliga."},wind:{level:"Måttligt känslig",detail:"Långa skott kan knäckas i stark vind. Plantera gärna intill ett staket eller sätt upp trådar att binda mot. Vindskydd förbättrar pollinering och skörd."}},watering:{need:"Medel-Hög",icon:"water",summary:"Hallon har grunda rötter och torkar lätt ut. Jämn fukt under blomning och mognad är avgörande för stora, saftiga bär.",phases:[{phase:"Vår (utbrytning)",need:"Medel",tip:"Vattna vid torka - busken vaknar och börjar skjuta nya skott. Mulcha med bark eller gräsklipp för att hålla fukten."},{phase:"Blomning (juni)",need:"Hög",tip:"Kritisk period! Vattenstress nu ger små bär eller att blommorna faller av. Vattna djupt 2-3 ggr/vecka om det inte regnar."},{phase:"Mognad (juli-aug)",need:"Hög",tip:"Fortsätt vattna regelbundet. Undvik övervattning precis innan skörd - det kan ge vattniga bär och mer mögel."},{phase:"Höst (efter skörd)",need:"Låg",tip:"Minska vattningen gradvis. Busken förbereder sig för vintervilka."}],mistakes:["Vattnar för lite under mognad - ger torra, småbär","Vattnar ovanifrån under skörd - bären möglar snabbt","Glömmer att vattna nyplanterade buskar första sommaren"],tip:"Dropp-bevattning eller vattenslang vid basen är idealiskt för hallon - det håller bladen torra och minskar mögel-risken dramatiskt."},soil:"Hallon trivs i humusrik, väldränerad jord. De HATAR stående vatten och lerjord. Blanda in rikligt med kompost vid plantering.",soilTips:["Blanda in 5-10 liter kompost per plantgrop","På lerjord: plantera upphöjt (15-20 cm) eller blanda in grov sand","Mulcha årligen med bark, halm eller löv - hallon älskar mulch","Undvik mark där det stått potatis eller tomater senaste 3 åren (verticillium-risk)"],timeline:{1:[{phase:"Plantering",months:"Maj",icon:"seedling"},{phase:"Blomning",months:"Juni-juli",icon:"bloom"},{phase:"Skörd (sommarhallon)",months:"Juli-aug",icon:"harvest"},{phase:"Beskärning",months:"Aug-sept (efter skörd)",icon:"scissors"},{phase:"Skörd (hösthallon)",months:"Aug-sept",icon:"harvest"},{phase:"Vintervila",months:"Nov-apr",icon:"snowflake"}],4:[{phase:"Plantering",months:"Maj",icon:"seedling"},{phase:"Blomning",months:"Juni",icon:"bloom"},{phase:"Skörd (sommarhallon)",months:"Juli",icon:"harvest"},{phase:"Beskärning",months:"Juli-aug (efter skörd)",icon:"scissors"},{phase:"Skörd (hösthallon)",months:"Aug-sept",icon:"harvest"},{phase:"Vintervila",months:"Okt-apr",icon:"snowflake"}],6:[{phase:"Plantering",months:"Maj-juni",icon:"seedling"},{phase:"Blomning",months:"Juni-juli",icon:"bloom"},{phase:"Skörd (sommarhallon)",months:"Juli-aug",icon:"harvest"},{phase:"Beskärning",months:"Aug (efter skörd)",icon:"scissors"},{phase:"Vintervila",months:"Sept-maj",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:3,P:2,K:2},{month:"Maj",N:7,P:4,K:3},{month:"Jun",N:6,P:6,K:5},{month:"Jul",N:4,P:5,K:8},{month:"Aug",N:3,P:3,K:6},{month:"Sep",N:1,P:2,K:4}],nutritionTips:[{timing:"Tidig vår (april)",tip:"Ge kompost eller brunnen hästgödsel runt basen. Hallon är näringshungriga och uppskattar en ordentlig vårstart."},{timing:"Blomning (juni)",tip:"En giva kaliumrik gödsel (tomatgödsel fungerar) främjar blomning och bärutveckling."},{timing:"Efter skörd",tip:"Ingen gödsel efter augusti - nya skott ska hinna mogna inför vintern, inte fortsätta växa."}],companions:{good:[{id:"vitlok",name:"Vitlök",icon:"vegetable",why:"Avskräcker bladlöss med sin starka doft. Klassisk kompanjon till bärbuskar."},{id:"ringblomma",name:"Ringblomma",icon:"flower",why:"Lockar pollinatörer och nyttiga insekter. Plus att den ser fantastisk ut vid hallonraden!"},{id:"rabarber",name:"Rabarber",icon:"vegetable",why:"Skuggar marken, behåller fukt och samsas bra utan konkurrens om samma näring."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Bägge är känsliga för verticillium-svamp. Plantera aldrig hallon där det stått potatis."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Samma verticillium-risk. Håll minst 3 meters avstånd eller vänta 3 år."},{id:"bjornbar",name:"Björnbär",icon:"berry",why:"Delar sjukdomar (virus, rotröta, rostsvamp). Håll 50+ meter avstånd."}]},rotation:{avoid:[{id:"hallon",name:"Hallon"},{id:"bjornbar",name:"Björnbär"},{id:"jordgubbar",name:"Jordgubbar"},{id:"potatis",name:"Potatis"},{id:"tomat",name:"Tomat"}],avoidWhy:"Alla Rubus-arter samt Solanaceae delar sjukdomar (verticillium, rotröta). Vänta minst 4-5 år innan du planterar hallon på samma plats igen.",goodBefore:[{name:"Gräsmatta"},{name:"Baljväxter"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Mark som legat som gräsmatta i flera år är idealisk - fri från de vanligaste hallonsjukdomarna. Baljväxter berikar jorden med kväve.",goodAfter:[{id:"gronkal",name:"Grönkål"},{id:"artor",name:"Ärtor"},{name:"Gröngödsling"}],goodAfterWhy:"Efter att hallonraden tagits bort (10+ år) är jorden utarmad. Baljväxter eller gröngödsling bygger upp den igen."},varieties:[{name:"Glen Ample",zones:[1,2,3,4],note:"Sommarhallon. Stora bär, tagglös, kraftig tillväxt. Den mest populära sommarsorten. E-planta."},{name:"Tulameen",zones:[1,2,3,4],note:"Sommarhallon. Fantastisk smak, stora bär. Lite frostkänsligare - börjar växa tidigt på våren."},{name:"Autumn Bliss",zones:[1,2,3],note:"Hösthallon. Bär på årets skott - enklaste beskärningen (klipp allt!). Behöver lång, varm höst för att hinna mogna."},{name:"Polka",zones:[1,2,3],note:"Hösthallon. Stora, söta bär. Mognar tidigare än Autumn Bliss. Lång skördeperiod aug-okt i södra Sverige."},{name:"Glen Coe",zones:[1,2,3,4],note:"Lila hallon! Tagglös, söt smak. Korsning mellan svarta och röda hallon. Begränsad tillgänglighet i Sverige."}],problems:[{name:"Hallonänger (Byturus tomentosus)",symptom:"Larver i bären, maskhål. Vita larver ~5 mm syns när bäret öppnas.",fix:"Feromonfällor i maj. Plocka infekterade bär. Nät med fint maska under blomning. Hösthallon angrips sällan."},{name:"Gråmögel (Botrytis)",symptom:"Gråludet mögel på mogna bär, speciellt i fuktig väderlek.",fix:"God luftcirkulation (gallring). Plocka bär ofta - lämna inte övermogna bär. Vattna vid basen, ej ovanifrån."},{name:"Skottsjuka",symptom:"Purpurfärgade fläckar på skotten, skotten vissnar och dör.",fix:"Klipp bort och bränn angripna skott. Förebygg med god gallring och luftcirkulation."}],goodToKnow:[{icon:"warning",title:"Hallon sprider sig - aktivt",text:"Hallonrötter skickar ut utlöpare och nya plantor dyker upp överallt. Använd rotspärr (nedgrävd plåt/plast 30 cm djupt) om du vill hålla dem på plats. Eller plantera i upphöjd bädd.",severity:"warning"},{icon:"warning",title:"Sommarhallon vs hösthallon - helt olika beskärning",text:"Sommarhallon bär frukt på fjolårets skott - klipp bara de som burit frukt. Hösthallon bär på årets skott - klipp ALLT på våren. Blandar du ihop detta förlorar du skörden!",severity:"warning"},{icon:"tip",title:"Fryser perfekt",text:"Hallon är ett av de bär som fryser bäst. Lägg ut dem i ett lager på en plåt, frys, flytta sedan till påse. Perfekt smak året runt.",severity:"tip"},{icon:"tip",title:"Plocka rätt",text:"Mogna hallon lossnar lätt från tappen (den vita kärnan). Om du behöver dra - vänta en dag till. Plocka gärna varannan dag under högsäsong.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Hallon planteras som barrotade plantor eller krukodlade plantor. Bäst att plantera på hösten eller tidig vår.",steps:["Gräv en grop dubbelt så bred som rotklumpen","Blanda in kompost i jorden","Plantera i samma djup som i krukan","Vattna rikligt vid plantering","Mulcha med bark eller halm","Sätt upp stöd (trådar eller staket) för skotten att binda mot"],tips:["Plantera på hösten om möjligt - ger starkare etablering","Sätt rotspärr om du vill begränsa spridningen","Nyplanterade buskar ger full skörd först år 2-3"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Hallon förökas enklast via rotskott - busken sprider sig naturligt och skickar upp nya plantor via utlöpare.",steps:["Identifiera friska rotskott med bra rotbildning","Gräv försiktigt upp rotskottet med så mycket rot som möjligt","Plantera om direkt på ny plats","Vattna rikligt och mulcha"],isolation:"Vegetativ förökning - kloner av moderplantan. Ingen korspollinering relevant.",storageYears:"Ej tillämpligt",tip:"Ta alltid förökningsmaterial från friska, produktiva buskar. Undvik att sprida sjukdomar genom att välja plantor utan tecken på skottsjuka eller virusangrepp."},storage:{shelfLife:"2-3 dagar (färska)",methods:[{method:"Frysning",icon:"snowflake",duration:"10-12 månader",description:"Det absolut bästa sättet. Lägg bären i ett lager på bakplåtspapper, frys 2 timmar, flytta sedan till påse. Behåller form och smak perfekt.",best:!0},{method:"Sylt & mos",icon:"storage",duration:"1+ år",description:"Klassikern. Hallon och socker i lika delar. Mindre socker ger bättre hallonsmak men kortare hållbarhet.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"2-3 dagar",description:"Lägg bären i ett lager på hushållspapper i en skål. Tvätta INTE förrän precis innan du äter - fukt ger mögel.",best:!1},{method:"Torkning",icon:"sun",duration:"6+ månader",description:"Torka i ugn på 50°C i 8-12 timmar eller i torkmaskin. Blir intensivt söta. Perfekt i müsli eller bakning.",best:!1}],tips:["Plocka alltid torra bär - vänta tills daggen torkat","Sortera och ta bort skadade bär direkt - en möglig buske förstör hela skålen","Frysta hallon kan gå direkt i smoothies utan att tina först"]},harvestCalc:{minPerSqm:.5,maxPerSqm:1.5,unit:"kg"},pruning:{label:"Beskärning",types:{summer:{name:"Sommarhallon",when:"Direkt efter skörd (juli-aug)",description:"Sommarhallon bär frukt på fjolårets skott. Efter skörd klipper du bort alla skott som burit frukt (bruna, vedartade) vid marknivå. Spara 6-8 av de starkaste nya gröna skotten per löpmeter och bind upp dem.",steps:["Klipp bort alla skott som burit frukt - nära marken","Välj ut 6-8 starka nya skott per löpmeter","Ta bort alla svaga, tunna eller skadade skott","Bind upp de kvarvarande skotten mot tråd/staket","Korta ev. topparna till ~170 cm höjd i feb"]},autumn:{name:"Hösthallon",when:"Tidig vår (mars-april) innan tillväxt börjar",description:"Hösthallon bär frukt på årets skott - därför klipper du enkelt ner ALLA skott till marknivå på våren. Nya skott växer upp, blommar och ger frukt samma sommar/höst.",steps:["Klipp ner ALLA skott till 5-10 cm ovan mark i mars-april","Rensa bort avklippta grenar","Mulcha med kompost eller bark","Nya skott dyker upp - gallra till 8-10 per löpmeter"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Rotskott",description:"Det enklaste sättet. Hallon skickar naturligt upp nya skott via utlöpare. Gräv upp ett skott med rot på våren eller hösten och plantera om.",icon:"seedling"},{method:"Sticklingar",description:"Klipp 15-20 cm bitar av friska skott i november. Sätt i fukt-hållen jord utomhus. De rotar sig under vintern och kan planteras ut på våren.",icon:"scissors"}],tip:"Ta alltid förökningsmaterial från friska, produktiva buskar. Undvik att sprida sjukdomar genom att välja plantor utan tecken på skottsjuka eller virusangrepp."}},$r=Object.freeze(Object.defineProperty({__proto__:null,hallon:S},Symbol.toStringTag,{value:"Module"})),x={name:"Hasselnöt",icon:"hasselnut",category:"frukt",family:"Björkväxter",familyLatin:"Betulaceae",perennial:!0,lifespan:"40-80 år (uppstammad), 1000+ år (buske via rotskott)",difficulty:"Enkel",difficultyWhy:"Hasseln är ursprunglig i Sverige och sköter sig i princip själv. De storfruktiga odlingssorterna kräver lite mer uppmärksamhet - framförallt en pollineringspartner och skydd mot nötvivlar. Men jämfört med andra fruktträd är hasseln förbluffande anspråkslös.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:null},days:"Skörd år 3-5",spacing:"3-5 m",spacingNote:"Buskform: 3-4 m. Uppstammad: 4-5 m. Tänk på att du behöver minst två sorter för pollinering!",rowSpacing:"4-5 m",depth:"Rotklumpens djup",depthNote:"Plantera på samma djup som plantan stått. Hasseln har ett relativt grunt rotsystem.",ph:{min:5.5,max:7.5,ideal:6},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Hasseln trivs i sol till halvskugga - den växer naturligt i skogsbryn. Men för god nötsättning behöver den rejält med sol. I djup skugga blommar den men nötterna uteblir."},temperature:{min:-30,max:35,ideal:"15-25°C",detail:"Extremt härdig - vilda hasslar tål ner mot -30°C. Men hängen (hanblommorna) som slår ut redan i januari-februari tål bara några minusgrader. Kalla vintrar ger dålig pollinering."},wind:{level:"Vindexponerad OK",detail:"Hasseln är vindpollinerad - den BEHÖVER lite vind! Men allt för utsatt läge torkar ut hängena. En lagom skyddad men luftig plats är perfekt."}},watering:{need:"Medel",icon:"water",summary:"Hasseln har ett relativt grunt rotsystem och saknar vaxskikt på bladen - den torkar därför ut lättare än man tror. Regelbunden vattning vid torka ger märkbart bättre skörd.",phases:[{phase:"Vår (pollinering)",need:"Låg",tip:"Normalt tillräckligt med vinterväta och vårregn. Pollineringen sker mitt i vintern - inget du kan påverka."},{phase:"Sommar (nötutveckling)",need:"Medel",tip:"Vattna vid torka! Kärnan börjar fylla skalet i juni - vattenstress nu ger tomma nötter."},{phase:"Sensommar (mognad)",need:"Medel",tip:"Fortsätt vattna vid behov. Nötterna mognar i september-oktober."},{phase:"Vinter",need:"Ingen",tip:"Busken vilar. Ingen vattning behövs."}],mistakes:["Underskattar vattningsbehovet - hasseln har grunt rotsystem och vaxfria blad","Glömmer att vattna under nötutvecklingen (juni-aug) - ger tomma skal"],tip:"Mulcha ordentligt runt busken - det håller fukt och minskar ogräs. Hasseln gillar ett tjockt lager löv eller flis."},soil:"Hasseln trivs i de flesta jordar men föredrar lätt, väldränerad, mullrik jord. Den tål inte vattensjuk mark - rötterna är ytliga och känsliga för stående vatten.",soilTips:["pH runt 6.0 är optimalt - hasseln gillar svagt sur jord","Blanda in kompost vid plantering","Undvik vattensjuka svackor - rötterna tål inte stående vatten","Mullrik skogsbrynsjord är drömmen"],timeline:{1:[{phase:"Hängen sprider pollen",months:"Feb-mars",icon:"bloom"},{phase:"Pollinering",months:"Feb-april",icon:"bloom"},{phase:"Nötutveckling",months:"Juni-sept",icon:"growth"},{phase:"Skörd",months:"Sept-okt",icon:"harvest"},{phase:"Beskärning",months:"Feb-mars",icon:"scissors"},{phase:"Vintervila",months:"Nov-jan",icon:"snowflake"}],4:[{phase:"Hängen sprider pollen",months:"Mars-april",icon:"bloom"},{phase:"Nötutveckling",months:"Juni-sept",icon:"growth"},{phase:"Skörd",months:"Sept-okt",icon:"harvest"},{phase:"Beskärning",months:"Mars",icon:"scissors"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}],6:[{phase:"Hängen sprider pollen",months:"April",icon:"bloom"},{phase:"Nötutveckling",months:"Juli-sept",icon:"growth"},{phase:"Skörd",months:"Okt",icon:"harvest"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}]},nutritionData:[{month:"Mar",N:2,P:1,K:1},{month:"Apr",N:4,P:2,K:1},{month:"Maj",N:6,P:4,K:2},{month:"Jun",N:7,P:5,K:4,label:"Kärnfyllning"},{month:"Jul",N:5,P:4,K:6},{month:"Aug",N:3,P:3,K:7,label:"Mognad"},{month:"Sep",N:1,P:2,K:4}],nutritionTips:[{timing:"Tidig vår (april-maj)",tip:"Ge kompost eller brunnen gödsel runt busken. Gödsla inte efter juli - det försämrar nötkvaliteten."},{timing:"Sommar",tip:"Ingen extra gödsling behövs. Mulcha med löv eller flis för långsam näringsfrisättning."},{timing:"Höst",tip:"Lägg ett tjockt lager löv som vintermulch - det bryts ner och ger perfekt vårstart."}],companions:{good:[{name:"Klöver",icon:"flower",why:"Fixerar kväve och täcker marken under hasselbuskarna. Perfekt marktäckare."},{name:"Vitsippa",icon:"flower",why:"Trivs naturligt under hasselbuskar i svenska skogsbryn. Blommar innan hasseln får blad."},{name:"Ramslök",icon:"herb",why:"Klassisk skogsbrynväxt som trivs i halvskuggan under hasselbuskar. Skörd på våren innan löven skuggar."}],bad:[{name:"Gräsmatta intill stammen",icon:"vegetable",why:"Gräs konkurrerar om vatten och näring. Håll marken runt busken fri med mulch istället."}]},rotation:{avoid:[{name:"Hasselnöt"}],avoidWhy:"Hasseln är inte känslig för trötthetssjuka på samma sätt som stenfrukter. En ny buske trivs bra på de flesta platser.",goodBefore:[{name:"Gröngödsling"},{name:"Gräsmatta"}],goodBeforeWhy:"Mullrik, väletablerad jord ger bäst start.",goodAfter:[{name:"Gröngödsling"}],goodAfterWhy:"Jorden under hasselbuskar är ofta utmärkt - rötterna har byggt upp jordstrukturen."},varieties:[{name:"Nottingham Prolific",zones:[1,2,3,4,5],note:"Medelstor nöt som inte krymper vid torkning - ovanligt! 6-8 nötter per klase. Tunn skal. God smak. Härdig till zon 4-5. Den bästa allroundsorten för svenska förhållanden."},{name:"Cosford",zones:[1,2,3],note:"Tunn skal, tidig pollinerare, nästan självfertil. Mild, söt smak. Krymper något vid torkning. Utmärkt pollineringspartner till andra sorter."},{name:"Jättenöt från Halle",zones:[1,2,3,4],note:"Stor nöt med tjockt skal - svårare för nötvivlar att ta sig in! Resistens mot gallkvalster. Härdig. Bra val om nötvivlar är ett problem i din trädgård."},{name:"Gunslebert",zones:[1,2,3],note:"Kraftig sort med söt, aromatisk smak. God pollinerare. Passar till färsk konsumtion, torkning och bakning."},{name:"Röd Zellernöt",zones:[1,2,3],note:"Bronsröda blad, röd hylsa, söt smak. Tidigt mogen (oktober). Både dekorativ och produktiv - vacker häckväxt."}],problems:[{name:"Nötvivel (Curculio nucum)",symptom:"Tomma nötter med ett litet runt hål. Baggen borrar in i den omogna nöten och lägger ägg. Larven äter kärnan inifrån och gnager sig sedan ut.",fix:"Täck marken under buskarna med fiberduk under sensommaren (hindrar larver att ta sig ner i marken). Välj sorter med tjockt skal (Jättenöt från Halle). Samla upp nedfallna nötter snabbt."},{name:"Nötskrika och ekorre",symptom:"Nötterna försvinner dagarna kring mognad. Nötskrikan och ekorren vet EXAKT när nötterna är klara.",fix:"Skörda lite innan full mognad - nötterna eftermognar. Täta bärnät runt buskarna. Var snabbare än djuren."},{name:"Hasselgallkvalster",symptom:'Svullna, rundade knoppar som inte slår ut på våren ("blinda knoppar"). Minskar skörden.',fix:"Plocka bort svullna knoppar under vintern och förstör dem. Välj resistenta sorter (Jättenöt från Halle). Regelbunden beskärning ger luftig krona."},{name:"Dålig nötsättning",symptom:"Busken blommar och växer fint men ger inga eller tomma nötter.",fix:"Vanligaste orsaken: saknar pollineringspartner! Hasseln är självsteril i praktiken. Plantera minst två olika sorter inom 18 meters avstånd. Kalla vintrar försämrar pollineringen."}],pollination:{selfFertile:!1,description:"Hasseln är vindpollinerad med separata han- och honblommor. Hängena (hanblommorna) sprider pollen redan i januari-mars - mitt i vintern! Honblommorna ser ut som små röda trådar ur knopparna. I praktiken är hasseln självsteril - du behöver minst två olika sorter.",groups:[{name:"Tidig pollinering",varieties:["Cosford","Röd Zellernöt"]},{name:"Mellansäsong",varieties:["Nottingham Prolific","Gunslebert"]},{name:"Sen pollinering",varieties:["Jättenöt från Halle"]},{name:"Universell pollinerare",varieties:["Vild hassel (Corylus avellana)"]}],tip:"Vild hassel fungerar utmärkt som pollinerare! Om du har vild hassel i närheten behöver du kanske bara en odlingssort. Krokhassel (Corylus avellana Contorta) är en dekorativ pollinerare som gör jobbet med stil."},establishment:{description:"Hasseln etablerar sig snabbt och ger de första nötterna redan efter 3-5 år. Den är anspråkslös och tålmodig - perfekt för den som vill ha ett produktivt fruktträd utan drama.",years:[{year:"År 1-2",tasks:["Vattna regelbundet under sommaren","Mulcha ordentligt runt busken","Bestäm form: buskform (naturlig) eller uppstammad","Ta bort oönskade rotskott från första säsongen"]},{year:"År 3-5",tasks:["Första nötterna!","Börja regelbunden beskärning: ta bort gamla stammar (tjockare än 10 cm)","Håll 6-10 huvudstammar i buskform","Kontrollera nötvivelproblem - tomma nötter med hål"]},{year:"År 5+",tasks:["Full skörd: 2-4 kg per buske i goda år","Årlig beskärning: byt ut gamla stammar mot nya skott","Ta bort rotskott som sprider sig utanför önskat område"]}],protection:["Stamskydd mot gnagare, särskilt under snötäcke (sorkar!)","Viltskydd om rådjur finns i området","Nätskydd mot nötskvärka och ekorre under skördesäsongen"],tip:"Hasseln bildar naturligt en flerstammig buske med rotskott. Bestäm tidigt om du vill ha buskform (traditionellt, enklare) eller uppstammad form (prydligare, lättare att skörda under). Ympade buskar på turkisk hassel som grundstam ger ingen rotskottsproduktion."},ripeningGuide:{description:"Hasselnötter mognar från september till november beroende på sort. Hylsan (svepet) gulnar och nöten släpper vid lätt vridning. Skörda strax innan full mognad - nötterna eftermognar och du hinner före djuren.",entries:[{variety:"Cosford",from:"sep",to:"okt",type:"Tidig hasselnöt"},{variety:"Nottingham Prolific",from:"sep",to:"okt",type:"Tidig hasselnöt"},{variety:"Röd Zellernöt",from:"okt",to:"okt",type:"Mellansäsong"},{variety:"Gunslebert",from:"okt",to:"okt",type:"Mellansäsong"},{variety:"Jättenöt från Halle",from:"okt",to:"nov",type:"Sen hasselnöt"}],tip:"Flyteprovet avslöjar allt: lägg nötterna i vatten. Tomma nötter flyter, fulla sjunker. Perfekt sätt att sortera bort nötvivelangrepp!"},goodToKnow:[{icon:"tip",title:"Sveriges egen nöt",text:"Hasseln är en av våra mest underskattade inhemska växter. Den invandrade till Sverige för 9 500 år sedan och växer vilt upp till Dalälven. Att odla hassel är att odla svensk historia.",severity:"tip"},{icon:"warning",title:"Du behöver TVÅ sorter",text:"Den vanligaste orsaken till utebliven skörd: hasseln är självsteril i praktiken. Han- och honblommorna på samma buske mognar vid olika tidpunkter. Plantera alltid minst två olika sorter inom 18 meters avstånd. Vild hassel i närheten fungerar som pollinerare.",severity:"warning"},{icon:"tip",title:"Hängen i januari - vinterns tecken på vår",text:"Hasselhängena som sprider gult pollen redan i januari-februari är ett av årets första vårtecken. Honblommorna är små röda trådar ur knopparna - lätta att missa men oerhört viktiga.",severity:"tip"},{icon:"warning",title:"Nötviveln - den listiga fienden",text:"Hittar du tomma nötter med ett litet runt hål har nötviveln varit framme. Baggen borrar in i den omogna nöten och lägger ägg. Larven äter kärnan och gnager sig sedan ut. Välj tjockskaliga sorter (Jättenöt från Halle) och täck marken med fiberduk under sensommaren.",severity:"warning"}],sowing:{method:"direct",label:"Plantering",description:"Hasselbuskar planteras som rotade plantor, helst på hösten. De etablerar sig snabbt och börjar ge nötter efter 3-5 år.",steps:["Gräv en grop dubbelt så bred som rotklumpen","Blanda in kompost i den uppgrävda jorden","Plantera på samma djup som plantan stått","Vattna rikligt efter plantering","Mulcha ordentligt i 1 meters radie","Tänk på att plantera minst TVÅ sorter för pollinering!"],tips:["Höstplantering ger bäst etablering","Plantera sorterna inom 18 meters avstånd för pollinering","Vild hassel i närheten räknas som pollinerare","Krokhassel (Contorta) är en dekorativ pollinerare"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Rotskott / Avläggning",biennial:!1,description:"Hasseln är en av de enklaste buskarna att föröka. Rotskott och avläggare ger genetiskt identiska kloner av moderplantan.",steps:["Rotskott: gräv upp ett rotskott med rötter intakta på tidig vår","Avläggare: böj en låg gren ner till marken, sticka och täck med jord","Ta bort knoppar på den begravda delen av avläggaren","Vattna under sommaren - rötter bildas på 6-12 månader","Separera från moderplantan nästa höst"],isolation:"Vegetativ förökning ger exakta kloner av moderplantan.",storageYears:"Nötter kan sås direkt på hösten för fröförökning",tip:"Rotskott är det enklaste sättet - hasseln producerar dem naturligt. Gräv upp ett skott med rötter och plantera på ny plats. Perfekt för att starta en hassellund!"},storage:{shelfLife:"6-24 månader (torkade)",methods:[{method:"Torkning + torrt förvar",icon:"cellar",duration:"1-2 år",description:"Torka nötterna i ventilerat rum i 4-6 veckor tills vattenhalten sjunkit till 8-10%. Förvara svalt och torrt i nätpåsar. De flesta sorter krymper vid torkning - det är normalt.",best:!0},{method:"Färsk i fuktig sand",icon:"cellar",duration:"3-4 månader",description:"Traditionellt svenskt knep: förvara nötterna i fuktig sand utomhus. Behåller färsk smak och textur till jul. Perfekt för sorter som krymper vid torkning.",best:!1},{method:"Frysning (skalade)",icon:"snowflake",duration:"2+ år",description:"Skala och frys i påsar. Alltid redo för bakning, müsli och snacks.",best:!1}],tips:["Flyteprovet: tomma nötter flyter, fulla sjunker - sortera snabbt","Torka ORDENTLIGT - fuktiga nötter möglar snabbt","Nottingham Prolific är unik: den krymper inte vid torkning","Nötskal komposteras långsamt - krossa eller bränn dem"]},harvestCalc:{minPerSqm:2,maxPerSqm:4,unit:"kg per buske"},pruning:{label:"Beskärning",types:{winter:{name:"Vinterbeskärning (buskform)",when:"Februari-mars (före hängesläpp i söder, efter i norr)",description:"Hasseln bildar naturligt en flerstammig buske. Målet är att hålla busken produktiv genom att regelbundet byta ut gamla stammar mot unga skott.",steps:["Behåll 6-10 huvudstammar av varierande ålder","Såga av stammar tjockare än 10 cm - de är förbi sin bästa tid","Ta bort stammar som växer inåt kronan","Ta bort oönskade rotskott (lämna 2-3 unga som ersättare)","Sikta på en öppen, skålformad buske med ljus i mitten"]},summer:{name:"Sommarbeskärning (brutning)",when:"Juli-augusti",description:"Traditionell metod: bryt (klipp inte!) kraftiga sidoskott till hälften. Det bromsar vegetativ tillväxt och stimulerar fruktknoppar. De brutna skotten hänger kvar och skuggar inte.",steps:["Bryt (inte klipp!) kraftiga sidoskott som är 25+ cm","Bryt till halva längden - skottet hänger kvar men slutar växa","Lämna fruktbärande korta skott i fred","Ta bort brutna skott vid vinterbeskärningen"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Rotskott",description:"Det enklaste sättet. Gräv upp ett rotskott med rötter intakta. Hasseln producerar dem naturligt - perfekt för den som vill starta en hassellund.",icon:"seedling"},{method:"Avläggning",description:"Böj en låg gren till marken och täck med jord. Rötter bildas på 6-12 månader. Separera nästa höst.",icon:"seedling"},{method:"Frösådd",description:"Stratifiera nötter hela vintern i fuktig sand. Så på våren. Ca 10% liknar moderplantan - bra för pollinerare men inte för namnsorter.",icon:"seed"}],tip:"Vill du föröka en namnsort exakt: rotskott eller avläggning. Frösådd ger unika plantor som fungerar utmärkt som pollinerare men inte är identiska med moderplantan."}},ra=Object.freeze(Object.defineProperty({__proto__:null,hasselnut:x},Symbol.toStringTag,{value:"Module"})),K={name:"Havtorn",icon:"havtorn",category:"bär",family:"Havtornsväxter",familyLatin:"Elaeagnaceae",perennial:!0,lifespan:"30-50+ år",difficulty:"Medel",difficultyWhy:"Extremt härdig och anspråkslös växt som klarar kyla, vind och mager jord. Utmaningarna? Du behöver både han- och honplantor för skörd, bären sitter fastklistrade bland vassa taggar, och rotskotten kan ta över trädgården om du inte håller koll.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:null},days:"År 3-5 (första skörd)",spacing:"150-200 cm",spacingNote:"Hanplantor kan stå lite tätare; 1 hane per 5-6 honor",rowSpacing:"300-400 cm",depth:"Samma djup som i krukan",depthNote:"Plantera inte för djupt - havtorn fixar kväve via rotbakterier som behöver syre",ph:{min:5.5,max:8,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Havtorn är en riktig solälskare - hon vill ha full sol för att producera de vitaminbomber till bär hon är känd för. I halvskugga överlever hon men ger klart färre bär. Tänk strandhed och kustklippor - det är hennes naturliga hem."},temperature:{min:-40,max:35,ideal:"15-25°C",detail:"En av Sveriges härdigaste bärväxter - tål ner till -40°C utan att blinka. Havtorn är ursprungligen hemma på Gotland och längs Östersjökusten och klarar allt svenskt klimat kan kasta mot henne."},wind:{level:"Mycket tålig",detail:"Havtorn är vindpollinerad och trivs faktiskt i blåsiga lägen! Hon är en pionjärväxt på strandvallar och kustklippor. Vind hjälper dessutom pollinet att nå från hanplantan till honplantorna."}},watering:{need:"Låg",icon:"water",summary:"Havtorn är fantastiskt torktålig tack vare sitt djupa rotsystem och kvävefixerande rotbakterier. En etablerad buske klarar sig i princip på naturlig nederbörd. Bara nyplanterade buskar och extremt torra somrar kräver extra vattning.",phases:[{phase:"Etablering (år 1-2)",need:"Medel",tip:"Nyplanterade buskar behöver regelbunden vattning tills de etablerat sitt rotsystem. Vattna djupt 1-2 ggr/vecka vid torka under första säsongen."},{phase:"Blomning (april-maj)",need:"Låg-Medel",tip:"Havtorn vindpollineras tidigt på våren. En alldeles för torr vår kan påverka pollensättningen, men normalt räcker naturlig fukt."},{phase:"Bärutveckling (juni-aug)",need:"Låg",tip:"Etablerade buskar klarar sig själva. Bara vid extrem torka (3+ veckor utan regn) behöver du vattna - och då djupt, inte lite och ofta."},{phase:"Höst/vinter",need:"Ingen",tip:"Lämna henne i fred. Havtorn sköter sig själv under viloperioden."}],mistakes:["Vattnar för mycket - havtorn avskyr vattensjuk jord och rötterna kan ruttna","Vattnar lite och ofta istället för djupt och sällan - det ger ytliga rötter","Glömmer nyplanterade buskar - de första 1-2 åren behöver de faktiskt vatten","Planterar i kompakt lerjord utan dränering - det är det säkraste sättet att döda en havtornsbuske"],tip:"Havtorn har sitt ursprung på torra strandvallar och sandiga kuster. Behandla henne som du skulle behandla en strandväxt - hellre för lite vatten än för mycket. Det enda hon verkligen inte tål är blöta fötter."},soil:"Havtorn är anmärkningsvärt anspråkslös och trivs i mager, sandig jord där andra växter ger upp. Hon fixar sitt eget kväve via symbiotiska Frankia-bakterier i rötterna - ett trick hon delar med baljväxter. Tung lerjord är det enda hon verkligen ogillar.",soilTips:["Sandig, väldränerad jord är perfekt - precis som hennes naturliga kusthabitat","Blanda INTE in kompost eller gödsel vid plantering - havtorn föredrar mager jord och fixar sitt eget kväve","Lerjord? Blanda in rikligt med sand och grus för dränering - det är helt avgörande","Tolererar alkalisk jord (upp till pH 8!) - ovanligt bland bärväxter och perfekt för kalkrika gotlandsmarker","Undvik absolut vattensjuk mark - bättre med en torr kulle än en fuktig sänka"],timeline:{1:[{phase:"Plantering",months:"Sept-okt eller april-maj",icon:"seedling"},{phase:"Blomning",months:"April-maj (före bladen)",icon:"bloom"},{phase:"Skörd",months:"Sept-okt",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (mars) eller sen höst",icon:"scissors"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],4:[{phase:"Plantering",months:"Okt-nov eller mars-april",icon:"seedling"},{phase:"Blomning",months:"Mars-april (före bladen)",icon:"bloom"},{phase:"Skörd",months:"Aug-sept",icon:"harvest"},{phase:"Beskärning",months:"Sen vinter (feb-mars)",icon:"scissors"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}],6:[{phase:"Plantering",months:"Okt-nov eller mars-april",icon:"seedling"},{phase:"Blomning",months:"Mars-april (före bladen)",icon:"bloom"},{phase:"Skörd",months:"Aug-sept",icon:"harvest"},{phase:"Beskärning",months:"Sen vinter (feb-mars)",icon:"scissors"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:2,P:1,K:1},{month:"Maj",N:3,P:2,K:2},{month:"Jun",N:2,P:3,K:3},{month:"Jul",N:2,P:3,K:5},{month:"Aug",N:1,P:2,K:4},{month:"Sep",N:1,P:1,K:2}],nutritionTips:[{timing:"Generellt",tip:"Havtorn fixar sitt eget kväve via Frankia-bakterier i rötterna - hon behöver alltså INTE kvävegödsling! Det gör henne till en av de mest lättgödslade bärväxterna du kan ha."},{timing:"Tidig vår",tip:"En lätt giva kalium- och fosforrik gödsel kan stärka blomning och bärkvalitet, men det är inget krav. Havtorn klarar sig på nästan ingenting."},{timing:"Vid plantering",tip:"Gödsel behövs inte - det kan faktiskt hämma Frankia-bakterierna som fixar kväve. Låt henne etablera sig i mager jord som hon gillar."},{timing:"Höst",tip:"En tunn mulch av löv runt basen ger tillräcklig näring. Överdriv inte - havtorn trivs i fattigdom."}],companions:{good:[{name:"Gräs och ängsväxter",icon:"flower",why:"Marktäckare som håller ogräs borta utan att konkurrera. Havtorn fixar kväve som gynnar omgivande växter - hon är generös med sina grannar."},{name:"Vildrosor",icon:"flower",why:"Samma tuffa krav - sol, vind, mager jord. De kompletterar varandra perfekt i en naturlig häck och ger mat åt fåglar."},{id:"rabarber",name:"Rabarber",icon:"vegetable",why:"Trivs med det kväve havtornen lämnar i jorden. Stora blad ger marktäckning. God kombination i en skogsträdgård."}],bad:[{name:"Grödor nära rotskott",icon:"vegetable",why:"Havtorn sprider sig aggressivt med rotskott och kan ta över ytan runt sig. Plantera ingenting värdefullt inom 3-4 meters radie som du inte vill att hon ska kolonisera."},{name:"Skuggkänsliga växter",icon:"flower",why:"En fullvuxen havtornsbuske blir 3-5 meter hög och skuggar allt under sig. Planera för hennes fulla storlek."}]},rotation:{avoid:[{name:"Havtorn"}],avoidWhy:"Plantera inte ny havtorn där gammal stått - jorden kan innehålla sjukdomar och Frankia-bakterierna kan vara ur balans. Vänta minst 5 år.",goodBefore:[{name:"Öppen, solig mark"},{name:"Sandiga ytor"},{name:"Vindexponerade lägen"}],goodBeforeWhy:"Havtorn är en pionjärväxt som trivs bäst där andra växter kämpar. Solig, mager, vindutsatt mark är hennes paradis.",goodAfter:[{name:"Grönsaker"},{name:"Bärbuskar"}],goodAfterWhy:"Efter havtorn är jorden kväveanrikad tack vare Frankia-bakterierna. Perfekt startplats för näringskrävande grödor som grönsaker."},varieties:[{name:"Botanitjeskaja Ljubitelskaja",zones:[1,2,3,4,5],note:"Honplanta. Rysk sort med ovanligt stora bär och kortare taggar. Lättare att skörda tack vare mjukare fruktskaft. Bland de bästa för handplockning. Finns hos Blomsterlandet, Klostra och Svartbackens."},{name:"Leikora",zones:[1,2,3,4],note:"Honplanta. Tysk sort som blivit standard i svensk handel. Stora, orangeröda bär med hög vitaminhalt. Produktiv och relativt lättskördad. Bäst i södra och mellersta Sverige."},{name:"Hergo",zones:[1,2,3],note:"Honplanta. Tysk sort med längre bärstjälk - gör skörden lite enklare. Orangea bär, god smak. Kompaktare växt än Leikora. Trivs bäst i milt klimat, begränsad härdighet i Sverige."},{name:"Pollmix",zones:[1,2,3,4],note:"HANPLANTA - pollinatör! Tysk klon som producerar rikligt med pollen och blommar länge. Du MÅSTE ha minst en hanplanta per 5-6 honplantor. Utan hane - inga bär. Placera i vindriktningen från honplantorna."}],problems:[{name:"Silverbladssjuka (Verticillium)",symptom:"Bladen blir silverglänsande och grenarna dör tillbaka. Vanligast i varma, fuktiga somrar. Kan spridas snabbt om man inte agerar.",fix:"Klipp bort angripna grenar minst 30 cm under synliga symptom. Desinficera sekatören mellan varje klipp. Bränn det sjuka materialet. God dränering minskar risken - havtorn i sandig jord drabbas sällan."},{name:"Havtornsflugan",symptom:"Larverna äter sig in i bären som blir mjuka och missfärgade. Små flugor (3-4 mm) syns runt buskarna i juni-juli.",fix:"Svår att bekämpa kemiskt. Skörda tidigt innan larverna gör stor skada. Plocka bort angripna bär. Insektsnät under juni-juli kan hjälpa på mindre buskar."},{name:"Rotröta",symptom:"Busken gulnar, växer dåligt och vissnar trots vattning. Rötterna är brunsvarta och mjuka.",fix:"Nästan alltid orsakat av dålig dränering. Förebygg genom att plantera i sandig, väldränerad jord. Drabbade buskar kan sällan räddas - gräv upp och förbättra dräneringen innan du planterar om."},{name:"Fåglar",symptom:"Trastsläktet och andra bärätande fåglar älskar havtornsbär. Kan plocka en buske ren på en dag.",fix:"Nät över buskarna när bären börjar mogna. Eller gör som gotlänningarna - skörda tidigt och låt fåglarna få sin del. Det finns gott om bär till alla."}],goodToKnow:[{icon:"warning",title:"Du MÅSTE ha en hanplanta!",text:"Havtorn är tvåbyggare - han- och honblommor sitter på separata buskar. Utan pollinatör blir det noll bär. Plantera 1 hanplanta (Pollmix) per 5-6 honplantor och placera den i vindriktningen. Pollinet sprids med vinden, inte insekter.",severity:"warning"},{icon:"warning",title:"Rotskotten tar över!",text:"Havtorn sprider sig aggressivt med rotskott som kan dyka upp flera meter från moderplantan. Plantera med rotspärr (vertikal barriär 60 cm ner) eller på en plats där hon får breda ut sig fritt. Klipp rotskott som dyker upp där du inte vill ha dem.",severity:"warning"},{icon:"warning",title:"Taggarna är brutala",text:"Havtornens taggar är långa och vassa - riktigt otrevliga att råka ut för. Använd alltid tjocka läderhandskar vid skörd och beskärning. Modernare sorter (Botanisjtjeskaja, Otradnaja) har färre taggar men de finns ändå där.",severity:"warning"},{icon:"tip",title:"Klipp-och-frys-metoden",text:"Det smartaste sättet att skörda havtorn: klipp av hela bärbärande grenar, frys dem, och sedan slå eller skaka av de frysta bären. De lossnar lättare frysta än färska. Busken tål att man tar grenar - det fungerar som en extra beskärning.",severity:"tip"},{icon:"tip",title:"Vitaminbomb utan like",text:'Havtornsbär innehåller 10 gånger mer C-vitamin än apelsiner, plus omega-3, -6, -7 och -9-fettsyror. De kallas ibland "havets olivolja" på grund av sin unika fettsyraprofil. Få växter i världen kan mäta sig näringsmässigt.',severity:"tip"},{icon:"tip",title:"Kvävefixerare - gödsel sig själv",text:"Havtorn lever i symbios med Frankia-bakterier som fixar luftkväve i rötterna - precis som baljväxter. Det betyder att hon bokstavligen gödsel sig själv och dessutom berikar jorden för omgivande växter. Perfekt i en skogsträdgård!",severity:"tip"},{icon:"tip",title:"Svensk kustklassiker",text:"Havtorn är en av få bärväxter som är vild i Sverige - framförallt längs Gotlands och Ölands kuster och vid Östersjön. Bären har plockats i århundraden och är en viktig del av kustens ekosystem.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Havtorn planteras som krukodlade plantor eller barrotade buskar. Höstplantering (okt-nov) ger bäst etablering i södra Sverige, vårplantering (april-maj) rekommenderas i norrland. Plantera alltid minst en hanplanta per 5-6 honplantor.",steps:["Välj en solig, väldränerad plats - gärna sandig jord, sluttning eller vindexponerat läge","Gräv en grop dubbelt så bred som rotklumpen men inte djupare","Blanda INTE in kompost - havtorn trivs i mager jord och fixar eget kväve","Om lerjord: blanda in rikligt med sand och grus i gropen och runt om för dränering","Plantera på samma djup som i krukan - inte djupare","Vattna rikligt vid plantering och regelbundet första sommaren","Installera rotspärr om du vill begränsa spridningen (60 cm djup barriär runt planteringen)","Placera hanplantan i rådande vindriktning från honplantorna - pollinet sprids med vinden"],tips:["Plantera hanplantan i lovartssidan (den sida vinden oftast kommer från) för bäst pollinering","Räkna med 3-5 år till första skörden - ha tålamod, det är värt väntan","Överväg rotspärr redan vid plantering - det är mycket enklare än att jaga rotskott sedan","Köp namngivna sorter från plantskola - vilda havtorn ger ofta små, sura bär som sitter extremt hårt"],indoorWeeks:null},seedSaving:{difficulty:"Medel",type:"Vegetativ förökning",biennial:!1,description:"Havtorn förökas enklast vegetativt med rotskott eller vedartade sticklingar. Fröförökning fungerar men ger en blandning av han- och honplantor och du vet inte könet förrän busken blommar efter 3-5 år.",steps:["Rotskott (enklast): gräv försiktigt upp rotskott med egna rötter, helst på hösten","Kontrollera att rotskottet har gott om fina rötter innan du skiljer det från moderplantan","Plantera rotskottet direkt på sin nya plats eller i kruka","Vedartade sticklingar: klipp 15-20 cm bitar av årets mogna ved i november","Doppa i rotningshormon och sätt i sandblandad jord utomhus","Sticklingar rotar sig under vintern och kan planteras ut nästa höst","OBS: Rotskott och sticklingar ger kloner av moderplantan - du vet alltså könet!"],isolation:"Vegetativ förökning ger exakta kloner. Fröplantor ger 50/50 han/hon men könet syns först vid blomning.",storageYears:"Ej tillämpligt (vegetativ förökning)",tip:"Rotskott är den absolut enklaste förökningsmetoden - havtorn producerar dem i överflöd! Gratis plantor som dyker upp av sig själva. Gräv upp dem med rötter och ge bort till vänner eller starta en ny häck."},storage:{shelfLife:"1-2 veckor (färska i kyl)",methods:[{method:"Frysning",icon:"snowflake",duration:"12+ månader",description:"Bästa och vanligaste metoden. Frys hela grenar eller lösa bär. Frysta bär är lättare att hantera och bevarar all näring. Perfekt som bas för juice, smoothies och sylt året runt.",best:!0},{method:"Juice/must",icon:"storage",duration:"6-12 månader (pastöriserad)",description:"Havtornsjuice är flytande guld - intensivt syrlig och fullpackad med C-vitamin. Mixa bären, sila bort fruktköttet, blanda med lite honung. Späd med vatten vid servering.",best:!1},{method:"Marmelad/sylt",icon:"storage",duration:"1+ år",description:"Havtornsmarmelad har en unik, tropisk smak som påminner om passionsfrukt. Koka med socker (och gärna äpple för pektin). Fantastisk på frukostmackan.",best:!1},{method:"Torkning",icon:"sun",duration:"6+ månader",description:"Torka i ugn på 40-50 grader (låg temperatur för att bevara vitaminerna). Torkade bär kan malas till pulver som kryddas i smoothies, yoghurt och bakning.",best:!1},{method:"Olja",icon:"storage",duration:"6-12 månader",description:"Havtornsolja pressas ur fruktköttet och fröna. Extremt nyttig med omega-fettsyror. Används både i mat och hudvård. Kräver speciell press men resultatet är unikt.",best:!1}],tips:["Frys bären på grenarna - det gör det mycket enklare att lossa dem efteråt","Havtornsjuice fläckar! Kläder, händer, bänkskivor - allt blir orange. Jobba med förkläde och handskar","Blanda havtornsjuice med honung och varmt vatten för en fantastisk vinterdryck full av C-vitamin","Havtornspulver (torkade, malda bär) är ett superenkelt sätt att få i sig nyttigheterna dagligen","Bären blir mildare och sötare efter första frosten - gotländsk tradition är att skörda sent"]},harvestCalc:{minPerSqm:.5,maxPerSqm:2,unit:"kg"},pruning:{label:"Beskärning",types:{maintenance:{name:"Underhållsbeskärning",when:"Sen vinter (feb-mars) eller direkt efter skörd",description:"Havtorn bär på 2-3 år gammal ved. Busken kan bli stor och vild utan beskärning men producerar ändå bra. Regelbunden beskärning håller storleken hanterbar och gör skörden lättare. Havtorn tål att man klipper av bärbärande grenar vid skörd - det är en form av beskärning i sig.",steps:["Ta bort döda, skadade och korsande grenar","Klipp bort de äldsta grenarna (4+ år) vid basen - de bär sämre","Håll busken öppen nog att du kan komma åt bären (det tackar du dig själv för vid skörd)","Korta långa skott för att hålla busken kompakt - annars blir hon 3-5 meter hög","Lämna unga sidoskott - det är där nästa års bär kommer","GLÖM INTE hanplantan - den behöver också beskäras för att hålla formen"]},rejuvenation:{name:"Föryngringsbeskärning",when:"Sen vinter",description:"En gammal, förvuxen havtornsbuske kan klippas ner hårt. Hon skjuter nya skott från stambasen och etablerade rötter. Det tar 2-3 år att bygga upp ny bärproduktion, men det är bättre än att kämpa med en ohanterlig jätte.",steps:["Klipp ner hela busken till 30-50 cm höjd","Havtorn skjuter kraftiga nya skott från basen och rothalsen","Välj ut 5-7 starka skott och ta bort resten","Första bären på de nya skotten kommer efter 2-3 år","Pass på att ta bort oönskade rotskott som dyker upp efter den hårda beskärningen"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Rotskott",description:"Det enklaste sättet! Havtorn producerar rotskott i överflöd - gräv försiktigt upp dem med egna rötter och plantera om direkt. Bäst på hösten. Du vet dessutom könet eftersom de är kloner av moderplantan.",icon:"seedling"},{method:"Vedartade sticklingar",description:"Klipp 15-20 cm bitar av årets mogna skott i november. Doppa i rotningshormon och sätt i sandig jord. Rotar sig under vintern. Lägre lyckandefrekvens än rotskott men fungerar.",icon:"scissors"},{method:"Frösådd",description:"Möjligt men opraktiskt - du vet inte könet på plantorna förrän de blommar efter 3-5 år. Fröna behöver kallstratifiering (2-3 månader i kyl). Ger stor genetisk variation.",icon:"seedling"}],tip:"Rotskott är den överlägset enklaste metoden. Havtorn producerar så många att problemet oftast är att bli av med dem - inte att få tag i dem. Ge bort till grannar och odlarkompisar!"}},aa=Object.freeze(Object.defineProperty({__proto__:null,havtorn:K},Symbol.toStringTag,{value:"Module"})),P={name:"Honungsbär",icon:"honungsbar",category:"bär",family:"Kaprifolväxter",familyLatin:"Caprifoliaceae",perennial:!0,lifespan:"30-50+ år",difficulty:"Enkel",difficultyWhy:"Honungsbär (sibiriskt blåbär) är otroligt härdigt och lättsköt. Extremt kalltåligt, minimala skötselkrav och praktiskt taget fritt från sjukdomar. Enda utmaningen? Du MÅSTE ha minst 2 sorter för korspollinering, annars blir det inga bär alls.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:null},days:"Skörd år 2-3, full skörd år 4-5",spacing:"120-150 cm",rowSpacing:"200-250 cm",depth:"Samma djup som i krukan",ph:{min:5.5,max:7,ideal:6},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Honungsbär trivs i full sol men klarar halvskugga bättre än de flesta bärväxter. I full sol blir bären fler och sötare. I halvskugga lever busken längre och stressar mindre i värme. Perfekt för den lite skuggigare hörnan."},temperature:{min:-45,max:30,ideal:"15-22°C",detail:"EXTREMT härdig - tål ner till -45°C! En av de absolut härdigaste bärväxterna i världen. Kommer från Sibirien, Kamtjatka och norra Japan. Blommar tidigt (april-maj) men blommorna tål frost ner till -7°C. Trivs bäst i svalt klimat."},wind:{level:"Tålig",detail:"Kompakt, stabil buske som klarar vind bra. Viktigare med vindskydd under blomningen - pollinatörerna behöver kunna jobba i lugn och ro för korspollinering."}},watering:{need:"Medel",icon:"water",summary:"Honungsbär har måttliga vattenbehov. Jämn fukt under blomning och bärmognad ger bäst resultat. Etablerade buskar klarar en del torka men tappar skörd.",phases:[{phase:"Vår (blomning)",need:"Medel",tip:"Blomningen sker tidigt (april-maj). Jämn fukt nu ger bättre fruktsättning. Honungsbär vaknar bland de första i trädgården."},{phase:"Bärmognad (maj-juni)",need:"Medel-Hög",tip:"Bären mognar tidigt! Jämn fukt under mognad ger större och saftigare bär. Ojämn vattning kan ge att bären faller av i förtid."},{phase:"Sommar (efter skörd)",need:"Låg-Medel",tip:"Minska vattningen efter skörd. Busken behöver inte mycket uppmärksamhet resten av säsongen."},{phase:"Höst/vinter",need:"Låg",tip:"Busken klarar sig själv. Minimalt vattenbehov."}],mistakes:["Vattensjuk jord - honungsbär vill ha fukt men inte stående vatten","Glömmer nyplanterade buskar första sommaren","Torka under blomning - ger dålig fruktsättning trots god pollinering"],tip:"Mulcha med bark eller gräsklipp för jämn fukt. Honungsbär är inte krävande - regelbunden vattning vid torka räcker gott."},soil:"Honungsbär trivs i de flesta jordtyper och är flexibel. Föredrar humusrik, fukthållande jord med god dränering. Klarar både lerjord och sandjord - bara inte extremt vattensjuk mark.",soilTips:["Blanda in kompost vid plantering för en bra start","Klarar de flesta jordtyper - remarkabelt flexibel","Svagt surt till neutralt pH (5.5-7.0) - funkar i nästan alla svenska trädgårdar","Mulcha med bark eller gräsklipp årligen","God dränering viktigt - inte stående vatten"],timeline:{1:[{phase:"Plantering",months:"Okt-nov eller april",icon:"seedling"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Skörd",months:"Juni-juli",icon:"harvest"},{phase:"Beskärning",months:"Sen vinter (mars)",icon:"scissors"},{phase:"Vintervila",months:"Nov-april",icon:"snowflake"}],4:[{phase:"Plantering",months:"Okt eller april",icon:"seedling"},{phase:"Blomning",months:"April-maj",icon:"bloom"},{phase:"Skörd",months:"Juni",icon:"harvest"},{phase:"Beskärning",months:"Sen vinter (feb-mars)",icon:"scissors"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],6:[{phase:"Plantering",months:"Okt-nov eller mars-april",icon:"seedling"},{phase:"Blomning",months:"April",icon:"bloom"},{phase:"Skörd",months:"Maj-juni",icon:"harvest"},{phase:"Beskärning",months:"Sen vinter (feb-mars)",icon:"scissors"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:3,P:2,K:2},{month:"Maj",N:4,P:3,K:3},{month:"Jun",N:3,P:3,K:4},{month:"Jul",N:2,P:2,K:3},{month:"Aug",N:1,P:1,K:2},{month:"Sep",N:1,P:1,K:1}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge kompost eller allroundgödsel runt busken. Honungsbär är inte speciellt hungrig men uppskattar en vårstart."},{timing:"Efter skörd (juni)",tip:"En lätt giva gödsel efter skörd hjälper busken återhämta sig och lägga grunden för nästa års blommor."},{timing:"Höst",tip:"Mulcha med kompost eller löv. Ingen aktiv gödsling behövs."}],companions:{good:[{name:"Andra honungsbärssorter",icon:"berry",why:"ABSOLUT NÖDVÄNDIGT! Honungsbär är helt beroende av korspollinering. Utan minst 2 olika sorter - inga bär."},{id:"ringblomma",name:"Ringblomma",icon:"flower",why:"Lockar pollinatörer. Honungsbär blommar tidigt när pollinerarna precis vaknat - alla hjälper."},{name:"Vårlökar (krokus, scilla)",icon:"flower",why:"Tidiga vårlökar lockar bin och humlor just när honungsbäret blommar. Perfekt timing!"}],bad:[{name:"Inga kända dåliga grannar",icon:"vegetable",why:"Honungsbär är remarkabelt problemfri och samsas bra med det mesta. Inga kända negativa interaktioner."}]},rotation:{avoid:[{name:"Honungsbär (Lonicera caerulea)"}],avoidWhy:"Undvik att plantera på samma plats för att minska risk för jordburna sjukdomar. Vänta 3-4 år.",goodBefore:[{name:"Solig, öppen plats"},{name:"Gräsmatta"}],goodBeforeWhy:"Frisk mark utan tidigare honungsbärsodling. Inte kräsen.",goodAfter:[{name:"De flesta grödor"}],goodAfterWhy:"Honungsbär lämnar jorden i gott skick. Inga speciella restriktioner."},varieties:[{name:"Indigo Gem",zones:[1,2,3,4,5,6,7],note:"Kanadensisk sort (University of Saskatchewan), en av de bästa! Stora, avlånga bär med utmärkt smak - söt med balanserad syra. Kompakt buske. Bra pollinatör för Blue Velvet."},{name:"Blue Velvet",zones:[1,2,3,4,5,6],note:"Stora, söta bär. Kompakt buske (120-150 cm). Tidig mognad. God smak med lite syrlighet. Pollinera med Indigo Gem eller Bakczarskaja."},{name:"Bakczarskaja",zones:[1,2,3,4,5,6,7,8],note:"Rysk sort (Bakczarskaja Jubilejnaja), extremt härdig. Stora bär med god smak. Bland de tidigast mognande - bär redan i maj i södra Sverige!"},{name:"Duet",zones:[1,2,3,4,5,6,7],note:"Polsk sort med god skörd. Kompakt buske. Trots namnet behöver du fortfarande en annan sort för korspollinering!"}],problems:[{name:"Fåglar",symptom:"Bären försvinner. Honungsbär mognar tidigt (maj-juni) när fåglarna är som hungrigast efter vintern.",fix:"Nät är det enda pålitliga skyddet. Fåglarna älskar honungsbär och de mognar just när det finns minst annan mat. Sätt upp nät i god tid!"},{name:"Bärfall (fysiologiskt)",symptom:"Bären faller av busken innan de hinner mogna. Busken ser frisk ut.",fix:"Oftast orsakat av dålig pollinering (för få sorter!) eller torka under bärutveckling. Se till att du har minst 2 olika sorter och håll jämn fukt."},{name:"Mjöldagg (sällsynt)",symptom:"Vitt belägg på bladen sent på säsongen. Mycket ovanligt på honungsbär.",fix:"God luftcirkulation. Sällan allvarligt - honungsbär är remarkabelt sjukdomsresistent."}],goodToKnow:[{icon:"warning",title:"Du MÅSTE ha 2 sorter!",text:"Honungsbär är HELT beroende av korspollinering mellan olika sorter. Med bara en sort - eller två plantor av samma sort - blir det noll bär. Köp alltid minst 2 namngivna sorter som pollinerar varandra. Det är det viktigaste du behöver veta.",severity:"warning"},{icon:"tip",title:"Säsongens FÖRSTA bär",text:"Honungsbär mognar otroligt tidigt - redan i maj-juni! Det gör dem till de absolut första bären du kan skörda i trädgården, långt före jordgubbar och hallon. Perfekt för den som inte kan vänta på bärsäsongen.",severity:"tip"},{icon:"tip",title:"Sibirisk superkraft",text:"Honungsbär (Lonicera caerulea) kommer från Sibirien, Kamtjatka och norra Japan. De tål ner till -45°C - bland de härdigaste bärväxterna i världen. Blommorna tål frost till -7°C. Perfekt för norrlandsodlare!",severity:"tip"},{icon:"tip",title:"Smaken? Tänk blåbär med twist",text:"Smaken påminner om blåbär med en ton av vindruva och kiwi. Söt-syrlig och unik. Bären ser ut som avlånga blåbär med en blågrå daggbeläggning. Godast direkt från busken, solvarma.",severity:"tip"},{icon:"warning",title:"Bären faller lätt",text:"Mogna honungsbär lossnar och faller lätt från busken. Lägg gärna en duk under vid skörd. Vissa sorter (Berry Blue) sitter fastare. Skörda ofta - gärna varannan dag under mognadsperioden.",severity:"warning"},{icon:"tip",title:"Extremt långlivad",text:"Honungsbärsbuskar kan leva 30-50+ år och producera bär under hela sin livstid. Det är en riktig långtidsinvestering. Med minimal skötsel ger hon dig bär i decennier.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Honungsbär planteras som krukodlade plantor eller barrotade buskar. Höstplantering rekommenderas. Köp ALLTID minst 2 olika namngivna sorter för korspollinering!",steps:["Gräv en grop dubbelt så bred som rotklumpen","Blanda in kompost i jorden","Plantera i samma djup som i krukan","Vattna rikligt","Mulcha med bark eller gräsklipp","Plantera den andra sorten inom 3-4 meters avstånd för pollinering"],tips:["Köp ALLTID 2 olika sorter - utan korspollinering blir det inga bär!","Höstplantering (okt-nov) ger bäst resultat","Placera sorternas inom 3-4 meter från varandra - pollinatörerna ska kunna nå båda","Första ordentliga skörden år 3, full skörd från år 4-5"],indoorWeeks:null},seedSaving:{difficulty:"Medel",type:"Vegetativ förökning",biennial:!1,description:"Honungsbär förökas med halvmogna sticklingar eller vedartade sticklingar. Rotning kan vara lite trögare än hos vinbär men lyckas med tålamod.",steps:["Halvmogna sticklingar (juni-juli): klipp 10-15 cm av halvmogna skott","Ta bort nedre bladen, behåll 2-3 blad i toppen","Doppa i rotningshormon","Sätt i fuktig blandning av torv och perlit under fukthuv","Rotning tar 4-8 veckor","Vedartade sticklingar (november): 20 cm av årets mogna ved, sätt utomhus"],isolation:"Vegetativ förökning - kloner av moderplantan.",storageYears:"Ej tillämpligt",tip:"Halvmogna sticklingar i juni-juli med rotningshormon ger bäst resultat. Vedartade sticklingar på hösten fungerar men med lägre lyckandefrekvens. Köp hellre nya plantor om du bara vill ha ett par till."},storage:{shelfLife:"5-7 dagar (färska)",methods:[{method:"Frysning",icon:"snowflake",duration:"12+ månader",description:"Bästa sättet att bevara. Frys i ett lager på plåt, flytta sedan till påse. Frysta honungsbär funkar direkt i smoothies, pannkakor och bakning. Behåller smak och näring perfekt.",best:!0},{method:"Sylt och mos",icon:"storage",duration:"1+ år",description:"Honungsbärssylt har en unik, blåbärslik smak med tropisk underton. Koka med socker och citronjuice. Otroligt god och annorlunda - gör gärna extra!",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"5-7 dagar",description:"Håller sig hyfsat i kylen. Förvara i skål med hushållspapper. Tvätta inte förrän du äter.",best:!1},{method:"Torkning",icon:"sun",duration:"6+ månader",description:"Torka i ugn på 50°C i 8-12 timmar. Blir söta och intensiva. Bra i müsli och bakning.",best:!1},{method:"Saft",icon:"storage",duration:"1+ år",description:"Vacker blåviolett saft med unik smak. Safta med ångsaftare eller koka och sila.",best:!1}],tips:["Skörda försiktigt - bären är mjuka och märks lätt","Lägg en duk under busken och skaka försiktigt - mogna bär faller av","Honungsbär mognar ojämnt - plocka varannan dag under 1-2 veckor","Smaken är bäst direkt från busken, solvarma - spara lite till direktätning!"]},harvestCalc:{minPerSqm:.5,maxPerSqm:2,unit:"kg"},pruning:{label:"Beskärning",types:{maintenance:{name:"Underhållsbeskärning",when:"Sen vinter (feb-mars) ELLER direkt efter skörd (juni)",description:"Honungsbär kräver minimal beskärning de första 5-6 åren - låt busken bygga upp sig i fred. Från år 6-7: börja gallra de äldsta grenarna för att hålla busken produktiv. Bär bäst på 2-5 år gammal ved.",steps:["De första 5 åren: minimal beskärning, bara ta bort döda och skadade grenar","Från år 6: ta bort 2-3 av de äldsta grenarna vid basen årligen","Gallra svaga och korsande skott i mitten","Sikta på 10-15 grenar totalt, blandade åldrar","Håll buskens mitt öppen för ljus och luft"]},rejuvenation:{name:"Föryngringsbeskärning",when:"Sen vinter",description:"Gammal, förväxt buske? Honungsbär tål föryngring men gör det stegvis - ta bort en tredjedel av de äldsta grenarna varje år i tre år. Undvik att klippa ner allt på en gång.",steps:["År 1: Ta bort en tredjedel av de äldsta, grövsta grenarna vid basen","År 2: Ta bort ytterligare en tredjedel av de gamla grenarna","År 3: Ta bort sista tredjedelen","Gödsla med kompost efter varje omgång","Busken behåller viss skörd under hela processen"]}}},propagation:{difficulty:"Medel",methods:[{method:"Halvmogna sticklingar",description:"Klipp 10-15 cm av halvmogna skott i juni-juli. Doppa i rotningshormon, sätt i fuktig torv/perlit under fukthuv. Rotning tar 4-8 veckor. Bästa metoden men kräver lite tålamod.",icon:"scissors"},{method:"Vedartade sticklingar",description:"Klipp 20 cm av årets mogna skott i november. Sätt i fuktig jord utomhus. Lägre lyckandefrekvens men enklare att utföra.",icon:"scissors"},{method:"Nedböjning",description:"Böj ner en låg gren och fäst mot marken med bygel. Täck med jord. Klipp loss nästa år. Säkrare än sticklingar men kräver en låg gren.",icon:"seedling"}],tip:"Halvmogna sticklingar i juni-juli med rotningshormon ger bäst resultat. Om du bara vill ha 1-2 nya plantor är det enklare att köpa - honungsbär är billigare nu när de blivit populärare."}},ea=Object.freeze(Object.defineProperty({__proto__:null,honungsbar:P},Symbol.toStringTag,{value:"Module"})),B={name:"Jordärtskocka",icon:"jordartskocka",family:"Korgblommiga",familyLatin:"Asteraceae",perennial:!0,lifespan:"Flerårig (odlas oftast som ettårig)",difficulty:"Enkel",difficultyWhy:"Extremt härdig och anspråkslös. Sätts som potatis men kräver ännu mindre omvårdnad. Största utmaningen är att STOPPA henne från att ta över hela trädgården.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:null},days:"120-150",spacing:"30-40 cm",rowSpacing:"60-80 cm",depth:"10-15 cm",ph:{min:6,max:7.5,ideal:7},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Vill ha full sol för bäst knölskörd, men klarar halvskugga. I skugga blir hon mest blast och blommor - vackert men inte lika produktivt."},temperature:{min:-20,max:35,ideal:"18-25°C",detail:"Knölarna överlever ner till -20°C i marken - hon är praktiskt taget oförstörbar. Blasten fryser vid frost men knölarna sover gott under jorden."},wind:{level:"Skyddat",detail:"Blir 2-3 meter hög! I blåsiga lägen riskerar hon att knäckas eller luta sig som ett berusat torn. Sätt henne intill ett staket eller mur, eller stötta med bambukäppar."}},watering:{need:"Låg",icon:"water",summary:"Jordärtskockan är en riktig överlevare som klarar sig på remarkabelt lite vatten. Hon har djupa rötter som hittar fukt långt ner. Bara i riktigt torra perioder behöver du hjälpa till.",phases:[{phase:"Sättning till uppkomst",need:"Medel",tip:"Vattna vid sättning och håll jorden lätt fuktig tills hon kommit upp. Efter det klarar hon sig i princip själv."},{phase:"Tillväxt",need:"Låg",tip:"Behöver sällan vattning om det regnar någorlunda normalt. Vid extrem torka (2+ veckor utan regn), ge en ordentlig genomvattning."},{phase:"Blomning",need:"Låg-Medel",tip:"Lite extra vatten under blomning kan ge större knölar, men hon klarar sig utan. Stressa inte."},{phase:"Höst (knölmognad)",need:"Låg",tip:"Sluta vattna. Blasten vissnar naturligt efter första frosten och knölarna mognar klart i jorden."}],mistakes:["Vattna för mycket - jordärtskockan trivs inte i blöt jord, knölarna kan ruttna","Vattna ovanifrån sent på kvällen - kan ge mjöldagg på de stora bladen"],tip:"Jordärtskockan är den perfekta grödan för den som glömmer att vattna. Hon klarar sig nästan alltid själv."},soil:"Trivs i nästan allt! Föredrar lös, sandblandad jord men växer glatt i lera, sand och allt däremellan. Undvik bara stående vatten.",soilTips:["Lös jord ger finare, lättskördade knölar - i tung lera blir de knotiga och svårgrävda","Blanda in sand eller kompost i tung lera för att luckra upp","Behöver ingen speciell jordförbättring - hon är tacksam av sig"],timeline:{1:[{phase:"Sätt knölar",months:"Apr",icon:"seed"},{phase:"Uppkomst",months:"Maj",icon:"seedling"},{phase:"Kraftig tillväxt",months:"Jun-Jul",icon:"leaf"},{phase:"Blomning",months:"Aug-Sep",icon:"flower"},{phase:"Skörd",months:"Okt-Mar",icon:"harvest"}],4:[{phase:"Sätt knölar",months:"Apr-Maj",icon:"seed"},{phase:"Uppkomst",months:"Maj-Jun",icon:"seedling"},{phase:"Kraftig tillväxt",months:"Jun-Aug",icon:"leaf"},{phase:"Blomning",months:"Aug-Sep",icon:"flower"},{phase:"Skörd",months:"Okt-Mar",icon:"harvest"}],6:[{phase:"Sätt knölar",months:"Maj",icon:"seed"},{phase:"Uppkomst",months:"Jun",icon:"seedling"},{phase:"Kraftig tillväxt",months:"Jul-Aug",icon:"leaf"},{phase:"Blomning",months:"Sep",icon:"flower"},{phase:"Skörd",months:"Okt-Mar",icon:"harvest"}]},nutritionData:[{month:"Apr",N:10,P:10,K:10,label:"Sättning"},{month:"Maj",N:30,P:20,K:15,label:"Uppkomst"},{month:"Jun",N:60,P:35,K:30,label:"Blasttillväxt"},{month:"Jul",N:70,P:45,K:40,label:"Kraftig tillväxt"},{month:"Aug",N:50,P:55,K:50,label:"Blomning"},{month:"Sep",N:20,P:60,K:70,label:"Knölbildning"},{month:"Okt",N:5,P:30,K:50,label:"Mognad"}],nutritionTips:[{timing:"Före sättning",tip:"En skopa kompost i hålet räcker gott. Jordärtskockan är inte kräsen - hon hittar näring var hon än står."},{timing:"Tillväxt (juni-juli)",tip:"Om blasten ser blek ut, ge lite flytande gödsel. Men oftast behövs det inte - hon är en fantastisk självförsörjare."},{timing:"Blomning (augusti)",tip:"Kalium gynnar knölbildningen. En näve vedaska runt plantorna gör nytta om du vill maximera skörden."},{timing:"Generellt",tip:"Övergödsla inte! För mycket kväve ger en jättelik buske med små knölar. Hon vill ha det magert."}],companions:{good:[{name:"Solros",icon:"flower",why:"Nära släkting (Helianthus) - trivs i samma förhållanden. Fina tillsammans längs ett staket."},{id:"sockermajs",name:"Majs",icon:"vegetable",why:"Likartade behov av sol och utrymme. Båda blir höga utan att skugga varandra nämnvärt."},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Fixerar kväve som jordärtskockan drar nytta av. Låg planta som inte konkurrerar om ljuset."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Konkurrerar om samma markutrymme och näring. Knölarna trasslar ihop sig och förvirrar vid skörd."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Jordärtskockan skuggar tomaterna totalt med sina 2-3 meter. Ingen chans för stackars tomatplantan."}]},rotation:{avoid:[{name:"Solros"},{name:"Jordärtskocka"}],avoidWhy:"Samma familj (korgblommiga). Jordärtskockan lämnar dessutom alltid kvar knölar i jorden som dyker upp året efter - räkna med frivilliga plantor.",goodBefore:[{name:"Grönsaker som gillar lös jord"},{id:"potatis",name:"Potatis"},{id:"morot",name:"Morötter"}],goodBeforeWhy:"Jordärtskockans djupa rötter luckrar jorden fantastiskt. Perfekt föregångare till rotgrönsaker.",goodAfter:[{id:"bondbona",name:"Bondböna"},{id:"artor",name:"Ärtor"},{name:"Baljväxter"}],goodAfterWhy:"Baljväxter återställer kvävet som jordärtskockan tagit. Dessutom fixerar de kväve som gynnar eventuella kvarglömda knölar."},varieties:[{name:"Fuseau",zones:[1,2,3,4,5,6,7],note:"Slät och avlång fransk sort - mycket lättare att skala än de knotiga sorterna. Mild, nötaktig smak."},{name:"Bianka",zones:[1,2,3,4,5,6,7,8],note:"Vit knöl. Extremt härdig - klarar även zon 8. Bra avkastning. Blomsterlandet (Säve Plantskola)."},{name:"Rema",zones:[1,2,3,4,5,6,7],note:"Sen tysk sort med jämna knölar och god smak. Pålitlig och lättskördad. Larsviken."}],problems:[{name:"Sork och mullvad",symptom:"Knölarna försvinner eller gnags sönder under jorden. Gångar i jorden nära plantorna.",fix:"Sätt i upphöjd bädd med nätbotten (hönsnät). Eller odla i stor kruka/tunna. Fällor vid behov. Sorkar ÄLSKAR jordärtskockor."},{name:"Mjöldagg",symptom:"Vitt, mjölaktigt belägg på bladen, oftast sent på säsongen.",fix:"Sällan ett allvarligt problem - knölarna påverkas inte. God luftcirkulation och lagom avstånd mellan plantorna förebygger."},{name:"Stormskador",symptom:"Stjälkarna knäcks eller lutar kraftigt efter hård vind.",fix:"Stötta med bambukäppar eller odla intill staket/mur. Kan toppas (klippas av på 1.5 m) för att minska vindytan - minskar dock skörden lite."}],goodToKnow:[{icon:"warning",title:"SPRIDER SIG AGGRESSIVT",text:"Varje liten knölbit som blir kvar i jorden ger nya plantor nästa år. Och året efter det. Och efter det. Hon är praktiskt taget omöjlig att bli av med när hon väl etablerat sig. Plantera ALLTID med avgränsning: nedgrävd barriär (minst 40 cm djup), stor kruka/tunna, eller ge henne ett eget hörn av trädgården som hon får äga.",severity:"warning"},{icon:"warning",title:"Gasvarning!",text:"Jordärtskockan innehåller inulin istället för stärkelse - fantastiskt för diabetiker och tarmfloran, men ger rejäl gasbildning de första gångerna man äter den. Börja med små portioner och öka gradvis. Din mage vänjer sig efter ett par veckor.",severity:"warning"},{icon:"leaf",title:"Den fattige mannens potatis",text:'Historiskt viktig gröda som räddade många under svåra tider. Kallades "den fattige mannens potatis" eftersom hon växer var som helst, kräver noll omvårdnad och ger enorma skördar. Innehåller inulin istället för stärkelse - bra för blodsockret.',severity:"tip"},{icon:"harvest",title:"Skörda hela vintern!",text:"Till skillnad från potatis kan knölarna ligga kvar i marken hela vintern och grävas upp vid behov - de tål frost ner till -20°C. Täck med ett lager löv eller halm så är jorden lättare att gräva i. Fryser marken djupt, gräv upp ett lager i förväg.",severity:"tip"},{icon:"leaf",title:"Vacker vindskydd",text:"Med sina 2-3 meter och vackra gula solrosliknande blommor fungerar jordärtskockan utmärkt som vindskydd, häck eller skärm i köksgrönsakslandet. Praktisk OCH dekorativ.",severity:"tip"},{icon:"harvest",title:"Perfekt för odlingslata",text:"Sätt ner knölarna på våren, gå därifrån, kom tillbaka på hösten och gräv upp middagen. Ingen kupning, ingen gallring, minimal vattning. Finns det en enklare gröda? Nej.",severity:"tip"}],sowing:{method:"direct",label:"Sättknölar",description:"Jordärtskocka odlas från knölar - precis som potatis men ännu enklare. Köp sättknölar eller spara från förra årets skörd. Ingen förgroning behövs, bara ner i jorden och vänta.",steps:["Välj en plats med avgränsning - nedgrävd barriär, stor kruka eller ett eget hörn (hon KOMMER sprida sig)","Luckra jorden och blanda eventuellt in lite kompost","Gräv hål eller fåra 10-15 cm djupt","Lägg knölarna med 30-40 cm mellanrum, groddarna (ögonen) uppåt","Täck med jord och vattna lätt","Vänta - hon dyker upp efter 2-3 veckor","Stötta eventuellt med käppar när hon passerar metern"],tips:["Köp knölar i mars-april eller spara från förra årets skörd - det fungerar lika bra","Varje knöl som är större än en valnöt kan användas som sättknöl","I norr (zon 5+): sätt lite senare när marken verkligen tinat - hon kommer ikapp ändå","Toppning (klipp av på 1-1.5 m) ger kompaktare plantor men lite mindre skörd"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Jordärtskockan förökas vegetativt - varje knöl du sparar blir en ny planta. Det finns inget enklare. Spara knölar i marken eller gräv upp och lagra svalt.",steps:["Vid skörd: spara en handfull fina, medelstora knölar","Alternativ 1: Lämna dem kvar i marken (de klarar vintern)","Alternativ 2: Gräv upp och lagra i fuktig sand i jordkällare eller kylskåp","På våren: sätt de sparade knölarna på ny plats (eller samma, hon bryr sig inte)","Varje knöl ger en ny planta som producerar 1-3 kg knölar"],isolation:"Vegetativ förökning - ingen korspollinering att tänka på. Varje knöl är en genetisk klon.",storageYears:"1 år (men hon sparar sig själv i marken!)",tip:"Det enklaste fröbesparandet som finns - lämna bara kvar några knölar i jorden. Problem: hon sparar sig själv lite för bra. Se till att gräva upp ALLA knölar om du vill flytta eller avsluta odlingen."},storage:{shelfLife:"Hela vintern (i marken)",methods:[{method:"Kvar i marken",icon:"leaf",duration:"Oktober-mars (hela vintern)",description:"Det absolut bästa sättet! Knölarna tål frost ner till -20°C och håller sig fräscha i jorden. Täck med löv eller halm så att marken inte fryser stenhårt - då är det lättare att gräva. Gräv upp vid behov, en portion i taget.",best:!0},{method:"Jordkällare / sandlåda",icon:"cellar",duration:"2-4 månader",description:"Gräv upp och lagra i fuktig sand eller torv. 2-4°C och hög luftfuktighet. Knölarna skrumpnar lättare än potatis eftersom de saknar tjockt skal - fuktig sand är nyckeln.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"1-2 veckor",description:"Nödlösning. Lägg i plastpåse med hål - de torkar ut snabbt annars. Bäst att gräva upp färskt från trädgården istället.",best:!1}],tips:["Gräv hellre upp små portioner ofta än hela skörden på en gång","Knölarna har tunt skal och torkar ut snabbt - lagra alltid fuktigt","Markera var du planterat med en pinne så du hittar dem under snön","Skrumpna knölar går utmärkt att koka soppa på - de smakar lika bra"]},harvestCalc:{minPerSqm:2,maxPerSqm:10,unit:"kg"}},ta=Object.freeze(Object.defineProperty({__proto__:null,jordartskocka:B},Symbol.toStringTag,{value:"Module"})),T={name:"Jordgubbar",icon:"jordgubbar",category:"bär",family:"Rosväxter",familyLatin:"Rosaceae",perennial:!0,lifespan:"3-5 år (byt sedan ut plantorna)",difficulty:"Enkel",difficultyWhy:"Jordgubben är generös och tacksam - ge henne sol, vatten och lite kärlek så bjuder hon på skördefest redan första sommaren. Perfekt för nybörjare och barn!",zones:{outdoor:[1,2,3,4,5,6,7],indoor:null,greenhouse:null},days:"60-90",spacing:"30-40 cm",rowSpacing:"60-80 cm",depth:"Kronans nivå",depthNote:"Hjärtpunkten precis i markytan",ph:{min:5.5,max:6.5,ideal:6},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Jordgubben vill ha minst 8 timmars sol om dagen - ju mer sol, desto sötare bär. Hon kan klara lite eftermiddagsskugga i södra Sverige, men i norr behöver hon allt solljus hon kan få."},temperature:{min:-20,max:30,ideal:"18-24°C",detail:"Härdig ner till -20°C med ordentligt snötäcke eller halmtäckning. Blommar tidigt (maj) och är känslig för sen vårfrost - täck med fiberduk om frost hotar under blomningen!"},wind:{level:"Skyddat",detail:"Jordgubbens blommor är ömtåliga och behöver pollinatörer. Vindskydd förbättrar pollineringen och ger fler perfekt formade bär. Plantera gärna i ett soligt, skyddat läge."}},watering:{need:"Medel-Hög",icon:"water",summary:"Jordgubben är törstig, speciellt under blomning och fruktmognad. Jämn fukt ger stora, saftiga bär - ojämn vattning ger missformade och torra bär.",phases:[{phase:"Vår (tillväxt)",need:"Medel",tip:"Vattna vid torka när de nya bladen kommer. Mulcha med halm för att hålla fukten och hålla bären rena."},{phase:"Blomning (maj-juni)",need:"Hög",tip:"Kritisk period! Vattenstress nu ger missformade bär eller att blommorna faller av. Vattna jämnt men undvik att blöta blommorna."},{phase:"Fruktmognad (juni-juli)",need:"Hög",tip:"Fortsätt vattna regelbundet. Minska lite precis innan skörd - det koncentrerar smaken och minskar risk för mögel."},{phase:"Efter skörd",need:"Medel",tip:"Fortsätt vattna - nu anlägger plantan nästa års blomknoppar. Sluta inte bara för att bären är plockade!"}],mistakes:["Vattnar ovanifrån under mognad - bären möglar och ruttnar","Ojämn vattning under fruktbildning - ger missformade, hårda bär","Slutar vattna efter skörd - plantan behöver fukt för nästa års blomknoppar"],tip:"Dropp-bevattning under halmen är jordgubbsodlarens bästa vän. Bladen och bären hålls torra, marken jämnt fuktig, och mögel-risken halveras."},soil:"Jordgubben vill ha lös, humusrik och väldränerad jord. Hon HATAR stående vatten och kompakt lera. Sandig mylla är drömmen - blanda in rikligt med kompost om du har tung jord.",soilTips:["Blanda in 5-10 liter kompost per löpmeter rad","På lerjord: odla i upphöjd bädd (15-20 cm) eller blanda in sand och kompost",'Mulcha med halm, halmtäcket har gett jordgubben sitt engelska namn "strawberry"',"Undvik mark där det stått potatis, tomater eller hallon senaste 3-4 åren (verticillium-risk)"],timeline:{1:[{phase:"Plantering",months:"Maj-juni",icon:"seedling"},{phase:"Blomning",months:"Juni-juli",icon:"bloom"},{phase:"Skörd",months:"Juli-aug",icon:"harvest"},{phase:"Revklippning",months:"Juli-aug",icon:"scissors"},{phase:"Höststädning",months:"Sept-okt",icon:"scissors"},{phase:"Vintervila",months:"Nov-apr",icon:"snowflake"}],4:[{phase:"Plantering",months:"Maj",icon:"seedling"},{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Skörd",months:"Juni-juli",icon:"harvest"},{phase:"Revklippning",months:"Juni-aug",icon:"scissors"},{phase:"Höststädning",months:"Sept",icon:"scissors"},{phase:"Vintervila",months:"Okt-apr",icon:"snowflake"}],6:[{phase:"Plantering",months:"April-maj",icon:"seedling"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Skörd",months:"Juni-juli",icon:"harvest"},{phase:"Revklippning",months:"Juni-aug",icon:"scissors"},{phase:"Höststädning",months:"Sept",icon:"scissors"},{phase:"Vintervila",months:"Nov-mar",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:4,P:2,K:2},{month:"Maj",N:6,P:4,K:3},{month:"Jun",N:5,P:5,K:7},{month:"Jul",N:3,P:4,K:8},{month:"Aug",N:3,P:3,K:5},{month:"Sep",N:2,P:2,K:3}],nutritionTips:[{timing:"Tidig vår (april)",tip:"Ge kompost eller brunnen gödsel runt plantorna. Jordgubben vaknar hungrig och vill ha en bra start. Undvik färsk gödsel - det bränner rötterna."},{timing:"Blomning (maj-juni)",tip:"En giva kaliumrik gödsel (tomatgödsel fungerar utmärkt) ger fler och sötare bär. Kalium är jordgubbens hemliga vapen."},{timing:"Efter skörd (juli-aug)",tip:"Ge en lätt giva allroundgödsel. Nu anlägger plantan nästa års blomknoppar - bra näring nu betyder bra skörd nästa år."}],companions:{good:[{id:"lok",name:"Lök",icon:"lok",why:"Avskräcker jordgubbskvalster och andra skadedjur med sin starka doft. Klassisk kombination!"},{id:"basilika",name:"Basilika",icon:"basilika",why:"Sägs förstärka smaken på jordgubbarna (ingen vet riktigt varför, men odlare svär på det). Lockar dessutom pollinatörer."},{id:"bondbona",name:"Bondböna",icon:"bondbona",why:"Fixerar kväve i marken som jordgubbarna tacksamt tar del av. Bra förfrukt att plantera jordgubbar efter."}],bad:[{id:"gronkal",name:"Grönkål",icon:"gronkal",why:"Kålväxter konkurrerar om näring och utrymme. Håll dem i varsitt land."},{id:"potatis",name:"Potatis",icon:"potatis",why:"Delar verticillium-svamp med jordgubbar. Plantera aldrig jordgubbar där det stått potatis - vänta minst 3-4 år."}]},rotation:{avoid:[{id:"hallon",name:"Hallon"},{id:"potatis",name:"Potatis"},{id:"tomat",name:"Tomat"},{id:"jordgubbar",name:"Jordgubbar"}],avoidWhy:"Jordgubbar, hallon, potatis och tomater delar verticillium-svamp. Plantera aldrig jordgubbar efter dessa grödor - vänta minst 3-4 år på samma plats.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"lok",name:"Lök"}],goodBeforeWhy:'Baljväxter fixerar kväve och gör jorden rik. Lök "rensar" jorden från skadliga svampar. Perfekta förfrukter!',goodAfter:[{id:"lok",name:"Lök"},{id:"morot",name:"Morot"}],goodAfterWhy:"Efter 3-5 år jordgubbar behöver jorden en paus. Lök och rotfrukter är bra efterföljare som inte delar samma sjukdomar."},varieties:[{name:"Honeoye",zones:[1,2,3,4,5,6],note:"Tidig sort med stora, blanka bär. Riklig skörd och bra smak. En av de mest odlade i Sverige."},{name:"Polka",zones:[1,2,3,4,5,6],note:"Mellansäsong. Fantastiskt söta, mörkröda bär. Frysbar och bra till sylt. Tålig sort."},{name:"Florence",zones:[1,2,3,4,5],note:"Sen sort som förlänger jordgubbssäsongen. Stora, fasta bär med intensiv smak. Sjukdomstolerant."},{name:"Ostara",zones:[1,2,3,4,5,6],note:"Månadsjordgubbe (remonterande) - ger bär från juni till frosten! Mindre bär men otroligt lång säsong."}],problems:[{name:"Gråmögel (Botrytis)",symptom:"Gråludet mögel på mogna bär, speciellt i fuktig väderlek. Bären blir mjuka och ruttnar.",fix:"Mulcha med halm så bären inte ligger mot marken. Plocka bort angripna bär direkt. Vattna vid basen, aldrig ovanifrån. God luftcirkulation genom rätt avstånd."},{name:"Sniglar",symptom:"Gnagmärken och hål i bären, speciellt nära marken. Slemspår.",fix:"Jordgubbens ärkefiende nr 1! Halm-mulch hjälper (sniglar ogillar halm). Snigelstängsel runt bädden. Ölbägare som fällor. Plocka sniglar på kvällen."},{name:"Jordgubbskvalster",symptom:"Skrynkliga, missfärgade blad. Plantorna ser tillplattade ut. Dålig tillväxt.",fix:"Svår att bli av med. Plantera lökkransar runt bädden (lök avskräcker). Byt plats och köp nya friska plantor vid kraftigt angrepp."},{name:"Mjöldagg",symptom:"Vitt, mjölaktigt belägg på bladens ovansida. Bladen rullar sig uppåt.",fix:"Välj resistenta sorter. God luftcirkulation. Undvik kvävegödsling sent på säsongen. Vattna vid basen."}],goodToKnow:[{icon:"warning",title:"Planteringsdjup - livsavgörande",text:"Jordgubbens hjärtpunkt (kronan) MÅSTE sitta precis i markytan. För djupt - ruttnar. För grunt - torkar ut. Det här är det vanligaste nybörjarfelet och det viktigaste att få rätt.",severity:"warning"},{icon:"warning",title:"Byt plantor vart 3-5 år",text:"Jordgubbar tappar kraft med åren. Efter 3-5 år ger plantorna allt sämre skörd. Starta en ny bädd med nya plantor (eller egna revor) på en NY plats. Det är så proffsen gör.",severity:"warning"},{icon:"tip",title:"Revor - gratis nya plantor",text:"Jordgubben skickar ut revor (utlöpare) med småplantor. Tryck ner dem i en kruka med jord vid sidan av moderplantan, klipp av när de rotat sig. Obegränsat med nya plantor - helt gratis!",severity:"tip"},{icon:"tip",title:"Halm-tricket",text:"Lägg halm under och runt plantorna när bären börjar mogna. Det håller bären rena, minskar mögel, avskräcker sniglar och ser dessutom fint ut. Det finns en anledning att det heter jordgubbe på engelska!",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Jordgubbar planteras som färdiga plantor (krukodlade eller barrotade). Plantera på våren eller sensommaren - sensommarplantering ger skörd redan nästa år!",steps:["Gräv en grop som rymmer rotklumpen med god marginal","Blanda in kompost i botten","Placera plantan så att hjärtpunkten (kronan) sitter precis i markytan","Fyll igen och tryck till försiktigt","Vattna rikligt vid plantering","Mulcha med halm runt (inte över) plantan"],tips:["Sensommarplantering (aug) ger starkare plantor och skörd redan nästa sommar","Klipp bort blommor första året vid vårplantering - det ger starkare plantor","Plantera INTE för djupt - kronan i markytan, aldrig under"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Jordgubbar förökas enklast via revor (utlöpare). Varje planta skickar ut långa revor med småplantor som rotar sig av sig själva. Det är naturens eget kloningssystem!",steps:["Välj ut revor från friska, produktiva moderplantor","Tryck ner plantan i en liten kruka med jord bredvid moderplantan","Håll fuktig tills den rotat sig ordentligt (2-3 veckor)","Klipp av revorna från moderplantan","Plantera ut på ny plats"],isolation:"Vegetativ förökning - kloner av moderplantan. Ingen korspollinering relevant.",storageYears:"Ej tillämpligt",tip:"Ta bara revor från friska, kraftiga plantor som gett bra skörd. Sjuka plantor ger sjuka revor - var skoningslös och välj bara det bästa materialet."},storage:{shelfLife:"1-3 dagar (färska)",methods:[{method:"Ät direkt",icon:"harvest",duration:"Samma dag",description:"Jordgubbar är bäst direkt från plantan - solvarm och nyplockat. Inget slår det. Alla andra metoder är kompromisser.",best:!0},{method:"Frysning",icon:"snowflake",duration:"10-12 månader",description:"Frys hela bär på bakplåtspapper, flytta sedan till påse. Perfekt till smoothies, sylt och glass. Tinar du dem blir de mjuka men smaken är kvar.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"1-3 dagar",description:"Lägg OTVÄTTADE bär i ett lager på hushållspapper. Tvätta precis innan du äter. Fukt är fienden - den snabbar på mögel.",best:!1},{method:"Sylt & mos",icon:"storage",duration:"1+ år",description:"Klassisk jordgubbssylt - Sveriges mest älskade sylt. Koka med mindre socker än receptet säger för att behålla bärsmaken.",best:!1}],tips:["Plocka jordgubbar på morgonen när de är svala - de håller sig längre","Tvätta ALDRIG före förvaring - fukt ger mögel inom timmar","Skadade bär sprider mögel blixtsnabbt - sortera bort direkt"]},harvestCalc:{minPerSqm:.3,maxPerSqm:1,unit:"kg"},pruning:{label:"Skötsel",types:{spring:{name:"Vårstädning",when:"Mars-april, när snön smält",description:"Vårens stora uppröjning! Ta bort allt gammalt, vissnat bladmaterial och gammal halm. Ge plantan en fräsch start med luft och ljus till hjärtpunkten.",steps:["Ta bort alla bruna, döda blad nära basen","Rensa bort gammal halm-mulch","Luckra försiktigt runt plantorna (grunt!)","Toppdress med kompost","Lägg ny halm-mulch när marken värmt upp sig"]},summer:{name:"Revklippning",when:"Juni-augusti, löpande",description:"Jordgubben skickar ut revor som tokig under sommaren. Klipp bort alla revor du inte vill ha som nya plantor - de tar energi från bärproduktionen.",steps:["Klipp revor regelbundet under hela sommaren","Spara 2-3 revor per planta om du vill föröka","Tryck ner önskade revor i krukor med jord","Klipp bort alla andra revor vid basen"]},autumn:{name:"Höststädning",when:"September-oktober",description:"Rensa bort sjuka blad och sista revorna. Ge plantan en sista giva näring och förbered för vintern.",steps:["Ta bort sjuka och fläckiga blad","Klipp bort sista revorna","Rensa ogräs runt plantorna","Lägg på vinterskydd (halm eller fiberduk) i nordliga zoner"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Revor (utlöpare)",description:"Det enklaste sättet i hela trädgårdsvärlden! Jordgubben gör allt jobb själv - bara tryck ner revplantorna i jord och klipp av efter 2-3 veckor. Klart.",icon:"seedling"},{method:"Delning",description:"Äldre plantor kan delas på våren. Gräv upp, dela med skarp kniv så varje del har rötter och hjärtpunkt. Plantera om direkt. Fungerar men revor är enklare.",icon:"scissors"}],tip:"Revor är så enkelt att barn kan göra det - och borde! Det är ett fantastiskt trädgårdsprojekt för små odlare. Välj alltid revor från de plantor som gett bäst bär."}},na=Object.freeze(Object.defineProperty({__proto__:null,jordgubbar:T},Symbol.toStringTag,{value:"Module"})),w={name:"Kålrabbi",icon:"vegetable",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Enkel",difficultyWhy:"Kålrabbi är kålfamiljens snällaste medlem - snabb, lättodlad och otroligt förlåtande. Från frö till skörd på bara 50-70 dagar. Perfekt för nybörjare som vill ha snabb belöning.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:[1,2,3,4,5,6,7,8]},days:"50-70",spacing:"15-25 cm",rowSpacing:"30-40 cm",depth:"0.5-1 cm",ph:{min:6,max:7.5,ideal:7},optimalConditions:{sun:{level:"Full sol till halvskugga",icon:"sun",detail:"Trivs bäst i full sol men klarar halvskugga utan problem. I halvskugga tar det några dagar extra, men knölen blir mildare och sötare. Minst 4-5 timmar sol per dag."},temperature:{min:-5,max:25,ideal:"15-20°C",detail:"Kålrabbi är en sval karaktär som trivs bäst i 15-20°C. Tål lätt frost ner till -5°C, vilket gör henne perfekt som tidig vår- och höstskörd. Över 25°C blir hon stressad och vedartad."},wind:{level:"Tålig",detail:"Kålrabbi sitter lågt och stadigt - vinden är inget bekymmer. Knölen växer ovanför marken men profilen är kompakt nog att klara de flesta lägen."}},watering:{need:"Medel",icon:"water",summary:'Kålrabbi vill ha jämn fukt men är inte överdrivet krävande. Ojämn vattning är hennes enda akilleshäl - då spricker knölen eller blir vedartad. Tänk "lagom och stadigt".',phases:[{phase:"Groning (0-2 veckor)",need:"Hög",tip:"Håll jorden jämnt fuktig tills fröna grott. Kålrabbifrön gror på 5-10 dagar vid 15-20°C."},{phase:"Etablering (2-4 veckor)",need:"Medel",tip:"Nyutplanterade plantor behöver daglig vattning i varmt väder tills rötterna tagit sig. Direktsådda plantor klarar sig med mindre."},{phase:"Knölbildning (4-7 veckor)",need:"Medel-Hög",tip:"Kritisk period! Nu sväller knölen och jämn fukt är avgörande. Torka följt av plötslig fukt ger spruckna knölar."},{phase:"Skörd (7-10 veckor)",need:"Medel",tip:"Fortsätt vattna jämnt men minska något. Skörda inte för sent - en övermogen kålrabbi som fått för lite vatten blir träig."}],mistakes:["Ojämn vattning (torrt-blött-torrt) - ger spruckna knölar varje gång","Låta jorden torka ut under knölbildningen - resulterar i vedartade, fiberiga knölar","Övervattna i tung lerjord - rötterna ruttnar och knölen blir vattnig"],tip:"Mulcha med gräsklipp eller halm runt plantorna. Det håller fukten jämn och sparar dig en massa vattning - kålrabbin tackar dig med mjuka, saftiga knölar."},soil:"Lucker, näringsrik jord med bra dränering. Kålrabbi är inte kinkig men trivs allra bäst i kompostrik matjord som inte packar sig.",soilTips:["Blanda in kompost och lite hornmjöl vid plantering - kålrabbi vill ha en bra start","Undvik nygödslad jord med färsk gödsel - det ger mer blast än knöl","Kalka om pH är under 6.0 - alla kålväxter gillar kalkrik jord och det motverkar klumprotsjuka"],timeline:{1:[{phase:"Förodla inomhus",months:"Feb-Mar",icon:"seedling"},{phase:"Direktså/plantera ut",months:"Apr",icon:"leaf"},{phase:"Skörd våromgång",months:"Maj-Jun",icon:"harvest"},{phase:"Direktså sommaromgång",months:"Jun-Jul",icon:"seedling"},{phase:"Skörd sommaromgång",months:"Aug-Sep",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Direktså/plantera ut",months:"Maj",icon:"leaf"},{phase:"Skörd våromgång",months:"Jun-Jul",icon:"harvest"},{phase:"Direktså sommaromgång",months:"Jul",icon:"seedling"},{phase:"Skörd sommaromgång",months:"Aug-Sep",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Plantera ut",months:"Jun",icon:"leaf"},{phase:"Skörd",months:"Jul-Aug",icon:"harvest"}]},nutritionData:[{month:"Apr",N:20,P:15,K:10,label:"Sådd/förodling"},{month:"Maj",N:45,P:25,K:20,label:"Etablering"},{month:"Jun",N:70,P:35,K:35,label:"Knölbildning"},{month:"Jul",N:50,P:30,K:45,label:"Tillväxt/skörd"},{month:"Aug",N:30,P:20,K:35,label:"Höstsådd tillväxt"},{month:"Sep",N:15,P:15,K:25,label:"Sen skörd"}],nutritionTips:[{timing:"Vid sådd/plantering",tip:"Grundgödsla med brunnen kompost. Kålrabbi behöver en bra start men är inte lika hungrig som broccoli eller blomkål."},{timing:"Tre veckor efter etablering",tip:"En giva nässelvatten ger fin skjuts. Kålrabbi bygger knölen nu och vill ha lite extra kväve och kalium."},{timing:"Under knölbildning",tip:"Lite kaliumrik gödsel (vedaska eller alggödsel) ger knölar med bättre smak och textur. Övergödsla inte med kväve - det ger bara blad."}],companions:{good:[{id:"sallat",name:"Sallat",icon:"vegetable",why:"Sallat trivs i kålrabbins lätta skugga och de konkurrerar inte alls - perfekt samodling."},{id:"artor",name:"Ärtor",icon:"vegetable",why:"Ärtorna fixerar kväve som kålrabbin tacksamt tar del av. Bra grannar."},{id:"dill",name:"Dill",icon:"herb",why:"Lockar nyttoinsekter som äter kålfjärilens larver. Kålrabbins personliga livvakt."},{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft förvirrar kålfjärilen - ett klassiskt skydd för alla kålväxter."},{id:"spenat",name:"Spenat",icon:"vegetable",why:"Snabb mellangröda som kan sås mellan kålrabbiraderna. Skördas innan kålrabbin behöver platsen."}],bad:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Båda vill ha mycket näring - de konkurrerar och ingen av dem blir riktigt glad."},{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Jordgubbar hämmas av kålväxter. Håll dem långt ifrån varandra."},{name:"Andra kålväxter",icon:"vegetable",why:"Odla inte kålrabbi intill annan kål - de delar skadedjur och sjukdomar och förstärker problemen."}]},rotation:{avoid:[{id:"gronkal",name:"Grönkål"},{id:"broccoli",name:"Broccoli"},{id:"blomkal",name:"Blomkål"},{name:"Vitkål"},{name:"Rödkål"},{name:"Brysselkål"},{id:"radisa",name:"Rädisa"}],avoidWhy:"Alla i korsblommiga familjen delar sjukdomar - framför allt klumprotsjuka som lever kvar i jorden i 7+ år. Vänta minst 4 år innan du odlar kål på samma plats.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"potatis",name:"Potatis"}],goodBeforeWhy:"Baljväxter lämnar kväve i jorden - gratis gödsel till hungriga kålväxter. Potatis lämnar fin, lös jord.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"sallat",name:"Sallat"},{id:"rodbeta",name:"Rödbeta"}],goodAfterWhy:"Rotgrönsaker och lök trivs i den välbearbetade jorden. Sallat utnyttjar det kväve som kålrabbin lämnat kvar."},varieties:[{name:"Superschmelz",zones:[1,2,3,4,5,6],note:"Jättesorten som kan bli stor som en melon utan att bli vedartad! Perfekt om du missar skördetiden. Öppet pollinerad och otroligt förlåtande."},{name:"Blaro",zones:[1,2,3,4,5,6],note:"Blåviolett, vacker sort med mild smak. Tidig och pålitlig. Fin kontrast på tallriken."},{name:"Lanro",zones:[1,2,3,4,5,6],note:"Klassisk grönvit sort. Snabb, mild och pålitlig. En av de mest odlade i Sverige."},{name:"Korist F1",zones:[1,2,3,4,5,6],note:"F1-hybrid med jämn storlek och bra sjukdomsresistens. Bra val om du vill ha likformig skörd."},{name:"Logo",zones:[1,2,3,4,5,6],note:"Öppet pollinerad, ljusgrön med fin, mild smak. Tålig sort som funkar bra i hela landet."}],problems:[{name:"Kålfjäril",symptom:"Gröna larver som äter bladen. Gröna spillningshögar på och runt bladen.",fix:"Fiberduk från dag ett! Handplocka larver morgon och kväll. Samodla med dill och lök. Bacillus thuringiensis (Bt) funkar bra vid kraftiga angrepp."},{name:"Jordloppan",symptom:"Små runda hål i bladen, speciellt på unga plantor.",fix:"Fiberduk skyddar effektivt. Håll jorden fuktig - jordloppan avskyr fukt. Strö lite stenmjöl på bladen."},{name:"Kålfluga",symptom:"Plantan vissnar trots vattning, vita larver vid rötterna.",fix:"Kålkragar runt stjälken vid utplantering hindrar flugan att lägga ägg. Fiberduk fungerar också."},{name:"Klumprotsjuka",symptom:"Plantan slutar växa, vissnar. Rötterna har klumpiga, svullna utväxter.",fix:"Ingen bot - dra upp och bränn! Kalka jorden ordentligt (pH over 7.0). Växtföljd med minst 4 års uppehåll. Allvarlig svampsjukdom."},{name:"Vedartad knöl",symptom:"Knölen blir hård, fiberig och träig istället för saftig.",fix:"Skörda i tid! De flesta sorter ska skördas vid 5-8 cm diameter. Jämn vattning och rätt sort (Superschmelz tål att bli stor utan att bli träig)."}],goodToKnow:[{icon:"harvest",title:"Skörda vid tennisbollsstorlek",text:"De flesta kålrabbisorter ska skördas när knölen är 5-8 cm i diameter - ungefär som en tennisboll. Väntar du längre blir hon vedartad och trådig. Undantag: Superschmelz som kan bli jättestor utan att tappa kvalitet.",severity:"tip"},{icon:"seedling",title:"Successionssådd ger skörd hela säsongen",text:"Så en omgång var tredje vecka från april till juli. Då har du färsk kålrabbi från juni ända in i oktober. Hon är snabb nog att hinna med 2-3 omgångar per säsong.",severity:"tip"},{icon:"tip",title:"Bladen är också mat!",text:"Släng aldrig bladen! Unga kålrabbiblad är faktiskt godare än spenat. Fräs dem i smör, använd i soppa eller ät råa i sallad. Hel planta - noll svinn.",severity:"tip"},{icon:"warning",title:"Klumprotsjuka - ta det på allvar",text:"Odla aldrig kålväxter på samma plats oftare än var fjärde år. Klumprotsjuka lever i jorden i 7+ år och det finns inget botemedel. Kalka ordentligt - svampen trivs i sur jord.",severity:"warning"},{icon:"sun",title:"Perfekt för nybörjare och barn",text:"Kålrabbi växer snabbt, tar lite plats och är väldigt förlåtande. Den uppsvällda stjälken är fascinerande att se växa - barn älskar att följa utvecklingen.",severity:"tip"},{icon:"calendar",title:"Tidig vår- och höstskörd",text:"Kålrabbi tål frost ner till -5°C och trivs i svalare väder. Det gör henne till en utmärkt gröda för tidig vår och sen höst när det inte finns så mycket annat att skörda.",severity:"tip"}],sowing:{method:"both",label:"Direktsådd eller förodling",description:"Kålrabbi kan både förodlas inomhus och direktsås. Förodling ger tidigare skörd och ett försprång mot skadedjur. Direktsådd funkar utmärkt från maj och framåt - hon gror snabbt och etablerar sig lätt.",steps:["Förodling: Så 0.5-1 cm djupt i celler, 4-5 veckor före utplantering","Håll jorden runt 18-20°C för snabb groning (5-8 dagar)","Härda av 7-10 dagar innan utplantering","Plantera ut med 20-25 cm avstånd när plantan har 3-4 riktiga blad","Direktsådd: Så 1-2 cm djupt med 20-25 cm mellanrum från maj","Gallra till 20-25 cm om det blivit för tätt","Vattna ordentligt vid utplantering eller efter sådd"],tips:["Förodling ger 2-3 veckors försprång - värt det för tidig skörd","Fiberduk direkt vid sådd eller utplantering skyddar mot kålfjäril och jordloppa","Så var tredje vecka för skörd hela säsongen - kålrabbi är perfekt för successionssådd"],indoorWeeks:"4-5 veckor"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!0,description:"Kålrabbi är tvåårig för frösparing - hon behöver övervintras för att blomma andra året. Knölen grävs upp på hösten, lagras svalt, och planteras ut igen på våren. Hon korsar sig med ALL annan kål, så isolering är ett måste.",steps:["Välj den finaste, friskaste plantan med bäst form och smak","Gräv upp knölen med rötter på hösten innan hård frost","Lagra i sandlåda i källare eller jordkällare (0-4°C) över vintern","Plantera ut knölen igen tidigt på våren, med krona i marknivå","Blomstjälk skjuter upp - gula blommor pollineras av insekter","Låt fröskidorna mogna och torka på plantan tills de är bruna och spröda","Klipp av stjälkarna, torka inomhus och gnugla loss fröna"],isolation:"Korsar med ALLA andra Brassica oleracea (grönkål, broccoli, blomkål, vitkål, brysselkål). Odla bara en sort för frö, eller isolera med minst 500 m-1 km.",storageYears:"3-5 år",tip:"Kålrabbifrö är relativt enkelt att spara om du har utrymme att övervintra knölen. Välj öppet pollinerade sorter som Superschmelz eller Logo - F1-sorter ger inte samma resultat i nästa generation."},storage:{shelfLife:"2-4 veckor (färsk), 3-4 månader (källare)",methods:[{method:"Kylskåp",icon:"snowflake",duration:"2-4 veckor",description:"Klipp av bladen (spara dem - de är ätbara!). Lägg knölen i en plastpåse med några hål i grönsakslådan. Kålrabbi håller sig förvånansvärt länge i kylskåp.",best:!0},{method:"Jordkällare/sandlåda",icon:"storage",duration:"3-4 månader",description:"Lagra hela knölar i fuktig sand i källare vid 0-4°C. Klipp av bladen men lämna lite stjälk kvar. Kontrollera regelbundet och plocka bort eventuella dåliga.",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Skala, tärna och blanchera 2-3 minuter. Kyl i isvatten, torka av och frys in. Perfekt för soppor, gratänger och grytor.",best:!1},{method:"Fermentera",icon:"storage",duration:"3-6 månader",description:"Riv eller strimla kålrabbin och fermentera med 2% salt. Milt och gott - tänk sauerkraut fast mjukare i smaken.",best:!1}],tips:["Kålrabbi med bladen kvar tappar fukt snabbare - klipp av bladen direkt vid skörd","Unga, nyskördade kålrabbier är godast råa - den milda söta smaken försvinner med tiden","Skalet kan skalas bort men på unga knölar är det så tunt att det inte behövs","Sena höstskördar lagras bättre än sommarskördar - svalare väder ger bättre hållbarhet"]},harvestCalc:{minPerSqm:2,maxPerSqm:4,unit:"kg"}},ia=Object.freeze(Object.defineProperty({__proto__:null,kalrabbi:w},Symbol.toStringTag,{value:"Module"})),M={name:"Kinakål",icon:"kinakal",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Enkel",difficultyWhy:"Tacksam och snabbväxande bara du sår vid rätt tidpunkt. Hemligheten? Så i juli och låt henne bli en höstkål - då slipper du allt strul med skottbildning.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:[1,2,3,4,5,6,7]},days:"55-75",spacing:"30-40 cm",rowSpacing:"40-50 cm",depth:"1-2 cm",ph:{min:6.5,max:7.5,ideal:7},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"partial-sun",detail:"Trivs i sol men uppskattar halvskugga mitt på dagen, särskilt vid höstsådd. Lite skugga håller temperaturen nere och minskar risken att hon skjuter i blom."},temperature:{min:-3,max:25,ideal:"15-20°C",detail:"Klarar lätt frost ner till -3°C och blir faktiskt sötare av det! Men över 22-25°C i kombination med långa dagar panikblommar hon. Trivs allra bäst i sval höstluft."},wind:{level:"Skyddat",detail:"Kinakål bildar höga, lösa huvuden som kan bli vindkänsliga. Ett skyddat läge gör att huvudena sluter sig finare och bladen inte torkar ut."}},watering:{need:"Medel-Hög",icon:"water",summary:"Kinakål är till stor del vatten - hon behöver jämn fukt hela vägen från sådd till skörd. Torka stressar henne och kan trigga blomning, så var generös men undvik stående vatten.",phases:[{phase:"Groning (0-1 vecka)",need:"Hög",tip:"Håll jorden jämnt fuktig tills fröna grott. Kinakål gror snabbt, ofta inom 4-7 dagar."},{phase:"Tillväxt (1-4 veckor)",need:"Medel-Hög",tip:"Vattna regelbundet 2-3 gånger i veckan. Jämn fukt ger saftiga, milda blad och förhindrar att hon stressar."},{phase:"Huvudbildning (4-8 veckor)",need:"Hög",tip:"Kritisk period! Nu bygger hon sitt huvud och behöver ordentligt med vatten. Torka nu kan ge lösa, dåliga huvuden."},{phase:"Skörd (8-10 veckor)",need:"Medel",tip:"Fortsätt vattna men minska något. Alltför blöt jord vid skörd gör att huvudena lagras sämre."}],mistakes:["Ojämn vattning stressar plantan och triggar skottbildning - det vanligaste misstaget","Stående vatten ger rotröta, särskilt i tung lerjord","Torka under huvudbildningen ger lösa, luftiga huvuden med bitter smak","Vattna på bladen istället för vid roten ökar risken för svampsjukdomar"],tip:"Mulcha med gräsklipp eller halm runt plantorna - det håller jorden jämnt fuktig och sval, precis som kinakål vill ha det."},soil:"Mullrik, näringsrik och fukthållande jord med god dränering. Kinakål vill ha varm, kalkrik jord - hon är hungrigare än de flesta bladgrönsaker.",soilTips:["Blanda in rikligt med brunnen kompost eller stallgödsel innan sådd - kinakål är en riktig storätare","Kalka om pH ligger under 6.5 - kinakål trivs i neutral till svagt basisk jord och kalk minskar risken för klumprotsjuka","Undvik kompakt lerjord - luckra ordentligt och blanda in sand om jorden är tung"],timeline:{1:[{phase:"Förkultivering",months:"Mar-Apr",icon:"seedling"},{phase:"Utplantering vår",months:"Apr-Maj",icon:"seedling"},{phase:"Direktså höst",months:"Jun-Jul",icon:"seedling"},{phase:"Tillväxt höst",months:"Jul-Sep",icon:"leaf"},{phase:"Skörd",months:"Sep-Nov",icon:"harvest"}],4:[{phase:"Förkultivering",months:"Apr",icon:"seedling"},{phase:"Utplantering vår",months:"Maj",icon:"seedling"},{phase:"Direktså höst",months:"Jul",icon:"seedling"},{phase:"Tillväxt höst",months:"Aug-Sep",icon:"leaf"},{phase:"Skörd",months:"Sep-Okt",icon:"harvest"}],6:[{phase:"Förkultivering",months:"Maj",icon:"seedling"},{phase:"Utplantering",months:"Jun",icon:"seedling"},{phase:"Direktså höst",months:"Jun-Jul",icon:"seedling"},{phase:"Tillväxt höst",months:"Jul-Aug",icon:"leaf"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Jul",N:30,P:20,K:20,label:"Sådd"},{month:"Aug",N:60,P:30,K:35,label:"Tillväxt"},{month:"Sep",N:50,P:35,K:45,label:"Huvudbildning"},{month:"Okt",N:25,P:20,K:30,label:"Skörd"}],nutritionTips:[{timing:"Före sådd/plantering",tip:"Grundgödsla med brunnen kompost och en näve benmjöl per kvadratmeter. Kinakål vill ha en näringsrik start."},{timing:"Under tidig tillväxt",tip:"Ge en omgång flytande nässelvatten eller kompostvatten efter 2-3 veckor. Det kväverika gödslat ger frodiga blad."},{timing:"Vid huvudbildning",tip:"En sista giva med kaliumrikt gödsel (vedaska eller algbaserat) stärker plantan och ger fastare huvuden."},{timing:"Hela säsongen",tip:"Övergödsla inte med kväve sent - det gör bladen vattniga och försämrar lagringen."}],companions:{good:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft förvirrar kålflugor och andra kålskadedjur - en naturlig bodyguard"},{id:"morot",name:"Morot",icon:"vegetable",why:"Kompletterande rotsystem - moroten går djupt medan kinakål har ytliga rötter. Doften förvirrar varandras skadedjur"},{id:"dill",name:"Dill",icon:"herb",why:"Lockar nyttoinsekter som äter bladlöss, och doften kan förvirra kålfjärilar"},{id:"spenat",name:"Spenat",icon:"vegetable",why:"Bra markskydd som håller jorden fuktig och sval runt kinakålen"}],bad:[{id:"gronkal",name:"Grönkål",icon:"vegetable",why:"Samma familj - delar kålfluga, jordloppor och klumprotsjuka"},{id:"broccoli",name:"Broccoli",icon:"vegetable",why:"Samma familj - konkurrerar om samma näring och ökar sjukdomstrycket"},{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Lockar sniglar som älskar kinakål, och konkurrerar om fukt"}]},rotation:{avoid:[{id:"gronkal",name:"Grönkål"},{id:"broccoli",name:"Broccoli"},{id:"blomkal",name:"Blomkål"},{id:"vitkal",name:"Vitkål"},{id:"radisa",name:"Rädisa"},{id:"pak-choi",name:"Pak choi"},{id:"kalrabbi",name:"Kålrabbi"}],avoidWhy:"Alla korsblommiga delar klumprotsjuka, kålbråck och kålfluga. Vänta minst 4 år innan du odlar kinakål på samma plats som annan kål stått.",goodBefore:[{name:"Baljväxter (ärtor, bönor)"},{id:"lok",name:"Lök"},{id:"potatis",name:"Potatis"}],goodBeforeWhy:"Baljväxter fixerar kväve som kinakål älskar. Lök och potatis lämnar ren jord utan kålsjukdomar.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"sallat",name:"Sallat"}],goodAfterWhy:"Morötter, lök och sallat tillhör helt andra familjer och påverkas inte av kålsjukdomar i jorden."},varieties:[{name:"Granaat",zones:[1,2,3,4,5],note:"En av få OP-sorter som fortfarande finns. Bildar fina cylindriska huvuden med ljusgröna, krispiga blad och breda vita mittnerv. Pålitlig och beprövad. Runåbergs, ekologiskt frö."},{name:"Kaito",zones:[1,2,3,4,5],note:"Ny OP-sort med kompakta ovala huvuden, 20-25 cm höga. Ovanligt god motståndskraft mot skottbildning för att vara öppenpollinerad - äntligen! Lindbloms, ekologiskt/demeter."},{name:"Scarvita F1",zones:[1,2,3,4,5,6],note:"F1-hybrid med vackra mörkgröna blad med lila ton. Sen att skjuta i blom och tål mer värme. OBS: F1 - sparar du frö får du inte samma sort tillbaka. Nelson Garden."},{name:"Bilko F1",zones:[1,2,3,4,5,6],note:"Robust F1-hybrid som ger stora, tunga huvuden (1-2 kg). Mycket god lagringsförmåga och motståndskraftig mot sjukdomar. OBS: F1 - ger inte sortäkta frö. Semenco, ekologiskt."}],problems:[{name:"Jordloppor",symptom:"Massor av små hål i bladen, som om någon skjutit med hagelgevär. Värst i torr, varm väderlek.",fix:"Fiberduk direkt vid sådd är det enda som verkligen funkar. Håll jorden fuktig - jordloppor avskyr fukt. Blandodla med lök."},{name:"Kålfluga",symptom:"Plantan vissnar trots vattning. Tittar du vid roten hittar du vita larver som äter sig igenom.",fix:"Kålkrage runt stjälken hindrar flugan från att lägga ägg. Fiberduk fungerar också bra som barriär."},{name:"Klumprotsjuka",symptom:"Plantan blir gul, vissnar och växer dåligt. Rötterna har fula, svulstliknande knölar.",fix:"Ingen bot tyvärr. Kalka jorden till pH 7+, håll god växtföljd (minst 4 år) och kompostera aldrig sjuka plantor. Dränera bra - sjukdomen trivs i blöt jord."},{name:"Sniglar",symptom:"Stora, oregelbundna hål i bladen och slemspår. Värst på hösten i fuktig väderlek.",fix:"Snigelkorn, ölfällor eller plocka för hand på kvällen. Kinakålen är ren snigelmat - var extra vaksam på fuktiga höstkvällar."}],goodToKnow:[{icon:"warning",title:"Så ALDRIG mitt i sommaren",text:"Kinakål är extremt känslig för långa dagar och värme - hon skjuter rakt i blom. I Sverige betyder det: så i juli för höstskörd. Vårsådd med förkultivering kan fungera men kräver mer planering och rätt sortval.",severity:"warning"},{icon:"warning",title:"Känslig vid störning",text:"Kinakål ogillar att bli omflyttad och störd. Vill du förkultivera, använd torvkrukor eller djupa pluggar som du sätter ner direkt i jorden - då slipper rötterna chocken.",severity:"warning"},{icon:"harvest",title:"Sötare efter frost",text:"Precis som grönkål blir kinakål sötare och mildare efter den första lätta frosten. Plantan omvandlar stärkelse till socker som frostskydd - och det kan du smaka!",severity:"tip"},{icon:"leaf",title:"Perfekt kimchikål",text:"Kinakål är grunden i koreansk kimchi. Odla en extra omgång på hösten, salta och krydda med chili och vitlök - du får probiotisk mat som håller hela vintern.",severity:"tip"},{icon:"sun",title:"Fiberduk från dag ett",text:"Jordloppor och kålfluga attackerar direkt. En fiberduk vid sådd löser båda problemen och håller dessutom jämnare fukt och temperatur. Lyft bara för vattning och ogräsrensning.",severity:"tip"},{icon:"seedling",title:"Lagrar bättre än du tror",text:"Sena sorter som Bilko F1 kan hålla sig 2-3 månader i kylskåp. Packa varje huvud i tidningspapper och lägg i grönsakslådan - perfekt vinterförråd.",severity:"tip"}],sowing:{method:"both",label:"Direktsådd eller förkultivering",description:"Kinakål kan både direktsås och förkultiveras. Höstsådd direkt i juli är enklast och ger bäst resultat. Vårsådd kräver förkultivering inomhus och snabb utplantering innan dagarna blir för långa.",steps:["Direktsådd (rekommenderas): Så i juli, direkt på friland. Dra ett grunt spår (1-2 cm djupt) och lägg fröna med 5-10 cm mellanrum","Täck med ett tunt lager jord och vattna försiktigt med stril","Gallra till 30-40 cm avstånd när plantorna har 3-4 riktiga blad - gallringsplantorna kan ätas som babysallad","Förkultivering: Så i djupa pluggar eller torvkrukor 3-4 veckor före utplantering (mars-april beroende på zon)","Undvik att störa rötterna vid utplantering - kinakål ogillar omplantering","Plantera ut på samma djup och vattna rikligt vid planteringen","Täck med fiberduk direkt efter sådd/plantering för att skydda mot jordloppor och kålfluga"],tips:["Höstsådd i juli är det säkraste - svalare väder, kortare dagar och färre problem med skottbildning","Vårsådd kräver en sort som tål långa dagar (Kaito eller Bilko F1) och snabb utplantering","Fiberduk direkt vid sådd skyddar mot jordloppor, kålfluga och håller jämn fukt","Successiv sådd var 2 vecka i juli ger skörd under längre tid"],indoorWeeks:"3-4 veckor"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!1,description:"Kinakål kan gå i blom och sätta frö samma säsong (om hon stressas) eller övervintras för fröproduktion. Hon korsar extremt lätt med pak choi, majrova och alla andra Brassica rapa - det gör frötagning knepigt om du odlar flera arter.",steps:["Välj de finaste plantorna med bäst huvudbildning och låt dem stå kvar","I milda vintrar kan kinakål övervintra utomhus med skydd (zon 1-2)","Alternativt: stressa en höstplanta genom att minska vattning - hon börjar blomma","Gula blommor pollineras av insekter - blommorna sitter på höga stjälkar","Låt skidorna mogna på plantan tills de blir bruna och torra","Klipp av stjälkarna och torka i papperspåse inomhus en vecka","Gnugga loss fröna och blås bort skal och skräp försiktigt","Förvara torrt och svalt i märkt påse"],isolation:"Korsar med pak choi, majrova, rova och alla andra Brassica rapa. Isolera minst 500 m eller odla bara en sort ur denna grupp för frösparande.",storageYears:"3-5 år",tip:"Eftersom kinakål korsar så lätt med pak choi och majrova, bör du bara spara frö om du inte odlar andra Brassica rapa-arter i närheten. F1-hybrider (Bilko, Scarvita) ger inte sortäkta avkomma - använd Granaat eller Kaito för frötagning."},storage:{shelfLife:"1-3 månader",methods:[{method:"Kylskåp",icon:"snowflake",duration:"2-3 månader",description:"Packa hela huvudet i tidningspapper och lägg i grönsakslådan. Tvätta inte förrän du ska använda - fukt på bladen ger röta. Sena sorter håller längst.",best:!0},{method:"Kallförråd",icon:"storage",duration:"1-2 månader",description:"Förvara i mörkt utrymme vid 0-5°C och hög luftfuktighet. Kontrollera regelbundet och plocka bort yttre blad som börjar vissna.",best:!1},{method:"Fermentera (kimchi)",icon:"storage",duration:"3-6 månader",description:"Salta, krydda med chili, vitlök och ingefära och låt jäsa. Klassisk koreansk kimchi - det bästa sättet att ta vara på höstskörden!",best:!1},{method:"Frysa",icon:"snowflake",duration:"6-12 månader",description:"Blanchera i 2 minuter, kyl i isvatten, pressa ur vätska och frys i portionspåsar. Passar bra i soppor och grytor.",best:!1}],tips:["Sena sorter (Bilko F1) lagras betydligt längre än tidiga sorter","Skörda på morgonen när huvudena är kalla och fasta - det förlänger hållbarheten","Lagra aldrig kinakål tillsammans med äpplen eller tomater - etylengasen påskyndar nedbrytningen","Överskott? Gör kimchi! Det är den klassiska användningen och håller hela vintern","Yttre blad som vissnar kan plockas bort - inuti är huvudet ofta fortfarande fint"]},harvestCalc:{minPerSqm:2,maxPerSqm:5,unit:"kg"}},la=Object.freeze(Object.defineProperty({__proto__:null,kinakal:M},Symbol.toStringTag,{value:"Module"})),F={name:"Koriander",icon:"koriander",category:"kryddor",family:"Flockblommiga",familyLatin:"Apiaceae",perennial:!1,difficulty:"Enkel",difficultyWhy:"Direktsås utomhus, gror lätt och kräver minimal skötsel. Enda utmaningen är att hon gärna går i blom lite väl snabbt i värme - men med rätt sort och successionsådd fixar du det.",zones:{outdoor:[1,2,3,4,5,6],indoor:[1,2,3,4,5,6,7,8],greenhouse:[1,2,3,4,5,6,7,8]},days:"50-70 (blad), 90-120 (frö)",spacing:"5-10 cm",spacingNote:"Fröodling: 15-20 cm",rowSpacing:"25-30 cm",depth:"0.5-1 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Koriander vill ha minst 6 timmars sol per dag men uppskattar lite skugga under de varmaste timmarna på högsommaren. Skydd mot middagssolen fördröjer blomningen - och det vill vi."},temperature:{min:5,max:28,ideal:"15-20°C",detail:"Gror redan vid 5°C och tål lätt frost som etablerad planta. Men i värme över 25°C tänker hon bara på en sak: att blomma och sätta frö. Trivs bäst i svalare väder."},wind:{level:"Skyddat",detail:"De tunna stammarna knäcks lätt i vind, särskilt när plantan gått i blom och blivit hög. Ett skyddat läge intill mur eller staket är perfekt."}},watering:{need:"Medel",icon:"water",summary:"Jämn fukt är nyckeln till lyckad koriander. Torkar jorden ut går hon i blom snabbare än du hinner blinka - och då är bladsäsongen över.",phases:[{phase:"Groning (1-3 veckor)",need:"Hög",tip:"Håll jorden jämnt fuktig tills plantorna är uppe. Korianderfröet har ett hårt skal och kan ta 1-3 veckor att gro - ge inte upp!"},{phase:"Bladskörd (3-8 veckor)",need:"Medel",tip:"Vattna 2-3 gånger i veckan om det inte regnar. Jämn fukt fördröjer blomningen och ger mer blad. Det är nu det gäller!"},{phase:"Blomning och frösättning",need:"Låg",tip:"När plantan blommar kan du slappna av med vattningen. Nu är fokus på fröproduktion och hon klarar sig med mindre."}],mistakes:["Låter jorden torka ut - den vanligaste orsaken till att koriander skjuter i blom för tidigt","Vattnar ovanifrån i sol - bättre att vattna vid basen, tidigt på morgonen","Ojämn vattning - stress triggar blomning direkt"],tip:"Mulcha runt plantorna med gräsklipp eller kompost. Det håller fukten jämn och jorden sval - precis som koriandern vill ha det."},soil:"Koriander trivs i lätt, mullrik jord med bra dränering. Sandblandad trädgårdsjord är perfekt. Hon är inte kräsen men avskyr vattensjuk mark - rötterna ruttnar snabbt i stående vatten.",soilTips:["Lätt och lucker jord är viktigast - blanda in lite sand om du har tung lerjord","Kompost i måttlig mängd ger bra start - men övergödsla inte, koriander har lågt näringsbehov","Bra dränering är ett måste - korianderns rötter tål inte att stå blöta","Fungerar utmärkt i kruka med vanlig planteringsjord - minst 3-5 liter per kruka"],timeline:{1:[{phase:"Direktsådd 1",months:"Apr",icon:"seedling"},{phase:"Omsådd 2",months:"Maj",icon:"seedling"},{phase:"Omsådd 3",months:"Jun-jul",icon:"seedling"},{phase:"Bladskörd",months:"Maj-aug",icon:"harvest"},{phase:"Fröskörd",months:"Aug-sep",icon:"seed"}],4:[{phase:"Direktsådd 1",months:"Maj",icon:"seedling"},{phase:"Omsådd 2",months:"Jun",icon:"seedling"},{phase:"Bladskörd",months:"Jun-aug",icon:"harvest"},{phase:"Fröskörd",months:"Sep",icon:"seed"}],6:[{phase:"Direktsådd",months:"Jun",icon:"seedling"},{phase:"Bladskörd",months:"Jul-aug",icon:"harvest"},{phase:"Fröskörd",months:"Sep",icon:"seed"}]},nutritionData:[{month:"Apr",N:2,P:1,K:1},{month:"Maj",N:4,P:2,K:2},{month:"Jun",N:5,P:3,K:3},{month:"Jul",N:4,P:3,K:3},{month:"Aug",N:2,P:2,K:2}],nutritionTips:[{timing:"Vid sådd",tip:"Blanda in lite kompost i jorden - det räcker för hela säsongen. Koriander har lågt näringsbehov och mår bäst av att inte bli bortskämd."},{timing:"Tillväxt (juni-juli)",tip:"En lätt giva utspädd nässelvatten varannan vecka om du vill. Men hon klarar sig helt fint utan - övergödsling ger stor planta men tunnare smak."},{timing:"Obs!",tip:"Koriander behöver betydligt mindre näring än de flesta kryddor. Spara gödslet på basilikan och tomaterna - koriandern vill ha det enkelt."}],companions:{good:[{id:"spenat",name:"Spenat",icon:"vegetable",why:"Trivs i liknande fuktiga, svala förhållanden. Spenatens breda blad skuggar marken och håller fukten jämn - precis som koriandern vill ha det."},{id:"artor",name:"Ärtor",icon:"vegetable",why:"Baljväxter fixerar kväve som koriander har nytta av. Och koriandern lockar nyttiga rovinsekter som håller bladlössen i schack."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Koriandens doft avskräcker bladlöss och spinnkvalster som annars angriper tomater. En välkommen granne i växthuset."},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Liknande krav på fukt och svalka. Koriander kan ge lite skugga åt sallat under de varmaste veckorna."}],bad:[{id:"fankal",name:"Fänkål",icon:"vegetable",why:"Fänkål utsöndrar ämnen som hämmar koriandens tillväxt. Klassisk dålig granne bland flockblommiga."},{id:"dill",name:"Dill",icon:"herb",why:"Samma familj och liknande blommor - de konkurrerar om pollinerare. Håll dem åtskilda för bäst resultat."}]},rotation:{avoid:[{id:"morot",name:"Morot"},{id:"dill",name:"Dill"},{id:"persilja",name:"Persilja"},{id:"palsternacka",name:"Palsternacka"}],avoidWhy:"Alla tillhör flockblommiga (Apiaceae) och delar sjukdomar och skadedjur. Vänta 3-4 år innan du sår koriander på samma plats.",goodBefore:[{name:"Kålväxter"},{id:"sallat",name:"Sallat"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Koriander tar lite näring från jorden och lämnar den i fint skick. Kål och sallat trivs bra efter.",goodAfter:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"potatis",name:"Potatis"}],goodAfterWhy:"Baljväxter berikar jorden med kväve. Potatis lämnar lucker jord som koriandens rötter uppskattar."},varieties:[{name:"Jantar",zones:[1,2,3,4,5,6],note:"Troligen Europas mest odlade sort. Sen blomning, riklig bladmassa och aromatiska frön med en fin apelsindoft. 50-70 cm. Ekologiskt frö hos Lindbloms."},{name:"Filtro (bladkoriander)",zones:[1,2,3,4,5,6],note:"Slow-bolt bladkoriander - extra sen blomning och kompakt växtsätt. Bästa valet om du främst vill ha blad. Finns hos Runåbergs."},{name:"Confetti",zones:[1,2,3,4,5,6],note:"Särpräglad sort med mycket finflikiga blad som påminner om morotsblast. Sötare, mildare smak. Vacker i sallad. Finns hos Impecta."},{name:"Leisure",zones:[1,2,3,4,5],note:"Slow-bolt-sort med stora blad och sen blomning. 60-90 cm. Ger riklig bladskörd. Finns hos Impecta."}],problems:[{name:"Skottning (bolting)",symptom:"Plantan sträcker sig, bildar tunna dillliknande blad och blomställning. Bladsmaken blir bitter.",fix:"Det vanligaste problemet! Välj slow-bolt-sorter (Jantar, Filtro), ge skugga under varmaste timmarna, håll jämn fukt. Successionsådd var 3:e vecka är den bästa försäkringen."},{name:"Bladlöss",symptom:"Kolonier på stjälkar och bladundersidor, klibbigt honungsdagg.",fix:"Spruta med såpvatten. Bonustips: låt några plantor gå i blom - korianderns blommor lockar nyckelpigor och parasitsteklar som äter bladlössen åt dig."},{name:"Mjöldagg",symptom:"Vitt, mjöligt belägg på bladen vid dålig luftcirkulation.",fix:"Ge mer luft mellan plantorna, vattna vid basen istället för ovanifrån. Ta bort drabbade blad."},{name:"Dålig groning",symptom:"Ojämn eller utebliven uppkomst trots vattning.",fix:"Korianderfrön har ett hårt skal. Krossa försiktigt (dela tvillingfröet) eller blötlägg 12-24 timmar före sådd. Gror bäst i mörker - täck fröet med jord."}],goodToKnow:[{icon:"tip",title:"Två kryddor i en",text:"Koriander ger dig TVÅ helt olika kryddor från samma planta. Bladen (som kallas cilantro i engelskspråkiga länder) har en fräsch, citrusig smak. Fröna har en helt annan, varm och nötig karaktär. Rötterna används dessutom i thailändskt kök. Tre för priset av en!",severity:"tip"},{icon:"warning",title:"Tvålgenen - det är inte ditt fel",text:"Smakar koriander tvål för dig? Du är inte ensam - 4-14% av alla människor har en genvariant (OR6A2) som gör att de känner aldehyderna i korianderblad extra starkt. Bland européer är det hela 17%. Det är helt genetiskt och inget du kan ändra på. Odla för fröna istället!",severity:"warning"},{icon:"warning",title:"Går i blom blixtsnabbt",text:"Koriandens största utmaning i Sverige: hon blommar fort vid värme och torka. Så i omgångar var 3:e vecka, välj slow-bolt-sorter (Jantar, Filtro) och ge lite eftermiddagsskugga. Eller omfamna blomningen - fröna är minst lika användbara!",severity:"warning"},{icon:"tip",title:"Höstsådd-tricket",text:"I zon 1-3 kan du så koriander i oktober-november. Fröna övervintrar i jorden och gror supertidig på våren - långt innan du normalt kan börja bearbeta marken. Gratis försprång!",severity:"tip"},{icon:"tip",title:"Dela fröet för bättre groning",text:"Korianderfrön är egentligen tvillingfrön - två frön ihopsatta i ett runt skal. Krossa dem försiktigt med en kavelkavel eller botten av ett glas innan du sår. Groningen blir jämnare och snabbare.",severity:"tip"}],sowing:{method:"direct",label:"Direktsådd",description:"Koriander föredrar att sås direkt på friland - hon har en ömtålig pålrot som inte gillar att bli störd. Blötlägg gärna fröna 12-24 timmar före sådd för snabbare groning. Gror på 7-21 dagar beroende på temperatur.",steps:["Blötlägg fröna i ljummet vatten 12-24 timmar (eller krossa försiktigt för att dela tvillingfröet)","Luckra jorden och kratta till jämn yta","Dra grunda spår (0.5-1 cm djupa) med 25-30 cm avstånd","Så fröet i raderna - glesare (15-20 cm) om du vill ha fröskörd, tätare (5 cm) för bladskörd","Täck med ett tunt lager jord - koriander gror bäst i mörker","Vattna försiktigt med stril och håll jämnt fuktigt","Groning tar 7-21 dagar - ge inte upp, koriandern tar sin tid!","Gallra vid behov när plantorna är 5 cm höga"],tips:["Successionsådd var 3:e vecka är hemligheten för färsk koriander hela sommaren","Välj slow-bolt-sorter (Jantar, Filtro) om du främst vill ha blad","Kan sås i kruka (minst 3-5 liter) - perfekt för balkong och fönsterbräda","Höstsådd i zon 1-3 (okt-nov) ger supertidig skörd nästa vår"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Insektspollinerad",biennial:!1,description:"Fröbesparing från koriander är nästan löjligt enkelt - fröna ÄR ju själva kryddan! Låt plantor gå i blom, samla fröna, och du har både utsäde och korianderfrö till matlagning i ett svep.",steps:["Låt utvalda plantor gå i full blom (vitrosa flockblommor som lockar pollinerare)","Vänta tills fröställningarna brunfärgas och börjar torka (aug-sep)","Klipp av hela fröställningen innan alla frön faller av","Häng upp och ner i en papperspåse på torr, luftig plats","Fröna faller av av sig själva i påsen när de torkar (1-2 veckor)","Rensa bort skräp och förvara torrt i glasburk","Spara en del som utsäde, använd resten som krydda - dubbel nytta!"],isolation:"Koriander pollineras av insekter men korsar sällan med andra sorter i hemmaträdgården. För garanterat sortrena frön behövs ca 300 meters avstånd mellan sorter.",storageYears:"2-5 år",tip:"Koriander självsår sig gärna om du låter några fröställningar stå kvar. Nästa vår dyker det upp gratis koriander - en present från förra säsongen!"},storage:{shelfLife:"5-7 dagar (färska blad)",methods:[{method:"I vatten i kylen (bäst!)",icon:"water",duration:"1-2 veckor",description:"Ställ stjälkarna i ett glas vatten som en bukett och täck löst med en plastpåse. Förvara i kylen och byt vatten varannan dag. Hållbarheten slår allt annat.",best:!0},{method:"Frysning (blad)",icon:"snowflake",duration:"3-6 månader",description:"Hacka bladen fint och fyll i isbitsfack med vatten eller olivolja. Perfekt att slänga direkt i grytan eller woken. Tappar lite textur men smaken bevaras.",best:!1},{method:"Hela korianderfrön",icon:"seed",duration:"2-3 år",description:"Förvara i lufttät glasburk, svalt och mörkt. Hela frön behåller aromen mycket längre än malda. Rosta i torr panna och mal först vid användning.",best:!1},{method:"Mald koriander",icon:"storage",duration:"6-12 månader",description:"Tappar arom snabbt efter malning - mal alltid vid behov istället för att köpa färdigmald. En kryddkvarn eller mortel gör jobbet på sekunder.",best:!1}],tips:["Färska blad i glas med vatten + plastpåse i kylen håller sig dubbelt så länge som i påse","Frys hackade blad i isbitsfack med olivolja - perfekta portioner för asiatisk matlagning","Hela korianderfrön - rosta i torr panna före malning för maximal smak","Fröna ÄR kryddan korianderfrö - din fröskörd ger både utsäde och krydda!"]},harvestCalc:{minPerSqm:.15,maxPerSqm:.4,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp blad löpande, eller skörda hela fröställningar",description:"Börja skörda blad när plantan är ca 15 cm hög. Klipp de yttre bladen först så fortsätter plantan producera. När blomningen kommit igång skiftar fokus till fröskörd - vänta tills fröna brunfärgas.",uses:[{use:"Färska blad",tip:"Tillsätt SIST i matlagningen - koriander tappar all smak av värme. Oumbärlig i asiatisk, mexikansk och indisk matlagning. Riv eller hacka grovt."},{use:"Korianderfrö (helt)",tip:"Rosta i torr panna och mal vid behov. Grundkrydda i curry, garam masala och marinader. Varm, nötig smak som inte liknar bladen alls."},{use:"Rötter",tip:"Används i thailändsk matlagning (currypasta). Intensivare smak än bladen. Tvätta noga och hacka fint."},{use:"Mikroblad",tip:"Koriander fungerar utmärkt som mikrogrönt - så tätt och skörda efter 10-14 dagar. Intensiv smak i miniatyr."}]}},sa=Object.freeze(Object.defineProperty({__proto__:null,koriander:F},Symbol.toStringTag,{value:"Module"})),V={name:"Körsbär",icon:"korsbar",category:"frukt",family:"Rosväxter",familyLatin:"Rosaceae",perennial:!0,lifespan:"30-80+ år",difficulty:"Medel",difficultyWhy:"Kräver beskärning under rätt period (JAS - aldrig vinter!), fågelskydd vid skörd och viss sjukdomskontroll. Men ett etablerat körsbärsträd ger fantastisk skörd i decennier. Surkörsbär är enklare än sötkörsbär.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:null},days:"Skörd år 3-5",spacing:"3-5 m",spacingNote:"Sötkörsbär på svagväxande grundstam (Gisela) 3-4 m, surkörsbär (buskform) 2-3 m",rowSpacing:"4-6 m",depth:"Ympstället 10 cm ovan mark",depthNote:"Samma princip som äpple och päron - ympstället ska aldrig hamna under jord",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Körsbär vill ha minst 6-8 timmars direkt sol. Sötkörsbär kräver det bästa läget du har - sydvänd, skyddad plats. Surkörsbär är mer skuggtåliga och klarar halvskugga."},temperature:{min:-25,max:35,ideal:"18-25°C",detail:"Behöver vinterkyla (600-1000 kylltimmar under 7°C) för att bryta vila. Körsbär blommar TIDIGT på våren - vårfrost är den absolut största fienden. En enda frostnatt under blomning och skörden är körd."},wind:{level:"Skyddat",detail:"Vindskydd under blomning är avgörande - kall vind skrämmer bort pollinatörer och skadar ömtåliga blommor. Sluttningar med god luftcirkulation är perfekt (undviker frostfickor)."}},watering:{need:"Medel",icon:"water",summary:"Etablerade körsbärsträd klarar sig oftast på regnvatten. Nyplanterade träd behöver regelbunden vattning de första 2-3 åren. Ojämn vattning under fruktmognad ger sprickor.",phases:[{phase:"Vår (blomning)",need:"Medel",tip:"Vattna vid torka under blomning - torrt och kallt väder ger dålig pollinering och liten skörd."},{phase:"Sommar (fruktmognad)",need:"Medel",tip:"Vattna jämnt under fruktmognad. Plötsligt regn efter torka = sprickta körsbär. Det är fruktodlarens mardröm."},{phase:"Efterskörd",need:"Låg",tip:"Minska vattningen efter skörd. Trädet bygger energi för nästa år."},{phase:"Vinter",need:"Ingen",tip:"Trädet vilar. Ingen vattning behövs."}],mistakes:["Glömmer att vattna nyplanterade träd första somrarna","Ojämn vattning under fruktmognad - ger sprickta körsbär","Vattnar sent på hösten - stimulerar sen tillväxt som inte hinner mogna före frost"],tip:"Mulcha med gräsklipp eller kompost runt trädet (inte intill stammen). Jämn markfukt minskar risken för sprickta körsbär dramatiskt."},soil:"Körsbär vill ha väldränerad, kalkrik jord. De tål INTE vattensjuk mark - stående vatten dödar rötterna snabbare än kyla. En lätt, mullrik jord på en sluttning är drömmen.",soilTips:["Kalka om pH är under 6.0 - körsbär älskar kalk","Undvik blöta svackor och mark med hög grundvattennivå","Blanda in kompost i planteringsgropen (max 1/3)","På tung lera: plantera upphöjt för bättre dränering"],timeline:{1:[{phase:"Blomning",months:"April-maj",icon:"bloom"},{phase:"Fruktmognad",months:"Juni-aug",icon:"harvest"},{phase:"Sommarbeskärning (JAS)",months:"Juli-sept",icon:"scissors"},{phase:"Höstplantering",months:"Okt-nov",icon:"seedling"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],4:[{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Fruktmognad",months:"Juli-aug",icon:"harvest"},{phase:"Sommarbeskärning (JAS)",months:"Juli-sept",icon:"scissors"},{phase:"Höstplantering",months:"Sept-okt",icon:"seedling"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],6:[{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Fruktmognad",months:"Aug-sept",icon:"harvest"},{phase:"Sommarbeskärning (JAS)",months:"Juli-aug",icon:"scissors"},{phase:"Höstplantering",months:"Sept-okt",icon:"seedling"},{phase:"Vintervila",months:"Okt-april",icon:"snowflake"}]},nutritionData:[{month:"Mar",N:2,P:1,K:1},{month:"Apr",N:5,P:3,K:2},{month:"Maj",N:7,P:5,K:3,label:"Blomning"},{month:"Jun",N:6,P:5,K:5,label:"Fruktsättning"},{month:"Jul",N:4,P:4,K:7,label:"Mognad"},{month:"Aug",N:2,P:2,K:5},{month:"Sep",N:1,P:1,K:3}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge kompost eller brunnen naturgödsel runt droppzonen. Körsbär är inte extremt näringskrävande - övergödsel ger frodigt bladverk men dålig frukt."},{timing:"Blomning (maj)",tip:"En liten giva vedaska (kaliumrik) stärker blomning och fruktsättning."},{timing:"Efter skörd",tip:"Ingen extra gödsel behövs. Mulcha med gräsklipp för långsam näringsfrisättning."},{timing:"Höst",tip:"Ingen kvävegödsling efter midsommar - nya skott ska hinna mogna och härda före vintern."}],companions:{good:[{name:"Kaprifol",icon:"flower",why:"Lockar pollinatörer tidigt på våren - avgörande för körsbär som blommar innan de flesta andra fruktträd."},{name:"Ringblomma",icon:"flower",why:"Avskräcker bladlöss och lockar nyttoinsekter. Perfekt som underplantering."},{id:"graslok",name:"Gräslök",icon:"herb",why:"Traditionellt planterad runt fruktträd. Lökdoften avskräcker vissa skadeinsekter."},{name:"Klöver",icon:"flower",why:"Fixerar kväve och täcker marken. Lockar humlor som pollinerar körsbärsblommorna."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Ökar risken för rotröta (Phytophthora) som kan skada trädets rotsystem."},{name:"Gräsmatta ända intill stammen",icon:"vegetable",why:"Gräs konkurrerar om vatten och näring. Håll en meter fritt runt stammen med mulch istället."}]},rotation:{avoid:[{name:"Körsbär"},{name:"Plommon"},{name:"Päron"},{name:"Äpple"}],avoidWhy:"Plantera aldrig ett nytt körsbärsträd där ett gammalt Prunus-träd stått - trötthetssjuka (replant disease) gör att det nya trädet aldrig riktigt trivs. Svampsporer och näringsbrister i jorden saboterar etableringen. Vänta minst 5 år eller välj en annan plats.",goodBefore:[{name:"Gräsmatta"},{name:"Gröngödsling"}],goodBeforeWhy:"Mark som legat som gräsmatta eller gröngödslats i flera år ger den bästa starten.",goodAfter:[{name:"Gröngödsling"},{name:"Baljväxter"}],goodAfterWhy:"Om ett gammalt träd tas bort, gröngödsla marken i minst 3-5 år innan du planterar ett nytt fruktträd."},varieties:[{name:"Gårdebo",zones:[1,2,3,4,5],note:"Sötkörsbär. Grönt kulturarv E-planta från Tranås, Småland. En av de härdigaste sötkörsbären. Liten, mörkröd, söt och saftig frukt. Sannolikt självfertil."},{name:"Fryksås",zones:[1,2,3,4,5],note:"Sötkörsbär. Grönt kulturarv E-planta från Dalarna. Gulröd hjärtformad bigarrå med saftigt fruktkött. Sannolikt självfertil. Mognar sent augusti."},{name:"Stella",zones:[1,2,3],note:"Sötkörsbär. Kanadensisk klassiker. Stor, mörkröd bigarrå. Helt självfertil och dessutom utmärkt pollengivare för andra sorter. Den säkra nybörjarsorten."},{name:"Sunburst",zones:[1,2,3,4],note:"Sötkörsbär. Korsning Van x Stella. Stor, mörkröd till nästan svart, mycket söt. Självfertil. Tidig mognad (mitten juli)."},{name:"Stor Svart Bigarrå",zones:[1,2,3],note:"Sötkörsbär. Grönt kulturarv. Gammal sort (möjligen 1500-tal). Stora, svartröda, otroligt söta dessertkörsbär. Kräver pollinatör."},{name:"Skuggmorell",zones:[1,2,3,4,5],note:"Surkörsbär. E-planta. Stora, mörkt brunröda bär med syrlig smak. Helt självfertil. Perfekt för saft, sylt och paj. Den mest odlingsvärda surkörsbärssorten."},{name:"Nordia",zones:[1,2,3,4,5,6],note:"Surkörsbär. Svensk sort från SLU Balsgård. Kompakt buskform (2-3 m). Extremt härdig. Självfertil. Mörkröd, syrlig frukt för saft och sylt."},{name:"Lettisk Låg",zones:[1,2,3,4,5,6],note:"Surkörsbär. Buskform, bara ca 2 meter. Extremt härdig. Självfertil. Tidig mognad. Passar balkong och liten trädgård."}],problems:[{name:"Monilia/Blom- och grentorka (Monilinia laxa)",symptom:"Blommor och unga skott vissnar och svartnar som bränts. Mumifierade frukter hänger kvar på grenarna. Värst i fuktigt väder under blomning.",fix:"Skär bort angripna delar minst 20 cm in i frisk ved. Plocka bort ALLA fruktmumier - de sprider sporer nästa vår. Håll kronan öppen och luftig."},{name:"Silversjuka (Chondrostereum purpureum)",symptom:"Bladen får silveraktig metallglans, först i enstaka grenar. Sjukdomen sprids via sår - särskilt vinterbeskärningssår!",fix:"Beskär ALDRIG körsbär på vintern! JAS-perioden (juli-aug-sept) är enda rätta tiden. Sår torkar snabbt på sommaren och risken för infektion sjunker dramatiskt."},{name:"Körsbärsfluga (Rhagoletis cerasi)",symptom:"Larver i frukterna som äter fruktköttet inifrån. Upptäcks ofta först vid skörd.",fix:"Finmaskigt insektsnät över trädet innan frukterna börjar färgas. Plocka upp fallfrukt. Biologisk bekämpning med nyttosvampar (Beauveria bassiana) finns."},{name:"Fåglar",symptom:"Koltrastar, starar och sidensvans äter upp hela skörden innan du hinner reagera. De börjar redan när körsbären är halvmogna.",fix:"Bärnät är enda riktigt effektiva skyddet. Täck trädet INNAN bären börjar rodna. Fågelskrämmor fungerar bara tillfälligt - fåglarna vänjer sig. Välj dvärgträd som är enklare att nättäcka."}],pollination:{selfFertile:!1,description:"Sötkörsbär är ofta självsterila och behöver en pollinationspartner. Surkörsbär är däremot nästan alltid självfertila. Om du bara har plats för ett träd: välj en självfertil sort (Stella, Sunburst, Gårdebo) eller ett surkörsbär. Två olika sorter ger alltid bättre skörd, även hos självfertila sorter.",groups:[{name:"Självfertila sötkörsbär",varieties:["Stella","Sunburst","Lapins","Gårdebo","Fryksås"]},{name:"Kräver pollinatör (sötkörsbär)",varieties:["Stor Svart Bigarrå","Hedelfinger","Van","Regina"]},{name:"Surkörsbär (alla självfertila)",varieties:["Skuggmorell","Nordia","Lettisk Låg","Fanal","Kellerris 16"]}],tip:"Surkörsbär pollinerar faktiskt sötkörsbär! En Skuggmorell är en utmärkt partner till ett sötkörsbärsträd. Två flugor i en smäll - du får körsbär för direkt ätning OCH för saft och sylt."},establishment:{description:"Körsbärsträd etablerar sig snabbt jämfört med andra fruktträd. Ge dem en bra start de första åren så belönar de dig med riklig skörd.",years:[{year:"År 1",tasks:["Vattna 20-30 liter per vecka hela första sommaren","Plocka bort ALL frukt som sätts - trädet ska bygga rötter","Kontrollera att stödbindningen sitter lagom löst","Mulcha i 1 meters radie runt stammen (inte intill stammen!)"]},{year:"År 2",tasks:["Första formande beskärning under JAS-perioden (juli-sept)","Fortsätt vattna vid torka","Tillåt en liten skörd (5-10 frukter)","Gödsla försiktigt med kompost på våren"]},{year:"År 3-5",tasks:["Årlig JAS-beskärning: öppna kronan, ta bort vattenskott","Öka tillåten skörd gradvis - full skörd år 4-5 (dvärgträd)","Montera fågelnät inför skörd","Trädet blir alltmer självgående"]}],protection:["Stamskydd mot gnagare (nät eller spiral) - kaniner och sorkar gnager bark","Viltskydd om rådjur finns i området","Stammskydd mot solbränna (vit kalkmjölk) på sydvästra sidan vintertid","Fågelnät - planera för detta redan vid val av grundstam (dvärgträd är enklare att skydda)"],tip:"Välj dvärgträd på Gisela-grundstam om du har en liten trädgård. De blir 2-4 meter, bär frukt redan år 2-3 och går att nättäcka mot fåglar. Ett fullstort körsbärsträd (8-12 m) är vackert men praktiskt omöjligt att skydda."},ripeningGuide:{description:"Körsbär mognar från juni till september beroende på sort och typ. Sötkörsbär äts färska direkt från trädet, surkörsbär används till saft, sylt och paj. Tiderna gäller zon 1-3 - räkna 2-4 veckor senare i norr.",entries:[{variety:"Sunburst",from:"jul",to:"jul",type:"Tidigt sötkörsbär"},{variety:"Stella",from:"jul",to:"aug",type:"Sötkörsbär"},{variety:"Gårdebo",from:"jul",to:"aug",type:"Sötkörsbär"},{variety:"Stor Svart Bigarrå",from:"jul",to:"aug",type:"Sötkörsbär"},{variety:"Fryksås",from:"aug",to:"aug",type:"Sent sötkörsbär"},{variety:"Fanal",from:"jul",to:"aug",type:"Surkörsbär"},{variety:"Lettisk Låg",from:"jul",to:"jul",type:"Tidigt surkörsbär"},{variety:"Skuggmorell",from:"aug",to:"aug",type:"Surkörsbär"},{variety:"Nordia",from:"aug",to:"aug",type:"Sent surkörsbär"}],tip:"Plocka körsbär med stjälk! Det ger längre hållbarhet och minskar risken för mögel. Sötkörsbär ska ätas samma dag eller inom 2-3 dagar. Surkörsbär håller lite längre och kan fryses direkt."},goodToKnow:[{icon:"warning",title:"Beskär ALDRIG på vintern!",text:"Den viktigaste regeln för körsbär: beskär bara under JAS-perioden (juli-aug-sept). Vinterbeskärning ger silversjuka - en svampinfektion som tar sig in via snitten och som det inte finns botemedel mot. Snitten torkar dåligt i kall, fuktig väderlek.",severity:"warning"},{icon:"warning",title:"Fåglarna vinner om du inte skyddar",text:"Det är inte en fråga om ifall fåglarna hittar dina körsbär, utan när. Koltrastar, starar och sidensvans kan tömma ett helt träd på en dag. Enda riktiga skyddet är bärnät - häng det INNAN bären börjar rodna.",severity:"warning"},{icon:"tip",title:"Surkörsbär - den underskattade hjälten",text:"Alla drömmer om söta körsbär, men surkörsbär (Skuggmorell, Nordia) är egentligen smartare: de är härdigare, alltid självfertila, mindre fågelkänsliga och ger fantastisk saft, sylt och paj. Dessutom pollinerar de sötkörsbär!",severity:"tip"},{icon:"tip",title:"Dvärgträd - framtidens körsbärsodling",text:"Moderna dvärggrundstammar (Gisela 5) ger körsbärsträd på 2-4 meter som bär frukt redan år 2-3. Lättare att beskära, nättäcka mot fåglar och skörda. Perfekt för villaträdgården.",severity:"tip"},{icon:"warning",title:"Akta frostfickor",text:"Körsbär blommar tidigt - ofta redan i april-maj. En enda frostnatt under blomning förstör hela skörden. Plantera ALDRIG i en svacka där kall luft samlas. En sluttning med god luftcirkulation är idealisk.",severity:"warning"}],sowing:{method:"direct",label:"Plantering",description:"Körsbärsträd planteras som ympade träd. Barrotade träd planteras på hösten för bäst etablering. Krukodlade kan planteras hela säsongen.",steps:["Gräv en grop dubbelt så bred som rotsystemet men lika djup","Slå ner en stödpåle INNAN du sätter trädet","Sätt trädet med ympstället 10 cm ovan mark","Fyll igen med uppgrävd jord blandat med kompost","Packa jorden försiktigt runt rötterna","Vattna rikligt - minst 20-30 liter","Bind stammen löst mot stödpålen med mjuk bindning","Mulcha en cirkel på 1 meters radie runt stammen"],tips:["Höstplantering ger bäst etablering - rötterna växer hela vintern","Välj svagväxande grundstam (Gisela 5) för en hanterbar trädstorlek","Tänk på pollinering: behöver du en partner, eller väljer du en självfertil sort?","Plantera i en sluttning om möjligt - aldrig i en frostficka"],indoorWeeks:null},seedSaving:{difficulty:"Avancerad",type:"Ympning",biennial:!1,description:"Körsbärsträd förökas genom ympning. Att så kärnor ger ett helt nytt träd med okända egenskaper - kul som experiment men vänta 8-15 år på skörd.",steps:["Samla ympkvistar i jan-feb (vilande, ettåriga skott)","Förvara i fuktig tidning i kylskåp till april","Välj grundstam (Gisela 5 för dvärgträd, fågelbär för fullstort)","Utför kopulationsympning eller ögonympning","Skydda ympstället med ympvax","Vänta 2-4 år på första skörd"],isolation:"Ympning klonar sorten exakt - ingen korspollinering relevant.",storageYears:"Ympkvistar håller 2-3 månader i kylskåp",tip:"Gå en ympkurs! Lokala trädgårdsföreningar arrangerar kurser varje vår. Kulturarvssorter som Gårdebo och Fryksås kan vara svåra att hitta i handeln men finns som ympkvistar via pomologiska föreningar."},storage:{shelfLife:"2-7 dagar (färska), 1+ år (förädlade)",methods:[{method:"Färska i kyl",icon:"cellar",duration:"3-7 dagar",description:"Sötkörsbär håller bara några dagar i kyl. Plocka med stjälk, sprid ut i tunnt lager. Tvätta inte förrän du ska äta dem.",best:!0},{method:"Frysning",icon:"snowflake",duration:"10-12 månader",description:"Bästa sättet att bevara körsbär. Kärna ur, sprid ut på bakplåt och frys. Flytta till påsar. Perfekt till pajer, smoothies och glass.",best:!1},{method:"Saft och sylt",icon:"storage",duration:"1+ år",description:"Surkörsbärssaft är en svensk klassiker. Koka ur med socker, sila och häll på flaskor. Körsbärssylt med en gnutta mandelessens - gudomligt!",best:!1},{method:"Torkning",icon:"sun",duration:"6+ månader",description:"Kärna ur och torka i ugn (50°C, 8-10 timmar). Torkade körsbär är fantastiskt snacks och i müsli.",best:!1}],tips:["Sötkörsbär ska ätas snabbt - de tappar smak för varje dag i kylen","Plocka alltid med stjälk - körsbär utan stjälk möglar snabbare","Surkörsbär (Skuggmorell) är gjorda för saft - den bästa saften du kan göra","Frysta körsbär funkar utmärkt i matlagning men tappar sin krispighet"]},harvestCalc:{minPerSqm:5,maxPerSqm:30,unit:"kg per träd (år 5+)"},pruning:{label:"Beskärning",types:{summer:{name:"JAS-beskärning (den ENDA rätta tiden)",when:"Juli-augusti-september",description:"Körsbär och alla Prunus-arter ska BARA beskäras under JAS-perioden. Snitten torkar snabbt i sommarens värme och risken för silversjuka (Chondrostereum purpureum) sjunker dramatiskt. Vinterbeskärning är den vanligaste orsaken till silversjuka.",steps:["Ta bort döda, sjuka och korsande grenar","Ta bort rakt uppåtväxande vattenskott","Öppna kronan för ljus och luftcirkulation","Korta in årets skott till 3-4 blad","Desinficera verktygen mellan varje träd (Pseudomonas sprids via redskap)","Ta aldrig bort mer än 1/4 av kronvolymen per år"]}}},propagation:{difficulty:"Avancerad",methods:[{method:"Ympning",description:"Kvist från önskad sort fästs på grundstam (Gisela 5 för dvärgträd, fågelbär/Prunus avium för fullstort). Kopulationsympning på våren eller ögonympning i augusti.",icon:"seedling"},{method:"Frösådd (experiment)",description:"Stratifiera körsbärskärnor i kylskåp i 10-12 veckor, så i kruka. Du får ett unikt träd, men det tar 8-15 år till skörd. Fågelbär (Prunus avium) från frö ger bra grundstammar.",icon:"seed"}],tip:"Surkörsbär (Prunus cerasus) bildar rotskott som kan användas som nya plantor - det enklaste sättet att föroka dem. Gräv upp ett rotskott med rötter och plantera på ny plats."}},oa=Object.freeze(Object.defineProperty({__proto__:null,korsbar:V},Symbol.toStringTag,{value:"Module"})),L={name:"Krasse",icon:"krasse",category:"kryddor",family:"Korsblommiga",familyLatin:"Brassicaceae",perennial:!1,difficulty:"Enkel",difficultyWhy:"Världens enklaste växt att odla. Gror på 2-3 dagar, klar att skörda efter en vecka. Behöver inte ens jord - ett fuktigt hushållspapper räcker. Perfekt för barn och otåliga odlare.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:[1,2,3,4,5,6,7,8],greenhouse:[1,2,3,4,5,6,7,8]},days:"7-10",spacing:"Så tätt",spacingNote:"Mikrogrönt - strö jämnt",rowSpacing:"15 cm",depth:"Ytså",depthNote:"Strö på ytan - täck inte",ph:{min:6,max:6.8,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Flexibel. Växer bra i fönsterkarmen, på balkongen eller utomhus. Halvskugga fungerar fint - krassens korta livscykel gör att hon inte hinner bry sig om perfekta ljusförhållanden."},temperature:{min:5,max:30,ideal:"15-20°C",detail:"Gror redan vid 5°C men trivs bäst i rumstemperatur. Tål inte frost men det spelar sällan roll - de flesta odlar krasse inomhus året runt."},wind:{level:"Tålig",detail:"Skyddad odling inomhus är normen. Utomhus klarar hon lite vind, men plantorna är så späda att kraftig vind kan torka ut dem."}},watering:{need:"Hög",icon:"water",summary:"Krasse vill ha konstant fukt - fröna och de späda plantorna får ALDRIG torka ut. Vattna dagligen eller håll underlaget (papper/bomull) genomfuktigt.",phases:[{phase:"Groning (dag 1-3)",need:"Hög",tip:"Fröna måste ligga fuktigt hela tiden. Spraya med vattenspruta 1-2 gånger om dagen. De gror på bara 1-3 dagar!"},{phase:"Tillväxt (dag 3-7)",need:"Hög",tip:"Fortsätt hålla fuktigt. Plantorna är så tunna att de torkar ut på nolltid."},{phase:"Skörd (dag 7-10)",need:"Medel",tip:"Klipp med sax vid basen. Ingen återväxt - så en ny omgång istället!"}],mistakes:["Låter underlaget torka ut - fröna dör eller plantorna vissnar direkt","Övervattnar så det står vatten - kan ge mögel, särskilt inomhus"],tip:"Spraya med vattenspruta istället för att hälla - ger jämn fukt utan att skölja bort de små fröna."},soil:"Krasse behöver inte ens jord! Växer på fuktigt hushållspapper, bomull, hampmatta eller vatten. För utomhusodling fungerar vanlig trädgårdsjord utmärkt.",soilTips:["Hushållspapper på en tallrik - enklaste metoden, fungerar perfekt","Bomullstuss i en skål - klassikern för barn och skolor","Fuktig såjord i en låg kruka - ger lite kraftigare plantor","Äggskal fyllda med bomull - tradition till påsk!"],timeline:{1:[{phase:"Inomhussådd (året runt)",months:"Jan-dec",icon:"indoor"},{phase:"Utomhussådd",months:"Apr-sep",icon:"seedling"},{phase:"Skörd (7-10 dagar efter sådd)",months:"Jan-dec",icon:"harvest"}],4:[{phase:"Inomhussådd (året runt)",months:"Jan-dec",icon:"indoor"},{phase:"Utomhussådd",months:"Maj-sep",icon:"seedling"},{phase:"Skörd (7-10 dagar efter sådd)",months:"Jan-dec",icon:"harvest"}],6:[{phase:"Inomhussådd (året runt)",months:"Jan-dec",icon:"indoor"},{phase:"Utomhussådd",months:"Jun-aug",icon:"seedling"},{phase:"Skörd (7-10 dagar efter sådd)",months:"Jan-dec",icon:"harvest"}]},nutritionData:[{month:"Jan",N:2,P:1,K:1},{month:"Mar",N:2,P:1,K:1},{month:"Jun",N:2,P:1,K:1},{month:"Sep",N:2,P:1,K:1}],nutritionTips:[{timing:"Aldrig",tip:"Krasse behöver INGEN gödsling. Med en livscykel på 7-10 dagar hinner hon inte ens sakna näring. Fukt och ljus räcker."}],companions:{good:[{id:"sallat",name:"Sallat",icon:"vegetable",why:"Liknande krav på fukt och svalka. Krasse kan sås som snabb markbetäckare mellan sallatrader."},{id:"radisa",name:"Rädisa",icon:"vegetable",why:"Samma familj (korsblommiga) och liknande snabbväxande karaktär. Goda grannar i pallkragen."}],bad:[{id:"vitkal",name:"Kålväxter",icon:"vegetable",why:"Samma familj - kan dela sjukdomar vid upprepad odling på samma plats. Mest relevant vid utomhusodling."}]},rotation:{avoid:[{id:"radisa",name:"Rädisa"},{id:"vitkal",name:"Kålväxter"},{id:"broccoli",name:"Broccoli"}],avoidWhy:"Korsblommiga delar sjukdomar. Men krasse odlas nästan alltid inomhus på papper - då är växtföljd inte relevant.",goodBefore:[{name:"Allt"}],goodBeforeWhy:"Krasse tar ingenting från jorden (odlas ju oftast utan jord!).",goodAfter:[{name:"Allt"}],goodAfterWhy:"Irrelevant - krasse odlas nästan alltid i sin egen lilla värld på fönsterbrädan."},varieties:[{name:"Smörgåskrasse (standard)",zones:[1,2,3,4,5,6,7,8],note:"Klassikern med slätbladiga plantor. Snabb, pålitlig, pepprigt god. Finns hos alla svenska fröhandlare."},{name:"Cresso (krusbladig)",zones:[1,2,3,4,5,6,7,8],note:"Krusiga blad, extra vitaminrik. Snabbväxande och snygg på smörgåsen. Finns hos Impecta."},{name:"Broadleaved (storbladig)",zones:[1,2,3,4,5,6,7,8],note:"Större blad, lättare att skörda. Snabbväxande. Finns hos Impecta och Blomsterlandet."}],problems:[{name:"Mögel",symptom:"Vitt ludd på underlaget eller kring fröna, särskilt inomhus.",fix:"Bättre luftcirkulation! Täck inte helt lufttätt. Undvik att övervattna - fuktigt men inte dränkt."},{name:"Uttorkning",symptom:"Plantorna hänger och vissnar.",fix:"Krassens enda fiende. Håll underlaget konstant fuktigt - det tar bara en timme utan vatten för att förlora hela omgången."}],goodToKnow:[{icon:"tip",title:"Från frö till tallrik på 7 dagar",text:"Inget annat du kan odla kommer ens i närheten. Krasse gror på 1-3 dagar och är klar att äta efter en vecka. Omedelbar belöning för den otåliga odlaren.",severity:"tip"},{icon:"tip",title:"Behöver inte ens jord",text:"Fuktigt hushållspapper, bomull eller en våt svamp räcker. Strö på fröna, håll fuktigt, klipp efter en vecka. Enklare odling finns inte.",severity:"tip"},{icon:"tip",title:"Barnens första odling",text:'Det klassiska "första odlingsprojektet" för svenska barn. Omedelbar gratifikation, noll chans att misslyckas. Så i äggskal till påsk - en svensk tradition!',severity:"tip"},{icon:"tip",title:"Färskt året runt",text:"En av extremt få grödor du kan skörda färsk VARJE VECKA hela året, i vilken lägenhet som helst. Så en ny omgång var 5-7:e dag för obruten tillgång.",severity:"tip"},{icon:"warning",title:"Inte samma sak som indiankrasse",text:"Smörgåskrasse (Lepidium sativum, korsblommiga) och indiankrasse (Tropaeolum majus, indiankrasseväxter) är HELT olika växter som råkar dela namn och pepprig smak. Indiankrasse är en blommande klätterväxt, smörgåskrasse är mikrogrönt.",severity:"warning"}],sowing:{method:"direct",label:"Direktsådd (inomhus eller ute)",description:"Världens enklaste sådd. Strö fröna tätt på ett fuktigt underlag - hushållspapper, bomull, jord eller hampmatta. Håll fuktigt. Klipp efter 7-10 dagar. Klart.",steps:["Välj underlag: fuktigt hushållspapper på en tallrik, bomull i en skål, eller tunn jord i en kruka","Fukta underlaget ordentligt (blött men inte dränkt)","Strö fröna tätt över ytan - de ska nästan röra varandra","Spraya med vatten och ställ ljust (fönsterkarm perfekt)","Spraya dagligen - underlaget får ALDRIG torka ut","Groning på 1-3 dagar","Klipp med sax vid basen efter 7-10 dagar när plantorna är 5-10 cm"],tips:["Successionsådd var 5-7 dagar = obruten tillgång på färsk krasse","Så i äggskal med bomull till påsk - klassisk svensk tradition","Fröna är billiga - köp stort och så generöst","Ingen återväxt efter klippning - så en ny omgång istället"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Självpollinerande",biennial:!1,description:"Låt plantor växa förbi skördemogen ålder. De blommar snabbt med små vita blommor och sätter fröskidor. Skörda skidorna när de blivit ljusbruna.",steps:["Låt en omgång plantor växa vidare istället för att skörda","Plantorna blommar efter 4-6 veckor med små vita blommor","Fröskidor bildas och mognar (blir ljusbruna)","Klipp av innan skidorna öppnar sig helt","Torka i papperspåse och tröska ur fröna","Förvara torrt - hållbara 2-5 år"],isolation:"Krasse är till stor del självpollinerande. Håll bara en sort blommande åt gången för helt sortrena frön.",storageYears:"2-5 år",tip:"Men ärligt talat - krasse-frön kostar nästan ingenting. Spara frö mest för kul, inte av nödvändighet!"},storage:{shelfLife:"Bäst direkt (ingen förvaring!)",methods:[{method:"Levande på fönsterbrädan (bäst!)",icon:"indoor",duration:"Tills du klipper",description:"Låt plantorna stå och klipp efter behov. Det är den BÄSTA förvaringen - levande och färsk. Kan inte bli enklare.",best:!0},{method:"Färsk i kylskåp",icon:"water",duration:"2-3 dagar",description:"Klippt krasse i fuktig hushållspapper i kylskåp. Men den tappar krispighet snabbt - ät helst direkt.",best:!1}],tips:["Klipp bara det du behöver, låt resten stå - levande växter är bästa förvaringen","Kan varken frysas eller torkas - all smak och näring försvinner",'Successionsådd är det enda "förvaringstricket" som fungerar']},harvestCalc:{minPerSqm:.1,maxPerSqm:.3,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp med sax vid basen, 5-10 cm höga",description:"Klipp hela omgången på en gång med sax, nära basen. Varje frö ger bara en planta utan återväxt. Använd helst rå - smaken försvinner vid tillagning.",uses:[{use:"Smörgås",tip:"DEN klassiska användningen - smörgåskrasse heter det av en anledning. En skvätt krasse på en ost- eller äggsmörgås lyfter allt."},{use:"Sallad & garnering",tip:"Strö över färdiga rätter för pepprig fräschör. Vackert och gott på soppor, potatismos och ägghalvor."},{use:"Smoothies",tip:"Mixa med frukt och yoghurt. Krassens pepprighet balanseras fint av sötma."},{use:"Färskost & smör",tip:"Blanda finhackad krasse i färskost eller mjukt smör. Fantastiskt på nybakat bröd."}]}},da=Object.freeze(Object.defineProperty({__proto__:null,krasse:L},Symbol.toStringTag,{value:"Module"})),A={name:"Kronärtskocka",icon:"kronartskocka",family:"Korgblommiga",familyLatin:"Asteraceae",difficulty:"Avancerad",difficultyWhy:"Lång etableringstid, kräver förkultivering redan i januari-februari och övervintring är osäker norr om zon 3. Men lyckas du? Då ger en enda planta skördar i åratal.",zones:{outdoor:[1,2,3],indoor:null,greenhouse:[1,2,3,4]},days:"120-180",spacing:"80-100 cm",rowSpacing:"80-100 cm",depth:"1-2 cm",ph:{min:6.5,max:7.5,ideal:7},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Kronärtskockan vill ha minst 6-8 timmars direkt sol. I skugga blir plantorna rangliga och knopparna små. Hon är en medelhavsbrud som saknar solen - ge henne bästa läget du har."},temperature:{min:-10,max:30,ideal:"15-22°C",detail:"Trivs i sval till varm väderlek. Klarar lätt frost på hösten och kan med skydd övervintra ner till -10°C. Men vinterns fiende nummer ett är inte kylan - det är vätan."},wind:{level:"Skyddat",detail:"Plantorna blir 100-150 cm höga med stora blad - ett vindutsatt läge gör att stjälkarna knäcks. Södervägg eller häckskydd är perfekt."}},watering:{need:"Medel-Hög",icon:"water",summary:"Kronärtskockan tål inte uttorkning under växtsäsongen - jämn fukt är nyckeln till stora, fina knoppar. Men vintertid vill hon ha det TORRT vid rötterna.",phases:[{phase:"Förkultivering (jan-apr)",need:"Medel",tip:"Håll såjorden jämnt fuktig men aldrig blöt. Melonkrukorna gillar inte att stå i vatten."},{phase:"Etablering (maj-jun)",need:"Hög",tip:"Vattna rikligt vid utplantering och håll jämn fukt de första veckorna. Rötterna behöver etablera sig ordentligt."},{phase:"Knoppbildning (jul-aug)",need:"Medel-Hög",tip:"Kritisk period! Vattenstress nu ger små, torra knoppar. Vattna djupt 2-3 gånger i veckan."},{phase:"Höst och vinter",need:"Låg",tip:"Minska vattningen gradvis. Vintertid: torrt! Vinterväta runt rötterna dödar plantan snabbare än kyla."}],mistakes:["Vinterväta vid rötterna - vanligaste dödsorsaken för övervintrande plantor","Låta plantan torka ut under knoppbildning - ger torra, små knoppar utan smak","Vattna på bladen - de stora bladen samlar vatten som ger svampsjukdomar","Glömma vattning efter utplantering - kronärtskockan behöver tid att etablera sig"],tip:"Mulcha runt plantan med grovt material (bark, halm) för att hålla jämn fukt under sommaren. Men ta bort mulchen på hösten så rötterna inte står fuktigt under vintern."},soil:"Djup, lucker, mullrik och väldränerad jord. Hon är en riktig storätare som vill ha näringsrik mark - och dränering är livsviktigt, särskilt om du vill övervintra.",soilTips:["Arbeta ner 10 cm brunnen stallgödsel och kompost före plantering - kronärtskockan är en riktig storätare som tackar med fler och större knoppar","Kalka om pH är under 6.5 - hon trivs i neutral till svagt basisk jord","Sandjord blandad med kompost är idealt: god dränering + hög näring. Tung lerjord? Blanda in grovt sand och skapa upphöjd bädd"],timeline:{1:[{phase:"Förkultivering",months:"Jan-Mar",icon:"seedling"},{phase:"Utplantering",months:"Maj",icon:"seedling"},{phase:"Tillväxt",months:"Jun-Jul",icon:"leaf"},{phase:"Skörd (frösorter)",months:"Aug-Sep",icon:"harvest"},{phase:"Vinterskydd",months:"Nov",icon:"snowflake"}],4:[{phase:"Förkultivering",months:"Feb-Mar",icon:"seedling"},{phase:"Utplantering",months:"Jun",icon:"seedling"},{phase:"Tillväxt",months:"Jun-Jul",icon:"leaf"},{phase:"Skörd (om lyckad)",months:"Aug-Sep",icon:"harvest"},{phase:"Vinterskydd",months:"Okt-Nov",icon:"snowflake"}],6:[{phase:"Förkultivering",months:"Feb-Apr",icon:"seedling"},{phase:"Utplantering (växthus)",months:"Jun",icon:"seedling"},{phase:"Tillväxt",months:"Jul-Aug",icon:"leaf"},{phase:"Skörd (osäker)",months:"Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:50,P:30,K:20,label:"Tidig tillväxt"},{month:"Maj",N:70,P:35,K:30,label:"Vegetativ fas"},{month:"Jun",N:60,P:40,K:45,label:"Stängelbildning"},{month:"Jul",N:45,P:45,K:65,label:"Knoppbildning"},{month:"Aug",N:30,P:35,K:50,label:"Skörd"},{month:"Sep",N:10,P:15,K:20,label:"Invintring"}],nutritionTips:[{timing:"Före plantering",tip:"Grundgödsla med brunnen stallgödsel och 1 dl vedaska per planteringsplats. Kronärtskockan är en riktig storätare."},{timing:"Under tillväxtperioden",tip:"Ge flytande gödsel (nässelvatten eller kompostvatten) varannan vecka. Stora blad och höga stänglar kräver ordentligt med näring."},{timing:"Vid knoppbildning",tip:"En extra giva kaliumrik gödsel (vedaska, algbaserat) stärker stänglarna och ger fastare, finare knoppar."},{timing:"På hösten",tip:"Sluta gödsla helt från september! Kväve på hösten stör förhärdningsprocessen och gör plantan känsligare för vintern."}],companions:{good:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Kvävefixerande rötter kompenserar kronärtskockans enorma kvävebehov"},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Kan växa i skuggan av den stora plantan och utnyttjar ytan effektivt"},{id:"dill",name:"Dill",icon:"herb",why:"Lockar nyttoinsekter som äter bladlöss - kronärtskockans vanligaste plåga"},{name:"Gurkört",icon:"herb",why:"Klassisk följeslagare som förbättrar jorden och lockar pollinerande insekter"}],bad:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Båda är starkätare som konkurrerar om samma näring - ingen blir nöjd"},{id:"potatis",name:"Potatis",icon:"vegetable",why:"Konkurrerar om utrymme och näring, stör kronärtskockans kraftiga rotsystem"},{id:"lok",name:"Lök",icon:"vegetable",why:"Trivs inte tillsammans - obekant mekanism men flera odlare rapporterar dåliga resultat"}]},rotation:{avoid:[{id:"sallat",name:"Sallat"},{id:"jordartskocka",name:"Jordärtskocka"},{name:"Solros"}],avoidWhy:"Korgblommiga delar skadedjur och svampsjukdomar. Vänta minst 3-4 år. Kronärtskockan odlas dock helst permanent på sin plats i 3-5 år.",goodBefore:[{id:"bondbona",name:"Bondböna"},{id:"artor",name:"Ärtor"}],goodBeforeWhy:"Baljväxter fixerar kväve och lämnar näringsrik jord - perfekt för den hungriga kronärtskockan.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"radisa",name:"Rädisa"}],goodAfterWhy:"Rotgrönsaker och lök tillhör helt andra familjer och drar nytta av den djupt bearbetade jorden kronärtskockan lämnar efter sig."},varieties:[{name:"Imperial Star",zones:[1,2,3,4],note:"Snabbast till skörd - ger knoppar redan första året! Utvecklad för ettårig odling. Söta, stora knoppar. Drygt 1 meter hög. Runåbergs, ekologiskt frö."},{name:"Green Globe",zones:[1,2,3],note:"Den klassiska sorten sedan 1863. Stora gröna knoppar, 8-10 cm, 3-5 per planta. Beprövad och pålitlig. Sara Bäckmo har övervintrat den framgångsrikt tre år i rad!"},{name:"Herrgårds",zones:[1,2,3,4],note:"Svensk perenn sort (Grönt Kulturarv 2014)! Silvriga blad, 15-30 knoppar per år på etablerade plantor. 150 cm hög. Härdig till zon 4 enligt SLU. Säljs som plantor/delning via Elitplantstationen - ej fröäkta."},{name:"Violet de Provence",zones:[1,2],note:"Vacker grön-violett sort från södra Frankrike. Dekorativ och smakrik men kräver bra värme. Impecta."}],problems:[{name:"Svarta bladlöss",symptom:"Kolonier av svarta bladlöss samlas i de spädaste skotten och knopparna. Kladdiga blad med honungsdagg.",fix:"Spreja med tvålvatten (1 liter vatten + 0.5 dl flytande tvål). Upprepa varje vecka. Klicka bort kolonier med fingrarna. Locka nyckelpigor med dill och gurkört i närheten."},{name:"Sniglar",symptom:"Unga plantor tuggade till stump, slemspår. Allvarligt hot de första veckorna efter utplantering.",fix:"Snigelkorn (järnfosfat) runt varje planta. Fiberduk den första veckan. Ölfällor. Var extra vaksam fuktiga kvällar."},{name:"Ingen knoppbildning",symptom:"Frodig planta med stora blad men inga knopp-stänglar syns trots att det är mitt i sommaren.",fix:"Oftast för lite värme eller sen start. Förkultivera tidigt (januari!). Ge extra näring. Sorten Imperial Star är bäst för förstårsskörd."},{name:"Vinterdöd",symptom:"Plantan dyker aldrig upp på våren efter övervintring.",fix:"Vinterväta är fienden - inte kylan. Bygg regnskydd (ram med presenning) över plantan. 20-30 cm löv som isolering. Säkerställ god dränering."}],goodToKnow:[{icon:"warning",title:"Förkultivera i januari-februari",text:"Kronärtskockan behöver 120-180 dagar till skörd. Väntar du till mars-april med att så hinner du inte skörda första året. Tidig start är allt.",severity:"warning"},{icon:"warning",title:"Vinterväta dödar mer än kyla",text:"Den vanligaste orsaken till att kronärtskockor dör vintern över är inte frost utan stående vatten vid rötterna. Regnskydd och god dränering är viktigare än isolering.",severity:"warning"},{icon:"harvest",title:"Skörda i tid!",text:"Plocka knopparna medan de fortfarande är fasta och kompakta, INNAN yttre fjällen börjar öppna sig. Väntar du för länge blir de torra och tuggsega. Skär med 5-10 cm stjälk.",severity:"tip"},{icon:"tip",title:"Perenn lönar sig enormt",text:"En övervintrande planta ger 2-3 gånger fler knoppar än en fröodlad. Herrgårds-sorten kan ge 15-30 knoppar per år. Investera i övervintring om du bor i zon 1-3!",severity:"tip"},{icon:"leaf",title:"Storslagen prydnadsväxt",text:"Silvriga, djupt flikiga blad och arkitektonisk form. Även om du inte får en enda knopp är kronärtskockan en av trädgårdens vackraste plantor. Låt en knopp blomma - de lila blommorna är spektakulära.",severity:"tip"},{icon:"warning",title:"Skörden blötläggs först",text:"Lägg nypptade knoppar i ättiksvatten 30-60 minuter efter skörd - det lokkar ut eventuella insekter som gömt sig mellan fjällen.",severity:"tip"}],sowing:{method:"indoor",label:"Förkultivering inomhus",description:"Kronärtskockan MÅSTE förkultiveras i Sverige - hon behöver en lång, varm start. Så redan i januari-februari för att ge henne bästa chansen till skörd samma år.",steps:["Blötlägg fröna i ljummet vatten 12-24 timmar - förbättrar groningen avsevärt","Så i djupa krukor (10-12 cm), 1-2 cm djupt. Använd näringsrik såjord.","Ställ varmt (20-25°C) och håll jämnt fuktigt. Groningen tar 10-20 dagar - ha tålamod!","Sänk temperaturen till 15-18°C efter groning. Ge 14-16 timmars ljus - växtbelysning är nästan nödvändigt i januari-februari.","Plantera om i större kruka (1-2 liter) när plantan har 4-5 riktiga blad","Härda av gradvis under 2 veckor i maj. Kronärtskockan tål lätt frost men mjuka blad behöver tid att anpassa sig.","Plantera ut efter sista frost med 80-100 cm avstånd. Sänk plantan något djupare än den stod i krukan."],tips:["Januari-februari-start ger skörd samma år! Vänta till mars och du riskerar att missa skörden helt","Växtbelysning är nästan ett måste vid så tidig förkultivering - annars blir plantorna rangliga och svaga","Imperial Star är den enda sorten som pålitligt ger skörd redan första året"],indoorWeeks:"10-14 veckor"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!1,description:"Kronärtskockan pollineras av insekter och korsar med kardon (Cynara cardunculus). I Sverige odlas sällan kardon, så risken för oönskad korsning är liten. Herrgårds-sorten förökas INTE med frö utan genom delning.",steps:["Välj de finaste plantorna med bäst knoppbildning - de bästa generna ska föras vidare","Låt 2-3 knoppar sitta kvar och blomma ut helt. De lila blommorna är spektakulära!","Vänta tills blomhuvudet torkat och blivit brunt (september-oktober)","Klipp av de torra blomhuvudena och lägg i en papperspåse","Gnugga loss fröna - de sitter bland den torra blomfjunen","Rensa bort fjun och skräp genom att blåsa försiktigt eller använda ett såll","Torka fröna ytterligare 1-2 veckor inomhus på en tallrik","Förvara i märkt papperspåse, svalt och torrt"],isolation:"Kronärtskocka korsar med kardon men inte med jordärtskocka (annan art). I Sverige odlas sällan kardon, så risken är låg. 250-800 m isoleringsavstånd mellan sorter.",storageYears:"5-7 år",tip:"Spara frö från OP-sorter som Green Globe eller Imperial Star. Herrgårds förökas uteslutande genom delning av sidoskott på våren - det är enklare och ger sortäkta plantor direkt."},storage:{shelfLife:"1-2 veckor",methods:[{method:"Kylskåp",icon:"snowflake",duration:"1-2 veckor",description:"Skär med 5-10 cm stjälk kvar, det förlänger hållbarheten. Spraya med vatten, lägg i plastpåse med hål. Förvara i grönsakslådan.",best:!0},{method:"Inläggning (ättika)",icon:"storage",duration:"Flera månader",description:"Putsa och koka små knoppar. Lägg i ättikspad och konservera i glas. Italiensk klassiker - carciofi sott'olio!",best:!1},{method:"Frysning",icon:"snowflake",duration:"6-12 månader",description:"Putsa, blanchera 15 minuter, kyl snabbt i isvatten. Frys i portionsförpackningar. Perfekt för soppor och gratänger.",best:!1}],tips:["Skörda på morgonen när knopparna är svala - de håller sig bättre","Skär alltid med 5-10 cm stjälk - det är som en vattentank som håller knoppen fräsch","Ät färska knoppar så snart som möjligt - smaken försämras snabbt efter skörd","Blötlägg i citronsyrat vatten efter putsning - förhindrar att snittytorna mörknar"]},harvestCalc:{minPerSqm:.3,maxPerSqm:1,unit:"kg"}},ma=Object.freeze(Object.defineProperty({__proto__:null,kronartskocka:A},Symbol.toStringTag,{value:"Module"})),H={name:"Krusbär",icon:"krusbar",category:"bär",family:"Ripsväxter",familyLatin:"Grossulariaceae",perennial:!0,lifespan:"15-20 år",difficulty:"Enkel",difficultyWhy:"Extremt härdig buske som klarar kyla och halvskugga. Kräver minimal skötsel utöver årlig beskärning och lite uppmärksamhet mot mjöldagg. Taggarna är det värsta - inte svårighetsgraden.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:null},days:"60-80",spacing:"150-200 cm",rowSpacing:"200-250 cm",depth:"Något djupare än i krukan",ph:{min:5.5,max:7,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Krusbär är en av de mest skuggtåliga bärbuskarna. Full sol ger sötare bär, men halvskugga fungerar utmärkt - busken trivs faktiskt bättre i lite svalare läge. Undvik bara helskugga."},temperature:{min:-30,max:30,ideal:"15-22°C",detail:"Riktigt härdig - tål ner till -30°C utan problem. Blommar tidigt på våren, så sena nattfroster kan ta blommorna. Trivs bäst i sval sommar och ogillar hetta."},wind:{level:"Tålig",detail:"Kompakt buske som klarar vind bra. Vindskydd förbättrar pollinering och minskar uttorkning under blomning, men det är ingen krisartad fråga."}},watering:{need:"Medel",icon:"water",summary:"Krusbär har ganska grunda rötter och behöver jämn fukt, men busken är tåligare mot torka än man tror. Kritisk period är under blomning och bärutveckling - resten av året klarar hon sig mestadels själv.",phases:[{phase:"Vår (knoppsprickning)",need:"Medel",tip:"Busken drar igång tidigt. Vattna vid torr vår så att knoppar och blommor får en bra start."},{phase:"Blomning (maj-juni)",need:"Hög",tip:"Kritisk period! Vattenstress nu ger dålig fruktbildning. Vattna djupt 2 ggr/vecka vid torka - hon belönar dig med fler bär."},{phase:"Bärmognad (juni-juli)",need:"Medel-Hög",tip:"Jämn fukt ger stora, saftiga bär. Ojämn vattning kan ge att bären spricker precis innan skörd."},{phase:"Höst (efter skörd)",need:"Låg",tip:"Minska vattningen. Busken förbereder sig för vintervila och behöver inte pysslas med."}],mistakes:["Vattnar för lite under blomning - bären sätter inte frukt ordentligt","Ojämn vattning under mognad - ger sprickta bär som möglar","Glömmer nyplanterade buskar - de behöver extra omsorg första sommaren","Vattnar ovanifrån i täta buskar - fukten stannar kvar och bjuder in mjöldagg"],tip:"Mulcha runt busken med gräsklipp eller bark. Håller fukten jämn, matar maskarna och sparar dig en massa vattning. Krusbär älskar mulch - det är deras hemliga lyckopiller."},soil:"Krusbär trivs i näringsrik, fukthållande men väldränerad jord. De klarar de flesta jordtyper inklusive lerjord, bara den inte är vattensjuk. Lite tyngre jord funkar faktiskt bättre än sandiga lägen.",soilTips:["Blanda in rikligt med kompost vid plantering - krusbär uppskattar en näringsrik start","Mulcha årligen med kompost, bark eller gräsklipp - det är buskens favoritmåltid","Klarar lerjord bra men blanda i lite sand om den är riktigt tung och kompakt","Undvik extremt kalkrik jord - krusbär föredrar svagt surt till neutralt pH"],timeline:{1:[{phase:"Plantering",months:"Okt-nov eller mars-april",icon:"seedling"},{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Skörd",months:"Juli-aug",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (mars)",icon:"scissors"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],4:[{phase:"Plantering",months:"Okt eller april-maj",icon:"seedling"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Skörd",months:"Juli",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (feb-mars)",icon:"scissors"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],6:[{phase:"Plantering",months:"Maj-juni",icon:"seedling"},{phase:"Blomning",months:"Juni",icon:"bloom"},{phase:"Skörd",months:"Juli-aug",icon:"harvest"},{phase:"Beskärning",months:"Sen vinter (mars-april)",icon:"scissors"},{phase:"Vintervila",months:"Okt-april",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:4,P:2,K:2},{month:"Maj",N:6,P:4,K:3},{month:"Jun",N:5,P:5,K:6},{month:"Jul",N:3,P:4,K:8},{month:"Aug",N:2,P:3,K:5},{month:"Sep",N:1,P:2,K:3}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge en ordentlig giva brunnen gödsel eller kompost runt busken. Krusbär är inte de hungrigaste buskarna men tackar ändå för en vårstart med näring."},{timing:"Blomning (maj)",tip:"En giva kaliumrik gödsel (typ tomatgödsel) stärker blomning och bärkvalitet. Kalium ger smak och motståndskraft."},{timing:"Efter skörd",tip:"Ingen gödsling efter juli - busken ska förbereda sig för vinter, inte skjuta nya skott som inte hinner mogna."},{timing:"Höst (mulch)",tip:"Lägg på ett tjockt lager kompost eller lövmull som höstmulch. Det bryts ner under vintern och matar busken sakta inför nästa säsong."}],companions:{good:[{id:"ringblomma",name:"Ringblomma",icon:"flower",why:"Lockar pollinatörer under den kritiska blomningen. Krusbär behöver bra pollinering för full skörd - ringblommorna är som en neonskyltar för humlor."},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Fixerar kväve i jorden som bärbuskarna uppskattar. Växer upprätt och konkurrerar inte om utrymmet."},{id:"graslok",name:"Gräslök",icon:"herb",why:"Den starka doften avskräcker bladlöss och den tidiga blomningen lockar nyttoinsekter. Perfekt markskydd under buskarna."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Kan sprida svampsjukdomar som drabbar krusbärsbuskarna. Håll bra avstånd."},{id:"svarta-vinbar",name:"Svarta vinbär",icon:"berry",why:"Delar samma sjukdomar och skadedjur (mjöldagg, gallkvalster). Bättre att sprida ut Ribes-arter i trädgården istället för att klumpa ihop dem."}]},rotation:{avoid:[{id:"krusbar",name:"Krusbär"},{id:"svarta-vinbar",name:"Svarta vinbär"},{id:"roda-vinbar",name:"Röda vinbär"},{id:"vita-vinbar",name:"Vita vinbär"}],avoidWhy:"Alla Ribes-arter delar sjukdomar (mjöldagg, bladfallsjuka, gallkvalster). Plantera inte nya krusbär eller vinbär där gamla stått - vänta minst 5 år så jorden hinner bli frisk.",goodBefore:[{name:"Solig, öppen plats"},{name:"Baljväxter"},{name:"Gräsmatta"}],goodBeforeWhy:"En plats som legat som gräsmatta eller odlats med baljväxter ger frisk, kväverik jord - perfekt startplats för en krusbärsbuske.",goodAfter:[{name:"Gröngödsling"},{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodAfterWhy:"Efter 15-20 år med krusbär är jorden utarmad på näring. Gröngödsling och baljväxter bygger upp den igen."},varieties:[{name:"Invicta",zones:[1,2,3,4,5],note:"Den stora vinnaren - mjöldaggsresistent, produktiv och härdig. Gröna bär med mild, söt smak. Taggig men pålitlig."},{name:"Hinnonmäki Röd",zones:[1,2,3,4,5,6],note:"Finsk sort som tål det mesta. Rödlila bär med fantastisk smak - söta och aromatiska. Härdig och mjöldaggstålig."},{name:"Hinnonmäki Gul",zones:[1,2,3,4,5,6],note:"Systersort till den röda. Guldgula, honungssöta bär. Kanske den godaste krusbärssorten för färskning. Lika härdig."},{name:"Pax",zones:[1,2,3,4,5,6],note:"Nästan taggfri! Röda bär med bra smak. Perfekt för familjer med barn som vill plocka själva utan att riva sig."},{name:"Captivator",zones:[1,2,3,4,5],note:"Kanadensisk sort, nästan taggfri. Rödlila bär. God smak och bra sjukdomsresistens. Ger riklig skörd."}],problems:[{name:"Amerikanskt krusbärsmjöldagg",symptom:"Vitt-grått mjölaktigt belägg på unga skott, blad och bär. Bären får en brun, filtaktig yta. De värst drabbade skotten krullar ihop sig.",fix:"Välj resistenta sorter (Invicta, Hinnonmäki!). Gallra ordentligt för god luftcirkulation. Klipp bort angripna skottspetsar tidigt på säsongen. Undvik kvävegödsling sent."},{name:"Krusbärsmätarlarv",symptom:"Gröna-vita larver äter bladen systematiskt. Busken kan bli helt avlövad på några veckor om man inte reagerar. Larverna börjar inifrån busken.",fix:"Handplocka larver tidigt (kolla undersidan av bladen i maj!). Biologiskt: Bacillus thuringiensis (Bt). Vintergrävning runt busken stör pupporna."},{name:"Bladfallsjuka",symptom:"Bruna fläckar på bladen som sedan faller av i förtid. Busken tappar bladen redan i juli-augusti och försvagas.",fix:"Rensa bort nedfallna löv noggrant (svampen övervintrar där). God gallring ger bättre luftcirkulation. Friska, väl skötta buskar klarar sig bäst."},{name:"Krusbärssteklar",symptom:"Gröna larver med svarta prickar som äter bladen. Liknar krusbärsmätarlarven men ser lite annorlunda ut - samma effekt: kala grenar.",fix:"Handplocka larver tidigt - de gömmer sig gärna i buskens mitt. Kontrollera undersidan av bladen från maj. Biologiska medel med Bt fungerar."}],goodToKnow:[{icon:"warning",title:"Taggarna är på riktigt",text:"Krusbärsbuskar har vassa taggar och plockning kan vara en plågsam upplevelse. Använd tjocka trädgårdshandskar, eller välj taggfria sorter som Pax eller Captivator om du vill slippa blodiga fingrar.",severity:"warning"},{icon:"warning",title:"Mjöldagg - krusbärets ärkefiende",text:"Amerikanskt krusbärsmjöldagg är den vanligaste sjukdomen och kan förstöra hela skörden. Välj resistenta sorter (Invicta, Hinnonmäki) och gallra för luftcirkulation - det är din bästa försäkring.",severity:"warning"},{icon:"tip",title:"Skörd i två omgångar",text:"Gallringsskörd i juni (ta bort varannat bär) ger dels gröna bär till matlagning, dels utrymme för de kvarvarande att bli stora och söta till dessertbäret i juli. Dubbelvinst!",severity:"tip"},{icon:"tip",title:"Gröna vs mogna - två helt olika bär",text:"Gröna, omogna krusbär är syrliga och perfekta till sylt, gele och paj. Fullt mogna bär (gula/röda) är honungssöta och äts bäst direkt från busken. Det är som två olika frukter!",severity:"tip"},{icon:"tip",title:"Gammal svensk klassiker",text:"Krusbär var en av de vanligaste bärbuskarna i svenska trädgårdar förr - krusbärskräm med mjölk var barndomsmat för generationer. De förtjänar en comeback!",severity:"tip"},{icon:"tip",title:"Skuggtåligast av alla bär",text:"Få bärväxter klarar halvskugga lika bra som krusbär. Har du ett läge som får sol bara halva dagen? Perfekt för en krusbärsbuske - hon tackar och tar emot.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Krusbär planteras som barrotade buskar (höst eller tidig vår) eller krukodlade plantor (hela säsongen). Höstplantering ger bäst etablering - rötterna jobbar hela vintern.",steps:["Gräv en grop dubbelt så bred som rotklumpen och lika djup plus 5-10 cm","Blanda in rikligt med kompost i jorden - krusbär vill ha en näringsrik start","Plantera något djupare än busken stod i krukan - stimulerar nya skott från basen","Vattna rikligt vid plantering - riktigt genomblött","Klipp ner alla grenar till ca 15-20 cm, 3-5 knoppar per gren (det känns brutalt men det är rätt)","Mulcha med bark eller gräsklipp runt busken - men inte intill stammen"],tips:["Höstplantering (okt-nov) ger bäst etablering - rötterna jobbar medan du vilar","Klipp ner busken vid plantering - det ger en starkare, tätare buske från start","Första skörden kommer år 2, full skörd från år 3-4. Ha tålamod!"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Krusbär förökas enklast med vedartade sticklingar på hösten. Lite svårare att rota än vinbär men fortfarande fullt görbart med lite tålamod.",steps:["Klipp 20-25 cm långa sticklingar av årets mogna skott i oktober-november","Ta bort alla taggar från nedre halvan (skona fingrarna vid hanteringen)","Klipp snett i nedre änden, rakt i övre","Doppa gärna nedre änden i rotningshormon - krusbär rotar sig inte lika villigt som vinbär","Sätt sticklingarna i fuktig, sandblandad jord utomhus med 2-3 knoppar ovan mark","Vattna vid torka under vintern","Sticklingarna rotar sig under vintern/våren och kan planteras ut nästa höst"],isolation:"Vegetativ förökning - kloner av moderplantan. Ingen korspollinering relevant.",storageYears:"Ej tillämpligt",tip:"Krusbärssticklingar har lägre rotningsfrekvens än vinbärssticklingar - gör dubbelt så många som du behöver. Rotningshormon ökar chansen markant. Alternativt: nedböjning (marklager) fungerar ännu bättre."},storage:{shelfLife:"1-2 veckor (färska)",methods:[{method:"Kylskåp",icon:"snowflake",duration:"1-2 veckor",description:"Krusbär håller sig förvånansvärt länge i kylen tack vare det fasta skalet. Lägg dem i en skål med hushållspapper och tvätta inte förrän du ska använda dem.",best:!0},{method:"Frysning",icon:"snowflake",duration:"12+ månader",description:"Lägg ut bären i ett lager på bakplåtspapper, frys, flytta sedan till påse. Perfekt till sylt, paj och kräm året runt.",best:!1},{method:"Sylt och gele",icon:"storage",duration:"1+ år",description:"Krusbär har naturligt hög pektinhalt och gelerar briljant. Gröna bär ger den bästa gelen - syrlig och klargul. En skandinavisk klassiker.",best:!1},{method:"Kräm",icon:"storage",duration:"3-5 dagar (färsk), 6+ månader (fryst)",description:"Krusbärskräm med vaniljsås eller mjölk - den ultimata nostalgidesserten. Koka bären med socker, mosa lätt. Fryser utmärkt.",best:!1},{method:"Torkning",icon:"sun",duration:"6+ månader",description:"Torka i ugn på 50-60 grader i 10-14 timmar. Blir söta och lite sega. Fungerar i müsli och bakning.",best:!1}],tips:["Krusbär håller sig mycket bättre än hallon och vinbär tack vare det tjocka skalet","Gröna, omogna bär håller längst i kylen - perfekt om du skördar lite i förväg","Frys gärna både gröna (till matlagning) och mogna (till dessert) - två helt olika användningsområden","Toppa och svansa bären med en sax innan du fryser eller kokar - det är tråkigt men gör stor skillnad"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3.5,unit:"kg"},pruning:{label:"Beskärning",types:{maintenance:{name:"Underhållsbeskärning",when:"Tidig vår (feb-mars) innan knopparna svällt",description:"Krusbär bär bäst på 2-4 år gammal ved. Busken ska vara öppen och luftig - det är din bästa vapen mot mjöldagg. En frisk buske har 8-12 grenar av blandad ålder med en öppen mitt som en pokal.",steps:["Ta bort alla grenar som är 4+ år gamla (mörkare bark, grövre) vid basen","Ta bort svaga, korsande eller nedåtpekande grenar - ingenting ska hänga mot marken","Öppna upp buskens mitt ordentligt - luft och ljus ska nå in","Spara 2-3 starka nya skott från föregående år","Sikta på 8-12 grenar totalt i busken, spritt i ålder","Klipp gärna tillbaka sidoskott till 2-3 knoppar för att stimulera bärbildning"]},rejuvenation:{name:"Föryngringsbeskärning",when:"Tidig vår",description:"Gammal, tät, mjöldaggsdrabbad krusbärsbuske? Ta tag i situationen. Klipp ner hårt och bygg upp busken från grunden. Krusbär tål hård beskärning och kommer tillbaka starkare.",steps:["Klipp bort alla grenar äldre än 4 år samt alla svaga, sjuka skott","Behåll 4-5 av de starkaste unga grenarna","Korta de kvarvarande grenarna till halva längden","Gödsla med kompost och vattna ordentligt","Skörd igen från nästa år, full skörd om 2 år"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Vedartade sticklingar",description:"Klipp 20-25 cm bitar av årets mogna skott i oktober-november. Ta bort taggar från nedre halvan, doppa i rotningshormon och sätt i fuktig jord utomhus. Rotar sig under vintern. Lägre rotningsfrekvens än vinbär - gör extra sticklingar.",icon:"scissors"},{method:"Nedböjning (marklager)",description:"Det enklaste sättet för krusbär! Böj ner en låg gren och fäst den mot marken med en bygel. Täck med jord. Grenen rotar sig under säsongen och kan klippas loss och planteras om nästa höst. Nästan 100% lyckandefrekvens.",icon:"seedling"}],tip:"Nedböjning (marklager) är det säkraste sättet att föröka krusbär - grenen sitter kvar på moderplantan och får näring medan den rotar sig. Perfekt för den som vill ha garanterad framgång."}},ka=Object.freeze(Object.defineProperty({__proto__:null,krusbar:H},Symbol.toStringTag,{value:"Module"})),G={name:"Kummin",icon:"kummin",category:"kryddor",family:"Flockblommiga",familyLatin:"Apiaceae",perennial:!1,difficulty:"Enkel",difficultyWhy:"Extremt lättodlad och härdig - klarar alla svenska zoner och kräver knappt någon skötsel. Enda kravet är tålamod: kummin är tvåårig och ger fröskörd först andra året.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:[1,2,3,4,5,6,7,8],greenhouse:null},days:"Blad år 1, frö år 2 (tvåårig)",spacing:"20-25 cm",rowSpacing:"30-45 cm",depth:"0.5-1 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Full sol ger bäst arom och frösättning. Tolererar halvskugga men fröskörden blir sämre. Kummin är inte kräsen - hon växer vild på svenska ängar i all möjlig belysning."},temperature:{min:-30,max:30,ideal:"15-21°C",detail:"En av Sveriges härdigaste kryddväxter. Klarar ner till -30°C och växer vild ända upp i fjällen. Gror redan vid låga temperaturer och trivs bäst i svalare väder."},wind:{level:"Tålig",detail:"Växer vilt på öppna ängar och vägkanter - klarar vind utan problem. Kan behöva stöd om stammarna blir höga och tunga av frö."}},watering:{need:"Låg",icon:"water",summary:"Anspråkslös som få. Kummin klarar sig med den fukt som faller från himlen i de flesta av Sveriges klimat. Vattna bara vid långvarig torka.",phases:[{phase:"Groning (1-2 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig tills plantorna är uppe. Fröna gror på 10-14 dagar."},{phase:"År 1 (bladrosett)",need:"Låg",tip:"Knappt något behov. Kummin har djup pålrot och hittar vatten på egen hand. Vattna bara om det är extremt torrt."},{phase:"År 2 (blomning & frö)",need:"Låg",tip:"Jämn fukt under blomningen ger bättre frösättning, men övervattna aldrig."}],mistakes:["Övervattning - kummin avskyr vattensjuk jord, rötterna ruttnar","Stressvattnar - ojämn vattning är värre än lite torka"],tip:"Kummin är en vildväxt som sköter sig själv. Om du glömmer att vattna gör det inget - hon har klarat sig utan dig i tusentals år."},soil:"Lätt, väldränerad jord. Kummin trivs i de flesta jordar bara de inte är vattensjuka. Sandig-lerig jord fungerar utmärkt. Tung lerjord utan dränering är det enda hon inte gillar.",soilTips:["Väldränerad jord är viktigast - blanda in sand om du har tung lera","Näringsrik jord ger bättre fröskörd, men kummin klarar sig i mager jord också","Djup pålrot som luckrar jorden - kummin är en utmärkt förfrukt för andra grödor","Kalk uppskattas - strö lite trädgårdskalk om du har sur jord"],timeline:{1:[{phase:"Direktsådd",months:"Apr-maj",icon:"seedling"},{phase:"Bladrosett (år 1)",months:"Jun-sep",icon:"harvest"},{phase:"Blomning (år 2)",months:"Jun-jul",icon:"flower"},{phase:"Fröskörd (år 2)",months:"Jul-aug",icon:"seed"}],4:[{phase:"Direktsådd",months:"Maj",icon:"seedling"},{phase:"Bladrosett (år 1)",months:"Jun-sep",icon:"harvest"},{phase:"Blomning (år 2)",months:"Jun-jul",icon:"flower"},{phase:"Fröskörd (år 2)",months:"Jul-aug",icon:"seed"}],6:[{phase:"Direktsådd",months:"Jun",icon:"seedling"},{phase:"Bladrosett (år 1)",months:"Jul-sep",icon:"harvest"},{phase:"Blomning (år 2)",months:"Jul",icon:"flower"},{phase:"Fröskörd (år 2)",months:"Aug-sep",icon:"seed"}]},nutritionData:[{month:"Maj",N:2,P:1,K:1},{month:"Jun",N:4,P:2,K:2},{month:"Jul",N:3,P:3,K:3},{month:"Aug",N:2,P:2,K:2}],nutritionTips:[{timing:"Vid sådd",tip:"Lite kompost i jorden räcker gott. Kummin har lågt näringsbehov och mår bra av spartansk behandling."},{timing:"År 2 (vår)",tip:"En lätt kompostgiva kan ge bättre frösättning, men det är inget krav. Kummin klarar sig fint utan."},{timing:"Obs!",tip:"Övergödsel inte! Kummin som vildväxt klarar sig på det som finns i marken. Mager jord ger faktiskt mer aromatiskt frö."}],companions:{good:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Klassisk kombination. Baljväxter berikar jorden med kväve som kummin uppskattar till sin frösättning."},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Olika rotsystem och tidpunkter - de stör inte varandra och nyttjar jorden effektivt."},{id:"lok",name:"Lök",icon:"vegetable",why:"Olika familjer, olika rotsystem. Kummin lockar nyttoinsekter som hjälper lökodlingen."}],bad:[{id:"dill",name:"Dill",icon:"herb",why:"Samma familj (flockblommiga) - kan korsa och förstöra frösmaken. Håll avstånd!"},{id:"morot",name:"Morot",icon:"vegetable",why:"Delar sjukdomar och skadedjur inom Apiaceae-familjen."}]},rotation:{avoid:[{id:"morot",name:"Morot"},{id:"dill",name:"Dill"},{id:"persilja",name:"Persilja"},{id:"koriander",name:"Koriander"}],avoidWhy:"Flockblommiga (Apiaceae) delar sjukdomar. Vänta minst 4 år mellan kummin och andra i familjen.",goodBefore:[{name:"De flesta grödor"},{id:"potatis",name:"Potatis"}],goodBeforeWhy:"Kummins djupa pålrot luckrar jorden fantastiskt - en perfekt förfrukt som förbättrar jordstrukturen.",goodAfter:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodAfterWhy:"Baljväxter berikar jorden med kväve. Men kummin klarar sig ärligt talat var du än sätter henne."},varieties:[{name:"Kummin (standardart)",zones:[1,2,3,4,5,6,7,8],note:"Säljs som ren art - inga namngivna kultivarer behövs. Ekologiskt frö hos Runåbergs, Lindbloms och Impecta. Samma kummin som växer vild på svenska ängar."}],problems:[{name:"Kumminmal",symptom:"Fjärilslarver som äter blommor och frön. Kan förstöra hela skörden.",fix:"Insektsnät under blomningen. Plocka bort angripna flockar. Gynna naturliga fiender genom blandodling."},{name:"Morotsflugan",symptom:"Larver angriper roten (samma skadedjur som på morötter).",fix:"Insektsnät, växtföljd. Undvik att odla nära morötter och andra flockblommiga."},{name:"Rotröta",symptom:"Gulnande plantor, mjuka rötter.",fix:"Orsakas av vattensjuk jord. Förbättra dräneringen. Kummin vill ha det torrt snarare än blött."}],goodToKnow:[{icon:"tip",title:"Sveriges mest svenska krydda",text:"Kummin definierar svensk matkultur som ingen annan krydda. Knäckebröd, akvavit, kryddost, korv, surkål - kummin finns överallt. O.P. Anderson Prima Aquavit har haft kummin som huvudsmak sedan 1891.",severity:"tip"},{icon:"tip",title:"Tvåårig med dubbel nytta",text:"Kummin ger dig TVÅ skördar: späda blad att använda som krydda första året, och de aromatiska fröna andra året. Bladen smakar milt av kummin och är fina i sallad och soppa.",severity:"tip"},{icon:"tip",title:"Roten är ätbar",text:"Kummins rot kan ätas som palsternacka - en bortglömd delikatess! Koka eller stek den som vilken rotfrukt som helst. Smaken påminner om palsternacka med en fin kummindoft.",severity:"tip"},{icon:"tip",title:"Världens äldsta krydda",text:"Kummin har använts som krydda sedan stenåldern - arkeologer har hittat kumminfrön i 5000 år gamla bosättningar. Finland är ett av världens ledande exportländer för kummin - de långa sommardagarna ger frön med extra rik halt eteriska oljor.",severity:"tip"},{icon:"warning",title:"Direktså alltid - flytta aldrig kummin",text:"Kummin har en djup pålrot och HATAR att bli omflyttad. Förodling fungerar inte. Så direkt på friland - fröna gror lätt ändå.",severity:"warning"}],sowing:{method:"direct",label:"Direktsådd",description:"Kummin sås alltid direkt på friland - pålroten tål inte omplantering. Gror på 10-14 dagar. Första året bildas en bladrosett, andra året kommer blommor och frö.",steps:["Luckra jorden och kratta till jämn yta","Dra grunda spår (0.5-1 cm djupa) med 30-45 cm avstånd","Så fröet glest längs raderna","Täck med ett tunt lager jord och vattna försiktigt","Håll jämnt fuktigt tills plantorna är uppe (10-14 dagar)","Gallra till 20-25 cm avstånd när plantorna är 5 cm höga","År 2: Plantorna vaknar av sig själva och skjuter blomstjälkar i juni"],tips:["Höstsådd (aug-sep) i zon 1-3 ger plantorna ett försprång till år 2","Kummin självsår sig gärna - låt några fröställningar stå kvar så har du ny kummin varje år","Sår du varje år får du en löpande skörd: blad från årets plantor, frö från fjolårets"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Insektspollinerad",biennial:!0,description:"Kumminfrön ÄR skörden - fröbesparing och kryddskörd är samma sak! Klipp fröställningarna när de börjar bruna och låt eftertorka i papperspåse.",steps:["Vänta tills frökapslarna börjar bruna (juli-augusti, år 2)","Klipp hela fröställningarna innan alla frön faller av","Bind ihop och häng i papperspåse med öppningen nedåt","Fröna faller ner i påsen av sig själva under torkningen","Rensa bort skräp och förvara torrt i glasburk","Spara en del som utsäde, använd resten i köket!"],isolation:"Håll kummin borta från dill och fänkål vid frötagning. De tillhör samma familj och pollinatörer rör sig mellan dem, vilket kan ge frön med förändrad smak. Äkta korsning mellan dessa släkten är osannolik, men separation rekommenderas för sortrena frön.",storageYears:"2-3 år",tip:"En planta ger massor av frön - mer än du behöver för både matlagning och utsäde. Dela med odlarkompisar!"},storage:{shelfLife:"Färska blad 3-5 dagar, hela frön 2-3 år",methods:[{method:"Hela frön (bäst!)",icon:"seed",duration:"2-3 år",description:"Förvara i lufttät glasburk, svalt och mörkt. Hela frön behåller aromen fantastiskt länge. Krossa eller mal först vid användning.",best:!0},{method:"Mald kummin",icon:"storage",duration:"6-12 månader",description:"Tappar arom snabbt efter malning. Mal alltid vid behov istället för att köpa färdigmald.",best:!1},{method:"Färska blad (år 1)",icon:"water",duration:"3-5 dagar",description:"Använd helst färska direkt i sallad eller soppa. Kan frysas i isbitsfack med vatten.",best:!1}],tips:["Hela frön i glasburk - mer arom kvar efter ett år än nymald kummin efter en månad","Rosta i torr panna före malning - frigör de eteriska oljorna och ger djupare smak","Kummins rot kan förvaras som palsternacka i kylskåp eller jordkällare"]},harvestCalc:{minPerSqm:.05,maxPerSqm:.15,unit:"kg frö"},harvest:{label:"Skörd & användning",method:"Blad år 1, fröskörd år 2 när kapslarna brunar",description:"År 1: Plocka späda blad till sallad och soppa. År 2: Skörda fröställningarna när de börjar bruna men inte helt öppnat sig - då har du maximal arom.",uses:[{use:"Knäckebröd & rågbröd",tip:"DEN klassiska användningen. Blanda hela eller krossade frön i bröddegen. Svenskare blir det inte."},{use:"Akvavit & snaps",tip:"Kummin är huvudkryddan i svensk akvavit. Gör egen kryddsnaps: ett par teskedar kumminfrö i en flaska brännvin, låt dra 1-2 veckor."},{use:"Ost & korv",tip:"Kryddost med kummin är en nordisk klassiker. Blanda i hemgjord färskost eller strö över gratinerad potatis."},{use:"Kål & rotsaker",tip:"Kummin och kål är bästa vänner - hela frön i surkål, stuvad vitkål eller rostad palsternacka."}]}},ga=Object.freeze(Object.defineProperty({__proto__:null,kummin:G},Symbol.toStringTag,{value:"Module"})),D={name:"Lagerblad",icon:"lagerblad",category:"kryddor",family:"Lagerväxter",familyLatin:"Lauraceae",perennial:!0,difficulty:"Avancerad",difficultyWhy:"Lagerblad är en medelhavsbuske som inte är vinterhärdig i Sverige. Hon måste odlas i kruka och tas in varje höst. Inte svår att hålla vid liv om du har en ljus, sval plats att övervintras på - men det kräver planering och utrymme.",zones:{outdoor:null,indoor:[1,2,3,4,5,6,7,8],greenhouse:[1,2,3]},days:"Löpande bladskörd från år 2",spacing:"1 per kruka",spacingNote:"Minst 30 cm diameter",rowSpacing:"-",depth:"1 cm",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Lagerblad vill ha så mycket sol som möjligt under sommaren - minst 6-8 timmar om dagen. Ställ henne utomhus på den soligaste platsen du har. Tolererar halvskugga men blir glesare och mindre aromatisk."},temperature:{min:-5,max:35,ideal:"15-25°C",detail:"En medelhavsväxt som klarar kortvarig frost ner till -5°C men inte svenska vintrar. Övervintras ljust och svalt inomhus vid 5-10°C. Temperatursvängningar gör henne stressad - flytta inte fram och tillbaka i onödan."},wind:{level:"Skyddat",detail:"Föredrar ett skyddat läge, gärna vid en södervägg som ger extra värme och vindskydd. Kall nordanvind i kombination med frost är hennes värsta fiende."}},watering:{need:"Medel",icon:"water",summary:"Lagerblad vill ha rejäla vattningar men måste få torka upp lite emellan. Tänk medelhavsklimat: kraftiga regnskurar följda av soliga, torra dagar.",phases:[{phase:"Sommar (aktiv tillväxt)",need:"Medel",tip:"Vattna rejält så hela jordklumpen blir genomblöt, låt sedan torka upp något innan nästa vattning. Fingret i jorden 2-3 cm ner - torrt? Dags att vattna."},{phase:"Höst (inför övervintring)",need:"Låg",tip:"Minska vattningen gradvis när du tar in henne. Hon ska trappa ner och förbereda sig för vila."},{phase:"Vinter (vila)",need:"Låg",tip:"Vattna sparsamt - kanske varannan vecka. Jorden ska inte vara knastertorr, men heller aldrig blöt. Kall, fuktig jord = rotröta."},{phase:"Vår (uppvakning)",need:"Medel",tip:"Öka vattningen sakta när dagarna blir längre och hon börjar skjuta nya skott."}],mistakes:["Övervattnar under vintern - den absolut vanligaste dödsorsaken för kruklager i Sverige","Ställer henne på ett fat med stående vatten - rötterna ruttnar","Glömmer att vattna under sommaren när hon står ute i full sol och avdunstningen är hög"],tip:"Låt alltid överskottsvatten rinna av. Lagerblad i kruka vill aldrig stå i vatten - men torka ut helt ska hon inte heller göra."},soil:"Väldränerad jord är viktigast. Blanda vanlig planteringsjord med perlit eller grus så vattnet rinner igenom snabbt. Medelhavsjord från trädgårdshandeln fungerar utmärkt.",soilTips:["Blanda 2 delar planteringsjord med 1 del perlit eller grus för perfekt dränering","Lägg ett lager lecakulor eller krukskärvor i botten av krukan","Omplanteras inte ofta - byt jord vart 3-4 år eller toppdress med ny jord","Undvik torv som enda substrat - den blir vattenstötande när den torkar ut"],timeline:{1:[{phase:"Ut på balkong/terrass",months:"Maj",icon:"seedling"},{phase:"Skörd löpande",months:"Maj-okt",icon:"harvest"},{phase:"Beskärning",months:"Apr",icon:"flower"},{phase:"In för övervintring",months:"Okt",icon:"indoor"}],4:[{phase:"Ut på balkong/terrass",months:"Jun",icon:"seedling"},{phase:"Skörd löpande",months:"Jun-sep",icon:"harvest"},{phase:"Beskärning",months:"Apr-maj",icon:"flower"},{phase:"In för övervintring",months:"Sep",icon:"indoor"}],6:[{phase:"Ut (skyddat läge)",months:"Jun-jul",icon:"seedling"},{phase:"Skörd löpande",months:"Jul-aug",icon:"harvest"},{phase:"Beskärning",months:"Maj",icon:"flower"},{phase:"In för övervintring",months:"Aug-sep",icon:"indoor"}]},nutritionData:[{month:"Apr",N:3,P:2,K:2},{month:"Maj",N:5,P:3,K:3},{month:"Jun",N:6,P:3,K:4},{month:"Jul",N:5,P:3,K:4},{month:"Aug",N:4,P:2,K:3},{month:"Sep",N:2,P:1,K:2}],nutritionTips:[{timing:"Vår (april-maj)",tip:"Ge en lätt giva flytande näring när hon vaknar och börjar skjuta nya blad. Eko-gödsel för krukväxter fungerar bra."},{timing:"Sommar (juni-aug)",tip:"Gödsla varannan vecka med svag dos flytande näring. Lagerblad är ingen storätare men uppskattar regelbunden, modest matning."},{timing:"Höst-vinter",tip:"Sluta gödsla helt från september. Hon ska vila, inte växa. Ny näring i kall jord gör mer skada än nytta."}],companions:{good:[{id:"timjan",name:"Timjan",icon:"herb",why:"Båda mediterrana och trivs i samma soliga, torra förhållanden. Perfekt sällskap i en medelhavskrukgrupp på balkongen."},{id:"rosmarin",name:"Rosmarin",icon:"herb",why:"Samma krav på sol, dränering och övervintring. De delar livsstil och kan stå sida vid sida hela året."},{id:"salvia",name:"Salvia",icon:"herb",why:"Ännu en medelhavsgranne som vill ha exakt samma behandling. Tillsammans bildar de bouquet garni-trion."}],bad:[{id:"basilika",name:"Basilika",icon:"herb",why:"Basilika vill ha rik, fuktig jord och massor av vatten. Raka motsatsen till vad lagerblad behöver."},{id:"mynta",name:"Mynta",icon:"herb",why:"Mynta är aggressiv, fuktälskande och tar över varje kruka den kommer i närheten av."}]},rotation:{avoid:[{name:"Inte relevant"}],avoidWhy:"Lagerblad odlas i kruka och står på samma plats i många år. Växtföljd är inte relevant.",goodBefore:[{name:"Inte relevant"}],goodBeforeWhy:"Perenn krukväxt - växtföljd gäller inte.",goodAfter:[{name:"Inte relevant"}],goodAfterWhy:"Perenn krukväxt - växtföljd gäller inte."},varieties:[{name:"Laurus nobilis (vanlig lagerbuske)",zones:[1,2,3,4,5,6,7,8],note:'Den enda arten som odlas. Köps enklast som färdig planta från trädgårdshandeln. Säljs som "lagerträd" eller "äkta lager". Alla plantor ger samma aromatiska blad.'},{name:"Aurea (guldlager)",zones:[1,2,3],note:"Dekorativ sort med gyllene unga blad som mörknar med åldern. Samma arom som den gröna. Lite mer värmekrävande och passar bäst i zon 1-3."}],problems:[{name:"Sköldlöss",symptom:'Bruna, ovala "prickar" som sitter fast på undersidan av bladen och längs grenarna. Klibbigt, blankt utsöndrat socker (honungsdagg).',fix:"Skrapa bort manuellt med nageln eller en gammal tandborste. Behandla med rapsolja-baserat medel. Kontrollera regelbundet - de är svåra att bli av med helt."},{name:"Bladlöss",symptom:"Små gröna eller svarta insekter på unga skott. Krusade, deformerade nya blad.",fix:"Spola av med hård vattenstråle. Behandla med såpvatten (1 tsk flytande tvål per liter vatten). Gynna nyckelpigor utomhus."},{name:"Brunfläckiga blad (övervattning)",symptom:"Bruna, mjuka fläckar på bladen. Gulnande blad som faller av. Dålig lukt från jorden.",fix:"Minska vattningen omedelbart. Låt jorden torka upp. Kontrollera dräneringen - finns det hål i botten? Byt jord om den luktar illa."},{name:"Frost-/kylskada",symptom:"Bruna, torra blad efter en kall natt. Bark som spricker. Hela grenar som dör.",fix:"Klipp bort skadat material på våren och vänta. Lagerblad kan ofta återhämta sig från roten om stammen klarat sig. Flytta in henne tidigare nästa höst."}],goodToKnow:[{icon:"warning",title:"Övervintring är nyckeln",text:"Lagerblad klarar INTE svensk vinter utomhus. Ta in henne i ett ljust, svalt rum (5-10°C) innan första frosten. Ouppvärmd glasveranda, trappuppgång eller garage med fönster funkar perfekt.",severity:"warning"},{icon:"warning",title:"Inte i vardagsrummet",text:"Vanligt misstag: ställa lagerbusken i varmt vardagsrum vintertid. Hon vill ha SVALKA och vila, inte 22°C och torr luft. Resultatet blir sköldlöss och tappade blad.",severity:"warning"},{icon:"tip",title:"Torkade blad är smakrikare",text:"Färska lagerblad är ganska milda. Det är först efter 1-2 veckors torkning som de eteriska oljorna koncentreras och den klassiska lagerbladsdoften och smaken utvecklas fullt ut.",severity:"tip"},{icon:"tip",title:"Bouquet garni-klassikern",text:"Lagerblad, timjan och persilja - bundna ihop med en bit bomullssnöre. DEN klassiska franska kryddbuketten som gör varje gryta, soppa och buljong till något alldeles extra.",severity:"tip"},{icon:"tip",title:"Gammal symbolväxt",text:'Lagerkransen var den högsta utmärkelsen i antikens Grekland och Rom. Ordet "laureat" (som i Nobelpristagare) kommer från Laurus. En växt med 3000 års historia i din kruka!',severity:"tip"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Lagerblad är extremt långsam att dra från frö - groningen kan ta månader och växten behöver år innan den är användbar. Köp en färdig planta istället! Det sparar dig bokstavligen åratal av väntan.",steps:["Köp en liten lagerbuske (Laurus nobilis) i trädgårdshandeln (absolut enklast)","Plantera om i en kruka med bra dränering - lecakulor i botten, perlit i jorden","Ställ ljust och soligt inomhus eller utomhus (efter sista frost)","Börja plocka enstaka blad efter att plantan etablerat sig (första sommaren)","Ta in före första frosten på hösten till ljust, svalt utrymme (5-10°C)","Beskär på våren för att hålla formen kompakt och stimulera nya skott"],tips:["Köp planta, inte frö. Lagerblad från frö tar 1-2 månader att gro och flera år innan den ger användbar skörd","Sticklingar fungerar men tar 3-6 månader att rota sig. Halvförvedad skott på sensommaren ger bäst resultat","Beskärningsrester kan torkas och användas som krydda direkt!"],indoorWeeks:null},seedSaving:{difficulty:"Avancerad",type:"Insektspollinerad",biennial:!1,description:"Lagerblad blommar sällan i svensk odling och sätter ännu mer sällan frö. Förökning genom sticklingar är mycket mer praktiskt. Fröna behöver dessutom stratifiering (köldbehandling) för att gro.",steps:["Lagerblad är tvåbyggare - du behöver både han- och honplanta för frukt","Blomning sker sällan inomhus i Sverige - kräver somrar utomhus i skyddat, varmt läge","Om bären bildas: vänta tills de är helt svarta och mogna (oktober-november)","Rensa bort fruktköttet och tvätta fröna","Stratifiera: lägg fröna i fuktig sand i kylen i 4-6 veckor","Så i fuktig jord vid 15-20°C. Groning kan ta 1-6 månader!"],isolation:"Inte relevant i Sverige - lagerblad blommar sällan och det finns bara en art.",storageYears:"1 år (grobarhet sjunker snabbt - använd färskt frö)",tip:"Glöm frö - ta sticklingar istället. Klipp 10-15 cm halvförvedad gren på sensommaren, doppa i rothormon och sätt i fuktig perlit. Mycket enklare och snabbare."},storage:{shelfLife:"Färska blad 2-4 veckor, torkade 1-2 år",methods:[{method:"Torkning (bäst!)",icon:"storage",duration:"1-2 år",description:"Lägg bladen på ett nät eller häng kvistar i en torr, mörk plats. Torka i 1-2 veckor. Torkade lagerblad är faktiskt smakrikare än färska - de eteriska oljorna koncentreras.",best:!0},{method:"Färsk i kyl",icon:"water",duration:"2-4 veckor",description:"Lägg bladen i en plastpåse eller burk i kylen. Lagerbladets läderartade blad håller sig förvånansvärt länge färska.",best:!1},{method:"Frysning",icon:"snowflake",duration:"6+ månader",description:"Lägg hela blad i fryspåse. Kan användas direkt från frysen i grytor och soppor.",best:!1}],tips:["Torkade lagerblad i lufttät burk, mörkt och svalt - håller sig i 1-2 år med bibehållen arom","Knäck eller vik bladet innan du lägger det i grytan - frigör mer smak","Ta ALLTID bort lagerbladet innan servering - de blir aldrig mjuka och kan fastna i halsen","Byt ut dina torkade lagerblad en gång om året - efter det tappar de smak"]},harvestCalc:{minPerSqm:.05,maxPerSqm:.15,unit:"kg"},harvest:{label:"Skörd & användning",method:"Plocka enstaka blad löpande, välj mogna (mörkgröna) blad",description:"Plocka blad efter behov under hela växtsäsongen. Välj de mörkgröna, fullt utvecklade bladen - de har mest smak. Plocka inte mer än en tredjedel av bladen åt gången så busken mår bra.",uses:[{use:"Grytor & soppor",tip:"DEN klassiska användningen. Lägg ett lagerblad i varje gryta, soppa eller buljong. Smaken är subtil men gör enorm skillnad - testa att laga samma rätt med och utan."},{use:"Marinader",tip:"Lagerblad i marinader för kött och fisk ger en fin, djup smak. Krossa bladet lite först så de eteriska oljorna frigörs snabbare."},{use:"Inläggningar",tip:"Lagerblad i ättikslag för inlagd gurka, rödbetor och sill. En svensk klassiker som ger karaktär och djup."},{use:"Mjölksås & bechamel",tip:"Värm mjölken med ett lagerblad innan du gör sås. Subtilt men fantastiskt - det lilla extra som gör en enkel gräddsås till magi."}]}},pa=Object.freeze(Object.defineProperty({__proto__:null,lagerblad:D},Symbol.toStringTag,{value:"Module"})),N={name:"Libbsticka",icon:"libbsticka",category:"kryddor",family:"Flockblommiga",familyLatin:"Apiaceae",perennial:!0,lifespan:"10-20+ år",difficulty:"Enkel",difficultyWhy:"Libbsticka är en av de mest lättskötta kryddväxterna du kan ha. Extremt härdig, klarar alla svenska zoner, växer som ogräs och ger massvis med blad utan att kräva mycket till. Den enda utmaningen? Att hålla henne i schack - en etablerad libbsticka kan bli 2 meter hög!",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:[1,2,3,4,5,6,7,8],greenhouse:null},days:"75-90 (bladskörd från år 1, full skörd år 2)",spacing:"40-60 cm",rowSpacing:"60-90 cm",depth:"1-2 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun-half",detail:"Libbsticka trivs i full sol men tolererar halvskugga utmärkt. Faktum är att bladen smakar mildare och sötare i halvskugga, medan full sol ger mer intensiv arom. Perfekt växt för den där lite skuggiga hörnan där inget annat vill växa."},temperature:{min:-35,max:30,ideal:"15-25°C",detail:"Stenhård! Libbsticka klarar ner till -35°C utan problem. Hon är en av Sveriges härdigaste kryddväxter och övervintrar pålitligt i alla zoner. På våren är hon en av de första att sticka upp - ofta redan i mars i södra Sverige."},wind:{level:"Tålig",detail:"Libbstickans kraftiga, ihåliga stammar kan nå 2 meter och svaja i blåsten. Hon klarar vind men uppskattar ett skyddat läge - framför allt för att höga stammar inte ska knäckas. Kan behöva stöd i blåsiga lägen."}},watering:{need:"Medel",icon:"water",summary:"Libbsticka har en djup pålrot och är ganska torktålig när hon väl etablerat sig. Men hon föredrar jämnt fuktig jord - torka ger bittra blad. Tänk skogsglänta: aldrig knastertorrt, aldrig vattensjukt.",phases:[{phase:"Etablering (år 1)",need:"Medel",tip:"Håll jämnt fuktigt det första året så roten hittar ner ordentligt. Mulcha gärna runt plantan."},{phase:"Etablerad planta (sommar)",need:"Låg-Medel",tip:"Den djupa pålroten hittar vatten på egen hand. Vattna bara vid långvarig torka. Torrt väder ger tyvärr bittra blad - om du vill ha fin smak, ge lite extra vid hetta."},{phase:"Vinter",need:"Låg",tip:"Plantan är nerklipt och vilar under marken. Ingen vattning behövs."}],mistakes:["Vattensjuk jord - libbsticka har djup pålrot som ruttnar i stående vatten","Låter jorden torka ut helt under sommaren - bladen blir bittra och dåliga att använda som krydda","Glömmer att vattna under första året - etableringsperioden är viktig"],tip:"Mulcha med kompost eller gräsklipp runt plantan. Håller fukten jämn, matar jorden sakta och förbättrar jordstrukturen - allt libbsticka älskar."},soil:"Djup, mullrik och väldränerad jord. Libbsticka trivs bäst i näringsrik lerjord men klarar de flesta jordar. Det viktigaste är att jorden är djup nog för hennes imponerande pålrot.",soilTips:["Gräv ordentligt djupt vid plantering - pålroten vill ner minst 30-40 cm","Blanda in rikligt med kompost i planteringsgropen - libbsticka är en storätare jämfört med de flesta kryddor","Mulcha varje vår med en tjock giva kompost - hon tackar med frodigare tillväxt","Fungerar i kruka men välj en rejält djup (minst 40 cm) - annars trivs hon inte"],timeline:{1:[{phase:"Förodling inomhus",months:"Mars-april",icon:"indoor"},{phase:"Utplantering/direktsådd",months:"Maj",icon:"seedling"},{phase:"Bladskörd löpande",months:"Maj-okt",icon:"harvest"},{phase:"Blomning",months:"Jul-aug",icon:"flower"},{phase:"Fröskörd",months:"Aug-sep",icon:"seed"}],4:[{phase:"Förodling inomhus",months:"April",icon:"indoor"},{phase:"Utplantering/direktsådd",months:"Maj-jun",icon:"seedling"},{phase:"Bladskörd löpande",months:"Jun-sep",icon:"harvest"},{phase:"Blomning",months:"Jul-aug",icon:"flower"},{phase:"Fröskörd",months:"Sep",icon:"seed"}],6:[{phase:"Förodling inomhus",months:"April",icon:"indoor"},{phase:"Utplantering",months:"Jun",icon:"seedling"},{phase:"Bladskörd löpande",months:"Jul-sep",icon:"harvest"},{phase:"Blomning",months:"Aug",icon:"flower"}]},nutritionData:[{month:"Apr",N:4,P:2,K:2},{month:"Maj",N:6,P:3,K:3},{month:"Jun",N:7,P:3,K:4},{month:"Jul",N:5,P:4,K:4},{month:"Aug",N:4,P:3,K:3},{month:"Sep",N:2,P:2,K:2}],nutritionTips:[{timing:"Tidig vår",tip:"Ge en rejäl giva kompost eller brunnen kogödsel när hon vaknar i mars-april. Libbsticka är en av få kryddor som faktiskt gillar att bli bortskämd med näring."},{timing:"Försommar",tip:"En giva nässelvatten i juni ger kraftig bladtillväxt. Libbsticka svarar bra på kvävegödsel till skillnad från de flesta medelhavskryddor."},{timing:"Obs!",tip:"Libbsticka i kruka behöver mer gödsel än i friland - rötterna kan inte leta sig ut. Ge flytande näring varannan vecka under sommaren."}],companions:{good:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Libbstickans starka doft avskräcker bladlöss och spinnkvalster. Plantera i norra kanten av tomatbädden så hon inte skuggar."},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Baljväxter fixerar kväve som den storätande libbstickan tacksamt tar del av."},{id:"timjan",name:"Timjan",icon:"herb",why:"Timjans låga växtsätt kompletterar libbstickans höjd. De stör inte varandra och lockar tillsammans massor av pollinerare."}],bad:[{id:"morot",name:"Morot",icon:"vegetable",why:"Samma familj (Apiaceae) - delar sjukdomar och skadedjur. Morotsflugan kan flytta mellan dem."},{id:"dill",name:"Dill",icon:"herb",why:"Samma familj. Dessutom konkurrerar dill dåligt med libbstickans massiva storlek."}]},rotation:{avoid:[{id:"morot",name:"Morot"},{id:"dill",name:"Dill"},{id:"persilja",name:"Persilja"},{id:"palsternacka",name:"Palsternacka"}],avoidWhy:"Flockblommiga (Apiaceae) delar jordburna sjukdomar. Men libbsticka är perenn och bör stå kvar på samma plats i 10-15 år - flytta bara om plantan blivit för stor.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodBeforeWhy:"Baljväxter berikar jorden med kväve. Libbstickans djupa pålrot luckrar sedan jorden fantastiskt.",goodAfter:[{name:"Kål"},{id:"lok",name:"Lök"}],goodAfterWhy:"När libbsticka till slut tas bort efter 10-15 år lämnar pålroten djupa kanaler i jorden. Perfekt för kål och lök som uppskattar luckrad jord."},varieties:[{name:"Libbsticka (standardart)",zones:[1,2,3,4,5,6,7,8],note:"Det finns i princip bara en sort i odling - arten i sig. Ekologiskt frö hos Lindbloms (Demeter-certifierat) och Impecta. NordFrö säljer också frö odlat utan syntetiska bekämpningsmedel. Alla ger samma kraftfulla, sellerilikande smak."}],problems:[{name:"Sellerifluga",symptom:"Bruna, pappersliknande fläckar i bladen där larverna minerar (äter sig fram inuti bladet). Två generationer per år.",fix:"Klipp bort angripna blad. Insektsnät under våren och sensommaren. Samma skadedjur som på selleri och palsternacka - växtföljd hjälper."},{name:"Bladlöss",symptom:"Gröna eller svarta löss på unga skott på våren. Klibbig honungsdagg.",fix:"Spola av med hård vattenstråle. Libbsticka är så kraftig att hon oftast växer ifrån angreppen. Gynna nyckelpigor och blomflugor."},{name:"Mjöldagg",symptom:"Vitt puder på bladen vid torrt väder och dålig luftcirkulation.",fix:"Klipp bort angripna delar. Gallra för bättre luftcirkulation. Libbsticka skjuter snabbt nya friska blad."}],goodToKnow:[{icon:"tip",title:"Maggikryddan!",text:'Libbsticka kallas "Maggikraut" (maggiört) på tyska - smaken och doften påminner slående om Maggis buljongkrydda. Men roliga faktumet: Maggi innehåller faktiskt ingen libbsticka! Libbsticka innehåller naturligt glutamat, därav den umami-rika smaken.',severity:"tip"},{icon:"tip",title:"Munkarnas krydda",text:"Libbsticka fördes till Sverige av munkar under medeltiden och odlades i klosterträdgårdarna. Förr stod det en libbsticka vid varje husmodersköksdörr - ett blad i grytan ersatte dyra buljongkryddor.",severity:"tip"},{icon:"tip",title:"Hela växten är ätbar",text:"Inte bara bladen! Roten kan kokas eller stekas som rotfrukt (smakar som kraftig selleri). Fröna används som krydda (som sellerifrö). Stjälkarna kan kanderas som konfekt!",severity:"tip"},{icon:"warning",title:"Hon blir STOR",text:"En etablerad libbsticka blir 2 meter hög och bred som en buske. Planera för det! Ge henne en plats i norra kanten av trädgårdslandet så hon inte skuggar allt annat. Klipp ner blommorna om du vill hålla henne lite i styr.",severity:"warning"},{icon:"tip",title:"Pollinatorernas favorit",text:"Libbstickans gula flockblommor är fantastiska för nyttoinsekter - speciellt parasitsteklar och blomflugor som äter bladlöss. En libbsticka i trädgården ger biologisk skadedjursbekämpning på köpet.",severity:"tip"}],sowing:{method:"both",label:"Direktsådd eller förodling",description:"Libbsticka kan förodlas inomhus eller sås direkt. Fröna gror ojämnt och långsamt (2-3 veckor), men det enklaste sättet att starta är att dela en befintlig planta - fråga en odlarkompis! En vuxen libbsticka kan enkelt delas i 3-4 bitar.",steps:["Förodling: Så 1-2 cm djupt i fuktig såjord i mars-april","Håll jämnt fuktigt och varmt (15-21°C)","Groning tar 14-21 dagar och sker ojämnt - ha tålamod","Gallra eller flytta plantorna till egna krukor vid 5 cm höjd","Härda av 1 vecka innan utplantering efter sista frost","Plantera ut med 40-60 cm avstånd - ge henne utrymme att växa!","Alternativ: Direktså utomhus i maj-juni, 1-2 cm djupt"],tips:["Delning av en etablerad planta på våren är det absolut enklaste sättet att starta. Gräv upp, dela med spade, plantera direkt","Färska frön gror mycket bättre än gamla - grobarhet sjunker snabbt. Köp nytt frö varje år","Höstsådd (september) direkt utomhus kan ge bättre groning - kylbehandlingen över vintern bryter fröets dvala naturligt"],indoorWeeks:"6-8 veckor före utplantering"},seedSaving:{difficulty:"Enkel",type:"Insektspollinerad",biennial:!1,description:"Libbsticka sätter gott om frö från och med år 2-3. Fröna mognar på sensommaren och kan samlas in genom att klippa av hela fröställningarna när de börjar bruna.",steps:["Låt 1-2 fröställningar mogna helt på plantan (augusti-september)","Klipp av när fröna börjar bruna men innan de faller av","Häng uppochner i papperspåse på torr plats","Fröna faller ner i påsen av sig själva under torkning","Rensa och förvara torrt i glasburk eller kuvert","Så helst samma höst eller nästa vår - grobarhet sjunker snabbt"],isolation:"Libbsticka är ensam i sitt släkte (Levisticum) i svensk odling - ingen risk för korspollinering med andra arter. Enda arten i sin familj hon kan korsa med finns inte i våra trädgårdar.",storageYears:"1-2 år (använd helst färskt frö)",tip:"Libbsticka självsår sig gärna om du låter fröna falla. Rensa bort oönskade plantor på våren - annars har du snart en hel libbstickskog!"},storage:{shelfLife:"Färska blad 3-5 dagar, torkade 6-12 månader",methods:[{method:"Frysning (bäst!)",icon:"snowflake",duration:"6+ månader",description:"Frysning bevarar libbstickans smak och arom bäst. Hacka bladen och frys i isbitsfack med vatten. Eller frys hela blad i påse - plocka efter behov rakt i grytan.",best:!0},{method:"Torkning",icon:"storage",duration:"6-12 månader",description:"Häng knippen uppochner på mörk, luftig plats i 1-2 veckor. Smaken ändras lite vid torkning - blir mer koncentrerad men förlorar en del fräschör. Fortfarande utmärkt som krydda.",best:!1},{method:"Färsk i kyl",icon:"water",duration:"3-5 dagar",description:"Ställ stjälkarna i ett glas vatten i kylen - som en bukett. Eller linda i fuktigt hushållspapper i plastpåse.",best:!1}],tips:["Frys portionsvis i isbitsfack - ett fack = en grytas behov av libbsticka","Roten kan skivas och torkas som krydda - stark selleriartad smak","Fröna kan användas hela som krydda, liknar sellerifrö i smak","En planta ger mer blad än du någonsin kan använda - dela med grannar och vänner!"]},harvestCalc:{minPerSqm:.5,maxPerSqm:1.5,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp bladkluster löpande, aldrig mer än halva plantan",description:"Skörda genom att klippa bladkluster med stjälk. Libbsticka är generös - hon skjuter snabbt nya skott efter skörd. Unga, ljusgröna blad har mildast smak, äldre mörkgröna blad är kraftigare.",uses:[{use:"Soppor & buljonger",tip:"DEN klassiska användningen. Ett enda blad ger en hel gryta den där djupa, umami-rika smaken som förr krävde buljongkuber. Mormors hemliga ingrediens!"},{use:"Potatis & rotfrukter",tip:"Finstrimla blad i potatissallad, potatissoppa eller rotsaksgryta. Libbsticka och potatis är ett odödligt par."},{use:"Smör & ost",tip:"Hacka fint och blanda i smör eller färskost. Libbstickesmör på nykokt potatis - rent trädgårdslyx."},{use:"Smoothies & drinkar",tip:"Oväntat men fantastiskt! Ett par blad i en grön smoothie ger en selleriartad, salt-umami ton. Eller muddla med gin och tonic."}]}},ua=Object.freeze(Object.defineProperty({__proto__:null,libbsticka:N},Symbol.toStringTag,{value:"Module"})),J={name:"Lingon",icon:"lingon",category:"bär",family:"Ljungväxter",familyLatin:"Ericaceae",perennial:!0,lifespan:"20-30+ år",difficulty:"Medel",difficultyWhy:"Lingon är Sveriges eget skogsbär och extremt härdigt - hon klarar allt väder vi kan kasta mot henne. Men hon kräver sur jord (pH 4-5.5) och det tar 2-3 år innan hon ger ordentligt med bär. Tålmodig odlare belönas rikligt.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:null},days:"Skörd år 2-3",spacing:"25-35 cm",rowSpacing:"40-50 cm",depth:"Ytligt",depthNote:"Grunt rotsystem - plantera i samma djup som i krukan, aldrig djupare",ph:{min:4,max:5.5,ideal:4.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"I skogen växer lingon i halvskugga under tallarna, men i trädgården ger mer sol fler och sötare bär. Hon klarar allt från full sol till halvskugga - anpassningsbar som få. Undvik bara mörk helskugga."},temperature:{min:-40,max:30,ideal:"15-22°C",detail:"En av Sveriges härdigaste växter - tål ner till -40°C utan att blinka. Klarar alla svenska odlingszoner utan vinterskydd. Trivs bäst i sval sommar och ogillar tropisk hetta."},wind:{level:"Tålig",detail:"Låg, marknära växt som vinden blåser rakt över. Lingon bryr sig inte om vind - hon har överlevt tusentals vintrar i fjällen. Vindskydd behövs inte."}},watering:{need:"Låg-Medel",icon:"water",summary:"Lingon är vana vid den svenska skogen - jämn fukt men aldrig blött. Hon har grunda rötter och torkar ut lättare än man tror, men är samtidigt känslig för stående vatten. Mulcha med barr eller bark för att hålla jämn fukt.",phases:[{phase:"Vår (tillväxt)",need:"Medel",tip:"Vattna vid torr vår så att nya skott och blommor får en bra start. Mulcha med tallbarr om du inte redan gjort det."},{phase:"Blomning (maj-juni)",need:"Medel",tip:"Jämn fukt under blomningen ger bättre fruktsättning. Inte mycket - bara se till att jorden inte torkar ut helt."},{phase:"Bärmognad (aug-sept)",need:"Medel",tip:"Fortsätt hålla jämn fukt. Uttorkning nu ger mindre bär. Lingon har grunt rotsystem och kan torka ut snabbt i sandjord."},{phase:"Höst-vinter",need:"Låg",tip:"Minska vattningen. Lingon är vintergrön och klarar sig bra utan extra vatten under vila."}],mistakes:["Vattnar för mycket - lingon HATAR stående vatten och blöt jord","Vattnar med kalkhaltigt kranvatten - höjer pH och lingon förtvinar","Glömmer att vattna nyplanterade plantor första sommaren - de har ännu inte etablerat sig"],tip:"Samla regnvatten! Lingon föredrar mjukt, kalkfritt vatten precis som i skogen. Kranvatten med hög pH kan gradvis göra jorden för basisk."},soil:"Lingon kräver SUR jord - pH 4.0-5.5. Det här är icke-förhandlingsbart. Blanda vanlig trädgårdsjord med rikligt med torv (eller torvfri surblandning), barkmull och tallbarr. Tänk skogsbotten!",soilTips:["Blanda 50/50 trädgårdsjord och sur torvmull eller barkmull","Mulcha med tallbarr, barkmull eller sågspån av barrträ - det håller pH nere","Testa pH! Vanlig trädgårdsjord har ofta pH 6-7, alldeles för högt för lingon","Undvik kalk och aska nära lingonplantor - det höjer pH och dödar dem långsamt","Sandig, humusrik mark med bra dränering är perfekt - precis som i tallskogen"],timeline:{1:[{phase:"Plantering",months:"Juni",icon:"seedling"},{phase:"Blomning (vårblom)",months:"Juni-juli",icon:"bloom"},{phase:"Skörd (första)",months:"Aug",icon:"harvest"},{phase:"Blomning (höstblom)",months:"Juli-aug",icon:"bloom"},{phase:"Skörd (andra)",months:"Sept",icon:"harvest"},{phase:"Vintervila",months:"Okt-maj",icon:"snowflake"}],4:[{phase:"Plantering",months:"Maj-juni",icon:"seedling"},{phase:"Blomning (vårblom)",months:"Maj-juni",icon:"bloom"},{phase:"Skörd (första)",months:"Juli-aug",icon:"harvest"},{phase:"Blomning (höstblom)",months:"Juli",icon:"bloom"},{phase:"Skörd (andra)",months:"Sept-okt",icon:"harvest"},{phase:"Vintervila",months:"Nov-apr",icon:"snowflake"}],6:[{phase:"Plantering",months:"April-maj",icon:"seedling"},{phase:"Blomning (vårblom)",months:"Maj",icon:"bloom"},{phase:"Skörd (första)",months:"Juli",icon:"harvest"},{phase:"Blomning (höstblom)",months:"Juni-juli",icon:"bloom"},{phase:"Skörd (andra)",months:"Sept",icon:"harvest"},{phase:"Vintervila",months:"Nov-mar",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:1,P:1,K:1},{month:"Maj",N:3,P:2,K:2},{month:"Jun",N:3,P:3,K:3},{month:"Jul",N:2,P:3,K:4},{month:"Aug",N:2,P:2,K:4},{month:"Sep",N:1,P:1,K:2}],nutritionTips:[{timing:"Tidig vår (april-maj)",tip:"Ge en lätt giva rhododendrongödsel eller annat surgörande gödselmedel. Lingon är blygsamma ätare - för mycket näring gör mer skada än nytta. Tänk skogsjord, inte grönsaksland."},{timing:"Försommar (juni)",tip:"En tunn påfyllning av barkmull eller tallbarr fungerar både som gödsel och mulch. Lingon i skogen gödslas av nedfallna barr - efterlikna det."},{timing:"Höst",tip:"Ingen gödsel efter juli. Lingon ska inte triggas till ny tillväxt inför vintern. Hon vet vad hon gör - låt henne förbereda sig i fred."}],companions:{good:[{name:"Blåbär",icon:"berry",why:"Samma krav på sur jord! Perfekta grannar som trivs i exakt samma jordmix. Skapa en egen skogsbrynsbädd."},{name:"Rhododendron",icon:"flower",why:"Delar kravet på sur jord och bildar ett snyggt skogsinspirerat planteringsschema. Rhododendron ger skugga som lingon uppskattar."},{name:"Ljung",icon:"flower",why:"Naturlig kompanjon i den svenska skogen. Ljung och lingon trivs i exakt samma förhållanden och ser vackra ut ihop."}],bad:[{name:"Kålväxter",icon:"vegetable",why:"Kålväxter vill ha neutral till basisk jord - raka motsatsen till lingon. Kalkning för kålen dödar lingon."},{id:"lok",name:"Lök",icon:"vegetable",why:"Lök trivs i kalkrik, neutral jord. Jordkraven krockar totalt med lingon."},{name:"De flesta grönsaker",icon:"vegetable",why:"Grönsaker vill ha pH 6-7, lingon vill ha pH 4-5. Håll dem i separata bäddar."}]},rotation:{avoid:[{name:"Blåbär"},{name:"Tranbär"},{name:"Lingon"}],avoidWhy:"Ljungväxter (Ericaceae) delar svampsjukdomar och kan bygga upp jordburna problem. Plantera inte nya lingon där det stått andra ljungväxter nyligen.",goodBefore:[{name:"Ingen gröda (nybruten mark)"},{name:"Barrskog/skogsmark"}],goodBeforeWhy:"Lingon trivs bäst i jord som inte odlats intensivt. Mark nära barrskog eller nybruten skogsmark har ofta rätt pH och mykorrhiza naturligt.",goodAfter:[{name:"Gröngödsling"},{name:"Barrträd"}],goodAfterWhy:"Efter lingon (20+ år) är jorden sur och utarmad på kalk. Gröngödsling eller barrträd trivs. Kalka och bearbeta om du vill odla grönsaker efteråt."},varieties:[{name:"Sanna",zones:[1,2,3,4,5],note:"Svensk sort! Framtagen vid SLU Balsgård 1988, utvald från vilda lingonkloner i Småland. Stora bär, hög avkastning, kompakt växtsätt. Den bästa sorten för trädgårdsodling."},{name:"Ida",zones:[1,2,3,4,5],note:"Svensk sort! Framtagen vid SLU Balsgård 1997, från samma urvalsprogram som Sanna. Mycket stora bär. Remonterar (ger två skördar). Upprätt, kompakt växt som fungerar utmärkt som marktäckare."},{name:"Koralle",zones:[1,2,3,4,5],note:"Tysk sort med riklig bärsättning och upprätt växtsätt. Stora, djupröda bär. Den vanligaste lingonsorten i svensk handel."},{name:"Red Pearl",zones:[1,2,3,4,5],note:"Holländsk sort med extra stora bär. Kraftig tillväxt och bra som marktäckare. Mognar jämnt. Växer 30-40 cm hög."}],problems:[{name:"Fåglar",symptom:"Bären försvinner innan du hinner plocka. Trastar och andra bärfåglar älskar lingon.",fix:"Täck med nät när bären börjar färgas. Fåglarna är snabba - väntar du tills bären är röda är det för sent. Välj finmaskigt nät som inte skadar fåglarna."},{name:"Exobasidium (bladsvullnad)",symptom:"Blad och bär svullnar upp, blir bleka och deformerade. Svampinfektion som är relativt vanlig på vilda lingon.",fix:"Plocka bort och kassera angripna delar. God luftcirkulation förebygger. Sällan allvarligt i trädgårdsodling med bra skötsel."},{name:"Rostsvamp",symptom:"Orangebruna prickar på bladens undersida. Bladen kan gulna och falla av vid kraftigt angrepp.",fix:"Ta bort angripna blad. Undvik övervattning. Lingon i rätt jord och läge drabbas sällan. God hygien och luftcirkulation förebygger."},{name:"Klorös (gula blad)",symptom:"Bladen gulnar mellan nerverna medan nerverna förblir gröna. Plantan växer dåligt.",fix:"Nästan alltid pH-relaterat! Testa jorden - om pH är över 5.5 är det för basiskt. Sänk pH med svavel eller sura tillsatser. Vattna med regnvatten istället för kranvatten."}],goodToKnow:[{icon:"warning",title:"Sur jord - absolut krav",text:"Lingon dör sakta i vanlig trädgårdsjord (pH 6-7). Hon MÅSTE ha pH 4.0-5.5. Testa alltid innan du planterar. Blanda in rikligt med torv, barkmull eller surblandning. Det här är det viktigaste du behöver veta om lingon.",severity:"warning"},{icon:"warning",title:"Tålamod krävs - hon levererar inte direkt",text:"Lingon ger sparsamt med bär de första 2-3 åren. Hon lägger all energi på att etablera sig och sprida sina underjordiska revor. Men när hon väl kommit igång producerar hon bär i 20-30 år. Det är en långsiktig investering.",severity:"warning"},{icon:"tip",title:"Sveriges mest svenska bär",text:"Lingon växer vilt i hela Sverige och har plockats av svenskar i tusentals år. Lingonsylt, rårörda lingon, lingondricka - det finns en anledning att IKEA serverar lingon. Odlade sorter ger dubbelt till tredubbelt så stora bär som vilda.",severity:"tip"},{icon:"tip",title:"Perfekt marktäckare",text:"Lingon sprider sig via underjordiska utlöpare och bildar täta mattor av glänsande, vintergröna blad. Använd henne som marktäckare under bärbuskar eller i surjordsbäddar. Vacker, nyttig och sköter sig nästan helt själv.",severity:"tip"},{icon:"tip",title:"Två skördar per år",text:"De flesta odlade lingonsorter blommar två gånger - en gång på försommaren och en gång på högsommaren. Det ger två skördeperioder: en tidig skörd i juli-aug och huvudskörden i sept-okt. Höstbären är ofta de godaste.",severity:"tip"},{icon:"tip",title:"Allemansrätten gäller",text:"Vilda lingon får plockas fritt överallt i Sverige tack vare allemansrätten. Men odlade sorter i din trädgård ger mångdubbelt mer per kvadratmeter - och du slipper myggen i skogen.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Lingon planteras som krukodlade småplantor, oftast på våren eller tidig höst. Förbered jorden ordentligt med sur jordmix - det är viktigare än själva planteringen.",steps:["Förbered jorden: blanda 50/50 trädgårdsjord och sur torv/barkmull","Testa pH - det MÅSTE vara under 5.5","Gräv en grund planteringsgrop (lingon har ytligt rotsystem)","Plantera i samma djup som i krukan - aldrig djupare","Vattna rikligt med regnvatten (ej kalkhaltigt kranvatten)","Mulcha med tallbarr, barkmull eller sågspån av barrträ (5-8 cm)"],tips:["Plantera 25-35 cm avstånd - lingon fyller ut mellanrummen med utlöpare inom 2-3 år","Upphöjd bädd med surjordsmix är perfekt om din trädgård har kalkrik jord","Förvänta dig inte skörd första året - lingon behöver tid att etablera sig"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Lingon sprider sig naturligt via underjordiska utlöpare (rhizomer). Nya plantor dyker upp runt moderplantan och kan enkelt separeras och planteras om. Precis som i skogen!",steps:["Identifiera friska utlöparplantor med egna rötter i kanten av beståndet","Gräv försiktigt upp med så mycket rot som möjligt","Plantera om direkt i förberedd surjordsmix","Vattna rikligt och mulcha med tallbarr","Håll jämnt fuktig första sommaren tills plantan etablerat sig"],isolation:"Vegetativ förökning - kloner av moderplantan. Ingen korspollinering relevant.",storageYears:"Ej tillämpligt",tip:"Dela på våren eller tidig höst för bäst resultat. Lingon kan också förökas med sticklingar - ta 5-8 cm skott i juli, sätt i sur torv, och de rotar sig på 6-8 veckor."},storage:{shelfLife:"2-4 veckor (färska i kylskåp)",methods:[{method:"Rårörda lingon",icon:"storage",duration:"Månader i kylskåp",description:"Den mest svenska konserveringsmetoden som finns. Krossa bären lätt, blanda med socker (hälften så mycket socker som bär). Behåller den friska, lite syrliga smaken. Perfekt till köttbullar, pannkakor och gröt.",best:!0},{method:"Frysning",icon:"snowflake",duration:"12+ månader",description:"Lingon fryser fantastiskt bra tack vare den naturliga bensorsyran. Frys direkt i påsar - inget behov av att frysa i ett lager först, bären fryser inte ihop lika lätt som andra bär.",best:!1},{method:"Vattlagda lingon",icon:"storage",duration:"6+ månader",description:"Urgammal metod! Häll bären i en burk, fyll på med vatten och lite socker. Lingonens naturliga konserveringsmedel (bensorsyra) gör att de håller sig månader i kylskåp. Helt utan kokning.",best:!1},{method:"Lingonsylt",icon:"storage",duration:"1+ år",description:"Koka bären med socker (3 dl socker per kg bär). Enklare än annan sylt - lingon gelerar lätt tack vare naturligt pektin. Perfekt på mackan.",best:!1},{method:"Kylskåp (färska)",icon:"snowflake",duration:"2-4 veckor",description:"Lingon håller sig oväntat länge färska tack vare bensorsyran - naturens eget konserveringsmedel. Förvara svalt och torrt.",best:!1}],tips:["Lingon innehåller naturlig bensorsyra - de konserverar sig nästan själva!","Plocka bären när de är helt genomröda och fasta","Rårörda lingon smakar bäst efter 1-2 dagars kylskåpsvila - smakerna gifter sig","Frysta lingon kan rivas direkt som garnering utan att tinas - de smular fint"]},harvestCalc:{minPerSqm:.2,maxPerSqm:.5,unit:"kg"},pruning:{label:"Beskärning",types:{maintenance:{name:"Underhållsbeskärning",when:"Tidig vår (mars-april), innan tillväxten börjar",description:"Lingon kräver minimal beskärning. Klipp bort döda och skadade grenar, och gallra om beståndet blivit för tätt. Syftet är att hålla god luftcirkulation och ta bort gammalt material.",steps:["Ta bort döda och brunfärgade grenar vid basen","Klipp bort grenar som växer utanför önskat område","Gallra om beståndet är mycket tätt - luftcirkulation förebygger svamp","Mulcha med nytt tallbarr eller barkmull"]},rejuvenation:{name:"Föryngringsbeskärning",when:"Tidig vår, vart 5-7 år",description:"Äldre lingonbestånd kan bli förvedade och ge allt sämre skörd. Klipp då ner hela beståndet till 3-5 cm ovan mark. Det känns brutalt men lingon skjuter nya friska skott från rötterna och är tillbaka bättre än någonsin inom 1-2 år.",steps:["Klipp ner HELA beståndet till 3-5 cm ovan mark","Rensa bort avklippt material","Toppdress med barkmull och en lätt giva surgörande gödsel","Vattna jämnt under återetableringen","Nya skott dyker upp inom veckor - full skörd igen år 2"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Utlöpare (rhizomer)",description:"Det enklaste sättet. Lingon sprider sig naturligt via underjordiska utlöpare. Gräv upp en utlöparplanta med rot på våren eller hösten och plantera om. Naturen gör jobbet åt dig.",icon:"seedling"},{method:"Sticklingar",description:"Klipp 5-8 cm halvmogna skott i juli. Doppa i rotpulver och sätt i fuktig, sur torv. Placera svalt och skuggigt. Rotbildning tar 6-8 veckor. Fungerar bra men kräver lite mer tålamod.",icon:"scissors"},{method:"Delning",description:"Gräv upp ett etablerat bestånd och dela det i bitar med rötter och skott. Plantera om delarna direkt i förberedd surjordsmix. Bäst på våren.",icon:"scissors"}],tip:"Utlöpare är absolut enklast - lingon sköter förökningen helt själv om du bara låter henne sprida sig. Vill du ha nya plantor snabbt? Gräv upp kantplantor med rot och flytta dem dit du vill."}},va=Object.freeze(Object.defineProperty({__proto__:null,lingon:J},Symbol.toStringTag,{value:"Module"})),R={name:"Lök",icon:"lok",family:"Lökväxter",familyLatin:"Amaryllidaceae",difficulty:"Enkel",difficultyWhy:"Sättlök är bland det enklaste du kan odla - stoppa ner i jorden, vattna ibland, skörda. Punkt.",zones:{outdoor:[1,2,3,4,5,6,7],indoor:null,greenhouse:null},days:"90-120",spacing:"10-15 cm",rowSpacing:"25-30 cm",depth:"2-3 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Löken är envis - hon vill ha SOL för att bilda ordentliga lökar. Minst 6 timmar direkt solljus per dag. I halvskugga får du mycket blast men klena lökar."},temperature:{min:5,max:30,ideal:"15-22°C",detail:"Tålig dame som klarar lätt frost som liten planta. Trivs bäst i svalare väder under tillväxten och lite varmare när lökarna mognar."},wind:{level:"Tålig",detail:"Löken har låg profil och bryr sig inte om vind. Inga särskilda åtgärder behövs."}},watering:{need:"Låg-Medel",icon:"water",summary:"Löken vill ha jämn fukt under tillväxten men HATAR att stå blöt. När blasten börjar lägga sig - sluta vattna helt. Det är signalen att hon vill torka och mogna.",phases:[{phase:"Etablering (0-3 veckor)",need:"Medel",tip:"Håll jorden lätt fuktig efter sättning. Rötterna behöver etablera sig ordentligt. Vattna 1-2 gånger i veckan om det inte regnar."},{phase:"Tillväxt (3-10 veckor)",need:"Medel",tip:"Jämn fukt är nyckeln. Vattna djupt en gång i veckan hellre än lite varje dag. Mulcha gärna mellan raderna för att hålla fukten."},{phase:"Lökbildning (10-14 veckor)",need:"Låg",tip:"Minska vattningen gradvis. Löken bygger nu upp sina lager och för mycket vatten ger vattniga lökar som lagras dåligt."},{phase:"Mognad (sista 2-3 veckorna)",need:"Ingen",tip:"SLUTA vattna helt när blasten börjar gulna och lägga sig. Nu ska löken torka och bilda ordentligt skal. Vatten nu förstör lagringen."}],mistakes:["Vattna när blasten redan lagt sig - lökarna ruttnar istället för att mogna","Övervattning generellt - löken får svampsjukdomar och lagras dåligt","Stående vatten runt lökarna - de måste ha dränering"],tip:"Lägg ett tunt lager gräsklipp eller halm mellan raderna. Det håller fukten jämn och håller ogräset borta - löken avskyr konkurrens."},soil:"Väldränderad, näringsrik jord. Löken vill ha det luftigt kring rötterna - lerjord funkar om du blandar i sand och kompost.",soilTips:["Luckra ordentligt till 20 cm djup","Blanda in väl brunnen kompost och lite sand i tung lerjord","Löken gillar kalkrik jord - strö lite trädgårdskalk om pH är under 6","Gärna en upphöjd bädd om du har tung, vattensjuk jord"],timeline:{1:[{phase:"Sätt sättlök",months:"Apr",icon:"seedling"},{phase:"Rensa ogräs",months:"Maj-Jun",icon:"leaf"},{phase:"Minska vattning",months:"Jul",icon:"water"},{phase:"Skörd och torkning",months:"Aug",icon:"harvest"}],4:[{phase:"Sätt sättlök",months:"Apr-Maj",icon:"seedling"},{phase:"Rensa ogräs",months:"Jun",icon:"leaf"},{phase:"Minska vattning",months:"Jul-Aug",icon:"water"},{phase:"Skörd och torkning",months:"Aug-Sep",icon:"harvest"}],6:[{phase:"Sätt sättlök",months:"Maj",icon:"seedling"},{phase:"Rensa ogräs",months:"Jun-Jul",icon:"leaf"},{phase:"Minska vattning",months:"Aug",icon:"water"},{phase:"Skörd och torkning",months:"Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:30,P:15,K:10,label:"Sättning"},{month:"Maj",N:60,P:25,K:20,label:"Tillväxt"},{month:"Jun",N:70,P:35,K:35,label:"Bladtillväxt"},{month:"Jul",N:30,P:50,K:65,label:"Lökbildning"},{month:"Aug",N:10,P:40,K:80,label:"Mognad"},{month:"Sep",N:5,P:20,K:50,label:"Skörd"}],nutritionTips:[{timing:"Vid sättning",tip:"Grundgödsla med brunnen kompost. Lite benmjöl ger bra fosfortillskott för rotutvecklingen."},{timing:"Tidig tillväxt",tip:"Lätt giva flytande gödsel varannan vecka. Löken vill ha kväve nu för att bygga blast."},{timing:"Lökbildning",tip:"Sluta med kväve helt. Ge kaliumrik gödsel (vedaska) - det hjälper löken att bilda fina, fasta lager."},{timing:"Mognad",tip:"Ingen gödsling. Låt löken mogna ifred."}],companions:{good:[{id:"morot",name:"Morot",icon:"vegetable",why:"Klassiskt radarpar - lökens doft skrämmer bort morotsflugan och moroten håller lökflugan borta"},{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Löken skyddar jordgubbarna mot gråmögel med sin svamphämmande doft"},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Bra markutnyttjande - sallaten skördas innan löken behöver platsen"}],bad:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Löken hämmar ärtornas tillväxt - de trivs inte alls ihop"},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Samma problem som ärtor - baljväxter och lök funkar inte ihop"}]},rotation:{avoid:[{id:"vitlok",name:"Vitlök"},{id:"purjolok",name:"Purjolök"},{id:"schalottenlok",name:"Schalottenlök"},{id:"graslok",name:"Gräslök"}],avoidWhy:"Alla tillhör lökväxter (Amaryllidaceae) - delar sjukdomar som lökröta och lökfluga. Vänta minst 4 år.",goodBefore:[{name:"Kål"},{id:"squash",name:"Squash"}],goodBeforeWhy:"Näringshungriga grödor drar nytta av den välgödslade jord löken lämnar efter sig.",goodAfter:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodAfterWhy:"Baljväxter fixerar kväve i jorden och bygger upp näringen inför nästa säsong."},varieties:[{name:"Stuttgarter Riesen",zones:[1,2,3,4,5,6,7],note:"Klassikern bland sättlök. Pålitlig, bra lagring, mild smak."},{name:"Sturon",zones:[1,2,3,4,5,6,7],note:"Rund, fast och lagrar fantastiskt. Tålig mot sjukdomar."},{name:"Setton",zones:[1,2,3,4,5,6,7],note:"Jämna, fina lökar. Vidareutveckling av Sturon med bra sjukdomsresistens och lång lagring."},{name:"Red Baron",zones:[1,2,3,4,5,6],note:"Rödlök med djup färg och mild sötma. Vacker i sallad!"}],problems:[{name:"Lökfluga",symptom:"Gula, slappa blad. Larver i löken vid basen.",fix:"Täck med fiberduk i maj-juni. Samodla med morot. Strö kalkstensmjöl vid basen."},{name:"Lökröta (Botrytis)",symptom:"Mjukt, grått mögel vid halsen. Löken ruttnar vid lagring.",fix:"Torka lökarna ordentligt efter skörd. Bra ventilation. Skörda i torrt väder."},{name:"Falskt mjöldagg",symptom:"Blågrå beläggning på bladen. Blasten vissnar tidigt.",fix:"Växtföljd! Undvik övervattning. Plocka bort angripna plantor direkt."},{name:"Mjuk lök vid skörd",symptom:"Lökarna känns mjuka och vattniga",fix:"Ofta för mycket vatten sent i säsongen. Sluta vattna 2-3 veckor före skörd."}],goodToKnow:[{icon:"seedling",title:"Sättlök eller frö? Sättlök!",text:"Sättlök ger resultat 4-6 veckor snabbare och är mycket enklare. Frösådd kräver 150+ dagar och förkultivering - välj sättlök om du inte är van odlare.",severity:"tip"},{icon:"sun",title:"Daglängd styr lökbildningen",text:"Löken börjar bilda lök när dagarna är långa nog (juni-juli i Sverige). Det är därför det är viktigt att sätta tidigt - hon behöver ha byggt ordentlig blast innan lökbildningen startar.",severity:"tip"},{icon:"harvest",title:"Blasten lägger sig? Dags snart!",text:"När 50-75% av blasten naturligt lagt sig är det skörddags. Böj INTE ner blasten manuellt - det sprider sjukdomar. Låt naturen bestämma tempot.",severity:"warning"},{icon:"storage",title:"Torkning är allt",text:"Torka lökarna 2-3 veckor på en luftig, torr plats efter skörd. Skalet ska vara helt torrt och rasslande - först då är de redo för lagring. Hoppa aldrig över detta steg!",severity:"warning"},{icon:"warning",title:"Ogräs är lökens fiende nummer ett",text:"Löken har grunt rotsystem och knappt något bladverk som skuggar marken. Ogräs konkurrerar stenhårt. Rensa ofta och försiktigt - hacka INTE för djupt nära lökarna.",severity:"warning"}],sowing:{method:"both",label:"Sättlök eller frösådd",description:"Sättlök rekommenderas starkt för nybörjare - enklare, snabbare och mer pålitligt. Frösådd ger fler sorter att välja bland men kräver förkultivering och tålamod.",steps:["Sättlök: Tryck ner sättlöken i jorden med spetsen uppåt, 2-3 cm djupt","Avstånd 10-15 cm i raden, 25-30 cm mellan raderna","Spetsen ska precis sticka upp ovanför jordytan","Vattna lätt efter sättning","Frösådd: Förkultivera inomhus i februari-mars (8-10 veckor före utplantering)","Så tunt i djupa krukor - lökplantor vill inte bli omplacerade","Plantera ut efter avhärdning när frostrisken är över"],tips:["Välj alltid värmebehandlad sättlök - det minskar risken för skottbildning","Sätt inte sättlöken för djupt - löken ska ligga nära ytan","Strö lite benmjöl i planteringshålet för stark rotutveckling","Frösådd ger möjlighet att odla spännande sorter som inte finns som sättlök"],indoorWeeks:"8-10 veckor"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Löken är tvåårig - första året bildar hon lök, andra året blommar hon och sätter frö. Du måste överväntra hela löken och plantera ut den igen.",steps:["Välj de finaste, friskaste lökarna vid skörd","Lagra dem svalt (4-8°C) men frostfritt över vintern - precis som mat-lök","Plantera ut hela löken tidigt på våren med halsen i marknivå","Löken skjuter en hög blomstjälk (upp till 1 meter!) med rund blomkula","Insekter pollinerar blommorna under sommaren","Låt frökapsarna mogna tills de börjar öppna sig och visa svarta frön","Klipp av hela blomhuvudet och torka inomhus i en papperspåse","Skaka ut fröna när de är helt torra"],isolation:"Korsar fritt med andra sorter av vanlig lök (Allium cepa). Isolera med minst 1 km eller odla bara en sort för frö.",storageYears:"1-3 år",tip:"Lökfrö tappar grobarhet snabbt! Använd helst fröna redan nästa säsong. Förvara torrt och svalt."},storage:{shelfLife:"3-6 månader",methods:[{method:"Torrt och luftigt (hängande)",icon:"storage",duration:"4-6 månader",description:"Fläta ihop lökarna i strängar eller häng dem i nätpåsar på en sval, torr plats. Klassisk metod som fungerar utmärkt. Lökarna ska hänga fritt med bra luftcirkulation.",best:!0},{method:"Sval förvaring (källare)",icon:"storage",duration:"3-5 månader",description:"Lägg lökarna i lådor med god ventilation - gärna i ett enda lager. Temperatur 1-5°C och låg luftfuktighet. Kolla regelbundet att ingen börjat mögla.",best:!1},{method:"Frysa (hackad)",icon:"snowflake",duration:"6-8 månader",description:"Hacka löken och frys in i portionspåsar. Perfekt för matlagning - behöver inte tinas innan den hamnar i grytan. Texten blir mjukare men smaken finns kvar.",best:!1},{method:"Torka",icon:"sun",duration:"12+ månader",description:"Skiva tunt och torka i ugn på 55°C eller i torkautomat. Mixa till lökpulver eller använd flingorna direkt i matlagning.",best:!1}],tips:["Torka ALLTID lökarna ordentligt (2-3 veckor) före lagring - det är skillnaden mellan 2 veckor och 6 månader","Lagra aldrig lök tillsammans med potatis - de avger gaser som påskyndar förruttnelse hos varandra","Rödlök lagras kortare än gul lök - ät rödlöken först","Lök som börjat gro kan fortfarande användas - de gröna skotten är ätbara!"]},harvestCalc:{minPerSqm:2,maxPerSqm:4,unit:"kg"}},ha=Object.freeze(Object.defineProperty({__proto__:null,lok:R},Symbol.toStringTag,{value:"Module"})),E={name:"Majrova",icon:"majrova",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Enkel",difficultyWhy:"Anspråkslös och snabb - bara stoppa ner fröet i jorden så fixar hon resten. En av Sveriges äldsta grödor av en anledning.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:null},days:"50-80",spacing:"15-20 cm",rowSpacing:"30-40 cm",depth:"1-2 cm",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Trivs bäst i full sol men klarar halvskugga. I skuggigare lägen tar det lite längre tid, men roten blir mildare och sötare."},temperature:{min:-4,max:25,ideal:"12-18°C",detail:"En riktig svalväxtare som gror redan vid 5°C och tål frost ner till -4°C. Över 25°C blir hon stressad och vedartad. Trivs allra bäst i sval vår- och höstluft."},wind:{level:"Tålig",detail:"Låg och kompakt med bladen nära marken - vind stör henne inte det minsta."}},watering:{need:"Medel",icon:"water",summary:"Jämn fukt ger söta, milda rovor. Torka gör henne bitter och vedig - men hon drunknar inte heller gärna.",phases:[{phase:"Groning (0-2 veckor)",need:"Hög",tip:"Håll jorden jämnt fuktig tills plantorna kommit upp. Majrovan gror på 4-7 dagar i lagom temperatur."},{phase:"Bladtillväxt (2-4 veckor)",need:"Medel",tip:"Vattna 2-3 gånger i veckan om det inte regnar. Nu bygger hon bladverk som ska driva rottillväxten."},{phase:"Rotsvällning (4-8 veckor)",need:"Medel-Hög",tip:"Kritisk period! Jämn fukt nu avgör om rovan blir söt och saftig eller bitter och vedig. Låt aldrig jorden torka ut helt."}],mistakes:["Ojämn vattning (torrt-blött-torrt) ger spruckna rovor med bitter smak","Uttorkad jord under rotsvällning ger vediga, trådfyllda rovor","Stående vatten ger röta - majrovan vill ha fuktig men dränerad jord"],tip:"Mulcha med gräsklipp eller halm runt plantorna när de är 5-10 cm höga. Håller fukten jämn och jordlopporna borta."},soil:"Lös, mullrik, väldränerad jord. Majrovan vill kunna svälla fritt utan att kämpa mot kompakt lera.",soilTips:["Luckra de översta 20-25 cm ordentligt - rovan behöver utrymme neråt","Blanda in kompost om jorden är mager, men övergödsla inte med kväve","Undvik stenig jord - stenar ger missformade rovor","Sandblandad lera funkar utmärkt om den luckrats väl"],timeline:{1:[{phase:"Direktså vårsådd",months:"Mar-Apr",icon:"seedling"},{phase:"Skörd vårsådd",months:"Maj-Jun",icon:"harvest"},{phase:"Direktså höstsådd",months:"Jul-Aug",icon:"seedling"},{phase:"Skörd höstsådd",months:"Sep-Okt",icon:"harvest"}],4:[{phase:"Direktså vårsådd",months:"Apr-Maj",icon:"seedling"},{phase:"Skörd vårsådd",months:"Jun-Jul",icon:"harvest"},{phase:"Direktså höstsådd",months:"Jul-Aug",icon:"seedling"},{phase:"Skörd höstsådd",months:"Sep-Okt",icon:"harvest"}],6:[{phase:"Direktså vårsådd",months:"Maj",icon:"seedling"},{phase:"Skörd vårsådd",months:"Jul",icon:"harvest"},{phase:"Direktså höstsådd",months:"Jun-Jul",icon:"seedling"},{phase:"Skörd höstsådd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:15,P:10,K:10,label:"Sådd"},{month:"Maj",N:25,P:15,K:15,label:"Bladtillväxt"},{month:"Jun",N:20,P:25,K:35,label:"Rotsvällning"},{month:"Jul",N:10,P:20,K:40,label:"Mognad"},{month:"Aug",N:5,P:15,K:30,label:"Skörd/lagring"}],nutritionTips:[{timing:"Vid sådd",tip:"Grundgödsla med brunnen kompost. Majrovan är inte hungrig - för mycket kväve ger frodig blast men liten rova."},{timing:"Under bladtillväxt",tip:"Ingen extra gödsling behövs om jorden har fått kompost. Kalium (vedaska) gynnar rottillväxt."},{timing:"Rotsvällning",tip:"Lite vedaska eller kaliumrik gödsel stärker rovan. Undvik kväverik gödsling nu - det driver bara bladtillväxt."}],companions:{good:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Ärtorna fixerar kväve som majrovan tacksamt tar del av. Bra grannar som inte konkurrerar."},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Sallaten skuggar marken och håller fukten - perfekt kompis i varmt väder."},{id:"dill",name:"Dill",icon:"herb",why:"Dillens doft förvirrar kålfjärilar och jordloppor. Dessutom lockar den nyttoinsekter."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Konkurrerar om samma näring och utrymme under jord. Håll dem åtskilda."},{id:"gronkal",name:"Grönkål",icon:"vegetable",why:"Samma familj (korsblommiga) - delar skadedjur som kålfluga och jordloppa."},{id:"broccoli",name:"Broccoli",icon:"vegetable",why:"Samma familj - ökar risk för klumprotsjuka och kålfluga."}]},rotation:{avoid:[{id:"gronkal",name:"Grönkål"},{id:"vitkal",name:"Vitkål"},{id:"broccoli",name:"Broccoli"},{id:"blomkal",name:"Blomkål"},{id:"radisa",name:"Rädisa"},{id:"kalrabbi",name:"Kålrabbi"}],avoidWhy:"Alla tillhör korsblommiga och delar klumprotsjuka, kålfluga och jordloppa. Vänta minst 4 år innan du odlar majrova på samma plats.",goodBefore:[{name:"Baljväxter (ärtor, bönor)"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter fixerar kväve som majrovan drar nytta av. Lök har helt andra sjukdomar - perfekt föregångare.",goodAfter:[{id:"sallat",name:"Sallat"},{id:"lok",name:"Lök"},{name:"Baljväxter (ärtor, bönor)"}],goodAfterWhy:"Majrovan lämnar lös, lucker jord efter sig som sallat och lök trivs i. Baljväxter fyller på kvävet som majrovan använt."},varieties:[{name:"Purple Top Milan",zones:[1,2,3,4,5,6,7],note:"Klassisk OP-sort med vacker lila topp och vitt kött. Snabb och pålitlig - den mest odlade majrovan. Impecta."},{name:"Guldboll",zones:[1,2,3,4,5,6],note:"Gul OP-kulturarvssort (1863) med söt, mild smak. Fantastisk rostad eller i soppa. Ekofrö hos Runåbergs."},{name:"Snowball",zones:[1,2,3,4,5,6],note:"Rund, vit OP-sort med mild, söt smak. Snabb och pålitlig - redo på 40-50 dagar. Ekofrö hos Runåbergs."},{name:"Petrowski",zones:[1,2,3,4,5,6,7],note:"Gul, plattund rysk kulturarvssort (OP). Söt och nötig smak, pålitlig i kalla klimat. En favorit bland fröbevarare. Ekofrö hos Lindbloms."}],problems:[{name:"Jordloppor",symptom:"Små runda hål i bladen, unga plantor kan ätas helt",fix:"Viktigaste skadedjuret! Fiberduk direkt vid sådd. Håll jorden fuktig - jordloppor trivs i torr, varm jord. Vattna på morgonen."},{name:"Kålfluga",symptom:"Plantor vissnar trots vattning, larver i roten",fix:"Kålkrage runt varje planta eller fiberduk över hela raden. Växtföljd med minst 4 års uppehåll från korsblommiga."},{name:"Mjöldagg",symptom:"Vitt, mjölaktigt belägg på bladen",fix:"Undvik att vattna på bladen - vattna vid markytan. God luftcirkulation hjälper. Gallra om det står för tätt."},{name:"Vediga rötter",symptom:"Hård, trådig konsistens med bitter smak",fix:"Skörda i tid - en övervuxen majrova blir vedig snabbt. Jämn fukt och sval väderlek förebygger. Sommarvärme är fienden."}],goodToKnow:[{icon:"history",title:"Sveriges glömda basföda",text:"Före potatisen var majrovan en av Sveriges viktigaste vintergrödor. Varje gård hade majrovor i källaren. Hon förtjänar en renässans - enkel att odla, gott att äta, och lagrar sig i månader.",severity:"tip"},{icon:"leaf",title:"Blasten är också mat!",text:"Blastmajrova (majrovsblast) är fullpackad med vitaminer och smakar utmärkt fräst, i soppa eller som ersättning för spenat. Släng aldrig blasten - det är halva skörden!",severity:"tip"},{icon:"snowflake",title:"Frosten gör henne sötare",text:"Precis som morot och palsternacka omvandlar majrovan stärkelse till socker när det blir kallt. En lätt frost på hösten ger sötare, mildare rovor.",severity:"tip"},{icon:"seedling",title:"Dubbelsådd ger skörd från vår till vinter",text:"Så tidigt på våren för sommarskörd och igen i juli-augusti för höstskörd och vinterlagring. Höstsådden ger rovor som lagrar sig mycket bättre.",severity:"tip"},{icon:"warning",title:"Sommarvärme är fienden",text:"Majrovan är en svalväxtare. I högsommarvärme blir hon bitter, vedig och kan skjuta i blom. Planera odlingen för vår och höst - undvik att hon mognar mitt i juli.",severity:"warning"}],sowing:{method:"direct",label:"Direktsådd",description:"Majrovan sås alltid direkt på friland. Hon har en pålrot som inte tål att störas och är så lättodlad att förodling är onödigt.",steps:["Luckra jorden väl och kratta till en jämn yta","Dra ett grunt spår, 1-2 cm djupt","Så fröna glest - försök hålla 2-3 cm mellanrum","Täck med ett tunt lager jord och tryck till lätt","Vattna försiktigt med stril","Gallra till 15-20 cm när plantorna har 3-4 riktiga blad"],tips:["Vårsådd i april ger sommarrovor - höstsådd i juli-augusti ger lagringsrovor","Lägg fiberduk direkt vid sådd för att skydda mot jordloppor","Gallringsplantorna kan ätas som bladsallat - slösa inte!","Blötlägg inte fröna - de gror snabbt ändå (4-7 dagar)"],indoorWeeks:null},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!0,description:"Majrovan är tvåårig - hon sätter frö först andra året. Spara de finaste rovorna över vintern och plantera ut dem på våren. Hon korsar lätt med andra Brassica rapa (kinakål, pak choi), så odla bara en sort åt gången.",steps:["Välj ut de finaste, friskaste rovorna vid höstskörden","Lagra dem i sand eller torv i källaren över vintern (nära 0°C)","Plantera ut rovorna tidigt på våren med roten neråt och toppen ovan jord","Majrovan skjuter blomstjälk med gula blommor","Insekter pollinerar blommorna - bin och humlor älskar dem","Låt fröskidorna mogna och torka på plantan tills de blivit bruna","Klipp av hela stjälken och torka inomhus i en papperspåse","Gnugga eller traska loss fröna ur skidorna","Rensa bort skal och förvara torrt och svalt"],isolation:"Korsar med alla Brassica rapa-arter (kinakål, pak choi, rova). Odla bara en sort för frösparing, eller isolera med minst 500 m.",storageYears:"3-5 år",tip:"Föreningen Sesam är en fantastisk resurs om du vill fördjupa dig i fröbevarande av gamla svenska rotgrönsaksorter."},storage:{shelfLife:"3-4 månader",methods:[{method:"Källarlagring",icon:"storage",duration:"3-4 månader",description:"Det klassiska sättet! Lägg rovorna i lådor med fuktig sand eller torv i en sval källare (0-4°C). Klipp av blasten men lämna 2 cm. Kontrollera regelbundet och plocka bort mjuka rovor.",best:!0},{method:"Kylskåp",icon:"snowflake",duration:"2-4 veckor",description:"Klipp av blasten och lägg rovorna i en plastpåse med några hål. Håller sig bra i grönsakslådan. Perfekt för sommarrovorna som inte ska lagras länge.",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-10 månader",description:"Skala och tärna rovorna. Blanchera i 2-3 minuter, kyl snabbt i isvatten och frys in. Utmärkt till soppor och grytor.",best:!1},{method:"Syra/fermentera",icon:"storage",duration:"3-6 månader",description:"Riv eller skiva tunt och mjölksyra som surkål. Gammalt svenskt sätt att ta vara på majrovor. Salt, kryddor och tid - klart!",best:!1}],tips:["Höstsådda rovor lagrar sig mycket bättre än vårsådda","Ta bort blasten direkt vid skörd - den suger fukt ur rovan","Skörda före hård frost men efter några lätta nattfroster (ger sötare smak)","Lämna gärna rovorna i jorden så länge som möjligt på hösten - de lagrar sig bäst där"]},harvestCalc:{minPerSqm:2,maxPerSqm:4,unit:"kg"}},ca=Object.freeze(Object.defineProperty({__proto__:null,majrova:E},Symbol.toStringTag,{value:"Module"})),C={name:"Mangold",icon:"vegetable",family:"Mållväxter",familyLatin:"Amaranthaceae",difficulty:"Enkel",difficultyWhy:"Tålig, snabbväxande och snäll mot nybörjare. Mangold klarar både värme och lätt frost, ger skörd i månader och ser dessutom fantastisk ut i rabatten.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:[1,2,3,4,5,6,7,8]},days:"50-70",spacing:"25-30 cm",rowSpacing:"35-40 cm",depth:"2 cm",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Trivs i full sol (6+ timmar) men klarar halvskugga galant - bladen blir till och med mjukare och mildare i smaken. Under högsommaren uppskattar hon faktiskt lite skugga under de hetaste timmarna."},temperature:{min:5,max:30,ideal:"15-24°C",detail:"En riktig allroundare! Kan tekniskt gro vid 5°C men räkna med 10°C+ för pålitlig groning. Föredrar 15-24°C. Tål lätt frost ner till -5°C och hanterar sommarvärme mycket bättre än spenat. Hon varken boltar eller klagar - bara fortsätter växa."},wind:{level:"Måttligt tålig",detail:"De stora bladen kan ta stryk i hård blåst. I utsatta lägen kan en enkel vindskärm vara bra, men i normala trädgårdslägen klarar hon sig fint."}},watering:{need:"Medel",icon:"water",summary:"Mangold vill ha jämn fukt men är förvånansvärt förlåtande. De djupa rötterna hjälper henne att klara kortare torrperioder, men bäst skörd får du med regelbunden vattning.",phases:[{phase:"Groning (0-3 veckor)",need:"Hög",tip:"Håll jorden jämnt fuktig. Mangoldfrön är som rödbetans - frönystan med flera frön i varje, så förvänta dig flera plantor per frö."},{phase:"Tillväxt (3-8 veckor)",need:"Medel",tip:"Vattna 2-3 gånger i veckan om det inte regnar. Djupvattna ordentligt varje gång - mangoldens rötter går djupt och tackar för det."},{phase:"Löpande skörd (8+ veckor)",need:"Medel",tip:"Fortsätt med jämn fukt. Varje gång du skördar blad sätter hon fart och producerar nya - men bara om hon har vatten att jobba med."}],mistakes:["Övervattning i tung jord - rötterna ruttnar trots att mangold gillar fukt","Torka under högsommaren - bladen blir sega och bittra istället för mjuka och milda","Vattnar på bladen på kvällen - inbjudan till bladmögel och svampsjukdomar"],tip:"Mulcha runt plantorna med gräsklipp eller halm. Det håller fukten jämn, minskar ogräs och mangoldens rötter hålls svala under varma dagar."},soil:"Näringsrik, lucker jord med god dränering. Mangold är hungrig - ju bättre jord, desto mer imponerande blad.",soilTips:["Blanda in rikligt med kompost - mangold är en bladgrönsak som älskar kväve","Undvik sur jord - strö lite kalk om pH är under 6.0. Mangold trivs bäst nära neutralt","Lös, djupgrävd jord ger starkare pålrot och tåligare plantor"],timeline:{1:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Direktså/plantera ut",months:"Apr-Maj",icon:"seedling"},{phase:"Gallra",months:"Maj",icon:"scissors"},{phase:"Löpande skörd",months:"Jun-Okt",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Direktså/plantera ut",months:"Maj",icon:"seedling"},{phase:"Gallra",months:"Jun",icon:"scissors"},{phase:"Löpande skörd",months:"Jul-Okt",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Maj",icon:"seedling"},{phase:"Direktså/plantera ut",months:"Jun",icon:"seedling"},{phase:"Gallra",months:"Jun-Jul",icon:"scissors"},{phase:"Löpande skörd",months:"Jul-Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:30,P:15,K:15,label:"Sådd/förodling"},{month:"Maj",N:65,P:25,K:25,label:"Tillväxt"},{month:"Jun",N:80,P:35,K:35,label:"Full bladtillväxt"},{month:"Jul",N:75,P:35,K:40,label:"Löpande skörd"},{month:"Aug",N:65,P:30,K:40,label:"Fortsatt skörd"},{month:"Sep",N:40,P:20,K:30,label:"Avslutande skörd"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla med brunnen kompost eller hönsgödsel. Mangold är en riktig kväveslukare - hon bygger stora blad och behöver bränsle."},{timing:"Under tillväxt",tip:"Flytande brännässelvatten varannan vecka ger kraftfulla, mörkgröna blad. Mangold tackar med att växa explosivt."},{timing:"Vid löpande skörd",tip:"Ge en extra giva näring varje gång du skördar rejält. Varje nytt blad hon producerar kostar energi."},{timing:"Sensommar",tip:"Trappa ner gödslingen mot slutet av säsongen. Kalium (vedaska) stärker mot frost om du vill förlänga skörden in i hösten."}],companions:{good:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens doft håller skadedjur borta och de konkurrerar inte om näring. Klassisk kombination."},{id:"morot",name:"Morot",icon:"morot",why:"Olika rotdjup och behov - moroten går djupt medan mangoldens blad ger markskydd."},{id:"sallat",name:"Sallat",icon:"sallat",why:"Sallaten trivs i skuggan av mangoldens stora blad under sommaren. Perfekt samarbete."},{id:"radisa",name:"Rädisa",icon:"radisa",why:"Rädisan är klar på 4 veckor och lämnar plats åt mangoldens blad att breda ut sig."},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Baljväxter fixerar kväve som mangold älskar. En generös granne."}],bad:[{id:"rodbeta",name:"Rödbeta",icon:"rodbeta",why:"Samma art (Beta vulgaris)! De konkurrerar om exakt samma näring och delar alla sjukdomar."},{id:"spenat",name:"Spenat",icon:"spenat",why:"Samma familj (mållväxter) - delar sjukdomar som bladmögel och tävlar om kväve."}]},rotation:{avoid:[{id:"rodbeta",name:"Rödbeta",category:"grönsaker"},{id:"spenat",name:"Spenat",category:"grönsaker"}],avoidWhy:"Alla tillhör mållväxter (Amaranthaceae). Mangold och rödbeta är till och med samma art! Delar sjukdomar och skadedjur. Vänta minst 3 år.",goodBefore:[{id:"artor",name:"Ärtor",category:"grönsaker"},{id:"bondbona",name:"Bondböna",category:"grönsaker"},{id:"lok",name:"Lök",category:"grönsaker"}],goodBeforeWhy:"Baljväxter lämnar kväverik jord som mangold tacksamt slänger sig över. Lök sanerar mot svampsjukdomar.",goodAfter:[{name:"Kål"},{id:"morot",name:"Morot",category:"grönsaker"},{id:"potatis",name:"Potatis",category:"grönsaker"}],goodAfterWhy:"Kål och rotgrönsaker trivs i den mullrika, välgödslade jorden som mangold lämnar efter sig."},varieties:[{name:"Bright Lights",zones:[1,2,3,4,5,6],note:"Regnbågsmixen! Stjälkar i rött, gult, orange, rosa och vitt. Lika vacker som god - en riktig showstopper i trädgården."},{name:"Lucullus",zones:[1,2,3,4,5,6],note:"Grön klassiker med ljusgröna, bubbliga blad. Mild, fin smak och mycket tålig. Svenskt fröhandelsklassiker."},{name:"Rhubarb Chard",zones:[1,2,3,4,5,6],note:"Djupt röda stjälkar mot mörkgröna blad. Riktig karaktär och lite kraftigare smak än de ljusa sorterna."},{name:"Fordhook Giant",zones:[1,2,3,4,5,6],note:"Breda, vita stjälkar med stora blad. Klassisk sort med mild smak och hög avkastning. Perfekt för matlagning."},{name:"Orange Fantasia",zones:[1,2,3,4,5,6],note:"Öppenpollinerad sort med lysande orangea stjälkar. Heirloom-sort som fungerar utmärkt för frösparing."}],problems:[{name:"Bladmögel",symptom:"Gulgröna fläckar på ovansidan, gråviolett beläggning under bladen. Vanligast i fuktigt, svalt väder.",fix:"God luftcirkulation - gallra ordentligt. Vattna vid roten, inte på bladen. Ta bort drabbade blad direkt. Växtföljd minskar risken."},{name:"Betflugan (minerarfluga)",symptom:"Bruna, genomskinliga blåsor/gångar i bladen. Larverna äter sig fram inuti bladet.",fix:"Plocka bort angripna blad och släng dem (inte i komposten). Fiberduk tidigt på säsongen förebygger. Sällan ett allvarligt problem - mangold växer ifrån det."},{name:"Bladlöss",symptom:"Kolonier av små gröna eller svarta löss under bladen, klibbigt sekret.",fix:"Spruta av med kraftig vattenstråle. Plantera blommor intill för nyttoinsekter. Undvik övergödsling med kväve - det lockar löss som flugor till sirap."},{name:"Sniglar",symptom:"Stora, oregelbundna hål i bladen, slemspår på morgonen.",fix:"Snigelkorn (järnfosfat), kopparhinder runt odlingen. Vattna på morgonen. Mangoldens stora blad är ett riktigt snigelbuffefavorit, så var vaksam."},{name:"Skottskjutning (sällsynt)",symptom:"Blomstjälk skjuter upp första året. Bladen blir sega och bittra.",fix:"Kan triggas av kyla (under 5°C i längre perioder) tidigt på säsongen. Plantera inte ut för tidigt. Skottskjutna plantor ger inget mer - ersätt dem."}],goodToKnow:[{icon:"tip",title:"Skörda-och-kom-igen",text:"Mangold är den ultimata skörda-och-kom-igen-grödan. Plocka de yttre bladen och lämna hjärtat - hon fortsätter producera nya blad i månader. En enda planta kan ge skörd från juni till frost!",severity:"tip"},{icon:"warning",title:"Samma art som rödbeta",text:"Mangold och rödbeta är faktiskt samma art (Beta vulgaris). Tänk på det vid växtföljd och frötagning - de korsar sig utan att tveka.",severity:"warning"},{icon:"sun",title:"Fungerar som prydnadsväxt",text:"Regnbågsmangold (Bright Lights) är lika snygg i rabatten som i grönsakslandet. De färgglada stjälkarna i rött, gult och orange är en riktig ögonfröjd.",severity:"tip"},{icon:"seedling",title:"Frönystan som rödbeta",text:'Varje "frö" är egentligen ett nystan med 2-4 frön i. Du får alltid flera plantor per frö - gallring är ett måste om du inte vill ha en mangolddjungel.',severity:"warning"},{icon:"harvest",title:"Stjälkarna är delikatessen",text:"Stjälkarna är minst lika goda som bladen - tillagas som sparris. De behöver bara lite längre tillagningstid än bladen, så starta med stjälkarna och lägg i bladen sist.",severity:"tip"},{icon:"calendar",title:"Vintergrön i milda vintrar",text:"I zon 1-3 kan mangold med fiberduk överleva milda vintrar och ge tidig skörd redan i april nästa år. Värt att testa!",severity:"tip"}],sowing:{method:"both",label:"Direktsådd eller förodling",description:"Mangold kan antingen sås direkt utomhus eller förodlas inomhus för tidigare skörd. Hon hanterar omplantering bättre än rödbeta och spenat, så förodling fungerar fint.",steps:["Blötlägg fröna i ljummet vatten 12-24 timmar - det snabbar på groningen rejält","Förodling: Så i krukor 4-6 veckor före utplantering, 2 cm djupt. Gallra till starkaste plantan per kruka.","Direktsådd: Dra spår ca 2 cm djupa med 35-40 cm mellanrum","Så fröna med 5-10 cm mellanrum","Täck med jord och tryck till lätt","Vattna försiktigt med stril","Gallra till 25-30 cm avstånd när plantorna har 4-5 blad (ät de gallrade plantorna som babymangold!)"],tips:["Förodling ger 3-4 veckors försprång och tidigare skörd","Varje frönystan ger flera plantor - var inte rädd att gallra ordentligt","Mangold i kruka fungerar utmärkt: minst 25 cm djup, rymlig kruka. En planta per 5-litersgryta."],indoorWeeks:"4-6"},seedSaving:{difficulty:"Medel",type:"Vindpollinerare",biennial:!0,description:"Mangold är tvåårig och bildar frö andra året. Du måste överväntra plantan och låta den blomma nästa säsong. Korsar sig fritt med rödbeta och andra betor!",steps:["Välj de finaste, friskaste plantorna vid slutet av första säsongen","I zon 1-3: Lämna kvar i jorden med rejäl täckning (halm + fiberduk). I zon 4+: Gräv upp roten och lagra i sand i frostfritt utrymme.","Plantera ut övervintrade rötter tidigt på våren (zon 4+)","Mangold skjuter upp en blomstjälk som kan bli 1-1.5 meter hög","Pollinering sker med vind - låt naturen sköta sitt","Fröna mognar under sensommaren - vänta tills de blir bruna och torra","Klipp av stjälken och torka inomhus i en papperspåse","Gnugga loss frönystanen och förvara torrt och svalt"],isolation:"Vindpollinerare som korsar sig med rödbeta, sockerbeta och andra mangoldsorter. Odla bara en sort för frö, eller isolera med minst 1.5 km. Mangold och rödbeta kan INTE odlas för frö samtidigt.",storageYears:"4-5 år",tip:"Välj OP-sorter som Lucullus eller Bright Lights om du vill fröspara. F1-hybrider ger oförutsägbara resultat i nästa generation."},storage:{shelfLife:"1-2 veckor",methods:[{method:"Kylskåp i fuktig handduk",icon:"snowflake",duration:"5-7 dagar",description:"Linda otvättade blad och stjälkar i fuktig hushållspapper, stoppa i plastpåse. Tvätta inte förrän du ska äta - fukt gör att bladen sladdrar snabbare.",best:!0},{method:"Frysa (blancherad)",icon:"snowflake",duration:"8-12 månader",description:"Blanchera bladen 2 minuter (stjälkarna 3 minuter), kyl i isvatten, pressa ur vattnet och frys i portioner. Perfekt för grytor och gratänger hela vintern.",best:!1},{method:"Direkt från trädgården",icon:"leaf",duration:"Hela säsongen",description:"Den absolut bästa lagringen! Lämna mangolden i landet och plocka blad efter behov. Hon fortsätter producera ända tills frosten tar henne.",best:!1},{method:"Stjälkar inlagda",icon:"storage",duration:"3-6 månader",description:"Mangoldstjälkar kan läggas in som pickles med ättika och kryddor. Krispiga, färgglada och riktigt goda som tillbehör.",best:!1}],tips:["Skörda på morgonen när bladen är som mest spänstiga och fyllda med vatten","Stjälkar och blad har olika hållbarhet - stjälkarna håller sig längre i kylen","Förvara blad och stjälkar separat om du vill ha maximal hållbarhet","Mangold som börjar sloka kan fortfarande användas i soppor, smoothies och gratänger"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3.5,unit:"kg"}},ba=Object.freeze(Object.defineProperty({__proto__:null,mangold:C},Symbol.toStringTag,{value:"Module"})),O={name:"Mejram",icon:"mejram",category:"kryddor",family:"Kransblommiga",familyLatin:"Lamiaceae",perennial:!1,difficulty:"Medel",difficultyWhy:"Mejram är inte svår att odla men kräver en smula extra omtanke. Hon är köldkänslig och måste förodlas inomhus. De pyttelila fröna gror långsamt och vill ha värme. Men väl etablerad belönar hon dig med en av kökets mest aromatiska kryddor.",zones:{outdoor:[1,2,3,4],indoor:[1,2,3,4,5,6,7,8],greenhouse:[1,2,3,4,5,6]},days:"70-90",spacing:"15-20 cm",rowSpacing:"25-30 cm",depth:"Ytså",depthNote:"Ljusgroddare - tryck fast men täck inte",ph:{min:6.5,max:7.5,ideal:7},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Mejram är en medelhavsväxt som vill ha full sol - minst 6 timmars direkt solljus per dag. I halvskugga blir hon ranglig med svagare arom. Söderläge mot en varm vägg? Perfekt - hon suger in värmen."},temperature:{min:0,max:35,ideal:"18-25°C",detail:"Köldkänslig! Mejram klarar inte frost och vill ha det varmt. Plantera inte ut förrän natttemperaturen är stabilt över 10°C. I Sverige odlas hon som ettårig - men i en solig fönsterbräda kan hon leva vidare inomhus."},wind:{level:"Skyddat",detail:"Föredrar ett skyddat, varmt läge. Mejrams späda, mjuka blad torkar lätt ut i hård vind. En skyddad plats i kryddlandet eller i en krukgrupp på balkongen är perfekt."}},watering:{need:"Medel",icon:"water",summary:"Mejram vill ha jämn fukt men avskyr blöta fötter. Tänk som en medelhavsflicka - hon vill inte torka ut helt men heller aldrig stå i vatten.",phases:[{phase:"Groning (2-3 veckor)",need:"Medel",tip:"Håll jämnt fuktigt men vattna inte rakt på de pyttelila fröna - det spolar bort dem. Spreja försiktigt med vattenspray."},{phase:"Småplantor",need:"Medel",tip:"Fortsätt med jämn fukt. Låt inte jorden torka ut helt mellan vattningarna - mejramplantor har grunt rotsystem och torkar ut fort."},{phase:"Etablerad planta",need:"Medel",tip:"Vattna när ytan känns torr. Mejram klarar kort torka men tappar smak och kan gå i blom för tidigt om hon stressas."}],mistakes:["Övervattnar - våta fötter leder snabbt till rotröta, speciellt i tung jord","Vattnar på kvällen - fukten ligger kvar och bjuder in svampsjukdomar","Låter jorden torka ut helt - mejram stressar och blommar för tidigt, då tappar bladen smak"],tip:"Mulcha med ett tunt lager gräsklipp runt plantorna. Håller jorden jämnt fuktig och varm - precis som mejram vill ha det."},soil:"Lätt, varm, väldränerad jord. Mejram trivs i sandig-lerig jord som värms upp snabbt på våren. Tung, kall lerjord är hennes värsta mardröm.",soilTips:["Blanda in sand eller perlit i tung jord för bättre dränering och snabbare uppvärmning","Lite kalk om jorden är sur - mejram föredrar neutral till svagt basisk jord","I kruka: vanlig planteringsjord med en skvätt perlit fungerar utmärkt","Undvik för näringsrik jord - mejram på mager jord ger starkare arom"],timeline:{1:[{phase:"Förodling inomhus",months:"Mars",icon:"indoor"},{phase:"Utplantering",months:"Maj",icon:"seedling"},{phase:"Skörd löpande",months:"Jun-sep",icon:"harvest"},{phase:"Blomning",months:"Jul-aug",icon:"flower"},{phase:"Frötagning",months:"Aug-sep",icon:"seed"}],4:[{phase:"Förodling inomhus",months:"Mars-april",icon:"indoor"},{phase:"Utplantering",months:"Jun",icon:"seedling"},{phase:"Skörd löpande",months:"Jul-sep",icon:"harvest"},{phase:"Blomning",months:"Aug",icon:"flower"},{phase:"Frötagning",months:"Sep",icon:"seed"}],6:[{phase:"Förodling inomhus",months:"April",icon:"indoor"},{phase:"Utplantering",months:"Jun",icon:"seedling"},{phase:"Skörd löpande",months:"Jul-aug",icon:"harvest"},{phase:"Blomning",months:"Aug-sep",icon:"flower"}]},nutritionData:[{month:"Apr",N:2,P:1,K:1},{month:"Maj",N:4,P:2,K:2},{month:"Jun",N:5,P:3,K:3},{month:"Jul",N:4,P:3,K:4},{month:"Aug",N:3,P:2,K:3},{month:"Sep",N:2,P:1,K:2}],nutritionTips:[{timing:"Vid plantering",tip:"Blanda in lite kompost i planteringsgropen. Mejram har modest näringsbehov - hon behöver inte mycket men uppskattar en god start."},{timing:"Midsommar",tip:"En svag giva flytande näring om plantorna ser bleka ut. Men övergödsel inte - mager jord ger faktiskt starkare smak."},{timing:"Obs!",tip:"Aldrig kraftig gödsel! Mejram som överstimuleras med kväve växer snabbt men förlorar sin aromatiska personlighet. Hellre lite hungrig och smakrik."}],companions:{good:[{id:"morot",name:"Morot",icon:"vegetable",why:"Mejrams starka doft förvirrar morotsflugan som navigerar efter lukt. Ett klassiskt skyddspar i kryddlandet."},{id:"paprika",name:"Paprika",icon:"vegetable",why:"Båda gillar värme och sol. Mejram lockar pollinerare som hjälper paprikans fruktsättning."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Mejram avskräcker bladlöss och vitflugor. Dessutom sägs mejram förstärka tomatens smak om de odlas nära varandra."}],bad:[{id:"gurka",name:"Gurka",icon:"vegetable",why:"Gurka vill ha rik, fuktig jord och mycket vatten - raka motsatsen till mejrams preferenser."},{id:"mynta",name:"Mynta",icon:"herb",why:"Myntan sprider sig aggressivt och tar över. Dessutom vill hon ha fuktigare förhållanden än mejram."}]},rotation:{avoid:[{id:"oregano",name:"Oregano"},{id:"timjan",name:"Timjan"},{id:"salvia",name:"Salvia"},{id:"basilika",name:"Basilika"}],avoidWhy:"Kransblommiga (Lamiaceae) delar en del jordburna sjukdomar. Vänta 2-3 år mellan mejram och andra kransblommiga på samma plats.",goodBefore:[{name:"Baljväxter"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter berikar jorden med kväve. Lök lämnar ren jord utan sjukdomstryck.",goodAfter:[{id:"morot",name:"Morot"},{id:"sallat",name:"Sallat"}],goodAfterWhy:"Mejrams aromatiska rester i jorden har mild desinficerande effekt som kan gynna efterföljande grödor."},varieties:[{name:"Mejram (Origanum majorana)",zones:[1,2,3,4],note:"Standardarten - den klassiska kökskryddan. Kompakta, aromatiska plantor med små runda blad och karaktäristiska knutformade blomställningar. Ekologiskt frö hos Lindbloms, Runåbergs och Impecta. OP."}],problems:[{name:"Bladlöss",symptom:"Klibbiga blad, deformerade skottspetsar. Små gröna löss på bladens undersida.",fix:"Spola av med vatten. Spraya med utspädd såplösning. Mejram i full sol och luftigt läge angrips sällan."},{name:"Mjöldagg",symptom:"Vitt, pudrigt överdrag på bladen. Vanligast i fuktig luft med dålig cirkulation.",fix:"Klipp bort angripna delar. Plantera luftigare. Undvik att vattna på bladen - vattna alltid vid roten."},{name:"Rotröta",symptom:"Plantan sloknar trots att jorden är blöt. Stambasen mörknar. Rötterna är bruna och mjuka.",fix:"Tyvärr ingen bot. Förebygg med väldränerad jord och måttlig vattning. Mejram vill hellre vara lite torr än för blöt."}],goodToKnow:[{icon:"warning",title:"Inte samma sak som oregano!",text:'Mejram och oregano är släkt men INTE samma krydda. Mejram (Origanum majorana) har en mildare, sötare, mer komplex smak. Oregano (Origanum vulgare) är kraftigare och "pizzaigare". Blanda inte ihop dem i recepten!',severity:"warning"},{icon:"warning",title:"Frostöm - vänta med utplantering",text:"Mejram klarar inte frost alls. Plantera inte ut förrän natttemperaturen är stabilt över 10°C. En sen frostnatt i maj kan ta kål på alla dina fina plantor.",severity:"warning"},{icon:"tip",title:"Sötare smak före blomning",text:"Skörda mejram precis innan hon blommar - då är aromen som mest komplex och söt. Efter blomning blir smaken något bitter. Klipp regelbundet så hon inte hinner blomma!",severity:"tip"},{icon:"tip",title:"Kärlekens krydda",text:"I antikens Grekland var mejram helgad åt Afrodite, kärlekens gudinna. Nygifta kröntes med mejramkransar för att säkra lycka i äktenskapet. Idag vet vi att mejram innehåller lugnande ämnen som faktiskt kan minska stress.",severity:"tip"},{icon:"tip",title:"Korvkryddan nr 1",text:'Mejram kallas ibland "korvkryddan" i Europa - den är den hemliga ingrediensen i klassisk bratwurst, leverpastej och falukorv. Smaka efter nästa gång du äter korv!',severity:"tip"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Mejram måste förodlas inomhus i Sverige - hon behöver värme och lång säsong. Fröna är pyttelila och gror långsamt (2-3 veckor) men har du tålamod belönas du rikligt.",steps:["Fyll små krukor eller pluggbrätte med fuktig såjord","Strö de pyttelila fröna på ytan - TÄCK INTE, de behöver ljus för att gro","Tryck försiktigt så fröna får jordkontakt","Spreja med vattenspray - översvämma inte","Täck med plastfolie och ställ varmt (18-25°C). Lufta dagligen","Groning tar 2-3 veckor - ha tålamod!","Gallra eller flytta till egna krukor vid 3-4 cm höjd","Härda av i 1 vecka innan utplantering. Plantera ut efter sista frost (natttemp över 10°C)"],tips:["Blanda de pyttelila fröna med lite sand för att så jämnare - annars kommer de i klumpar","En solig fönsterbräda räcker gott som förodlingsplats - mejram behöver inte växtbelysning","Nyp av topparna regelbundet från start så plantorna buskar sig istället för att sträcka sig"],indoorWeeks:"8-10 veckor före utplantering"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!1,description:"Mejram producerar pyttelila frön i sina karaktäristiska knutformade blomställningar. Låt några grenar blomma ut helt och torka på plantan innan du samlar in fröna.",steps:["Låt 2-3 grenar blomma ut helt (övriga klipps för skörd)","Vänta tills blomställningarna torkat och blivit bruna","Klipp av de torra blomgrenarna","Lägg i en papperspåse och skaka - fröna faller ut","Sikta bort skräp genom ett fint nät","Förvara torrt i märkt kuvert eller glasburk"],isolation:"Mejram kan korsa med oregano om de blommar samtidigt. Håll minst 100 meter avstånd för sortrena frön, eller låt bara en av dem blomma åt gången.",storageYears:"2-3 år",tip:"Mejramfrön är pyttelila och det kan vara lurigt att skilja dem från skräp. Torka blomställningarna ordentligt innan du försöker separera fröna."},storage:{shelfLife:"Färsk 3-5 dagar, torkad 12+ månader",methods:[{method:"Torkning (bäst!)",icon:"storage",duration:"12+ månader",description:"Mejram är en av de kryddor som faktiskt blir smakrikare av torkning. Häng knippen uppochner på torr, mörk plats i 1-2 veckor. Eller torka i ugn på lägsta temperatur (40°C) i 2-3 timmar.",best:!0},{method:"Frysning",icon:"snowflake",duration:"6+ månader",description:"Hacka bladen och frys i isbitsfack med lite vatten eller olivolja. Perfekt portioner att kasta direkt i grytan.",best:!1},{method:"Färsk i kyl",icon:"water",duration:"3-5 dagar",description:"Linda i fuktigt hushållspapper och lägg i plastpåse i kylen. Mejram är skör och vissnar snabbt - använd helst samma dag.",best:!1}],tips:["Torkad mejram är starkare än färsk - använd ungefär hälften så mycket","Förvara i mörk, lufttät glasburk - mejrams flyktiga oljor bryts ner av ljus","Smula bladen först vid användning - de behåller arom bättre hela",'Blanda med oregano och timjan för en egen "herbes de Provence"-mix']},harvestCalc:{minPerSqm:.1,maxPerSqm:.3,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp kvistar, nyp av toppar regelbundet",description:"Skörda mejram genom att klippa hela kvistar eller nypa av skottspetsar. Regelbunden skörd gör plantan buskigare och fördröjer blomningen. Skörda gärna på förmiddagen när daggen torkat men solen ännu inte gassar - då är halten av eteriska oljor som högst.",uses:[{use:"Korv & chark",tip:'Mejrams klassiska domän. Oumbärlig i bratwurst, falukorv, leverpastej och köttfärs. Det är mejram som ger den där "korvsmaken" du känner igen.'},{use:"Grytor & soppor",tip:"Tillsätt mejram mot slutet av kokningen - hon tappar smak vid långkok. En nypa torkad mejram lyfter varje ärtsoppa och köttgryta."},{use:"Potatis & rotfrukter",tip:"Strö mejram över rostade potatisar, rotsaker eller gratänger. Hon gifter sig fantastiskt med stärkelse och smör."},{use:"Ägg & ost",tip:"En nypa mejram i äggröran, omeletten eller ostpajen. Klassisk krydda i tyska och österrikiska äggrätter."}]}},fa=Object.freeze(Object.defineProperty({__proto__:null,mejram:O},Symbol.toStringTag,{value:"Module"})),z={name:"Melon",icon:"melon",family:"Gurkväxter",familyLatin:"Cucurbitaceae",difficulty:"Avancerad",difficultyWhy:"Kräver lång, varm säsong, helst växthus i Sverige, handpollinering och noggrant vattenmanagement. Ger fantastisk belöning om du lyckas - men det krävs erfarenhet och tålamod.",zones:{outdoor:[1,2],indoor:null,greenhouse:[1,2,3,4]},days:"90-120",spacing:"80 cm",rowSpacing:"100 cm",depth:"1-2 cm",ph:{min:6,max:6.8,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Melonen vill ha alla soltimmar hon kan få - minst 8 timmar direkt sol. I Sverige är varje solstråle guld värd för att frukterna ska mogna och bli söta. Skugga ger små, vattniga meloner utan smak."},temperature:{min:5,max:35,ideal:"22-28°C",detail:"Slutar växa helt under 10°C och dör av frost. Nätterna är flaskhalsen i Sverige - hon vill ha minst 18°C även på natten. Det är därför växthus är nästan ett måste norr om Skåne."},wind:{level:"Skyddat",detail:"Vindkänsliga rankor och blad. Skyddat läge vid södervägg eller i växthus är perfekt. Vinden kyler dessutom marken - och meloner VILL ha varma fötter."}},watering:{need:"Hög",icon:"water",summary:"Melonen är törstig men kräsen - hon vill ha jämn fukt hela säsongen men ALDRIG kallt vatten. Och hemligheten bakom söta meloner? Minska vattningen de sista 1-2 veckorna.",phases:[{phase:"Groning och plantutveckling",need:"Medel",tip:"Håll jorden jämnt fuktig. Vattna med ljummet vatten - kallt vatten chockar de värmekrävande rötterna."},{phase:"Vegetativ tillväxt",need:"Hög",tip:"Generös vattning 2-3 gånger i veckan. Rankorna växer snabbt nu och behöver ordentligt med fukt."},{phase:"Blomning och fruktbildning",need:"Hög",tip:"Kritisk period! Ojämn fukt nu gör att blommorna faller av och frukterna spricker. Vattna jämnt och aldrig på bladen."},{phase:"Mognad (sista 1-2 veckorna)",need:"Låg",tip:"MINSKA vattningen ordentligt! Det koncentrerar sockret och ger söta, smakrika meloner istället för vattniga besvikelser."}],mistakes:["Vattna med kallt kranvatten - melonens rötter hatar kyla och det ökar risken för svampsjukdomar","Vattna på bladen istället för vid roten - ger mjöldagg och gråmögel","Fortsätta vattna rikligt ända till skörd - resulterar i vattniga, smaklösa meloner","Ojämn vattning under fruktbildning - frukterna spricker eller faller av"],tip:"Ställ ut en hink med vatten i växthuset på morgonen så det värms upp, och vattna med det ljumma vattnet på eftermiddagen. Melonrötter ÄLSKAR varmt vatten."},soil:"Lucker, mullrik och näringsrik jord som värms upp snabbt. Sandig lerjord är perfekt - hon vill ha varma fötter och hatar kall, vattensjuk mark.",soilTips:["Bygg en varm bädd: gräv ner en lager halvförmultnad kompost eller stallgödsel 30 cm ner, fyll med jord ovanpå. Värmen underifrån ger melonen en flygande start","Mulcha med svart marktäckväv eller mörk kompost - det värmer jorden och håller fukt","Blanda in grovkornig sand om jorden är tung - meloner behöver luft runt rötterna och varm, porös jord"],timeline:{1:[{phase:"Förkultivering",months:"Mar-Apr",icon:"seedling"},{phase:"Utplantering",months:"Maj-Jun",icon:"seedling"},{phase:"Blomning",months:"Jun-Jul",icon:"flower"},{phase:"Fruktmognad",months:"Jul-Aug",icon:"sun"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}],4:[{phase:"Förkultivering",months:"Apr",icon:"seedling"},{phase:"Utplantering (växthus)",months:"Jun",icon:"seedling"},{phase:"Blomning",months:"Jul",icon:"flower"},{phase:"Fruktmognad",months:"Aug",icon:"sun"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}],6:[{phase:"Förkultivering",months:"Apr-Maj",icon:"seedling"},{phase:"Utplantering (växthus)",months:"Jun",icon:"seedling"},{phase:"Blomning",months:"Jul-Aug",icon:"flower"},{phase:"Fruktmognad",months:"Aug-Sep",icon:"sun"},{phase:"Skörd (om lyckad)",months:"Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:30,P:20,K:15,label:"Förkultivering"},{month:"Maj",N:70,P:30,K:30,label:"Vegetativ tillväxt"},{month:"Jun",N:50,P:60,K:40,label:"Blomning"},{month:"Jul",N:30,P:50,K:80,label:"Fruktbildning"},{month:"Aug",N:15,P:30,K:60,label:"Mognad"}],nutritionTips:[{timing:"Före plantering",tip:"Grundgödsla ordentligt med brunnen stallgödsel och kompost. Melonen är en riktig storätare och vill ha ett näringsrikt bord från start."},{timing:"Vegetativ fas",tip:"Ge flytande nässelvatten varannan vecka. Nu bygger hon rankor och blad och behöver mycket kväve."},{timing:"Vid blomning",tip:"Byt till fosforrik gödsel (benmjöl eller algbaserat) för att stötta fruktbildningen. Minska kvävet - annars får du bara rankor utan frukt."},{timing:"Under fruktmognad",tip:"Kaliumrik gödsel (vedaska) ger sötare frukt och starkare skal. Kväve ska vara minimalt nu."}],companions:{good:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Kvävefixerande rötter ger gratis näring till den hungriga melonplantan"},{id:"dill",name:"Dill",icon:"herb",why:"Lockar nyttoinsekter som äter bladlöss och andra skadegörare"},{id:"sockermajs",name:"Sockermajs",icon:"vegetable",why:"Fungerar som vindskydd och ger lä åt de värmekrävande melonrankorna"},{name:"Tagetes",icon:"flower",why:"Avskräcker nematoder och bladlöss med sin starka doft - en perfekt bodyguard"}],bad:[{id:"gurka",name:"Gurka",icon:"vegetable",why:"Samma familj och delar sjukdomar som mjöldagg och fusarium"},{id:"pumpa",name:"Pumpa",icon:"vegetable",why:"Konkurrerar om samma näring och utrymme, delar dessutom skadedjur"},{id:"potatis",name:"Potatis",icon:"vegetable",why:"Stor näringskonsument som tävlar med melonens hungriga rötter"}]},rotation:{avoid:[{id:"gurka",name:"Gurka"},{id:"squash",name:"Squash"},{id:"pumpa",name:"Pumpa"}],avoidWhy:"Alla gurkväxter delar jordburna svampsjukdomar som fusarium och pythium. Vänta minst 4 år innan du odlar melon på samma plats som annan gurkväxt stått.",goodBefore:[{id:"bondbona",name:"Bondböna"},{id:"artor",name:"Ärtor"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter fixerar kväve som melonen älskar. Lök och vitlök lämnar ren jord utan gurkväxtsjukdomar.",goodAfter:[{id:"morot",name:"Morot"},{id:"sallat",name:"Sallat"},{id:"lok",name:"Lök"}],goodAfterWhy:"Lättare grönsaker från andra familjer tar vara på restnäring utan att bygga på sjukdomstryck."},varieties:[{name:"Sweet Granite",zones:[1,2,3],note:"En av de allra tidigaste sorterna - helt avgörande i Sverige. Något avlånga frukter med svag nätning. Söt, aromatisk smak. Runåbergs, ekologiskt frö."},{name:"Jenny Lind",zones:[1,2,3],note:"Amerikansk kulturarvssort från 1850-talet med armeniskt ursprung. Ger många små, platta frukter. Pålitlig och bra för nybörjare. Runåbergs, ekologiskt."},{name:"Petit Gris de Rennes",zones:[1,2,3],note:"Creme de la creme bland franska cantaloupe-meloner. Små frukter med intensiv, söt smak. Kräver värme men belönar den som väntar. Runåbergs, ekologiskt."},{name:"Herma",zones:[1,2],note:"Svensk natmelon med söt, krispig, rosa-tonat fruktkött. Introducerad av Weibulls, numera sällsynt och återupptagen. Kräver god värme. Runåbergs, ekologiskt."},{name:"Charentais",zones:[1,2],note:"Den klassiska franska melonen - otrolig smak men kräver absolut bästa läge eller växthus. Värd besväret om du kan ge henne värme. Runåbergs, ekologiskt."}],problems:[{name:"Mjöldagg",symptom:"Vitt, puddrigt belägg på bladen som sprider sig snabbt. Vanligt i slutet av säsongen.",fix:"Luftig plantering är bästa förebyggande. Klipp bort angripna blad. Behandla med utspädd mjölk (1:9) eller åkerfräkenlag som förebyggande."},{name:"Gråmögel (Botrytis)",symptom:"Grått, luddigt mögel på frukter och stjälkar, särskilt i fuktig väderlek.",fix:"Förbättra luftcirkulationen i växthuset. Vattna aldrig på bladen. Ta bort angripna delar direkt."},{name:"Spinnkvalster",symptom:"Fina spindelnät på bladens undersida och gula prickar. Trivs i torr, varm luft.",fix:"Duscha bladens undersida med vatten regelbundet. Biologisk bekämpning med rovkvalster fungerar utmärkt i växthus."},{name:"Sniglar",symptom:"Stora hål i blad och gnagskador på unga frukter, särskilt nattetid.",fix:"Snigelkorn (järnfosfat), ölfällor eller kopparband runt odlingsbädden. Extra viktigt i fuktiga perioder."}],goodToKnow:[{icon:"warning",title:"Växthus nästan ett måste",text:"I Sverige räcker sällan sommarvärmen utomhus norr om Skåne. Växthus eller tunnel ger de extra graderna som melonen behöver - särskilt de varma nätterna.",severity:"warning"},{icon:"warning",title:"Handpollinering i växthus",text:"Inga bin i växthuset? Då måste du handpollinera. Ta en liten pensel, samla pollen från hanblommorna (de utan liten frukt vid basen) och stryk på honblommorna. Morgonen är bäst.",severity:"warning"},{icon:"harvest",title:"Begränsa antalet frukter",text:"Max 3-5 frukter per planta, gärna bara 2-3 för större sorter. Mer än så ger små, vattniga frukter som aldrig hinner mogna. Var brutal och plocka bort överflödiga.",severity:"tip"},{icon:"tip",title:"Stjälksprickan avslöjar allt",text:"Cantaloupe-meloner är mogna när stjälken spricker där den möter frukten och frukten lossnar lätt. Lukta vid blomänden - en söt melondoft betyder att det är dags!",severity:"tip"},{icon:"sun",title:"Rankning sparar plats",text:"I växthus kan du leda rankorna uppåt längs snören eller nät. Häng frukt i nätpåsar som stöd. Du sparar golvyta och frukterna får bättre luftcirkulation.",severity:"tip"},{icon:"warning",title:"Sluta vattna innan skörd",text:"Minska vattningen kraftigt 1-2 veckor före skörd. Det koncentrerar sockret och ger den där söta, aromatiska smaken som gör egenodlad melon oförglömlig.",severity:"tip"}],sowing:{method:"indoor",label:"Förkultivering inomhus",description:"Meloner MÅSTE förkultiveras i Sverige - säsongen är för kort för direktsådd. Så inomhus i mars-april och plantera ut när all frostrisk är över och jorden är ordentligt varm.",steps:["Så 2-3 frön i varje kruka (8-10 cm), 1-2 cm djupt. Använd förfuktad såjord.","Ställ på varm plats (25-30°C) - ovanpå kylskåpet eller på en värmematta. Melonfrön vill ha VÄRME för att gro.","Fröna gror på 5-10 dagar. Gallra till den starkaste plantan i varje kruka.","Sänk temperaturen till 18-20°C efter groning. Ge 14-16 timmars ljus - gärna växtbelysning.","Härda av gradvis under 1-2 veckor innan utplantering. Börja med några timmar ute i skyddat läge.","Plantera ut när jordtemperaturen är minst 18°C och all frostrisk är borta - oftast juni i de flesta zoner.","Plantera i förberedd, uppvärmd bädd med 80 cm avstånd. Vattna rikligt vid plantering med ljummet vatten."],tips:["Blötlägg fröna i ljummet vatten över natten före sådd - förbättrar groningen markant","Förkultivera i torvkrukor eller djupa pluggar som planteras ut direkt - meloner ogillar att bli omflyttade","Svart marktäckväv eller plastmulch värmer jorden 3-5°C extra - kan vara skillnaden mellan skörd och fiasko"],indoorWeeks:"4-6 veckor"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!1,description:"Melonfrön är enkla att ta vara på och håller sig länge. Utmaningen är isolering - alla sockermeloner (Cucumis melo) korsar med varandra, men INTE med gurka eller vattenmelon.",steps:["Låt en frukt mogna helt på plantan - längre än du tror, tills den lossnar av sig själv","Skär frukten på mitten och skopa ut fröna med det geléartade fruktköttet runt","Lägg fröna i en burk med lite vatten och låt stå 2-3 dagar - fermentering tar bort groningshämmande ämnen","Skölj fröna noggrant i ett durkslag och ta bort allt fruktkött","Torka på ett kaffefilter eller papper i 1-2 veckor på luftig plats","Testa att ett frö går av när du böjer det - då är de tillräckligt torra","Förvara i märkt papperspåse, svalt och torrt"],isolation:"Sockermeloner (cantaloupe, honungsmelon, natmelon) korsar med varandra men INTE med gurka eller vattenmelon. Odla bara en sort för fröbesparing, eller handpollinera och märk blommorna.",storageYears:"5-10 år",tip:"Melonfrön är riktiga långlivare! Korrekt torkade och förvarade kan de gro efter 10 år. Alla rekommenderade sorter är OP - perfekta för fröbesparing."},storage:{shelfLife:"1-2 veckor",methods:[{method:"Rumstemperatur",icon:"temperature",duration:"3-5 dagar",description:"Bästa smaken! Hel melon vid rumstemperatur. Skuren melon täcks med plastfolie och äts inom ett dygn.",best:!0},{method:"Kylskåp",icon:"snowflake",duration:"1-2 veckor",description:"Hel, oskuren melon håller sig längst i kylskåp. Skuren melon i tättslutande behållare max 3-5 dagar. Ta ut ur kylen 30 minuter före servering - kyla dämpar smaken.",best:!1},{method:"Frysa",icon:"snowflake",duration:"6-12 månader",description:"Skär i tärningar eller gör kulor, frys på plåt och lägg sedan i påse. Konsistensen ändras men perfekt till smoothies och glass.",best:!1},{method:"Torka",icon:"sun",duration:"Flera månader",description:"Tunna skivor i torkugn eller dehydrator. Blir ett sött, segt snacks - överraskande gott!",best:!1}],tips:["Egenodlad melon har betydligt kortare hållbarhet än butiksmelon - ät den färsk och njut!","Omslagsmelon (cantaloupe) håller sig kortare än honungsmelon - planera att äta den snabbt","Lukta på blomänden - när den doftar sött är den perfekt mogen och bör ätas snart","Lagra aldrig skuren melon bredvid andra frukter - melondoften överförs lätt"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:4,unit:"kg"}},ja=Object.freeze(Object.defineProperty({__proto__:null,melon:z},Symbol.toStringTag,{value:"Module"})),_={name:"Morot",icon:"morot",family:"Flockblommiga",familyLatin:"Apiaceae",difficulty:"Enkel",difficultyWhy:"Direktsås utomhus, tålig, kräver minimal skötsel efter gallring.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:null},days:"60-130",spacing:"3-5 cm",rowSpacing:"25-30 cm",depth:"1 cm",ph:{min:6,max:6.8,ideal:6.3},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Minst 6 timmar sol per dag för bäst resultat, men klarar halvskugga (4+ timmar). I halvskugga blir morötterna tunnare men sötare."},temperature:{min:7,max:24,ideal:"15-20°C",detail:"Gror redan vid 7°C men trivs bäst runt 15-20°C. Tål lätt frost - morötter blir faktiskt sötare efter frost!"},wind:{level:"Tålig",detail:"Låg profil - påverkas sällan av vind. Inga särskilda krav."}},watering:{need:"Medel",icon:"water",summary:"Jämn fukt under hela säsongen - varken för blött eller för torrt. Ojämn bevattning ger spruckna eller håriga morötter.",phases:[{phase:"Groning (0-3 veckor)",need:"Hög",tip:"Håll jorden jämnt fuktig - fröna MÅSTE ha fukt för att gro. Torkar ytan ut dör groddarna. Vattna försiktigt med stril, gärna på morgonen."},{phase:"Tillväxt (3-8 veckor)",need:"Medel",tip:"Vattna 2-3 gånger i veckan om det inte regnar. Djupvattna hellre än att stänka lite ofta - det tvingar rötterna att söka sig nedåt."},{phase:"Rotutveckling (8+ veckor)",need:"Medel-Låg",tip:"Minska vattningen något. För mycket vatten nu ger vattniga morötter med sämre smak. Jämn fukt är viktigare än mycket fukt."}],mistakes:["Ojämn vattning (torrt→blött→torrt) ger spruckna morötter","Överspolning vid sådd - fröna sköljs ihop i klumpar","Vattna ovanifrån i full sol - dropparna kan bränna blasten"],tip:"Mulcha med gräsklipp eller halm efter uppkomst - det håller fukten jämn och minskar behovet av vattning rejält."},soil:"Lucker, sandblandad, stenfri jord. Undvik nygödslad jord - morötter blir krokiga och kluvna.",soilTips:["Gräv djupt (30 cm) och ta bort stenar","Blanda in sand om du har lerjord","Använd väl brunnen kompost från förra året - aldrig färsk gödsel"],timeline:{1:[{phase:"Direktså",months:"Apr",icon:"seedling"},{phase:"Gallra",months:"Maj",icon:"scissors"},{phase:"Gödsla (lätt)",months:"Jun",icon:"water"},{phase:"Skörd tidig",months:"Jul",icon:"harvest"},{phase:"Huvudskörd",months:"Aug-Sep",icon:"harvest"}],4:[{phase:"Direktså",months:"Maj",icon:"seedling"},{phase:"Gallra",months:"Jun",icon:"scissors"},{phase:"Gödsla (lätt)",months:"Jun-Jul",icon:"water"},{phase:"Skörd tidig",months:"Aug",icon:"harvest"},{phase:"Huvudskörd",months:"Sep",icon:"harvest"}],6:[{phase:"Direktså",months:"Jun",icon:"seedling"},{phase:"Gallra",months:"Jul",icon:"scissors"},{phase:"Gödsla (lätt)",months:"Jul",icon:"water"},{phase:"Huvudskörd",months:"Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:20,P:10,K:10,label:"Sådd"},{month:"Maj",N:60,P:20,K:15,label:"Tillväxt"},{month:"Jun",N:80,P:40,K:25,label:"Bladtillväxt"},{month:"Jul",N:40,P:70,K:50,label:"Rotutveckling"},{month:"Aug",N:15,P:80,K:75,label:"Mognad"},{month:"Sep",N:5,P:50,K:85,label:"Skörd"}],nutritionTips:[{timing:"Vid sådd",tip:"Grundgödsla med brunnen kompost. Inget extra kväve."},{timing:"Tidig tillväxt",tip:"Lätt giva flytande alggödsel varannan vecka."},{timing:"Rotutveckling",tip:"Sluta med kväve. Ge kaliumrik gödsel (t.ex. vedaska) för smak och lagring."},{timing:"Mognad",tip:"Ingen gödsling. Låt morötterna mogna och utveckla sötma."}],companions:{good:[{id:"lok",name:"Lök",icon:"vegetable",why:"Traditionellt samodlas med morot - lökens starka doft kan förvirra morotsflugan"},{id:"salvia",name:"Salvia",icon:"herb",why:"Salvia maskerar morotsdoften och håller skadedjur borta"},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Tomatens starka doft förvirrar morotsflugan"},{id:"purjolok",name:"Purjolök",icon:"vegetable",why:"Samma effekt som vanlig lök - doftbarriär"}],bad:[{id:"dill",name:"Dill",icon:"herb",why:"Samma familj (flockblommiga) - delar sjukdomar och skadedjur"},{id:"palsternacka",name:"Palsternacka",icon:"vegetable",why:"Samma familj - konkurrerar och delar morotsflugan"},{id:"selleri",name:"Selleri",icon:"vegetable",why:"Samma familj - ökar risk för sjukdomar"}]},rotation:{avoid:[{id:"palsternacka",name:"Palsternacka"},{id:"persilja",name:"Persilja"},{id:"selleri",name:"Selleri"},{id:"dill",name:"Dill"},{id:"fankal",name:"Fänkål"}],avoidWhy:"Alla tillhör flockblommiga - delar sjukdomar och skadedjur. Vänta minst 3 år.",goodBefore:[{name:"Baljväxter (ärtor, bönor)"},{id:"lok",name:"Lök"},{id:"vitlok",name:"Vitlök"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden. Lökväxter sanerar mot svampsjukdomar.",goodAfter:[{name:"Kål"},{id:"sallat",name:"Sallat"},{id:"spenat",name:"Spenat"}],goodAfterWhy:"Bladgrönsaker drar nytta av den djupt bearbetade jorden moroten lämnar efter sig."},varieties:[{name:"Nantes 2",zones:[1,2,3,4,5,6,7],note:"Klassikern. Pålitlig överallt."},{name:"Autumn King",zones:[1,2,3,4,5,6,7],note:"Stor, bra för lagring."},{name:"Flyaway F1",zones:[1,2,3,4,5,6,7],note:"Morotsfluge-resistent!"},{name:"Purple Haze F1",zones:[1,2,3,4,5,6],note:"Lila utsida, orange insida. F1-hybrid - frön ger inte sortäkta plantor."}],problems:[{name:"Morotsflugan",symptom:"Rostbruna gångar i roten",fix:"Samodla med lök. Fiberduk. Så efter mitten av juni."},{name:"Krokiga morötter",symptom:"Delade, krokiga rötter",fix:"Stenig eller nygödslad jord. Rensa stenar, använd gammal kompost."},{name:"Gröna toppar",symptom:"Grön missfärgning vid toppen",fix:"Kupa jord runt topparna när de sticker upp."}],goodToKnow:[{icon:"warning",title:"Så aldrig i nygödslad jord",text:"Färsk gödsel (eller för mycket kväve) ger krokiga, kluvna och håriga morötter. Använd bara väl brunnen kompost - helst från förra året.",severity:"warning"},{icon:"soil",title:"Stenar = krokiga morötter",text:"Varje sten i jorden tvingar roten att växa runt den. Rensa ordentligt ner till 30 cm djup, eller odla i upphöjd bädd med stenfri jord.",severity:"warning"},{icon:"rotation",title:"Så i omgångar - inte allt på en gång",text:"Så med 3 veckors mellanrum från april till juni. Då får du färska morötter hela sommaren och hösten istället för 40 kg samtidigt i september.",severity:"tip"},{icon:"snowflake",title:"Tål frost - en av de sista du skördar",text:"Morötter blir faktiskt sötare efter en lätt frost! Du kan lämna dem i jorden långt in på hösten. Täck med halm så klarar de sig ännu längre.",severity:"tip"},{icon:"scissors",title:"Gallra utan dåligt samvete",text:"Det känns slösigt att dra upp små plantor, men om du inte gallrar får du bara tunna, korta morötter. Var brutal - 3-5 cm avstånd.",severity:"tip"}],sowing:{method:"direct",label:"Direktsådd",description:"Moroten sås direkt på friland - den ogillar att bli omplacerad eftersom pålroten störs.",steps:["Luckra jorden djupt (minst 30 cm) och kratta till fin struktur","Dra ett grunt spår (ca 1 cm) med en pinne eller krattskaft","Så fröna glest - blanda gärna med sand för jämnare fördelning","Täck med ett tunt lager jord eller vermiculit","Vattna försiktigt med stril - fröna får inte spolas bort","Gallra till 3-5 cm avstånd när plantorna är 5 cm höga"],tips:["Så i omgångar med 3 veckors mellanrum för skörd hela säsongen","Blötlägg fröna i ljummet vatten 12 timmar före sådd - snabbar på groningen","Täck med fiberduk de första veckorna mot morotsflugan"],indoorWeeks:null},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Moroten är tvåårig - den bildar frö först andra året. Du måste överväntra roten och plantera ut den igen på våren.",steps:["Välj de finaste morötterna vid skörd och spara dem","Lagra rötterna i sand i en kall (men frostfri) källare över vintern","Plantera ut rötterna tidigt på våren med toppen i marknivå","Moroten skjuter blomstjälk under sommaren - vita flockar","Låt fröna mogna tills flockarna börjar bli bruna","Klipp av hela flocken och torka inomhus i en papperspåse","Gnugga loss fröna och rensa bort skräp"],isolation:"Korsar med vild morot och andra morotssorter. Odla bara en sort för frö, eller isolera med minst 500 m (gärna 1000 m).",storageYears:"2-3 år",tip:"Märk alltid sort och år! Morotsfrö tappar grobarhet snabbt efter 3 år."},storage:{shelfLife:"6-8 månader",methods:[{method:"I landet (med täckning)",icon:"leaf",duration:"Ända till december/januari",description:"Låt morötterna ligga kvar i jorden och täck med ett tjockt lager halm, löv eller fiberduk. Morötterna blir sötare av kylan och håller sig fräscha ända tills marken fryser på djupet.",best:!0},{method:"Sandlåda i källare",icon:"storage",duration:"4-6 månader",description:"Lägg morötterna i lager med fuktig sand i en låda. Förvara svalt (1-4°C) och mörkt. Klassisk metod som fungerar utmärkt. Kolla med jämna mellanrum att ingen börjat mögla.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"3-4 veckor",description:"Klipp av blasten (den suger fukt ur roten). Lägg i plastpåse med några hål. Fungerar för kortare lagring.",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Skala, skär i bitar och blanchera 2-3 minuter. Kyl snabbt i isvatten, torka av och frys in. Perfekt för soppa och gryta.",best:!1}],tips:["Ta alltid bort blasten direkt vid skörd - den suger fukt och näring ur roten","Tvätta INTE morötter som ska lagras länge - jord skyddar faktiskt","Skadade morötter lagras dåligt - ät dem först","Morötter som börjar bli slappa kan räddas genom att ställa dem i kallt vatten några timmar"]},harvestCalc:{minPerSqm:2,maxPerSqm:5,unit:"kg"}},ya=Object.freeze(Object.defineProperty({__proto__:null,morot:_},Symbol.toStringTag,{value:"Module"})),I={name:"Mullbär",icon:"mullbar",category:"bär",family:"Mullbärsväxter",familyLatin:"Moraceae",perennial:!0,lifespan:"100-300 år",difficulty:"Enkel",difficultyWhy:"När mullbärsträdet väl är etablerat är det en av de mest lättskötta fruktbärande växterna du kan ha. Inga speciella sjukdomar, minimal beskärning, självfertilt. Utmaningen? Att hitta rätt sort för din zon och få igenom trädet de första vintrarna.",zones:{outdoor:[1,2,3,4],indoor:null,greenhouse:null},days:"60-80",spacing:"400-600 cm",rowSpacing:"500-800 cm",depth:"Plantera i samma djup som i krukan",ph:{min:6,max:7.5,ideal:6.8},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Mullbärsträdet kräver full sol för att sätta riklig frukt. I halvskugga växer han fortfarande fint men skörden minskar drastiskt. Ge honom den soligaste, varmaste platsen du har - gärna mot en södervägg där värmen reflekteras."},temperature:{min:-30,max:35,ideal:"20-25°C",detail:"Morus alba (vitt mullbär) är härdigt ner till -30°C i vintervila - en äkta nordbo! Han bryter sent på våren (smart nog att undvika vårfrost) och trivs bäst i sommarens värme. Morus nigra (svart mullbär) klarar ca -20 till -23°C men behöver lång, varm sommar och fungerar enbart i zon 1-2."},wind:{level:"Skyddat",detail:"Unga träd behöver vindskydd de första åren. Etablerade träd klarar vind bra men de bästa bären får du i en skyddad, varm position. Grenvinklar kan vara spröda - kraftig vind med tunga bärklaser kan ge grenbrott."}},watering:{need:"Låg",icon:"water",summary:"Mullbärsträdet är förvånansvärt torktåligt när det väl etablerat sig. Hans djupa rötter hittar vatten långt ner. Men de första åren behöver han din hjälp, och under blomning och fruktmognad tackar han med sötare bär om han får vatten.",phases:[{phase:"Etablering (år 1-2)",need:"Hög",tip:"Vattna djupt varje vecka under torra perioder. Rötterna måste hitta ner ordentligt - det är nu grunden läggs för ett träd som ska leva i generationer."},{phase:"Vår (knoppsprickning)",need:"Medel",tip:"Vattna vid längre torka. Mullbärsträdet bryter sent på våren och behöver fukt för att komma igång ordentligt."},{phase:"Blomning och fruktmognad",need:"Medel",tip:"Jämn fukt nu ger större, saftigare bär. Torka under denna period ger små, torra bär som faller tidigt."},{phase:"Etablerat träd (5+ år)",need:"Låg",tip:"Ett etablerat mullbärsträd klarar sig i princip på naturlig nederbörd. Vattna bara vid riktigt utdragen torka."}],mistakes:["Övervattning - mullbärsträdet HATAR stående vatten. Rötterna ruttnar i vattensjuk jord","Glömmer nyplanterade träd under torra somrar - de första åren är kritiska","Vattnar för sent på hösten - trädet behöver mogna av och förbereda sig för vinter"],tip:"Mulcha med 10-15 cm bark eller kompost runt stammen (men inte ända intill!) det håller fukten, ger näring och skyddar rötterna mot kyla. Det allra viktigaste du kan göra för ett ungt mullbärsträd."},soil:"Djup, väldränerad och näringsrik jord. Mullbärsträdet anpassar sig till det mesta - sand, lera, mylla - men den absolut viktigaste regeln är god dränering. Stående vatten är döden.",soilTips:["Blanda in rikligt med kompost vid plantering - gräv en grop dubbelt så bred som rotklumpen","Kalkrik jord är en bonus - mullbärsträdet trivs med neutralt till svagt basiskt pH","På tung lerjord: plantera upphöjt 20-30 cm och blanda in grov sand","Undvik platser där vatten samlas efter regn - det är den säkraste vägen att döda trädet"],timeline:{1:[{phase:"Plantering",months:"Mar-Apr",icon:"seedling"},{phase:"Knoppsprickning",months:"Apr-Maj",icon:"leaf"},{phase:"Blomning",months:"Maj",icon:"flower"},{phase:"Skörd",months:"Jul-Aug",icon:"harvest"},{phase:"Beskärning",months:"Feb-Mar",icon:"scissors"},{phase:"Vintervila",months:"Nov-Mar",icon:"snowflake"}],4:[{phase:"Plantering",months:"Maj",icon:"seedling"},{phase:"Knoppsprickning",months:"Maj",icon:"leaf"},{phase:"Blomning",months:"Jun",icon:"flower"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"},{phase:"Beskärning",months:"Mar-Apr",icon:"scissors"},{phase:"Vintervila",months:"Okt-Apr",icon:"snowflake"}],6:[{phase:"Plantering",months:"Jun (om du vågar)",icon:"seedling"},{phase:"Blomning",months:"Jun-Jul",icon:"flower"},{phase:"Skörd",months:"Sep (om frukten hinner mogna)",icon:"harvest"},{phase:"Vintervila",months:"Okt-Maj",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:4,P:2,K:2,label:"Vårstart"},{month:"Maj",N:6,P:4,K:3,label:"Tillväxt"},{month:"Jun",N:5,P:5,K:4,label:"Blomning"},{month:"Jul",N:3,P:4,K:6,label:"Fruktmognad"},{month:"Aug",N:2,P:3,K:5,label:"Skörd"},{month:"Sep",N:1,P:2,K:3,label:"Avmognad"}],nutritionTips:[{timing:"Tidig vår (april)",tip:"Ge kompost eller brunnen gödsel i en ring runt trädets droppzon. Mullbärsträdet är ingen storkrävare men uppskattar en generös vårstart."},{timing:"Vid blomning (maj-juni)",tip:"En giva kaliumrik gödsel (vedaska eller alggödsel) stärker fruktbildningen och ger sötare bär."},{timing:"ALDRIG efter augusti",tip:"Sluta gödsla senast i augusti! Nya skott måste hinna mogna och härda av innan vintern. Sen gödsling kan kosta grenar - eller hela trädet."},{timing:"Etablerade träd",tip:"Ett mullbärsträd som stått i 10+ år behöver ofta ingen gödsling alls. Kompost som mulch räcker gott."}],companions:{good:[{id:"vitlok",name:"Vitlök",icon:"vegetable",why:"Vitlökens svaveldoft avskräcker bladlöss och kvalster. Plantera vitlök i en ring runt trädet - naturligt skadedjursskydd."},{id:"timjan",name:"Timjan",icon:"herb",why:"Lockar honungsbin som pollinerar mullbärsblommorna. Dessutom trivs timjan i samma soliga, väldränerade läge."},{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Perfekt marktäckare under mullbärsträdet. Jordgubbarna trivs i den lätta halvskuggan och lockar pollinatörer."}],bad:[{name:"Valnöt",icon:"vegetable",why:"Valnötsträd producerar juglone - ett ämne som är giftigt för mullbärsträd. Håll minst 15 meters avstånd!"}]},rotation:{avoid:[{name:"Andra mullbärsträd"},{name:"Fikon"}],avoidWhy:"Moraceae-familjen delar en del jordburna sjukdomar. Men mullbärsträdet är perennt och ska stå på samma plats i generationer - rotation är sällan aktuellt.",goodBefore:[{name:"Gräsmatta"},{name:"Baljväxter"}],goodBeforeWhy:"Mark som legat som gräsmatta eller gröngödsling i flera år är idealisk - ren från sjukdomar och med bra struktur.",goodAfter:[{id:"artor",name:"Ärtor"},{name:"Gröngödsling"}],goodAfterWhy:"Om ett träd tas bort efter 50+ år behöver jorden byggas upp. Baljväxter och gröngödsling återställer struktur och näring."},varieties:[{name:"Mulle",zones:[1,2,3,4],note:"DEN sort du ska välja i Sverige. E-planta-certifierad, buskform, börjar bära redan efter 2-3 år. Svarta, söta bär. Fröplantsfynd från Balsgård (SLU) på 1960-talet - utvald för nordiskt klimat."},{name:"Morus alba (vitt mullbär)",zones:[1,2],note:"Det klassiska mullbärsträdet. Blir 8-10 meter. Vita till rosa bär med mild smak. Härdig men trädformen kräver utrymme och tålamod. Kan fungera i zon 3 i gynnsamt läge."},{name:"Morus alba Pendula",zones:[1,2],note:"Hängande, graciös form som är lika vacker som den är användbar. Söta små bär och ett fantastiskt prydnadsträd. Vuxen höjd 3-4 meter."},{name:"Illinois Everbearing",zones:[1,2,3],note:"Snabbväxande Morus alba x rubra-hybrid med stora, mörka bär och fantastisk smak. Det närmaste du kommer svart mullbärs smak i nordligt klimat."},{name:"Morus nigra (svart mullbär)",zones:[1,2],note:"Den godaste av alla - intensiv, komplex smak. Men bara för de mildaste delarna av Sverige (Skåne, Gotland, Öland). Behöver skyddad, varm plats."}],problems:[{name:"Bladlöss",symptom:"Krusiga blad, klibbig honungsdagg på bladen. Vanligast på unga skott.",fix:"Spruta med såpvatten. Uppmuntra nyckelpigor och parasitsteklar. Samodla med vitlök. Friska träd hanterar lätta angrepp utan hjälp."},{name:"Mjöldagg",symptom:"Vit-grått puder på bladen, framför allt i fuktigt väder med svala nätter.",fix:"God luftcirkulation genom gallring. Ta bort drabbade blad. Undvik övervattning. Mjölkvatten (1 del mjölk, 9 delar vatten) kan förebygga."},{name:"Fåglar",symptom:"Bären försvinner innan du hinner skörda!",fix:'Ärligt talat: acceptera det eller häng nät. Många odlare planterar mullbärsträd AVSIKTLIGT som "uppoffring" - fåglarna äter mullbär istället för körsbär och blåbär.'},{name:"Stamblödning",symptom:"Riklig savflöde från sår och beskärningssnitt.",fix:'Beskär BARA i sen vintervila (februari-mars). Aldrig under saftiga perioder! Mullbärsträdet "blöder" kraftigt om man skär i fel tid.'}],goodToKnow:[{icon:"warning",title:"Bären färgar ALLT",text:"Mogna mullbär färgar händer, kläder, sten och trä djupt lila-svart. Plantera ALDRIG bredvid en vit husvägg, terrass, torkställning eller parkeringsplats. Det här är ingen överdrift - en enda mogen frukt på vit betong och du ser det i veckor.",severity:"warning"},{icon:"tip",title:"Bryter sent - och det är smart",text:'Mullbärsträdet bryter senare på våren än de flesta fruktträd. Det har länge tolkats som lathet, men det är faktiskt smart: han slipper vårfrosten som tar äppelblom och körsbärsblom. Färre missade skördar tack vare "sen start".',severity:"tip"},{icon:"tip",title:"Självfertilt - inget pollinatörsträd behövs",text:"Morus alba har både han- och honblommor på samma träd och pollineras av vinden. Du behöver bara ETT träd för skörd. Ett andra träd kan öka skörden, men det är inte nödvändigt.",severity:"tip"},{icon:"tip",title:"Fåglarnas favoritträd - använd det strategiskt",text:'Fåglar ÄLSKAR mullbär. Plantera ett mullbärsträd nära dina körsbärs- eller blåbärsodlingar så äter fåglarna mullbär istället. Det kallas "uppoffringsträd" och funkar förvånansvärt bra.',severity:"tip"},{icon:"warning",title:"Välj sort efter zon - KRITISKT",text:"Morus nigra (den godaste!) klarar bara zon 1-2. Vill du odla i zon 3-4 är Mulle eller Illinois Everbearing de enda säkra korten. Fel sortval = ett dött träd efter första riktiga vintern.",severity:"warning"},{icon:"tip",title:"Ett träd för generationer",text:"Mullbärsträd kan bli 150-300 år gamla. Du planterar inte bara för dig själv - du planterar för dina barnbarn. Det finns mullbärsträd i Sverige som planterats på 1700-talet och fortfarande bär frukt.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Mullbärsträd planteras som krukodlade eller barrotade plantor, helst på våren. Välj den soligaste, varmaste och mest skyddade platsen i trädgården.",steps:["Gräv en grop dubbelt så bred och lika djup som rotklumpen","Blanda planteringsjorden med rikligt kompost och lite benmjöl","Plantera i samma djup som i krukan - INTE djupare","Vattna rikligt vid plantering - genomblöt hela gropen","Mulcha med 10-15 cm bark eller kompost runt stammen (lämna 10 cm luft närmast stammen)","Sätt stödkäpp och bind löst med breda band","Skydda stammen mot gnag med stamnät om du har kaniner eller rådjur"],tips:["Mot en södervägg är drömplatsen - mullbärsträdet älskar reflekterad värme","Tänk på framtiden: ett mullbärsträd kan bli 8-10 meter brett. Ge det plats!","Plantera helst på våren i zon 3-4 så trädet har en hel sommar att etablera sig innan vintern"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Mullbärsträd förökas bäst vegetativt - sticklingar, ympning eller avläggare. Frösådd fungerar men avkomman varierar och det tar 5-10 år till första skörd. Namnsorter som Mulle förökas ALLTID vegetativt.",steps:["Sticklingar: Klipp 20-30 cm vedstycken på senvintern (feb-mars)","Doppa i rotningshormon och sätt i fuktig sand/perlit","Håll i sval, ljus miljö - rötter bildas inom 2-3 månader","Plantera ut på skyddad plats nästkommande vår","Eller: avläggning - böj ner en låg gren och täck med jord. Rötter bildas under säsongen","Klipp av från moderträdet nästa vår när rötterna är starka"],isolation:"Vegetativ förökning ger exakta kopior av moderträdet. Ingen korspollinering relevant.",storageYears:"Ej tillämpligt",tip:"Sticklingar är enklast för hemmaodlaren. Välj alltid friska grenar från ett sjukdomsfritt träd - allt följer med till den nya plantan."},storage:{shelfLife:"1-2 dagar (färska)",methods:[{method:"Frysning",icon:"snowflake",duration:"10-12 månader",description:"DET bästa sättet. Lägg bären i ett lager på bakplåtspapper, frys 2 timmar, flytta sedan till fryspåse. Perfekta i smoothies, bakning och glass hela vintern.",best:!0},{method:"Torkning",icon:"sun",duration:"6-12 månader",description:"Torka i ugn på 60°C eller i torkmaskin. Torkade mullbär är INTENSIVT söta och nästan godisaktiga. Fantastiska i müsli, bakning och som snacks.",best:!1},{method:"Sylt och saft",icon:"storage",duration:"1+ år",description:"Mullbärssylt är underbart och kräver mindre socker än många andra bär. Saften blir djupt lila och smakar fantastiskt. Blanda gärna med citron för lite syra.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"1-2 dagar",description:"Lägg i ett lager på hushållspapper. Tvätta INTE förrän du ska äta. Mullbär är extremt ömtåliga - ät dem samma dag om du kan.",best:!1}],tips:["Skörda genom att lägga en duk under trädet och skaka grenarna - mogna bär faller naturligt","Mullbär är EXTREMT ömtåliga och håller knappt en dag i rumstemperatur","Bären färgar allt - skörda i mörka kläder du inte bryr dig om","Torkade mullbär är naturligt söta och behöver inget tillsatt socker - perfekt hälsosnacks"]},harvestCalc:{minPerSqm:2,maxPerSqm:5,unit:"kg"},pruning:{label:"Beskärning",types:{formation:{name:"Uppbyggnadsbeskärning",when:"Sen vintervila (februari-mars) under de första 3-5 åren",description:"Mullbärsträdet bildar naturligt en vacker, rund krona. Din uppgift är att hjälpa det på traven: välj en central ledare eller öppen vasform, ta bort korsande grenar och skapa en stabil struktur som bär frukt i 100 år.",steps:["Välj 3-5 huvudgrenar jämnt fördelade runt stammen","Ta bort grenar som korsar varandra eller växer inåt","Korta sidoskott till 30-40 cm för att stimulera förgrening","Ta bort allt skottskjut från stammen under kronan","Gör ALLTID rena snitt nära en knopp - lämna inga stumpar","Behandla stora sår med trädvax (trädet blöder annars)"]},maintenance:{name:"Underhållsbeskärning",when:"Sen vintervila (februari-mars) - ALDRIG under växtsäsongen!",description:"Ett etablerat mullbärsträd behöver minimal beskärning. Regeln är enkel: ta bort dött, sjukt och korsande. Mullbärsträd som lämnas i fred bildar naturligt vackra kronor. Mindre är mer.",steps:["Ta bort döda och skadade grenar","Klipp bort grenar som korsar eller gnider mot varandra","Gallra inåtväxande grenar för bättre ljusinsläpp","Ta bort eventuella rotskott vid stambasen","Undvik att ta bort mer än 20-25% av kronan per år"]}}},propagation:{difficulty:"Medel",methods:[{method:"Vedsticklingar",description:"Klipp 20-30 cm bitar av fjolårsskott i februari-mars. Doppa i rotningshormon och sätt i fuktig sand. Rötter på 2-3 månader. Det enklaste sättet för hemmaodlaren.",icon:"scissors"},{method:"Avläggning",description:"Böj ner en låg gren till marken och täck med 10 cm jord. Rötter bildas under sommaren. Klipp av från moderträdet nästa vår.",icon:"seedling"},{method:"Ympning",description:"Proffsmetoden - ympa önskad sort på Morus alba-grundstam. Ger snabbast frukt (1-2 år) men kräver erfarenhet och verktyg.",icon:"plant"}],tip:"Vedsticklingar i februari-mars är det enklaste för hemmaodlaren. Var noga med rotningshormon och håll sticklingar fuktiga men inte blöta. Tålamod - det tar 2-3 månader."}},Sa=Object.freeze(Object.defineProperty({__proto__:null,mullbar:I},Symbol.toStringTag,{value:"Module"})),W={name:"Mynta",icon:"mynta",category:"kryddor",family:"Kransblommiga",familyLatin:"Lamiaceae",perennial:!0,lifespan:"10+ år (sprider sig kraftigt!)",difficulty:"Enkel",difficultyWhy:"Mynta är en av de mest lättodlade kryddväxterna som finns. Problemet är snarare att STOPPA henne - hon sprider sig aggressivt via underjordiska utlöpare och tar över hela trädgården om du inte håller henne i schack.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:[1,2,3,4,5,6,7,8],greenhouse:null},days:"90-110",spacing:"25-40 cm",rowSpacing:"40-50 cm",depth:"0.5 cm",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Mynta trivs i sol men klarar halvskugga utmärkt - hon blir till och med gladare i lite skugga under höga sommaren. Full skugga ger glesare tillväxt och svagare smak, men hon överlever ändå. En av få kryddor som faktiskt gillar skuggigare läge."},temperature:{min:-20,max:35,ideal:"15-22°C",detail:"Mynta är en riktig nordbo som överlevt många hårda vintrar. Ovanjordiska delar dör ned vid frost, men rotsystemet klarar ner till -20°C med snötäcke. På våren skjuter hon upp nya skott som om inget hänt."},wind:{level:"Tålig",detail:"Mynta är robust och klarar vind utan bekymmer. Stjälken är stadig och bladen är tuffa nog att stå emot både blåst och regn. Inga vindskydd behövs."}},watering:{need:"Medel",icon:"water",summary:"Mynta gillar jämn fukt och tackar med frodig tillväxt. Hon står ut en del torka tack vare sitt kraftiga rotsystem, men bladen tappar saftighet och smak om hon får törsta för länge.",phases:[{phase:"Etablering (vår)",need:"Medel",tip:"Håll jord jämnt fuktig första månaden efter plantering. Rötter behöver vatten för att hitta ner ordentligt - men låt inte jorden bli dränkt."},{phase:"Tillväxt (maj-aug)",need:"Medel",tip:"Vattna 2-3 gånger i veckan vid torrt väder. Mynta i kruka torkar ut snabbare än i friland - känn på jorden och vattna när den börjar kännas torr."},{phase:"Sensommar (sept)",need:"Låg",tip:"Minska vattningen när tillväxten avtar. Mynta förbereder sig för vintervila och behöver inte lika mycket längre."}],mistakes:["Låter jorden torka ut helt - mynta tappar smak och bladen blir sega och torra","Övervattning i kruka utan dräneringshål - rötterna ruttnar även hos denna tuffa växt","Glömmer att vattna krukodlad mynta - i friland klarar hon sig längre, men i kruka är hon beroende av dig"],tip:"Mulcha med gräsklipp runt plantorna - det håller fukten och mynta älskar det. I kruka: ställ på ett fat med grus så överflödigt vatten kan rinna undan."},soil:"Mynta är inte kräsen med jorden - hon växer i det mesta från lerjord till sandjord. Allra bäst trivs hon i fuktig, näringsrik jord med lite kompost inblandad. Men ärligt talat: ge henne något att växa i, så fixar hon resten.",soilTips:["Blanda in kompost vid plantering - mynta är hungrig och uppskattar näringsrik jord","I kruka: vanlig planteringsjord funkar perfekt, men se till att det finns dräneringshål i botten","Mynta trivs även i tyngre lerjord - hon är inte alls lika kräsen som många andra kryddor","Mulcha med kompost på hösten - det skyddar rötterna och ger näring till våren"],timeline:{1:[{phase:"Förodling/delning",months:"Mars-april",icon:"indoor"},{phase:"Utplantering",months:"April-maj",icon:"seedling"},{phase:"Skörd (löpande)",months:"Maj-okt",icon:"harvest"},{phase:"Blomning",months:"Juli-aug",icon:"flower"},{phase:"Nedvissnande",months:"Nov",icon:"dormant"}],4:[{phase:"Förodling/delning",months:"April",icon:"indoor"},{phase:"Utplantering",months:"Maj",icon:"seedling"},{phase:"Skörd (löpande)",months:"Juni-sept",icon:"harvest"},{phase:"Blomning",months:"Juli-aug",icon:"flower"},{phase:"Nedvissnande",months:"Okt",icon:"dormant"}],6:[{phase:"Förodling/delning",months:"Maj",icon:"indoor"},{phase:"Utplantering",months:"Juni",icon:"seedling"},{phase:"Skörd (löpande)",months:"Juni-aug",icon:"harvest"},{phase:"Blomning",months:"Juli-aug",icon:"flower"},{phase:"Nedvissnande",months:"Sept",icon:"dormant"}]},nutritionData:[{month:"Apr",N:4,P:2,K:2},{month:"Maj",N:6,P:3,K:3},{month:"Jun",N:8,P:4,K:4},{month:"Jul",N:7,P:4,K:5},{month:"Aug",N:5,P:3,K:4},{month:"Sep",N:2,P:2,K:3}],nutritionTips:[{timing:"Tidig vår",tip:"Ge en giva kompost eller brunnen stallgödsel när myntan börjar vakna. Hon är hungrig efter vintersömnen och tackar med explosiv tillväxt."},{timing:"Var 4:e vecka (juni-aug)",tip:"En skvätt nässelvatten håller henne igång hela sommaren. Men överdriva inte - mynta är inte lika näringskrävande som många tror."},{timing:"Hösten",tip:"Mulcha med kompost - det skyddar rötterna under vintern och ger naturlig näring när våren kommer."},{timing:"Obs!",tip:"För mycket kvävegödsel ger visserligen frodiga plantor, men smaken och aromen blir svagare. De eteriska oljorna trivs bäst med lagom näring."}],companions:{good:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Myntans starka doft förvirrar bladlöss och vitfjärilar som annars hittar tomatplantorna. Men plantera mynta i kruka bredvid - ALDRIG direkt i tomatbädden, för då tar hon över."},{id:"kal",name:"Kål",icon:"vegetable",why:"Myntans doft avskräcker kålfjärilar och jordloppor. Plantera mynta i nedgrävda krukor runt kållandet - skydd utan att myntan tar över."},{id:"artor",name:"Ärtor",icon:"vegetable",why:"Myntans starka doft kan hjälpa till att hålla bort bladlöss. Ärtorna i sin tur fixerar kväve i jorden som mynta uppskattar."}],bad:[{id:"basilika",name:"Basilika",icon:"herb",why:"Mynta och basilika har helt olika behov - mynta vill ha mer fukt och mindre sol. Dessutom drar myntas aggressiva rötter näring från den ömtåliga basilikan."},{id:"persilja",name:"Persilja",icon:"herb",why:"Myntas utlöpare kväver persiljans rötter. Persilja är för snäll för att klara konkurrensen - mynta vinner varje gång."}]},rotation:{avoid:[{id:"basilika",name:"Basilika"},{id:"mynta",name:"Mynta"},{id:"salvia",name:"Salvia"}],avoidWhy:"Kransblommiga (Lamiaceae) delar en del jordburna sjukdomar. Men mynta är perenn och bör stå kvar på samma plats i många år - så rotation handlar mest om vad du sätter EFTER att mynta grävts bort. Vänta 2 år.",goodBefore:[{name:"Baljväxter"},{id:"potatis",name:"Potatis"}],goodBeforeWhy:"Baljväxter berikar jorden med kväve. Potatis lämnar fin, lucker jord efter kupning. Bägge ger mynta en bra start.",goodAfter:[{id:"lok",name:"Lök"},{name:"Rotväxter"},{name:"Kål"}],goodAfterWhy:"Myntans aromatiska rester i jorden kan ha mild desinficerande effekt på jordburna sjukdomar. Bra föregångare för grönsaker som är känsliga."},varieties:[{name:"Grönmynta (Mentha spicata)",zones:[1,2,3,4,5,6,7,8],note:"Den klassiska myntan som de flesta tänker på. Mild, söt smak. Perfekt till te, sås och lemonad. Mycket härdig."},{name:"Pepparmynta (Mentha x piperita)",zones:[1,2,3,4,5,6,7,8],note:"Starkare mentolsmak än grönmynta. Fantastisk till te och chokladdessert. Korsning mellan vatten- och grönmynta."},{name:"Chokladmynta",zones:[1,2,3,4,5,6,7,8],note:"Mörka stjälkar och en antydan av chokladarom. Ser cool ut i trädgården och smakar fantastiskt i dessert och varm choklad."},{name:"Marockansk mynta",zones:[1,2,3,4,5,6],note:"DEN myntan för marockanskt te! Kompakt växt, passar utmärkt i kruka. Lite känsligare för kyla än de andra - skydda i zon 4 och norrut."},{name:"Vattenmynta (Mentha aquatica)",zones:[1,2,3,4],note:"Trivs i vattensjuk jord och vid dammkanter. Halvhärdig - växer vild i Götaland och södra Svealand. Blommar vackert och är en magnet för bin."}],problems:[{name:"Myntrost (Puccinia menthae)",symptom:"Orangebruna pustler på bladens undersida, bladen gulnar och faller av. Vanligast i fuktigt väder.",fix:"Klipp ner angripna delar till marken - nya friska skott kommer. Se till att luften cirkulerar bra runt plantorna. Undvik att vattna ovanifrån."},{name:"Myntbagge (Chrysolina herbacea)",symptom:"Runda hål i bladen, små metalliskt gröna skalbaggar (ca 8-9 mm) synliga på plantorna. Larverna äter också. Ovanlig i Sverige men kan förekomma i södra delarna.",fix:"Plocka bort baggarna för hand (de är lata och lätta att fånga). Klipp ner kraftigt angripna plantor - de växer tillbaka. Skadorna är mest kosmetiska."},{name:"Mjöldagg",symptom:"Vitt, mjölaktigt lager på bladen. Vanligt vid varmt och torrt väder med svala nätter.",fix:"Förbättra luftcirkulationen genom att gallra bland stjälkarna. Klipp bort angripna delar. Undvik att vattna på kvällen. Mjölkvatten (1 del mjölk, 9 delar vatten) kan hjälpa förebyggande."}],goodToKnow:[{icon:"warning",title:"EXTREMT INVASIV - aldrig i öppen jord!",text:"Myntas utlöpare är som underjordiska sprinter. Plantera ALLTID i kruka eller i en nedgrävd balja utan botten. Sätter du henne i rabatt en vecka dyker hon upp i gräsmattan, bland jordgubbarna och hos grannen. På riktigt.",severity:"warning"},{icon:"warning",title:"Utlöpare går genom nästan allt",text:"Vanliga plastkrukor? Mynta hittar ut genom dräneringshålen. Nedgrävd hink? Hon klättrar över kanten. Använd djupa krukor (minst 30 cm) och kontrollera kanterna varje vår. Det här är en växt som VILL sprida sig.",severity:"warning"},{icon:"tip",title:"Klipp ner för bättre skörd",text:"Klipp ner hela plantan till 5 cm ovanför marken 2-3 gånger under säsongen. Det låter brutalt, men mynta älskar det - hon skjuter fräscha, smakrika skott inom några veckor. Gamla stjälkar blir trådiga och tappar arom.",severity:"tip"},{icon:"tip",title:"Bäst smak före blomning",text:"Precis som basilika har mynta starkast smak och högst halt eteriska oljor strax innan blomningen. Skörda regelbundet och knip av blomknoppar så förlänger du den goda smakperioden hela sommaren.",severity:"tip"},{icon:"tip",title:"Perfekt krukväxt",text:"Mynta är som klippt och skuren för krukodling. En stor kruka (minst 5 liter) på balkongen ger massor av mynta hela sommaren - och du slipper oroa dig för spridning. Det bästa av två världar.",severity:"tip"},{icon:"tip",title:"Lever i många år",text:"Mynta är perenn och kommer tillbaka år efter år. Ovanjordiska delar dör vid frost, men under jorden lever rotsystemet vidare. På våren vaknar hon och skjuter nya skott. Krukodlad mynta kan behöva omplantering vart 2-3 år när rötterna fyller hela krukan.",severity:"tip"}],sowing:{method:"both",label:"Direktsådd eller förodling",description:"Mynta KAN sås från frö, men det är långsamt och sortäktheten varierar. Det överlägset bästa sättet är att ta sticklingar eller dela en befintlig planta - då vet du exakt vilken sort du får och har skörd samma år. Be en granne om en bit!",steps:["Bästa sättet: Ta en 10 cm stickling från en befintlig planta, knip av nedre bladen och ställ i vatten - rötter kommer på en vecka","Eller: gräv upp en bit av en befintlig planta med rötter och plantera om","Från frö: Så ytligt (0.5 cm) i fuktig jord, fröna behöver ljus","Håll jord jämnt fuktig, groning på 10-15 dagar vid 18-22°C","Gallra till 30-45 cm avstånd (eller plantera en per stor kruka)","Härda av förodlade plantor en vecka innan utplantering","VIKTIGT: Plantera alltid i kruka eller avgränsad behållare - aldrig direkt i rabatt!"],tips:["Sticklingar i vatten är det enklaste - de rotar sig nästan alltid. Byt vatten varannan dag","Köpmynta från mataffären kan planteras om i större kruka - klipp ner till 5 cm och låt henne växa till sig","Fröbaserade plantor kan variera i smak - sticklingar ger garanterat samma sort som moderplantan"],indoorWeeks:"6-8 veckor före utplantering"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!1,description:"Mynta blommar på sommaren och sätter små frön i de torkade blommorna. Men de flesta myntasorter är korsningar som inte kommer sorträtt från frö. Delning och sticklingar är överlägset bäst för att behålla sorten.",steps:["Låt några stjälkar blomma klart (juli-aug)","Vänta tills blommorna torkat och blivit bruna på plantan","Klipp av blomstjälkarna och lägg i en papperspåse","Låt eftertorka några dagar inomhus","Gnugga försiktigt för att lossa fröna från blomresterna","Sikta eller rensa bort skräp","Förvara i märkt kuvert, svalt och torrt"],isolation:"Mynta korspolleras av insekter och olika myntaarter korsas lätt. För sortrena plantor är sticklingar eller delning det enda säkra sättet.",storageYears:"2-3 år",tip:"Ärligt talat - glöm frön. Mynta förökar sig så effektivt via utlöpare och sticklingar att frötagning är onödigt. Dela hellre plantan eller ta sticklingar!"},storage:{shelfLife:"5-7 dagar (färsk)",methods:[{method:"Frysning (bäst!)",icon:"snowflake",duration:"6+ månader",description:"Plocka bladen, lägg i isbitsfack med lite vatten och frys. Perfekta myntakuber att slänga i lemonad, te eller matlagning. Behåller smaken fantastiskt.",best:!0},{method:"I glas med vatten",icon:"water",duration:"7-10 dagar",description:"Ställ stjälkarna i ett glas vatten i rumstemperatur (som en bukett). Byt vatten varannan dag. Håller sig fräscht längre än i kylen.",best:!1},{method:"Torkning",icon:"storage",duration:"12+ månader",description:"Häng knippen upp och ner på en torr, luftig plats. Eller torka i ugn på 50°C i 2-3 timmar. Torkad mynta tappar en del fräschör men funkar fint i te och matlagning.",best:!1}],tips:["Frys i isbitsfack med vatten - perfekta myntakuber för drycker hela året","Torka i knippen - häng upp och ner på en luftig plats så behåller bladen formen fint","Skörda på morgonen för starkast smak - eteriska oljorna är mest koncentrerade då","Skörda regelbundet under sommaren - mynta är mest aromatisk före blomning"]},harvestCalc:{minPerSqm:.3,maxPerSqm:1,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp stjälkar eller plocka enskilda blad",description:"Skörda genom att klippa hela stjälkar 5 cm ovanför marken, eller plocka enskilda blad efter behov. Mynta växer tillbaka snabbt - du kan skörda 3-4 gånger per säsong. Klipp gärna ner hela plantan till marknivå mitt på sommaren för en frodig andraskörd.",uses:[{use:"Te (färsk eller torkad)",tip:"Häll lite kokande vatten över färska myntablad och låt dra 5-7 minuter. Fantastiskt gott och magslugnande. Pepparmynta ger starkast smak, grönmynta mildare."},{use:"Matlagning",tip:"Klassisk i lammsås, tabbouleh, vårrullar och raita. Tillsätt sist - värme dödar den fräscha smaken. Hacka bladen strax före servering."},{use:"Drycker",tip:"Mojito, myntajulep, lemonad, smoothie - mynta gör nästan vilken dryck som helst bättre. Krossa bladen lätt för att frigöra smaken."},{use:"Efterrätt",tip:"Choklad och mynta är ett drömpar. Färska blad i fruktsallad, myntaglass, eller bara som dekoration på tallriken."}]}},xa=Object.freeze(Object.defineProperty({__proto__:null,mynta:W},Symbol.toStringTag,{value:"Module"})),U={name:"Oregano",icon:"oregano",category:"kryddor",family:"Kransblommiga",familyLatin:"Lamiaceae",perennial:!0,lifespan:"5-8 år (dela vart fjärde år)",difficulty:"Enkel",difficultyWhy:"Oregano är en av de mest lättskötta kryddväxterna du kan odla. Hon är torktålig, härdig och ger starkare smak ju mer hon får kämpa. Det enda misstaget du kan göra är att ge henne för mycket omsorg - oregano vill ha det tufft.",zones:{outdoor:[1,2,3,4,5],indoor:[1,2,3,4,5,6,7,8],greenhouse:null},days:"70-90",spacing:"20-30 cm",rowSpacing:"30-40 cm",depth:"0.3 cm",depthNote:"Ljusgroddare - tryck fast men täck knappt",ph:{min:6,max:8,ideal:7},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Oregano är en Medelhavsvilde som älskar sol - ju mer desto bättre. Ge henne minst 6-8 timmars direkt solljus per dag. I skugga blir hon ranglig och tappar nästan all smak. Söderlägt läge vid en varm mur? Då blir hon lyckligast."},temperature:{min:-25,max:35,ideal:"18-25°C",detail:"Oregano är riktigt härdig - etablerade plantor klarar ner till -25°C i väldränerad jord! Sommarvärme är bara ett plus, ju varmare desto mer koncentrerade eteriska oljor. Kyla plus väta är däremot en dödlig kombination."},wind:{level:"Tålig",detail:"Med sitt låga, buskiga växtsätt klarar oregano vind bra. Hon växer vilt på vindpiskade bergssidor i Medelhavet - svensk vind är ingen utmaning."}},watering:{need:"Låg",icon:"water",summary:"Oregano är uppvuxen på torra Medelhavsslänterna och vill ha det likadant här. Hon HATAR blöta fötter och tackar för torka med starkare smak. Låt hellre jorden torka ut ordentligt mellan vattningarna.",phases:[{phase:"Etablering (första månaden)",need:"Medel",tip:"Vattna regelbundet den första månaden så rötterna hittar ner. Men aldrig så mycket att jorden står blöt - dränering är allt. När hon börjar växa aktivt har hon landat."},{phase:"Etablerad planta (sommar)",need:"Låg",tip:"Vattna bara vid långvarig torka. Oregano klarar veckors torka utan problem. Faktum är att lite vattenstress ger STARKARE smak - de eteriska oljorna koncentreras när hon får kämpa."},{phase:"Vinter",need:"Låg",tip:"Vattna INTE vintertid utomhus. Oregano vilar och vill vara torr. Inomhus räcker det med en skvätt varannan vecka - låt jorden torka ut helt emellan."}],mistakes:["Övervattnar - vanligaste dödsorsaken för oregano. Rötterna ruttnar i blöt jord snabbare än du tror","Planterar i tung lerjord utan dränering - oregano behöver jord som släpper igenom vatten blixtsnabbt","Mulchar för tätt intill stammen - fukt vid basen orsakar stamröta och svamp","Vattnar på kvällen - fukten ligger kvar över natten och skapar perfekta förhållanden för svampsjukdomar"],tip:"Tumregel: är du osäker på om oregano behöver vatten? Det gör hon inte. Vänta några dagar till. Hon klarar torka hundra gånger bättre än för mycket vatten."},soil:"Oregano vill ha mager, väldränerad jord - gärna sandig eller grusig. Rik trädgårdsjord ger visserligen mer tillväxt, men smaken blir helt platt. Det är i kamp och torka som oregano utvecklar sin fantastiska arom.",soilTips:["Blanda in rikligt med sand eller grus i planteringsgropen - oregano vill ha en jord som släpper igenom vatten direkt","I kruka: blanda hälften planteringsjord, hälften perlit eller grus. Lägg ett lager grus i botten för extra dränering","Undvik att blanda in kompost eller gödsel - oregano trivs faktiskt bättre i mager jord. Rikare jord ger svagare arom","Ett lager grus eller småsten runt plantan håller fukten borta från stammen och ger värmeåterstrålning på kvällen"],timeline:{1:[{phase:"Förodling inomhus",months:"Mars",icon:"indoor"},{phase:"Utplantering",months:"Maj",icon:"seedling"},{phase:"Skörd löpande",months:"Juni-sept",icon:"harvest"},{phase:"Blomning",months:"Juli-aug",icon:"flower"},{phase:"Frötagning",months:"Aug-sept",icon:"seed"}],4:[{phase:"Förodling inomhus",months:"Mars-april",icon:"indoor"},{phase:"Utplantering",months:"Slutet av maj-juni",icon:"seedling"},{phase:"Skörd löpande",months:"Juni-sept",icon:"harvest"},{phase:"Blomning",months:"Juli-aug",icon:"flower"},{phase:"Frötagning",months:"Sept",icon:"seed"}],6:[{phase:"Förodling inomhus",months:"April",icon:"indoor"},{phase:"Utplantering",months:"Juni",icon:"seedling"},{phase:"Skörd löpande",months:"Juli-sept",icon:"harvest"},{phase:"Blomning",months:"Aug",icon:"flower"}]},nutritionData:[{month:"Apr",N:3,P:2,K:2},{month:"Maj",N:4,P:3,K:3},{month:"Jun",N:5,P:3,K:4},{month:"Jul",N:4,P:3,K:5},{month:"Aug",N:3,P:2,K:4},{month:"Sep",N:2,P:1,K:3}],nutritionTips:[{timing:"Tidig vår",tip:"En tunn giva kompost runt plantan när hon vaknar på våren räcker gott. Oregano är ingen storätare - hon klarar sig med lite."},{timing:"Försommar",tip:"Om plantan ser blek eller sliten ut, ge en svag giva nässelvatten. Men överdriv inte - för mycket kväve ger frodiga blad med svag smak. Det är INTE det vi vill ha."},{timing:"Höst",tip:"Strö lite vedaska runt plantan på hösten. Kaliumet stärker vinterhärdigheten och oregano gillar det svagt basiska."},{timing:"Obs!",tip:"Gödsla ALDRIG med kraftig stallgödsel eller syntetisk kvävegödsel. Oregano vill ha det magert - det är i kamp och torka som de eteriska oljorna koncentreras och smaken blir fantastisk."}],companions:{good:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Det klassiska italienska paret! Oregano avskräcker bladlöss och vitfjäril. Planterad bredvid tomaterna är hon både skyddsängel och kulinarisk partner."},{id:"paprika",name:"Paprika",icon:"vegetable",why:"Paprika och oregano trivs under samma förhållanden - sol och värme. Oreganos starka doft förvirrar skadeinsekter som annars hittar paprika."},{id:"squash",name:"Squash",icon:"vegetable",why:"Oreganos blommor lockar pollinerare som squash är beroende av. Planterad som kant runt squashlandet ger hon både sällskap och nytta."}],bad:[{id:"mynta",name:"Mynta",icon:"herb",why:"Mynta är aggressiv och sprider sig överallt via utlöpare. Hon tar över oreganos plats på nolltid. Dessutom vill mynta ha fuktigare förhållanden - de pratar helt enkelt olika språk."}]},rotation:{avoid:[{id:"oregano",name:"Oregano"},{id:"timjan",name:"Timjan"},{id:"salvia",name:"Salvia"}],avoidWhy:"Kransblommiga (Lamiaceae) delar en del jordburna sjukdomar. Men oregano är perenn och bör stå kvar på samma plats i många år - flytta bara om plantan dör eller blir för vedartad (efter 4-5 år).",goodBefore:[{name:"Baljväxter"},{id:"lok",name:"Lök"},{name:"Rotsaker"}],goodBeforeWhy:"Baljväxter berikar jorden med kväve. Lök och rotsaker lämnar ren jord. Alla dessa är bra föregångare för oregano.",goodAfter:[{id:"morot",name:"Morot"},{name:"Kål"},{id:"sallat",name:"Sallat"}],goodAfterWhy:"Oreganos aromatiska rester i jorden har mild desinficerande effekt. Bra för grönsaker som är känsliga för jordburna sjukdomar."},varieties:[{name:"Grekisk oregano (Origanum vulgare subsp. hirtum)",zones:[1,2,3,4,5],note:"Starkast smak av alla! Det här är oreganon du vill ha på pizzan. Kompakt växtsätt med små, håriga grågrönablad. Intensiv, nästan pepperaktig arom. DEN oregano du letar efter."},{name:"Italiensk oregano (Origanum x majoricum)",zones:[1,2,3,4,5],note:"Korsning mellan oregano och mejram. Mildare och rundare smak än grekisk. Större blad och frodigare växt. Perfekt för såser och grytor."},{name:"Gyllene oregano (Origanum vulgare Aureum)",zones:[1,2,3,4],note:"Vackert gulgröna blad som lyser upp rabatten! Något mildare smak, men fantastisk som marktäckare. Både vacker och ätbar."},{name:"Origanum vulgare (kungsmynta)",zones:[1,2,3,4,5,6],note:"Svensk vild form! Växer vilt i hela södra och mellersta Sverige. Mildare smak än de odlade sorterna, men härdigast av alla. Blommorna är älskade av bin och fjärilar."}],problems:[{name:"Rotröta (väta)",symptom:"Plantan gulnar och vissnar trots att jorden är fuktig. Stammens bas är mörk och mjuk. Rötter är bruna och luktar illa.",fix:"Tyvärr ingen bot när rotröta slagit till. Förebygg med väldränerad jord och sparsam vattning. Är det en stor planta kan du försöka ta sticklingar från friska grenar och starta om."},{name:"Mjöldagg",symptom:"Vitt, mjölaktigt pulver på bladen. Vanligast vid fuktig luft och dålig luftcirkulation.",fix:"Klipp bort angripna delar. Se till att plantan står luftigt och inte för tätt med andra växter. En blandning av vatten och lite bakpulver kan sprayas på friska blad som skydd."},{name:"Vedartade grenar (åldring)",symptom:"Plantan blir gles och vedartad efter 3-5 år. Få blad, mest bara torr ved.",fix:"Förebygg genom att klippa tillbaka oregano kraftigt varje vår - men aldrig in i den vedartade delen. När plantan är för gammal är det dags att ersätta med en ny. Ta sticklingar eller dela roten först!"},{name:"Bladlöss",symptom:"Klibbiga blad, deformerade skottspetsar. Små gröna eller svarta löss synliga.",fix:"Ovanligt på oregano tack vare de eteriska oljorna, men kan hända på svaga plantor. Spola av med vatten eller behandla med såplösning. Stark och frisk oregano är sällan angripen."}],goodToKnow:[{icon:"warning",title:"Vattna med måttans hand",text:"Oreganos största fiende är inte kyla - det är fukt. När oregano dör beror det nästan alltid på att hon stått för blött. Plantera i väldränerad jord och vattna sparsamt, så lever hon i många år.",severity:"warning"},{icon:"warning",title:"Klipp aldrig in i det vedartade",text:"När du beskär oregano på våren, klipp bara i den gröna delen - aldrig ner i den bruna, vedartade stammen. Därifrån kommer inga nya skott. Klipper du för hårt är grenen död.",severity:"warning"},{icon:"tip",title:"Starkast smak strax före blomning",text:"Planera huvudskörden till precis innan oregano börjar blomma - då är koncentrationen av eteriska oljor som högst. Torkad oregano vid rätt tidpunkt är faktiskt starkare än färsk!",severity:"tip"},{icon:"tip",title:"Stress ger bättre smak",text:"Till skillnad från de flesta växter GILLAR oregano att ha det tufft. Mager jord, lite vatten, stark sol - ju mer hon får kämpa, desto mer koncentrerade blir de eteriska oljorna. Bortskämda oreganoplantor smakar ingenting.",severity:"tip"},{icon:"tip",title:"Binas favorit",text:"Oreganos små lila-rosa blommor är fulla av nektar och lockar bin, humlor och fjärilar i massor. Låt gärna en del av plantan blomma - det är bra för hela trädgården. Och blommorna är ätbara!",severity:"tip"}],sowing:{method:"both",label:"Direktsådd eller förodling",description:"Oregano kan sås direkt utomhus eller förodlas inomhus. Fröna är pyttelitet små och gror långsamt (1-2 veckor), så förodling är lättast. Det allra enklaste? Köp en planta, dela en befintlig eller be någon om sticklingar - oregano är generös med att sprida sig.",steps:["Fyll krukor med sandblandad såjord (hälften såjord, hälften sand)","Strö fröna på ytan - TÄCK INTE. De behöver ljus för groning","Tryck försiktigt med handflatan så de får jordkontakt","Spreja med vatten - översvämma inte","Täck med plastfolie för att hålla fukt. Lufta dagligen","Ställ ljust och varmt (18-22°C). Groning tar 7-14 dagar","Gallra till 1-2 plantor per kruka vid 3-4 cm höjd","Härda av i 1 vecka innan utplantering. Plantera ut när frostrisken är över"],tips:["Sticklingar är det snabbaste sättet att få en ny planta - klipp en 10 cm gren, ta bort nedre bladen och sätt i fuktig sand. Rötter på 3-4 veckor!","Delning av en stor planta på våren är det allra lättaste - gräv upp, dela med spade, plantera om. Klart!","Oreganofrön är otroligt små - blanda med sand för att så jämnare"],indoorWeeks:"6-8 veckor före utplantering"},seedSaving:{difficulty:"Enkel",type:"Korspollinerare",biennial:!1,description:"Låt oregano blomma - de små blommorna producerar pyttelila frön som mognar på sensommaren. Klipp av blomstjälkarna när de torkat och skaka ut fröna. Oregano korspolleras av insekter, så olika sorter bör stå isär.",steps:["Låt en del av plantan blomma ut helt (juli-aug)","Vänta tills blommorna torkat och frökapslarna är bruna","Klipp av blomstjälkarna och lägg i en papperspåse","Låt eftertorka några dagar inomhus","Skaka och gnugga försiktigt - de pyttelila fröna faller ut","Sikta bort skräp genom ett fint såll","Förvara svalt och torrt i märkt kuvert"],isolation:"Oregano korspolleras av insekter. Håll 50+ meters avstånd mellan sorter om du vill ha sortrena frön. Observera att oregano korsar sig glädjefullt med mejram!",storageYears:"3-4 år",tip:"Delning av roten på våren är enklare än fröförökning - och du får en identisk planta direkt. Sticklingar fungerar också utmärkt."},storage:{shelfLife:"7-14 dagar (färsk)",methods:[{method:"Torkning (bäst!)",icon:"storage",duration:"12+ månader",description:"Oregano är en av de få kryddor som faktiskt blir BÄTTRE av torkning - smaken koncentreras enormt. Häng knippen uppochner på en torr, luftig plats i 1-2 veckor. Eller torka i ugn på 40°C i 2-3 timmar.",best:!0},{method:"Frysning",icon:"snowflake",duration:"6+ månader",description:"Lägg hela kvistar i en fryspåse och frys. Plocka blad direkt från frysen när du lagar mat - de lossnar lättare från stjälkarna när de är frysta!",best:!1},{method:"Färsk i kyl",icon:"water",duration:"7-14 dagar",description:"Linda kvistarna i fuktigt hushållspapper och lägg i en plastpåse i kylen. Oregano håller sig överraskande länge tack vare sina små, sega blad.",best:!1},{method:"Oreganoolja",icon:"storage",duration:"3-6 månader",description:"Lägg färsk oregano i en flaska med god olivolja. Låt dra 2-3 veckor. Sila bort kryddorna. Fantastisk smaksatt olja för pizza, pasta och bröd.",best:!1}],tips:["Torkad oregano är starkare än färsk - använd ungefär en tredjedel så mycket i recept","Skörda hela kvistar och låt bladen sitta kvar på stjälken under torkning - de är lättare att dra av när de är torra","Förvara torkad oregano i ett mörkt, lufttätt glas - ljus bryter ner de eteriska oljorna över tid","Gnugga torkad oregano mellan handflatorna precis före användning - det frigör aromen och ger maximal smak"]},harvestCalc:{minPerSqm:.2,maxPerSqm:.5,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp kvistar, aldrig mer än en tredjedel åt gången",description:"Skörda oregano genom att klippa av kvistar med en vass sax. Ta aldrig mer än en tredjedel av plantan åt gången - hon behöver blad för att återhämta sig. Klipp ovanför den vedartade delen så nya sidoskott kan växa ut. Bästa tiden är på morgonen när daggen torkat - då är de eteriska oljorna som starkast.",uses:[{use:"Pizzakrydda",tip:'Gnugga torkad oregano mellan handflatorna och strö över pizzan precis efter gräddning. Oregano är DEN klassiska pizzakryddan - inte för inget kallas hon "bergets glädje" på grekiska.'},{use:"Tomatsås och grytor",tip:"Lägg i torkad oregano tidigt i såser och grytor - hon tål långkok och smaken fördjupas med tid. En klassiker i italiensk, grekisk och mexikansk matlagning."},{use:"Oreganote",tip:"Häll hett vatten över färska eller torkade kvistar. Låt dra 5-10 minuter. Oreganote är inte bara gott - det används traditionellt som maglugnande och mot förkylning."},{use:"Smaksatt olja och vinäger",tip:"Lägg färska kvistar i olivolja eller vitvinsvinäger. Låt dra 2-3 veckor. Fantastisk till sallader, bröd och marinader."}]}},Ka=Object.freeze(Object.defineProperty({__proto__:null,oregano:U},Symbol.toStringTag,{value:"Module"})),q={name:"Pak choi",icon:"pak-choi",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Enkel",difficultyWhy:"Snabbväxande och tacksam - redo på en månad! Enda fällan är att hon skjuter i blom om det blir för varmt.",zones:{outdoor:[1,2,3,4,5,6,7],indoor:null,greenhouse:[8]},days:"40-60",spacing:"20-25 cm",rowSpacing:"30-50 cm",depth:"0.5-1 cm",ph:{min:6,max:7.5,ideal:6.8},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"partial-sun",detail:"Trivs i sol men uppskattar halvskugga, särskilt på sommaren. Lite skugga minskar risken för skottbildning i värmen."},temperature:{min:-3,max:25,ideal:"15-20°C",detail:"Klarar lätt frost ner till -3°C men avskyr hetta. Över 25°C och med långa dagar skjuter hon rakt i blom. Trivs allra bäst i sval vår- eller höstluft."},wind:{level:"Tålig",detail:"Låg och kompakt - vind är sällan ett problem. Lite luftrörelse håller dessutom svampsjukdomar borta."}},watering:{need:"Medel",icon:"water",summary:"Pak choi vill ha jämn fukt men aldrig stående vatten. Tänk på henne som en sallat - hon är mest vatten själv och behöver påfyllning regelbundet.",phases:[{phase:"Groning (0-1 vecka)",need:"Hög",tip:"Håll jorden jämnt fuktig tills fröna grott. Pak choi gror snabbt - ofta inom 3-5 dagar."},{phase:"Tillväxt (1-3 veckor)",need:"Medel",tip:"Vattna 2-3 gånger i veckan om det inte regnar. Jämn fukt ger saftiga, milda blad."},{phase:"Huvudbildning (3-5 veckor)",need:"Medel",tip:"Fortsätt med jämn vattning. Torka nu gör att hon skjuter i blom istället för att bilda fina huvuden."}],mistakes:["Ojämn vattning stressar plantan och triggar skottbildning","Stående vatten ger rotröta - hon vill ha fukt, inte en bassäng","Torka ger bitter smak och sega blad"],tip:"Mulcha med gräsklipp eller halm för att hålla jorden jämnt fuktig och sval - det minskar risken för skottbildning."},soil:"Mullrik, fukthållande jord. Pak choi vill ha näringsrik mark som håller fukt men inte blir vattensjuk.",soilTips:["Blanda in rikligt med kompost före sådd - hon är hungrigare än sin kusin rädisan","Undvik kompakt lerjord - luckra ordentligt eller blanda in sand","Jorden ska hålla fukt men aldrig bli dränkt - god dränering är viktigt"],timeline:{1:[{phase:"Förkultivering vår",months:"Feb-Mar",icon:"seedling"},{phase:"Utplantering vår",months:"Apr",icon:"seedling"},{phase:"Skörd vårsådd",months:"Maj-Jun",icon:"harvest"},{phase:"Direktså höst",months:"Jul-Aug",icon:"seedling"},{phase:"Skörd höstsådd",months:"Sep-Okt",icon:"harvest"}],4:[{phase:"Förkultivering vår",months:"Mar-Apr",icon:"seedling"},{phase:"Utplantering vår",months:"Maj",icon:"seedling"},{phase:"Skörd vårsådd",months:"Jun",icon:"harvest"},{phase:"Direktså höst",months:"Jul-Aug",icon:"seedling"},{phase:"Skörd höstsådd",months:"Sep-Okt",icon:"harvest"}],6:[{phase:"Förkultivering vår",months:"Apr",icon:"seedling"},{phase:"Utplantering vår",months:"Maj-Jun",icon:"seedling"},{phase:"Skörd vårsådd",months:"Jun-Jul",icon:"harvest"},{phase:"Direktså höst",months:"Jul",icon:"seedling"},{phase:"Skörd höstsådd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:20,P:15,K:15,label:"Sådd"},{month:"Maj",N:40,P:25,K:30,label:"Tillväxt"},{month:"Jun",N:35,P:20,K:25,label:"Huvudbildning"},{month:"Jul",N:15,P:15,K:20,label:"Skörd"}],nutritionTips:[{timing:"Vid sådd/plantering",tip:"Grundgödsla med brunnen kompost eller pelleterad hönsgödsel. Pak choi vill ha kväverik jord för att bygga sina saftiga blad."},{timing:"Under tillväxt",tip:"En omgång flytande nässel- eller kompostvatten efter 2-3 veckor ger henne en boost. Övergödsla inte - det lockar bladlöss."},{timing:"Huvudbildning",tip:"Ingen extra gödsling behövs nu. Fokusera på jämn vattning istället."}],companions:{good:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens doft förvirrar kålskadedjur - en naturlig bodyguard för pak choi"},{id:"morot",name:"Morot",icon:"vegetable",why:"Bra granne som inte konkurrerar om samma resurser och doften förvirrar skadedjur"},{id:"dill",name:"Dill",icon:"herb",why:"Lockar nyttoinsekter som äter bladlöss. Ser dessutom fint ut ihop!"}],bad:[{id:"gronkal",name:"Grönkål",icon:"vegetable",why:"Samma familj - delar skadedjur som kålfluga och jordloppa"},{id:"broccoli",name:"Broccoli",icon:"vegetable",why:"Samma familj - ökar risken för klumprotsjuka och andra kålproblem"},{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Konkurrerar om fukt och näring, och jordgubbar lockar sniglar som älskar pak choi"}]},rotation:{avoid:[{id:"gronkal",name:"Grönkål"},{id:"broccoli",name:"Broccoli"},{id:"blomkal",name:"Blomkål"},{id:"vitkal",name:"Vitkål"},{id:"radisa",name:"Rädisa"},{id:"kalrabbi",name:"Kålrabbi"}],avoidWhy:"Alla korsblommiga delar klumprotsjuka och kålfluga. Vänta minst 4 år innan du odlar pak choi på samma plats.",goodBefore:[{name:"Baljväxter (ärtor, bönor)"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Pak choi tar en del kväve ur jorden - baljväxter efter fyller på igen. Lök trivs efter kål tack vare lite andra krav.",goodAfter:[{id:"sallat",name:"Sallat"},{id:"lok",name:"Lök"}],goodAfterWhy:"Sallat och lök tillhör helt andra familjer och påverkas inte av kålsjukdomar."},varieties:[{name:"Prize Choi",zones:[1,2,3,4,5,6],note:"Öppen, vasformad OP-sort med breda, saftiga vita stjälkar. Pålitlig och lättodlad. Runåbergs."},{name:"Green Stem",zones:[1,2,3,4,5,6],note:"Stor OP-sort med svällda blad och vita baser, 200-300 g per planta. Mild smak. Impecta."},{name:"Taisai",zones:[1,2,3,4,5,6],note:"Japansk OP-typ med platta, mörkgröna blad som bildar en rosett. Härdig och tål lite mer kyla. Nära släkting (tatsoi). Lindbloms."},{name:"Joi Choi F1",zones:[1,2,3,4,5,6,7],note:"Stor, robust F1-hybrid med vita stjälkar och mörkgröna blad. Långsam att skjuta i blom - bra val för nybörjare. OBS: F1 - ger inte sortäkta avkomma. Impecta."}],problems:[{name:"Jordloppor",symptom:"Massor av små hål i bladen, som om någon skjutit med hagelgevär",fix:"Fiberduk direkt vid sådd - det enda som verkligen funkar. Håll jorden fuktig, jordloppor avskyr fukt. Blandodla med lök."},{name:"Kålfluga",symptom:"Plantan vissnar trots vattning, larver vid roten",fix:"Kålkrage runt stjälken hindrar flugan från att lägga ägg. Fiberduk fungerar också."},{name:"Sniglar",symptom:"Stora, oregelbundna hål i bladen, slemspår",fix:"Snigelkorn, ölfällor eller plocka för hand på kvällen. Pak choi är snigelgodis - var vaksam!"},{name:"Skottbildning",symptom:"Blomstjälk skjuter upp ur mitten, bladen blir bittra",fix:"Så sent (juli-aug) för höstskörd, eller tidigt (mars-apr) för vårskörd. Undvik att så mitt i sommaren. Jämn fukt och halvskugga minskar risken."}],goodToKnow:[{icon:"warning",title:"Tidpunkten är allt - så inte mitt i sommaren",text:"Pak choi skjuter i blom med en gång om hon utsätts för värme och långa dagar. Så tidigt på våren (mars-april) eller sent på sommaren (juli-augusti) för höstskörd. Höstsådden är faktiskt lättast - svalare och färre skadedjur.",severity:"warning"},{icon:"harvest",title:"Skörda blad för blad eller hela huvudet",text:"Du kan börja plocka ytterblad redan efter 3 veckor - då växer hon vidare från mitten. Eller vänta 5-7 veckor och skörda hela huvudet med en skarp kniv strax ovanför marken.",severity:"tip"},{icon:"leaf",title:"Perfekt för höstodling",text:"Pak choi trivs som allra bäst i sval höstluft. Så i juli-augusti och njut av krispiga huvuden i september-oktober. Lite frost gör henne till och med sötare!",severity:"tip"},{icon:"seedling",title:"Kimchi-grödan",text:"Pak choi är en av grundstenarna i koreansk kimchi. Odla en omgång extra på hösten och fermentera - du får probiotisk superfood som håller hela vintern.",severity:"tip"},{icon:"sun",title:"Fiberduk är din bästa vän",text:"Jordloppor och kålfluga är pak chois värsta fiender. En fiberduk direkt vid sådd löser båda problemen och håller dessutom jämnare fukt. Lyft bara för vattning och ogräsrensning.",severity:"tip"}],sowing:{method:"both",label:"Direktsådd eller förkultivering",description:"Pak choi kan både direktsås och förkultiveras. Vårsådd förkultiveras bäst inomhus för att få försprång. Höstsådd direktsås utan problem.",steps:["Direktsådd: Dra ett grunt spår (0.5-1 cm djupt) och så fröna med 2-3 cm mellanrum","Täck med ett tunt lager jord och vattna försiktigt med stril","Gallra till 20-25 cm när plantorna har 3-4 riktiga blad","Förkultivering: Så i små krukor 3-4 veckor innan utplantering","Härda av plantorna en vecka innan de flyttas ut","Plantera ut på samma djup som de stod i krukan"],tips:["Höstsådd (juli-aug) ger bäst resultat - svalare väder och färre skadedjur","Vårsådd kräver lite mer planering - förkultivera inomhus och plantera ut tidigt för att hinna före värmen","Fiberduk direkt vid sådd skyddar mot jordloppor och kålfluga","Successiv sådd var 2-3 vecka ger skörd under lång tid"],indoorWeeks:"3-4 veckor"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!1,description:"Pak choi är ettårig och sätter frö samma säsong. Var medveten om att hon korsar lätt med majrova och andra Brassica rapa-släktingar - odla bara en sort åt gången om du vill spara frö.",steps:["Välj de finaste plantorna och låt dem gå i blom","Gula blommor pollineras av bin och andra insekter","Låt skidorna mogna på plantan tills de blir bruna och torra","Klipp av hela blomstjälkarna och lägg i en papperspåse","Torka inomhus en vecka, gnugga sedan loss fröna","Rensa bort skal och skräp genom att blåsa försiktigt","Förvara torrt och svalt i märkt påse"],isolation:"Korsar med majrova, kinakål och andra Brassica rapa. Isolera med minst 500 m eller odla bara en sort ur denna grupp för frösparande.",storageYears:"3-5 år",tip:"Eftersom pak choi korsar så lätt med majrova och kinakål, är det enklast att spara frö om du bara odlar en Brassica rapa-sort i taget."},storage:{shelfLife:"3-5 dagar",methods:[{method:"Kylskåp",icon:"snowflake",duration:"3-5 dagar",description:"Lägg hela huvudet i en plastpåse med några hål i kylen. Tvätta inte förrän du ska använda henne - fukt på bladen påskyndar förruttnelse.",best:!0},{method:"Frysa",icon:"snowflake",duration:"6-12 månader",description:"Blanchera i 2 minuter, kyl snabbt i isvatten, pressa ur vätska och frys i portionspåsar. Perfekt för wok och soppor.",best:!1},{method:"Fermentera (kimchi)",icon:"storage",duration:"3-6 månader",description:"Salta, krydda med chili, vitlök och ingefära och låt jäsa. Klassisk koreansk kimchi - och ett fantastiskt sätt att ta vara på höstsörden!",best:!1}],tips:["Pak choi håller sig kort i kylskåp - planera att använda henne snabbt","Skörda på morgonen när bladen är som mest vattenfyllda","Bäst färsk i wok, soppa eller som snabb sidorätt","Överskott? Gör kimchi - du kommer inte ångra dig!"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3,unit:"kg"}},Pa=Object.freeze(Object.defineProperty({__proto__:null,pakChoi:q},Symbol.toStringTag,{value:"Module"})),Y={name:"Palsternacka",icon:"vegetable",family:"Flockblommiga",familyLatin:"Apiaceae",difficulty:"Enkel",difficultyWhy:"Direktsås utomhus, extremt härdig, kan övervintra i jorden. Kräver bara tålamod - groningen tar evigheter.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:null},days:"100-150",spacing:"10-15 cm",rowSpacing:"30-60 cm",depth:"1-2 cm",ph:{min:6.5,max:7.5,ideal:7},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Trivs bäst i full sol men klarar halvskugga. I halvskugga blir rötterna lite mindre men fortfarande goda."},temperature:{min:5,max:25,ideal:"12-18°C",detail:"Kan tekniskt gro vid 2°C men det är opraktiskt långsamt - räkna med minst 8°C för pålitlig groning. Optimal groningstemperatur 12-18°C. Tål hård frost - blir faktiskt godare efter frost! Kan stå ute hela vintern."},wind:{level:"Tålig",detail:"Låg profil under säsongen. Blasten kan bli hög men växten tål vind utan problem."}},watering:{need:"Låg-Medel",icon:"water",summary:"Palsternackan är ganska anspråkslös med vatten. Jämn grundfukt räcker - hon har djupa rötter som hittar vatten långt ner.",phases:[{phase:"Groning (2-4 veckor!)",need:"Hög",tip:"Här krävs TÅLAMOD. Fröna kan ta upp till 4 veckor att gro. Håll jorden jämnt fuktig hela den tiden - ge inte upp! Täck gärna med fiberduk eller fuktig tidningspapper."},{phase:"Etablering (4-10 veckor)",need:"Medel",tip:"Vattna 2 gånger i veckan vid torka. Plantorna ser ynkliga ut i början men är segare än de ser ut."},{phase:"Tillväxt (10+ veckor)",need:"Låg",tip:"De djupa rötterna klarar sig bra. Vattna bara vid långvarig torka. Övervattning ger mer blast än rot."}],mistakes:["Ge upp och sluta vattna under den långa groningsperioden","Övervattna under tillväxten - ger vattniga rötter med dålig smak","Ojämn vattning som ger spruckna rötter (samma problem som morot)"],tip:"Mulcha ordentligt efter uppkomst - det håller fukten jämn och minskar ogräset. Palsternackan växer långsamt i början och kan lätt bli överväxt av ogräs."},soil:"Djup, lucker, stenfri jord. Gärna sandblandad. Undvik nygödslad jord - precis som moroten blir palsternackan krokig och kluven av för mycket kväve.",soilTips:["Gräv djupt (minst 35-40 cm) - palsternackans rötter blir längre än morotens","Ta bort stenar noggrant - varje sten ger en krokig rot","Blanda in sand i lerjord för bättre dränering","Använd väl brunnen kompost - aldrig färsk gödsel"],timeline:{1:[{phase:"Direktså",months:"Mar-Apr",icon:"seedling"},{phase:"Gallra",months:"Maj",icon:"scissors"},{phase:"Ogräsrensning",months:"Maj-Jun",icon:"scissors"},{phase:"Skörd (tidig)",months:"Sep",icon:"harvest"},{phase:"Huvudskörd (efter frost)",months:"Okt-Nov",icon:"harvest"}],4:[{phase:"Direktså",months:"Apr-Maj",icon:"seedling"},{phase:"Gallra",months:"Jun",icon:"scissors"},{phase:"Ogräsrensning",months:"Jun-Jul",icon:"scissors"},{phase:"Skörd (tidig)",months:"Okt",icon:"harvest"},{phase:"Huvudskörd (efter frost)",months:"Nov-Dec",icon:"harvest"}],6:[{phase:"Direktså",months:"Maj-Jun",icon:"seedling"},{phase:"Gallra",months:"Jul",icon:"scissors"},{phase:"Ogräsrensning",months:"Jul-Aug",icon:"scissors"},{phase:"Huvudskörd",months:"Okt-Nov",icon:"harvest"}]},nutritionData:[{month:"Apr",N:15,P:10,K:10,label:"Sådd"},{month:"Maj",N:30,P:15,K:15,label:"Groning"},{month:"Jun",N:60,P:25,K:20,label:"Bladtillväxt"},{month:"Jul",N:70,P:40,K:30,label:"Tillväxt"},{month:"Aug",N:40,P:60,K:50,label:"Rotutveckling"},{month:"Sep",N:15,P:70,K:70,label:"Mognad"},{month:"Okt",N:5,P:50,K:80,label:"Skörd"}],nutritionTips:[{timing:"Vid sådd",tip:"Grundgödsla med väl brunnen kompost. Palsternackan är inte kräsen men uppskattar en bra start."},{timing:"Tidig tillväxt",tip:"Lätt giva alggödsel varannan vecka om jorden är mager. Övergödsla inte - det ger mer blast och krokiga rötter."},{timing:"Rotutveckling",tip:"Sluta med kvävegödsel. Ge kaliumrik gödsel (vedaska, stenmel) för smak och lagringsförmåga."},{timing:"Sen höst",tip:"Ingen gödsling alls. Låt frosten göra jobbet - stärkelsen omvandlas till socker och smaken blir fantastisk."}],companions:{good:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft förvirrar morotsflugan som även angriper palsternacka"},{id:"vitlok",name:"Vitlök",icon:"vegetable",why:"Samma skyddande dofteffekt som lök"},{id:"artor",name:"Ärtor",icon:"vegetable",why:"Fixerar kväve i jorden som palsternackan drar nytta av"},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Snabbväxande markskydd som håller ogräset borta medan palsternackan tar sin tid att gro"},{id:"radisa",name:"Rädisa",icon:"vegetable",why:"Markerar raden och luckrar ytan medan palsternackan sakta gror"}],bad:[{id:"morot",name:"Morot",icon:"morot",why:"Samma familj - delar skadedjur (morotsflugan) och sjukdomar"},{id:"dill",name:"Dill",icon:"herb",why:"Samma familj - lockar morotsflugan och delar sjukdomar"},{id:"persilja",name:"Persilja",icon:"herb",why:"Samma familj - konkurrerar och ökar sjukdomstrycket"},{name:"Selleri",icon:"vegetable",why:"Samma familj (flockblommiga) - samma problem med gemensamma skadedjur"}]},rotation:{avoid:[{id:"morot",name:"Morot",category:"grönsaker"},{id:"persilja",name:"Persilja",category:"kryddor"},{id:"dill",name:"Dill",category:"kryddor"},{name:"Selleri",category:"grönsaker"},{name:"Fänkål",category:"kryddor"}],avoidWhy:"Alla flockblommiga delar sjukdomar och morotsflugan. Vänta minst 3-4 år innan du odlar palsternacka på samma plats igen.",goodBefore:[{id:"artor",name:"Ärtor",category:"grönsaker"},{id:"bondbona",name:"Bondböna",category:"grönsaker"},{id:"lok",name:"Lök",category:"grönsaker"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden som ger palsternackan en bra start. Lökväxter sanerar mot svampsjukdomar.",goodAfter:[{name:"Kål",category:"grönsaker"},{id:"sallat",name:"Sallat",category:"grönsaker"},{id:"potatis",name:"Potatis",category:"grönsaker"}],goodAfterWhy:"Palsternackans djupa rötter luckrar jorden fantastiskt. Kål och potatis drar nytta av den fina strukturen."},varieties:[{name:"Halblange Weiss",zones:[1,2,3,4,5,6],note:'Klassisk, pålitlig sort med halvlånga rötter ("halvlång vit"). Lättskördad och lagrar bra. Finns hos Runåbergs.'},{name:"White Gem",zones:[1,2,3,4,5,6],note:"Kompakt sort med korta, breda rötter. Perfekt för tyngre jordar där långa rötter har svårt."},{name:"Tender and True",zones:[1,2,3,4,5,6],note:"Lång, slät rot med fin smak. Kräver djup, stenfri jord men belönar med storlek och sötma."},{name:"Guernsey",zones:[1,2,3,4,5,6],note:"Gammal kulturarvssort med halvlång rot. Bra smak och enkel att odla."},{name:"Student",zones:[1,2,3,4,5,6],note:"Kulturarvssort - en pålitlig gammal arbetshäst. Halvlånga, jämna rötter med fin sötma. Finns hos Runåbergs."}],problems:[{name:"Morotsflugan",symptom:"Rostbruna gångar i roten, rötterna ruttnar inifrån",fix:"Samodla med lök. Fiberduk vid sådd. Palsternacka drabbas mer sällan än morot men problemet finns."},{name:"Mjöldagg",symptom:"Vitt puder på bladen, speciellt sent på säsongen",fix:"Bra luftcirkulation, inte för tätt. Oftast ofarligt sent på säsongen - roten är redan klar."},{name:"Palsternackskräfta",symptom:"Mörka, ruttna fläckar på rotens övre del",fix:"Kupa jord runt kronan. Välj resistenta sorter. God växtföljd (minst 3 år)."},{name:"Dålig groning",symptom:"Få eller inga plantor dyker upp",fix:"Använd BARA färskt frö (max 1 år gammalt). Håll jorden fuktig i 3-4 veckor. Ge inte upp för tidigt!"}],goodToKnow:[{icon:"warning",title:"Använd bara färskt frö!",text:"Palsternacksfrö tappar grobarhet extremt snabbt. Frö som är mer än ett år gammalt gror väldigt dåligt. Köp alltid nytt frö varje säsong - det är inte värt att chansa.",severity:"warning"},{icon:"warning",title:"Blasten kan ge hudirritationer",text:"Palsternackans blad innehåller furokumariner som i kombination med solljus kan ge blåsor och utslag på huden. Använd handskar och långärmad tröja vid skötsel i solsken, särskilt när blasten är fuktig.",severity:"warning"},{icon:"tip",title:"Sötare efter frost - vintersnacks!",text:"Palsternackan gör en magisk grej när frosten kommer: stärkelsen omvandlas till socker. En palsternacka som fått uppleva frost smakar helt annorlunda - nötig, söt, nästan karamellaktig.",severity:"tip"},{icon:"tip",title:"Kan övervintra i jorden",text:"Till skillnad från de flesta rotgrönsaker kan palsternackan ligga kvar i jorden hela vintern. Täck med halm eller löv och gräv upp efter behov. Skörda innan den börjar växa igen på våren - då blir roten trättig.",severity:"tip"},{icon:"calendar",title:"Markera raden med rädisa",text:"Eftersom palsternackan tar 2-4 veckor att gro kan du glömma bort var du sådde. Blanda in lite rädisfrön som gror på en vecka och markerar raden. Rädisor skördas innan palsternackan behöver platsen.",severity:"tip"},{icon:"tip",title:"Rostad palsternacka - din nya favorit",text:"Skär i bitar, ringla olivolja, salt och en gnutta honung. Rosta i ugn på 200°C tills de karamelliseras. Smaken är nötig och söt - barn som inte äter rotfrukter brukar älska den här.",severity:"tip"}],sowing:{method:"direct",label:"Direktsådd",description:"Palsternackan sås direkt på friland - precis som moroten ogillar hon att bli omflyttad. Pålroten störs av omplantering. Sådd tidigt på våren ger längst säsong.",steps:["Gräv djupt (35-40 cm) och ta bort alla stenar","Kratta till fin, jämn yta","Dra spår ca 1-2 cm djupa med 30-40 cm avstånd","Så 3-4 frön var 5:e cm (fröna gror ojämnt, så var generös)","Täck med ett tunt lager fin jord eller vermiculit","Vattna försiktigt med stril - fröna får inte spolas bort","Var beredd på att vänta 2-4 veckor på groning!","Gallra till 10-15 cm avstånd när plantorna har 3-4 riktiga blad"],tips:["Blötlägg fröna i ljummet vatten 24 timmar innan sådd - kan snabba på groningen","Så rädisfrön i samma rad som markör - de gror på en vecka","Täck med fiberduk eller fuktigt tidningspapper för att hålla fukten under groningen","Så så tidigt som möjligt - palsternackan behöver hela säsongen"],indoorWeeks:null},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Palsternackan är tvåårig - hon bildar frö först andra året. Fördelen är att hon kan övervintra i jorden, så du slipper lagra rötterna inomhus som med morot.",steps:["Lämna de bästa plantorna kvar i jorden över vintern (täck med halm)","Alternativt: gräv upp, lagra svalt och plantera ut igen på våren","Palsternackan skjuter blomstjälk under andra sommaren - gula flockar","Låt fröna mogna tills flockarna blir bruna och torra","Klipp av hela flockarna och torka inomhus","Gnugga loss fröna och rensa","Använd fröna SAMMA år eller senast nästa vår - de tappar grobarhet snabbt"],isolation:"Korsar med vild palsternacka och andra palsternackssorter. Isolera med minst 500 m. Vild palsternacka är vanlig i södra Sverige - kan vara svårt att isolera.",storageYears:"1 år (max 2 med perfekt förvaring)",tip:"Palsternacksfrö har kortast hållbarhet av alla vanliga grönsaker. Använd alltid färskt frö - det är inte värt att spara!"},storage:{shelfLife:"4-6 månader (eller hela vintern i jorden)",methods:[{method:"I jorden (med täckning)",icon:"leaf",duration:"Hela vintern",description:"Palsternackans paradgren! Täck med ett tjockt lager halm, löv eller granris och gräv upp efter behov hela vintern. Frosten gör rötterna sötare. Skörda innan tillväxten startar på våren.",best:!0},{method:"Sandlåda i källare",icon:"storage",duration:"4-6 månader",description:"Lägg rötterna i lager med fuktig sand. Förvara svalt (0-4°C) och mörkt. Fungerar bra men du går miste om frostens sötningseffekt.",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Skala, skär i bitar och blanchera 2-3 minuter. Perfekt för soppa, mos och gratänger. Rostad palsternacka fryser också bra.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"2-4 veckor",description:"Klipp av blasten och lägg i plastpåse med hål. Fungerar för kortare lagring men rötterna torkar ut snabbare än morötter.",best:!1}],tips:["Ta bort blasten direkt vid skörd - den suger fukt ur roten","Tvätta inte rötter som ska lagras länge - jordlagret skyddar","Skörda inte alla på en gång - gräv upp efter behov hela vintern","Om du lämnar dem i jorden: skörda innan våren kommer och de börjar växa igen, annars blir roten trättig och smaklös"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3,unit:"kg"}},Ba=Object.freeze(Object.defineProperty({__proto__:null,palsternacka:Y},Symbol.toStringTag,{value:"Module"})),Z={name:"Paprika",icon:"paprika",family:"Potatisväxter",familyLatin:"Solanaceae",difficulty:"Medel",difficultyWhy:"Kräver lång förodling (8-10 v), trivs bäst i växthus i stora delar av Sverige och behöver värme och tålamod - frukterna tar sin tid att mogna.",zones:{outdoor:[1,2,3,4],indoor:null,greenhouse:[1,2,3,4,5,6,7]},days:"70-120",spacing:"40-50 cm",rowSpacing:"50-60 cm",depth:"0,5-1 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 8 timmar direkt sol per dag. Paprika älskar ljus och värme - i halvskugga får du en massa blad men frukt? Glöm det. Placera henne på den varmaste, soligaste platsen du har."},temperature:{min:12,max:35,ideal:"20-25°C",detail:"En riktig värmekär dam. Under 12°C stannar tillväxten helt och blommorna faller av. Bäst fruktsättning vid 20-25°C. Över 30°C kan pollineringen strula - blommorna stöter bort sitt eget pollen."},wind:{level:"Skyddat",detail:"Vindkänslig - grenarna är sprödare än tomatens och knäcks lätt. Plantera invid en södervägg eller i växthus. En uppbindningspinne ger trygghet när frukterna tynger ner."}},watering:{need:"Medel-Hög",icon:"water",summary:"Paprika vill ha jämn fukt utan att stå blöt. Hon är inte lika törstig som tomaten men reagerar direkt på vattenstress - blommorna faller av och frukterna blir bittra.",phases:[{phase:"Plantor inomhus",need:"Låg-Medel",tip:"Håll jorden lätt fuktig men aldrig sörjig. Paprikaplantor inomhus är känsliga för övervattning - rötterna ruttnar snabbare än du tror."},{phase:"Etablering ute (vecka 1-3)",need:"Medel",tip:"Vattna vid plantering och sedan varannan dag. Låt henne torka upp lite mellan vattningarna så rötterna söker sig djupt."},{phase:"Blomning",need:"Medel-Hög",tip:"Kritisk period! Vattenstress nu = blommorna faller av. Vattna jämnt, gärna på morgonen. Mulcha runt basen för att hålla fukten."},{phase:"Fruktsättning & mognad",need:"Hög",tip:"Nu bär hon frukt och är som törstigast. Vattna djupt 2-3 gånger i veckan. I växthus kan det behövas dagligen i högsommaren."}],mistakes:["Ojämn vattning - ger bittra, missformade frukter och blomfall","Vattna ovanifrån och blöta bladen - ger svampsjukdomar, speciellt i växthus","Övervattning av småplantor inomhus - rötterna ruttnar i blöt jord","Glömma att vattna i växthuset under heta dagar - paprika torkar ut snabbare än man tror"],tip:"Mulcha med gräsklipp eller halm runt plantan - det håller fukten jämn och jorden varm. Paprika älskar varm jord lika mycket som varm luft."},soil:"Näringsrik, väldränerad jord med bra struktur. Paprika vill ha det varmt och luftigt kring rötterna - aldrig kompakt och vattendränkt.",soilTips:["Blanda in rikligt med kompost och lite sand för bra dränering","Värm upp jorden med svart markväv eller plastfolie innan utplantering - paprika hatar kall jord","Kalka om pH är under 6.0 - paprika vill ha det lagom surt till neutralt"],timeline:{1:[{phase:"Förodla inomhus",months:"Mar",icon:"indoor"},{phase:"Härda av",months:"Maj",icon:"hardening"},{phase:"Plantera ut",months:"Maj (slutet)",icon:"seedling"},{phase:"Blomning",months:"Jun-Jul",icon:"bloom"},{phase:"Gödsla regelbundet",months:"Jun-Aug",icon:"water"},{phase:"Skörd",months:"Jul-Okt",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"indoor"},{phase:"Härda av",months:"Maj",icon:"hardening"},{phase:"Plantera ut (växthus rekm.)",months:"Jun",icon:"seedling"},{phase:"Blomning",months:"Jun-Jul",icon:"bloom"},{phase:"Gödsla regelbundet",months:"Jun-Aug",icon:"water"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Apr",icon:"indoor"},{phase:"Härda av",months:"Jun",icon:"hardening"},{phase:"Plantera ut (bara växthus)",months:"Jun",icon:"seedling"},{phase:"Blomning",months:"Jul",icon:"bloom"},{phase:"Gödsla regelbundet",months:"Jun-Aug",icon:"water"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Feb",N:10,P:8,K:5,label:"Grodd"},{month:"Mar",N:20,P:15,K:8,label:"Förodling"},{month:"Apr",N:35,P:20,K:15,label:"Tillväxt inomhus"},{month:"Maj",N:55,P:30,K:20,label:"Utplantering"},{month:"Jun",N:70,P:50,K:35,label:"Etablering & blomning"},{month:"Jul",N:55,P:70,K:60,label:"Fruktsättning"},{month:"Aug",N:35,P:75,K:80,label:"Mognad"},{month:"Sep",N:15,P:40,K:55,label:"Sen skörd"}],nutritionTips:[{timing:"Förodling (feb-april)",tip:"Svag näringslösning varannan vecka. Paprikaplantor är småätare som unga - övergödsel ger spinkiga, utdragna plantor."},{timing:"Utplantering",tip:"Blanda kompost och benmjöl i planteringsgropen. Ge henne en bra start med fosfor för starka rötter."},{timing:"Blomning (juni-juli)",tip:"Byt till kaliumrik gödsel (tomatgödsel fungerar utmärkt). Kalium hjälper blommorna att sätta frukt ordentligt."},{timing:"Fruktsättning (juli-aug)",tip:"Fortsätt med kaliumrik gödsel varannan vecka. Minska kväve nu - annars får du vacker buske men få frukter."}],companions:{good:[{id:"basilika",name:"Basilika",icon:"herb",why:"Håller bladlöss borta och trivs i samma värme - ett perfekt par som båda gillar det varmt och skyddat."},{id:"morot",name:"Morot",icon:"vegetable",why:"Luckrar jorden djupt med sina rötter, vilket ger paprikans grunda rötter bättre tillgång till vatten."},{name:"Tagetes",icon:"flower",why:"Avskräcker nematoder och vita flygare med sin starka doft - naturlig skadedjursbekämpning."},{id:"persilja",name:"Persilja",icon:"herb",why:"Lockar nyttiga rovinsekter som äter upp bladlöss. Bra marktäckare under paprikaplantor."}],bad:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Samma familj (potatisväxter) - delar sjukdomar och konkurrerar om samma näring. Håll dem på olika bäddar."},{id:"potatis",name:"Potatis",icon:"vegetable",why:"Också potatisväxter - potatisbladmögel sprider sig gärna vidare till paprika. Inte grannar!"},{id:"chili",name:"Chili",icon:"vegetable",why:"Samma art (Capsicum annuum) - konkurrerar om exakt samma näring och delar alla sjukdomar. Kan dessutom korsa sig och ge oförutsägbara frukter."},{id:"fankal",name:"Fänkål",icon:"herb",why:"Hämmar paprikans tillväxt genom allelopati - de pratar helt enkelt olika språk."}]},rotation:{avoid:[{id:"tomat",name:"Tomat"},{id:"potatis",name:"Potatis"},{name:"Aubergine"},{id:"chili",name:"Chili"}],avoidWhy:"Alla potatisväxter - delar sjukdomar som fusarium och bladmögel. Vänta minst 3-4 år innan du odlar potatisväxter på samma plats igen.",goodBefore:[{name:"Baljväxter"},{id:"lok",name:"Lök"},{name:"Gröngödsling"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden och lökväxter sanerar mot jordburna sjukdomar. Perfekt förspel.",goodAfter:[{name:"Rotgrönsaker"},{name:"Baljväxter"},{id:"sallat",name:"Sallat"}],goodAfterWhy:"Jorden har fortfarande bra struktur och näring kvar efter paprika. Rotgrönsaker och sallat tackar och tar emot."},varieties:[{name:"Yolo Wonder",zones:[1,2,3,4,5],note:"Klassisk OP-sort med stora, tjockvägga frukter. Pålitlig och generös - bra val för nybörjaren."},{name:"California Wonder",zones:[1,2,3,4,5],note:"Stor, blockig OP-paprika som mognar grönt till rött. Söt och krispig."},{name:"Friggitello",zones:[1,2,3,4],note:"Italiensk OP-spetspaprika. Tunn vägg, tidig mognad och fantastisk stekt i olivolja."},{name:"King of the North",zones:[1,2,3,4,5,6],note:"Tidig OP-sort framtagen för korta säsonger (finns hos Runåbergs). Mognar snabbt, perfekt för norr och växthus."},{name:"Lipstick",zones:[1,2,3,4,5],note:"Spetsig OP-paprika (finns hos Runåbergs). Tidig, söt och rikbärande. Fungerar bra i växthus."}],problems:[{name:"Bladlöss",symptom:"Kladdiga blad, krusiga skottspetsar, små gröna eller svarta insekter på undersidan",fix:"Spola av med vatten. Samodla med tagetes och basilika. Vid kraftigt angrepp: såpvatten (1 msk flytande såpa per liter vatten)."},{name:"Gråmögel (Botrytis)",symptom:"Gråaktig päls på blad, stjälk eller frukt - sprider sig snabbt i fuktig luft",fix:"Förbättra luftcirkulationen! Ta bort angripna delar direkt. Vattna vid basen, aldrig ovanifrån. Vädra växthuset flitigt."},{name:"Blomfall",symptom:"Blommor faller av utan att sätta frukt",fix:"Oftast vattenstress, för hög/låg temperatur eller näringsbrist. Vattna jämnt, gödsla med kalium och skaka försiktigt på plantorna för att hjälpa pollineringen."},{name:"Toppröta (blomändsröta)",symptom:"Svarta, insjunkna fläckar i botten av frukten - ser ut som röta men är näringsbrist",fix:"Kalciumbrist orsakad av ojämn vattning. Vattna jämnt och regelbundet. Mulcha för att hålla fukten stabil."}],goodToKnow:[{icon:"clock",title:"Starta tidigt - paprika tar sin tid",text:"Paprika behöver 8-10 veckors förodling inomhus. Börja redan i februari! Hon är långsammare än tomaten i starten och behöver mer tålamod.",severity:"warning"},{icon:"indoor",title:"Växthus gör hela skillnaden",text:"I zon 4 och uppåt blir det svårt att få mogna frukter utomhus. Ett växthus förlänger säsongen och ger paprikan den värme hon längtar efter. Skillnaden är enorm.",severity:"tip"},{icon:"leaf",title:"Grön paprika = omogen paprika",text:"Alla paprikafrukter börjar gröna och mognar sedan till röd, gul eller orange. Gröna frukter är inte en sort utan bara omogna. Vill du ha söt paprika? Ha tålamod och låt henne mogna klart.",severity:"tip"},{icon:"scissors",title:"Plocka den första blomman",text:"Ta bort den allra första blomman (kungsblomman) som sitter i den första grenvinkeln. Det verkar brutalt, men det tvingar plantan att satsa på att bygga sig stark först - och du får fler frukter totalt.",severity:"tip"},{icon:"warning",title:"Plantera ALDRIG för tidigt ut",text:"Paprika är känsligare för kyla än tomat. Vänta tills nattemperaturen stabilt håller sig över 12°C. En kall natt kan sätta tillbaka plantan med veckor.",severity:"warning"},{icon:"sun",title:"Varm jord är halva hemligheten",text:"Paprika vill ha varm jord minst lika mycket som varm luft. Värm upp odlingsbädden med svart markväv eller plastfolie ett par veckor före utplantering. Det ger en flygande start.",severity:"tip"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Paprika måste förodlas inomhus - den långa mognadstiden gör direktsådd utomhus omöjlig i Sverige. Börja tidigt i februari för att ge henne den tid hon behöver.",steps:["Fyll små krukor eller pluggbrätten med fuktig såjord","Lägg 1-2 frön per kruka, knappt 1 cm djupt","Täck med plastfolie eller miniväxthus - paprikafrön vill ha fukt och värme för att gro","Placera VARMT (22-28°C) - gärna på en värmematta. Paprikafrön är långsamma och kan ta 10-20 dagar att gro","När groddarna syns: ta bort plasten och ge maximalt ljus (växtbelysning rekommenderas starkt)","Omplantera till större kruka (10-12 cm) när plantan har 4-6 riktiga blad","Härda av 2 veckor före utplantering: börja med 1 timme utomhus och öka gradvis","Plantera ut i växthus eller på varmaste platsen när nätterna håller 12°C+"],tips:["Starta 8-10 veckor före planerad utplantering - paprika behöver mer tid än tomat","Värmematta under krukor gör enorm skillnad för groningen - det kan halvera väntetiden","Ge växtbelysning 14-16 timmar per dag - fönsterbrädan räcker sällan i februari"],indoorWeeks:"8-10 veckor"},seedSaving:{difficulty:"Enkel",type:"Självpollinerare",biennial:!1,description:"Paprika är huvudsakligen självpollinerare men kan korsa sig med andra paprika- och chilisorter via insekter. Ta frö från mogna, helst övermogna frukter.",steps:["Välj en fullt mogen frukt (röd, gul eller orange beroende på sort) från din finaste planta","Låt frukten sitta kvar på plantan så länge som möjligt - gärna tills den börjar rynka sig","Skär upp frukten och skrapa loss fröna från fröfästet","Skölj fröna lätt i vatten och ta bort allt fruktkött","Lägg fröna på hushållspapper och låt torka helt i rumstemperatur (5-7 dagar)","Förvara i märkt papperspåse på svalt, torrt ställe"],isolation:"Paprika kan korspollineras av insekter - isolera sorter med minst 50 meter, helst mer, eller täck blommorna med tyll för sortäkta frö. Tyll är enklast för hemmaodlare.",storageYears:"3-5 år",tip:"Ta frö från fasta OP-sorter som Yolo Wonder, California Wonder eller King of the North. Alla rekommenderade sorter ovan är öppenpollinerade och perfekta för fröbesparing."},storage:{shelfLife:"1-3 veckor (färsk) / 12 mån (fryst)",methods:[{method:"Kylskåp (färsk)",icon:"snowflake",duration:"1-3 veckor",description:"Lägg paprika i grönsakslådan i kylskåpet. Till skillnad från tomat mår paprika faktiskt bra av kyla. Tvätta inte förrän du ska använda den - fukt förkortar hållbarheten.",best:!0},{method:"Frysa (strimlad)",icon:"snowflake",duration:"8-12 månader",description:"Skär i strimlor eller tärningar och frys direkt - ingen blanchering behövs! Bred ut på en plåt så de inte klumpar ihop sig. Perfekt till matlagning.",best:!1},{method:"Torka",icon:"sun",duration:"6-12 månader",description:"Skär i tunna ringar och torka i ugn på 60°C i 6-8 timmar eller i mattork. Torkar snabbare än tomat. Förvaras lufttätt. Fantastisk i grytor.",best:!1},{method:"Inläggning",icon:"storage",duration:"6-12 månader",description:"Rostad paprika i olja eller ättiksinlagd - underbar smakbomb att ha i skafferiet. Sterilisera burkarna ordentligt.",best:!1}],tips:["Paprika klarar kylskåp bättre än tomaten - men håll henne borta från etylenrika frukter som äpplen","Gröna (omogna) paprikafrukter håller sig längre i kylskåp än mogna röda","Skörda med en bit stjälk kvar - det förlänger hållbarheten","Frysta paprikabitar blir mjuka efter tining men smaken är intakt - perfekt till grytor och såser","Spara kärnhuset med fröna om du vill ta frö - torka det separat"]},harvestCalc:{minPerSqm:2,maxPerSqm:5,unit:"kg"}},Ta=Object.freeze(Object.defineProperty({__proto__:null,paprika:Z},Symbol.toStringTag,{value:"Module"})),X={name:"Päron",icon:"paron",category:"frukt",family:"Rosväxter",familyLatin:"Rosaceae",perennial:!0,lifespan:"50-100+ år",difficulty:"Medel",difficultyWhy:"Kräver årlig beskärning, pollinering av en andra sort och visst sjukdomsförebyggande. Men ett etablerat päronträd ger skörd i generationer - det är en investering som betalar sig hundrafalt.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:null},days:"Skörd år 3-5",spacing:"3-5 m",spacingNote:"Beroende på grundstam: Pyrodwarf 3-3,5 m, kvittengrundstam 3-4 m, fröstam 4-5 m",rowSpacing:"4-6 m",depth:"Ympstället 10 cm ovan mark",depthNote:"Samma regel som äpple - planterar du ympstället under jord förlorar du dvärgeffekten",ph:{min:5.8,max:7,ideal:6.3},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6-8 timmars direkt sol. Päron vill ha det varmt och soligt - en sydvänd, skyddad plats är perfekt. I skugga blir frukten liten, sur och smaklös."},temperature:{min:-25,max:35,ideal:"18-25°C",detail:"Behöver vinterkyla (minst 600-1000 kylltimmar under 7°C) för att bryta vila. De flesta europeiska sorter tål -25°C i vila. Päronblomning är känsligare för vårfrost än äpple - en enda frostnatt i maj kan förstöra hela skörden."},wind:{level:"Skyddat",detail:"Vindskydd är avgörande - päronblommor är ömtåliga och kall vind under blomning minskar pollineringen dramatiskt. Plantera i lä av hus, mur eller häck."}},watering:{need:"Medel",icon:"water",summary:"Etablerade päronträd klarar sig ofta på regnvatten, men nyplanterade träd behöver vattning första åren. Under fruktutvecklingen kan torka ge små, torra frukter.",phases:[{phase:"Vår (blomning)",need:"Medel",tip:"Vattna vid torka under blomning - vattenstress nu ger dålig fruktsättning."},{phase:"Sommar (fruktutveckling)",need:"Medel-Hög",tip:"Vattna jämnt under frukttillväxten. Ojämn vattning kan ge steniga celler och grynig konsistens i frukten."},{phase:"Mognad (aug-okt)",need:"Medel",tip:"Minska vattningen mot mognad. Lite kontrollerad torka kan ge sötare, mer aromatiska päron."},{phase:"Vinter",need:"Ingen",tip:"Trädet vilar. Ingen vattning behövs."}],mistakes:["Glömmer att vattna nyplanterade träd - 90% av misslyckanden beror på vattenbrist år 1","Ojämn vattning under fruktutveckling - ger grynig, stenig konsistens","Vattnar sent på hösten - stimulerar sen tillväxt som fryser"],tip:"Mulcha med gräsklipp eller kompost i en ring runt trädet (lämna 10 cm fritt runt stammen). Det håller fukt, matar jorden och minskar ogräs."},soil:"Djup, väldränerad, humusrik jord. Päronträd är något mer krävande än äpple och trivs bäst i lagom näringsrik lerjord med god dränering.",soilTips:["Gräv en grop dubbelt så bred som rotklumpen, men inte djupare","Blanda in kompost i uppgrävd jord (max 1/3)","Undvik blöta svackor - päron tål inte stående vatten","På tung lera: plantera upphöjt så att ympstället hamnar högt"],timeline:{1:[{phase:"Beskärning",months:"Mars-april",icon:"scissors"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Fruktgallring",months:"Juni",icon:"growth"},{phase:"Fruktmognad",months:"Aug-okt",icon:"harvest"},{phase:"Höstplantering",months:"Okt-nov",icon:"seedling"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}],4:[{phase:"Beskärning",months:"Mars",icon:"scissors"},{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Fruktgallring",months:"Juni-juli",icon:"growth"},{phase:"Fruktmognad",months:"Sep-okt",icon:"harvest"},{phase:"Höstplantering",months:"Sept-okt",icon:"seedling"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],6:[{phase:"Beskärning",months:"Feb-mars",icon:"scissors"},{phase:"Blomning",months:"April-maj",icon:"bloom"},{phase:"Fruktgallring",months:"Juni",icon:"growth"},{phase:"Fruktmognad",months:"Aug-sept",icon:"harvest"},{phase:"Höstplantering",months:"Okt-nov",icon:"seedling"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}]},nutritionData:[{month:"Mar",N:2,P:1,K:1},{month:"Apr",N:5,P:3,K:2},{month:"Maj",N:7,P:5,K:3,label:"Blomning"},{month:"Jun",N:8,P:6,K:5,label:"Fruktsättning"},{month:"Jul",N:5,P:5,K:7},{month:"Aug",N:3,P:3,K:8,label:"Mognad"},{month:"Sep",N:1,P:2,K:5}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge kompost eller brunnen naturgödsel runt trädets droppzon. Päronträd är inte extremt näringskrävande - övergödsel ger frodigt bladverk men dålig frukt."},{timing:"Blomning (maj)",tip:"En liten giva kaliumrik gödsel (vedaska) stärker blomning och fruktsättning."},{timing:"Efter fruktgallring",tip:"Ingen extra gödsel behövs. Övergödsling ökar risken för skorv och kräfta."},{timing:"Höst",tip:"Mulcha med löv eller kompost. Ingen kvävegödsling efter midsommar - nya skott ska hinna mogna före vintern."}],companions:{good:[{name:"Kaprifol",icon:"flower",why:"Lockar pollinatörer tidigt på våren, precis när päronträden behöver dem som mest."},{name:"Ringblomma",icon:"flower",why:"Avskräcker bladlöss och lockar nyttoinsekter. Perfekt som underplantering."},{id:"graslok",name:"Gräslök",icon:"herb",why:"Traditionellt planterad runt fruktträd för att motverka sjukdomar."},{name:"Klöver",icon:"flower",why:"Fixerar kväve, täcker marken och lockar humlor. Perfekt marktäckare under fruktträd."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Ökar risken för Phytophthora (rotröta) som kan skada trädets rötter."},{name:"En (Juniperus)",icon:"tree",why:"Päronrost har en som mellanvärd - en enda enbuske inom 500 meter kan sprida sjukdomen till ditt päronträd."}]},rotation:{avoid:[{name:"Päron"},{name:"Äpple"},{name:"Plommon"},{name:"Körsbär"}],avoidWhy:'Plantera aldrig ett nytt päronträd där ett gammalt stått - "trötthetssjuka" (replant disease) gör att det nya trädet aldrig riktigt trivs. Sjukdomsorganismer och näringsbrister i jorden sätter käppar i hjulet. Vänta minst 5 år eller välj en annan plats.',goodBefore:[{name:"Gräsmatta"},{name:"Gröngödsling"}],goodBeforeWhy:"Mark som legat som gräsmatta eller gröngödslats i flera år ger den bästa starten.",goodAfter:[{name:"Gröngödsling"},{name:"Baljväxter"}],goodAfterWhy:"Om ett gammalt träd tas bort, gröngödsla marken i minst 3-5 år innan du planterar ett nytt fruktträd."},varieties:[{name:"Clapp's Favourite",zones:[1,2,3],note:"Tidig OP-sort (sen aug-sept). Stor, saftig, söt frukt med röd solsida. Amerikansk kulturarvssort från 1860-talet. Grönt kulturarv. Äts färsk - kort hållbarhet."},{name:"Clara Frijs",zones:[1,2,3],note:"Höstpäron (sept). Gröngelb, saftig, söt med fin arom. Dansk kulturarvssort. Grönt kulturarv. Bra kompott- och syltpäron."},{name:"Göteborgs Diamant",zones:[2,3,4],note:"Höstpäron (sept). Svenskt kulturarv odlat i 100+ år. Stor, saftigt, sött med fin arom. Friskt och sjukdomståligt träd. E-planta."},{name:"Conference",zones:[1,2],note:"Sent höstpäron (okt-nov). Världens mest odlade päron. Kolvsmal, brunrostig frukt med smältande kött och melonlik arom. Delvis självfertil. Skorvresistent."},{name:"Gråpäron",zones:[1,2,3,4],note:"Höstpäron (sept). Litet, grönt med gråbrun rost. Gammalt svenskt kulturarv (Grönt kulturarv). Ett av de härdigaste europeiska päronen."},{name:"Carola",zones:[1,2,3],note:"Sent höstpäron. Svensk sort från Balsgård 1983. Fast, krispigt kött. Sjuktålig. Lagras till jul. Grönt kulturarv."},{name:"Esperens Herre",zones:[1,2,3],note:"Höstpäron (sept-okt). Gammal belgisk sort. Söt, produktiv. Bra pollinatör för många andra sorter. Grönt kulturarv."},{name:"Fritjof",zones:[1,2,3],note:"Sent höstpäron. Norsk-svensk sort från Balsgård 1994. Tidig bärighet, sjuktålig. Lagras till nyår. Grönt kulturarv."},{name:"Detskaja",zones:[1,2,3,4,5],note:"Rysk sort (Moskva). Extremt härdig - klarar zon 5-6. Tidig, söt, medelstor frukt. Kort hållbarhet men perfekt för norra Sverige."},{name:"Suvenirs",zones:[1,2,3,4,5],note:"Lettisk sort. Självfertil och extremt härdig (zon 5-6). Stor, söt frukt. Lagras flera veckor. Bästa valet för norra Sverige."}],problems:[{name:"Päronrost (Gymnosporangium fuscum)",symptom:"Orangegula fläckar och utväxter på bladen. Kan ge bladfall. Kräver en (Juniperus) som mellanvärd.",fix:"Det enda som hjälper: ta bort enbuskar inom 500 meters radie. Inga bekämpningsmedel finns för hobbyodlare. Välj resistenta sorter."},{name:"Päronpest/Eldsjuka (Erwinia amylovora)",symptom:"Skottspetsar och blommor svartnar och viskar som bränts. Spridning snabb i fuktigt, varmt väder. Anmälningspliktig sjukdom!",fix:"Skär bort angripna grenar minst 30 cm under skadan. Desinficera verktygen mellan varje snitt. Anmäl misstänkta fall till Jordbruksverket - det är lag på det."},{name:"Päronbladloppa (Cacopsylla pyri)",symptom:"Klibbiga blad med honungsdagg, sot och sotdagg. Bladen kan krulla sig. Larver syns som gulgröna droppar.",fix:"Locka naturliga fiender (nyckelpigor, tvestjärtar). Beskär för god luftcirkulation. Spola av med vattenslang vid kraftigt angrepp."},{name:"Fruktträdskräfta (Neonectria ditissima)",symptom:"Insjunkna, döda barkfläckar som sprider sig runt grenen. Barken flagar och grenen kan dö.",fix:"Skär bort angripna grenar minst 20 cm under skadan. Desinficera verktygen. Undvik att beskära i regnväder - svampen sprids via fukt."}],pollination:{selfFertile:!1,description:"De allra flesta päronsorter är självsterila - du behöver minst två olika sorter som blommar samtidigt. Bin och humlor sköter pollineringen, men träden bör stå inom 50 meters avstånd. I villaområden finns ofta päronträd hos grannarna som hjälper till.",groups:[{name:"Tidig blomning",varieties:["Clapp's Favourite","Clara Frijs","Gråpäron"]},{name:"Mellanblommande",varieties:["Conference","Göteborgs Diamant","Williams","Esperens Herre"]},{name:"Sen blomning",varieties:["Carola","Fritjof","Ingeborg"]},{name:"Självfertila (zon 4-6)",varieties:["Suvenirs","Detskaja","Moskovskaja"]}],tip:"Conference är delvis självfertil och kan sätta lite frukt ensam - men ger mycket bättre skörd med en partner. Suvenirs är helt självfertil och perfekt om du bara har plats för ett träd i norr."},establishment:{description:"De första åren avgör trädets hela framtid. Päronträd är lite långsammare att etablera sig än äpple, men belönar dig med decennier av skörd om du ger dem en bra start.",years:[{year:"År 1",tasks:["Vattna 20-30 liter per vecka hela första sommaren - rötterna behöver tid att etablera sig","Plocka bort ALL frukt som sätts - trädet ska bygga rötter, inte bära frukt","Kontrollera att stödbindningen sitter lagom löst","Mulcha i 1 meters radie runt stammen (inte intill stammen)"]},{year:"År 2",tasks:["Första formande beskärning: välj 3-4 huvudgrenar jämnt runt stammen","Fortsätt vattna vid torka","Tillåt max 5-10 frukter","Gödsla försiktigt med kompost på våren"]},{year:"År 3-5",tasks:["Årlig vår- eller sommarbeskärning (JAS-metoden rekommenderas)","Öka tillåtna frukter gradvis - full skörd år 4-5 (dvärgträd)","Bryt vattenskott under sommaren","Trädet blir alltmer självgående"]}],protection:["Stamskydd mot gnagare (nät eller spiral) - kaniner och sorkar gnager bark på unga träd","Viltskydd om rådjur finns i området","Stammskydd mot solbränna (vit kalkmjölk) på sydvästra sidan vintertid","Vindskydd vid utsatta lägen - päronblomning är extra känslig för kall vind"],tip:"Det bästa du kan göra för ett nyplanterat päronträd: vattna, vattna, vattna. Det låter tråkigt, men 90% av alla misslyckanden med nya fruktträd beror på vattenbrist det första året."},ripeningGuide:{description:"Päron mognar efter plockning - de ska INTE lämnas att mogna klart på trädet! Ett päron som mognar på trädet blir grynigt och mjöligt inifrån. Plocka när frukten lossnar lätt vid en vridning, lägg svalt och låt eftermogna i rumstemperatur 2-7 dagar före ätning.",entries:[{variety:"Clapp's Favourite",from:"aug",to:"sep",type:"Sommarpäron"},{variety:"Clara Frijs",from:"sep",to:"sep",type:"Höstpäron"},{variety:"Gråpäron",from:"sep",to:"sep",type:"Höstpäron"},{variety:"Göteborgs Diamant",from:"sep",to:"sep",type:"Höstpäron"},{variety:"Esperens Herre",from:"sep",to:"okt",type:"Höstpäron"},{variety:"Conference",from:"okt",to:"nov",type:"Sent höstpäron"},{variety:"Carola",from:"okt",to:"dec",type:"Sent höstpäron"},{variety:"Fritjof",from:"okt",to:"dec",type:"Vinterpäron"},{variety:"Detskaja",from:"aug",to:"sep",type:"Sommarpäron"},{variety:"Suvenirs",from:"aug",to:"sep",type:"Sommarpäron"}],tip:"Tricket med päron: plocka dem INNAN de är helt mogna. Lagra svalt (2-4°C) och ta in i rumstemperatur 3-5 dagar före du vill äta dem. Ger du dem en banan som sällskap i en papperspåse snabbar etylenet på mognaden."},goodToKnow:[{icon:"warning",title:"Plocka päron INNAN de mognar",text:'Detta är den vanligaste nybörjarfejlen: att lämna päronen på trädet tills de "ser mogna ut". Gör inte det! Päron mognar inifrån och ut - när de ser mogna ut på utsidan är de redan gryniga inuti. Plocka när de lossnar lätt vid en vridning och kärnorna börjar mörkna.',severity:"warning"},{icon:"warning",title:"Akta päronrosten - den kommer från enbuskar",text:"Päronrost är den vanligaste sjukdomen och det finns inga botemedel. Svampen behöver en (Juniperus) som mellanvärd. Har du enbuskar inom 500 meter? Då kommer du förmodligen få päronrost. Överväg att ta bort enbuskarna om möjligt.",severity:"warning"},{icon:"tip",title:"Päronträd blir GAMLA",text:"Ett päronträd på fröstam kan bli 100-200+ år gammalt. Det är ett livsprojekt - du planterar inte bara för dig själv utan för kommande generationer. I Sverige finns päronträd som är flera hundra år gamla och fortfarande bär frukt.",severity:"tip"},{icon:"tip",title:"Norrlandssorter finns",text:"Tror du att päron inte funkar norr om Dalälven? Tänk om! Ryska och baltiska sorter som Detskaja och Suvenirs klarar zon 5-6 med glans. Suvenirs är dessutom självfertil - perfekt när du bara har plats för ett träd.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Päronträd planteras som ympade träd. Barrotade träd planteras på hösten (okt-nov) för bäst etablering, eller tidig vår. Krukodlade kan planteras hela säsongen.",steps:["Gräv en grop dubbelt så bred som rotsystemet men lika djup","Slå ner en stödpåle INNAN du sätter trädet (annars skadar du rötterna)","Sätt trädet med ympstället 10 cm ovan mark","Fyll igen med uppgrävd jord blandat med kompost","Packa jorden försiktigt runt rötterna","Vattna rikligt - minst 20-30 liter","Bind stammen löst mot stödpålen med mjuk bindning","Mulcha en cirkel på 1 meters radie runt stammen"],tips:["Höstplantering ger bäst etablering - rötterna växer hela vintern","Barrotade träd är billigare och ofta bättre kvalitet","Du behöver minst två sorter för pollinering (om du inte väljer en självfertil sort)","Fråga plantskolan vilken grundstam trädet är ympat på - det avgör trädets storlek"],indoorWeeks:null},seedSaving:{difficulty:"Avancerad",type:"Ympning",biennial:!1,description:"Päronträd förökas genom ympning - att fästa en kvist från önskad sort på en grundstam. Att så kärnor ger inte samma sort tillbaka utan ett helt nytt träd med okända egenskaper.",steps:["Samla ympkvistar i jan-feb (vilande, ettåriga skott)","Förvara i fuktig tidning i kylskåp till april","Välj grundstam (Pyrodwarf för halvdvärg, fröstam för fullstort)","Utför kopulationsympning eller ögonympning","Skydda ympstället med ympvax","Vänta 3-5 år på första skörd"],isolation:"Ympning klonar sorten exakt - ingen korspollinering relevant.",storageYears:"Ympkvistar håller 2-3 månader i kylskåp",tip:"Gå en ympkurs! Svenska trädgårdsföreningar och Riksförbundet Svensk Trädgård anordnar kurser varje vår. OBS: inte alla päronsorter är kompatibla med kvittengrundstam - kontrollera kompatibiliteten."},storage:{shelfLife:"1 vecka - 3 månader (beroende på sort)",methods:[{method:"Kallförvar",icon:"cellar",duration:"1-3 månader",description:"Lagra sent mognande sorter (Conference, Carola, Fritjof) svalt vid 2-4°C med hög luftfuktighet. Ta in i rumstemperatur 3-5 dagar före du vill äta dem.",best:!0},{method:"Sylt och marmelad",icon:"storage",duration:"1+ år",description:"Päron ger fantastisk sylt och marmelad. Blanda gärna med ingefära eller vanilj. Perfekt för överskottsskörd.",best:!1},{method:"Torkning",icon:"sun",duration:"6+ månader",description:"Skiva päron tunt och torka i ugn (50°C, 6-8 timmar). Torkade päron är ljuvligt söta som snacks.",best:!1},{method:"Frysning",icon:"snowflake",duration:"10-12 månader",description:"Skala, kärna ur och skiva. Frys med lite citronjuice mot brunfärgning. Bra till pajer och smulpajer.",best:!1}],tips:["Lagra bara felfria päron - en rutten frukt smittar snabbt","Sommarpäron (Clapp's) håller bara 1-2 veckor - ät direkt eller gör sylt","Sena sorter (Carola, Fritjof) förbättras i smak efter lagring","Päron avger etylen - förvara inte med andra frukter som tar skada"]},harvestCalc:{minPerSqm:2,maxPerSqm:8,unit:"kg per träd (år 5+)"},pruning:{label:"Beskärning",types:{winter:{name:"Vårbeskärning (uppbyggnad)",when:"Mars-april, innan knopparna svällt",description:"Päronträd beskärs försiktigare än äpple - hårda snitt ger massor av vattenskott. Fokusera på att forma kronan öppen och luftig. Päron växer naturligt mer upprätt än äpple, så tänk på att öppna ut kronan.",steps:["Ta bort döda, sjuka och korsande grenar","Ta bort rakt uppåtväxande vattenskott","Glesa ur kronan för ljus och luftcirkulation","Var FÖRSIKTIG - ta inte bort mer än 1/4 av kronan per år","Klipp snett strax ovanför en utåtriktad knopp","Desinficera verktygen vid sjukdomsmisstanke"]},summer:{name:"Sommarbeskärning (JAS-metoden)",when:"Juli-augusti-september",description:"Modern rekommendation: beskär päronträd på sommaren (JAS-perioden) istället för vintern. Det ger bättre vinterhärdighet och mindre vattenskottbildning. Bryt bort mjuka vattenskott och gallra fruktklungor.",steps:["Bryt bort vattenskott medan de fortfarande är mjuka","Ta bort skott som skuggar mognande frukt","Korta in årets sidoskott till 3-4 blad","Fördelen: snitten läker snabbt och svamprisken är lägre"]}}},propagation:{difficulty:"Avancerad",methods:[{method:"Ympning",description:"En kvist (ymp) från önskad sort fästs på en utvald grundstam. Kopulationsympning på våren eller ögonympning i augusti. OBS: kontrollera kompatibilitet med grundstammen - inte alla päronsorter fungerar på kvittengrundstam.",icon:"seedling"},{method:"Frösådd (experiment)",description:"Stratifiera päronkärnor i kylskåp i 8-10 veckor, så i kruka. Du får ett unikt träd, men det tar 10-15 år till skörd och frukten blir inte samma sort. Spännande men långsamt experiment!",icon:"seed"}],tip:"Ympkurser arrangeras av lokala trädgårdsföreningar varje vår. Flera kulturarvssorter (Gråpäron, Clara Frijs) kan vara svåra att hitta i handeln men går att få tag på som ympkvistar."}},wa=Object.freeze(Object.defineProperty({__proto__:null,paron:X},Symbol.toStringTag,{value:"Module"})),Q={name:"Persilja",icon:"persilja",category:"kryddor",family:"Flockblommiga",familyLatin:"Apiaceae",perennial:!1,difficulty:"Enkel",difficultyWhy:"Enkel att odla och tolererar kyla bra. Den enda utmaningen? Groningen tar evigheter - 2-4 veckor! Men har du tålamod belönas du med en av de mest tacksamma kryddväxterna.",zones:{outdoor:[1,2,3,4,5,6,7],indoor:[1,2,3,4,5,6,7,8],greenhouse:[1,2,3,4,5,6,7,8]},days:"70-90",spacing:"15-20 cm",rowSpacing:"25-30 cm",depth:"0.5-1 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Persilja trivs i sol men klarar halvskugga galant - faktiskt en av få kryddor som ger bra skörd även utan full sol. I söderläge kan hon till och med uppskatta lite skugga under högsommaren."},temperature:{min:-10,max:25,ideal:"12-20°C",detail:"Persilja är härdigare än de flesta tror! Klarar frost ner till -10°C och trivs bäst i sval väderlek. I stark värme skjuter hon i blom snabbare. En riktig nordbo bland kryddorna."},wind:{level:"Tålig",detail:"Persilja har stadiga stjälkar och sitter stabilt i marken. Hon klarar vind utan problem - inga krusiduller behövs."}},watering:{need:"Medel",icon:"water",summary:"Persilja vill ha jämn fukt men är inte krävande. Hon klarar torka bättre än basilika men ger mest blad med regelbunden vattning. Låt inte jorden torka ut helt.",phases:[{phase:"Groning (2-4 veckor!)",need:"Hög",tip:"DET HÄR är den kritiska perioden. Jorden MÅSTE hållas fuktig hela groningsperioden - torkar den ut dör fröna. Täck gärna med en fuktig tidning eller fiberduk. Tålamod!"},{phase:"Unga plantor",need:"Medel",tip:"Vattna regelbundet men låt ytan torka lite mellan vattningarna. Plantorna är små men segare än de ser ut."},{phase:"Etablerad planta",need:"Medel",tip:"Vattna 2-3 gånger i veckan vid torrt väder. Mulcha gärna runt plantorna för att hålla fukten."}],mistakes:["Ger upp under groningen - fröna tar verkligen 2-4 veckor!","Låt jorden torka ut under groning - då dör alla frön","Övervattnar i kruka - persilja har djup pålrot som ruttnar i stående vatten"],tip:'Blötlägg fröna i ljummet vatten över natten före sådd - det kan snabba på groningen med några dagar. Somliga häller kokande vatten över såddplatsen före sådd för att "väcka" fröna.'},soil:"Persilja vill ha näringsrik, lucker jord med bra dränering. Hon har en djup pålrot som behöver kunna gräva sig ner ordentligt. Lerig jord går, men blanda in sand eller kompost för att luckra upp.",soilTips:["Blanda in rikligt med kompost - persilja är hungrig och vill ha mat hela säsongen","Luckra jorden djupt (minst 25 cm) - pålroten vill ner!","I kruka: välj en djup kruka (minst 25 cm) - grunda krukor ger klena plantor","Mulcha med gräsklipp eller halm - håller fukten och matar jorden samtidigt"],timeline:{1:[{phase:"Förodling inomhus",months:"Mars-april",icon:"indoor"},{phase:"Direktså utomhus",months:"April-maj",icon:"seed"},{phase:"Skörd löpande",months:"Juni-okt",icon:"harvest"},{phase:"Övervintring möjlig",months:"Nov-mars",icon:"snowflake"}],4:[{phase:"Förodling inomhus",months:"Mars-april",icon:"indoor"},{phase:"Direktså utomhus",months:"Maj",icon:"seed"},{phase:"Skörd löpande",months:"Juli-sept",icon:"harvest"}],6:[{phase:"Förodling inomhus",months:"April",icon:"indoor"},{phase:"Direktså utomhus",months:"Juni",icon:"seed"},{phase:"Skörd löpande",months:"Juli-sept",icon:"harvest"}]},nutritionData:[{month:"Apr",N:2,P:1,K:1},{month:"Maj",N:4,P:2,K:2},{month:"Jun",N:6,P:3,K:3},{month:"Jul",N:7,P:4,K:4},{month:"Aug",N:6,P:3,K:3},{month:"Sep",N:4,P:2,K:2}],nutritionTips:[{timing:"Vid sådd/utplantering",tip:"Blanda in kompost eller brunnen stallgödsel i jorden. Persilja vill ha en bra start - tänk näringsrik men inte överdrivet."},{timing:"Varje 4:e vecka (juni-aug)",tip:"Ge en omgång nässelvatten eller annan mild flytande gödning. Persilja producerar massor av blad och behöver påfyll - men övergödsla inte, då tappar hon smak."},{timing:"Obs!",tip:"För mycket kväve ger stora men smakfattiga blad. Lagom är bäst - persilja ska smaka persilja, inte gödsel."}],companions:{good:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Persilja och tomat är bästa vänner! Persilja lockar nyttoinsekter som äter bladlöss på tomaterna. Dessutom sägs persilja förstärka tomaternas smak."},{id:"basilika",name:"Basilika",icon:"herb",why:"Basilika och persilja kompletterar varandra fint - olika växtform och rotsystem. Basilikan lockar pollinatörer medan persiljan ger marktäckning."},{id:"lok",name:"Lök",icon:"vegetable",why:"Lök och persilja kompletterar varandra - olika rotdjup, och lökens doft håller skadedjur borta från persiljan."}],bad:[{id:"sallat",name:"Sallat",icon:"vegetable",why:"Konkurrerar om samma yta och fukt. Båda vill breda ut sig i marknivån och det blir trängsel."}]},rotation:{avoid:[{id:"morot",name:"Morot"},{id:"dill",name:"Dill"},{id:"selleri",name:"Selleri"}],avoidWhy:"Alla tillhör Apiaceae (Flockblommiga) och delar skadegörare som morotsflugan och sjukdomar som bladfläcksjuka. Vänta 3-4 år innan du odlar persilja på samma plats.",goodBefore:[{id:"potatis",name:"Potatis"},{id:"squash",name:"Squash"}],goodBeforeWhy:"Potatis och squash mår bra av den jord persilja lämnar efter sig - välbearbetad och med lagom näring kvar.",goodAfter:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodAfterWhy:"Baljväxter berikar jorden med kväve som persiljan tacksamt tar emot. Perfekt förfrukt!"},varieties:[{name:"Gigante d'Italia",zones:[1,2,3,4,5,6,7],note:'Klassisk italiensk bladpersilja med stora, platta blad. Starkast smak av alla sorter. Favoriten i matlagning - den "riktiga" persiljan.'},{name:"Moss Curled",zones:[1,2,3,4,5,6,7],note:'Kruspersilja med tätt krusade blad. Mildare smak, men vacker som garnering och härdigt växtsätt. Den klassiska "pynt-persiljan".'},{name:"Hamburg",zones:[1,2,3,4,5,6],note:"Rotpersilja - odlas för den stora vita roten! Helt annan grönsak egentligen. Roten smakar milt som en mix av morot och selleri. Tar 90-100 dagar."}],problems:[{name:"Morotsflugan",symptom:"Plantan vissnar, bladen blir rödlila. Larver syns i roten (rotpersilja). Flugan lägger ägg vid basen.",fix:"Täck med insektsnät från sådddagen - det enklaste och säkraste skyddet. Samodla med lök vars doft förvirrar flugan. Undvik att gallra på kvällen då flugan är aktiv."},{name:"Bladfläcksjuka (Septoria)",symptom:"Bruna fläckar med ljus mitt på bladen. Blad gulnar och vissnar. Vanligast i fuktigt väder.",fix:"Ta bort drabbade blad direkt. Se till att plantorna har luftigt och inte står för tätt. Undvik att vattna ovanifrån. Odla inte Apiaceae på samma plats två år i rad."},{name:"Sniglar",symptom:"Avätna blad, slemspår. Unga plantor kan bli helt uppätna.",fix:"Snigelskydd runt såddplatsen, speciellt när plantorna är unga. Ölkoppar funkar bra. När plantan är större klarar hon lite snigelgnag utan problem."}],goodToKnow:[{icon:"warning",title:"SEGA frön - tålamod!",text:"Persiljafrön gror EXTREMT långsamt - 2 till 4 veckor! Det är normalt. Ge inte upp. Blötlägg fröna över natten i ljummet vatten före sådd för att snabba på processen. Håll jorden fuktig hela perioden - torkar den ut måste du börja om.",severity:"warning"},{icon:"warning",title:"Tvåårig - blommar och dör år två",text:"Persilja är tvåårig. Första året ger hon blad. Andra året skjuter hon i blom, sätter frö och dör. När hon börjar skjuta blomstjälk tappar bladen smak. Odla ny persilja varje år om du vill ha bra skörd.",severity:"warning"},{icon:"tip",title:"Två typer - välj rätt",text:"Slätbladig persilja (italiensk) har starkare smak och används mest i matlagning. Kruspersilja är mildare och fin som garnering. Rotpersilja är i princip en helt annan grönsak - odlas för roten. Välj sort efter hur du vill använda den!",severity:"tip"},{icon:"tip",title:"Köldhärdig - kan övervintra",text:"Persilja klarar frost ner till -5°C och kan med lite tur övervintra i zon 1-3. Täck med löv eller halm på hösten. På våren kommer hon tillbaka - men blommar snart och då är det dags för ny sådd.",severity:"tip"}],sowing:{method:"both",label:"Förodling & direktsådd",description:"Persilja kan både förodlas inomhus och direktsås utomhus. Förodling ger försprång men kräver tålamod - fröna tar 2-4 veckor att gro. Direktsådd fungerar fint från maj i de flesta zoner. Nyckeln? Håll jorden fuktig under hela groningen!",steps:["Blötlägg fröna i ljummet vatten över natten (snabbar på groningen)","Så 0.5-1 cm djupt i fuktig jord","Täck med fuktig tidning eller fiberduk för att hålla fukten","Håll jorden KONSTANT fuktig i 2-4 veckor - torkar den ut dör fröna","Groning på 14-28 dagar (ibland längre - ge inte upp!)","Gallra till 15-20 cm mellanrum när plantorna har 3-4 örtblad","Vid förodling: härda av 1 vecka innan utplantering","Plantera ut när marken är bearbetningsbar (tål lätt frost)"],tips:["Så flera omgångar med 3 veckors mellanrum för färsk persilja hela sommaren",'Häll kokande vatten över såddplatsen före sådd - gammalt trick som "väcker" fröna',"Kruspersilja gror snabbare än slätbladig - bra för otåliga odlare","Förodlade plantor ger 3-4 veckors försprång mot direktsådda"],indoorWeeks:"6-8 veckor före utplantering"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Persilja är tvåårig och blommar först andra året. Fröna bildas i flockar (typiskt för Apiaceae-familjen). Korspollerar med andra persiljassorter men INTE med morot trots samma familj.",steps:["Låt 3-4 plantor stå kvar över vintern (täck med löv i kalla zoner)","På våren skjuter blomstjälkar upp - låt dem blomma fritt","Insekter pollinerar blommorna under sommaren","Vänta tills fröna blivit bruna och torra på plantan (aug-sept)","Klipp av fröflockarna och låt dem eftertorka i papperspåse","Gnugga loss fröna - blås bort skal och skräp","Förvara svalt och torrt i märkt kuvert"],isolation:"Korspollerar med andra persiljassorter via insekter. Håll minst 500 meters avstånd mellan sorter för sortrena frön. Korspollerar INTE med morot, dill eller selleri trots samma familj.",storageYears:"1-2 år (groningsförmågan minskar snabbt)",tip:"Persiljafrön tappar grobarhet snabbt - använd helst färska frön (max 1-2 år gamla). Det är därför man alltid ska köpa nytt fröpaket om groningen uteblir!"},storage:{shelfLife:"1-2 veckor (färsk)",methods:[{method:"Frysning (bäst!)",icon:"snowflake",duration:"6+ månader",description:"Hacka persiljan och frys i isbitsfack med lite vatten eller olja. Perfekta portioner att slänga i grytan! Behåller smak och färg betydligt bättre än torkning.",best:!0},{method:"I glas med vatten",icon:"water",duration:"1-2 veckor",description:"Ställ stjälkarna i ett glas vatten i kylen med en plastpåse löst över. Byt vatten varannan dag. Enkelt och effektivt.",best:!1},{method:"Torkning",icon:"storage",duration:"12+ månader",description:"Häng i knippen eller torka i ugn på 50°C. Torkad persilja tappar mycket smak jämfört med färsk, men funkar i grytor och såser.",best:!1}],tips:["Frys i isbitsfack med olivolja - perfekta portioner för matlagning","Torkad persilja tappar 70% av smaken - frys hellre om du kan","Skörda på morgonen för bäst smak - eteriska oljorna är starkast då","Rotpersilja förvaras som morötter - i sand i en sval källare, håller hela vintern"]},harvestCalc:{minPerSqm:.2,maxPerSqm:.5,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp yttre stjälkar från basen, låt hjärtat växa vidare",description:"Skörda genom att klippa de yttre stjälkarna nära basen. Låt alltid de innersta bladen sitta kvar - det är därifrån ny tillväxt kommer. Börja skörda när plantan har 8-10 stjälkar. Ju mer du skördar, desto mer växer!",uses:[{use:"Färsk",tip:"Tillsätt sist i matlagningen för bäst smak. Slätbladig persilja har starkast smak. Hacka grovt - för fin hackning oxiderar och tappar smak."},{use:"Torkad",tip:'Funkar i grytor och såser men tappar mycket smak. Torka i ugn på 50°C eller hängtorka i knippen. Bäst som "bakgrundskrydda".'},{use:"Frusen",tip:"DET bästa sättet att bevara persilja! Hacka och frys i isbitsfack med vatten eller olivolja. Behåller både smak och färg."}]}},Ma=Object.freeze(Object.defineProperty({__proto__:null,persilja:Q},Symbol.toStringTag,{value:"Module"})),$={name:"Plommon",icon:"plommon",category:"frukt",family:"Rosväxter",familyLatin:"Rosaceae",perennial:!0,lifespan:"40-60 år",difficulty:"Medel",difficultyWhy:"Kräver årlig beskärning (OBS: bara sommarhalvåret!), viss sjukdomskontroll och tålamod de första åren. Men de flesta svenska plommonsorter är självfertila och ger riklig skörd - det är ett tacksamt fruktträd.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:null},days:"Skörd år 3-5",spacing:"3-5 m",spacingNote:"Beroende på grundstam: Pixy (dvärg) 2,5-3 m, St. Julien 3-4 m, fröstam 4-5 m",rowSpacing:"4-6 m",depth:"Ympstället 10 cm ovan mark",depthNote:"Samma princip som äpple och päron - ympstället ska synas ovanför jorden",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmars direkt sol. Plommon behöver sol och värme för att mogna ordentligt - i halvskugga blir frukten sur och liten. En sydvänd mur eller häck i ryggen gör underverk."},temperature:{min:-25,max:35,ideal:"18-25°C",detail:"De flesta europeiska plommonsorter tål -25°C i vila. Men sena vårfroster är den stora fienden - plommonblomningen är ömtålig. Välj en plats som inte är en frostficka."},wind:{level:"Skyddat",detail:"Vindskydd förbättrar pollinering och minskar fruktfall. Plommonträd med tung skörd kan tappa grenar i blåst - stötta tunga grenar med grenspjut."}},watering:{need:"Medel",icon:"water",summary:"Etablerade plommonträd klarar sig relativt bra på regnvatten. Nyplanterade träd behöver vattning, och under torra somrar kan extra vatten ge avsevärt bättre skörd.",phases:[{phase:"Vår (blomning)",need:"Medel",tip:"Vattna vid torka under blomning - vattenstress ger sämre fruktsättning."},{phase:"Sommar (fruktutveckling)",need:"Medel-Hög",tip:"Vattna jämnt under frukttillväxten. Ojämn vattning kan ge sprickbildning i frukten - ett vanligt problem med plommon."},{phase:"Mognad (jul-sep)",need:"Medel",tip:"Minska vattningen mot mognad. Lite torrare förhållanden ger sötare frukt med bättre arom."},{phase:"Vinter",need:"Ingen",tip:"Trädet vilar. Minska vattning redan från mitten av augusti."}],mistakes:["Glömmer att vattna nyplanterade träd första somrarna","Ojämn vattning under fruktutveckling - plommon spricker lätt","Vattnar för sent på hösten - stimulerar tillväxt som inte hinner mogna"],tip:"Mulcha med gräsklipp (max 10 cm tjockt) runt trädet men inte intill stammen. Sluta mulcha efter juli - trädet ska förbereda sig för vinter, inte fortsätta växa."},soil:"Väldränerad, näringsrik, mullrik jord. Plommon trivs bäst i lagom tung lerjord med god dränering. Tung, vattenmättad lera är den vanligaste orsaken till att plommonträd mår dåligt.",soilTips:["Gräv en grop dubbelt så bred som rotklumpen","Blanda in kompost i uppgrävd jord (max 1/3)","På tung lera: plantera i upphöjd bädd (ca 30 cm) för bättre dränering","Undvik frostfickor - välj en sluttning eller plats nära hus"],timeline:{1:[{phase:"Sommarbeskärning (JAS)",months:"Jul-aug",icon:"scissors"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Fruktgallring",months:"Juni-juli",icon:"growth"},{phase:"Fruktmognad",months:"Jul-sep",icon:"harvest"},{phase:"Höstplantering",months:"Sep-okt",icon:"seedling"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}],4:[{phase:"Sommarbeskärning (JAS)",months:"Jul-aug",icon:"scissors"},{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Fruktgallring",months:"Juli",icon:"growth"},{phase:"Fruktmognad",months:"Aug-sep",icon:"harvest"},{phase:"Höstplantering",months:"Sep-okt",icon:"seedling"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],6:[{phase:"Sommarbeskärning (JAS)",months:"Jul-aug",icon:"scissors"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Fruktgallring",months:"Juni-juli",icon:"growth"},{phase:"Fruktmognad",months:"Aug-sep",icon:"harvest"},{phase:"Höstplantering",months:"Okt",icon:"seedling"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}]},nutritionData:[{month:"Mar",N:2,P:1,K:1},{month:"Apr",N:5,P:3,K:2},{month:"Maj",N:7,P:5,K:4,label:"Blomning"},{month:"Jun",N:8,P:6,K:5,label:"Fruktsättning"},{month:"Jul",N:5,P:5,K:7,label:"Mognad börjar"},{month:"Aug",N:3,P:3,K:8,label:"Skörd"},{month:"Sep",N:1,P:2,K:4}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge kompost eller brunnen naturgödsel runt droppzonen. Undvik för mycket kväve - det ökar risken för sjukdomar och ger frodiga blad men dålig frukt."},{timing:"Blomning (maj)",tip:"En liten giva vedaska (kaliumrik) stärker blomning och fruktsättning."},{timing:"Sommar",tip:"Ingen extra gödsling behövs. Mulcha med gräsklipp för långsam näringstillförsel."},{timing:"Höst",tip:"Mulcha med löv eller kompost. Ingen kvävegödsling efter midsommar - nya skott måste mogna före vintern."}],companions:{good:[{name:"Ringblomma",icon:"flower",why:"Avskräcker bladlöss och lockar nyttoinsekter som pollinerar blommorna."},{name:"Klöver",icon:"flower",why:"Fixerar kväve, täcker marken och lockar humlor. Bra marktäckare under fruktträd."},{id:"graslok",name:"Gräslök",icon:"herb",why:"Traditionellt planterad runt fruktträd - kan motverka svampsjukdomar."},{name:"Lavendel",icon:"flower",why:"Lockar pollinatörer med sin starka doft och avskräcker vissa skadedjur."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Ökar risken för rotröta (Phytophthora) som kan skada trädets rötter."},{name:"Gräsmatta ända in",icon:"grass",why:"Gräs konkurrerar hårt om vatten och näring i rotzonen. Håll en ogräsfri cirkel (1 m radie) runt stammen."}]},rotation:{avoid:[{name:"Plommon"},{name:"Körsbär"},{name:"Äpple"},{name:"Päron"}],avoidWhy:"Plantera aldrig ett nytt plommonträd exakt där ett gammalt stått - sjukdomsorganismer i jorden (trötthetssjuka) gör att det nya trädet aldrig riktigt trivs. Vänta minst 5 år eller välj en annan plats.",goodBefore:[{name:"Gräsmatta"},{name:"Gröngödsling"}],goodBeforeWhy:"Mark som legat som gräsmatta eller gröngödslats ger bäst förutsättningar.",goodAfter:[{name:"Gröngödsling"},{name:"Baljväxter"}],goodAfterWhy:"Gröngödsla i minst 3-5 år efter att ett gammalt fruktträd tagits bort."},varieties:[{name:"Herman",zones:[1,2,3,4],note:'Tidigast av alla (slutet juli). Blålila, sötsyrlig, fast kött. Självfertil. Grönt kulturarv. "Sommarstugeägarens favorit" - hinner mogna före semesterns slut.'},{name:"Opal",zones:[1,2,3,4],note:"Tidig (aug). Rödviolett med grådagg, aromatisk och sötsyrlig. Självfertil. Grönt kulturarv (Balsgård). Sveriges mest populära plommonsort."},{name:"Victoria",zones:[1,2,3,4],note:"Sen (sept). Gulröd med violett dagg, söt, saftig. Självfertil. Grönt kulturarv. Sveriges mest odlade plommonsort. Otroligt produktiv - stötta grenarna!"},{name:"Jubileum",zones:[1,2,3,4],note:"Tidig höst (sept). Purpurfärgad, större och godare än Victoria. Svensk sort från Balsgård 1988. Självfertil. Grönt kulturarv. Ses som Victorias ersättare."},{name:"Reine Claude d'Oullins",zones:[1,2,3,4],note:"Sen sommar (aug-sept). Stor, rund, gulgrön med smältande sött kött. Självfertil. Grönt kulturarv. Anses av många som det godaste plommonet."},{name:"Czar",zones:[1,2,3,4,5],note:"Sen sommar (aug). Blå, oval, saftig. Självfertil. Gammal sort (1800-tal). Det härdigaste plommonet - fungerar upp till zon 5. Svagväxande, litet träd."},{name:"Violetta",zones:[1,2,3],note:"Mitten aug. Mörkviolett, söt, fin arom. Korsning Grand Duke x Herman. Självfertil. Grönt kulturarv. Litet träd med vacker blomning."},{name:"Experimentalfältsviskon",zones:[1,2,3,4],note:"Sent (mitten sept). Mörkviolett, liten, aromatisk. Svenskt kulturarv från Experimentalfältet i Stockholm. Självfertil. Kraftigt växande."},{name:"Stor Grön Reine Claude",zones:[1,2,3,4],note:"Höst (sept). Gröngrå, smältande sött kött med exceptionell arom. Kom till Sverige på 1700-talet. Kulturarvssort. Delvis självfertil - bättre med pollinator."},{name:"Excalibur",zones:[1,2,3],note:"Sen sommar (aug-sept). Rödviolett, välsmakande. Engelsk sort. INTE självfertil - behöver Opal eller Victoria som partner."}],problems:[{name:"Pungsjuka (Taphrina pruni)",symptom:'Frukterna deformeras till avlånga, tomma "pungplommon" utan kärna. Gulgröna, svampiga frukter. Vanligast vid kall, fuktig vår.',fix:"Plocka bort angripna frukter INNAN svampen hinner sprida sporer. Ingen kemisk bekämpning. Reine Claude d'Oullins, Opal och Victoria är motståndskraftiga."},{name:"Monilia (fruktröta/blomtorka)",symptom:"Blommor vissnar och hänger kvar, grenar dör. På frukt: brun röta med vita/gråa sporcirklar. Fruktmumier hänger kvar i trädet.",fix:"Ta bort alla fruktmumier (de sprider smitta!). Samla fallfrukt. Beskär angripna grenar in till frisk ved. God luftcirkulation och undvik övergödsling med kväve."},{name:"Plommonvecklare (Cydia funebrana)",symptom:'"Mask i plommonet" - larver äter sig in i frukten. Angripna plommon faller i förtid. Liten ljusbrun fjäril (1 cm vingspann).',fix:"Häng feromonfällor i trädet strax efter blomning. Plocka och kassera angripna frukter tidigt. Biologisk bekämpning med Bacillus thuringiensis (Bt)."},{name:"Gummiflöde (Gummosis)",symptom:'Trädet "blöder" klart, klibbigt harts/gummi från snittytor eller skador. Vanligt efter felbeskärning.',fix:"Beskär ALDRIG plommon på vintern! JAS-perioden (juli-aug-sept) är enda rätta tiden. Skydda mot barkskador. Rena, vassa verktyg minskar risken."}],pollination:{selfFertile:!0,description:"De flesta svenska plommonsorter (Herman, Opal, Victoria, Jubileum, Reine Claude d'Oullins, Czar) är självfertila - de kan sätta frukt ensamma. MEN: korspollinering ger alltid större, fler och bättre frukter. Har du plats, plantera gärna två sorter.",groups:[{name:"Tidig blomning",varieties:["Herman","Opal","Czar"]},{name:"Mellanblommande",varieties:["Victoria","Jubileum","Reine Claude d'Oullins","Excalibur"]},{name:"Sen blomning",varieties:["Experimentalfältsviskon","Stor Grön Reine Claude"]}],tip:"De flesta sorter är självfertila, men två träd ger alltid bättre skörd. Opal och Victoria är utmärkta universalpollinatörer som passar de flesta. OBS: europeiska plommon (Prunus domestica) och japanska plommon (P. salicina) kan INTE pollinera varandra."},establishment:{description:"Plommonträd etablerar sig snabbare än äpple och päron - särskilt på dvärggrundstam (Pixy) kan du få frukt redan år 2-3. Men de första åren avgör trädets hela framtid.",years:[{year:"År 1",tasks:["Vattna en hink per vecka hela första sommaren","Plocka bort ALL frukt - trädet ska bygga rötter","Kontrollera stödbindningen","Mulcha i 1 meters radie (inte intill stammen)","Ta bort rotskott tidigt - riv helst loss för hand"]},{year:"År 2",tasks:["Planteringsbeskärning: spara 3-4 huvudgrenar, korta in till ca 30 cm","Tillåt max 5-10 frukter","Fortsätt ta bort rotskott","Gödsla försiktigt med kompost"]},{year:"År 3-5",tasks:["Årlig sommarbeskärning (JAS) - aldrig vinter!","Öka tillåtna frukter gradvis","Fruktgallring: lämna 4-5 cm mellan frukter","Stötta tunga grenar med grenspjut (särskilt Victoria)"]}],protection:["Stamskydd mot gnagare (nät eller spiral) - kaniner och sorkar gnager bark","Viltskydd om rådjur finns i området","Stammskydd mot solbränna på sydvästra sidan vintertid","Stötta tunga grenar - plommonträd med rik skörd kan tappa grenar"],tip:"Plommonträd bildar ofta rotskott - särskilt om rötterna skadas av gräsklippare eller spade. Ta bort dem tidigt, helst genom att riva loss dem för hand (sekatör stimulerar fler skott)."},ripeningGuide:{description:"Plommon mognar från slutet av juli till oktober beroende på sort. Till skillnad från päron ska plommon mogna på trädet - plocka dem när de är mjuka, aromatiska och lossnar lätt. Ett plommon som mognat klart på trädet har en helt annan smak än ett butiksplockat.",entries:[{variety:"Herman",from:"jul",to:"aug",type:"Tidigt plommon"},{variety:"Opal",from:"aug",to:"aug",type:"Tidigt plommon"},{variety:"Violetta",from:"aug",to:"aug",type:"Sommarplommon"},{variety:"Czar",from:"aug",to:"aug",type:"Sommarplommon"},{variety:"Reine Claude d'Oullins",from:"aug",to:"sep",type:"Sommarplommon"},{variety:"Excalibur",from:"aug",to:"sep",type:"Sommarplommon"},{variety:"Jubileum",from:"sep",to:"sep",type:"Höstplommon"},{variety:"Victoria",from:"sep",to:"sep",type:"Höstplommon"},{variety:"Stor Grön Reine Claude",from:"sep",to:"sep",type:"Höstplommon"},{variety:"Experimentalfältsviskon",from:"sep",to:"sep",type:"Sent plommon"}],tip:"Bästa testet: ta försiktigt i plommonet. Ger det efter lite och doftar sött? Då är det dags. Plommon som plockats för tidigt blir aldrig riktigt goda - de mognar inte efter som päron gör."},goodToKnow:[{icon:"warning",title:"Beskär ALDRIG plommon på vintern!",text:'Detta är den viktigaste regeln för plommon: beskär BARA under JAS-perioden (juli, augusti, september). Vinterbeskärning ger gummiflöde - trädet "blöder" klart, klibbigt harts från snitten. Snitten läker dåligt och svampinfektioner tar sig in.',severity:"warning"},{icon:"warning",title:"Stötta tunga grenar",text:"Plommonträd - särskilt Victoria - kan ge så riklig skörd att grenarna knäcks. Stötta tunga grenar med grenspjut eller Y-formade pinnar. Bättre att förebygga än att förlora en huvudgren.",severity:"warning"},{icon:"tip",title:"Självfertilt = du kan nöja dig med ETT träd",text:"De flesta svenska plommonsorter (Herman, Opal, Victoria, Jubileum, Reine Claude d'Oullins, Czar) är självfertila. Du kan alltså plantera bara ett enda träd och ändå få skörd. Men två sorter ger alltid bättre resultat.",severity:"tip"},{icon:"tip",title:"Rotskott - ta bort dem!",text:"Plommonträd bildar ofta rotskott som dyker upp runt trädet. De suger energi och ger aldrig bra frukt (de kommer från grundstammen). Ta bort dem genom att riva loss dem för hand tidigt på säsongen.",severity:"tip"},{icon:"tip",title:"Torka till katrinplommon",text:"Har du överskott? Halvera, kärna ur och torka i ugn (50°C, 8 timmar) eller frukttork. Hemgjorda katrinplommon/sviskon är på en helt annan nivå än köpepåsen. Perfekt vintersnacks.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Plommonträd planteras som ympade träd. Plantera gärna på sensommaren eller tidig höst för optimal etablering. Krukodlade kan planteras hela säsongen.",steps:["Gräv en grop dubbelt så bred som rotsystemet men lika djup","Slå ner en stödpåle INNAN du sätter trädet","Sätt trädet med ympstället 10 cm ovan mark","Fyll igen med uppgrävd jord blandat med kompost","Packa jorden försiktigt runt rötterna","Vattna rikligt - minst 20-30 liter","Bind stammen löst mot stödpålen","Mulcha en cirkel på 1 meters radie (inte intill stammen)"],tips:["Sensommar/höstplantering ger bäst etablering","St. Julien INRA är den vanligaste grundstammen för hobbyodlare - bra balans mellan storlek och härdighet","De flesta sorter är självfertila, men två sorter ger alltid bättre skörd","Välj plats utan frostficka - plommonblomning är ömtålig"],indoorWeeks:null},seedSaving:{difficulty:"Avancerad",type:"Ympning",biennial:!1,description:"Plommonträd förökas genom ympning på grundstam. Att så kärnor ger nya, unika träd med okända egenskaper - spännande experiment men ingen garanti för god frukt.",steps:["Samla ympkvistar i jan-feb (vilande, ettåriga skott)","Förvara i fuktig tidning i kylskåp till april","Välj grundstam (St. Julien INRA för medelstor, Pixy för dvärg)","Utför kopulationsympning eller ögonympning","Skydda ympstället med ympvax","Vänta 2-4 år på första skörd (snabbare än äpple/päron)"],isolation:"Ympning klonar sorten exakt - ingen korspollinering relevant.",storageYears:"Ympkvistar håller 2-3 månader i kylskåp",tip:"Plommon är enklare att ympa än äpple. Går du en ympkurs på våren kan du ofta ta med dig ympkvistar av kulturarvssorter som Experimentalfältsviskon och Ive hem."},storage:{shelfLife:"1 vecka (färsk) / 6+ mån (torkad/sylt)",methods:[{method:"Kylskåp (färsk)",icon:"snowflake",duration:"5-7 dagar",description:"Lägg plommon i grönsakslådan. Kort hållbarhet - svenska plommon har mjukt kött och skört skal. Ät dem snart!",best:!0},{method:"Torkning (katrinplommon)",icon:"sun",duration:"6+ månader",description:"Halvera, kärna ur och torka i ugn på 50°C i ca 8 timmar eller i frukttork. Hemgjorda katrinplommon/sviskon är fantastiskt goda.",best:!1},{method:"Sylt",icon:"storage",duration:"1+ år",description:"Koka plommonsylt med socker och citronjuice. Fyll på steriliserade burkar. En klassiker som fångar smaken av sensommaren.",best:!1},{method:"Frysning",icon:"snowflake",duration:"8-12 månader",description:"Halvera, kärna ur och frys i påsar. Fryses hela med kärna också, men halverade tinar bättre. Perfekt till pajer och smoothies.",best:!1},{method:"Saft",icon:"storage",duration:"6+ månader",description:"Koka sönder i saftsil, tillsätt socker. Plommonsaft är underbart och en bortglömd svensk klassiker.",best:!1}],tips:["Plommon har kort hållbarhet - planera vad du ska göra med skörden INNAN den kommer","Skörda på morgonen för bäst hållbarhet","Tunnväggiga sorter (Herman) håller sämre än tjockväggiga (Victoria)","Mogen frukt med vaxdagg intakt håller bäst - tvätta inte förrän du ska äta"]},harvestCalc:{minPerSqm:3,maxPerSqm:10,unit:"kg per träd (år 5+)"},pruning:{label:"Beskärning",types:{summer:{name:"JAS-beskärning (huvudbeskärning)",when:"Juli-augusti-september (ALDRIG vinter!)",description:'Plommon är "blödande växtslag" - snitt på vintern ger gummiflöde (klart harts som läcker ur snitten). Därför beskärs plommon BARA under JAS-perioden. Snitt som görs på sommaren läker snabbt och risken för svampinfektion är minimal.',steps:["Ta bort döda, sjuka och korsande grenar","Nyp av mjuka vattenskott (sommarpincering)","Glesa ur kronan för ljus och luftcirkulation","Ta bort rotskott - riv helst loss för hand","Stötta tunga grenar med grenspjut vid rik skörd","Rena, vassa verktyg - desinficera vid sjukdomsmisstanke"]},winter:{name:"Planteringsbeskärning (undantag)",when:"Vid plantering (vår)",description:"Det enda tillfället du beskär plommon utanför JAS: vid plantering. Spara 3-4 huvudgrenar och en toppskottsledare. Korta in till ca 30 cm. Detta balanserar rot och krona.",steps:["Välj 3-4 jämnt fördelade huvudgrenar","Korta in till ca 30 cm","Ta bort svaga och korsande grenar","Gör detta bara vid planteringstillfället"]}}},propagation:{difficulty:"Avancerad",methods:[{method:"Ympning",description:"En kvist från önskad sort fästs på en utvald grundstam (St. Julien INRA vanligast). Kopulationsympning på våren eller ögonympning i augusti. Plommon är enklare att ympa än äpple.",icon:"seedling"},{method:"Frösådd (experiment)",description:"Stratifiera kärnor i kylskåp 8-12 veckor, så i kruka. Ger ett unikt träd med okända egenskaper. Snabbare till skörd än äpple/päron (5-8 år). Spännande men oförutsägbart!",icon:"seed"}],tip:"Plommon ympar sig oväntat lätt jämfört med äpple. Ympkurser arrangeras av trädgårdsföreningar varje vår - ofta kan du få med dig ympkvistar av gamla kulturarvssorter hem."}},Fa=Object.freeze(Object.defineProperty({__proto__:null,plommon:$},Symbol.toStringTag,{value:"Module"})),rr={name:"Potatis",icon:"potatis",family:"Potatisväxter",familyLatin:"Solanaceae",difficulty:"Enkel",difficultyWhy:"Sätts direkt utomhus, tålig, kräver bara kupning och vattning. Svårt att misslyckas helt.",zones:{outdoor:[1,2,3,4,5,6,7],indoor:null,greenhouse:null},days:"60-120",spacing:"30-35 cm",rowSpacing:"60-70 cm",depth:"8-10 cm",ph:{min:5,max:6.5,ideal:5.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6-8 timmar sol per dag. Blasten behöver sol för att producera energi till knölarna. I skugga: mycket blast, små knölar."},temperature:{min:7,max:30,ideal:"15-20°C",detail:"Jorden bör vara minst 8°C vid sättning. Knölbildning bäst vid 15-18°C. Över 25°C minskar knölbildningen - potatisen 'vilar'."},wind:{level:"Tålig",detail:"Blasten är relativt tålig. Inga särskilda vindkrav. Höga kupor ger extra stabilitet."}},watering:{need:"Medel-Hög",icon:"water",summary:"Potatis behöver jämn fukt, speciellt under knölbildningen (blomning). Vattningsmomentet är det som avgör om du får en OK skörd eller en fantastisk skörd.",phases:[{phase:"Sättning till uppkomst",need:"Låg",tip:"Vattna vid sättning men sedan sparsamt. Jorden ska vara fuktig men inte blöt - för mycket vatten nu ger röta."},{phase:"Blasttillväxt",need:"Medel",tip:"Öka vattningen gradvis. Vattna vid basen, inte ovanifrån - det minskar risken för bladmögel."},{phase:"Blomning = knölbildning",need:"Hög",tip:"DEN viktigaste perioden! När potatisen blommar bildas knölarna. Jämn, riklig fukt nu ger fler och större knölar. Torka under blomningen kostar dig halva skörden."},{phase:"Mognad (efter blomning)",need:"Låg",tip:"Minska vattningen. Potatisen behöver 'härdas' med torrare jord. Sluta vattna helt 2 veckor före skörd."}],mistakes:["Vattna för mycket vid sättning - sättknölarna ruttnar innan de hinner gro","Torka under blomningen - den enskilt största orsaken till dålig skörd","Vattna ovanifrån sent på dagen - stående fukt på bladen = bladmögel","Fortsätta vattna ända fram till skörd - ger vattnig potatis som lagras dåligt"],tip:"Kolla jordfukten med fingret under blomningen. Stick ner 5 cm - känns det torrt, vattna direkt. Det här är veckan som avgör din skörd."},soil:"Lös, väldränerad jord. Potatis trivs bäst i lätt sur jord - hög pH ger skorv. Undvik nyligen kalkad jord.",soilTips:["Luckra djupt - kompakt jord ger små, missformade knölar","Blanda in brunnen kompost eller lövmull före plantering","Undvik kalk samma år - det ökar risken för skorv rejält"],timeline:{1:[{phase:"Förgro inomhus",months:"Mar",icon:"seedling"},{phase:"Sätt potatis",months:"Apr",icon:"seed"},{phase:"Kupa (1:a gången)",months:"Maj",icon:"hill"},{phase:"Kupa (2:a gången)",months:"Jun",icon:"hill"},{phase:"Tidig skörd (färskpotatis)",months:"Jun-Jul",icon:"harvest"},{phase:"Huvudskörd",months:"Aug-Sep",icon:"harvest"}],4:[{phase:"Förgro inomhus",months:"Apr",icon:"seedling"},{phase:"Sätt potatis",months:"Maj",icon:"seed"},{phase:"Kupa (1:a gången)",months:"Jun",icon:"hill"},{phase:"Kupa (2:a gången)",months:"Jul",icon:"hill"},{phase:"Tidig skörd",months:"Jul",icon:"harvest"},{phase:"Huvudskörd",months:"Aug-Sep",icon:"harvest"}],6:[{phase:"Förgro inomhus",months:"Apr-Maj",icon:"seedling"},{phase:"Sätt potatis",months:"Jun",icon:"seed"},{phase:"Kupa",months:"Jun-Jul",icon:"hill"},{phase:"Huvudskörd",months:"Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:15,P:15,K:10,label:"Förgroning"},{month:"Maj",N:60,P:30,K:20,label:"Uppkomst"},{month:"Jun",N:80,P:50,K:40,label:"Blasttillväxt"},{month:"Jul",N:40,P:75,K:70,label:"Knölbildning"},{month:"Aug",N:15,P:60,K:85,label:"Mognad"},{month:"Sep",N:5,P:30,K:60,label:"Skörd"}],nutritionTips:[{timing:"Före plantering",tip:"Mylla ner brunnen stallgödsel (2-4 kg/m²). Aldrig färsk gödsel - potatisen tar smak."},{timing:"Vid uppkomst (maj-juni)",tip:"Lätt kvävegiva om blasten är blek. Men var försiktig - för mycket kväve ger jätteblast och pytteknölar."},{timing:"Knölbildning (juli)",tip:"Kalium är nyckeln nu. Vedaska eller kaliumrik gödsel förbättrar skalkvalitet och lagring."},{timing:"Mognad (aug)",tip:"Sluta gödsla. Klipp av blasten 2-3 veckor före skörd så skalet härdas."}],companions:{good:[{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Fixerar kväve i jorden som potatisen drar nytta av"},{name:"Kål",icon:"vegetable",why:"Kompakt rotsystem som inte konkurrerar med potatisens djupa rötter"},{id:"ringblomma",name:"Ringblomma",icon:"flower",why:"Lockar nyttoinsekter och kan minska nematodtryck i jorden"},{name:"Pepparrot",icon:"herb",why:"Traditionell samodling - pepparroten har djupt rotsystem som luckrar jorden"}],bad:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Samma familj (potatisväxter) - delar bladmögel. En sjuk potatisplanta smittar tomaterna på dagar."},{id:"squash",name:"Squash",icon:"vegetable",why:"Konkurrerar hårt om näring och utrymme - båda är storätare"},{id:"solros",name:"Solros",icon:"flower",why:"Utsöndrar ämnen (allelopati) som hämmar potatisens tillväxt"}]},rotation:{avoid:[{id:"tomat",name:"Tomat"},{id:"paprika",name:"Paprika"},{name:"Aubergine"},{id:"chili",name:"Chili"},{id:"potatis",name:"Potatis"}],avoidWhy:"Alla potatisväxter - delar bladmögel, brunröta och nematoder. Vänta minst 3-4 år. Odla ALDRIG potatis på samma plats två år i rad.",goodBefore:[{name:"Baljväxter (ärtor, bönor)"},{name:"Gröngödsling"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter fixerar kväve. Gröngödsling förbättrar jordstrukturen - perfekt före potatis.",goodAfter:[{name:"Kål"},{id:"sallat",name:"Sallat"},{id:"morot",name:"Morötter"}],goodAfterWhy:"Potatisen lämnar efter sig en väl bearbetad, luckrad jord som rotgrönsaker och kål älskar."},varieties:[{name:"Solist",zones:[1,2,3,4,5,6],note:"Sveriges populäraste färskpotatis. Tidig, krämig, fantastisk."},{name:"King Edward",zones:[1,2,3,4,5,6],note:"Klassikern. Mjölig, perfekt för mos och bakning. Bra lagring. Sen sort - kräver lång säsong."},{name:"Mandel",zones:[1,2,3,4,5,6,7],note:"Norrlandsfavoriten. Fast, gul, otrolig smak. Lagrar utmärkt."},{name:"Asterix",zones:[1,2,3,4,5,6],note:"Rödskalig. Bra allround och fantastisk lagringspotatis."},{name:"Amandine",zones:[1,2,3,4,5],note:"Fransk gourmetpotatis. Fast, len, sjukt god. Motståndskraftig."}],problems:[{name:"Bladmögel (brunröta)",symptom:"Bruna fläckar på blad och stjälk, vit beläggning under bladen vid fukt",fix:"Kupa högt. Välj resistenta sorter. Klipp av blasten direkt vid angrepp och bränn den. Skörda minst 2 veckor efter blastklippning."},{name:"Skorv",symptom:"Bruna, korkliknande fläckar på skalet",fix:"Håll pH lågt (under 6). Kalka inte samma år. Vattna jämnt under knölbildning."},{name:"Nematoder (potatiscystnematod)",symptom:"Plantan gulnar och vissnar fläckvis i raden, dålig tillväxt, små knölar",fix:"Växtföljd (minst 4 år). Välj resistenta sorter. Undvik att flytta jord mellan odlingar."},{name:"Gröna knölar",symptom:"Grön missfärgning på potatisen",fix:"Kupa ordentligt! Grönt = solanin = giftigt. Ät aldrig grön potatis. Skala bort grönt eller kassera."}],goodToKnow:[{icon:"warning",title:"Grön potatis är giftig",text:"Gröna partier innehåller solanin - ett gift som inte försvinner vid kokning. Kupa ordentligt så att knölarna aldrig ser ljus. Ät aldrig potatis som är grön under skalet.",severity:"warning"},{icon:"warning",title:"Använd ALLTID sättpotatis",text:"Plantera aldrig matpotatis från affären. Sättpotatis är certifierad fri från sjukdomar. Matpotatis kan bära virus och bladmögel som sprids i din jord i åratal.",severity:"warning"},{icon:"hill",title:"Kupning är allt",text:"Kupa jord runt plantorna minst 2 gånger. Det skyddar mot ljus (gröna knölar), ökar skörden genom att ge mer utrymme för knölar, och förebygger bladmögel genom bättre dränering.",severity:"warning"},{icon:"leaf",title:"Klipp blasten - dubbel vinst",text:"Klipp av blasten 2-3 veckor före skörd. Det stoppar bladmögel från att sprida sig till knölarna OCH härdar skalet så potatisen lagras bättre.",severity:"tip"},{icon:"calendar",title:"Tidig vs sen - två helt olika grödor",text:"Färskpotatis (60 dagar, tunn skal, ät direkt) och lagringspotatis (100-120 dagar, tjockt skal) är nästan som att odla två olika saker. Bestäm i förväg vad du vill ha.",severity:"tip"},{icon:"harvest",title:"Fungerar i hink!",text:"Har du ingen trädgård? Potatis växer utmärkt i en stor hink, säck eller odlingslåda. 30 liter jord + 2 sättknölar = ca 2 kg potatis. Perfekt för balkong.",severity:"tip"}],sowing:{method:"direct",label:"Sättning (lägga sättpotatis)",description:"Potatis sås inte från frö - du planterar sättknölar (certifierad sättpotatis). Förgro dem först för snabbare start och bättre skörd.",steps:["Köp certifierad sättpotatis (ALDRIG matpotatis från butik)","Förgro 3-4 veckor före plantering: lägg i äggkartong, ljust och svalt (8-15°C) tills groddarna är 1-2 cm","Vänta tills jorden är minst 8°C - stick ner ett finger, det ska kännas behagligt","Gräv en fåra eller enskilda hål, 10-15 cm djupt","Lägg sättpotatisen med groddarna uppåt, 30-35 cm mellan varje","Täck med jord och vattna lätt","Kupa första gången när blasten är 15-20 cm hög - dra upp jord runt stjälkarna","Kupa igen 2-3 veckor senare - ju högre kulle, desto fler knölar"],tips:["Förgrodda knölar ger 2-3 veckors försprång - stor skillnad i norr","Sätt tidiga sorter (Solist, Rocket) först och sena sorter (King Edward) en vecka senare","I norr (zon 5+): använd fiberduk de första veckorna för extra värme"],indoorWeeks:"3-4 veckor förgroning"},seedSaving:{difficulty:"Enkel",type:"Knölförökning",biennial:!1,description:"Potatis förökas vegetativt - du sparar helt enkelt de bästa knölarna från skörden och planterar dem nästa år. Inget frö behövs!",steps:["Välj de friskaste plantorna under säsongen (markera med en pinne)","Vid skörd: spara medelstora, felfria knölar från de bästa plantorna","Låt knölarna torka i skugga en dag - aldrig i sol","Lagra separat från matpotatis i papperspåse eller nätpåse","Förvara mörkt, svalt (4-6°C) och frostfritt över vintern","Kontrollera med jämna mellanrum - ta bort knölar som mjuknar eller möglar","Förgro på våren precis som vanlig sättpotatis"],isolation:"Vegetativ förökning - ingen korspollinering att oroa sig för. Varje knöl är en genetisk klon av moderplantan.",storageYears:"1 år (nytt utsäde varje säsong)",tip:"OBS: Efter 2-3 år med eget utsäde byggs sjukdomar upp. Köp ny certifierad sättpotatis vart 2-3:e år för att bryta smittcykeln."},storage:{shelfLife:"4-8 månader",methods:[{method:"Mörk källare / jordkällare",icon:"cellar",duration:"6-8 månader",description:"Optimalt 4-6°C, mörkt och svalt med lite luftfuktighet. Förvara i trälåda, jutesäck eller papperskasse - aldrig i plast. Kolla med jämna mellanrum och ta bort knölar som börjar mjukna.",best:!0},{method:"Kupa och lämna i jorden",icon:"leaf",duration:"2-4 veckor efter blasten dör",description:"Klipp blasten och låt potatisen ligga kvar i jorden. Skalet härdas och lagringskvaliteten ökar. Men gräv upp före ihållande regn eller frost.",best:!1},{method:"Kylskåp (nödlösning)",icon:"snowflake",duration:"2-3 veckor",description:"Fungerar i nödfall men kylan omvandlar stärkelse till socker - potatisen blir söt och brunfärgas vid stekning. Lägg i papperspåse, aldrig plast.",best:!1},{method:"Frysa (tillagad)",icon:"snowflake",duration:"8-12 månader",description:"Koka eller blanchera först - rå potatis fryser dåligt. Mos, gratäng och klyftpotatis fryser utmärkt. Vakuumförpacka för bäst resultat.",best:!1}],tips:["ALDRIG i solljus - det ger gröna, giftiga knölar","Förvara aldrig med äpplen - etylen får potatisen att gro snabbare","Låt potatisen torka 1-2 timmar i skugga efter skörd innan du lagrar","Skadade knölar lagras dåligt - ät dem först eller skär bort skadan","Sen potatis (King Edward, Asterix) lagras MYCKET bättre än tidig (Solist)"]},harvestCalc:{minPerSqm:2,maxPerSqm:4,unit:"kg"}},Va=Object.freeze(Object.defineProperty({__proto__:null,potatis:rr},Symbol.toStringTag,{value:"Module"})),ar={name:"Pumpa",icon:"pumpa",family:"Gurkväxter",familyLatin:"Cucurbitaceae",difficulty:"Enkel",difficultyWhy:"Pumpa sköter sig i stort sett själv om hon bara får sol, vatten och näringsrik jord. Det svåraste är att ha tålamod - hon behöver lång tid att mogna.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:[1,2,3,4,5,6]},days:"90-130",spacing:"100-200 cm",rowSpacing:"200-300 cm",depth:"2-3 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 8 timmar sol per dag. Pumpa vill ha det varmt och soligt - i halvskugga får du massor av blad men knappt en enda frukt."},temperature:{min:10,max:35,ideal:"20-28°C",detail:"Pumpa är en riktig solälskare. Sätts aldrig ut innan nattfrosten är helt förbi och jorden är minst 15°C. Redan en enda frostnatt är dödlig."},wind:{level:"Skyddat",detail:"De enorma bladen fungerar som segel i vinden. Ett läge intill en husvägg, mur eller häck ger extra värme och skydd som pumpa älskar."}},watering:{need:"Hög",icon:"water",summary:"Pumpa är en törstig jätte med enorma blad som avdunstar massor av vatten. Under högsommar kan hon behöva rejäla givor varannan dag.",phases:[{phase:"Etablering (0-3 veckor)",need:"Medel",tip:"Vattna vid plantering och håll jorden jämnt fuktig. Låt rötterna få fotfäste i lugn och ro."},{phase:"Tillväxt (3-7 veckor)",need:"Hög",tip:"Nu exploderar tillväxten! Djupvattna 2-3 gånger i veckan. Rankor kan växa 10 cm per dag - det kräver vatten."},{phase:"Blomning och fruktsättning (7-10 veckor)",need:"Hög",tip:"Kritisk period! Utan vatten faller blommorna av och frukterna stannar i tillväxten. Vattna vid roten, aldrig på bladen."},{phase:"Mognad (10+ veckor)",need:"Medel",tip:"Minska vattningen de sista veckorna innan skörd. Det gör skalet hårdare och förbättrar lagringsförmågan."}],mistakes:["Vattnar på bladen istället för vid roten - bjuder in mjöldagg och svampsjukdomar","Vattnar lite och ofta istället för ordentligt och djupt","Glömmer att minska vattningen inför skörd - det förkortar lagringen","Ger för lite vatten under fruktsättning - frukterna blir små och missformade"],tip:"Gräv ner en kruka eller PET-flaska med hål i botten intill plantan och fyll med vatten - det levererar vattnet direkt till rötterna utan att blöta bladen."},soil:"Pumpa vill ha den rikaste jorden du kan erbjuda - djup, humusrik och väldränerad. Odla gärna direkt på komposthögen, hon ÄLSKAR det.",soilTips:["Gräv ner en rejäl laddning brunnen gödsel eller kompost - minst en skottkärra per 2-3 plantor",'Odla i en "pumpkulle" - en upphöjd bädd med kompost i botten som ger extra värme underifrån',"Mulcha runt plantan med halm eller gräsklipp - det håller fukten, värmen och håller frukterna rena"],timeline:{1:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj",icon:"plant"},{phase:"Blomning",months:"Jun-Jul",icon:"flower"},{phase:"Frukttillväxt",months:"Jul-Aug",icon:"growth"},{phase:"Skörd",months:"Sep-Okt",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Apr-Maj",icon:"seedling"},{phase:"Plantera ut",months:"Jun",icon:"plant"},{phase:"Blomning",months:"Jul",icon:"flower"},{phase:"Frukttillväxt",months:"Aug",icon:"growth"},{phase:"Skörd",months:"Sep",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Maj",icon:"seedling"},{phase:"Plantera ut (växthus)",months:"Jun",icon:"plant"},{phase:"Blomning",months:"Jul-Aug",icon:"flower"},{phase:"Skörd",months:"Sep",icon:"harvest"}]},nutritionData:[{month:"Maj",N:25,P:20,K:15,label:"Etablering"},{month:"Jun",N:65,P:30,K:20,label:"Tillväxt"},{month:"Jul",N:80,P:55,K:40,label:"Blomning"},{month:"Aug",N:45,P:70,K:65,label:"Fruktsättning"},{month:"Sep",N:15,P:45,K:55,label:"Mognad"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla rejält med brunnen kompost eller hästgödsel. Gräv ner det 30 cm djupt - pumpa vill ha en riktig näringsbomb under sig."},{timing:"Under tillväxt",tip:"Ge flytande gödsel varannan vecka - brännässelvatten eller alggödsel. Pumpa är en storätare som suger ur jorden snabbt."},{timing:"Under blomning",tip:"Skifta till fosfor- och kaliumrik gödsel. Benmjöl och vedaska stärker blomning och fruktsättning."},{timing:"Sen säsong",tip:"Sluta gödsla helt i september. Plantan ska lägga energin på att mogna frukterna, inte producera nya blad."}],companions:{good:[{id:"sockermajs",name:"Majs",icon:"vegetable",why:'Klassiska "Tre systrar" - majsen ger vertikalt stöd, bönor fixar kväve och pumpa skuggar marken'},{id:"artor",name:"Ärtor",icon:"vegetable",why:"Ärtorna fixar kväve i jorden som pumpa är så hungrig efter - ett perfekt par"},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Samma princip som ärtor - baljväxterna levererar gratis kväve till den hungriga pumpan"},{id:"radisa",name:"Rädisa",icon:"vegetable",why:"Snabb mellanskörd innan pumpans rankor breder ut sig och tar över all plats"}],bad:[{id:"potatis",name:"Potatis",icon:"potatis",why:"Båda är storväxare som konkurrerar om samma näring och utrymme - ingen av dem blir nöjd"},{id:"squash",name:"Squash",icon:"squash",why:"Samma familj - delar sjukdomar som mjöldagg och kan korspollera (vilket ger konstiga frön)"},{id:"gurka",name:"Gurka",icon:"gurka",why:"Samma familj - sprider sjukdomar och skadedjur sinsemellan"}]},rotation:{avoid:[{id:"squash",name:"Squash"},{id:"gurka",name:"Gurka"},{id:"melon",name:"Melon"}],avoidWhy:"Alla gurkväxter delar sjukdomar som mjöldagg, fusarium och visnesjuka. Vänta minst 3-4 år innan du odlar gurkväxter på samma plats.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{name:"Gröngödsling"}],goodBeforeWhy:"Baljväxter och gröngödsling bygger upp kväveförrådet i jorden som pumpa sedan tacksamt suger ur.",goodAfter:[{id:"lok",name:"Lök"},{id:"morot",name:"Morot"},{id:"rodbeta",name:"Rödbeta"}],goodAfterWhy:"Lättfödda rotgrönsaker trivs efter pumpa som har luckrat och gödslat jorden grundligt."},varieties:[{name:"Uchiki Kuri",zones:[1,2,3,4,5],note:"Japansk hokkaido-pumpa (OP, C. maxima). Nötig, söt smak och kompakt storlek. Skalet går att äta!"},{name:"Atlantic Giant",zones:[1,2,3],note:"OP-jättepumpa (C. maxima) för tävlingar och skryt. Kan bli hundratals kilo. Inte den godaste - men vilken show!"},{name:"Jack O'Lantern",zones:[1,2,3,4],note:"Klassisk OP-halloweenpumpa (C. pepo). Orange, rund och perfekt att göra lykta av. Köttet funkar i soppa."},{name:"Muscade de Provence",zones:[1,2,3,4],note:"Vacker, räfflad OP-myskpumpa (C. moschata). Djupt orange kött med fantastisk smak till soppa och gratäng."},{name:"Gold Nugget",zones:[1,2,3,4,5],note:"Kompakt, tidig OP-sort (C. maxima, finns hos Runåbergs). Mognar snabbt, perfekt för kortare säsonger."}],problems:[{name:"Mjöldagg",symptom:"Vitt, pudrigt belägg på bladen, börjar ofta i slutet av säsongen",fix:"Vattna vid roten, aldrig på bladen. God luftcirkulation runt plantorna. Drabbade blad kan klippas bort - plantan överlever det."},{name:"Dålig pollinering",symptom:"Frukten börjar växa men gulnar, skrumpnar och faller av",fix:"Handpollera med en mjuk pensel - för pollen från hanblomman (lång rak stjälk) till honblomman (liten frukt vid basen). Gör det tidigt på morgonen."},{name:"Frukten ruttnar",symptom:"Frukten som ligger på marken blir mjuk undertill",fix:"Lägg en bräda, halm eller en tegelsten under varje frukt så den inte ligger direkt på fuktig jord. Speciellt viktigt i regniga perioder."},{name:"Sniglar",symptom:"Stora hål i blad och unga frukter, slemspår",fix:"Snigelkorn (järnfosfat), ölsaxar eller kopparhinder runt plantorna. Vattna på morgonen så marken hinner torka till kvällen."}],goodToKnow:[{icon:"warning",title:"Kräver PLATS",text:"En enda pumpaplanta kan breda ut sig flera meter åt alla håll. Planera minst 3-4 kvadratmeter per planta, eller led rankorna utmed ett staket.",severity:"warning"},{icon:"harvest",title:"Lagras i månader",text:"Vinterpumpor som Uchiki Kuri och Muscat de Provence håller 3-6 månader i rumstemperatur efter härdning. Perfekt mat hela vintern!",severity:"tip"},{icon:"warning",title:"Korspollinering",text:"Pumpa, squash och zucchini i samma art (t.ex. Cucurbita maxima) kan korsa sig. Köttet påverkas inte i år, men fröna ger oförutsägbara resultat nästa år.",severity:"warning"},{icon:"flower",title:"Blommorna är ätbara",text:"Hanblommorna (de utan liten frukt vid basen) kan plockas, fyllas med ost och friteras. Italiens bäst bevarade hemlighet!",severity:"tip"},{icon:"leaf",title:"Härda efter skörd",text:"Lägg vinterpumpor i solen 7-10 dagar efter skörd. Skalet hårdnar, små sår läker och hållbarheten förlängs rejält.",severity:"tip"},{icon:"warning",title:"Frost dödar omedelbart",text:"Pumpablad kollapsar vid minsta frost. Skörda ALLA frukter innan första frostnatt - även omogna frukter kan eftermogna inomhus.",severity:"warning"}],sowing:{method:"both",label:"Direktsådd eller förodling",description:"Förodling inomhus rekommenderas i de flesta zoner - pumpa behöver lång tid att mogna. I zon 1-2 kan du direktså utomhus i juni, men förodling ger alltid försprång.",steps:["Så 2-3 frön per kruka, 2-3 cm djupt, i stor kruka (minst 8 cm)","Håll varmt (20-25°C) - fröna gror på 5-10 dagar","Gallra till en planta per kruka när de fått första riktiga bladen","Härda av i en vecka genom att ställa ut dagtid, ta in på natten","Plantera ut när natttemperaturen stadigt håller sig över 10°C och all frostrisk är förbi","Ge MASSOR av plats - minst 100 cm mellan plantorna, gärna mer för storfruktig pumpa","Vattna ordentligt vid plantering och mulcha runt plantan med halm"],tips:["Så inte för tidigt inomhus - 3-4 veckor räcker. Pumpplantor växer snabbt och blir långa och rangliga i fönstret.","Blötlägg fröna 12-24 timmar innan sådd - det snabbar på groningen rejält",'Odla gärna i en "pumpkulle" - upphöjd bädd med kompost under som ger extra värme och näring underifrån'],indoorWeeks:"3-4 veckor"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!1,description:"Pumpa korspolleras av insekter inom samma art. Odlar du flera sorter av samma art (t.ex. två C. maxima) så korsar de sig.",steps:["Välj en fin, typisk frukt från den starkaste plantan","Låt frukten ligga kvar på plantan tills den är helt mogen - skalet ska vara hårt och stjälken börjat torka","Lagra frukten ytterligare 2-3 veckor inomhus efter skörd så fröna mognar klart","Skär upp pumpan och skrapa ut fröna med en sked","Skölj bort allt fruktkött i en sil under rinnande vatten","Lägg fröna i en skål med vatten - de som sjunker är bra, de som flyter är tomma","Torka fröna på tidningspapper i ett torrt rum i 2-3 veckor","Förvara torrt och svalt i papperspåse eller glasburk"],isolation:"Korspollinerare via insekter. Odla bara en sort per art (C. maxima, C. moschata, C. pepo) för rent frö, eller handpollera och tejpa igen blommorna.",storageYears:"4-6 år",tip:"Pumpafrön håller sig länge! Alla rekommenderade sorter ovan är öppenpollinerade och perfekta för fröbesparing."},storage:{shelfLife:"2-6 månader (beroende på sort)",methods:[{method:"Torr lagring i rumstemperatur",icon:"storage",duration:"3-6 månader",description:"Vinterpumpor lagras bäst i ett torrt, svalt rum (10-15°C). Härda dem i solen en vecka efter skörd först. Kontrollera regelbundet och ät de mjuka först.",best:!0},{method:"Kylskåp (uppskuren)",icon:"snowflake",duration:"5-7 dagar",description:"Uppskuren pumpa i plastfolie eller låda med lock i kylskåp. Använd inom en vecka. Skär bort märg och frön först.",best:!1},{method:"Frysa (tillagad)",icon:"snowflake",duration:"8-12 månader",description:"Skala, skär i bitar och koka eller ugnsrosta. Mosa eller frys i bitar. Perfekt för soppor, pajer och gratänger.",best:!1},{method:"Puré att frysa",icon:"snowflake",duration:"6-10 månader",description:"Ugnsrosta pumpan, mosa till puré och frys i portionspåsar. Redo att använda direkt i soppa, bröd eller bakverk.",best:!1}],tips:["Härda vinterpumpor i solen 7-10 dagar efter skörd - det gör skalet hårdare och förlänger hållbarheten enormt","Förvara aldrig vinterpumpa i kylskåp - kylan ger svampangrepp och förkortar hållbarheten","Lämna alltid 5-10 cm stjälk kvar vid skörd - utan stjälk ruttnar pumpan snabbt","Kontrollera lagrade pumpor varannan vecka - en rutten pumpa smittar snabbt de andra","Sommarpumpor (som Jack O'Lantern) lagras kortare än vinterpumpor (som Uchiki Kuri)"]},harvestCalc:{minPerSqm:2,maxPerSqm:6,unit:"kg"}},La=Object.freeze(Object.defineProperty({__proto__:null,pumpa:ar},Symbol.toStringTag,{value:"Module"})),er={name:"Purjolök",icon:"purjolok",family:"Lökväxter",familyLatin:"Amaryllidaceae",difficulty:"Medel",difficultyWhy:"Purjolöken kräver tålamod - hon har en lång odlingssäsong och vill bli kupad regelbundet för att utveckla sin fina vita stam. Men hon belönar dig med en fantastisk gröda som tål frost och till och med kan övervintras i mildare zoner.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:[1,2,3,4,5,6,7]},days:"120-180",spacing:"15-20 cm",rowSpacing:"30-40 cm",depth:"1-2 cm",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Full sol - halvskugga",icon:"sun",detail:"Purjolöken trivs bäst i full sol med minst 6 timmars direkt solljus, men klarar faktiskt halvskugga bättre än de flesta lökväxter. I skugga blir stammarna tunnare och slankare, men hon ger fortfarande skörd."},temperature:{min:-10,max:30,ideal:"13-24°C",detail:"Purjolöken är en tuff dam - hon tål frost ner till -10°C och kan stå kvar i marken långt in på vintern. Trivs bäst i svalare temperaturer och slutar inte växa bara för att hösten kommer."},wind:{level:"Skyddat",detail:"De höga bladen kan piska sönder i hård vind. Ett lite skyddat läge hjälper, men hon klarar sig om det inte blåser konstant."}},watering:{need:"Medel",icon:"water",summary:'Purjolöken vill ha jämn fukt genom hela sin långa odlingssäsong. Hon är inte lika känslig som vanlig lök, men torka gör henne seg och bitter. Tänk "konstant men inte dränkt".',phases:[{phase:"Förodling (0-8 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig i krukor och brätten. Plantorna är tunna som grässtrån och torkar ut snabbt om du glömmer dem."},{phase:"Etablering (utplantering + 3 veckor)",need:"Hög",tip:"Vattna ordentligt vid utplantering och håll jorden fuktig tills plantorna rotat sig. Nu lägger hon grunden - ge henne en bra start."},{phase:"Tillväxt (juni-september)",need:"Medel",tip:"Jämn fukt, gärna med mulch runt plantorna. Vattna djupt en gång i veckan om det inte regnar. Kupningen hjälper faktiskt till att hålla fukten."},{phase:"Höst/vinter",need:"Låg",tip:"Naturen sköter sig själv nu. Vattna bara vid lång torka under tidighösten. Purjolöken tar det lugnt och mognar sakta."}],mistakes:["Låta den torka ut under etableringen - tunna plantor som precis planterats ut klarar inte torka","Vattna ovanifrån så vatten samlas i bladverket - det kan ge röta, speciellt sent på säsongen","Glömma bort vattningen mitt i sommaren - purjolöken ser tålig ut men blir seg och bitter utan vatten"],tip:"Mulcha ordentligt runt plantorna med gräsklipp eller halm. Det håller fukten jämn, minskar ogräs OCH gör kupningen enklare."},soil:"Purjolöken vill ha djup, näringsrik, lucker jord. Hon skickar rötter djupt ner och behöver jord som inte packar sig - gärna med gott om kompost inblandad.",soilTips:["Gräv djupt och blanda in rikligt med brunnen kompost - purjolöken är en storätare","Om du har lerjord, blanda i sand och kompost för att få den lucker och luftig","Undvik nygödslad jord med färsk stallgödsel - det lockar lökfluga","En upphöjd bädd funkar utmärkt och gör kupningen enklare"],timeline:{1:[{phase:"Förodling inomhus",months:"Feb-Mar",icon:"seedling"},{phase:"Utplantering",months:"Maj",icon:"plant"},{phase:"Kupning (2-3 ggr)",months:"Jun-Aug",icon:"leaf"},{phase:"Skörd",months:"Sep-Nov",icon:"harvest"},{phase:"Övervintring möjlig",months:"Dec-Feb",icon:"snowflake"}],4:[{phase:"Förodling inomhus",months:"Mar",icon:"seedling"},{phase:"Utplantering",months:"Maj-Jun",icon:"plant"},{phase:"Kupning (2-3 ggr)",months:"Jul-Sep",icon:"leaf"},{phase:"Skörd",months:"Okt-Nov",icon:"harvest"}],6:[{phase:"Förodling inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Utplantering",months:"Jun",icon:"plant"},{phase:"Kupning (2 ggr)",months:"Jul-Sep",icon:"leaf"},{phase:"Skörd",months:"Sep-Okt",icon:"harvest"}]},nutritionData:[{month:"Mar",N:15,P:10,K:10,label:"Förodling"},{month:"Apr",N:25,P:15,K:15,label:"Tillväxt inne"},{month:"Maj",N:40,P:25,K:20,label:"Utplantering"},{month:"Jun",N:70,P:30,K:30,label:"Tillväxt"},{month:"Jul",N:80,P:35,K:40,label:"Intensiv tillväxt"},{month:"Aug",N:65,P:40,K:50,label:"Stambildning"},{month:"Sep",N:40,P:35,K:60,label:"Mognad"},{month:"Okt",N:15,P:20,K:45,label:"Skörd"}],nutritionTips:[{timing:"Vid utplantering",tip:"Grundgödsla med väl brunnen kompost. Lägg gärna lite benmjöl i botten av planteringsgropen - purjolöken behöver fosfor för att bygga starka rötter."},{timing:"Juni-juli",tip:"Ge flytande gödsel (t.ex. nässelvatten) varannan vecka. Nu bygger hon bladverk som en tokig och behöver kväve."},{timing:"Vid kupning",tip:"Strö lite vedaska runt plantorna innan du kupar. Kaliumet hjälper stammen att bli fast och fin."},{timing:"Sensommar",tip:"Sluta gödsla med kväve senast i augusti. Purjolöken behöver härdas inför vintern, inte pusha ny tillväxt."}],companions:{good:[{id:"morot",name:"Morot",icon:"vegetable",why:"Purjolökens starka doft skrämmer bort morotsflugan, och moroten håller lökflugan på avstånd. Klassiskt samarbete!"},{id:"selleri",name:"Selleri",icon:"vegetable",why:"Sellerins starka doft förvirrar skadedjur som söker purjolök. De trivs dessutom i liknande fuktiga förhållanden."},{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Purjolökens doft skyddar jordgubbarna mot gråmögel - samma trick som vanlig lök använder."},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Sallaten fyller ut marken mellan purjolöksraderna och skördas långt innan purjolöken behöver platsen."}],bad:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Lökväxter hämmar baljväxters tillväxt och kvävefixering. De pratar helt enkelt olika språk."},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Samma problem som med ärtor - purjolöken och baljväxter trivs inte ihop."}]},rotation:{avoid:[{id:"lok",name:"Lök"},{id:"vitlok",name:"Vitlök"},{id:"schalottenlok",name:"Schalottenlök"},{id:"graslok",name:"Gräslök"}],avoidWhy:"Alla lökväxter (Amaryllidaceae) delar sjukdomar som purjolöksrost och lökfluga. Vänta minst 4 år innan du odlar purjolök på samma plats igen.",goodBefore:[{name:"Kål"},{id:"squash",name:"Squash"},{id:"potatis",name:"Potatis"}],goodBeforeWhy:"Näringskrävande grödor som kål och squash mår bra av den kompostrika jord som purjolöken lämnar efter sig.",goodAfter:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"morot",name:"Morot"}],goodAfterWhy:"Baljväxter bygger upp kvävet i jorden igen efter purjolökens tunga näringsuttag. Morötter har helt andra sjukdomar och trivs i den luckra jorden."},varieties:[{name:"Musselburgh",zones:[1,2,3,4,5,6],note:"Brittisk OP-klassiker som klarar svensk vinter. Kraftig stam och mild, fin smak. Tålig och pålitlig."},{name:"Hannibal",zones:[1,2,3,4,5],note:"Tidig OP-sort med extra tjock, vit stam. Bra val om du vill skörda redan i september-oktober."},{name:"Blauwgroene Winter",zones:[1,2,3,4,5,6],note:"Vinterhärdig OP-favorit med blågröna blad. Kan stå kvar i marken ända till våren i mildare zoner."},{name:"Carentan 3",zones:[1,2,3,4,5],note:"Klassisk fransk OP-sort med kort, tjock stam. Utmärkt smak och bra frosttålighet."},{name:"Elefant",zones:[1,2,3,4,5,6,7],note:"Svensk OP-favorit som är anpassad till nordiska förhållanden. Kraftig och härdig - klarar även zon 7 i skyddat läge."}],problems:[{name:"Purjolöksrost",symptom:"Orange-rostfärgade prickar och ränder på bladen, speciellt sent på säsongen. Plantorna ser fula ut men lever vidare.",fix:"Ta bort angripna blad direkt. Bra luftcirkulation (inte för tätt!) hjälper. Växtföljd är viktigast - minst 4 år mellan lökväxter på samma plats."},{name:"Lökfluga",symptom:"Plantorna gulnar och slaknar. Larver i basen av stammen som äter sig inåt. Luktar illa.",fix:"Täck med fiberduk från maj till midsommar. Samodla med morot. Strö kalkstenmjöl vid basen av plantorna."},{name:"Purjolöksmal",symptom:"Ljusa gångar (minor) i bladen där larverna äter sig fram. Bladen kan bli fula och missformade.",fix:"Finmaskigt insektsnät är bästa skyddet. Plocka bort och förstör angripna blad. Undvik att plantera nära annan lök."}],goodToKnow:[{icon:"warning",title:"Kupning är nyckeln!",text:"Purjolöken kupas (jord dras upp runt stammen) 2-3 gånger under säsongen. Det är kupningen som ger den fina vita delen - utan den blir det mest grönt och segt.",severity:"warning"},{icon:"seedling",title:"Förodling krävs i Sverige",text:"Med 120-180 dagar till skörd hinner purjolöken inte om du direktsår utomhus i de flesta zoner. Starta inomhus i februari-mars, annars blir det knappt något att skörda.",severity:"warning"},{icon:"snowflake",title:"Tål frost - skörda sent!",text:"Purjolöken är en av de mest frosttåliga grödorna. I zon 1-3 kan hon stå kvar i marken hela vintern under ett lager löv eller halm. Smaken blir faktiskt mildare och finare efter frost.",severity:"tip"},{icon:"leaf",title:"Plantera djupt i gropar",text:"En smart metod: gör 15 cm djupa hål med en käpp, släpp ner plantan och fyll bara med vatten (inte jord). Jorden fyller på sig naturligt och du slipper kupa lika mycket.",severity:"tip"},{icon:"harvest",title:"Det gröna är också ätbart",text:"Släng inte det gröna! De mörkgröna bladen är segare men perfekta i buljong, soppor och grytor. Allt utom de allra yttersta torra bladen kan användas.",severity:"tip"},{icon:"warning",title:"Se upp med jord mellan bladen",text:"Vid kupning kan jord hamna mellan bladlagren. Skölj noga före tillagning - det finns inget jobbigare än sandiga purjolöksringar.",severity:"warning"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Purjolöken har en lång odlingssäsong och måste förodlas inomhus i Sverige. Med tidig start i februari-mars hinner hon bli tjock och fin till hösten.",steps:["Så frön 1-2 cm djupt i krukor eller brätten, gärna tätt (1 cm mellanrum)","Håll jämnt fuktigt och varmt (18-22°C) - fröna gror på 10-14 dagar","Ställ ljust så snart groddarna visar sig - de sträcker sig annars och blir rangliga","Klipp av topparna till ca 10 cm höjd när de blir långa - det stärker plantorna och gör dem tjockare","Härda av plantorna 1-2 veckor före utplantering genom att ställa ut dem dagtid","Plantera ut när plantorna är ca 15-20 cm höga och ungefär lika tjocka som en blyertspenna","Plantera djupt! Gör 15 cm djupa hål, släpp ner plantan och vattna ordentligt"],tips:["Klipp topparna flera gånger under förodlingen - varje klippning gör stammen tjockare","Plantera gärna i djupa gropar istället för att kupa - enklare och ger lika bra resultat","Purjolöksplantor är tåliga - om de ser lite risiga ut vid utplantering, oroa dig inte. De repar sig snabbt."],indoorWeeks:"10-12 veckor"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Purjolöken är tvåårig - första året äter du henne, andra året blommar hon. Du måste överväntra plantor i marken (eller gräva upp och lagra dem) för att få frö.",steps:["Välj ut 3-5 fina, friska plantor vid skörd och lämna dem i marken","Täck med ett tjockt lager halm eller löv före vintern i kallare zoner","Våren efter skjuter purjolöken en hög blomstjälk (kan bli över en meter!)","En stor, rund blomkula bildas i toppen med hundratals små blommor","Bin och humlor pollinerar blommorna under sommaren","Låt frökapsarna mogna och torka på plantan - de ska vara bruna och torra","Klipp av hela blomhuvudet och torka inomhus i en papperspåse","Skaka och gnugga försiktigt för att få loss de små, svarta fröna"],isolation:"Korsar med andra purjolökssorter men INTE med vanlig lök. Isolera minst 1 km mellan sorter eller odla bara en sort för frö.",storageYears:"2-3 år",tip:"Purjolöksfrö håller sig lite längre än vanligt lökfrö men tappar grobarhet med tiden. Friskast möjliga frö ger bäst resultat."},storage:{shelfLife:"2-4 månader",methods:[{method:"Stå kvar i marken",icon:"leaf",duration:"3-5 månader",description:"Den absolut bästa lagringsmetoden! Låt purjolöken stå kvar i bädden och skörda efter behov. Täck med halm eller löv i kallare zoner. Fräschare och godare än all annan lagring.",best:!0},{method:"Kylskåp",icon:"snowflake",duration:"2-4 veckor",description:"Skördad purjolök håller sig bra i kylskåpets grönsakslåda. Slå in i en fuktig handduk eller lägg i en plastpåse med hål.",best:!1},{method:"Frysa (strimlad)",icon:"snowflake",duration:"8-12 månader",description:"Strimla och frys in i portionspåsar. Perfekt för soppor och grytor - behöver inte tinas innan den hamnar i kastrullen.",best:!1},{method:"Torka",icon:"sun",duration:"12+ månader",description:"Strimla tunt och torka i ugn på 55°C eller torkautomat. Inte lika gott som färsk men funkar i soppor och kryddblandningar.",best:!1}],tips:["Purjolök i marken med ett lager halm kan klara ner till -15°C i skyddat läge","Skörda INTE all purjolök samtidigt - ta vad du behöver och låt resten stå","Rensa bort de yttersta bladen och skölj noga - jord mellan lagren är vanligt efter kupning","Fryst purjolök tappar lite textur men smaken är kvar - bäst i varma rätter"]},harvestCalc:{minPerSqm:2,maxPerSqm:4,unit:"kg"}},Aa=Object.freeze(Object.defineProperty({__proto__:null,purjolok:er},Symbol.toStringTag,{value:"Module"})),tr={name:"Rabarber",icon:"rabarber",category:"frukt",family:"Slideväxter",familyLatin:"Polygonaceae",perennial:!0,lifespan:"15-30+ år",difficulty:"Enkel",difficultyWhy:"En av de mest tacksamma perenner du kan odla. Planterar du en gång och ger henne mat och vatten belönar hon dig med skörd i decennier. Kräver minimalt underhåll.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:null},days:"Skörd år 2-3",spacing:"100 cm",rowSpacing:"100-150 cm",depth:"Sätt kronan 5 cm under jordytan",ph:{min:5.5,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Trivs bäst i sol men klarar halvskugga utmärkt - stjälkarna blir bara lite tunnare. I södra Sverige uppskattar hon faktiskt lite eftermiddagsskugga under riktigt varma veckor."},temperature:{min:-30,max:30,ideal:"12-20°C",detail:"En riktig nordbo som älskar kyla! Rabarbern BEHÖVER vintervila med ordentlig frost för att samla kraft till nästa säsong. Trivs bäst i sval svensk sommar - vid 25°C+ börjar hon stressa och skjuta i blom."},wind:{level:"Tålig",detail:"De stora bladen kan visserligen ta stryk i riktigt kraftig blåst, men generellt är rabarber en tålig växt som klarar de flesta lägen."}},watering:{need:"Medel-Hög",icon:"water",summary:"Rabarber är törstigare än man tror. De stora bladen avdunstar mycket vatten, och torkstress ger tunna, sega stjälkar. Jämn fukt under hela växtsäsongen är nyckeln till tjocka, saftiga stjälkar.",phases:[{phase:"Vår (utbrytning)",need:"Hög",tip:"Nu drar hon igång på allvar! Vattna rikligt när de första skotten bryter igenom - hon är hungrig och törstig efter vintersömnen."},{phase:"Skörd (maj-juni)",need:"Hög",tip:"Kritisk period! Vattenstress nu ger tunna, sega stjälkar som inte smakar lika bra. Vattna djupt 2-3 gånger i veckan vid torka."},{phase:"Sommar (efter skörd)",need:"Medel",tip:"Sluta skörda i midsommar och låt bladen arbeta. Fortsätt vattna men inte lika intensivt - hon behöver bygga upp energi till nästa år."},{phase:"Höst",need:"Låg",tip:"Minska vattningen gradvis. Bladen gulnar och hon förbereder sig för vintersömnen."}],mistakes:["Vattnar för lite under vårens tillväxtfas - ger tunna, torra stjälkar","Glömmer att nyplanterad rabarber behöver extra vatten första året","Vattnar inte alls efter skördestopp - hon behöver fukt för att bygga reserver","Vattnar ovanifrån och blöter ner kronan - kan ge röta"],tip:"Mulcha tjockt runt plantan med kompost eller gräsklipp. Det håller fukten, matar henne och sparar dig massor med vattnande. Bara se till att inte lägga mulchen rakt på kronan."},soil:"Rabarber vill ha djup, näringsrik jord med god dränering. Hon är en storätare som tackar ja till all näring du kan ge henne - kompost, brunnen gödsel, det mesta funkar.",soilTips:["Gräv djupt (40-50 cm) och blanda in rikligt med kompost och brunnen gödsel vid plantering - hon stannar länge!","Mulcha årligen med kompost på hösten - det är hennes favoritmåltid","Undvik vattensjuk mark - rabarberkronan kan ruttna om den står blöt","Förbättra lerjord med sand och kompost, men rabarber klarar faktiskt de flesta jordtyper"],timeline:{1:[{phase:"Plantering",months:"Mars-april",icon:"seedling"},{phase:"Skörd",months:"Maj-midsommar",icon:"harvest"},{phase:"Vila (bladen jobbar)",months:"Juli-sept",icon:"leaf"},{phase:"Gödsling",months:"Oktober",icon:"soil"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}],4:[{phase:"Plantering",months:"April-maj",icon:"seedling"},{phase:"Skörd",months:"Maj-midsommar",icon:"harvest"},{phase:"Vila (bladen jobbar)",months:"Juli-sept",icon:"leaf"},{phase:"Gödsling",months:"September-oktober",icon:"soil"},{phase:"Vintervila",months:"Nov-april",icon:"snowflake"}],6:[{phase:"Plantering",months:"Maj-juni",icon:"seedling"},{phase:"Skörd",months:"Juni-juli",icon:"harvest"},{phase:"Vila (bladen jobbar)",months:"Aug-sept",icon:"leaf"},{phase:"Gödsling",months:"September",icon:"soil"},{phase:"Vintervila",months:"Okt-maj",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:7,P:3,K:3,label:"Vårstart"},{month:"Maj",N:8,P:5,K:5,label:"Full tillväxt"},{month:"Jun",N:6,P:4,K:6,label:"Skördetid"},{month:"Jul",N:4,P:3,K:5,label:"Reservuppbyggnad"},{month:"Aug",N:2,P:3,K:4,label:"Avmattning"},{month:"Sep",N:1,P:2,K:3,label:"Inför vila"}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge en rejäl giva brunnen gödsel eller kompost runt plantan innan skotten bryter fram. Rabarber är en riktig storätare och tackar med tjockare stjälkar."},{timing:"Efter skörd (midsommar)",tip:"En giva kompost eller flytande gödsel hjälper henne att bygga upp reserver inför nästa år. Tänk på det som en tack-för-maten-present."},{timing:"Höst (oktober)",tip:"Lägg ett tjockt lager brunnen gödsel eller kompost som vintermulch. Det bryts ner under vintern och ger en perfekt vårstart."},{timing:"Undvik",tip:"Ge aldrig färsk gödsel direkt på kronan - det bränner. Och sluta gödsla med kvävericht efter midsommar, hon ska förbereda sig för vila."}],companions:{good:[{id:"hallon",name:"Hallon",icon:"berry",why:"Rabarber skuggar marken runt hallonen, behåller fukt och de konkurrerar inte om samma näring. Ett klassiskt par i svenska trädgårdar."},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Baljväxter fixerar kväve i jorden som rabarbern gärna tar del av. Plantera bondbönor på lagom avstånd."},{id:"lok",name:"Lök",icon:"vegetable",why:"Löken avskräcker skadedjur med sin starka doft, och tar inte upp mycket plats bredvid rabarberns stora blad."}],bad:[{name:"Dockblad",icon:"vegetable",why:"Nära släkting (samma familj). Kan sprida sjukdomar mellan sig och konkurrerar om samma näring."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Rabarberns stora blad skuggar tomaterna som behöver full sol. Tomaterna förlorar i den matchen."}]},rotation:{avoid:[{id:"rabarber",name:"Rabarber"},{name:"Dockblad"}],avoidWhy:"Rabarber är långliggare (10-15+ år) och suger ur jorden ordentligt. Plantera aldrig ny rabarber direkt efter gammal - vänta minst 5 år och berika jorden rejält först.",goodBefore:[{name:"Gräsmatta"},{name:"Baljväxter"},{name:"Gröngödsling"}],goodBeforeWhy:"Mark som legat som gräsmatta eller odlats med kvävefixerare ger frisk, näringsrik jord - precis vad rabarbern vill ha som startplats.",goodAfter:[{name:"Gröngödsling"},{id:"bondbona",name:"Bondböna"},{id:"artor",name:"Ärtor"}],goodAfterWhy:"Efter 10-15 år med rabarber är jorden utarmad. Gröngödsling och baljväxter bygger upp den igen. Ge jorden minst 2-3 år att återhämta sig."},varieties:[{name:"Victoria",zones:[1,2,3,4,5,6,7],note:"Sveriges klassiker sedan 1800-talet. Grönröda stjälkar, syrlig god smak. Finns i var och varannan gammal trädgård. Kan odlas från frö. Extremt härdig. Blommar gärna - bryt blomstänglarna."},{name:"Glaskins Perpetual",zones:[1,2,3,4,5],note:"Engelskt kulturarv (1920). Mörkröda stjälkar med låg oxalsyra och mild smak. Kan ge liten skörd redan första året från frö! Ekologiskt frö hos Runåbergs."},{name:"Barbro",zones:[1,2,3,4],note:"Svensk sort från SLU Balsgård (2012). Grönröd med fin smak och låg oxalsyra. God sjukdomsresistens. Kompakt - passar i kruka."},{name:"Canada Red",zones:[1,2,3,4,5],note:"Klarröd rakt igenom - den vackraste sorten. Låg oxalsyra, syrlig god smak, få blomstänglar. Sen sort med hög skörd."},{name:"Elmsblitz",zones:[1,2,3,4,5,6,7],note:"Tysk sort med vinröda stjälkar och mycket låg oxalsyra. Mild, nästan söt smak. Extremt härdig. Blommar gärna."},{name:"Timperley Early",zones:[1,2,3,4],note:'Tidigast av alla - perfekt för drivning under hink/rabarberklocka. Grönröda stjälkar, mild smak. Utmärkt "glasrabarber".'},{name:"Champagne Red",zones:[1,2,3,4,5,6,7],note:"Långa, smala, röda stjälkar (70-80 cm). Utmärkt syrlig-söt smak och få blommor. Extremt härdig."}],problems:[{name:"Kronröta",symptom:"Plantan vissnar, kronan blir mjuk och brunaktig med dålig lukt. Ofta efter en blöt vinter.",fix:"Förebygg med god dränering. Lägg aldrig mulch direkt på kronan. Drabbade plantor - gräv upp och byt jord. Plantera nytt på annan plats."},{name:"Sniglar",symptom:"Stora hål i bladen, speciellt på unga skott. Sniglarna äter sig igenom bladen nattetid och trivs i den fuktiga miljön under rabarberbuskens stora blad.",fix:"Snigelgel (järnfosfat) runt plantan. Ölburksfällor. Håll marken fri från gömslen. De stora rabarbersbladen fungerar tyvärr som perfekta snigelgömställen - var extra vaksam vid fuktig väderlek."},{name:"Bladfläcksjuka",symptom:"Bruna eller rödaktiga fläckar på bladen som kan växa samman. Oftast vid fuktig väderlek.",fix:"Ta bort angripna blad. Se till att plantan har god luftcirkulation. Undvik att vattna ovanifrån."},{name:"Blommstjälkar",symptom:"Tjocka blomstjälkar skjuter upp mitt i plantan och tar energi från stjälkproduktionen.",fix:"Bryt av blomstjälkarna så fort du ser dem - vrid och dra i basen. Det är inget sjukdomstecken, bara plantans sätt att försöka föröka sig."}],goodToKnow:[{icon:"warning",title:"Bladen är giftiga!",text:"Rabarberbladens höga halt av oxalsyra gör dem giftiga att äta. Bara stjälkarna ska skördas. Bladen är dock utmärkta i komposten.",severity:"warning"},{icon:"warning",title:"Skörda INTE första året",text:"Nya plantor behöver bygga upp kraftiga rötter. Skörda inte alls år 1, bara lite år 2, och full skörd från år 3. Tålamod belönas med en buske som ger i decennier!",severity:"warning"},{icon:"warning",title:"Sluta skörda runt midsommar",text:"Midsommarregeln handlar inte om gift utan om energi - plantan behöver stjälkarna för att lagra näring i rotstocken inför nästa år. Skördar du hela sommaren svälter du ut henne. Oxalsyran ökar lite mot säsongens slut, men stjälkarna är inte farliga.",severity:"warning"},{icon:"tip",title:"Drivning - tidig skörd",text:"Ställ en upp-och-nervänd hink eller rabarberdrivare över plantan i mars. Mörkret gör att stjälkarna sträcker sig och blir extra milda och rosa. Drivna stjälkar i april är en delikatess!",severity:"tip"},{icon:"tip",title:"Dela plantan vart 15:e år",text:"Rabarber kan stå på samma plats i decennier, men när stjälkarna blir tunnare och färre är det dags att dela. Gräv upp, dela med en vass spade (varje del ska ha 2-3 skott) och plantera om med ny kompost. Tidig vår är bästa tiden.",severity:"tip"},{icon:"tip",title:"Grönsak eller frukt?",text:"Botaniskt är rabarber en grönsak - det är bladskaften vi äter. Men i köket behandlas den som frukt: paj, kräm, saft, sylt. I USA klassificerades rabarber juridiskt som frukt redan 1947. Vi håller med kockarna - rabarber hör hemma bland frukterna!",severity:"tip"},{icon:"tip",title:"Frosten gör susen",text:"Rabarber BEHÖVER vinterfrost för att bryta sin vila. Det är därför hon trivs så bra i Sverige! Utan ordentlig kyla blir skörden sämre nästa år.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Rabarber planteras som rotdelar (kronor) eller krukodlade plantor. Frösådd är möjlig men tar längre tid och ger mer variabla resultat. Köp hellre en namnsort som rotdel.",steps:["Gräv en grop 40-50 cm djup och lika bred","Blanda in rikligt med brunnen gödsel och kompost i botten","Placera kronan så att ögonen (knopparna) sitter 5 cm under jordytan","Fyll igen och tryck till jorden ordentligt","Vattna rikligt - hon är törstig efter flytten","Mulcha runt plantan (inte på kronan!) med bark eller halm"],tips:["Plantera på hösten om möjligt - ger bäst etablering","Ge varje planta ordentligt med plats (minst 1 meter) - hon blir stor!","Motstå frestelsen att skörda första året - det lönar sig i längden","Skörda genom att vrida och dra stjälken vid basen - använd aldrig kniv"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Rabarber förökas bäst genom delning av etablerade plantor. Det ger exakta kopior av moderplantan och är mycket enklare än frösådd.",steps:["Välj en frisk, produktiv planta som är minst 4-5 år gammal","Gräv upp hela kronan på hösten eller tidig vår","Dela med en vass spade i 3-4 delar - varje del ska ha minst 2-3 ögon (knoppar)","Låt snittytorna torka några timmar","Plantera delarna direkt på nya platser med riklig kompost","Vattna ordentligt och mulcha"],isolation:"Vegetativ förökning - kloner av moderplantan. Ingen korspollinering relevant.",storageYears:"Ej tillämpligt",tip:"Dela gärna med grannar och vänner - en rabarberplanta ger enkelt 3-4 nya vid delning. Frösådd fungerar men ger plantor som kan variera i kvalitet och färg."},storage:{shelfLife:"1-2 veckor (färsk)",methods:[{method:"Frysning",icon:"snowflake",duration:"10-12 månader",description:"Det bästa sättet att bevara rabarber. Skär i 2-3 cm bitar, lägg på plåt och frys. Flytta sedan till påsar. Perfekt till paj och kompott hela vintern.",best:!0},{method:"Kompott/mos",icon:"storage",duration:"1+ år (fryst) / 1 vecka (kylskåp)",description:"Koka stjälkarna med lite socker till mjuka. Fantastiskt på gröt, pannkakor eller som dessert. Fryser utmärkt i portioner.",best:!1},{method:"Sylt",icon:"storage",duration:"1+ år",description:"Rabarbersylt med vanilj eller ingefära - en klassiker. Rabarberns naturliga syra balanserar sockret perfekt.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"1-2 veckor",description:"Linda stjälkarna i en fuktig handduk och lägg i plastpåse i kylskåpet. Skär inte i bitar förrän du ska använda dem.",best:!1},{method:"Saft",icon:"storage",duration:"6+ månader",description:"Rabarbersaft är sommar på flaska. Koka med socker och vatten, sila och häll upp. Fantastisk att blanda med jordgubbssaft!",best:!1}],tips:["Frys i portionspåsar (3-4 dl per påse) - perfekt till en paj","Rabarbern behöver inte skalas, bara sköljas","Kombinera med jordgubbar i allt - de är ett drömpar"]},harvestCalc:{minPerSqm:2,maxPerSqm:5,unit:"kg"}},Ha=Object.freeze(Object.defineProperty({__proto__:null,rabarber:tr},Symbol.toStringTag,{value:"Module"})),nr={name:"Rädisa",icon:"radisa",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Enkel",difficultyWhy:"Odlingens sprinterkung - 3 veckor från frö till skörd! Perfekt första gröda.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:null},days:"22-35",spacing:"3-5 cm",rowSpacing:"15-20 cm",depth:"1 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Trivs i sol men klarar halvskugga galant. I halvskugga tar det några dagar extra, men rädisan blir mildare i smaken."},temperature:{min:5,max:25,ideal:"12-18°C",detail:"Gror redan vid 5°C - en av de första du kan så på våren! Över 25°C skjuter hon snabbt i blom och blir vedartad och bitter. Trivs bäst i svalt vårväder."},wind:{level:"Tålig",detail:"Låg profil och snabb tillväxt - vind är inget problem."}},watering:{need:"Medel",icon:"water",summary:"Jämn fukt är nyckeln. Rädisan växer så snabbt att ojämn bevattning märks direkt - antingen spricker hon eller blir trådrig.",phases:[{phase:"Groning (0-1 vecka)",need:"Hög",tip:"Håll jorden jämnt fuktig - fröet måste ha fukt för att gro. Rädisan gror på 3-7 dagar om det är tillräckligt varmt och fuktigt."},{phase:"Tillväxt (1-3 veckor)",need:"Medel",tip:"Vattna 2-3 gånger i veckan om det inte regnar. Jämn fukt ger milda, krispiga rädisor. Torka ger trådiga, skarpa rädisor."},{phase:"Rotsvällning (3-4 veckor)",need:"Medel",tip:"Sluta inte vattna nu! Det är här rädisan sväller till och blir fin. Ojämn fukt ger spruckna rötter."}],mistakes:["Ojämn vattning (torrt-blött-torrt) ger spruckna rädisor","För lite vatten ger trådiga, vedartade rädisor med skarp smak","För mycket vatten ger vattniga rädisor utan sting"],tip:"Rädisan är så snabb att det knappt hinns mulcha - men en tunn strimma gräsklipp håller fukten de första veckorna."},soil:"Lucker, väldränerad jord. Rädisor är inte kräviga - nästan vilken jord som helst funkar bara den inte är kompakt.",soilTips:["Luckra de översta 15 cm - rädisan behöver inte djupt","Undvik klumpig lerjord - rädisan får svårt att svälla","Lite kompost räcker gott - övergödsla inte"],timeline:{1:[{phase:"Direktså 1:a omgången",months:"Mar-Apr",icon:"seedling"},{phase:"Skörd 1:a omgången",months:"Apr-Maj",icon:"harvest"},{phase:"Direktså 2:a omgången",months:"Maj",icon:"seedling"},{phase:"Skörd 2:a omgången",months:"Jun",icon:"harvest"},{phase:"Direktså höstsådd",months:"Aug",icon:"seedling"},{phase:"Skörd höstsådd",months:"Sep",icon:"harvest"}],4:[{phase:"Direktså 1:a omgången",months:"Apr",icon:"seedling"},{phase:"Skörd 1:a omgången",months:"Maj",icon:"harvest"},{phase:"Direktså 2:a omgången",months:"Maj-Jun",icon:"seedling"},{phase:"Skörd 2:a omgången",months:"Jun-Jul",icon:"harvest"},{phase:"Direktså höstsådd",months:"Aug",icon:"seedling"},{phase:"Skörd höstsådd",months:"Sep",icon:"harvest"}],6:[{phase:"Direktså 1:a omgången",months:"Maj",icon:"seedling"},{phase:"Skörd 1:a omgången",months:"Jun",icon:"harvest"},{phase:"Direktså 2:a omgången",months:"Jun-Jul",icon:"seedling"},{phase:"Skörd 2:a omgången",months:"Jul-Aug",icon:"harvest"},{phase:"Direktså höstsådd",months:"Jul-Aug",icon:"seedling"},{phase:"Skörd höstsådd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:15,P:10,K:10,label:"Sådd"},{month:"Maj",N:30,P:20,K:25,label:"Tillväxt"},{month:"Jun",N:20,P:30,K:40,label:"Rotsvällning"},{month:"Jul",N:10,P:20,K:30,label:"Skörd"}],nutritionTips:[{timing:"Vid sådd",tip:"Grundgödsla med brunnen kompost. Rädisan är inte krävig - för mycket kväve ger bara blast utan rot."},{timing:"Under tillväxt",tip:"Ingen extra gödsling behövs för vanliga rädisor. De växer så snabbt att näring i jorden räcker."},{timing:"Rotsvällning",tip:"Lite kalium (vedaska) kan ge krispigare rädisor, men är inget krav."}],companions:{good:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Perfekt mellanskörd - så rädisor mellan ärtraderna, skörda innan ärtorna tar över"},{id:"morot",name:"Morot",icon:"vegetable",why:"Rädisan markerar morotsraden (som gror långsamt) och skördas innan moroten behöver platsen"},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Samma snabba tempo - trivs ihop utan att konkurrera"}],bad:[{id:"gronkal",name:"Grönkål",icon:"vegetable",why:"Samma familj (korsblommiga) - delar skadedjur och sjukdomar"},{id:"broccoli",name:"Broccoli",icon:"vegetable",why:"Samma familj - ökar risk för kålfluga och klumprotsjuka"},{id:"blomkal",name:"Blomkål",icon:"vegetable",why:"Samma familj - samma problem som med broccoli"}]},rotation:{avoid:[{id:"gronkal",name:"Grönkål"},{id:"broccoli",name:"Broccoli"},{id:"blomkal",name:"Blomkål"},{id:"vitkal",name:"Vitkål"},{id:"rodkal",name:"Rödkål"},{id:"kalrabbi",name:"Kålrabbi"}],avoidWhy:"Alla tillhör korsblommiga - delar klumprotsjuka och jordloppa. Vänta minst 3 år.",goodBefore:[{id:"tomat",name:"Tomat"},{id:"squash",name:"Squash"},{id:"sallat",name:"Sallat"}],goodBeforeWhy:"Rädisan är så snabb att hon knappt hinner påverka jorden. Perfekt förfrukt till nästan vad som helst.",goodAfter:[{name:"Baljväxter (ärtor, bönor)"},{id:"lok",name:"Lök"},{id:"morot",name:"Morot"}],goodAfterWhy:"Nästan allt funkar efter rädisa - hon tar så lite näring att jorden knappt märkte att hon var där."},varieties:[{name:"Cherry Belle",zones:[1,2,3,4,5,6,7,8],note:"Klassisk rund, röd OP-sort. Pålitlig och snabb - redo på 22-25 dagar."},{name:"French Breakfast",zones:[1,2,3,4,5,6,7,8],note:"Avlång kulturarvssort (OP), röd med vit spets. Mildare smak än runda sorter."},{name:"Saxa 2",zones:[1,2,3,4,5,6,7,8],note:"Rund, klarröd OP-sort som mognar snabbt och jämnt. Populär i svenska frökataloger."},{name:"Plum Purple",zones:[1,2,3,4,5,6,7,8],note:"Rund, lila OP-sort med mild smak och krispig textur. Vacker färg i salladen."}],problems:[{name:"Jordloppan",symptom:"Små hål i bladen, plantor äts upp",fix:"Fiberduk direkt vid sådd. Håll jorden fuktig - jordloppan avskyr fukt."},{name:"Vedartad/trådig",symptom:"Hård, trådig konsistens",fix:"Skörda i tid! Väntar du en dag för länge blir hon vedartad. Jämn fukt hjälper också."},{name:"Skjuter i blom",symptom:"Blomstjälk istället för rot",fix:"För varmt eller för långa dagar. Så tidigt på våren eller sent på hösten. Undvik midsommar."},{name:"Klumprotsjuka",symptom:"Deformerade, svullna rötter",fix:"Kalka jorden om pH är lågt. Växtföljd med minst 3 års uppehåll från korsblommiga."}],goodToKnow:[{icon:"harvest",title:"Snabbast från frö till tallrik",text:"Rädisan är odlingens sprinter - 20 till 30 dagar från sådd till skörd. Perfekt för otåliga barn (och vuxna) som inte vill vänta.",severity:"tip"},{icon:"warning",title:"Väntar du för länge är det för sent",text:"En dag för lång i jorden och rädisan går från krispig till vedartad och bitter. Känn på henne - är hon större än en golfboll är det dags. Hellre för tidig än för sen.",severity:"warning"},{icon:"seedling",title:"Så var 14:e dag för skörd hela säsongen",text:"Nyckeln till rädisor hela sommaren är successionssådd. Så en liten rad varannan vecka från april till september (pausa i värsta värmen i juli).",severity:"tip"},{icon:"leaf",title:"Perfekt luckvaktare",text:"Så rädisor mellan långsammare grödor som morot eller lök. Rädisan markerar raden, skördas innan grannarna behöver platsen, och luckrar jorden på köpet.",severity:"tip"},{icon:"sun",title:"Undvik hetta - hon skjuter i blom",text:"Rädisan är en svalväxtare. Över 25°C och med långa ljusa dagar skjuter hon rakt upp i blom istället för att göra rot. Så tidigt på våren eller på hösten för bäst resultat.",severity:"warning"}],sowing:{method:"direct",label:"Direktsådd",description:"Rädisan sås alltid direkt på friland. Hon avskyr att bli omflyttad och är så snabb att förodling är meningslös.",steps:["Dra ett grunt spår (ca 1 cm djupt) med en pinne","Så fröna glest - helst 2-3 cm mellanrum direkt","Täck med ett tunt lager jord och tryck till lätt","Vattna försiktigt med stril","Gallra till 3-5 cm om det blivit för tätt"],tips:["Så lite och ofta - en kort rad varannan vecka ger skörd hela säsongen","Blanda rädisfrö med morotsfrö - rädisan markerar raden och skördas före moroten","Fiberduk direkt vid sådd skyddar mot jordloppan"],indoorWeeks:null},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!1,description:"Rädisan är ettårig för frösparing - låt några plantor stå kvar så skjuter de blomstjälk samma säsongen. Lätt att spara frö om du bara odlar en sort.",steps:["Välj de finaste plantorna och låt dem stå kvar i jorden","Rädisan skjuter blomstjälk efter några veckor","Vita eller lila blommor pollineras av insekter","Låt skidorna (fröbaljorna) mogna på plantan tills de börjar bli bruna","Klipp av hela stjälken och torka inomhus","Gnugga loss fröna ur skidorna","Förvara torrt och svalt"],isolation:"Korsar med andra rädissorter och vild rättika. Odla bara en sort för frö, eller isolera med 500 m.",storageYears:"3-5 år",tip:"Rädisfrö håller sig väldigt bra - upp till 5 år om det förvaras torrt och svalt."},storage:{shelfLife:"1-2 veckor",methods:[{method:"Kylskåp",icon:"snowflake",duration:"1-2 veckor",description:"Klipp av blasten direkt (den suger fukt). Lägg i en plastpåse med några hål eller i en skål med fuktigt hushållspapper. Rädisan håller sig krispig ungefär en vecka.",best:!0},{method:"I vatten",icon:"water",duration:"3-5 dagar",description:"Ställ rädisorna i ett glas kallt vatten i kylskåpet. Håller dem extra krispiga men de tappar lite smak efter några dagar.",best:!1},{method:"Inlagda",icon:"storage",duration:"2-3 månader",description:"Skiva rädisorna tunt och lägg in i ättika med lite socker och salt. Fantastiskt på smörgåsen eller till asiatisk mat.",best:!1}],tips:["Skörda på morgonen för krispigast resultat","Ta bort blasten direkt - den suger fukt ur roten","Slappa rädisor kan räddas genom att stå i isvatten en timme","Rädisan är bäst färsk - planera att äta henne inom några dagar"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3,unit:"kg"}},Ga=Object.freeze(Object.defineProperty({__proto__:null,radisa:nr},Symbol.toStringTag,{value:"Module"})),ir={name:"Ramslök",icon:"ramslok",category:"kryddor",family:"Lökväxter",familyLatin:"Amaryllidaceae",perennial:!0,lifespan:"20+ år (sprider sig sakta)",difficulty:"Enkel",difficultyWhy:"Ramslök är en av de mest lättskötta kryddväxterna du kan ha i trädgården. Väl etablerad sköter hon sig helt själv - sprider sig, kommer tillbaka varje vår och kräver nästan ingen skötsel alls. Det enda som kräver tålamod är att få igång henne från frö, men köper du lökar är du igång direkt.",zones:{outdoor:[1,2,3,4,5,6],indoor:[1,2,3,4,5,6,7,8],greenhouse:null},days:"Lökar: skörd första våren. Frö: 2-3 år till etablerad skörd",spacing:"10-15 cm",rowSpacing:"20-30 cm",depth:"5-10 cm",depthNote:"Lökar. Frö: ytså",ph:{min:5.5,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Halvskugga",icon:"partial-sun",detail:"Ramslök är en lundväxt som trivs allra bäst i halvskugga till skugga - under lövträd är perfekt. Hon klarar full sol på våren men vill ha skugga under sommaren. Tänk skogsgolv: sol genom nakna grenar på våren, sedan svalka under lövverket."},temperature:{min:-30,max:25,ideal:"5-18°C",detail:"En riktig vårväxt som älskar svalka! Ramslök vaknar tidigt på våren när det fortfarande är kallt och gör sitt livsverk innan sommarvärmen slår till. När temperaturen stiger över 20°C börjar hon gå i vila. Extremt frosttålig - lökarna övervintrar i marken utan problem."},wind:{level:"Skyddat",detail:"Trivs bäst i skyddade lägen, precis som i sin naturliga lundmiljö. De breda, tunna bladen torkar ut i stark vind. Under buskar eller träd, vid en skuggig husvägg - där mår hon som bäst."}},watering:{need:"Medel",icon:"water",summary:"Ramslök vill ha jämn fukt under våren när hon växer aktivt, men under sommaren när hon vilar spelar det ingen roll - då sover lökarna tryggt i jorden.",phases:[{phase:"Tidig vår (uppvaknande)",need:"Medel",tip:"Håll jorden jämnt fuktig när de första bladen tittar upp. Mulcha gärna med löv så håller fukten sig naturligt."},{phase:"Tillväxt och skörd (april-maj)",need:"Medel",tip:"Fortsätt med jämn fukt. Torr jord nu ger tunna, sega blad med sämre smak. Vattna på morgonen vid torrt väder."},{phase:"Blomning (maj-juni)",need:"Låg",tip:"Nu börjar hon stänga ner butiken. Minska vattningen gradvis - hon förbereder sig för sommarvila."},{phase:"Sommarvila (juli-februari)",need:"Låg",tip:"Lökarna vilar i jorden och klarar sig utmärkt på egen hand. Ingen extra vattning behövs."}],mistakes:["Vattnar för mycket under sommaren - lökarna vilar och kan ruttna i blöt jord","Glömmer fukt på våren - de tunna bladen torkar ut snabbt i torr mark","Planterar i stående vatten - ramslök vill ha fuktigt men aldrig vattensjukt"],tip:"Mulcha med ett tjockt lager löv på hösten - precis som i skogen. Det håller fukten, ger näring och efterliknar hennes naturliga miljö."},soil:"Mullrik, humusrik jord som håller fukt men inte är vattensjuk. Tänk skogsgolv - den mörka, lucker jorden under lövträd är precis vad ramslök drömmer om.",soilTips:["Blanda in rikligt med kompost och lövmull - det skapar den humusrika jord ramslök älskar","Lite kalk eller vedaska om jorden är sur - ramslök trivs bättre i neutral till svagt kalkhaltig jord","Undvik tung, kompakt lera - blanda i sand och kompost för bättre struktur","Låt nedfallna löv ligga kvar som naturlig mulch - det är precis så det fungerar i skogen"],timeline:{1:[{phase:"Plantera lökar",months:"Sep-okt / mar",icon:"seed"},{phase:"Tillväxt",months:"Mar-apr",icon:"seedling"},{phase:"Skörd (blad)",months:"Mar-maj",icon:"harvest"},{phase:"Blomning",months:"Maj",icon:"flower"},{phase:"Frötagning",months:"Jun-jul",icon:"seed"},{phase:"Sommarvila",months:"Jun-feb",icon:"dormant"}],4:[{phase:"Plantera lökar",months:"Sep-okt / apr",icon:"seed"},{phase:"Tillväxt",months:"Apr-maj",icon:"seedling"},{phase:"Skörd (blad)",months:"Apr-jun",icon:"harvest"},{phase:"Blomning",months:"Maj-jun",icon:"flower"},{phase:"Frötagning",months:"Jul",icon:"seed"},{phase:"Sommarvila",months:"Jul-mar",icon:"dormant"}],6:[{phase:"Plantera lökar",months:"Sep / maj",icon:"seed"},{phase:"Tillväxt",months:"Maj",icon:"seedling"},{phase:"Skörd (blad)",months:"Maj-jun",icon:"harvest"},{phase:"Blomning",months:"Jun",icon:"flower"},{phase:"Sommarvila",months:"Jul-apr",icon:"dormant"}]},nutritionData:[{month:"Mar",N:3,P:2,K:2},{month:"Apr",N:5,P:3,K:3},{month:"Maj",N:4,P:3,K:4},{month:"Jun",N:2,P:1,K:2},{month:"Jul",N:0,P:0,K:0},{month:"Aug",N:0,P:0,K:0}],nutritionTips:[{timing:"Tidig vår",tip:"Strö lite kompost eller välbrunnen gödsel runt plantorna när de första bladen syns. Ramslök har modest näringsbehov men uppskattar en vårgåva."},{timing:"Höstmulch",tip:"Låt löv och trädgårdsavfall ligga kvar som naturlig mulch över vintern. Det ger långsam näring precis som i skogen - den bästa gödseln för ramslök."},{timing:"Obs!",tip:"Aldrig kraftig mineralgödsel! Ramslök är en skogsväxt som trivs med naturlig, långsam näring. Kompost och lövmull är allt hon behöver."}],companions:{good:[{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Ramslöks vitlöksdoft avskräcker bladlöss och skadedjur. Dessutom trivs båda under buskar och träd i halvskugga."},{id:"morot",name:"Morot",icon:"vegetable",why:"Alliumdoften förvirrar morotsflugan som navigerar efter lukt. En klassisk och beprövad kombination."},{id:"rodbeta",name:"Rödbeta",icon:"vegetable",why:"Bra näringskomplement - ramslök och rödbeta har olika rotdjup och konkurrerar inte om samma resurser."}],bad:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Alliumväxter hämmar baljväxters tillväxt genom naturliga ämnen de utsöndrar i jorden. Håll dem isär!"},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Samma problem som med ärtor - alliumväxter och baljväxter talar inte samma språk."}]},rotation:{avoid:[{id:"lok",name:"Lök"},{id:"vitlok",name:"Vitlök"},{id:"purjolok",name:"Purjolök"},{id:"graslok",name:"Gräslök"}],avoidWhy:"Lökväxter (Amaryllidaceae) delar skadedjur och jordburna sjukdomar. Vänta 3-4 år innan du planterar annan lök på samma plats. Men i praktiken: ramslök är en permanent plantering som stannar på sin plats i årtionden.",goodBefore:[{name:"Baljväxter"},{name:"Bladgrönsaker"}],goodBeforeWhy:"Ramslök lämnar mullrik, väl genomrotad jord som baljväxter och bladgrönsaker uppskattar.",goodAfter:[{id:"morot",name:"Morot"},{id:"sallat",name:"Sallat"}],goodAfterWhy:"Alliumväxternas naturliga ämnen i jorden har mild sanerande effekt som gynnar efterföljande grödor."},varieties:[{name:"Ramslök (Allium ursinum)",zones:[1,2,3,4,5,6],note:"Vildarten - det enda som finns att köpa. Växer vild i södra Sverige upp till Uppland, men kan odlas i skyddade, skuggiga lägen upp till zon 6. Ekologiskt frö hos Runåbergs och Impecta. Lökar från specialistodlare. 100% öppenpollinerad vildväxt. OP."}],problems:[{name:"Invasiv spridning",symptom:"Ramslök sprider sig villigt via både frö och lökdelning. Efter några år kan du ha en hel matta.",fix:"Begränsa med kantband eller odla i ett avgränsat område. Eller njut av det - en hel ramslöksmatta på våren är magisk!"},{name:"Sniglar",symptom:"Tuggade bladkanter, speciellt på unga blad i fuktig väderlek. Slimstigar synliga.",fix:"Snigelfällor med öl, manuell plockning på kvällen, eller strö krossade äggskal runt plantorna."},{name:"Dålig grobarhet från frö",symptom:"Fröna gror inte alls eller bara sporadiskt trots rätt förhållanden.",fix:"Ramslöksfrö är notoriskt oberäkneligt. Använd alltid färskt frö, ge kall stratifiering (4-8 veckor i kylskåp) och ha tålamod. Eller ta genvägen - köp lökar istället!"}],goodToKnow:[{icon:"warning",title:"Livsfarlig förväxling!",text:"Ramslöksblad liknar liljekonvaljens och tidlösans - båda GIFTIGA! Skillnaden: ramslök luktar ALLTID vitlök när du gnuggar bladet. Luktar det inte vitlök - ät det inte. Odlar du själv vet du vad du har, men var extra försiktig vid plockning i naturen.",severity:"warning"},{icon:"warning",title:"Frö kräver tålamod",text:"Att dra upp ramslök från frö tar 2-3 år innan du har skördbar plantering. Fröna behöver kall stratifiering och groning är oberäknelig. Köp lökar om du vill komma igång snabbt.",severity:"warning"},{icon:"tip",title:"Vårens första skörd",text:"Ramslök är en av de allra första ätbara växterna på våren. Redan i mars-april, när trädgården annars ligger öde, bjuder hon på fräscha, vitlöksdoftande blad. Vårens gröna guld!",severity:"tip"},{icon:"tip",title:"Allt är ätbart",text:'Inte bara bladen! Blomknopparna kan syras in som "ramslökskapris", blommorna är dekorativa i sallad, och till och med lökarna smakar som mild vitlök (men skörda löken sparsamnt - det dödar plantan).',severity:"tip"},{icon:"tip",title:"Naturens egen vitlök",text:'Ramslök har använts som mat och medicin i tusentals år. Björnens favorit efter vinterdvalan (latinska artnamnet "ursinum" betyder just björnens). Rik på C-vitamin, järn och naturliga antibiotikaämnen.',severity:"tip"},{icon:"tip",title:"Skörda hållbart",text:"Ta aldrig alla blad från en planta - lämna alltid minst hälften så hon kan fylla på lökens energireserver inför nästa år. Från en etablerad koloni kan du skörda rikligt ändå.",severity:"tip"}],sowing:{method:"both",label:"Lökplantering eller frösådd",description:"Lökar är absolut enklast och ger skörd redan första våren. Frösådd funkar men kräver tålamod - groningen är långsam och oberäknelig, och det tar 2-3 år till ordentlig skörd. Välj lökar om du kan!",steps:["LÖKAR (rekommenderat): Plantera på hösten (sep-okt) eller tidig vår. Sätt lökarna 5-10 cm djupt med 10-15 cm mellanrum","Välj en halvskuggig plats med mullrik jord - under lövträd eller buskar är perfekt","Vattna efter plantering och mulcha med ett lager löv","FRÖ: Så färskt frö direkt utomhus på hösten för naturlig stratifiering över vintern","Alternativt: lägg fröna i fuktig sand i kylskåp i 4-8 veckor, så sedan i krukor på våren","Ytså - täck bara med ett tunt lager grus eller perlit, fröna behöver lite ljus","Ha tålamod - groningen kan ta allt från 1 månad till ett helt år!"],tips:["Köp lökar från en specialistodlare för snabbaste resultat - du kan skörda redan nästa vår","Använd alltid färskt frö om du sår - ramslöksfrö tappar grobarhet mycket snabbt","Låt de första årens plantor etablera sig utan skörd så bygger de upp en stark koloni"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Korspollinerare",biennial:!1,description:"Ramslök producerar rikligt med frö i sina vita blomställningar. Låt blommorna utvecklas och vänta tills frökapsarna torkat och spruckit upp - de små, svarta, runda fröna faller ut naturligt.",steps:["Låt ett antal plantor blomma ut helt (skörda inte alla blad från dessa)","Vänta tills frökapsarna torkat och blivit bruna (juni-juli)","Klipp av blomstjälkarna och lägg i en papperspåse","Skaka påsen försiktigt - fröna trillar ut","Så fröna så snart som möjligt - de tappar grobarhet snabbt!","Bäst: så direkt utomhus på hösten för naturlig stratifiering"],isolation:"Inget korsningsproblem i praktiken - det finns inga andra ramslöksorter att korsa med. Ren vildart.",storageYears:"Max 1 år (helst så färskt frö direkt)",tip:"Det enklaste sättet att föröka ramslök? Låt henne självsåda! Eller dela lökklumpar på hösten - mycket enklare och säkrare än frö."},storage:{shelfLife:"Färsk 3-7 dagar, fryst 6-10 månader",methods:[{method:"Pesto (bäst!)",icon:"storage",duration:"Fryst 6+ månader",description:"Mixa bladen med olivolja och lite salt till en pesto. Frys i isbitsformar - perfekta portioner att slänga i pastan, soppan eller smöret. Den godaste konserveringsmetoden!",best:!0},{method:"Frysning",icon:"snowflake",duration:"6-10 månader",description:"Bred ut hela eller hackade blad i fryspåsar. Använd direkt från frysen - ingen upptining behövs. Konsistensen blir mjuk men smaken bevaras fint.",best:!1},{method:"Färsk i vatten",icon:"water",duration:"3-7 dagar",description:"Ställ bladbuketten i ett glas vatten i kylen, som en bukett. Byt vatten varannan dag. Använd helst inom några dagar - ramslök är bäst superfärsk.",best:!1},{method:"Torkning",icon:"storage",duration:"6-12 månader",description:"Torka i ugn på 40°C eller lufttorka. Fungerar men en del av den fina aromen försvinner. Krossa de torra bladen och förvara i glasburk.",best:!1}],tips:["Ramslökspesto med parmesan, pinjenötter och olivolja - frys i isbitsformar för hela årets behov","Ramslökssmör: blanda finhackade blad i rumsvarmt smör, rulla i plastfolie och frys","Skörda på morgonen för bäst smak och hållbarhet","Bladen vissnar snabbt - processa eller ät dem samma dag du skördar"]},harvestCalc:{minPerSqm:.1,maxPerSqm:.3,unit:"kg"},harvest:{label:"Skörd och användning",method:"Plocka enskilda blad, lämna alltid minst hälften kvar",description:"Skörda ramslöksblad från tidig vår till början av blomningen - det är då smaken är som bäst. Plocka enskilda blad från olika plantor istället för att kalhugga en enda. Bladen är bäst helt färska men kan konserveras som pesto, i smör eller frysta.",uses:[{use:"Ramslökspesto",tip:"DEN klassiska användningen. Mixa med olivolja, parmesan och pinjenötter. Fantastiskt på pasta, som röra till grillat eller på en smörgås."},{use:"Sallad och topping",tip:"Strimla bladen och strö över sallad, soppa eller äggrätt. Den milda vitlökssmaken lyfter allt utan att ta över."},{use:"Soppa",tip:"Ramslökssoppa med potatis och grädde - en svensk vårklassiker! Tillsätt bladen mot slutet så behålls den gröna färgen och smaken."},{use:"Ramslökskapris",tip:'Syrainlägg blomknopparna innan de öppnar sig - du får fantastiska "kapris" med vitlökssmak. Perfekt till fisk och sallader.'}]}},Da=Object.freeze(Object.defineProperty({__proto__:null,ramslok:ir},Symbol.toStringTag,{value:"Module"})),lr={name:"Röda vinbär",icon:"roda-vinbar",category:"bär",family:"Ripsväxter",familyLatin:"Grossulariaceae",perennial:!0,lifespan:"15-20 år",difficulty:"Enkel",difficultyWhy:"En av de mest lättskötta bärbuskarna i svenska trädgårdar. Extremt härdig, kräver minimal omvårdnad och ger pålitlig skörd år efter år. Perfekt startbuske för den som aldrig odlat bär förut.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:null},days:"70-90",spacing:"120-150 cm",rowSpacing:"200-250 cm",depth:"Något djupare än i krukan",ph:{min:5.5,max:7,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Trivs bäst i full sol men klarar halvskugga bättre än de flesta bärväxter. I full sol blir bären sötare och klasarna större. Lite eftermiddagsskugga i södra Sverige är faktiskt inte fel - busken stressar mindre i värmen."},temperature:{min:-30,max:30,ideal:"15-22°C",detail:"Riktigt tålig - klarar ner till -30°C utan problem. Blommar något senare på våren än svarta vinbär, vilket gör den mindre känslig för sena vårfroster. Trivs allra bäst i sval svensk sommar - hon är ingen solbadare."},wind:{level:"Tålig",detail:"Kompakt och stabil buske som klarar vind bra. Lite vindskydd under blomning hjälper pollineringen - pollinerarna vill kunna jobba i lugn och ro."}},watering:{need:"Medel",icon:"water",summary:"Röda vinbär har grunda rötter och behöver jämn fukt under blomning och bärutveckling. Men hon är inte krävande - en mulchad buske klarar sig med minimal hjälp de flesta somrar.",phases:[{phase:"Vår (knoppsprickning)",need:"Medel",tip:"Busken vaknar tidigt. Vattna vid torr vår - hon behöver fukt för att driva knoppar och blommor ordentligt."},{phase:"Blomning (maj-juni)",need:"Hög",tip:"Kritisk period! Torka nu betyder att bären inte sätter frukt. Vattna djupt 2 gånger per vecka om det inte regnar. Det är nu det avgörs."},{phase:"Bärmognad (juni-juli)",need:"Medel-Hög",tip:"Jämn fukt ger fina, fasta bär. Ojämn vattning kan ge att bären spricker precis när de ska skördas - frustrerande!"},{phase:"Höst (efter skörd)",need:"Låg",tip:"Minska vattningen. Busken förbereder sig för vintervila och behöver inte mycket uppmärksamhet."}],mistakes:["Vattnar för lite under blomning - bären sätter inte frukt och klasarna blir glesa","Ojämn vattning under mognad - ger sprickta bär som sedan möglar","Glömmer nyplanterade buskar under första sommaren - de har inte hunnit bygga upp ordentliga rötter ännu"],tip:"Mulcha runt busken med gräsklipp, bark eller halm. Det håller fukten jämn, matar maskarna och håller ogräs borta. En mulchad röda vinbärsbuske klarar sig nästan själv."},soil:"Röda vinbär trivs i de flesta jordtyper bara den inte är vattensjuk. Föredrar näringsrik, fukthållande jord med god dränering. Klarar lerjord bättre än man tror - bara den inte är kompakt som betong.",soilTips:["Blanda in rikligt med kompost vid plantering - det ger en bra start och förbättrar jordstrukturen","Mulcha årligen med kompost, bark eller gräsklipp - det bästa du kan göra för busken","Klarar lerjord bra men blanda i lite sand och kompost om den är riktigt tung","Undvik extremt kalkrik jord - röda vinbär föredrar svagt surt till neutralt pH"],timeline:{1:[{phase:"Plantering",months:"Okt-nov eller mars-april",icon:"seedling"},{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Skörd",months:"Juli-aug",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (mars)",icon:"scissors"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],4:[{phase:"Plantering",months:"Okt eller april-maj",icon:"seedling"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Skörd",months:"Juli",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (feb-mars)",icon:"scissors"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],6:[{phase:"Plantering",months:"Maj-juni",icon:"seedling"},{phase:"Blomning",months:"Juni",icon:"bloom"},{phase:"Skörd",months:"Juli-aug",icon:"harvest"},{phase:"Beskärning",months:"Sen vinter (mars-april)",icon:"scissors"},{phase:"Vintervila",months:"Okt-april",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:4,P:2,K:2},{month:"Maj",N:5,P:4,K:3},{month:"Jun",N:4,P:5,K:6},{month:"Jul",N:3,P:4,K:7},{month:"Aug",N:2,P:3,K:5},{month:"Sep",N:1,P:2,K:3}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge en giva brunnen gödsel eller kompost runt busken. Röda vinbär är inte lika hungriga som svarta vinbär men uppskattar en vårstart med näring."},{timing:"Blomning (maj)",tip:"En giva kaliumrik gödsel (typ tomatgödsel eller vedaska) stärker blomning och bärkvalitet. Kalium ger smak och fina, genomskinliga bär."},{timing:"Efter skörd",tip:"Ingen gödsling efter juli - busken ska förbereda sig för vinter, inte skjuta nya skott som inte hinner mogna."},{timing:"Höst (mulch)",tip:"Lägg ett lager kompost eller lövmull som höstmulch. Det bryts ner under vintern och matar busken inför nästa säsong."}],companions:{good:[{id:"ringblomma",name:"Ringblomma",icon:"flower",why:"Lockar pollinatörer till buskarna under blomning. Röda vinbär behöver insektspollinering för fulla klasar - ringblommorna är som neonskyltar för humlor."},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Fixerar kväve i jorden som bärbuskarna uppskattar. Växer upprätt och konkurrerar inte om utrymmet."},{id:"graslok",name:"Gräslök",icon:"herb",why:"Starka doften avskräcker bladlöss. Den tidiga blomningen lockar nyttoinsekter. Perfekt markskydd under buskarna."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Kan sprida svampsjukdomar som drabbar vinbärsbuskarna. Håll bra avstånd."}]},rotation:{avoid:[{id:"roda-vinbar",name:"Röda vinbär"},{id:"svarta-vinbar",name:"Svarta vinbär"},{id:"vita-vinbar",name:"Vita vinbär"},{id:"krusbar",name:"Krusbär"}],avoidWhy:"Alla Ribes-arter delar sjukdomar (mjöldagg, bladfallsjuka, gallkvalster). Plantera inte nya vinbär eller krusbär där gamla stått - vänta minst 5 år så jorden hinner bli frisk.",goodBefore:[{name:"Solig, öppen plats"},{name:"Baljväxter"},{name:"Gräsmatta"}],goodBeforeWhy:"En plats som legat som gräsmatta eller odlats med baljväxter ger frisk, kväverik jord - perfekt startplats för en vinbärsbuske.",goodAfter:[{name:"Gröngödsling"},{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodAfterWhy:"Efter 15-20 år med vinbär är jorden utarmad. Gröngödsling och baljväxter bygger upp den igen."},varieties:[{name:"Jonkheer van Tets",zones:[1,2,3,4,5],note:"Holländsk klassiker och den vanligaste sorten i Sverige. Tidig, rikbärande med långa, fina klasar. Pålitlig som en gammal vän."},{name:"Rovada",zones:[1,2,3,4,5],note:"Sen sort med enormt långa klasar. Stora bär som är lätta att plocka. Ger fantastisk skörd."},{name:"Röda Holländska",zones:[1,2,3,4,5,6,7],note:"Den riktiga veteranen - odlad i over 300 år. Extremt härdig och tålig. Kanske inte de största bären, men aldrig sviker."},{name:"Rondom",zones:[1,2,3,4,5],note:"Sen sort med fina, jämna klasar. Stora bär och hög skörd. Finns hos Blomsterlandet."}],problems:[{name:"Bladlöss (vinbärsbladlus)",symptom:"Bladen bubblar och krälar ihop sig, ofta med rödfärgade blåsor på ovansidan. Ser dramatiskt ut men busken klarar det.",fix:"Spola av med hård vattenstråle tidigt på säsongen. Locka nyckelpigor och blomflugor med blommande växter intill. Busken klarar sig - det ser värre ut än det är."},{name:"Mjöldagg",symptom:"Vitt, mjöligt belägg på blad och skottspetsar. Röda vinbär drabbas mildare än svarta vinbär, men det kan hämma tillväxten.",fix:"God luftcirkulation genom ordentlig gallring är bästa försvaret. Klipp bort angripna skottspetsar tidigt. Undvik kvävegödsling sent på säsongen."},{name:"Bladfallsjuka",symptom:"Bruna fläckar på bladen som sedan faller av i förtid. Busken tappar bladen redan i juli-augusti.",fix:"Rensa bort nedfallna löv noggrant - svampen övervintrar där. God gallring ger bättre luftcirkulation. Friska, välskötta buskar klarar sig bäst."},{name:"Vinbärsgallkvalster",symptom:"Onormalt stora, uppsvällda knoppar på vintern/våren. Knopparna utvecklas inte till blad utan dör.",fix:"Plocka bort och bränn svullna knoppar under senvintern. Vid kraftigt angrepp - byt ut busken och plantera på ny plats. Drabbar röda vinbär mildare än svarta."}],goodToKnow:[{icon:"tip",title:"Genomskinliga juveler",text:"Mogna röda vinbär är nästan genomskinliga i solen - som små rubiner som lyser upp trädgården. Busken är lika mycket prydnadsväxt som nyttoväxt, speciellt på sensommaren.",severity:"tip"},{icon:"tip",title:"Gelekungens favorit",text:"Röda vinbär har extremt hög pektinhalt - de gelerar helt av sig själva utan tillsatser. Rödvinbärsgele till ost, vilt och kött är en ren delikatess som tar 20 minuter att göra.",severity:"tip"},{icon:"warning",title:"Bladlöss ser värre ut än det är",text:"De röda blåsorna på bladen ser alarmerande ut men busken tar ingen egentlig skada. Lugn - det är bara vinbärsbladlusen som jobbar. Bären påverkas inte.",severity:"warning"},{icon:"tip",title:"Bär bäst på gammal ved",text:"Till skillnad från svarta vinbär bär röda vinbär bäst på 2-4 år gamla grenar. Var inte för ivrig med beskärningen - de äldre grenarna är de mest produktiva. Behåll dem längre!",severity:"tip"},{icon:"tip",title:"Hela klasen i taget",text:"Plocka hela klasar med en sax istället för bär för bär. Det går 10 gånger snabbare och bären håller sig längre. Rensa från stjälkar efteråt med en gaffel.",severity:"tip"},{icon:"warning",title:"Fåglarna älskar dem",text:"Fåglar är galna i röda vinbär - de röda bären syns på långt håll. Täck med nät när bären börjar färgas, annars hinner fåglarna före dig. Koltrastar är värst.",severity:"warning"}],sowing:{method:"direct",label:"Plantering",description:"Röda vinbär planteras som barrotade buskar (höst eller tidig vår) eller krukodlade plantor (hela säsongen). Höstplantering ger bäst etablering - rötterna jobbar i fred hela vintern.",steps:["Gräv en grop dubbelt så bred som rotklumpen och lika djup plus 5 cm","Blanda in rikligt med kompost i jorden","Plantera något djupare än busken stod i krukan - stimulerar nya skott från basen","Vattna rikligt vid plantering - riktigt genomblött","Klipp ner alla grenar till ca 20 cm, 3-5 knoppar per gren (det känns brutalt men ger en starkare buske)","Mulcha med bark eller gräsklipp runt busken, men inte intill stammen"],tips:["Höstplantering (okt-nov) ger bäst etablering - rötterna jobbar medan du vilar inför vintern","Klipp ner busken vid plantering - det ger en starkare, tätare buske från start","Första skörden kommer år 2, full skörd från år 3-4. Ha tålamod - det är värt väntan!"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Röda vinbär förökas enklast med vedartade sticklingar på hösten. Inte riktigt lika enkel rotning som svarta vinbär, men fortfarande väldigt högt lyckandefrekvens.",steps:["Klipp 20-25 cm långa sticklingar av årets mogna skott i oktober-november","Klipp snett i nedre änden, rakt i övre (så du vet vad som är upp och ner)","Ta bort alla knoppar utom de 3-4 översta","Sätt sticklingarna i fuktig jord utomhus med bara de översta knopparna ovan mark","Vattna vid torka under vintern","Sticklingarna rotar sig under vintern och kan planteras ut nästa höst"],isolation:"Vegetativ förökning - kloner av moderplantan. Ingen korspollinering relevant.",storageYears:"Ej tillämpligt",tip:"Röda vinbär rotar sig bra från sticklingar, men inte lika lätt som svarta vinbär. Gör gärna extra sticklingar - räkna med att 7 av 10 lyckas. Alternativt fungerar nedböjning (marklager) utmärkt."},storage:{shelfLife:"5-7 dagar (färska)",methods:[{method:"Frysning",icon:"snowflake",duration:"12+ månader",description:"Frys hela klasar direkt - bären lösgör sig enkelt när de är frysta. Perfekt att plocka fram till gele, saft eller garnering. Det smidigaste sättet att ta vara på en stor skörd.",best:!0},{method:"Gele",icon:"storage",duration:"1+ år",description:"Rödvinbärsgele är en delikatess - bären har så hög pektinhalt att det gelerar helt av sig själv. Koka bären med lite vatten, sila, tillsätt socker och koka till gelerande. Fantastisk till ost och kött.",best:!1},{method:"Saft",icon:"storage",duration:"1+ år",description:"Vackert rubinröd saft som är festlig och god. Koka bären med vatten, sila och tillsätt socker. Kan spädas eller drickas som den är.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"5-7 dagar",description:"Röda vinbär håller sig bättre än de flesta bär tack vare det fasta skalet. Förvara i skål med hushållspapper. Tvätta inte förrän du ska använda dem.",best:!1},{method:"Torkning",icon:"sun",duration:"6+ månader",description:"Torka i ugn på 50-60 grader i 10-14 timmar. Blir intensivt sötsyrliga. Fina i müsli, bakning och som garnering.",best:!1}],tips:["Plocka hela klasar med sax - det går mycket snabbare och bären håller sig bättre","Rensa bären från stjälkar med en gaffel - dra klasen genom gaffelns tänder. Genialiskt enkelt!","Frys i portionspåsar - perfekt att ta fram till en snabb gele eller saft mitt i vintern","Röda vinbär håller sig längre än hallon och svarta vinbär tack vare det tjockare skalet"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3.5,unit:"kg"},pruning:{label:"Beskärning",types:{maintenance:{name:"Underhållsbeskärning",when:"Tidig vår (feb-mars) innan knopparna svällt",description:"Röda vinbär bär bäst på 2-4 år gammal ved - till skillnad från svarta vinbär som vill ha yngre grenar. Var alltså inte för ivrig med saxen! En frisk buske har 8-12 grenar av blandad ålder med en öppen, luftig mitt.",steps:["Ta bort grenar som är 4+ år gamla (mörkare bark, grövre) vid basen","Ta bort svaga, korsande eller skadade grenar","Spara 2-3 starka nya skott från föregående år som ersättning","Sikta på 8-12 grenar totalt i busken, spridda i ålder","Korta sidoskott till 2-3 knoppar för att stimulera bärbildning på de äldre grenarna","Håll buskens mitt öppen och luftig - ljus och luft ska nå in"]},rejuvenation:{name:"Föryngringsbeskärning",when:"Tidig vår",description:"Gammal och risig buske? Röda vinbär tål föryngringsbeskärning bra. Du kan antingen klippa ner hela busken eller göra det stegvis över 2-3 år genom att ta bort en tredjedel av de äldsta grenarna varje år.",steps:["Ta bort alla grenar äldre än 4 år samt alla svaga och sjuka skott","Behåll 4-5 av de starkaste grenarna i 2-3 årsåldern","Korta de kvarvarande grenarna till halva längden","Gödsla med kompost och vattna ordentligt","Skörd igen redan nästa år, full skörd om 2 år"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Vedartade sticklingar",description:"Klipp 20-25 cm bitar av årets mogna skott i oktober-november. Ta bort alla knoppar utom de översta 3-4. Sätt i fuktig jord utomhus. Röda vinbär rotar sig bra - inte riktigt lika enkelt som svarta vinbär, men fortfarande hög lyckandefrekvens.",icon:"scissors"},{method:"Nedböjning (marklager)",description:"Böj ner en låg gren och fäst den mot marken med en bygel. Täck med jord. Grenen rotar sig under säsongen och kan klippas loss och planteras om nästa höst. Fungerar utmärkt för röda vinbär.",icon:"seedling"}],tip:"Sticklingar av röda vinbär rotar sig bra men gör gärna extra - räkna med att 7 av 10 lyckas. Nedböjning (marklager) är det säkraste alternativet med nästan garanterad framgång."}},Na=Object.freeze(Object.defineProperty({__proto__:null,rodaVinbar:lr},Symbol.toStringTag,{value:"Module"})),sr={name:"Rödbeta",icon:"rodbeta",family:"Mållväxter",familyLatin:"Amaranthaceae",difficulty:"Enkel",difficultyWhy:"Tålig, direktsås utomhus, kräver minimal skötsel och klarar de flesta jordar.",zones:{outdoor:[1,2,3,4,5,6,7],indoor:null,greenhouse:null},days:"55-70",spacing:"10-12 cm",rowSpacing:"30-40 cm",depth:"2 cm",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Minst 6 timmar sol per dag ger de finaste rötterna. Klarar halvskugga (4+ timmar), men då tar det längre tid och betorna blir mindre. Blasten växer fint i halvskugga om du odlar för bladens skull."},temperature:{min:5,max:28,ideal:"15-20°C",detail:"Gror redan vid 5°C men trivs bäst runt 15-20°C. Tål lätt frost ner till -4°C. Långvarig kyla under 10°C kan dock trigga skottskjutning - då tror hon att det är dags för vinter och skickar upp en blomstjälk istället."},wind:{level:"Tålig",detail:"Låg profil med kraftig blast - inga problem med vind. Blasten kan till och med fungera som vindskydd för mer känsliga grannar."}},watering:{need:"Medel",icon:"water",summary:"Jämn fukt ger jämna, fina betor. Rödbetan är ganska förlåtande, men ojämn vattning kan ge vediga eller spruckna rötter.",phases:[{phase:"Groning (0-3 veckor)",need:"Hög",tip:"Håll jorden jämnt fuktig tills groddarna kommer upp. Rödbetans frön är egentligen frönystan med flera frön i varje, så det kommer ofta upp flera plantor på samma ställe."},{phase:"Tillväxt (3-8 veckor)",need:"Medel",tip:"Vattna 2-3 gånger i veckan om det inte regnar. Djupvattna ordentligt varje gång istället för att stänka lite varje dag."},{phase:"Rotutveckling (8+ veckor)",need:"Medel",tip:"Fortsätt med jämn fukt. Torka nu ger vediga, hårda betor med vita ringar inuti. Inte kul."}],mistakes:["Ojämn vattning (torrt-blött-torrt) ger spruckna rötter och vita ringar inuti","Övervattning i tung lerjord - rötterna kan börja ruttna","Glömma vattningen under varma perioder - betorna blir vediga och förlorar sötman"],tip:"Mulcha med gräsklipp eller halm efter uppkomst. Det håller fukten jämn, minskar ogräs och gör att du slipper vattna lika ofta."},soil:"Lucker, mullrik jord med bra dränering. Rödbetan är inte så kräsen, men trivs bäst i lagom lätt jord utan stora stenar.",soilTips:["Blanda in väl brunnen kompost för bättre struktur och näring","Undvik för sur jord - rödbetan gillar det nära neutralt (strö lite kalk om pH är under 6)","Gräv bort stora stenar ner till 20 cm djup - annars kan betorna bli konstiga i formen"],timeline:{1:[{phase:"Direktså",months:"Apr-Maj",icon:"seedling"},{phase:"Gallra",months:"Maj",icon:"scissors"},{phase:"Gödsla (lätt)",months:"Jun",icon:"water"},{phase:"Tidig skörd (knytnavsbetor)",months:"Jun-Jul",icon:"harvest"},{phase:"Huvudskörd",months:"Aug-Sep",icon:"harvest"}],4:[{phase:"Direktså",months:"Maj",icon:"seedling"},{phase:"Gallra",months:"Jun",icon:"scissors"},{phase:"Gödsla (lätt)",months:"Jun-Jul",icon:"water"},{phase:"Tidig skörd",months:"Jul-Aug",icon:"harvest"},{phase:"Huvudskörd",months:"Sep",icon:"harvest"}],6:[{phase:"Direktså",months:"Jun",icon:"seedling"},{phase:"Gallra",months:"Jul",icon:"scissors"},{phase:"Gödsla (lätt)",months:"Jul",icon:"water"},{phase:"Huvudskörd",months:"Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:25,P:15,K:10,label:"Sådd"},{month:"Maj",N:55,P:25,K:20,label:"Tillväxt"},{month:"Jun",N:70,P:40,K:30,label:"Bladtillväxt"},{month:"Jul",N:35,P:65,K:55,label:"Rotutveckling"},{month:"Aug",N:15,P:75,K:80,label:"Mognad"},{month:"Sep",N:5,P:50,K:85,label:"Skörd"}],nutritionTips:[{timing:"Vid sådd",tip:"Grundgödsla med brunnen kompost. Rödbetan behöver inte mycket extra om jorden är bra."},{timing:"Tidig tillväxt",tip:"Ge en lätt giva flytande alggödsel varannan vecka under bladtillväxten."},{timing:"Rotutveckling",tip:"Byt till kaliumrik gödsel (vedaska är perfekt). Kalium ger sötare, tätare betor med fin färg."},{timing:"Mognad",tip:"Sluta gödsla 3-4 veckor före skörd. Låt rödbetan mogna klart i lugn och ro."}],companions:{good:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft håller skadedjur borta, och de konkurrerar inte alls om samma näring."},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Sallaten växer snabbt och skördas innan rödbetan behöver platsen. Perfekt markskydd mellan raderna."},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Baljväxter fixerar kväve i jorden som rödbetan tacksamt tar hand om."},{id:"vitlok",name:"Vitlök",icon:"vegetable",why:"Samma effekt som lök - doftbarriär mot skadedjur."}],bad:[{id:"spenat",name:"Spenat",icon:"vegetable",why:"Samma familj (mållväxter) - delar sjukdomar som bladfläcksjuka. Undvik framförallt i växtföljd."},{id:"mangold",name:"Mangold",icon:"vegetable",why:"Nära släkting (samma art, faktiskt!) - delar alla sjukdomar och skadedjur."}]},rotation:{avoid:[{id:"spenat",name:"Spenat"},{id:"mangold",name:"Mangold"}],avoidWhy:"Alla tillhör mållväxter (Amaranthaceae) och delar sjukdomar. Mangold och rödbeta är till och med samma art! Vänta minst 3-4 år.",goodBefore:[{name:"Baljväxter (ärtor, bönor)"},{id:"lok",name:"Lök"},{id:"potatis",name:"Potatis"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden. Lök sanerar mot svampsjukdomar. Potatis lämnar välbearbetad jord.",goodAfter:[{name:"Kål"},{id:"morot",name:"Morot"},{id:"lok",name:"Lök"}],goodAfterWhy:"Kålväxter och morötter trivs i den mullrika jord rödbetan lämnar efter sig."},varieties:[{name:"Detroit Dark Red 2",zones:[1,2,3,4,5,6,7],note:"Klassikern! Rund, jämn, djupt röd hela vägen igenom. Pålitlig OP-sort som fungerar överallt."},{name:"Cylindra",zones:[1,2,3,4,5,6],note:"Avlång OP-sort som gör det enkelt att skära jämna skivor. Bra smak och lagring."},{name:"Chioggia",zones:[1,2,3,4,5,6],note:"Italiensk kulturarvssort (OP) med rosa-vita ränder inuti. Mildare smak, fantastisk i sallad."},{name:"Bull's Blood",zones:[1,2,3,4,5,6],note:"OP-kulturarvssort från 1800-talet. Odlas lika mycket för de mörkröda bladen som roten."},{name:"Burpees Golden",zones:[1,2,3,4,5,6],note:"Gul rödbeta (OP)! Söt, mild smak som inte färgar allt rött. Perfekt om du vill ha variation."}],problems:[{name:"Betflugan",symptom:"Bruna, torra fläckar (minor) i bladen. Bladen ser ut som de har blåsor.",fix:"Plocka bort angripna blad. Fiberduk tidigt på säsongen. Sällan allvarligt - rödbetan överlever."},{name:"Vediga betor",symptom:"Hårda, torra, fibriga betor med tydliga ringar.",fix:"Beror nästan alltid på ojämn vattning eller att betorna stått för länge. Skörda i tid och håll jämn fukt."},{name:"Svampfläckar (Cercospora)",symptom:"Små runda fläckar med grå mitt och mörk kant på bladen.",fix:"God luftcirkulation, undvik att vattna bladen. Växtföljd (vänta 3 år). Ta bort angripna blad."},{name:"Skottskjutning",symptom:"Blomstjälk skjuter upp mitt i säsongen istället för att bilda rot.",fix:"Orsakas av kyla (under 10°C i mer än 2 veckor) följt av värme. Så inte för tidigt på våren. Skottskjutna betor går inte att rädda."}],goodToKnow:[{icon:"warning",title:'Varje "frö" ger flera plantor',text:"Rödbetans frön sitter ihop i nystan. Du får ofta 2-3 plantor från varje frö, så gallring är ett måste. Var inte rädd för att plocka bort - annars trängs alla och ingen blir stor.",severity:"warning"},{icon:"warning",title:"Mangold är samma art",text:"Rödbeta och mangold är faktiskt samma art (Beta vulgaris). Tänk på det vid växtföljd och frötagning - de korsar sig glatt med varandra.",severity:"warning"},{icon:"leaf",title:"Blasten är mat!",text:"Rödbetsblasten är lika nyttig som spenat och smakar fantastiskt. Tillaga den som mangold - stek snabbt med vitlök och olivolja. Släng den aldrig!",severity:"tip"},{icon:"rotation",title:"Så i omgångar",text:"Så med 3-4 veckors mellanrum från maj till midsommar. Då får du knytnavsbetor hela sommaren istället för en jätteladning i september.",severity:"tip"},{icon:"snowflake",title:"Tål frost - skörda sent",text:"Rödbetan klarar lätt frost ner till -4°C. En natt med frost gör faktiskt smaken bättre! Lämna gärna betorna i jorden till sent på hösten.",severity:"tip"},{icon:"tip",title:"Koka med skalet på",text:"Skala aldrig rödbeta före kokning - den blöder ut färg och smak. Koka hel med rot och blastrest kvar, skala efteråt. Lätt som en plätt.",severity:"tip"}],sowing:{method:"direct",label:"Direktsådd",description:"Rödbetan sås direkt på friland. Hon ogillar att bli omflyttad och pålroten störs av omplantering.",steps:["Luckra jorden och kratta till fin, jämn yta","Dra spår ca 2 cm djupa med 30-40 cm mellanrum","Blötlägg fröna i ljummet vatten 2-4 timmar före sådd - det snabbar på groningen rejält","Så fröna med 3-4 cm mellanrum (de ser ut som små knotiga klumpar)","Täck med jord och tryck till lätt","Vattna försiktigt med stril","Gallra till 10-12 cm avstånd när plantorna är 5-8 cm höga (ät de gallrade plantorna - de är goda!)"],tips:["Så i omgångar med 3-4 veckors mellanrum för skörd hela säsongen","De gallrade småplantorna är utmärkta i sallad - hela plantan, både blad och minirot","Täck med fiberduk de första veckorna om betflugan brukar vara ett problem"],indoorWeeks:null},seedSaving:{difficulty:"Medel",type:"Vindpollinerare",biennial:!0,description:"Rödbetan är tvåårig och bildar frö andra året. Du måste överväntra roten och plantera ut den igen på våren.",steps:["Välj de finaste, friskaste betorna vid höstens skörd","Klipp av blasten till ca 3 cm men lämna roten hel","Lagra i sand i en kall (men frostfri) källare eller garage över vintern","Plantera ut rötterna tidigt på våren med toppen precis i marknivå","Rödbetan skjuter upp en blomstjälk som kan bli över en meter hög","Fröna mognar under sensommaren - vänta tills de blir bruna och torra","Klipp av hela stjälken och torka inomhus i en papperspåse","Gnugga loss frönystanen och förvara torrt och svalt"],isolation:"Vindpollinerare som korsar med mangold och andra betor. Pollen sprids kilometerlångt - odla bara en sort för frö, eller isolera med minst 1-2 km.",storageYears:"3-5 år",tip:"Rödbetsfrö har lång hållbarhet jämfört med många andra grödor. Märk alltid sort och år!"},storage:{shelfLife:"4-6 månader",methods:[{method:"Sandlåda i källare",icon:"storage",duration:"4-6 månader",description:"Klipp av blasten till 3 cm (vrid av den, klipp inte - det minskar blödning). Lägg i lager med fuktig sand i en låda. Förvara svalt (1-4°C) och mörkt. Klassisk metod som fungerar utmärkt.",best:!0},{method:"I landet (med täckning)",icon:"leaf",duration:"Till november-december",description:"Täck med tjockt lager halm eller löv. Rödbetan tål frost ner till -4°C, men gräv upp innan marken fryser ordentligt. Fungerar bäst i zon 1-3.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"2-4 veckor",description:"Klipp av blasten, lägg i plastpåse med några hål. Tvätta inte förrän du ska använda dem - jord skyddar.",best:!1},{method:"Inkokt/inlagd",icon:"storage",duration:"12+ månader",description:"Koka hel, skala, skär i skivor och lägg in med ättika, socker och kryddor. Klassisk svensk inläggning som håller i evigheter!",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Koka hel tills nästan mjuk, skala, skär i bitar och frys in. Rå rödbeta fryser dåligt - den blir gummig.",best:!1}],tips:["Vrid av blasten istället för att klippa - det minskar blödningen och betorna håller längre","Tvätta INTE betor som ska lagras - jordrester skyddar mot uttorkning","Lagra aldrig skadade eller spruckna betor - ät dem först","Rödbeta som börjar bli mjuk kan fortfarande användas i soppa eller ugnsrostning"]},harvestCalc:{minPerSqm:2,maxPerSqm:4,unit:"kg"}},Ja=Object.freeze(Object.defineProperty({__proto__:null,rodbeta:sr},Symbol.toStringTag,{value:"Module"})),or={name:"Rödkål",icon:"rodkal",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Medel",difficultyWhy:"Rödkål är snäll men bestämd - hon vill ha kalkrik jord, jämn fukt och skydd mot kålfjärilen. Ger du henne det belönar hon dig med vackert lila huvuden som håller långt in på vintern. Lite mer krävande än sallat, men absolut överkomligt.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:[1,2,3,4,5,6,7,8]},days:"70-150",spacing:"40-50 cm",rowSpacing:"50-60 cm",depth:"1-2 cm",ph:{min:6.5,max:7.5,ideal:7},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmar sol per dag. Rödkål behöver ordentligt med ljus för att bygga täta huvuden och utveckla den djupa, violetta färgen. I halvskugga blir både huvudena och färgen svagare."},temperature:{min:-5,max:25,ideal:"15-18°C",detail:"Rödkål är en sval tjej som trivs bäst runt 15-18°C. Hon tål frost ner till -5°C och kan stå kvar i landet långt in på hösten. Över 25°C stressar hon och färgutvecklingen hämmas."},wind:{level:"Skyddat",detail:"Precis som sin kusin vitkålen bygger rödkål tunga huvuden som kan fånga vind. Ge henne lite vindskydd eller kupa jord runt stambasen."}},watering:{need:"Medel-Hög",icon:"water",summary:"Rödkål vill ha jämn fukt hela säsongen. Ojämn vattning kan få huvudena att spricka - och en sprucken rödkål tappar snabbt sin fina färg.",phases:[{phase:"Förodling (0-6 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig men aldrig blöt. Kålfrön gror snabbt (5-10 dagar) vid rumstemperatur."},{phase:"Etablering (utplantering)",need:"Hög",tip:"Vattna rikligt vid utplantering och dagligen den första veckan. Nyplanterade kålplantor behöver extra omsorg för att sätta sig."},{phase:"Tillväxt och bladbildning",need:"Medel-Hög",tip:"Djupvattna 2-3 gånger i veckan. Nu bygger hon bladmassan som ska bli det vackra lila huvudet."},{phase:"Huvudbildning och mognad",need:"Hög",tip:"Kritisk period! Håll jämn fukt - plötsligt regn efter torka kan få huvudena att spricka. Hellre lite och ofta."}],mistakes:["Ojämn vattning - torka följt av storvattning gör att huvudena spricker. Det klassiska nybörjarmisstaget.","Vattna ovanifrån sent på kvällen - fuktiga blad i mörkret bjuder in svampsjukdomar","Tro att hon klarar sig själv bara för att hon ser tålig ut - speciellt under huvudbildningen behöver hon jämn fukt","Sluta vattna för tidigt på hösten - sena lagringssorter behöver fukt ända till skörd"],tip:"Mulcha ordentligt med gräsklipp eller halm runt plantorna. Det håller jorden fuktig och sval, och minskar risken för de plötsliga fuktsvängningar som får huvudena att spricka."},soil:"Näringsrik, kalkrik, mullrik jord med bra struktur. Rödkål är en storätare som vill ha djup, bra jord. Kalkrik jord är extra viktigt - det skyddar mot klumprotsjuka och påverkar faktiskt färgen positivt.",soilTips:["Kalka på hösten om pH är under 6.5 - rödkål ÄLSKAR kalkrik jord. Hög pH ger dessutom mer blåviolett färg, medan sur jord gör henne rödare.","Blanda in rikligt med brunnen kompost och gärna lite hönsgödsel innan plantering. Rödkål är hungrig som en tonåring.","Undvik packad jord - luckra djupt och blanda in sand om du har tung lera. Rötterna vill ner ordentligt."],timeline:{1:[{phase:"Förodla inomhus",months:"Feb-Mar",icon:"seedling"},{phase:"Plantera ut",months:"Apr-Maj",icon:"leaf"},{phase:"Gödsla",months:"Maj-Jun",icon:"water"},{phase:"Skörd tidiga sorter",months:"Jun-Jul",icon:"harvest"},{phase:"Skörd sena sorter",months:"Sep-Nov",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj-Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Skörd tidiga sorter",months:"Jul-Aug",icon:"harvest"},{phase:"Skörd sena sorter",months:"Okt-Nov",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Plantera ut",months:"Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Skörd tidiga sorter",months:"Aug-Sep",icon:"harvest"},{phase:"Skörd sena sorter",months:"Sep-Okt",icon:"harvest"}]},nutritionData:[{month:"Mar",N:20,P:10,K:10,label:"Förodling"},{month:"Apr",N:30,P:15,K:10,label:"Tillväxtstart"},{month:"Maj",N:60,P:25,K:20,label:"Utplantering"},{month:"Jun",N:85,P:35,K:30,label:"Kraftig bladtillväxt"},{month:"Jul",N:90,P:40,K:45,label:"Huvudbildning"},{month:"Aug",N:70,P:35,K:50,label:"Mognad"},{month:"Sep",N:40,P:25,K:40,label:"Sena sorter mognar"},{month:"Okt",N:15,P:15,K:25,label:"Lagringskål skördas"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla med brunnen kompost och hornmjöl. Rödkål behöver en kväverik start för att bygga de stora ytterbladen som ska forma huvudet."},{timing:"Tre veckor efter utplantering",tip:"Ge flytande nässelvatten eller alggödsel. Hon ska vara i full gång nu och behöver ordentligt med näring."},{timing:"Vid huvudbildning",tip:"Extra giva med kaliumrik gödsel (vedaska eller alggödsel). Kalium hjälper huvudet att bli tätt och stärker den fina lila färgen."},{timing:"Sensommar (sena sorter)",tip:"En sista lätt giva med kalium stärker cellväggarna och gör kålen mer motståndskraftig mot frost. Bra för lagringsegenskaperna."}],companions:{good:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft förvirrar kålfjärilen - hon hittar inte kålen bland all lökdoft. Ett beprövat försvar som funkar."},{id:"dill",name:"Dill",icon:"herb",why:"Lockar parasitsteklar som äter kålfjärilens larver. Dillen jobbar som rödkålens personliga livvakt."},{id:"selleri",name:"Selleri",icon:"vegetable",why:"Sellerins starka doft maskerar kålen för skadedjur. De trivs fint ihop i samma bädd."},{id:"rodbeta",name:"Rödbeta",icon:"vegetable",why:"Tar näring från ett annat djup i jorden - de konkurrerar inte utan kompletterar varandra."}],bad:[{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Jordgubbar hämmas av kålväxter. De trivs verkligen inte ihop - håll dem åtskilda."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Båda är storätare som slåss om samma näring. Ingen av dem blir nöjd."},{name:"Andra kålväxter",icon:"vegetable",why:"Odla inte rödkål bredvid annan kål - de delar skadedjur och sjukdomar och förstärker problemen."}]},rotation:{avoid:[{id:"gronkal",name:"Grönkål"},{id:"blomkal",name:"Blomkål"},{id:"broccoli",name:"Broccoli"},{id:"vitkal",name:"Vitkål"},{id:"brysselkal",name:"Brysselkål"},{id:"kalrabbi",name:"Kålrabbi"},{id:"radisa",name:"Rädisa"},{id:"pak-choi",name:"Pak choi"}],avoidWhy:"Alla tillhör korsblommiga och delar sjukdomar som klumprotsjuka. Vänta minst 4 år - helst 6-7 år - innan du odlar kål på samma plats igen. Klumprotsjuka lever kvar i jorden extremt länge.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"potatis",name:"Potatis"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden - gratis gödsel för hungriga rödkål! Potatis och lök lämnar ren, väl bearbetad jord.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"sallat",name:"Sallat"},{id:"rodbeta",name:"Rödbeta"}],goodAfterWhy:"Rotgrönsaker trivs i den djupt bearbetade, näringsrika restjorden efter kål. Sallat gillar kvävet som kålen lämnar efter sig."},varieties:[{name:"Langedijker Bewaar 2",zones:[1,2,3,4,5],note:"Klassisk holländsk lagringssort med stora, fasta huvuden. Håller hela vintern i källaren. Djupt violett färg och mild smak. Finns hos Nelson Garden och Svedberga."},{name:"Rodynda",zones:[1,2,3,4,5,6],note:"Tidig-medelsort (Kultursaat) med runda, jämna huvuden på 2-3 kg. Pålitlig och lättodlad med fin färg. Ekofrö hos Lindbloms (demeter/eko)."},{name:"Kalibos",zones:[1,2,3,4,5],note:"Unik spetskålsform med lös struktur - perfekt för sallader! Mildare smak än runda sorter och vackert rubinröd. Ekofrö hos Runåbergs."},{name:"Integro F1",zones:[1,2,3,4,5,6],note:"F1-hybrid med mycket jämna huvuden och bra sjukdomsresistens. Ger pålitliga resultat men fröna kan inte sparas. Ekofrö hos Semenco."}],problems:[{name:"Kålfjäril",symptom:"Gröna larver som tuggar stora hål i bladen. Lämnar gröna spillningshögar och kan förstöra hela plantor på kort tid.",fix:"Fiberduk från dag ett - det enda helt säkra skyddet! Handplocka larver regelbundet. Spruta med Bacillus thuringiensis (Bt) mot larverna. Samodla med dill och lök för att förvirra fjärilarna. Pudra med stenmjöl på fuktiga blad."},{name:"Kålfluga",symptom:"Plantan vissnar trots vattning. Dra upp en och titta - rötterna är fulla av vita larver som äter sig igenom rotsystemet.",fix:"Kålkragar runt stjälken vid utplantering - hindrar flugan från att lägga ägg vid stambasen. Fiberduk hjälper också. Kraftiga plantor med bra rotsystem klarar lättare angrepp."},{name:"Klumprotsjuka",symptom:"Plantan stannar i tillväxt och vissnar i värme. Rötterna har fula, klumpiga svullnader. Det här är kålodlarens mardröm.",fix:"Ingen bot - dra upp och bränn angripna plantor! Kalka jorden ordentligt (pH över 7). Odla inte kål på samma plats på minst 6-7 år. Svampen överlever i jorden extremt länge."},{name:"Spruckna huvuden",symptom:"Huvudet spricker mitt i mognadsfasen, ofta efter en period av torka följd av kraftigt regn.",fix:"Nästan alltid orsakat av ojämn vattning. Mulcha och håll jämn fukt. Vrid plantan ett kvarts varv för att bryta några rötter och bromsa tillväxten om du inte hinner skörda i tid."}],goodToKnow:[{icon:"warning",title:"Kalka - klumprotsjukans fiende",text:"Det absolut viktigaste du kan göra för kål är att kalka jorden. Klumprotsjuka trivs i sur jord och finns den väl i marken stannar den i 7+ år. Kalka på hösten, sikta på pH runt 7.",severity:"warning"},{icon:"leaf",title:"Färgen avslöjar jordens pH",text:"Rödkålens färg påverkas av jordens surhet! I alkalisk jord (hög pH) blir hon mer blåviolett, i sur jord mer röd. Det är samma kemi som gör att rödkål kan användas som pH-indikator i skolans kemisal.",severity:"tip"},{icon:"warning",title:"Fiberduk HELA säsongen",text:"Kålfjärilen flyger från maj till september. Lägg fiberduk vid utplantering och ta inte bort den förrän du skördar. Det är irriterande, men det funkar.",severity:"warning"},{icon:"harvest",title:"Nyttigare än vitkål",text:"Rödkål innehåller mer antioxidanter och C-vitamin än sin gröna kusin. Den djupa lila färgen kommer från antocyaniner - samma ämnen som gör blåbär och svarta vinbär så nyttiga.",severity:"tip"},{icon:"seedling",title:"Frost gör henne godare",text:"Rödkål tål frost bra och sena sorter kan stå kvar långt in på hösten. Lätt frost gör att sockret i bladen ökar - vinterns första frostknäpp förvandlar smaken till något alldeles speciellt.",severity:"tip"},{icon:"storage",title:"Syra rödkål - en svensk klassiker",text:"Rödkål kokt med äpple, ättika och kryddnejlika är en klassiker till julbordet. Men prova också att äta henne rå i sallader - krispig, söt och vackert lila. Eller fermentera som surkål!",severity:"tip"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Rödkål förodlas nästan alltid inomhus för att få tillräckligt lång säsong. Tidiga sorter kan direktsås i zon 1-3 men förodling ger bättre kontroll och tidigare skörd.",steps:["Så 1-2 cm djupt i krukor eller celler, 5-6 veckor före planerad utplantering","Håll jorden runt 18-20°C för snabb groning (5-10 dagar)","Flytta till svalare plats (12-15°C) och starkt ljus så snart plantorna är uppe - det ger kompakta, starka plantor","Gallra till en planta per cell om du sått flera frön","Härda av plantorna 7-10 dagar innan utplantering - ställ ut dagtid, in på natten","Plantera ut med 40-50 cm avstånd när plantan har 4-6 riktiga blad","Tryck till jorden ordentligt runt stammen, vattna rikligt och sätt kålkragar + fiberduk direkt"],tips:["Sena lagringssorter behöver förodlas redan i mars-april för att hinna mogna innan vintern","Tidiga sorter som Rodynda kan förodlas lite senare och ger skörd redan efter 70-90 dagar","Kålkragar runt stjälken vid utplantering skyddar mot kålfluga - gör dem av kartong, filt eller köp färdiga"],indoorWeeks:"5-6 veckor"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Rödkål är tvåårig - hon sätter frö först andra året. Huvudet måste övervintras och planteras ut igen på våren. En utmaning, men för den som vill bevara gamla sorter är det värt allt besvär.",steps:["Välj det finaste, friskaste huvudet med bäst färg och skörda det med roten kvar","Förvara hela plantan svalt (0-5°C) över vintern - källare eller jordkällare fungerar","Plantera ut igen på våren med intakt rot och huvudstump","Huvudet spricker upp och en blomstjälk växer upp ur mitten","Gula blommor pollineras av insekter - se till att bara EN sort av Brassica oleracea blommar","Låt fröskidorna mogna och torka på plantan tills de är bruna och spröda","Klipp av blomstjälkarna och eftertorka i papperspåse","Krossa skidorna försiktigt och blås bort agnarna. Förvara svalt och torrt."],isolation:"Korsar med ALLA andra Brassica oleracea (vitkål, grönkål, broccoli, blomkål, brysselkål, kålrabbi). Odla bara en sort för frö, eller isolera med minst 1 km.",storageYears:"4-5 år",tip:"Frötagning av rödkål kräver att du kan förvara en hel kålplanta över vintern. Välj OP-sorter som Langedijker Bewaar 2 eller Kalibos - de ger äkta avkomma. F1-hybrider som Integro ger inte sortriktiga frön."},storage:{shelfLife:"1-2 veckor (färsk), 3-6 månader (källare), 12 månader (syrad/fryst)",methods:[{method:"Källarlagring",icon:"storage",duration:"3-6 månader",description:"Sena lagringssorter som Langedijker Bewaar 2 hängs upp och ner i en sval källare (0-4°C) med roten kvar. Hög luftfuktighet (90-95%) är nyckeln. Rödkål lagrar generellt lika bra som vitkål.",best:!0},{method:"Kylskåp",icon:"snowflake",duration:"2-4 veckor",description:"Lägg i plastpåse med några hål i grönsakslådan. Hela huvuden håller längre än delad kål. Rödkål håller sig faktiskt lite bättre i kylskåp än vitkål tack vare de tätare bladen.",best:!1},{method:"Syra/inlägga",icon:"storage",duration:"6-12 månader",description:"Strimla kålen fint, koka med ättika, socker och kryddnejlika. Klassisk svensk inläggning som passar perfekt till julbordet och viltkött. Kan även fermenteras som surkål.",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Strimla, blanchera 1-2 minuter, kyl i isvatten och frys i portionspåsar. Perfekt för grytor och tillagade rätter. Texturen ändras men smaken och den fina färgen består.",best:!1},{method:"Torka",icon:"storage",duration:"6-12 månader",description:"Strimla tunt och torka i ugn på 50°C eller i torkmaskin. Kompakt och platssnålt. Färgen bleknar något men smaken håller sig bra.",best:!1}],tips:["Lagringssorter (Langedijker Bewaar 2) håller MYCKET längre än tidiga sorter - välj rätt sort om du vill lagra","Skörda lagringskål så sent som möjligt på hösten - gärna efter en lätt frost. Det förbättrar hållbarheten.","Häng kålhuvudena upp och ner i källaren med roten kvar - det förlänger lagringstiden rejält","Syrad rödkål är enklare att göra än du tror och resultatet blir fantastiskt till jul och höstmiddagar","Kontrollera lagrad kål regelbundet och ta bort blad som börjar bli sladdriga - resten av huvudet är ofta helt fint under"]},harvestCalc:{minPerSqm:2,maxPerSqm:6,unit:"kg"}},Ra=Object.freeze(Object.defineProperty({__proto__:null,rodkal:or},Symbol.toStringTag,{value:"Module"})),dr={name:"Rosmarin",icon:"rosmarin",category:"kryddor",family:"Kransblommiga",familyLatin:"Lamiaceae",perennial:!0,lifespan:"10-15+ år (i kruka 5-10 år)",difficulty:"Medel",difficultyWhy:"Rosmarin är egentligen lättskött - men den svenska vintern är hennes fiende. I de flesta zoner måste hon tas in eller skyddas noggrant. Klarar du övervintringen har du en trogen vän i många, många år.",zones:{outdoor:[1,2],indoor:[1,2,3,4,5,6,7,8],greenhouse:[1,2,3,4,5,6]},days:"80-120",spacing:"40-60 cm",rowSpacing:"60 cm",depth:"0.5 cm",depthNote:"Ytligt - fröna vill ha ljus",ph:{min:6,max:8,ideal:7},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Rosmarin är en riktig solälskare - hon kommer från Medelhavets torra, solstekta kuster. Ge henne minst 6-8 timmars sol per dag. I halvskugga blir hon ranglig och doften svagare. Söderläge vid en varm mur? Perfekt - hon älskar den extra värmen."},temperature:{min:-10,max:35,ideal:"18-24°C",detail:"Medelhavsväxt som trivs bäst i värme. Etablerade plantor klarar ner till -10°C, och den extra härdiga sorten Arp kan klara -15°C om hon står TORRT och skyddat. Våta, kalla vintrar är det som dödar. I zon 3+ måste hon in - antingen i växthus eller i fönsterkarmen."},wind:{level:"Tålig",detail:"Rosmarins vedartade växtsätt och smala, läderartade barr gör henne överraskande vindtålig. Hon växer vilt på utsatta klippor vid Medelhavet. Vind hjälper till att hålla henne torr - och torrt är bra."}},watering:{need:"Låg",icon:"water",summary:"Rosmarin HATAR blöta fötter. Hon är uppvuxen på Medelhavets torra klippor och vill ha det likadant här. Torka ut ordentligt mellan vattningarna - hellre för lite än för mycket.",phases:[{phase:"Etablering (första månaden)",need:"Medel",tip:"Vattna regelbundet den första månaden så rötterna hittar ner. Men aldrig så att jorden står blöt - dränering är allt. När hon börjar växa synligt har hon landat."},{phase:"Etablerad planta (sommar)",need:"Låg",tip:"Vattna bara vid långvarig torka. Rosmarin klarar veckors torka utan problem. Jorden ska torka ut helt mellan vattningarna. Känner du fukt 3-4 cm ner? Vänta."},{phase:"Vinter (inomhus)",need:"Låg",tip:"Vattna sparsamt men låt INTE jorden torka ut helt - torr luft inomhus i kombination med uttorkad jord dödar. Känn med fingret varannan vecka. Lite fuktig, aldrig blöt."}],mistakes:["Övervattnar - den absolut vanligaste dödsorsaken. Rötterna ruttnar i blöt jord fortare än du tror","Planterar i tung lerjord utan dränering - en dödsdom för rosmarin","Glömmer att vattna inomhus på vintern - torr inomhusluft suger fukten ur henne","Vattnar ovanifrån i tät buske - fukt vid basen ger stamröta"],tip:"Tumregel: är du osäker, vänta med vattningen. Rosmarin klarar torka hundra gånger bättre än övervattning. Doft-testet funkar: klicka på barren - stark doft = mår bra, svag doft = kolla rötterna."},soil:"Rosmarin vill ha väldränerad, mager jord - gärna sandig eller grusig. Tänk Medelhavets steniga kustsluttningar. För rik jord ger visserligen mer tillväxt, men svagare arom och sämre vinterhärdighet.",soilTips:["Blanda in rikligt med sand eller grus i planteringsgropen - rosmarin vill ha jord som släpper igenom vatten direkt","I kruka: blanda hälften planteringsjord, hälften perlit eller grus. Lager grus i botten. Krukan MÅSTE ha dräneringshål","Undvik att blanda in kompost - rosmarin trivs faktiskt bättre i mager jord. Rikare jord ger svagare doft","Ett lager grus eller småsten runt plantan håller fukten borta från stammen och ger värmeåterstrålning - hon älskar det"],timeline:{1:[{phase:"Förodling/sticklingar inomhus",months:"Mars-april",icon:"indoor"},{phase:"Utplantering",months:"Maj-juni",icon:"seedling"},{phase:"Skörd löpande",months:"Maj-okt",icon:"harvest"},{phase:"Blomning",months:"Juni-juli",icon:"flower"},{phase:"Vinterskydd",months:"Nov-mars",icon:"snowflake"}],4:[{phase:"Sticklingar/köp planta",months:"April",icon:"indoor"},{phase:"Utplantering (växthus/kruka)",months:"Juni",icon:"seedling"},{phase:"Skörd löpande",months:"Juni-sept",icon:"harvest"},{phase:"Ta in (frostfritt)",months:"Oktober",icon:"indoor"},{phase:"Övervintring inomhus",months:"Nov-april",icon:"snowflake"}],6:[{phase:"Sticklingar/köp planta",months:"April-maj",icon:"indoor"},{phase:"Odla i växthus/kruka",months:"Juni-sept",icon:"indoor"},{phase:"Skörd löpande",months:"Juni-sept",icon:"harvest"},{phase:"Ta in (frostfritt)",months:"Sept",icon:"indoor"},{phase:"Övervintring inomhus",months:"Okt-maj",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:3,P:2,K:2},{month:"Maj",N:4,P:3,K:3},{month:"Jun",N:5,P:3,K:4},{month:"Jul",N:4,P:3,K:5},{month:"Aug",N:3,P:2,K:4},{month:"Sep",N:2,P:1,K:3}],nutritionTips:[{timing:"Tidig vår",tip:"En tunn giva kompost runt plantan när hon vaknar på våren. Rosmarin är ingen storätare - hon klarar sig med lite. Övergödslad rosmarin tappar sin fantastiska doft."},{timing:"Försommar",tip:"En svag giva nässelvatten om plantan ser blek ut. Men överdriv aldrig - magra förhållanden ger starkast arom. Tänk: hennes bästa vänner i Medelhavet är sten och sol, inte gödsel."},{timing:"Höst",tip:"Strö lite vedaska runt plantan i september. Kaliumet stärker vinterhärdigheten - och rosmarin gillar det svagt basiska. Sluta gödsla senast en månad före första frost."},{timing:"Obs!",tip:"Gödsla ALDRIG kraftigt. Rosmarin vill ha det magert - det är i kamp och torka som de eteriska oljorna koncentreras och doften blir fantastisk. Övergödslad rosmarin = stor planta utan själ."}],companions:{good:[{id:"morot",name:"Morot",icon:"vegetable",why:"Rosmarins starka doft förvirrar morotsflugan som navigerar efter lukt. En klassisk kombination som verkligen fungerar. Plantera rosmarin som kant runt morotslandet."},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Rosmarins intensiva doft avskräcker bladlöss och sniglar som annars älskar sallat. Sallaten drar nytta av rosmarins beskyddande aromdimma."},{id:"artor",name:"Ärtor",icon:"vegetable",why:"Baljväxter fixerar kväve i jorden som rosmarin kan dra nytta av. Ärtor ger dessutom lite skugga åt rosmarins bas under heta sommardagar."}],bad:[{id:"basilika",name:"Basilika",icon:"herb",why:"Basilika vill ha rik, fuktig jord. Rosmarin vill ha mager, torr jord. De pratar helt enkelt olika språk och ingen av dem kan kompromissa."},{id:"mynta",name:"Mynta",icon:"herb",why:"Myntan är aggressiv och sprider sig överallt via utlöpare. Hon tar över rosmarins plats på nolltid. Dessutom vill mynta ha fuktigare förhållanden."}]},rotation:{avoid:[{id:"rosmarin",name:"Rosmarin"},{id:"timjan",name:"Timjan"},{id:"salvia",name:"Salvia"}],avoidWhy:"Kransblommiga (Lamiaceae) delar en del jordburna sjukdomar. Men rosmarin är perenn och bör stå kvar på samma plats i många år - flytta bara om plantan dör eller blir för stor.",goodBefore:[{name:"Baljväxter"},{id:"lok",name:"Lök"},{name:"Rotsaker"}],goodBeforeWhy:"Baljväxter berikar jorden med kväve. Lök och rotsaker lämnar ren jord. Alla dessa är bra föregångare för rosmarin.",goodAfter:[{id:"morot",name:"Morot"},{name:"Kål"},{id:"sallat",name:"Sallat"}],goodAfterWhy:"Rosmarins aromatiska rester i jorden har mild desinficerande effekt. Bra för grönsaker som är känsliga för jordburna sjukdomar."},varieties:[{name:"Salem",zones:[1],note:"Upprätt växtsätt med fin, balanserad arom. Inte speciellt härdig - odlas bäst i kruka som tas in på vintern. Populär i mildare klimat men kräver skydd i Sverige."},{name:"Arp",zones:[1,2],note:"Den mest vinterhärdiga sorten - kan klara ner till -15°C i torr, väldränerad jord! Ljusare, grågrön blad. Lite mildare smak men väl värd det för härdigheten. Bästa valet om du vill prova utomhusodling."},{name:"Vanlig rosmarin (Salvia rosmarinus)",zones:[1],note:"Klassikern med kraftig, kamferliknande arom. Upprätt buske som kan bli 1-1.5 meter i milda klimat. Bäst i kruka i Sverige - lätt att ta in på vintern. Tidigare kallad Rosmarinus officinalis."},{name:"Krypande rosmarin (Prostratus)",zones:[1],note:"Krypande/hängande växtsätt, perfekt i amplar och stenmurar. Vacker när hon hänger ner. Mindre härdig - måste alltid tas in på vintern. Blommar rikligt med blå blommor."}],problems:[{name:"Rotröta (väta)",symptom:"Plantan gulnar och vissnar trots att jorden är fuktig. Stammens bas är mörk och mjuk. Barren faller av.",fix:"Tyvärr ingen bot när rotröta slagit till. Förebygg med väldränerad jord och sparsam vattning. Rädda friska kvistar som sticklingar och starta om. Ren sand i botten av krukan gör underverk."},{name:"Mjöldagg",symptom:"Vitt, mjölaktigt pulver på barren. Vanligast vid fuktig luft och dålig luftcirkulation.",fix:"Klipp bort angripna delar. Se till att plantan står luftigt. En blandning av vatten och lite bakpulver kan sprayas som skydd. Bästa förebyggandet: god luftcirkulation och inte för tät placering."},{name:"Vinterskador",symptom:"Bruna, torra grenar på våren. Barren är grå och spricker sönder mellan fingrarna. Ingen ny tillväxt.",fix:"Vänta tills maj innan du ger upp! Rosmarin kan se död ut men skjuta skott från basen. Klipp försiktigt av torrt virke. Förebygg: vinterskydd med granris, dränerande jord, skyddat läge vid husmur."},{name:"Bladlöss",symptom:"Klibbiga barr, deformerade skottspetsar. Små gröna eller svarta löss samlade vid topparna.",fix:"Ovanligt på frisk rosmarin tack vare de starka eteriska oljorna. Spola av med vatten. Stress (för mörkt, för blött) gör henne känsligare - åtgärda grundproblemet."}],goodToKnow:[{icon:"warning",title:"Vintern - rosmarins stora utmaning i Sverige",text:"Rosmarin klarar INTE svensk vinter i de flesta zoner. I zon 3-8 måste hon tas in eller stå i frostfritt utrymme. Även i zon 1-2 behöver hon skyddad plats, väldränerad jord och vinterskydd med granris. Det är kyla + väta som dödar - torr kyla klarar hon bättre.",severity:"warning"},{icon:"warning",title:"Dränering - viktigare än allt annat",text:"Blöta fötter är den vanligaste dödsorsaken. Rosmarin ruttnar i tung, fuktig jord snabbare än du hinner blinka. Plantera i sandblandad jord, använd grus i botten av krukor, och välj alltid en upphöjd plats där vatten rinner undan.",severity:"warning"},{icon:"tip",title:"Sticklingar - enklaste sättet att föröka",text:"Glöm frö - sticklingar är det överlägset enklaste sättet att få ny rosmarin. Klipp en 10 cm kvist, ta bort nedre barren, sätt i fuktig sand. Rötter på 3-4 veckor. Vill du vara extra säker? Be en granne om en kvist - rosmarin delar man gärna.",severity:"tip",refs:[{id:"timjan",name:"Timjan"}]},{icon:"tip",title:"Ät henne - hon tål det!",text:"Rosmarin mår faktiskt BRA av att beskäras regelbundet. Skörda genom att klippa kvistar - det stimulerar ny tillväxt och håller busken kompakt. Skörda aldrig mer än en tredjedel åt gången.",severity:"tip"},{icon:"tip",title:"Bina älskar henne",text:"Rosmarins blå blommor är fulla av nektar och blommar tidigt på året - en viktig tidig matkälla för bin och humlor. Rosmarinhonung är en exklusiv delikatess i Medelhavsländerna. Låt gärna en del av busken blomma!",severity:"tip"}],sowing:{method:"indoor",label:"Sticklingar eller förodling",description:"Rosmarin kan sås från frö, men det är LÅNGSAMT och opålitligt - groningen tar 2-4 veckor och många frön gror aldrig. Sticklingar är det överlägset enklaste och snabbaste sättet. Be en kompis om en kvist eller köp en planta och ta sticklingar från den.",steps:["Klipp en 10-15 cm kvist från en frisk planta (gärna halvförvedade skott)","Ta bort barren på nedre halvan av stickningen","Doppa gärna i rotningshormon (inte nödvändigt men snabbar på processen)","Sätt i fuktig sand eller perlit - tryck ner 3-4 cm","Håll fuktigt men inte blött. Täck gärna med plastpåse för att hålla luftfuktigheten","Ställ ljust men inte i direkt sol. Rötter bildas på 3-6 veckor","När rötterna är 2-3 cm långa: plantera om i kruka med sandig jord","Härda av successivt innan utplantering (om den ska ut)"],tips:["Sticklingar från halvförvedade skott (inte helt nya, inte helt vedartade) rotar sig bäst","Ta sticklingar på sensommaren (aug-sept) - då har du tid att etablera plantor innan vintern","Vill du så frö? Var beredd på att det tar 2-4 veckor för groning och att bara 30-50% gror. Värme (20-25°C) och tålamod krävs","Köp-plantor från trädgårdshandeln är ofta den enklaste starten - ta sedan sticklingar från den"],indoorWeeks:"8-10 veckor före utplantering (om du sår från frö)"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!1,description:"Rosmarin sätter frö, men groningsprocenten är låg (30-50%) och det tar lång tid. I svenskt klimat hinner fröna sällan mogna ordentligt utomhus. Sticklingar är ett mycket enklare och pålitligare sätt att föröka rosmarin.",steps:["Låt blommorna sitta kvar och mogna till frö (sommar-höst)","Vänta tills de små nötlikande fröna mörknar och faller lätt","Klipp av blomstjälkarna och skaka ut fröna över papper","Rensa bort skräp och blomrester","Låt fröna eftertorka en vecka inomhus","Förvara svalt och torrt i märkt kuvert"],isolation:"Rosmarin korspolleras av insekter. I praktiken spelar det liten roll i Sverige eftersom vi har så få sorter i odling. Sticklingar ger garanterat samma sort.",storageYears:"2-3 år (men groningsprocenten sjunker snabbt)",tip:"Skippa fröförökning - ta sticklingar istället! En enda planta kan ge dig tio nya på en säsong, alla identiska med mamman och med garanterad groningssuccé."},storage:{shelfLife:"10-14 dagar (färsk)",methods:[{method:"Torkning (bäst!)",icon:"storage",duration:"12+ månader",description:"Rosmarin är en av de bästa kryddorna att torka - hon behåller sin arom fantastiskt. Häng kvistar uppochner på en torr, luftig plats i 1-2 veckor. Eller torka i ugn på 40°C i 2-3 timmar. Barren lossnar lätt från kvisten när de är torra.",best:!0},{method:"Frysning",icon:"snowflake",duration:"6+ månader",description:"Lägg hela kvistar i en fryspåse och frys direkt. Dra av barren när du behöver dem - de lossnar ännu lättare frysta. Fin metod om du vill ha en mer färsk smak än torkad.",best:!1},{method:"Färsk i kyl",icon:"water",duration:"10-14 dagar",description:"Linda kvistarna i fuktigt hushållspapper och lägg i en plastpåse i kylen. Rosmarins sega, läderartade barr håller sig överraskande länge. Eller ställ som en bukett i ett glas vatten.",best:!1},{method:"Rosmarinsmör",icon:"storage",duration:"3-6 månader (fryst)",description:"Finhacka rosmarin och blanda in i rumstempererat smör. Rulla i plastfolie till en korv och frys. Skär av skivor direkt till kött, potatis eller bröd. Himmelskt.",best:!1}],tips:["Torkad rosmarin är starkare i smak - använd ungefär halva mängden jämfört med färsk","Rosmarinbarr är sega även färska - hacka fint om du inte vill ha hela barr i maten","Förvara torkad rosmarin i mörkt, lufttätt glas - håller aromen i över ett år","Hela kvistar i grytor och stekpannor ger fin smak och är lätta att plocka bort efteråt"]},harvestCalc:{minPerSqm:.2,maxPerSqm:.5,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp kvistar, aldrig mer än en tredjedel åt gången",description:"Skörda rosmarin genom att klippa av hela kvistar med en vass sax. Ta aldrig mer än en tredjedel av busken - hon behöver sina barr för att fotosyntetisera och överleva vintern. Klipp ovanför en bladkrans så nya sidoskott kan växa ut.",uses:[{use:"Stekt och grillat kött",tip:"DEN klassiska rosmarinpartnern. Lägg hela kvistar på köttet vid stekning eller grillning. Lamm + rosmarin + vitlök = matkärlek."},{use:"Rostad potatis",tip:"Hacka rosmarin och blanda med olivolja, salt och vitlök. Vänd ner potatisklyftor och rosta i ugn. Enkelt och oförglömligt gott."},{use:"Bröd och focaccia",tip:"Strö rosmarinbarr och grovt salt på focacciadegen innan gräddning. Eller baka in hackad rosmarin i bröddegen - doften när den gräddas!"},{use:"Rosmarinte",tip:"Häll kokande vatten över en kvist rosmarin. Låt dra 5-10 minuter. Uppfriskande och sägs vara bra för minnet och koncentrationen."}]}},Ea=Object.freeze(Object.defineProperty({__proto__:null,rosmarin:dr},Symbol.toStringTag,{value:"Module"})),mr={name:"Rotselleri",icon:"rotselleri",family:"Flockblommiga",familyLatin:"Apiaceae",difficulty:"Avancerad",difficultyWhy:"Extremt lång säsong (180+ dagar) kräver tidig förodling inomhus redan i februari. Känslig för torkstress och kräver jämn fukt hela säsongen. Inget för den otålige.",zones:{outdoor:[1,2,3,4],indoor:null,greenhouse:[1,2,3,4,5,6]},days:"180-220",spacing:"35-40 cm",rowSpacing:"40-50 cm",depth:"0.5 cm",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Trivs bäst i full sol men klarar halvskugga. I skugga blir knölen mindre och mognar långsammare - och hon behöver verkligen all tid hon kan få."},temperature:{min:5,max:28,ideal:"15-21°C",detail:"Groningstemperatur 18-22°C. Tål lätt frost ner till -3°C men trivs inte i kyla. Värme över 25°C stressar henne och hon kan börja gå i blom istället för att satsa på knölen."},wind:{level:"Skyddat",detail:"Uppskattar ett skyddat läge. Blasten kan bli hög men stjälkarna är sköra. Vinden torkar också ut jorden snabbt - och hon vill ha det jämnt fuktigt."}},watering:{need:"Hög",icon:"water",summary:"Rotsellerin är en riktig vattenälskare. Jämn fukt hela säsongen är nyckeln - hon får panik av torka och svarar med ihåliga, vediga knölar.",phases:[{phase:"Förodling (feb-apr)",need:"Medel",tip:"Håll jorden jämnt fuktig men aldrig blöt. Små plantor är känsliga för svampangrepp vid för mycket fukt. Spraya med finfördelat vatten."},{phase:"Etablering (maj-jun)",need:"Hög",tip:"Kritisk period! Nyplanterade plantor måste aldrig torka ut. Vattna dagligen första veckan, sedan varannan dag. Mulcha genast för att hålla fukten."},{phase:"Knölbildning (jul-aug)",need:"Hög",tip:"NU bygger hon knölen - torka nu ger ihålig, svampig selleri. Ge minst 25 mm vatten per vecka. Djupvattna ordentligt istället för lite och ofta."},{phase:"Mognad (sep-okt)",need:"Medel",tip:"Minska vattningen gradvis. Knölen ska koncentrera smak nu. Sluta vattna helt sista veckan före skörd för bättre lagring."}],mistakes:["Låta jorden torka ut under knölbildningen - ger ihålig, vedartad selleri","Vattna lite och ofta istället för ordentliga djupvattningar","Glömma mulch - selleris ytliga rötter torkar snabbt utan markskydd","Övervattna under förodling - ger rotröta och svampangrepp på de små plantorna"],tip:"Mulcha ordentligt med gräsklipp eller halm direkt vid utplantering. Rotsellerin har ytliga rötter som torkar ut snabbt i bar jord. Mulchen är din bästa vän hela säsongen."},soil:"Djup, näringsrik, fuktighetshållande jord. Hon är en storätare som vill ha det bördigt och fuktigt - tänk kompostrik trädgårdsjord med bra struktur.",soilTips:["Blanda in rikligt med väl brunnen kompost - rotsellerin är en av de mest näringskrävande grödorna","Undvik nygödslad jord med färsk gödsel - det ger deformerade knölar","I lerjord: blanda in sand och kompost för bättre dränering utan att tappa fukthållning","Kalka om pH är under 6.0 - hon trivs inte i sur jord"],timeline:{1:[{phase:"Förodla inomhus",months:"Feb-Mar",icon:"seedling"},{phase:"Härda av",months:"Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj",icon:"sprout"},{phase:"Knölbildning",months:"Jul-Aug",icon:"growth"},{phase:"Skörd",months:"Okt-Nov",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Feb",icon:"seedling"},{phase:"Härda av",months:"Maj",icon:"seedling"},{phase:"Plantera ut",months:"Maj-Jun",icon:"sprout"},{phase:"Knölbildning",months:"Jul-Sep",icon:"growth"},{phase:"Skörd",months:"Okt-Nov",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Feb",icon:"seedling"},{phase:"Härda av",months:"Jun",icon:"seedling"},{phase:"Plantera ut (växthus)",months:"Jun",icon:"sprout"},{phase:"Knölbildning",months:"Aug-Sep",icon:"growth"},{phase:"Skörd",months:"Sep-Okt",icon:"harvest"}]},nutritionData:[{month:"Mar",N:10,P:10,K:10,label:"Förodling"},{month:"Apr",N:20,P:15,K:10,label:"Tillväxt inomhus"},{month:"Maj",N:40,P:20,K:15,label:"Utplantering"},{month:"Jun",N:70,P:30,K:25,label:"Etablering"},{month:"Jul",N:80,P:50,K:40,label:"Knölbildning"},{month:"Aug",N:60,P:65,K:55,label:"Intensiv tillväxt"},{month:"Sep",N:30,P:70,K:70,label:"Mognad"},{month:"Okt",N:10,P:50,K:60,label:"Skörd"}],nutritionTips:[{timing:"Vid jordförberedelse",tip:"Grundgödsla rejält med väl brunnen kompost och gärna lite benmjöl. Rotsellerin är en storätare - var generös."},{timing:"Vid utplantering",tip:"Ge en startgiva med alggödsel eller brännässelvatten. Hon behöver en bra start efter den långa förodlingen."},{timing:"Under knölbildning (jul-aug)",tip:"Gödsla varannan vecka med flytande alggödsel eller kompostvatten. Kaliumrik gödsel (vedaska) stärker knölen."},{timing:"Från september",tip:"Sluta gödsla med kväve. Ge en sista giva kalium (vedaska) för bättre lagring och smakkoncentration."}],companions:{good:[{id:"lok",name:"Lök",icon:"lok",why:"Lökens starka doft förvirrar sellerifluga och morotsflugan som även angriper selleri"},{id:"purjolok",name:"Purjolök",icon:"purjolok",why:"Samma skyddande dofteffekt som lök, plus att de trivs i liknande jordförhållanden"},{id:"tomat",name:"Tomat",icon:"tomat",why:"Klassiskt par - tomaten drar nytta av sellerins aromatiska ämnen som håller skadedjur borta"},{id:"bondbona",name:"Bondböna",icon:"bondbona",why:"Fixerar kväve i jorden som sellerin tacksamt tar emot"}],bad:[{id:"morot",name:"Morot",icon:"morot",why:"Samma familj (flockblommiga) - delar skadedjur som sellerifluga och morotsflugan"},{id:"palsternacka",name:"Palsternacka",icon:"palsternacka",why:"Samma familj - ökar risken för sjukdomar och skadedjur"},{id:"dill",name:"Dill",icon:"dill",why:"Samma familj - lockar sellerifluga och delar sjukdomar"}]},rotation:{avoid:[{id:"morot",name:"Morot",category:"grönsaker"},{id:"palsternacka",name:"Palsternacka",category:"grönsaker"},{id:"persilja",name:"Persilja",category:"kryddor"},{id:"dill",name:"Dill",category:"kryddor"},{name:"Fänkål",category:"grönsaker"}],avoidWhy:"Alla flockblommiga delar sjukdomar och skadedjur. Sellerifluga, morotsflugan och septoria trivs i familjen. Vänta minst 4 år innan du odlar rotselleri på samma plats.",goodBefore:[{id:"artor",name:"Ärtor",category:"grönsaker"},{id:"bondbona",name:"Bondböna",category:"grönsaker"},{id:"potatis",name:"Potatis",category:"grönsaker"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden - perfekt för den kvävehungriga rotsellerin. Potatis luckrar jorden och lämnar bra struktur.",goodAfter:[{id:"artor",name:"Ärtor",category:"grönsaker"},{id:"lok",name:"Lök",category:"grönsaker"},{id:"sallat",name:"Sallat",category:"grönsaker"}],goodAfterWhy:"Baljväxter och lättnärda grönsaker fungerar bra efter sellerins intensiva näringsuttag. Lök sanerar jorden mot svampsjukdomar."},varieties:[{name:"Monarch",zones:[1,2,3,4],note:"Klassisk, pålitlig OP-kulturarvssort med stora, släta knölar och fin smak. Lagrar bra. Ekofrö hos Runåbergs."},{name:"Giant Prague",zones:[1,2,3,4],note:"Kulturarvssort (1871) med rejäla knölar. Gammal favorit som fortfarande levererar. Gedigen smak och bra lagringsförmåga."},{name:"Ibis",zones:[1,2,3,4],note:"OP-sort med jämna, runda knölar och få birötter. Lättskördad och rensar fint. Finns hos Lindbloms."},{name:"Prinz",zones:[1,2,3,4,5],note:"OP-sort med mycket jämna knölar och bra motståndskraft mot sjukdomar. Tål tuffare förhållanden. Ekofrö hos Lindbloms och Semenco."}],problems:[{name:"Sellerifluga (Euleia heraclei)",symptom:"Blåsor och bruna gångar i bladen, larver minerar inuti bladskivan",fix:"Fiberduk vid utplantering och hela säsongen. Plocka bort angripna blad. Samodla med lök som förvirrar flugan."},{name:"Septoria (bladfläcksjuka)",symptom:"Bruna fläckar med mörka prickar på bladen, bladen gulnar och dör",fix:"Bra luftcirkulation, inte för tätt. Ta bort sjuka blad direkt. Undvik övervattning på bladen - vattna vid markytan."},{name:"Ihålig knöl",symptom:"Knölen blir svampig och ihålig inuti, vedartad konsistens",fix:"Jämn vattning hela säsongen - det här är nästan alltid torkstress. Mulcha ordentligt och djupvattna regelbundet."},{name:"Blommning (skottskjutning)",symptom:"Plantan skjuter blomstjälk istället för att bilda knöl",fix:"Undvik kyla under förodling (aldrig under 10°C längre perioder). Härda av försiktigt. En planta som gått i blom kan inte räddas."}],goodToKnow:[{icon:"warning",title:"Starta tidigt - redan i februari!",text:"Rotsellerin behöver 180-220 dagar. Missar du förodlingsfönstret i februari-mars hinner knölen aldrig bli stor. Det här är inte en gröda man spontansår i maj.",severity:"warning"},{icon:"warning",title:"Plantera inte för djupt",text:"Knölens krona ska ligga i marknivå eller strax ovanför. Planterar du för djupt får du deformerade knölar och rotröta. Tryck ner henne lagom.",severity:"warning"},{icon:"tip",title:"Ta bort yttre birötter",text:"Under sensommaren kan du försiktigt böja undan jord och klippa bort birötter som växer ut från knölens sidor. Det ger en slätare knöl och mindre rensarbete i köket.",severity:"tip"},{icon:"tip",title:"Tål lätt frost - skörda sent",text:"Rotsellerin tål frost ner till -3°C. Sena skördar i oktober-november ger större knölar och mer koncentrerad smak. Ingen brådska att plocka upp henne förrän det börjar bli riktigt kallt.",severity:"tip"},{icon:"tip",title:"Hela plantan är ätbar",text:"Blasten har en fantastisk, intensiv selleriSmak. Använd den i soppor, buljonger och som krydda. Stjälkarna funkar som smakgivare i grytor. Ingenting behöver kastas.",severity:"tip"},{icon:"calendar",title:"Inte samma sak som stjälkselleri",text:"Rotselleri och stjälkselleri är olika varianter av samma art. Rotsellerin bildar en stor knöl under marken medan stjälksellerin satsar på tjocka stjälkar. Blanda inte ihop sorterna!",severity:"tip"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Rotsellerin MÅSTE förodlas inomhus - den extremt långa säsongen (180+ dagar) gör direktsådd omöjlig i Sverige. Starta i februari för att ge henne en chans.",steps:["Fyll små krukor eller pluggbrätte med frösåjord, fukta ordentligt","Strö fröna på ytan - de är ljusgroende och ska INTE täckas med jord","Tryck till fröna lätt mot jorden så de får kontakt","Täck med plastfolie eller lock för att hålla fukten","Ställ varmt (18-22°C) - groningen tar 14-21 dagar, ha tålamod","Ta bort plasten så fort groddar syns och ge maximalt ljus","Omplantera till 8 cm krukor när plantorna har 2-3 riktiga blad","Härda av gradvis i 1-2 veckor innan utplantering efter sista frost","Plantera ut när natttemperaturen stabilt håller sig över 8-10°C"],tips:["Placera fröna i kylskåp 2-3 dagar innan sådd - kylbehandling (stratifiering) kan förbättra groningen","Undvik temperaturer under 10°C under förodlingen - det triggar blommning senare","Ge extra belysning om du startar tidigt i februari - plantorna behöver 12-14 timmars ljus"],indoorWeeks:"10-12 veckor"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Rotselleri är tvåårig och bildar frö först andra året. Knölen måste övervintras inomhus i svalt utrymme och planteras ut igen på våren. Kräver planering och tålamod.",steps:["Välj de bästa, friskaste knölarna vid skörd - jämna, runda med få birötter","Klipp av blasten till ca 5 cm, lämna hjärtbladen intakta","Lagra knölarna i fuktig sand vid 0-4°C över vintern (källare fungerar bra)","Plantera ut knölarna på våren så fort jorden kan bearbetas","Blomstjälken skjuter upp under sommaren - vita flockblommor","Låt fröna mogna tills flockarna blir bruna","Klipp av och torka inomhus i papperspåsar","Gnugga loss fröna och rensa från skal och skräp"],isolation:"Korsar med stjälkselleri och andra sellerityper. Isolera med minst 800 m, eller odla bara en typ. Vild selleri förekommer inte i Sverige.",storageYears:"3-5 år",tip:"Frötagning från F1-hybrider ger ojämna resultat. Använd OP-sorter som Monarch eller Giant Prague om du vill spara frö. Föreningen Sesam har bra information om selleri-fröbesparing."},storage:{shelfLife:"4-6 månader",methods:[{method:"Sandlåda i källare",icon:"storage",duration:"4-6 månader",description:"Den bästa metoden! Lägg knölarna i lager med fuktig sand i en låda. Förvara svalt (0-4°C) och mörkt. Kontrollera regelbundet att sanden håller sig fuktig. Knölarna ska inte röra varandra.",best:!0},{method:"Kylskåp",icon:"snowflake",duration:"2-4 veckor",description:"Linda i fuktig kökshandduk och lägg i plastpåse med hål. Fungerar för kortare lagring efter skörd. Håll koll på att handduken inte torkar ut.",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Skala, tärna och blanchera 2-3 minuter. Frys i portionspåsar. Perfekt för soppor, gratänger och mos. Konsistensen ändras men smaken är kvar.",best:!1},{method:"Torka",icon:"sun",duration:"12+ månader",description:"Skala och skär i tunna skivor. Torka i ugn på 50°C eller i torkmaskin tills helt spröda. Mal till pulver som krydda eller använd skivorna i soppor.",best:!1}],tips:["Ta bort blasten direkt vid skörd - den suger fukt och näring ur knölen","Tvätta INTE knölar som ska lagras länge - jordlagret skyddar","Kontrollera lagrade knölar regelbundet och ta bort eventuella ruttna exemplar","Rotselleri som börjar bli mjuk kan fortfarande användas i soppa och gryta"]},harvestCalc:{minPerSqm:2,maxPerSqm:4,unit:"kg"}},Ca=Object.freeze(Object.defineProperty({__proto__:null,rotselleri:mr},Symbol.toStringTag,{value:"Module"})),kr={name:"Sallat",icon:"sallat",family:"Korgblommiga",familyLatin:"Asteraceae",difficulty:"Enkel",difficultyWhy:"Snabb från sådd till skörd, tålig, och perfekt för nybörjare. Går att odla nästan var som helst - i landet, i kruka, på balkongen.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:[1,2,3,4,5,6,7,8],greenhouse:null},days:"30-90",spacing:"20-25 cm",rowSpacing:"30 cm",depth:"0.5 cm",depthNote:"Ljusgroddare - täck bara lätt",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Trivs i 4-6 timmar sol, men klarar halvskugga bra. Faktum är att lite skugga mitt på dagen kan vara en fördel - sallat som får för mycket sol och värme blir bitter och skjuter i blom."},temperature:{min:4,max:24,ideal:"12-18°C",detail:"En riktig svalvädersvän! Gror redan vid 4°C och trivs bäst när det är svalt. Över 24°C börjar hon stressa och skjuter i blom - och då blir smaken bitter."},wind:{level:"Tålig",detail:"Låg profil och inga speciella krav. Vinden är sällan ett problem."}},watering:{need:"Medel",icon:"water",summary:'Jämn fukt är nyckeln. Sallat har grunt rotsystem och torkar ut snabbt, men vill inte stå i vatten. Tänk "fuktig tvättsvamp" - aldrig blöt, aldrig torr.',phases:[{phase:"Groning (0-2 veckor)",need:"Hög",tip:"Fröna behöver fukt och ljus för att gro - täck knappt med jord och håll ytan fuktig. Spruta med en blomspruta istället för att vattna med kanna."},{phase:"Tillväxt (2-5 veckor)",need:"Medel",tip:"Vattna jämnt 2-3 gånger i veckan. Djupvattna hellre än att stänka lite ofta. Mulcha för att hålla fukten."},{phase:"Huvudbildning (5+ veckor)",need:"Medel",tip:"Fortsätt vattna jämnt. Torka nu ger bitter smak och stressar plantan att gå i blom."}],mistakes:["Vattnar på bladen i solsken - dropparna bränner och bjuder in svampsjukdomar","Ojämn vattning (torrt-blött-torrt) stressar plantan att skjuta i blom","Glömmer att sallat i kruka torkar ut MYCKET snabbare än i landet"],tip:"Mulcha med gräsklipp runt plantorna - det håller fukten, kyler jorden och gör att du slipper vattna lika ofta."},soil:"Lös, humusrik jord som håller fukt. Sallat har grunt rotsystem och vill ha fin, lucker jord i ytan.",soilTips:["Blanda in kompost i de översta 15 cm - sallat rotar inte djupt","Undvik nygrävd, klumpig jord - fröna är pyttelilla och behöver fin struktur","I kruka: vanlig planteringsjord fungerar utmärkt"],timeline:{1:[{phase:"Första sådd",months:"Mar-Apr",icon:"seedling"},{phase:"Skörd vår",months:"Maj-Jun",icon:"harvest"},{phase:"Andra sådd",months:"Jul-Aug",icon:"seedling"},{phase:"Skörd höst",months:"Sep-Okt",icon:"harvest"}],4:[{phase:"Första sådd",months:"Apr-Maj",icon:"seedling"},{phase:"Skörd",months:"Jun-Jul",icon:"harvest"},{phase:"Andra sådd",months:"Jul",icon:"seedling"},{phase:"Skörd höst",months:"Aug-Sep",icon:"harvest"}],6:[{phase:"Så",months:"Maj-Jun",icon:"seedling"},{phase:"Skörd",months:"Jul-Aug",icon:"harvest"}]},nutritionData:[{month:"Apr",N:30,P:15,K:20,label:"Groning"},{month:"Maj",N:65,P:25,K:35,label:"Bladtillväxt"},{month:"Jun",N:80,P:30,K:40,label:"Huvudbildning"},{month:"Jul",N:50,P:20,K:30,label:"Skörd"}],nutritionTips:[{timing:"Vid sådd",tip:"Grundgödsla med kompost. Sallat är inte jättehungrig men vill ha tillgängligt kväve för snabb bladtillväxt."},{timing:"Under tillväxt",tip:"En lätt giva flytande gödsel (brännässelvatten) varannan vecka ger fina, frodiga blad."},{timing:"Viktigt",tip:"Övergödsla INTE - för mycket kväve ger visserligen stora blad men också bitter smak och sämre hållbarhet."}],companions:{good:[{id:"morot",name:"Morot",icon:"morot",why:"Morötter och sallat kompletterar varandra perfekt - moroten rotar djupt, sallaten ytligt. Ingen konkurrens."},{id:"radisa",name:"Rädisa",icon:"vegetable",why:"Rädisan skördas innan sallaten behöver platsen - perfekt tajming"},{id:"artor",name:"Ärtor",icon:"vegetable",why:"Sallat trivs i halvskuggan under ärtorna och drar nytta av kvävet de fixar"},{id:"lok",name:"Lök",icon:"vegetable",why:"Lökdoften håller sallatsbitare som bladlöss på avstånd"}],bad:[{id:"selleri",name:"Selleri",icon:"vegetable",why:"Konkurrerar om samma utrymme och näringsämnen i ytan"},{id:"persilja",name:"Persilja",icon:"herb",why:"Samma problem - ytliga rötter som konkurrerar"}]},rotation:{avoid:[{id:"solros",name:"Solros"},{name:"Kronärtskocka"},{name:"Jordärtskocka"}],avoidWhy:"Alla korgblommiga delar sjukdomar som sallatsröta. Vänta 2-3 år.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{name:"Kål"}],goodBeforeWhy:"Baljväxter och kål lämnar kväve- och näringsrik jord som sallat trivs i.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"potatis",name:"Potatis"}],goodAfterWhy:"Rotgrönsaker och lök rotar djupare och drar nytta av en annan jordnivå."},varieties:[{name:"Lollo Rossa",zones:[1,2,3,4,5,6,7],note:"Vacker röd bladsallat. Tålig och långsam att skjuta i blom. Plocka blad för blad."},{name:"Salad Bowl",zones:[1,2,3,4,5,6,7,8],note:"Klassisk grön bladsallat med flikiga blad. Otroligt lättodlad och produktiv."},{name:"Isbergssallat Great Lakes",zones:[1,2,3,4,5],note:"Knaprig isbergssallat - den du köper i affären. Kräver lite mer plats och tid."},{name:"Batavia Leny",zones:[1,2,3,4,5,6],note:"Mellanting mellan isberg och bladsallat. Knaprig, tålig och smakar underbart."},{name:"Rucola",zones:[1,2,3,4,5,6,7,8],note:"Tekniskt inte sallat (korsblommig) men odlas likadant. Pepprig smak, superstark!"}],problems:[{name:"Sallaten skjuter i blom",symptom:"Stjälken sträcker sig uppåt, bladen blir tunna och bittra",fix:"Värme och torka triggar blomning. Odla i halvskugga under högsommar. Välj bolomtåliga sorter. Skörda tidigt - det går inte att vända."},{name:"Sniglar",symptom:"Stora oregelbundna hål i bladen, slemspår",fix:"Snigelkorn (järnfosfat), kopparhinder, ölsaxar. Vattna på morgonen så marken torkar till kvällen. Odla i upphöjd bädd."},{name:"Bladlöss",symptom:"Kolonier av gröna löss på undersidan av bladen",fix:"Spruta av med stark vattenstråle. Plantera dill och blommor intill för att locka nyttoinsekter. Fungerar löss sig ner i huvudet - skölj i saltvatten."},{name:"Gråmögel",symptom:"Gråbrunt ludd på blad och stjälk, ofta i fuktig väderlek",fix:"God luftcirkulation - inte för tätt. Vattna på morgonen vid roten. Ta bort drabbade blad direkt."}],goodToKnow:[{icon:"seedling",title:"Successionsådd - gyllene regeln",text:"Så en kort rad varannan vecka från april till augusti. Då har du alltid perfekt sallat istället för 20 huvuden samtidigt som alla skjuter i blom.",severity:"tip"},{icon:"warning",title:"Skjuter i blom i värme",text:"Över 24°C börjar sallat stressa och vill blomma. Bitter smak och gummigt blad. Under högsommar (juli) kan du pausa sådden och börja igen i augusti.",severity:"warning"},{icon:"leaf",title:"Plocka blad - inte hela huvudet",text:"Bladsallat skördas bäst genom att plocka de yttersta bladen och låta hjärtat växa vidare. En planta kan ge skörd i veckor!",severity:"tip"},{icon:"snowflake",title:"Tål lätt frost",text:"Sallat klarar frost ner till -3°C. Du kan så tidigt på våren och sent på hösten. Under fiberduk klarar den sig ännu längre.",severity:"tip"},{icon:"warning",title:"Fröna behöver ljus",text:"Sallatsfrön gror bäst i ljus - täck knappt med jord (max 0.5 cm). I mörker gror de dåligt. Tryck ner fröna i ytan och håll fuktig.",severity:"warning"}],sowing:{method:"both",label:"Direktsådd eller förodling",description:"Direktsådd utomhus är enklast, men förodling inomhus ger försprång. Bladsallat direktsås, huvudsallat förodlas ofta.",steps:["Kratta till fin jordyta - sallatsfrön är pyttelilla och behöver bra kontakt","Så tunt i grunt spår (max 0.5 cm djupt) eller strö på ytan och tryck ner lätt","Vattna försiktigt med stril - fröna får inte spolas bort","Fröna gror på 5-10 dagar beroende på temperatur","Gallra till 20-25 cm avstånd (ät gallringsplantorna som babysallat!)","Så ny omgång var 14:e dag för kontinuerlig skörd"],tips:["I värme (>25°C) gror sallatsfrön dåligt. Lägg fröna i kylskåp 2 dagar före sådd eller så på kvällen","Förodla i celler eller krukor inomhus 3-4 veckor före utplantering för tidigt försprång","Babysallat (skördas efter 3 veckor) behöver bara 5 cm avstånd - perfekt i kruka"],indoorWeeks:"3-4 veckor"},seedSaving:{difficulty:"Enkel",type:"Självpollinerare",biennial:!1,description:"Sallat är självpollinerare och ett av de enklaste fröerna att spara. Låt en planta gå i blom och samla fröna.",steps:["Låt en fin planta gå i blom (det hon normalt inte får göra)","Stjälken sträcker sig uppåt och bildar små gula blommor","Vänta tills fröfjunna (som maskrosor) börjar bildas","Klipp av blomstjälkarna och lägg i en papperspåse","Skaka påsen dagligen i en vecka - fröna lossnar","Sikta bort fjunen och skräpet","Förvara i papperspåse på sval, torr plats"],isolation:"Självpollinerare - korsar sällan. Olika sorter kan odlas nära varandra. 1-2 m avstånd är mer än tillräckligt.",storageYears:"1-3 år",tip:"Sallatsfrö tappar grobarhet snabbare i värme. Förvara i kylskåp för extra lång hållbarhet."},storage:{shelfLife:"1-2 veckor",methods:[{method:"Kylskåp i fuktig handduk",icon:"snowflake",duration:"5-10 dagar",description:"Skölj, centrifugera torrt i sallatsslungare, linda i fuktig hushållspapper och lägg i plastpåse med lite luft. Håller sig knaprig och fräsch.",best:!0},{method:"Stående i vatten",icon:"water",duration:"3-5 dagar",description:"Ställ hela huvudet med roten i en skål med lite vatten i kylskåpet. Fungerar som en bukett blommor - sallaten håller sig levande längre.",best:!1},{method:"Direkt från trädgården",icon:"leaf",duration:"Hela säsongen",description:"Den bästa lagringen! Lämna sallaten i jorden och plocka blad efter behov. Skörda på morgonen när bladen är som knaprigast.",best:!1}],tips:["Sallat ska ätas färsk - den förlorar näring och smak snabbt efter skörd","Skörda tidigt på morgonen när bladen är fulla av vatten och som knaprigast","Tvätta INTE sallat förrän du ska äta den - fukt gör att den ruttnar snabbare","Sallat fryses ALDRIG - den blir sörja. Det finns ingen bra långtidslagring."]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3,unit:"kg"}},Oa=Object.freeze(Object.defineProperty({__proto__:null,sallat:kr},Symbol.toStringTag,{value:"Module"})),gr={name:"Salvia",icon:"salvia",category:"kryddor",family:"Kransblommiga",familyLatin:"Lamiaceae",perennial:!0,lifespan:"4-6 år (förvedas med tiden)",difficulty:"Medel",difficultyWhy:"Själva odlingen är enkel, men övervintring är den stora utmaningen. Salvia hatar blöta fötter på vintern och kräver väldränerad jord och skydd i kallare zoner. Behöver också föryngringsbeskärning vart 3-4 år.",zones:{outdoor:[1,2,3,4,5],indoor:[1,2,3,4,5,6,7,8],greenhouse:[1,2,3,4,5,6,7,8]},days:"60-70 (blad), 100-130 (från frö till full planta)",spacing:"30 cm",rowSpacing:"35 cm",depth:"0.2 cm",depthNote:"Ljusgroddare - tryck fast men täck knappt",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Medelhavsväxt som kräver minst 6 timmars direkt sol per dag. I halvskugga blir salvian gles och smaken svagare. Söderläge mot en varm mur? Perfekt - det är som ett litet medelhavsparadis."},temperature:{min:-15,max:35,ideal:"15-25°C",detail:"Klarar ner till -15°C med snötäcke och väldränerad jord. Men det är inte kylan som dödar henne - det är fukten. En blöt höst följd av frost tar kål på salvian snabbare än ren vinterköld."},wind:{level:"Tålig",detail:"Halv buske med vedartade stammar - klarar vind bättre än de flesta kryddor. Men ett skyddat, soligt läge ger alltid bäst resultat och bättre övervintring."}},watering:{need:"Låg",icon:"water",summary:"Torktålig medelhavsväxt som mår bäst av att inte bli bortskämd med vatten. Bättre att låta jorden torka ut lite mellan vattningarna än att riskera blöta fötter.",phases:[{phase:"Nyplanterad (första månaden)",need:"Medel",tip:"Vattna regelbundet tills plantan etablerat sig - men aldrig så det står vatten. Korta, frekventa givor är bättre än att dränka henne."},{phase:"Etablerad planta",need:"Låg",tip:"Vattna bara vid långvarig torka. Salvian har djupa rötter och hittar fukt på egen hand. Övervattning är det farligaste du kan göra."},{phase:"Krukodlad",need:"Medel",tip:"I kruka torkar jorden snabbare - kolla med fingret och vattna när de översta 3 cm är torra. Bra dränering i botten är ett absolut måste."}],mistakes:["Övervattning - den absolut vanligaste dödsorsaken för salvia. Rötterna ruttnar i blöt jord","Vattnar sent på hösten - fuktig jord + frost = garanterad övervintringsdöd","Planterar i tung lerjord utan dränering - bäddar för problem"],tip:"Blanda in grus eller perlite i jorden vid plantering. Tänk medelhavsjord - mager, torr och väldränerad. Salvian tackar dig med intensiv arom."},soil:"Salvia vill ha genomsläpplig, gärna kalkrik jord med bra dränering. Tänk medelhavsjord - sandig, mager och aldrig vattensjuk. Blanda gärna in grus eller sand om du har tung jord.",soilTips:["Genomsläpplig jord är A och O - blanda in grus eller sand i tung lerjord","Kalkrik jord uppskattas - strö lite trädgårdskalk om du har sur jord","Behöver inte rik jord - mager jord ger faktiskt starkare arom","I kruka: blanda planteringsjord med 1/3 perlite eller grus för bra dränering"],timeline:{1:[{phase:"Förodling inomhus",months:"Feb-mar",icon:"indoor"},{phase:"Utplantering",months:"Maj",icon:"seedling"},{phase:"Blomning",months:"Jun-aug",icon:"flower"},{phase:"Skörd (löpande)",months:"Jun-okt",icon:"harvest"},{phase:"Vintertäckning",months:"Nov",icon:"snowflake"}],4:[{phase:"Förodling inomhus",months:"Mar-apr",icon:"indoor"},{phase:"Utplantering",months:"Slutet av maj-jun",icon:"seedling"},{phase:"Blomning",months:"Jul-aug",icon:"flower"},{phase:"Skörd (löpande)",months:"Jul-sep",icon:"harvest"},{phase:"Vintertäckning",months:"Okt",icon:"snowflake"}],6:[{phase:"Förodling inomhus",months:"Mar-apr",icon:"indoor"},{phase:"Utplantering",months:"Jun",icon:"seedling"},{phase:"Skörd",months:"Jul-aug",icon:"harvest"},{phase:"Storskord före frost",months:"Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:2,P:1,K:1},{month:"Maj",N:3,P:2,K:2},{month:"Jun",N:4,P:3,K:3},{month:"Jul",N:4,P:3,K:3},{month:"Aug",N:3,P:2,K:2},{month:"Sep",N:1,P:1,K:1}],nutritionTips:[{timing:"Vår (april-maj)",tip:"En lätt giva kompost runt plantan räcker gott. Salvia är anspråkslös och mår bäst av mager jord - övergödsling ger stor planta men svag smak."},{timing:"Sommar",tip:"Ingen extra gödsling behövs. Salvian klarar sig fint med det som finns i jorden. Mager jord ger faktiskt starkare eteriska oljor."},{timing:"Obs!",tip:"Kväverik gödsel ger frodigt bladverk men slapp växt som övervintrar dåligt. Håll det spartanskt - salvian tackar dig med intensivare arom."}],companions:{good:[{id:"vitkal",name:"Kålväxter",icon:"vegetable",why:"Salvians starka doft avskräcker kålfjärilar och kålmalar. Plantera salvia runt kålodlingen som en naturlig insektsbarriär."},{id:"morot",name:"Morot",icon:"vegetable",why:"Salvian avskräcker morotsflugan med sin intensiva doft. Ett klassiskt och beprövat kompanjonpar."},{id:"rosmarin",name:"Rosmarin",icon:"herb",why:"Medelhavskompisar! Exakt samma krav på sol, dränering och mager jord. Trivs fantastiskt ihop i ett kryddland."},{id:"timjan",name:"Timjan",icon:"herb",why:"Liknande odlingskrav - båda vill ha torrt, magert och soligt. Bildar ett fint medelhavshörn i trädgården."}],bad:[{id:"gurka",name:"Gurka",icon:"vegetable",why:"Salvia hämmar gurkans tillväxt. Helt olika behov - gurkan vill ha fukt och näring, salvian vill ha torrt och magert."},{id:"basilika",name:"Basilika",icon:"herb",why:"Helt olika krav! Basilika vill ha rik, fuktig jord - raka motsatsen till salvia. Deras eteriska oljor sägs dessutom störa varandra."},{id:"lok",name:"Lök",icon:"vegetable",why:"Trivs inte nära varandra - olika krav och kemisk oförenlighet i jorden."}]},rotation:{avoid:[{id:"salvia",name:"Salvia"},{id:"mynta",name:"Mynta"},{id:"basilika",name:"Basilika"},{id:"oregano",name:"Oregano"}],avoidWhy:"Kransblommiga (Lamiaceae) delar jordburna sjukdomar. Plantera inte ny salvia där gammal salvia stått - vänta minst 3 år.",goodBefore:[{name:"Kålväxter"},{name:"Rotgrönsaker"}],goodBeforeWhy:"Salvia lämnar väldränerad, ogödslad jord som passar bra för kål och rotfrukter.",goodAfter:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodAfterWhy:"Baljväxter berikar jorden med kväve. Men salvia är perenn - rotation gäller mest när du tar bort en gammal planta."},varieties:[{name:"Kryddsalvia (standard)",zones:[1,2,3,4,5],note:"Den klassiska, grågröna. Härdigast av alla och har odlats i Sverige sedan medeltiden. Ekologiskt frö hos Runåbergs. Kulturarv."},{name:"Extracta",zones:[1,2,3,4],note:"Silvergrå blad, extra aromatisk med blåvioletta blommor. Bra för torkning. Finns hos Impecta."},{name:"Purpurascens",zones:[1,2,3],note:"Mörkt vinröda blad med starkare smak. Vacker i rabatten men något mindre härdig - bäst i sydliga zoner."},{name:"Berggarten",zones:[1,2,3,4],note:"Stora, runda blad och kompakt växt. Blommar sällan - perfekt om du bara vill skörda blad. Favorit bland kockar."}],problems:[{name:"Övervintringsdöd (rotröta)",symptom:"Plantan dör under vintern eller tidig vår. Rötterna är brunsvarta och mjuka.",fix:"Förebygg med väldränerad jord - blanda in grus/sand vid plantering. Täck med granris på hösten. Undvik blöta lägen. Det är fukt, inte kyla, som tar kål på salvian."},{name:"Förvedning",symptom:"Plantan blir kålig och vedartad nerifrån efter 3-4 år, tappar blad.",fix:"Beskär varje vår (april-maj) - skär ner till friskt, grönt ved. Klipp aldrig in i helt bart ved. Föryngra genom sticklingar vart 3-4 år för friska, nya plantor."},{name:"Mjöldagg",symptom:"Vitt, mjölaktigt pulver på bladen, särskilt vid torrt väder med hög luftfuktighet.",fix:"Klipp bort drabbade delar. Ge bättre luftcirkulation. Undvik att vattna ovanifrån."},{name:"Bladlöss",symptom:"Gröna eller svarta små insekter på unga skott.",fix:"Friska plantor i full sol angrips sällan. Spola av med vatten vid behov. Salvian lockar själv nyttoinsekter med sina blommor."}],goodToKnow:[{icon:"tip",title:"Bättre torkad än färsk",text:"Salvia är en av få kryddor som faktiskt är GODARE torkad. Torkningen koncentrerar de eteriska oljorna och ger en mer avrundad, djup smak. De flesta kryddor tappar smak vid torkning - salvian gör tvärtom.",severity:"tip"},{icon:"warning",title:"Fukt dödar - inte kyla",text:"Salvian kan klara -15°C med snötäcke. Men en blöt höst följd av frost? Garanterad död. Väldränerad jord och granristäckning är de bästa livförsäkringarna. Tänk medelhav - torrt, magert, soligt.",severity:"warning"},{icon:"tip",title:"Kålfjärilens fiende",text:"Salvians starka doft avskräcker kålfjärilar och kålmalar. Plantera en rad salvia runt kålodlingen så slipper du halvätna blad. Biologisk bekämpning som dessutom ger dig krydda!",severity:"tip"},{icon:"warning",title:"Beskär varje vår - annars blir hon ful",text:"Utan vårskärning blir salvian vedartad och kal nerifrån efter 3-4 år. Klipp ner till grönt ved i april-maj så hon skjuter friska skott. Eller ta sticklingar och börja om - salvia rotar sig enkelt i fuktig sand.",severity:"warning"},{icon:"tip",title:"Klosterkrydda sedan medeltiden",text:'Namnet Salvia kommer från latinets "salvare" - att rädda. Munkar tog med den till Sverige redan på 800-talet. Ett gammalt latinskt ordspråk lyder: "Varför ska en människa dö som har salvia i sin trädgård?"',severity:"tip"}],sowing:{method:"indoor",label:"Förodling & sådd",description:"Salvia förodlas bäst inomhus på våren. Fröna är ljusgroddare - tryck fast dem på ytan men täck knappt. Gror på 10-21 dagar vid 20-25°C. Sticklingar och delning är snabbare alternativ för den otåliga.",steps:["Fyll krukor med fuktig såjord","Lägg fröna på ytan och tryck fast lätt - täck bara med ett hafs jord (ljusgroddare)","Håll jämnt fuktigt och varmt (20-25°C)","Groning på 10-21 dagar - tålamod krävs!","Gallra till 1 planta per kruka vid 2-3 örtblad","Härda av 1-2 veckor före utplantering","Plantera ut i väldränerad jord på solig plats efter sista frost"],tips:["Sticklingar (juli-aug) ger snabbare resultat - klipp 10 cm kvistar och sätt i fuktig sand","Dela etablerade plantor på våren - enklaste sättet att få nya plantor","Plantera gärna intill en sydvänd mur - extra värme och vindskydd","Blanda in grus i planteringsgropen för bästa dränering"],indoorWeeks:"6-8 veckor före utplantering"},seedSaving:{difficulty:"Medel",type:"Insektspollinerad",biennial:!1,description:"Salvia blommar vanligtvis från andra året. Låt blomställningarna torka på plantan och samla fröna när de mörknat. Groningsförmågan minskar snabbt - använd färskt frö för bäst resultat.",steps:["Låt plantan blomma ut (juni-augusti)","Vänta tills blomställningarna torkar och fröna mörknar (bruna/svarta)","Klipp av blomstjälkarna när fröhusen är bruna men inte helt öppna","Häng upp i papperspåse att eftertorka 1-2 veckor","Skaka ur fröna och rensa bort skal och skräp","Förvara i märkt kuvert eller glasburk, svalt och torrt"],isolation:"Kryddsalvia pollineras av humlor och bin. Håll ca 400 meters avstånd mellan sorter för sortrena frön. I praktiken räcker det ofta med mindre avstånd i en hemmaträdgård.",storageYears:"2-3 år (använd helst färskt frö)",tip:"Sticklingar och delning ger identiska kloner av din favoritplanta - snabbare och säkrare än frö. Men frösådd ger genetisk variation som kan ge spännande resultat!"},storage:{shelfLife:"1-2 veckor (färsk)",methods:[{method:"Torkning (bäst!)",icon:"storage",duration:"1+ år",description:"Bind små knippen och häng upp och ner på varm, luftig plats. Eller torka på galler. Salvia är en av få kryddor som faktiskt blir GODARE av att torkas - aromerna koncentreras.",best:!0},{method:"Frysning",icon:"snowflake",duration:"6-12 månader",description:"Hacka blad och frys i isbitsfack med lite olivolja. Eller frys hela kvistar på plåt och förvara i fryspåse. Behåller smaken bra.",best:!1},{method:"Salviesmör",icon:"storage",duration:"3-6 månader (fryst)",description:"Blanda finhackad salvia i rumstempererat smör, rulla till en rulle i plastfilm och frys. Skiva av vid behov - fantastiskt till pasta och potatis.",best:!1},{method:"Färsk (kort lagring)",icon:"water",duration:"1-2 veckor",description:"Ställ kvistar i ett glas vatten i kylen, eller linda i fuktigt hushållspapper. Salvias vedartade stammar gör att hon håller sig bra.",best:!1}],tips:["Torka hela blad i mörk, tätslutande burk - behåller aromerna fantastiskt länge","Stekta salviablad i smör (30 sek) = krispig delikatess direkt på pastan","Använd halva mängden torkad vs färsk - torkning koncentrerar smaken rejält","Skörda före blomning för starkaste smak i bladen"]},harvestCalc:{minPerSqm:.3,maxPerSqm:.8,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp kvistar och blad löpande under säsongen",description:"Skörda genom att klippa hela kvistar - det stimulerar ny tillväxt. Börja plocka när plantan är väletablerad med minst 6-8 bladpar. Skörda aldrig mer än en tredjedel av plantan åt gången.",uses:[{use:"Kött (lamm, fläsk, vilt)",tip:"DEN klassiska lammkryddan. Gnid in köttet med färska eller torkade blad före tillagning. Fungerar fantastiskt till jul-skinka och korv."},{use:"Pasta (burro e salvia)",tip:"Klassisk italiensk rätt: stek salviablad i smör tills de blir krispiga, häll över nykokad pasta. Enkelt, snabbt, gudomligt."},{use:"Torkad krydda",tip:"Torka i knippen och förvara i burk. Använd sparsamt - salvia är stark! Perfekt i grytor, soppor och fyllningar."},{use:"Te",tip:"Salviate (färska eller torkade blad i hett vatten) har traditionellt använts mot halsont. Mild, kryddigt smak som värmer."}]}},za=Object.freeze(Object.defineProperty({__proto__:null,salvia:gr},Symbol.toStringTag,{value:"Module"})),pr={name:"Savoykål",icon:"vegetable",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Medel",difficultyWhy:"Savoykål kräver lite tålamod och god planering - hon vill ha näringsrik jord, jämn fukt och skydd mot kålfjärilen. Men hon är faktiskt snällare än vitkål, tåligare mot frost och förlåter fler misstag. Det krusiga bladverket gör henne till en riktig skönhet i landet.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:[1,2,3,4,5,6,7,8]},days:"90-140",spacing:"40-50 cm",rowSpacing:"50-60 cm",depth:"1-2 cm",ph:{min:6.5,max:7.5,ideal:7},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmar sol per dag. Savoykål vill ha ordentligt med ljus för att bygga sina vackra, krusiga huvuden. I halvskugga blir huvudena mindre och lösare - hon ger sitt bästa i full sol."},temperature:{min:-10,max:25,ideal:"12-18°C",detail:"Savoykål är en riktig nordbo som trivs bäst i svalka runt 12-18°C. Hon tål frost imponerande bra - härdade plantor klarar ner till -10°C! Det gör henne perfekt för sen höstskörd. Över 25°C stressar hon och tillväxten bromsas."},wind:{level:"Skyddat",detail:"De krusiga bladen fångar vind effektivt. Ge henne lite vindskydd, eller kupa jord runt stambasen för stabilitet. I utsatta lägen kan hon välta med sina tunga huvuden."}},watering:{need:"Medel-Hög",icon:"water",summary:"Savoykål vill ha jämn fukt hela säsongen, men de krusiga bladen gör henne lite bättre på att hålla fukt än slätbladig kål. Ojämn vattning kan ändå göra att huvudena spricker.",phases:[{phase:"Förodling (0-6 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig men inte blöt. Kålfrön gror snabbt (5-10 dagar) vid rumstemperatur."},{phase:"Etablering (utplantering)",need:"Hög",tip:"Vattna rikligt vid utplantering och dagligen den första veckan. Nya kålplantor är törstiga och vill snabbt få fäste."},{phase:"Tillväxt och bladbildning",need:"Medel-Hög",tip:"Djupvattna 2-3 gånger i veckan. Nu bygger hon sitt fina, krusiga bladverk och varje blad som bildas blir en del av det kommande huvudet."},{phase:"Huvudbildning",need:"Hög",tip:"Kritisk period! Håll jämn fukt - plötsligt regn efter torka kan få huvudena att spricka. Hellre lite och ofta än stora svall."}],mistakes:["Ojämn vattning - torka följt av storvattning gör att huvudena spricker. Klassiskt nybörjarmisstag.","Vattna ovanifrån sent på kvällen - fuktiga krusiga blad torkar långsammare och bjuder in svampsjukdomar","Tro att kålen klarar sig själv bara för att hon ser tålig ut - speciellt under huvudbildningen behöver hon jämn fukt","Glömma bort vattning sent på hösten - savoykål som står kvar i kylan behöver fortfarande fukt"],tip:"Mulcha ordentligt med gräsklipp eller halm runt plantorna. De krusiga bladen samlar dagg naturligt, men rötterna behöver jämn markfukt. Mulchen hjälper enormt."},soil:"Näringsrik, kalkrik jord med bra struktur. Savoykål är en storätare precis som sin kusin vitkål, men hon trivs bra i lite lättare jord än ren lera.",soilTips:["Kalka på hösten om pH är under 6.5 - savoykål ÄLSKAR kalkrik jord och det skyddar mot klumprotsjuka","Blanda in rikligt med brunnen kompost och gärna lite hönsgödsel innan plantering. Hon äter för två.","Undvik packad jord - luckra djupt. De krusiga bladen signalerar en raffinerad dam, men under marken vill rötterna ha utrymme."],timeline:{1:[{phase:"Förodla inomhus",months:"Feb-Mar",icon:"seedling"},{phase:"Plantera ut",months:"Apr-Maj",icon:"leaf"},{phase:"Gödsla",months:"Maj-Jun",icon:"water"},{phase:"Bladtillväxt",months:"Jun-Jul",icon:"leaf"},{phase:"Skörd",months:"Aug-Nov",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Bladtillväxt",months:"Jul-Aug",icon:"leaf"},{phase:"Skörd",months:"Sep-Nov",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Plantera ut",months:"Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Bladtillväxt",months:"Jul-Aug",icon:"leaf"},{phase:"Skörd",months:"Sep-Okt",icon:"harvest"}]},nutritionData:[{month:"Mar",N:15,P:10,K:10,label:"Förodling"},{month:"Apr",N:25,P:15,K:10,label:"Tillväxtstart"},{month:"Maj",N:55,P:25,K:20,label:"Utplantering"},{month:"Jun",N:80,P:35,K:30,label:"Kraftig bladtillväxt"},{month:"Jul",N:85,P:40,K:45,label:"Huvudbildning"},{month:"Aug",N:65,P:35,K:50,label:"Mognad"},{month:"Sep",N:35,P:25,K:40,label:"Sena sorter mognar"},{month:"Okt",N:15,P:15,K:25,label:"Höstskörd"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla med brunnen kompost och hornmjöl. Savoykål behöver en kväverik start för att bygga alla de krusiga bladen som ska bli huvudet."},{timing:"Tre veckor efter utplantering",tip:"Ge flytande nässelvatten eller alggödsel. Hon ska vara i full gång nu och behöver bränsle för sin imponerande bladproduktion."},{timing:"Vid huvudbildning",tip:"Extra giva med kaliumrik gödsel (vedaska eller alggödsel). Kalium hjälper huvudet att bli tätt och förbättrar frosttåligheten."},{timing:"Sensommar",tip:"En sista lätt giva med kalium stärker cellväggarna och gör kålen ännu mer frosttålig. Perfekt timing inför hösten."}],companions:{good:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft förvirrar kålfjärilen - den hittar helt enkelt inte kålen bland all lökdoft. Ett klassiskt knep."},{id:"dill",name:"Dill",icon:"herb",why:"Lockar parasitsteklar som äter kålfjärilens larver. Dillen jobbar som kålens personliga livvakt."},{id:"selleri",name:"Selleri",icon:"vegetable",why:"Sellerins starka doft maskerar kålen för skadedjur. De trivs bra ihop och utnyttjar jorden på olika djup."},{id:"rodbeta",name:"Rödbeta",icon:"vegetable",why:"Tar näring från ett annat djup i jorden - de konkurrerar inte utan kompletterar varandra fint."}],bad:[{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Jordgubbar hämmas av kålväxter. De pratar helt enkelt olika språk - håll dem åtskilda."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Båda är storätare som slåss om samma näring. Ingen av dem blir nöjd med den uppgörelsen."},{name:"Andra kålväxter",icon:"vegetable",why:"Odla inte savoykål bredvid annan kål - de delar skadedjur och sjukdomar och förstärker varandras problem."}]},rotation:{avoid:[{id:"vitkal",name:"Vitkål"},{id:"gronkal",name:"Grönkål"},{id:"blomkal",name:"Blomkål"},{id:"broccoli",name:"Broccoli"},{id:"rodkal",name:"Rödkål"},{id:"brysselkal",name:"Brysselkål"},{id:"kalrabbi",name:"Kålrabbi"},{id:"radisa",name:"Rädisa"}],avoidWhy:"Alla tillhör korsblommiga och delar sjukdomar som klumprotsjuka. Vänta minst 4 år - helst 6-8 år - innan du odlar kål på samma plats igen. Klumprotsjuka lever kvar i jorden extremt länge.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"potatis",name:"Potatis"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden - gratis gödsel för hungriga savoykål! Potatis och lök lämnar ren, väl bearbetad jord som kålen älskar.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"sallat",name:"Sallat"},{id:"rodbeta",name:"Rödbeta"}],goodAfterWhy:"Rotgrönsaker trivs i den djupt bearbetade, näringsrika restjorden efter kål. Sallat gillar kvävet som kålen lämnar efter sig."},varieties:[{name:"Vertus 2",zones:[1,2,3,4,5,6],note:"Klassisk OP-sort med mörkgröna, krusiga blad och fasta huvuden. Milt och sött - den självklara savoykålen för svenska odlare. Finns hos Impecta."},{name:"Vorbote 3",zones:[1,2,3,4,5],note:"Tidig OP-sort som mognar snabbt. Kompakta, fina huvuden som är perfekta för den som vill ha tidig skörd. Funkar bra i kortare säsonger."},{name:"Wirosa F1",zones:[1,2,3,4,5,6],note:"F1-hybrid med utmärkt köldhärdighet och kompakta, blågröna huvuden. Tål frost extremt bra och har lång ståndtid i fält. Välj denna om du vill ha maximal frosttålighet."},{name:"Deadon F1",zones:[1,2,3,4,5,6],note:"F1-hybrid med utmärkt vinterhärdighet och vackra blågröna blad med lila ton. God sjukdomsresistens och fin smak. Ekofrö hos Semenco. OBS: F1 - ger inte sortäkta frö."}],problems:[{name:"Kålfjäril",symptom:"Gröna larver som tuggar stora hål i de krusiga bladen. Lämnar spillningshögar och kan förstöra plantor snabbt. Larverna gömmer sig extra bra bland savoykålens krusade bladverk.",fix:"Fiberduk från dag ett - det enda helt säkra skyddet! Handplocka larver regelbundet (kolla extra noga i vecken). Spruta med Bacillus thuringiensis (Bt) mot larverna. Samodla med dill och lök."},{name:"Kålfluga",symptom:"Plantan vissnar trots vattning. Rötterna är fulla av vita larver som äter sig igenom rotsystemet.",fix:"Kålkragar runt stjälken vid utplantering - hindrar flugan från att lägga ägg vid stambasen. Fiberduk hjälper också. Kraftiga plantor med bra rotsystem klarar lättare angrepp."},{name:"Klumprotsjuka",symptom:"Plantan stannar i tillväxt och vissnar i värme. Rötterna har fula, klumpiga svullnader. Kålodlarens absoluta mardröm.",fix:"Ingen bot - dra upp och bränn angripna plantor! Kalka jorden ordentligt (pH över 7). Odla inte kål på samma plats på minst 6-8 år. Svampen överlever i jorden extremt länge."},{name:"Jordloppor",symptom:"Små runda hål i unga blad, som om någon skjutit med hagelgevär. Värst i varmt, torrt väder. Unga plantor är mest utsatta.",fix:"Fiberduk är bästa skyddet. Håll jorden fuktig - jordloppor avskyr fukt. Pudra med stenmjöl eller vedaska. Starka, välgödda plantor klarar angrepp bättre."}],goodToKnow:[{icon:"warning",title:"Kalka - klumprotsjukans fiende",text:"Det absolut viktigaste du kan göra för kål är att kalka jorden. Klumprotsjuka trivs i sur jord och finns den väl i marken stannar den i 7+ år. Kalka på hösten, sikta på pH runt 7.",severity:"warning"},{icon:"snowflake",title:"Tål frost bättre än vitkål",text:"Savoykål är den frosttåligaste av huvudkålarna. Härdade plantor klarar ner till -10°C! De krusiga bladen fungerar som isolering och gör henne perfekt för sen höstskörd.",severity:"tip"},{icon:"warning",title:"Larverna gömmer sig i vecken",text:"De krusiga bladen är vackra men ger också kålfjärilens larver perfekta gömställen. Var extra noggrann när du letar larver - titta i varje veck och krås.",severity:"warning"},{icon:"leaf",title:"Mildare smak än vitkål",text:"Savoykål har en finare, mildare och sötare smak än vitkål. Perfekt i soppor, grytor och gratänger. Bladen blir silkeslena vid tillagning - en riktig höstfavorit i köket.",severity:"tip"},{icon:"harvest",title:"Frost gör henne ännu godare",text:"Precis som grönkål omvandlar savoykål stärkelse till socker vid frost. Vänta gärna med skörden till efter första frosten - smaken blir märkbart sötare.",severity:"tip"},{icon:"warning",title:"Lagras sämre än vitkål",text:"Savoykål håller sig inte lika länge som vitkål i källaren. Planera för att äta upp den inom några veckor efter skörd, eller frys in den direkt. Det krusiga bladverket gör henne mer känslig vid lagring.",severity:"warning"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Savoykål förodlas nästan alltid inomhus för att få tillräckligt lång säsong. Direktsådd fungerar i zon 1-3 men förodling ger bättre kontroll och tidigare skörd av de vackra, krusiga huvudena.",steps:["Så 1-2 cm djupt i krukor eller celler, 4-6 veckor före planerad utplantering","Håll jorden runt 18-20°C för snabb groning (5-10 dagar)","Flytta till svalare plats (12-15°C) och starkt ljus så snart plantorna är uppe - det ger kompakta, starka plantor","Gallra till en planta per cell om du sått flera frön","Härda av plantorna 7-10 dagar innan utplantering - ställ ut dagtid, in på natten","Plantera ut med 40-50 cm avstånd när plantan har 4-6 riktiga blad","Tryck till jorden ordentligt runt stammen, vattna rikligt och sätt kålkragar + fiberduk direkt"],tips:["Savoykål kan även sås i juli för en sen höstskörd - välj tidiga sorter som Vorbote 3 för detta","Kålkragar runt stjälken vid utplantering skyddar mot kålfluga - gör dem av kartong, filt eller köp färdiga","Förodlade plantor som härdats ordentligt klarar frostknäppar mycket bättre efter utplantering"],indoorWeeks:"4-6 veckor"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Savoykål är tvåårig - hon sätter frö först andra året. Huvudet måste övervintras och planteras ut igen på våren. Krävande men givande för den som vill bevara gamla sorter.",steps:["Välj det finaste, friskaste huvudet och skörda det med roten kvar","Förvara hela plantan svalt (0-5°C) över vintern - källare eller jordkällare fungerar","Plantera ut igen på våren med intakt rot och huvudstump","Huvudet spricker upp och en blomstjälk växer upp ur mitten","Gula blommor pollineras av insekter - se till att bara EN sort av Brassica oleracea blommar","Låt fröskidorna mogna och torka på plantan tills de är bruna och spröda","Klipp av blomstjälkarna och eftertorka i papperspåse","Krossa skidorna försiktigt och blås bort agnarna. Förvara svalt och torrt."],isolation:"Korsar med ALLA andra Brassica oleracea (vitkål, grönkål, broccoli, blomkål, brysselkål, kålrabbi). Odla bara en sort för frö, eller isolera med minst 1 km.",storageYears:"4-5 år",tip:"Frötagning av savoykål kräver att du kan förvara en hel kålplanta över vintern. För gamla OP-sorter som Vertus 2 är det absolut värt besväret. F1-hybrider som Wirosa ger inte äkta avkomma - satsa på OP-sorter för fröbesparing!"},storage:{shelfLife:"1-4 veckor (färsk), 1-2 månader (källare), 8-12 månader (fryst)",methods:[{method:"Kylskåp",icon:"snowflake",duration:"1-3 veckor",description:"Lägg i plastpåse med några hål i grönsakslådan. Hela huvuden håller längre än delad kål. De krusiga bladen torkar ut snabbare än vitkål - håll koll.",best:!0},{method:"Sval källare",icon:"storage",duration:"1-2 månader",description:"Häng upp och ner i sval källare (0-4°C) med roten kvar. Håller inte lika länge som vitkål men kan ge dig savoykål en bit in på vintern.",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Strimla eller dela i bitar, blanchera 2 minuter, kyl i isvatten och frys i portionspåsar. Perfekt för soppor, grytor och kåldolmar under vintern.",best:!1},{method:"Kåldolmar",icon:"storage",duration:"3-4 månader (frysta)",description:"Savoykålens mjuka, krusiga blad är PERFEKTA för kåldolmar. Gör en stor sats och frys in - bättre kåldolmsblad finns inte.",best:!1},{method:"Torka",icon:"storage",duration:"6-12 månader",description:"Strimla tunt och torka i ugn på 50°C eller i torkmaskin. Kompakt och platssnålt. Bra krydda i soppor och grytor.",best:!1}],tips:["Savoykål lagras sämre än vitkål - planera för att använda den relativt snabbt efter skörd","Låt kålen stå kvar i landet så länge som möjligt - hon tål frost bra och kylan gör henne godare","Gör kåldolmar! Savoykålens mjuka, böjliga blad är som gjorda för ändamålet - oändligt mycket bättre än vitkålsblad","Strimla och blanchera för frysning direkt efter skörd - det bevarar smak och näring bäst","Kolla lagrad kål regelbundet och ta bort blad som börjar bli sladdriga - inuti är den ofta helt fin"]},harvestCalc:{minPerSqm:2,maxPerSqm:5,unit:"kg"}},_a=Object.freeze(Object.defineProperty({__proto__:null,savoykal:pr},Symbol.toStringTag,{value:"Module"})),ur={name:"Schalottenlök",icon:"schalottenlok",family:"Lökväxter",familyLatin:"Amaryllidaceae",difficulty:"Enkel",difficultyWhy:"Sättlök i jorden, vänta, skörda en hel klunga lökar. Schalottenlöken gör det mesta jobbet själv - hon delar sig och multiplicerar utan att du lyfter ett finger.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:null},days:"90-120",spacing:"15-20 cm",rowSpacing:"25-30 cm",depth:"2-3 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Schalottenlöken är solälskare precis som sin kusin vanlig lök. Minst 6 timmar direkt solljus per dag. I halvskugga får du bladmassa men klena, outvecklade klungor."},temperature:{min:5,max:30,ideal:"15-22°C",detail:"Tålig liten dam som klarar lätt frost som etablerad planta. Trivs bäst i svalare väder under tillväxten och lite varmare när lökarna mognar och delar sig."},wind:{level:"Tålig",detail:"Med sin låga profil bryr sig schalottenlöken inte nämnvärt om vind. Inga särskilda åtgärder behövs."}},watering:{need:"Låg-Medel",icon:"water",summary:"Schalottenlöken vill ha jämn, lätt fukt under tillväxten men HATAR blöta fötter. Ännu känsligare för övervattning än vanlig lök - hon ruttnar lätt om det står vatten. När blasten börjar gulna och lägga sig - sluta vattna helt.",phases:[{phase:"Etablering (0-3 veckor)",need:"Medel",tip:"Håll jorden lätt fuktig efter sättning så rötterna kan etablera sig. Vattna 1-2 gånger i veckan om det inte regnar. Undvik att blöta ner själva sättlöken."},{phase:"Tillväxt (3-10 veckor)",need:"Medel",tip:"Jämn fukt utan att överdriva. Schalottenlöken bygger nu sin klunga och behöver vatten - men aldrig stående vatten. Mulcha gärna för att hålla fukt och ogräs borta."},{phase:"Delning och lökbildning (10-14 veckor)",need:"Låg",tip:"Minska vattningen gradvis. Klungan delar sig och varje lök bygger upp sina lager. För mycket vatten ger vattniga lökar som lagras dåligt."},{phase:"Mognad (sista 2-3 veckorna)",need:"Ingen",tip:"SLUTA vattna helt när blasten gulnar och lägger sig. Lökarna ska torka och bilda ordentligt skal. Vatten nu förstör den fantastiska lagringsförmågan."}],mistakes:["Vattna när blasten redan lagt sig - lökarna ruttnar istället för att mogna","Övervattning generellt - schalottenlök är ännu känsligare än vanlig lök","Stående vatten runt klungan - dränering är helt avgörande"],tip:"Mulcha med halm eller gräsklipp mellan raderna. Det håller fukten jämn, ogräset borta och jorden sval - precis som schalottenlöken vill ha det."},soil:"Väldränderad, lätt, mullrik jord. Schalottenlöken vill ha det luftigt - tung lerjord är hennes fiende nummer ett. Blanda i sand och kompost om jorden är tung.",soilTips:["Luckra ordentligt till 20 cm djup - klungan behöver plats att breda ut sig","Blanda in sand och väl brunnen kompost i tung jord","Upphöjda bäddar är perfekta - bra dränering och varm jord","Strö lite trädgårdskalk om pH är under 6","Undvik FÖR rik jord - det ger mycket blast men små lökar"],timeline:{1:[{phase:"Sätt sättlök",months:"Apr",icon:"seedling"},{phase:"Rensa ogräs",months:"Maj-Jun",icon:"leaf"},{phase:"Minska vattning",months:"Jul",icon:"water"},{phase:"Skörd och torkning",months:"Aug",icon:"harvest"}],4:[{phase:"Sätt sättlök",months:"Apr-Maj",icon:"seedling"},{phase:"Rensa ogräs",months:"Jun",icon:"leaf"},{phase:"Minska vattning",months:"Jul-Aug",icon:"water"},{phase:"Skörd och torkning",months:"Aug-Sep",icon:"harvest"}],6:[{phase:"Sätt sättlök",months:"Maj",icon:"seedling"},{phase:"Rensa ogräs",months:"Jun-Jul",icon:"leaf"},{phase:"Minska vattning",months:"Aug",icon:"water"},{phase:"Skörd och torkning",months:"Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:25,P:15,K:10,label:"Sättning"},{month:"Maj",N:55,P:25,K:20,label:"Tillväxt"},{month:"Jun",N:65,P:35,K:30,label:"Bladtillväxt"},{month:"Jul",N:25,P:45,K:60,label:"Delning och lökbildning"},{month:"Aug",N:10,P:35,K:75,label:"Mognad"},{month:"Sep",N:5,P:20,K:45,label:"Skörd"}],nutritionTips:[{timing:"Vid sättning",tip:"Grundgödsla med brunnen kompost. Lite benmjöl i planteringshålet ger bra fosfortillskott för rotutvecklingen. Gå lätt på kvävet - schalottenlöken behöver mindre än vanlig lök."},{timing:"Tidig tillväxt",tip:"Lätt giva flytande gödsel varannan vecka. Lagom med kväve - för mycket ger yvig blast och dålig delning."},{timing:"Delning och lökbildning",tip:"Sluta med kväve helt. Ge kaliumrik gödsel (vedaska) - det hjälper varje lök i klungan att bilda fina, fasta lager."},{timing:"Mognad",tip:"Ingen gödsling. Låt lökkklungan mogna ifred."}],companions:{good:[{id:"morot",name:"Morot",icon:"vegetable",why:"Klassiskt radarpar - schalottenlökens doft skrämmer bort morotsflugan och moroten håller lökflugan borta"},{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Lökdoften skyddar jordgubbarna mot gråmögel - fungerar precis som med vanlig lök"},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Smart markutnyttjande - sallaten skördas innan schalottenlöken behöver all plats för sin klunga"}],bad:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Lökväxter hämmar ärtornas tillväxt - de trivs inte alls ihop"},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Samma problem som ärtor - baljväxter och lökväxter funkar inte ihop"}]},rotation:{avoid:[{id:"lok",name:"Lök"},{id:"vitlok",name:"Vitlök"},{id:"purjolok",name:"Purjolök"},{id:"graslok",name:"Gräslök"}],avoidWhy:"Alla tillhör lökväxter (Amaryllidaceae) - delar sjukdomar som lökröta och lökfluga. Vänta minst 4 år.",goodBefore:[{name:"Kål"},{id:"squash",name:"Squash"}],goodBeforeWhy:"Näringshungriga grödor drar nytta av den välgödslade jord schalottenlöken lämnar efter sig.",goodAfter:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodAfterWhy:"Baljväxter fixerar kväve i jorden och bygger upp näringen inför nästa säsong."},varieties:[{name:"Jermor",zones:[1,2,3,4,5],note:"Halvlång bananschalottenlök och en riktig lagringskunglighet. Pålitlig sort som ger jämna, fina klungor. Larsviken."},{name:"Zebrune",zones:[1,2,3,4,5],note:"Avlång och elegant med mild, fin smak och silkig textur. En favorit bland kockar. Fröodlad. Impecta."},{name:"Longor",zones:[1,2,3,4,5],note:"Lång, rödskälig bananschalottenlök med bra skörd och fin smak. Lagrar bra. Nelson Garden (sättlök)."},{name:"Golden Gourmet",zones:[1,2,3,4,5,6],note:"Rund, gul och mild. Tidig sort som passar bra även i kallare zoner. Wexthuset, Plantagen m.fl."}],problems:[{name:"Lökfluga",symptom:"Gula, slappa blad. Larver vid lökarnas bas som äter sig in.",fix:"Täck med fiberduk i maj-juni. Samodla med morot. Strö kalkstensmjöl vid basen av klungan."},{name:"Lökröta (Botrytis)",symptom:"Mjukt, grått mögel vid halsen. Lökarna ruttnar vid lagring.",fix:"Torka klungorna ordentligt efter skörd. Skörda i torrt väder. God ventilation vid lagring."},{name:"Falskt mjöldagg",symptom:"Blågrå beläggning på bladen. Blasten vissnar tidigt.",fix:"Växtföljd! Undvik övervattning och plantera luftigt. Plocka bort angripna plantor direkt."},{name:"För tidig skottbildning",symptom:"Löken skjuter blomstjälk redan första året istället för att bilda klunga.",fix:"Förvara sättlöken svalt (inte under 5°C) innan sättning. Välj värmebehandlad sättlök. Sätt inte för tidigt i kall jord."}],goodToKnow:[{icon:"seedling",title:"En blir MÅNGA - magisk multiplikation!",text:"Det här är schalottenlökens superkraft - en enda sättlök delar sig och blir en klunga på 5-12 lökar. Fantastisk avkastning på din investering! Spara de finaste lökarna som sättlök till nästa år.",severity:"tip"},{icon:"leaf",title:"Gourmetsmak i en enkel lök",text:"Schalottenlöken har en mildare, sötare och mer komplex smak än vanlig lök. Det är inte utan anledning att franska kockar älskar den. Perfekt rå i vinaigretter eller karamelliserad.",severity:"tip"},{icon:"storage",title:"Lagringsdrottningen",text:"Ordentligt torkade schalottenlökar lagrar ofta 6-8 månader - bättre än de flesta vanliga lökar! Hemligheten är den extra torktiden och bra luftcirkulation.",severity:"tip"},{icon:"sun",title:"Daglängd styr lökbildningen",text:"Precis som vanlig lök styrs schalottenlökens lökbildning av daglängden. Sätt tidigt på säsongen så hon hinner bygga ordentlig blast innan de långa dagarna triggar lökbildningen.",severity:"tip"},{icon:"seedling",title:"Sättlök framför frösådd - alltid",text:"Schalottenlök odlas traditionellt från sättlök, och det finns goda skäl. Frösådd tar mycket längre tid och ger ofta sämre resultat. Sättlök ger pålitliga klungor redan första säsongen.",severity:"tip"},{icon:"warning",title:"Tung lera? Tänk om!",text:"Schalottenlöken avskyr tung, vattensjuk lera mer än sin kusin vanlig lök. Klungan behöver kunna breda ut sig i luftig jord. En upphöjd bädd med sandblandad kompost gör underverk.",severity:"warning"}],sowing:{method:"both",label:"Sättlök eller frösådd",description:"Sättlök rekommenderas starkt - det är traditionellt och ger bäst resultat. Varje sättlök delar sig till en klunga på 5-12 lökar. Frösådd är möjligt men tar längre tid och ger ofta mindre klungor.",steps:["Sättlök: Tryck ner sättlöken i jorden med spetsen uppåt, 2-3 cm djupt","Spetsen ska precis sticka upp ovanför jordytan","Avstånd 15-20 cm i raden (klungan behöver plats att breda ut sig!), 25-30 cm mellan raderna","Vattna lätt efter sättning","Frösådd: Förkultivera inomhus i februari-mars (8-10 veckor före utplantering)","Så tunt i djupa krukor - lökplantor vill inte bli omplacerade","Plantera ut efter avhärdning när frostrisken är över"],tips:["Välj värmebehandlad sättlök - det minskar risken för tidig skottbildning","Sätt inte sättlöken för djupt - klungan behöver kunna breda ut sig nära ytan","Lite benmjöl i planteringshålet ger stark rotutveckling","Spara de finaste lökarna från årets skörd som sättlök till nästa år - gratis multiplikation!"],indoorWeeks:"8-10 veckor"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Schalottenlöken är tvåårig - första året bildar hon klunga, andra året blommar hon och sätter frö. Du behöver överväntra utvalda lökar och plantera ut dem igen. De flesta odlare sparar istället sättlök från klungan - mycket enklare!",steps:["Välj de finaste, friskaste lökarna från de bästa klungorna vid skörd","Lagra dem svalt (4-8°C) men frostfritt över vintern","Plantera ut hela löken tidigt på våren med halsen i marknivå","Löken skjuter en hög blomstjälk med rund blomkula","Insekter pollinerar blommorna under sommaren","Låt frökapsarna mogna tills de börjar öppna sig och visa svarta frön","Klipp av hela blomhuvudet och torka inomhus i en papperspåse","Skaka ut fröna när de är helt torra"],isolation:"Korsar med andra sorter av schalottenlök och potentiellt med vanlig lök (båda Allium cepa). Isolera med minst 1 km eller odla bara en sort för frö.",storageYears:"1-3 år",tip:"Enklare alternativ: spara bara de bästa lökarna ur klungan som sättlök till nästa år! Det är så schalottenlök traditionellt förökas - och det bevarar sortegenskaperna perfekt."},storage:{shelfLife:"4-8 månader",methods:[{method:"Hängande i nätpåse",icon:"storage",duration:"6-8 månader",description:"Häng klungorna i nätpåsar eller fläta ihop dem i strängar på en sval, torr plats. Schalottenlökens fantastiska lagringsförmåga kommer verkligen till sin rätt här. Bättre hållbarhet än vanlig lök!",best:!0},{method:"Sval förvaring (källare)",icon:"storage",duration:"4-6 månader",description:"Lägg lökarna i lådor med god ventilation, gärna i ett enda lager. Temperatur 1-5°C och låg luftfuktighet. Kolla regelbundet att ingen börjat mögla.",best:!1},{method:"Frysa (hackad)",icon:"snowflake",duration:"6-8 månader",description:"Hacka lökarna och frys in i portionspåsar. Perfekt för matlagning - den milda smaken bevaras bra. Behöver inte tinas innan den hamnar i pannan.",best:!1},{method:"Torka",icon:"sun",duration:"12+ månader",description:"Skiva tunt och torka i ugn på 55°C eller i torkautomat. Ger ett fantastiskt fint lökpulver med mer komplex smak än vanligt lökpulver.",best:!1}],tips:["Torka klungorna ordentligt (2-3 veckor) efter skörd - det är hemligheten bakom den långa hållbarheten","Schalottenlök lagrar ofta BÄTTRE än vanlig lök - räkna med 6-8 månader i bra förhållanden","Lagra aldrig tillsammans med potatis - de avger gaser som påskyndar förruttnelse","Spara de finaste lökarna som sättlök till nästa säsong istället för att äta upp alla!"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3,unit:"kg"}},Ia=Object.freeze(Object.defineProperty({__proto__:null,schalottenlok:ur},Symbol.toStringTag,{value:"Module"})),vr={name:"Selleri",icon:"selleri",family:"Flockblommiga",familyLatin:"Apiaceae",difficulty:"Avancerad",difficultyWhy:"Lång odlingssäsong, kräver förodling tidigt på våren, känslig för kyla och torka, och behöver jämn fukt hela vägen. Inget för den som glömmer att vattna.",zones:{outdoor:[1,2,3,4],indoor:null,greenhouse:[1,2,3,4,5]},days:"120-180",spacing:"25-35 cm",rowSpacing:"40-60 cm",depth:"0 cm",depthNote:"Ljusgroddare - lägg på ytan och tryck fast",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Trivs bäst i full sol men klarar halvskugga. I halvskugga blir stjälkarna tunnare och mindre saftiga. Minst 6 timmar sol per dag för riktigt fina stjälkar."},temperature:{min:10,max:30,ideal:"15-21°C",detail:"Sellerin är en riktig primadonna med temperaturen. Under 13°C riskerar hon att gå i blom istället för att växa - katastrofalt! Tål ingen frost alls som ung planta, men etablerade plantor kan klara en lätt nattfrost ner till -6°C sent på hösten."},wind:{level:"Skyddat",detail:"Föredrar ett skyddat läge. Vind torkar ut de saftiga stjälkarna och kan knäcka blasten. Planteras gärna intill en häck eller mur."}},watering:{need:"Hög",icon:"water",summary:"Sellerin är en riktig vattenslukare - hon kommer från fuktiga strandängar och det märks. Jämn fukt hela säsongen är helt avgörande för saftiga, krispiga stjälkar.",phases:[{phase:"Groning och förodling",need:"Hög",tip:"Fröna behöver ljus och fukt för att gro. Håll ytan konstant fuktig med sprayflaska - fröna är pyttelika och torkar ut på nolltid."},{phase:"Utplantering och etablering",need:"Hög",tip:"Vattna dagligen den första veckan efter utplantering. Sellerin hatar att torka ut när hon försöker rota sig."},{phase:"Tillväxt (juni-aug)",need:"Hög",tip:"Kritisk period! Vattna djupt 2-3 gånger i veckan, gärna med mulch runt basen. Ojämn vattning ger ihåliga, sega stjälkar."},{phase:"Skörd (sep-okt)",need:"Medel",tip:"Fortsätt vattna regelbundet men minska något. Stjälkarna ska fortfarande vara saftiga vid skörd."}],mistakes:["Låta jorden torka ut mellan vattningarna - ger sega, bittra stjälkar som inte går att äta","Vattna ovanifrån sent på dagen - fuktiga blad + kyla = svampsjukdomar","Ojämn vattning som ger ihåliga stjälkar och sprickbildning","Glömma att vattna under varma sommardagar - sellerin vissnar dramatiskt"],tip:"Mulcha ordentligt runt plantorna med gräsklipp eller halm. Det håller fukten, och sellerin tackar dig med tjockare, saftigare stjälkar."},soil:"Djup, mullrik och fukthållande jord. Sellerin vill ha det nästan som en rabattpjäs - gödsla rejält och se till att jorden aldrig torkar ut.",soilTips:["Blanda in rikligt med väl brunnen kompost eller kogödsel - sellerin är en storätare","Fukthållande jord är A och O - blanda in torvmull eller kokosfibrer i sandig jord","Undvik nygödslad jord med färsk gödsel - det ger bladbränna och konstig smak","God dränering trots hög fukt - sellerin vill ha fuktigt men inte vattensjukt"],timeline:{1:[{phase:"Förodla inomhus",months:"Feb",icon:"seedling"},{phase:"Härda av",months:"Apr-Maj",icon:"sun"},{phase:"Plantera ut",months:"Maj",icon:"seedling"},{phase:"Tillväxt och skötsel",months:"Jun-Aug",icon:"water"},{phase:"Blekning (valfritt)",months:"Aug-Sep",icon:"scissors"},{phase:"Skörd",months:"Sep-Nov",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar",icon:"seedling"},{phase:"Härda av",months:"Maj",icon:"sun"},{phase:"Plantera ut",months:"Jun",icon:"seedling"},{phase:"Tillväxt och skötsel",months:"Jun-Aug",icon:"water"},{phase:"Blekning (valfritt)",months:"Aug-Sep",icon:"scissors"},{phase:"Skörd",months:"Sep-Okt",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Feb-Mar",icon:"seedling"},{phase:"Plantera ut (växthus)",months:"Jun",icon:"seedling"},{phase:"Tillväxt",months:"Jul-Aug",icon:"water"},{phase:"Skörd",months:"Sep",icon:"harvest"}]},nutritionData:[{month:"Mar",N:10,P:5,K:5,label:"Förodling"},{month:"Apr",N:20,P:10,K:10,label:"Tillväxt inomhus"},{month:"Maj",N:40,P:20,K:15,label:"Utplantering"},{month:"Jun",N:70,P:30,K:25,label:"Stark tillväxt"},{month:"Jul",N:85,P:40,K:35,label:"Maximal tillväxt"},{month:"Aug",N:75,P:50,K:50,label:"Stjälkutveckling"},{month:"Sep",N:40,P:45,K:60,label:"Mognad"},{month:"Okt",N:15,P:30,K:50,label:"Skörd"}],nutritionTips:[{timing:"Vid utplantering",tip:"Ge en rejäl dos väl brunnen kompost eller kogödsel runt varje planta. Sellerin är en storätare och behöver rikligt med näring från dag ett."},{timing:"Var tredje vecka (juni-aug)",tip:"Flytande gödsel med alggödsel eller nässelvatten. Sellerin slukar kväve under sin kraftiga tillväxtperiod."},{timing:"Augusti",tip:"Skifta till kaliumrik gödsel (vedaska, stenmel) för krispiga, hållbara stjälkar."},{timing:"Hela säsongen",tip:"Mulcha med gräsklipp som långsamt bryter ner och matar jorden - sellerin uppskattar den ständiga näringen."}],companions:{good:[{id:"tomat",name:"Tomat",icon:"tomat",why:"Tomaternas starka doft förvirrar selleriflugan. Dessutom skuggar tomatplantan sellerins rot och håller fukten."},{id:"lok",name:"Lök",icon:"lok",why:"Lökens doft maskerar sellerin och skyddar mot insektsangrepp."},{id:"bondbona",name:"Bondböna",icon:"bondbona",why:"Fixerar kväve i jorden som den hungriga sellerin tacksamt tar emot."},{id:"sallat",name:"Sallat",icon:"sallat",why:"Bra markskydd som håller fukten uppe - precis vad sellerin vill ha."}],bad:[{id:"morot",name:"Morot",icon:"morot",why:"Samma familj (flockblommiga) - delar skadedjur som morotsflugan och selleriflugan."},{id:"palsternacka",name:"Palsternacka",icon:"palsternacka",why:"Samma familj - samma problem med gemensamma skadedjur och sjukdomar."},{id:"dill",name:"Dill",icon:"dill",why:"Samma familj (flockblommiga) - lockar morotsflugan och ökar sjukdomstrycket."}]},rotation:{avoid:[{id:"morot",name:"Morot",category:"grönsaker"},{id:"palsternacka",name:"Palsternacka",category:"grönsaker"},{id:"persilja",name:"Persilja",category:"kryddor"},{id:"dill",name:"Dill",category:"kryddor"},{name:"Rotselleri",category:"grönsaker"},{name:"Fänkål",category:"grönsaker"}],avoidWhy:"Alla flockblommiga (Apiaceae) delar sjukdomar och skadedjur. Vänta minst 3-4 år innan du odlar selleri på samma plats igen.",goodBefore:[{id:"artor",name:"Ärtor",category:"grönsaker"},{id:"bondbona",name:"Bondböna",category:"grönsaker"},{id:"lok",name:"Lök",category:"grönsaker"},{id:"potatis",name:"Potatis",category:"grönsaker"}],goodBeforeWhy:"Baljväxter fixerar kväve - perfekt för sellerin som behöver massor av näring. Lök och potatis sanerar mot svampsjukdomar.",goodAfter:[{id:"gronkal",name:"Grönkål",category:"grönsaker"},{id:"sallat",name:"Sallat",category:"grönsaker"},{id:"radisa",name:"Rädisa",category:"grönsaker"}],goodAfterWhy:"Sellerin lämnar efter sig en välgödslad, väl bearbetad plats som kål och sallat drar nytta av."},varieties:[{name:"Tall Utah",zones:[1,2,3,4],note:"Den stora klassikern! Hög, mörkgrön och upprätt med kompakt växtsätt. Pålitlig och smakrik - finns hos Runåbergs och Lindbloms (demeter/ekologiskt)."},{name:"Giant Pascal",zones:[1,2,3,4],note:"Gammal kulturarvssort (Vilmorin 1885) med tjocka, breda stjälkar. Behöver lång säsong men belönar med saftiga, milda stjälkar perfekta för blekning. Internationella fröhus."},{name:"Redventure",zones:[1,2,3],note:"Vacker OP-sort med violettröda stjälkar från Runåbergs. Ger färg i köksträdgården och på tallriken."},{name:"Chinese Pink Celery",zones:[1,2,3,4],note:"Nyhet hos Runåbergs 2026! Ljust rosa-lila stjälkar. Vacker och ovanlig - ett samtalsämne i trädgården."},{name:"Victoria F1",zones:[1,2,3,4,5],note:"F1-hybrid med extra stark motståndskraft mot borrning (för tidig blomning). Bra val i kalla lägen där temperaturen kan svänga."}],problems:[{name:"Selleriflugan",symptom:"Bruna gångar och blåsor i bladen - larverna äter sig genom bladskivan",fix:"Fiberduk från utplantering! Kolla bladen regelbundet och klipp bort angripna blad direkt. Samodla med lök."},{name:"Sellerirost",symptom:"Bruna, upphöjda fläckar på blad och stjälkar. Sprider sig snabbt i fuktigt väder.",fix:"God luftcirkulation, inte för tätt. Undvik vattning ovanifrån. Ta bort angripna blad. God växtföljd."},{name:"Borrning (skottskjutning)",symptom:"Plantan skjuter blomstjälk mitt i säsongen istället för att bilda stjälkar",fix:"Undvik kalla nätter under tidig tillväxt. Härda av plantorna ordentligt. Välj borrningståliga sorter (Victoria F1). Plantera inte ut för tidigt."},{name:"Ihåliga stjälkar",symptom:"Stjälkarna blir ihåliga och sega istället för fasta och saftiga",fix:"Beror nästan alltid på ojämn vattning eller näringsbrist. Vattna jämnt och gödsla regelbundet. Mulcha!"}],goodToKnow:[{icon:"warning",title:"Sellerin hatar kyla som ung!",text:"Temperaturer under 13°C i mer än en vecka kan lura sellerin att tro att det är vinter och hon börjar gå i blom. Plantera inte ut för tidigt - vänta tills nätterna säkert är över 10°C.",severity:"warning"},{icon:"warning",title:"Ljusgroende frön",text:"Sellerins frön ska INTE täckas med jord - de behöver ljus för att gro. Tryck bara ner dem lätt mot ytan. Många misslyckas här.",severity:"warning"},{icon:"warning",title:"Groningen tar tid",text:"Sellerifröna är pyttelika och kan ta 2-4 veckor att gro. Ge inte upp! Håll ytan fuktig med sprayflaska och ha tålamod.",severity:"warning"},{icon:"tip",title:"Blekning ger mildare smak",text:"Vill du ha ljusa, milda stjälkar som i butiken? Linda tidningspapper eller kartong runt stjälkarna 2-3 veckor före skörd. Solljuset stängs ute och smaken blir mildare och sötare.",severity:"tip"},{icon:"tip",title:"Skörda stjälk för stjälk",text:"Du behöver inte ta hela plantan på en gång! Bryt av de yttre stjälkarna när de är tjocka nog och låt mitten fortsätta växa. Så har du färsk selleri i veckor.",severity:"tip"},{icon:"tip",title:"Fantastisk smakbas",text:"Selleri, morot och lök - den heliga treenigheten i köket. Odla alla tre så har du grunden till nästan all god matlagning.",severity:"tip"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Sellerin MÅSTE förodlas inomhus - hon behöver 12-16 veckor innan utplantering och det hinner inte i vår korta svenska sommar om man sår direkt. Starta tidigt!",steps:["Fyll en såbricka med fin såjord och fukta ordentligt","Strö ut de pyttelika fröna på ytan - TÄCK INTE med jord (ljusgroende!)","Tryck försiktigt med en bräda så fröna får kontakt med jorden","Spraya med vatten och täck med plastfolie eller glasskiva för att hålla fukten","Ställ ljust och varmt (18-22°C) - fönsterbräda eller växthylla med belysning","Spraya dagligen - fröna får aldrig torka ut","Groningen tar 2-4 veckor - ha tålamod!","Pricka ut i enskilda krukor när plantorna har 2-3 riktiga blad","Härda av i 1-2 veckor innan utplantering - ställ ut dagtid, in på natten"],tips:["Starta redan i februari (zon 1) eller mars (zon 3-4) - sellerin behöver varenda dag","Använd odlingsbelysning de första veckorna - vinterljuset räcker inte","Blötlägg fröna i ljummet vatten 24 timmar före sådd - kan snabba på groningen"],indoorWeeks:"12-16 veckor"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Sellerin är tvåårig och bildar frö först andra året. Hon korsar med rotselleri och vild selleri, så isolering krävs. Inget för nybörjare!",steps:["Välj de bästa, friskaste plantorna att spara","Gräv upp plantorna på hösten med intakta rötter","Klipp bort de yttre bladen men spara hjärtbladen","Förvara frostfritt över vintern (rotkällare, ouppvärmt växthus)","Plantera ut igen på våren när jorden värmts upp, med tillväxtpunkten i marknivå","Ge gott om plats - 50-60 cm mellan plantorna, de blir stora andra året","Låt blomflockarna mogna tills de blir bruna och torra","Klipp av och torka inomhus, gnugga loss fröna"],isolation:"Korsar med rotselleri, bladselleri och vild selleri. Isolera med minst 500 meter mellan olika sellerisorter.",storageYears:"4-6 år",tip:"Betydligt enklare att bara köpa nytt frö varje år. Men vill du prova - spara ALLTID frö från OP-sorter, aldrig från F1-hybrider."},storage:{shelfLife:"2-4 veckor (färsk), flera månader (fryst)",methods:[{method:"Kylskåp (i vatten)",icon:"snowflake",duration:"2-4 veckor",description:"Ställ stjälkarna upprätt i ett glas med vatten, som en blombukett. Täck med plastpåse. Fungerar förvånansvärt bra och stjälkarna håller sig krispiga.",best:!0},{method:"Kylskåp (inlindade)",icon:"snowflake",duration:"1-2 veckor",description:"Linda stjälkarna i fuktig hushållspapper och lägg i plastpåse. Fungerar men inte lika bra som vattenmetoden.",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Skär i bitar och frys in direkt - ingen blanchering behövs. Perfekt till soppor och grytor men blir mjuk, inte krispig.",best:!1},{method:"Torka",icon:"sun",duration:"Upp till 1 år",description:"Skär i tunna skivor och torka i ugn på 50°C eller i tork. Torkad selleri är fantastisk krydda i soppor och buljonger.",best:!1}],tips:["Skörda på morgonen när stjälkarna är som mest vattenfyllda och krispiga","Kyl ner stjälkarna direkt efter skörd - lägg i kallt vatten en stund","Selleribladen är minst lika goda som stjälkarna! Torka eller frys in bladen separat som krydda","Sellerin tappar snabbt krispighet i rumstemperatur - kyl direkt"]},harvestCalc:{minPerSqm:2,maxPerSqm:4,unit:"kg"}},Wa=Object.freeze(Object.defineProperty({__proto__:null,selleri:vr},Symbol.toStringTag,{value:"Module"})),hr={name:"Sockermajs",icon:"sockermajs",family:"Gräs",familyLatin:"Poaceae",difficulty:"Medel",difficultyWhy:"Behöver lång, varm säsong och förordling i de flesta zoner. Vindpollinering kräver att man planerar planteringen rätt - för få plantor ger tomma kolvar.",zones:{outdoor:[1,2,3,4],indoor:null,greenhouse:[1,2,3,4,5,6]},days:"70-100",spacing:"25-35 cm",rowSpacing:"70-80 cm",depth:"3-4 cm",ph:{min:5.8,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 8 timmar direkt sol per dag. Sockermajsen är en riktig solälskare - i halvskugga får du långa, spinkiga plantor som knappt sätter kolvar."},temperature:{min:10,max:35,ideal:"20-30°C",detail:"Värmekrävande! Groningen startar först när jorden är minst 12°C, och plantan växer bäst över 20°C. Under 10°C stannar tillväxten helt. Frost dödar plantan direkt."},wind:{level:"Skyddat",detail:"Höga plantor (upp till 2 meter) med grunt rotsystem - kraftig vind kan lägga hela rader. Men lite vind är bra för pollineringen! Plantera gärna intill en vägg eller häck."}},watering:{need:"Hög",icon:"water",summary:"Sockermajsen är törstig, speciellt under blomning och kolvfyllnad. Vattenstress då ger halvfyllda kolvar med luckor - och det är tyvärr omöjligt att laga i efterhand.",phases:[{phase:"Groning och etablering (0-3 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig men inte blöt. Fröna behöver värme och fukt för att komma igång."},{phase:"Vegetativ tillväxt (3-8 veckor)",need:"Medel",tip:"Vattna 2-3 gånger i veckan. Rötterna växer djupt nu - djupvattna så de söker sig nedåt."},{phase:"Blomning och pollinering",need:"Hög",tip:"Kritisk period! Vattenstress nu ger glesa, halvfyllda kolvar. Vattna djupt och regelbundet - minst varannan dag i värme."},{phase:"Kolvfyllnad och mognad",need:"Hög",tip:"Varje korn är mestadels vatten. Låt inte jorden torka ut nu - det påverkar både storlek och sötma direkt."}],mistakes:["Vattnar för lite under blomning - ger luckor i kolven som aldrig fylls igen","Vattnar ovanifrån under pollinering - sköljer bort pollen från silkena","Glömmer att majsplantor i värme behöver vatten VARJE dag","Vattnar grunt och ofta istället för djupt och ordentligt"],tip:"Mulcha ordentligt runt plantorna med gräsklipp eller halm. Det håller fukt, hämmar ogräs och ger extra näring när det bryts ner."},soil:"Näringsrik, väldränerad jord som håller fukt. Sockermajs är en storätare som behöver mycket kväve - ta gärna efter baljväxter i växtföljden.",soilTips:["Gräv ner rikligt med kompost eller brunnen gödsel på hösten innan - majsen behöver ett fullt skafferi från start","Undvik tunga lerjordar som blir kalla på våren - majsen vill ha det varmt om fötterna","Mulcha med gräsklipp under säsongen för att hålla fukt och ge extra kväve"],timeline:{1:[{phase:"Förordla inomhus",months:"Apr",icon:"indoor"},{phase:"Härda av",months:"Maj",icon:"hardening"},{phase:"Plantera ut",months:"Maj",icon:"seedling"},{phase:"Tillväxt",months:"Jun-Jul",icon:"leaf"},{phase:"Blomning och pollinering",months:"Jul",icon:"flower"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}],4:[{phase:"Förordla inomhus",months:"Apr-Maj",icon:"indoor"},{phase:"Härda av",months:"Jun",icon:"hardening"},{phase:"Plantera ut",months:"Jun",icon:"seedling"},{phase:"Tillväxt",months:"Jul",icon:"leaf"},{phase:"Blomning och pollinering",months:"Jul-Aug",icon:"flower"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}],6:[{phase:"Förordla inomhus",months:"Maj",icon:"indoor"},{phase:"Plantera ut (växthus)",months:"Jun",icon:"seedling"},{phase:"Tillväxt",months:"Jul-Aug",icon:"leaf"},{phase:"Blomning och pollinering",months:"Aug",icon:"flower"},{phase:"Skörd (om säsongen räcker)",months:"Sep",icon:"harvest"}]},nutritionData:[{month:"Maj",N:25,P:15,K:10,label:"Etablering"},{month:"Jun",N:60,P:25,K:20,label:"Vegetativ tillväxt"},{month:"Jul",N:90,P:45,K:35,label:"Snabb tillväxt"},{month:"Aug",N:70,P:65,K:55,label:"Blomning och kolvfyllnad"},{month:"Sep",N:30,P:50,K:70,label:"Mognad"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla rejält med kompost och lite benmjöl. Majs vill ha kväve från dag ett - hon är en riktig storätare."},{timing:"När plantorna är 30 cm",tip:"Sidogödsla med kväverik gödsel (brännässlevatten, horngödsel). Lägg en ring runt varje planta, inte rakt på stammen."},{timing:"Vid blomning",tip:"Ge extra kalium och fosfor för kolvfyllnad. Vedaska och benmjöl är perfekta nu. Fortsätt med lite kväve också."},{timing:"Sen säsong",tip:"Trappa ner gödslingen. Plantan ska lägga all energi på att fylla och mogna kolvarna."}],companions:{good:[{id:"squash",name:"Squash",icon:"vegetable",why:'Klassiska "Three Sisters" - squashens stora blad skuggar marken och håller fukt, majsen ger skugga uppifrån'},{id:"artor",name:"Ärtor",icon:"vegetable",why:"Baljväxter fixerar kväve som majsen slukar. Ärtorna kan även klättra på majsstjälken"},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Kvävefixerare som majsen älskar som granne - de levererar gratiskväve rakt till rötterna"},{name:"Pumpa",icon:"vegetable",why:'Tredje systern i "Three Sisters" - samma funktion som squash, skuggar marken och håller ogräs borta'}],bad:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Båda är storätare som konkurrerar om samma näring. Majsen vinner kampen och tomaten lider."},{name:"Selleri",icon:"vegetable",why:"Konkurrerar om vatten och näring, och majsen skuggar sellerin för mycket"},{name:"Beta",icon:"vegetable",why:"Hämmar varandras tillväxt - de pratar helt enkelt olika språk"}]},rotation:{avoid:[{name:"Majs"},{name:"Hirs"}],avoidWhy:"Odla inte grässväxter på samma plats två år i rad. Majsen suger ur jorden och bygger upp jordbundna sjukdomar. Vänta minst 2-3 år.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{name:"Klöver/gröngödsling"}],goodBeforeWhy:"Baljväxter och gröngödsling bygger upp kväveförrådet som majsen sedan tar för sig av rejält.",goodAfter:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"lok",name:"Lök"},{name:"Rotgrönsaker"}],goodAfterWhy:"Baljväxter återställer kvävet, och lättfödda rotgrönsaker trivs i den välbearbetade jorden."},varieties:[{name:"Golden Bantam",zones:[1,2,3,4],note:"Klassisk kulturarvssort (1902) med fin smak. Inte lika söt som moderna hybrider men har karaktär. Perfekt för frötagning."},{name:"Ashworth",zones:[1,2,3,4],note:"Tidig OP-sort som gror bra även i sval jord. Pålitlig och anpassad för nordiskt klimat."},{name:"Damaun",zones:[1,2,3,4],note:"Anses vara den sötaste öppetpollinerade sockermajsen. Ca 99 dagar till skörd."},{name:"Sweet Nugget F1",zones:[1,2,3,4],note:"F1-hybrid med supersöta korn. Kompakt planta (ca 150 cm). Finns hos Nelson Garden och Impecta."},{name:"Minipop F1",zones:[1,2,3,4,5],note:"F1 - ger småmajskolvar för att äta färska i sallad eller woka. Mognar snabbt och är lättodlad."}],problems:[{name:"Majsmal (Ostrinia nubilalis)",symptom:"Hål i stjälk och kolv, sågspånsliknande borrmjöl vid hålen. Plantan kan knäckas.",fix:"Ta bort och förstör angripna delar. Ställ upp fågelholkar - mesar älskar majsmalslarver. Klipp ner och förstör gamla stjälkar på hösten."},{name:"Fritfluga (Oscinella frit)",symptom:"Unga plantor får deformerade, snedvridna blad. Stannar i tillväxten.",fix:"Så inte för tidigt i kall jord - fritflugan trivs i kyla. Täck med fiberduk vid sådd. Friska plantor växer ifrån det."},{name:"Kolbrand (Ustilago maydis)",symptom:"Stora grå-vita svulster på kolvar och stjälk som småningom svartnar.",fix:"Plocka bort svulsterna före de spricker. I Mexiko är det faktiskt en delikatess (huitlacoche)! Växtföljd hjälper - odla inte majs på samma plats två år i rad."},{name:"Dålig pollinering",symptom:"Kolven har luckor och glesa korn, speciellt i toppen.",fix:"Plantera ALLTID i block (minst 4x4), aldrig i en lång rad. Majsen är vindpollinerare - pollen från toppen ska landa på silkena (trådarna). I en rad blåser pollen bort."}],goodToKnow:[{icon:"warning",title:"Plantera i BLOCK, inte rader",text:"Majs är vindpollinerare. Pollen faller från toppen (vippan) ner på silkena (trådarna på kolven). En lång rad ger dålig pollinering med tomma korn. Plantera minst 4x4 plantor i ett block.",severity:"warning"},{icon:"warning",title:"Utmanande norr om zon 4",text:"Sockermajs behöver lång, varm sommar. I zon 5-8 är det svårt att få mogna kolvar utomhus. Växthus är nästan ett måste, och välj de allra tidigaste sorterna. Var ärlig med dig själv - det krävs tur med vädret också.",severity:"warning"},{icon:"harvest",title:"Skörda när silket brunfärgats",text:"Kolven är mogen när silkena (trådarna) blivit bruna och torkat. Pressa på ett korn med nageln - om det sprutar mjölkvit saft är det perfekt. Klar saft = för tidig, deg = för sen.",severity:"tip"},{icon:"tip",title:"Koka direkt efter skörd",text:"Sockret i majs börjar omvandlas till stärkelse redan minuter efter skörd. Sätt på vattnet FÖRE du går ut och plockar - då får du den sötaste majs du någonsin smakat.",severity:"tip"},{icon:"leaf",title:"Kvar i landet på hösten",text:"Majsstjälkarna är fantastiskt kompostmaterial. Klipp dem i bitar och lägg på komposten, eller gräv ner dem direkt i jorden som jordförbättring till nästa år.",severity:"tip"},{icon:"warning",title:"Varning för F1-hybrider vid frötagning",text:"Många moderna sockermajssorter är F1-hybrider. Frö från dem ger inte samma sort nästa år. Välj öppetpollinerade sorter som Golden Bantam, Ashworth eller Damaun om du vill spara frö.",severity:"warning"}],sowing:{method:"both",label:"Direktsådd eller förordling",description:"Förordling inomhus rekommenderas i de flesta zoner för att ge plantorna maximal tid. I zon 1-2 kan du direktså utomhus från slutet av maj när jorden värmts upp ordentligt.",steps:["Så 2 frön per kruka i stora krukor (minst 8 cm), 3-4 cm djupt","Håll varmt (20-25°C) - fröna gror på 7-10 dagar","Gallra till en planta per kruka när de är 5-8 cm höga","Härda av i en vecka före utplantering - ut på dagen, in på natten","Plantera ut när nattfrosten är över och jorden är minst 12°C","Plantera i BLOCK (minst 4x4), inte i långa rader - viktigt för pollineringen","Vattna ordentligt vid plantering och mulcha runt plantorna"],tips:["Blötlägg fröna över natten före sådd - det påskyndar groningen med några dagar","Förordla inte för tidigt - majsplantor växer snabbt och ogillar att bli rotbundna. 3-4 veckor före utplantering räcker.","Direktsådd fungerar i zon 1-2 från slutet av maj, men förordling ger alltid bättre resultat i Sverige"],indoorWeeks:"3-4 veckor"},seedSaving:{difficulty:"Medel",type:"Vindpollinerare",biennial:!1,description:"Majs är vindpollinerare och korsas lätt med andra majssorter. Du behöver avstånd eller timing för att hålla sorterna rena.",steps:["Välj kolvar från de starkaste plantorna - låt dem sitta kvar på plantan","Låt kolvarna torka på plantan så länge som möjligt, gärna tills det fryser","Skörda kolvarna när svepebladen är helt torra och bruna","Riv av kornen för hand (använd handskar - det är tuffare än man tror)","Låt kornen eftertorka inomhus i 2-3 veckor på tidningspapper","Testa att ett korn går sönder när du biter på det - då är det torrt nog","Förvara i papperspåse eller glasburk på sval, torr plats"],isolation:"Vindpollinerare - behöver minst 400-500 meters avstånd till andra majssorter för rent frö. Alternativt kan man isolera i tid genom att odla sorter med olika mognadsperiod.",storageYears:"1-2 år",tip:"Majsfrö har kort hållbarhet - använd helst inom 1-2 år. Många sockermajssorter är F1-hybrider vars frö inte ger samma resultat nästa år. För frötagning - välj öppetpollinerade sorter som Golden Bantam, Ashworth eller Damaun."},storage:{shelfLife:"1-3 dagar (färsk) / 12 månader (fryst)",methods:[{method:"Färsk (ät SAMMA DAG)",icon:"harvest",duration:"1-3 dagar",description:"Sockermajs är allra bäst inom timmar efter skörd. Sockret börjar omvandlas till stärkelse direkt. Förvara i kylskåp med svepebladen kvar.",best:!0},{method:"Frysa (blanscherad)",icon:"snowflake",duration:"8-12 månader",description:"Blanschera hela kolvar 4-5 minuter, kyl i isbad. Skär av kornen eller frys hela. Det bästa sättet att bevara smaken över vintern.",best:!1},{method:"Frysa (kornen)",icon:"snowflake",duration:"8-12 månader",description:"Skär av kornen från rå kolv, blanschera 2-3 minuter och frys i portionspåsar. Smart för soppor, grytor och salsa.",best:!1},{method:"Torka",icon:"sun",duration:"12+ månader",description:"Låt kolvar torka på plantan eller inomhus. Torkade korn kan malas till mjöl eller poppas som popcorn (om rätt sort). Fungerar bara med specifika sorter.",best:!1}],tips:["Sätt på vattnet FÖRE du går ut och skördar - varje minut räknas för sötman","Förvara aldrig skalad majs - svepebladen skyddar och håller fukt","Blanschering före frysning är ett måste - det stoppar enzymerna som förstör smaken","Frysta majskorn är fantastiska att ha i frysen - kasta i soppor, salsa, gratänger och plättar"]},harvestCalc:{minPerSqm:.8,maxPerSqm:1.5,unit:"kg"}},Ua=Object.freeze(Object.defineProperty({__proto__:null,sockermajs:hr},Symbol.toStringTag,{value:"Module"})),cr={name:"Sparris",icon:"sparris",category:"grönsaker",family:"Sparrisväxter",familyLatin:"Asparagaceae",perennial:!0,lifespan:"15-20+ år",difficulty:"Avancerad",difficultyWhy:"Kräver tålamod som en zen-mästare - du planterar år 1 och skördar inte ordentligt förrän år 3. Dessutom behöver sparrisen djupbearbetad jord, korrekt plantering och förståelse för när man ska sluta skörda. Men när den väl är etablerad ger hon troget i 15-20 år.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:[1,2,3,4,5,6,7]},days:"Skörd år 3+",spacing:"30-45 cm",rowSpacing:"120-150 cm",depth:"15-20 cm",depthNote:"Planteras i dike",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Sparrisen vill ha full sol hela dagen - minst 6-8 timmar. I halvskugga blir skotten tunna och spinkiga och skörden halveras. Välj den soligaste platsen i trädgården, för här ska hon stå i 15-20 år."},temperature:{min:-25,max:35,ideal:"16-24°C",detail:"Extremt härdig i vila - tål ner till -25°C under marken. Skotten skjuter när jorden når 10-12°C. Trivs bäst i sval-varm sommar. Hetta över 30°C gör att fjällen på skottspetsarna börjar öppna sig för tidigt."},wind:{level:"Måttligt känslig",detail:"De höga sommarskotten (150+ cm) kan knäckas i stark vind. Plantera gärna med vindskydd i ryggen, eller sätt upp stöd. Knäckta sommarskott minskar nästa års skörd."}},watering:{need:"Medel",icon:"water",summary:"Sparrisen har djupa rötter och klarar torka bättre än de flesta grönsaker. Men jämn fukt under skördeperioden ger tjockare, mörare skott. Övervattna aldrig - rötterna ruttnar.",phases:[{phase:"Tidig vår (skottskjutning)",need:"Medel",tip:"Vattna jämnt när skotten börjar komma upp. Torr jord ger tunna, sega skott. Blöt jord ger röta. Lagom är nyckeln."},{phase:"Skördeperiod (maj-juni)",need:"Medel-Hög",tip:"Regelbunden vattning ger tjockare skott och längre skördesäsong. Vattna vid basen, inte ovanifrån."},{phase:"Sommar (efter skörd)",need:"Medel",tip:"Fortsätt vattna - nu bygger plantan upp energi i rötterna för nästa år. Sommarskotten behöver vatten för att frodas."},{phase:"Höst-vinter",need:"Låg",tip:"Minska gradvis. Plantan går i vila och behöver inte vattning. God dränering är viktigare än fukt nu."}],mistakes:["Övervattnar i tung jord - sparrisrötter ruttnar snabbt i stående vatten","Glömmer att vattna under skördeperioden - ger tunna, tråkiga skott","Slutar vattna direkt efter skörd - sommarskotten behöver fukt för att bygga upp rötterna","Vattnar ovanifrån - kan ge svampsjukdomar på skotten"],tip:"Mulcha rejält med halm eller kompost runt plantorna. Det håller fukten jämn, hindrar ogräs och sparrisen älskar det organiska materialet som sakta bryts ner."},soil:"Sparrisen kräver djup, väldränerad, sandig-mullig jord. Hon HATAR lerjord och stående vatten - rötterna ruttnar snabbt. Gräv djupt och blanda in rikligt med kompost och sand.",soilTips:["Gräv ett ordentligt dike (30-40 cm djupt) och blanda in kompost och grov sand i botten","På lerjord: odla upphöjt eller blanda i massvis med sand och organiskt material","Sparrisrötter kan nå 150+ cm djupt - ju bättre du förbereder desto bättre skörd i 15 år","Undvik nyligen gödslad mark med färsk stallgödsel - det ger röta och sjukdomar"],timeline:{1:[{phase:"Plantering (år 1)",months:"April",icon:"seedling"},{phase:"Etablering (år 1-2)",months:"Maj-sept",icon:"leaf"},{phase:"Första skörd (år 3)",months:"Maj-juni",icon:"harvest"},{phase:"Sommarväxt",months:"Juni-sept",icon:"leaf"},{phase:"Nedklippning",months:"Nov",icon:"scissors"},{phase:"Vintervila",months:"Dec-mars",icon:"snowflake"}],4:[{phase:"Plantering (år 1)",months:"Maj",icon:"seedling"},{phase:"Etablering (år 1-2)",months:"Maj-sept",icon:"leaf"},{phase:"Första skörd (år 3)",months:"Maj-mitten juni",icon:"harvest"},{phase:"Sommarväxt",months:"Juni-sept",icon:"leaf"},{phase:"Nedklippning",months:"Okt-nov",icon:"scissors"},{phase:"Vintervila",months:"Nov-april",icon:"snowflake"}],6:[{phase:"Plantering (år 1)",months:"Maj-juni",icon:"seedling"},{phase:"Etablering (år 1-2)",months:"Juni-aug",icon:"leaf"},{phase:"Första skörd (år 3)",months:"Juni",icon:"harvest"},{phase:"Sommarväxt",months:"Juli-aug",icon:"leaf"},{phase:"Nedklippning",months:"Sept-okt",icon:"scissors"},{phase:"Vintervila",months:"Okt-maj",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:5,P:3,K:3,label:"Vårstart"},{month:"Maj",N:7,P:4,K:5,label:"Skottskjutning"},{month:"Jun",N:6,P:5,K:6,label:"Sommarväxt"},{month:"Jul",N:5,P:4,K:7,label:"Energilagring"},{month:"Aug",N:3,P:3,K:6,label:"Uppbyggnad"},{month:"Sep",N:1,P:2,K:4,label:"Avmognad"}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Strö kompost eller brunnen gödsel runt plantorna innan skotten kommer upp. Sparrisen är hungrig på våren och tackar med tjockare skott."},{timing:"Direkt efter skörd (juni)",tip:"Ge en rejäl giva allroundgödsel eller kompost. Nu ska plantan bygga upp rötterna inför nästa år - det är nu pengarna sätts in på banken."},{timing:"Sensommar (aug)",tip:"En giva kaliumrik gödsel (vedaska, tomatgödsel) stärker rötterna inför vintern. Kalium ger härdighet."},{timing:"Höst",tip:"Mulcha med 5-10 cm kompost eller löv efter nedklippning. Maskar drar ner materialet och matar rötterna under vintern."}],companions:{good:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Klassiskt par! Tomater avskräcker sparrisbaggar, och sparris avskräcker rotnematoder som angriper tomater."},{id:"persilja",name:"Persilja",icon:"herb",why:"Persilja trivs i sparrisens skugga under sommaren och avskräcker sparrisfluga. Dessutom utnyttjar den ytan mellan raderna."},{id:"ringblomma",name:"Ringblomma",icon:"flower",why:"Lockar pollinatörer och nyttoinsekter, och ringblommans rötter sägs motverka skadliga nematoder i jorden."},{id:"basilika",name:"Basilika",icon:"herb",why:"Avskräcker bladlöss och sparrisfluga med sin starka doft. Dessutom trivs basilika i sparrisens skyddade mikroklimat."}],bad:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökväxter hämmar sparrisens rottillväxt. De pratar helt enkelt inte samma språk under marken."},{id:"vitlok",name:"Vitlök",icon:"vegetable",why:"Samma problem som lök - hämmar sparrisens rotutveckling. Håll bra avstånd."},{id:"potatis",name:"Potatis",icon:"vegetable",why:"Konkurrerar om samma jorddjup och båda är känsliga för liknande jordburna sjukdomar. Potatisens kupning stör dessutom sparrisrötterna."}]},rotation:{avoid:[{id:"sparris",name:"Sparris"}],avoidWhy:"Plantera aldrig ny sparris där gammal sparris stått - jorden är utarmad och sjukdomar (fusarium, rotröta) lever kvar i minst 5-8 år. Välj alltid helt ny mark.",goodBefore:[{name:"Baljväxter"},{name:"Gräsmatta"},{name:"Gröngödsling"}],goodBeforeWhy:"Mark som legat som gräsmatta eller odlats med baljväxter ger kväverik, frisk jord. Gröngödsling i ett år innan plantering ger perfekt start.",goodAfter:[{name:"Gröngödsling"},{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodAfterWhy:"Efter 15-20 år med sparris är jorden djupt utarmad. Baljväxter och gröngödsling i flera år bygger upp den igen. Räkna med 5+ år innan platsen är redo för sparris igen."},varieties:[{name:"Gijnlim",zones:[1,2,3,4,5],note:"Hanplanta, tidig skörd, mycket produktiv. Den vanligaste sorten i Sverige och det finns en anledning - pålitlig och generös."},{name:"Backlim",zones:[1,2,3,4,5,6],note:"Hanplanta, härdigare än Gijnlim och fungerar längre norrut. Kraftiga, tjocka skott med fin smak."},{name:"Millennium",zones:[1,2,3,4,5],note:"Utvecklad i Kanada (University of Guelph) - extremt härdig F1-hanplanta. Klarar tuffa vintrar."},{name:"Mary Washington",zones:[1,2,3,4],note:"Klassisk gammaldags sort med både han- och honplantor. Mindre produktiv men nostalgisk charm och bra smak."},{name:"Erasmus",zones:[1,2,3,4,5],note:"Holländsk hanplanta. Tjocka, gröna skott med lila toppar. Sen men pålitlig och sjukdomstolerant."}],problems:[{name:"Sparrisbagge (Crioceris asparagi)",symptom:"Orangeröda skalbaggar med svarta prickar på sommarskotten. Larverna äter barren och skotten blir nakna och bruna.",fix:"Handplocka baggar och larver tidigt på morgonen (de är tröga). Duk över plantorna vid kraftiga angrepp. Friska, välgödslade plantor klarar sig bättre."},{name:"Sparrisrost (Puccinia asparagi)",symptom:"Orangebruna rostfläckar på sommarskotten. Skotten gulnar i förtid och plantan försvagas.",fix:"Klipp ner och bränn angripna skott på hösten. God luftcirkulation och väldränerad jord förebygger. Välj resistenta sorter."},{name:"Fusarium (rotröta)",symptom:"Plantan tappar vigor, skotten blir tunna och gulnar. Rötterna har bruna, ruttna partier.",fix:"Tyvärr ingen bot för drabbade plantor. Förebygg med väldränerad jord, friskt plantmaterial och aldrig plantera sparris där sparris stått förut."},{name:"Sparrisfluga (Platyparea poeciloptera)",symptom:"Skotten böjer sig i en karaktäristisk krok och vissnar. Inuti skottet hittar man en liten larv.",fix:"Klipp bort och bränn krokiga skott direkt. Täck med fiberduk under flygtiden (maj-juni). Persiljeplanterade bredvid sägs avskräcka flugan."}],goodToKnow:[{icon:"warning",title:"Tålamod, tålamod, tålamod",text:"Sparris är trädgårdens långtidsinvestering. Du planterar år 1, plockar INGA skott år 1-2, skördar försiktigt 2-3 veckor år 3, och får full skörd först år 4+. Men sedan ger hon i 15-20 år utan att klaga.",severity:"warning"},{icon:"warning",title:"Sluta skörda i tid!",text:"Efter midsommar (eller 6-8 veckor) - STOPP. Även om det kommer fler skott. Plantan behöver sommarskotten för att bygga upp energi till nästa år. Skördar du för länge svälter du ut henne.",severity:"warning"},{icon:"tip",title:"Han- vs honplantor",text:"Hanplantor ger fler men tunnare skott och sprider sig inte med frö. Honplantor ger färre men tjockare skott men sprider sig med bär. Moderna sorter (Gijnlim, Backlim) är renodlade hanplantor.",severity:"tip"},{icon:"tip",title:"Grön vs vit sparris",text:"Samma planta! Vit sparris kupas med jord/sand så skotten aldrig ser solljus. Grön sparris växer fritt i ljuset. Grön är enklare att odla hemma och har mer smak.",severity:"tip"},{icon:"tip",title:"Morgonskörd ger bäst resultat",text:"Skörda tidigt på morgonen när skotten är knapriga och fasta. Under dagen värms de av solen och fjällen börjar öppna sig - då tappar de sin fina textur.",severity:"tip"},{icon:"warning",title:"Ogräs är fiende nummer ett",text:"Sparris konkurrerar dåligt mot ogräs, speciellt de första åren. Mulcha rejält och rensa ofta. Kvickrot i en sparrisodling är en mardröm att bli av med.",severity:"warning"}],sowing:{method:"direct",label:"Plantering",description:"Sparris planteras nästan alltid som ettåriga kronor (rötter) som köps från plantskola. Fröodling tar 1 extra år. Kronor ger snabbare resultat och garanterar sort.",steps:["Gräv ett dike 30-40 cm djupt och 40 cm brett","Lägg ett lager kompost och sand (10 cm) i botten och forma en liten kulle","Lägg kronan (rötterna) på kullen med rötterna utspridda som en spindel","Fyll på med 5-8 cm jord - inte mer! Resten fylls på successivt under sommaren","Vattna försiktigt men ordentligt","Fyll på mer jord vartefter skotten växer, tills diket är jämnt med marknivån","Mulcha med halm eller kompost"],tips:["Köp ettåriga kronor av känd sort - det sparar ett helt år jämfört med frösådd","Blötlägg kronorna i ljummet vatten 30 minuter före plantering - det väcker rötterna","Plantera ALDRIG för djupt direkt - fyll på successivt, annars kvävs plantan"],indoorWeeks:null},seedSaving:{difficulty:"Medel",type:"Insektspollinerare",biennial:!1,description:"Sparris är tvåbyggare - han- och honplantor var för sig. Bara honplantor ger bär och frö. Moderna sorter är renodlade hanplantor och ger inga frö alls.",steps:["Identifiera honplantor - de har röda bär på hösten","Låt bären mogna helt tills de är klarröda och mjuka (september-oktober)","Plocka bären och krossa dem i vatten","Skölj bort fruktköttet - frön sjunker till botten","Torka fröna på hushållspapper i rumstemperatur i en vecka","Förvara torrt och svalt i märkt påse"],isolation:"Sparris pollineras av insekter (bin, humlor) - 250-500 meter isolering för sortrenhet. I hemträdgården spelar det mindre roll.",storageYears:"3-4 år",tip:"Moderna F1-hansorter (Gijnlim, Backlim) ger inga frön. Om du vill spara frö behöver du en gammal sort som Mary Washington med honplantor."},storage:{shelfLife:"3-5 dagar (färsk)",methods:[{method:"Stående i vatten",icon:"storage",duration:"4-7 dagar",description:"Bästa sättet för färsk sparris. Ställ skotten upprätt i ett glas med 2-3 cm vatten i kylskåpet, som en bukett. Byt vatten varannan dag. Sparrisen håller sig fast och knaprig.",best:!0},{method:"Frysning",icon:"snowflake",duration:"8-12 månader",description:"Skölj, klipp i bitar och blanchera 2-3 minuter. Kyl ner i isvatten, torka och frys på plåt. Flytta till påsar. Perfekt till soppor och gratänger.",best:!1},{method:"Inlagd (ättika)",icon:"storage",duration:"6-12 månader",description:"Blanchera skotten 2 minuter. Lägg i burk med ättikslag (1:1 vatten och ättika, socker, salt, dill). Fantastiskt till förrätt eller på smörgås.",best:!1},{method:"Kylskåp (fuktig handduk)",icon:"snowflake",duration:"3-5 dagar",description:"Linda skottens nedre del i fuktig hushållspapper och lägg i plastpåse i kylen. Inte lika bra som stående i vatten men funkar.",best:!1}],tips:["Ät sparris samma dag om möjligt - smaken försämras snabbt efter skörd","Bryt av den sega nederdelen istället för att skära - den bryts naturligt precis där den slutar vara mör","Förvara aldrig sparris bredvid frukt - etylen från frukt påskyndar åldrandet","Tjock sparris är inte segare än tunn - tvärtom, tjocka skott har ofta bättre textur"]},harvestCalc:{minPerSqm:.3,maxPerSqm:.8,unit:"kg"}},qa=Object.freeze(Object.defineProperty({__proto__:null,sparris:cr},Symbol.toStringTag,{value:"Module"})),br={name:"Spenat",icon:"spenat",family:"Mållväxter",familyLatin:"Amaranthaceae",difficulty:"Enkel",difficultyWhy:"Snabb, tålig och trivs i svalka. Perfekt för nybörjare som vill ha tidig skörd - spenaten är redo innan de flesta andra grödor ens har vaknat.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:[1,2,3,4,5,6,7,8],greenhouse:null},days:"30-50",spacing:"10-15 cm",rowSpacing:"25-30 cm",depth:"1-2 cm",ph:{min:6,max:7.5,ideal:6.8},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Trivs i 4-6 timmar sol men klarar halvskugga utmärkt - faktiskt en fördel under sommaren. Sol hela dagen i juli-värme gör att hon skjuter i blom snabbare än du hinner blinkar."},temperature:{min:2,max:25,ideal:"10-18°C",detail:"En riktig svalvädersdrottning! Gror redan vid 2°C och älskar temperaturer runt 15°C. Över 23°C - särskilt i kombination med långa dagar (14+ timmar) - börjar hon stressa och blomma. Och då är det kört."},wind:{level:"Tålig",detail:"Låg profil och kompakta blad - vinden är inget problem. Lite luftrörelse är faktiskt bra för att minska svamprisken."}},watering:{need:"Medel",icon:"water",summary:"Jämn fukt ger mjuka, fina blad. Spenat har ganska grunt rotsystem och torkar ut snabbt i varmt väder, men vill absolut inte stå i vatten.",phases:[{phase:"Groning (0-2 veckor)",need:"Hög",tip:"Håll jorden jämnt fuktig tills groddarna kommer upp. Fröna gror snabbt (5-10 dagar) om du håller dem glada och fuktiga."},{phase:"Tillväxt (2-4 veckor)",need:"Medel",tip:"Vattna jämnt 2-3 gånger i veckan. Mulcha gärna för att hålla fukten - spenat har ytliga rötter som torkar ut snabbt."},{phase:"Skörd (4+ veckor)",need:"Medel",tip:"Fortsätt med jämn fukt. Torka och värme nu är den snabbaste vägen till blomning - och bittra, sega blad."}],mistakes:["Vattnar för lite i varmt väder - spenaten skjuter i blom som svar på stressen","Vattnar på bladen på kvällen - fuktiga blad över natten bjuder in bladmögel","Ojämn vattning (torrt-blött-torrt) ger sega, bittra blad istället för mjuka och milda"],tip:"Vattna på morgonen vid roten, inte på bladen. Mulcha med gräsklipp - det håller fukten och kyler jorden, vilket spenaten älskar."},soil:"Näringsrik, lucker jord med god dränering. Spenat är hungrig och vill ha ordentligt med kväve för att ge frodiga, gröna blad.",soilTips:["Blanda in rikligt med kompost - spenat är en av de mest kvävehungriga bladgrönsakerna","Kalkrik jord är ett plus - strö lite trädgårdskalk om pH är under 6.0","Undvik tung lerjord som bildar skorpa på ytan - de små groddarna har svårt att ta sig igenom"],timeline:{1:[{phase:"Vårsådd",months:"Mar-Apr",icon:"seedling"},{phase:"Vårskörd",months:"Apr-Jun",icon:"harvest"},{phase:"Höstsådd",months:"Aug-Sep",icon:"seedling"},{phase:"Höstskörd",months:"Sep-Nov",icon:"harvest"}],4:[{phase:"Vårsådd",months:"Apr-Maj",icon:"seedling"},{phase:"Vårskörd",months:"Maj-Jun",icon:"harvest"},{phase:"Höstsådd",months:"Aug",icon:"seedling"},{phase:"Höstskörd",months:"Sep-Okt",icon:"harvest"}],6:[{phase:"Vårsådd",months:"Maj",icon:"seedling"},{phase:"Skörd",months:"Jun-Jul",icon:"harvest"},{phase:"Höstsådd",months:"Jul-Aug",icon:"seedling"},{phase:"Höstskörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Mar",N:35,P:15,K:15,label:"Tidig sådd"},{month:"Apr",N:70,P:25,K:30,label:"Bladtillväxt"},{month:"Maj",N:85,P:30,K:35,label:"Full tillväxt"},{month:"Jun",N:60,P:25,K:30,label:"Skörd"},{month:"Aug",N:70,P:25,K:30,label:"Höstsådd"},{month:"Sep",N:50,P:20,K:25,label:"Höstskörd"}],nutritionTips:[{timing:"Vid sådd",tip:"Grundgödsla med kompost eller brunnen hönsgödsel. Spenat är en riktig kväveslukare - ge henne en bra start."},{timing:"Under tillväxt",tip:"Flytande brännässelvatten varannan vecka ger frodiga, mörkgröna blad. Spenat tackar med att växa som om hon menar det."},{timing:"Höstsådd",tip:"Ge en extra giva kompost vid höstsådden - jorden har ofta gett ifrån sig mycket näring under sommaren."},{timing:"Varning",tip:"Övergödsla inte med kväve sent - det ger visserligen fina blad men kan leda till hög nitrathalt. Sluta gödsla 2-3 veckor före skörd."}],companions:{good:[{id:"jordgubbar",name:"Jordgubbar",icon:"jordgubbar",why:"Jordgubbarna ger markskydd och spenaten drar nytta av den fuktiga miljön. De har olika rottdjup och konkurrerar inte."},{id:"radisa",name:"Rädisa",icon:"radisa",why:"Rädisan skördas snabbt och lämnar plats åt spenaten. Perfekt successionsgranne."},{id:"artor",name:"Ärtor",icon:"artor",why:"Ärtor fixerar kväve i jorden som spenaten älskar. Ärtorna ger dessutom lite skugga på varma dagar."},{id:"sallat",name:"Sallat",icon:"sallat",why:"Samma krav på svalka och fukt - de trivs ihop och skördefönstren kompletterar varandra."}],bad:[{id:"rodbeta",name:"Rödbeta",icon:"rodbeta",why:"Samma familj (mållväxter) - de konkurrerar om samma näring och delar sjukdomar som bladmögel."},{id:"mangold",name:"Mangold",icon:"vegetable",why:"Nära släkting i samma familj. Delar sjukdomar och skadedjur - håll dem isär."}]},rotation:{avoid:[{id:"rodbeta",name:"Rödbeta"},{id:"mangold",name:"Mangold"}],avoidWhy:"Alla tillhör mållväxter (Amaranthaceae) och delar sjukdomar som bladmögel och betcystnematod. Vänta minst 3 år.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter lämnar kväverik jord som spenaten älskar. Lök sanerar mot svampsjukdomar.",goodAfter:[{name:"Kål"},{id:"morot",name:"Morot"},{id:"potatis",name:"Potatis"}],goodAfterWhy:"Kål och rotgrönsaker trivs i den mullrika, välgödslade jorden som spenat lämnar efter sig."},varieties:[{name:"Matador",zones:[1,2,3,4,5,6,7],note:"Klassisk, pålitlig sort med mörkgröna, tjocka blad. Relativt långsam att gå i blom. Funkar överallt."},{name:"Bloomsdale Long Standing",zones:[1,2,3,4,5,6],note:"Krispiga, bubbliga blad och en av de mest blomtåliga sorterna. Perfekt för sommarsådd."},{name:"Butterflay",zones:[1,2,3,4,5,6,7,8],note:"Snabbväxande, ger skörd redan efter 35 dagar. Mjuka blad som är fantastiska färska. Lindbloms (demeter/ekologiskt)."},{name:"Monstrueux de Viroflay",zones:[1,2,3,4,5,6],note:"Fransk heirloom (1866) med stora, breda blad. Ger riklig skörd men kräver bra näring. Finns hos Impecta."},{name:"Palco F1",zones:[1,2,3,4,5,6,7],note:"Hybrid med hög bladmögelresistens. Bra i fuktigt klimat men spara inte frö (F1)."}],problems:[{name:"Bladmögel",symptom:"Gulgröna fläckar på ovansidan, gråviolett beläggning på undersidan av bladen.",fix:"God luftcirkulation - inte för tätt. Vattna på morgonen vid roten. Välj resistenta sorter (Palco F1). Ta bort drabbade blad direkt."},{name:"Skjuter i blom (skottskjutning)",symptom:"Mittenstjälken sträcker sig snabbt uppåt, bladen blir spetsiga och bittra.",fix:"Orsakas av värme (>20°C), torka eller långa dagar. Odla i halvskugga på sommaren. Så blomtåliga sorter. Skörda tidigt - en gång spenaten bestämt sig finns det ingen återvändo."},{name:"Bladlöss",symptom:"Kolonier av små gröna löss under bladen, klibbigt sekret.",fix:"Spruta av med stark vattenstråle. Plantera dill och blommor intill för nyttoinsekter. Undvik övergödsling med kväve - det lockar löss."},{name:"Snigelskador",symptom:"Oregelbundna hål i bladen, slemspår synliga på morgonen.",fix:"Snigelkorn (järnfosfat), kopparhinder runt odlingen. Vattna på morgonen så marken hinner torka till kvällen. Upphöjd bädd hjälper."}],goodToKnow:[{icon:"warning",title:"Skjuter i blom i värme",text:"Spenat HATAR värme och långa dagar. Över 23°C i kombination med mer än 14 timmar ljus per dag triggar blomning. Odla på vår och höst - skippa midsommar.",severity:"warning"},{icon:"seedling",title:"Successionsådd - nyckeln till spenatlycka",text:"Så en kort rad varannan vecka under våren (mars-maj) och igen i augusti. Då har du alltid mjuka, perfekta blad istället för en jätteskörd som boltar samtidigt.",severity:"tip"},{icon:"snowflake",title:"Tål rejäl kyla",text:"Spenat överlever frost ner till -8°C och gror redan vid 2°C. Med fiberduk kan du skörda långt in i november - till och med hela vintern i zon 1.",severity:"tip"},{icon:"warning",title:"Oxalsyra - ät inte kilovis rå",text:"Spenat innehåller oxalsyra som binder kalcium. Inget problem i normala mängder, men ät inte kilovis rå spenat varje dag. Kokning minskar oxalsyran rejält.",severity:"warning"},{icon:"leaf",title:"Plocka ytterbladen",text:"Skörda de yttre bladen och lämna hjärtat. Plantan fortsätter producera nya blad i flera veckor - mycket smartare än att dra upp hela plantan.",severity:"tip"},{icon:"tip",title:"Dubbelgrödning",text:"Spenat är klar så tidigt att du kan så en ny gröda efter den - bönor, squash eller sallat. Dubbel skörd från samma yta!",severity:"tip"}],sowing:{method:"direct",label:"Direktsådd",description:"Spenat sås direkt utomhus - hon ogillar att bli omflyttad och pålroten störs av omplantering. Dessutom växer hon så snabbt att förodling inte ger särskilt mycket försprång.",steps:["Luckra jorden och blanda in kompost i de översta 15 cm","Dra spår ca 1-2 cm djupa med 25-30 cm mellanrum","Blötlägg fröna 12-24 timmar i ljummet vatten före sådd - det snabbar på groningen","Så fröna med 2-3 cm mellanrum","Täck med jord och tryck till lätt","Vattna försiktigt med stril","Gallra till 10-15 cm avstånd när plantorna har 3-4 blad (ät de gallrade plantorna som babyspenat!)"],tips:["Så i omgångar varannan vecka för kontinuerlig skörd - spenat går snabbt från perfekt till blomma","Höstsådd (aug-sep) ger ofta finare spenat än vårsådd - svalare nätter och kortare dagar gör henne glad","I kruka: minst 15 cm djup, vanlig planteringsjord med lite extra kompost. Perfekt på balkong!"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vindpollinerare",biennial:!1,description:"Spenat är tvåkönad med skilda han- och honplantor (dioik). Låt några plantor gå i blom - det hon normalt inte får göra - och samla fröna när de mognat.",steps:["Välj 5-10 fina plantor och låt dem gå i blom (ja, det du normalt försöker undvika)","Spenat har skilda han- och honplantor - behåll båda för pollinering","Hanplantorna blommar först med tunna blomklasar, honplantorna bildar frön efteråt","Vänta tills fröna är hårda och bruna (ca 6 veckor efter blomning)","Klipp av hela plantan och torka hängande inomhus","Gnugga loss fröna och sikta bort skräp","Förvara i papperspåse på sval, torr plats"],isolation:"Vindpollinerare med extremt lätt pollen som färdas långt. Odla bara en sort för frö, eller isolera med minst 800 m (helst mer).",storageYears:"3-5 år",tip:"Spenatfrö har taggigt skal - helt normalt. Välj frö från plantor som gick i blom SENT, så selekterar du för blomtålighet."},storage:{shelfLife:"1-2 veckor",methods:[{method:"Kylskåp i fuktig handduk",icon:"snowflake",duration:"5-7 dagar",description:"Lägg otvättade blad i fuktig hushållspapper, stoppa i plastpåse med lite luft. Tvätta inte förrän du ska äta - fukt gör att bladen blir sladdriga snabbare.",best:!0},{method:"Frysa (blancherad)",icon:"snowflake",duration:"8-12 månader",description:"Blanchera i kokande vatten 30 sekunder, kyl snabbt i isvatten, pressa ur vattnet och frys i portionsförpackningar. Perfekt för soppor och grytor hela vintern.",best:!1},{method:"Frysa (rå)",icon:"snowflake",duration:"3-6 månader",description:"Tvätta, torka och frys lösa blad på plåt. Flytta till påse när de frusit. Bladen blir mjuka vid upptining men funkar fint i smoothies och soppor.",best:!1},{method:"Direkt från trädgården",icon:"leaf",duration:"Hela säsongen",description:"Den absolut bästa lagringen! Lämna spenaten i jorden och plocka blad efter behov. Skörda på morgonen när bladen är som spänst.",best:!1}],tips:["Spenat förlorar C-vitamin snabbt efter skörd - ät den helst samma dag eller nästa dag","Skörda på morgonen - bladen är fyllda med vatten och håller sig bättre","Tvätta INTE spenat som ska lagras i kylen - fukten gör att den ruttnar snabbare","Blancherad, fryst spenat behåller faktiskt mer näring än spenat som legat i kylen en vecka"]},harvestCalc:{minPerSqm:1,maxPerSqm:2.5,unit:"kg"}},Ya=Object.freeze(Object.defineProperty({__proto__:null,spenat:br},Symbol.toStringTag,{value:"Module"})),fr={name:"Squash",icon:"squash",family:"Gurkväxter",familyLatin:"Cucurbitaceae",difficulty:"Enkel",difficultyWhy:"Växter sig stor och stark utan mycket hjälp. Ger enorma skördar - problemet är snarare att hänga med och skörda i tid.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:[1,2,3,4,5,6]},days:"50-65",spacing:"80-100 cm",rowSpacing:"120-150 cm",depth:"2-3 cm",ph:{min:5.8,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 8 timmar sol per dag. Squash vill ha det varmt och ljust - i skugga blir plantan lång och ranglig med få frukter."},temperature:{min:10,max:35,ideal:"20-28°C",detail:"Värmekrävande! Sätts inte ut förrän jorden är minst 15°C och nattfrosten är över. Fryser ihjäl vid minsta frost."},wind:{level:"Skyddat",detail:"De stora bladen fungerar som segel - en blåsig plats sliter på plantan. Sätt den intill en vägg eller häck om möjligt."}},watering:{need:"Hög",icon:"water",summary:"Squash är en törstig planta med enorma blad som avdunstar massor av vatten. Under högsäsong kan hon behöva vatten varje dag.",phases:[{phase:"Etablering (0-3 veckor)",need:"Medel",tip:"Vattna vid plantering och håll jorden fuktig men inte blöt. Låt rötterna etablera sig i lugn och ro."},{phase:"Tillväxt (3-6 veckor)",need:"Hög",tip:"Nu börjar det på allvar! Plantan växer explosionsartat och behöver massor av vatten. Djupvattna 2-3 gånger i veckan."},{phase:"Blomning (6-8 veckor)",need:"Hög",tip:"Kritisk period - utan vatten faller blommorna av. Vattna vid roten, aldrig på bladen. Tidigt på morgonen är bäst."},{phase:"Fruktsättning (8+ veckor)",need:"Hög",tip:"Varje frukt är mestadels vatten - plantan behöver enorma mängder nu. I hetta kan du behöva vattna varje dag."}],mistakes:["Vattnar på bladen istället för vid roten - bjuder in mjöldagg","Vattnar lite och ofta istället för ordentligt och djupt","Glömmer att squashplantor under fruktsättning kan behöva vatten VARJE dag i värme"],tip:"Gräv ner en kruka eller PET-flaska med hål intill plantan och fyll med vatten - det rinner rakt ner till rötterna utan att blöta bladen."},soil:"Näringsrik, humusrik jord som håller fukt men inte står blöt. Squash är en av de mest näringshungriga grödorna du kan odla.",soilTips:["Gräv ner en rejäl laddning kompost eller brunnen gödsel innan plantering - minst en skottkärra per 2-3 plantor","Odla gärna direkt på komposthögen - squash ÄLSKAR det","Mulcha runt plantan med gräsklipp eller halm för att hålla fukten och hålla frukterna rena"],timeline:{1:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj",icon:"plant"},{phase:"Blomning",months:"Jun-Jul",icon:"flower"},{phase:"Skörd",months:"Jul-Sep",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Apr-Maj",icon:"seedling"},{phase:"Plantera ut",months:"Jun",icon:"plant"},{phase:"Blomning",months:"Jul",icon:"flower"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Maj",icon:"seedling"},{phase:"Plantera ut (växthus)",months:"Jun",icon:"plant"},{phase:"Blomning",months:"Jul-Aug",icon:"flower"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Maj",N:30,P:20,K:15,label:"Etablering"},{month:"Jun",N:70,P:35,K:25,label:"Tillväxt"},{month:"Jul",N:80,P:60,K:45,label:"Blomning"},{month:"Aug",N:50,P:75,K:70,label:"Fruktsättning"},{month:"Sep",N:20,P:50,K:60,label:"Mognad"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla rejält med brunnen kompost eller hästgödsel. Gräv ner det 30 cm djupt."},{timing:"Under tillväxt",tip:"Ge flytande gödsel (brännässelvatten, alggödsel) varannan vecka. Squash är en storätare."},{timing:"Under blomning",tip:"Byt till fosfor- och kaliumrik gödsel. Benmjöl och vedaska stärker blomning och fruktsättning."},{timing:"Sen säsong",tip:"Trappa ner gödslingen i augusti. Plantan ska fokusera på att mogna befintliga frukter, inte sätta nya."}],companions:{good:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Ärtornas kvävefixering ger squashen det kväve hon är så hungrig efter"},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Samma sak som ärtor - baljväxter fixar kväve som squash älskar"},{id:"sockermajs",name:"Majs",icon:"vegetable",why:'Klassiska "Tre systrar" - majsen ger stöd, squashen skuggar marken'},{id:"radisa",name:"Rädisa",icon:"vegetable",why:"Snabb mellanskörd innan squashen tar över all plats"}],bad:[{id:"potatis",name:"Potatis",icon:"potatis",why:"Konkurrerar om samma näringsämnen och utrymme - båda är storväxare"},{id:"gurka",name:"Gurka",icon:"vegetable",why:"Samma familj - delar sjukdomar som mjöldagg och kan korspollera"},{id:"pumpa",name:"Pumpa",icon:"vegetable",why:"Samma familj - delar alla sjukdomar och lockar samma skadedjur"}]},rotation:{avoid:[{id:"gurka",name:"Gurka"},{id:"pumpa",name:"Pumpa"},{id:"melon",name:"Melon"}],avoidWhy:"Alla gurkväxter delar sjukdomar som mjöldagg och visnesjuka. Vänta minst 3 år innan du odlar gurkväxter på samma plats.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{name:"Gröngödsling"}],goodBeforeWhy:"Baljväxter och gröngödsling bygger upp kväveförrådet som squash sedan suger ur.",goodAfter:[{id:"lok",name:"Lök"},{id:"morot",name:"Morot"},{id:"radisa",name:"Rädisa"}],goodAfterWhy:"Lättfödda rotgrönsaker trivs efter squash som har luckrat och gödslat jorden ordentligt."},varieties:[{name:"Black Beauty",zones:[1,2,3,4,5],note:"Klassisk mörkgrön OP-zucchini. Tidig, pålitlig och otroligt produktiv."},{name:"Gold Rush",zones:[1,2,3,4,5],note:"Gul OP-zucchini (finns hos Runåbergs) - lika produktiv som gröna, men vackrare på tallriken."},{name:"Ronde de Nice",zones:[1,2,3,4],note:"Rund, ljusgrön OP-sort (även kallad Tondo Chiaro di Nizza). Perfekt att fylla och gratinera."},{name:"Vegetable Spaghetti",zones:[1,2,3,4,5],note:"OP-vintersquash (C. pepo) - köttet blir som spaghetti! Kräver 90-100 dagar, så starta tidigt."},{name:"Butternut Waltham",zones:[1,2,3,4],note:"OP-vintersquash (C. moschata, inte C. pepo). Lagras i månader. Söt, nötig smak. Kräver 100+ dagar."}],problems:[{name:"Mjöldagg",symptom:"Vitt, pudrigt belägg på bladen, börjar ofta sent i säsongen",fix:"Vattna vid roten, aldrig på bladen. God luftcirkulation. Drabbade blad kan klippas bort - plantan överlever det."},{name:"Blomänderöta",symptom:"Mörk, insjunken fläck i blomänden av frukten som mjuknar och ruttnar",fix:"Orsakas av kalciumbrist (ofta pga ojämn vattning). Vattna jämnt och mulcha. Det är inte kalcium som saknas i jorden utan vatten som transporterar det."},{name:"Dålig pollinering",symptom:"Frukten börjar växa men torkar in och faller av",fix:"Handpollera med en mjuk pensel - för pollen från hanblomman (lång rak stjälk) till honblomman (liten frukt vid basen). Gör det tidigt på morgonen."},{name:"Sniglar",symptom:"Stora hål i blad och frukter, slemspår",fix:"Snigelkorn (järnfosfat), ölsaxar, eller kopparhinder runt plantorna. Vattna på morgonen så att marken hinner torka."}],goodToKnow:[{icon:"warning",title:"Skörda LITEN - max 20 cm",text:"En zucchini på 20 cm är perfekt. Lämnar du den i tre dagar har du en basebollträ. Stor squash blir vattnig, trögig och smaklös. Skörda ofta och tidigt!",severity:"warning"},{icon:"harvest",title:"Omöjliga skördar",text:"En enda squashplanta kan ge 5-10 kg under en säsong. Plantera inte för många om du inte har grannar att ge till. Två plantor räcker för en familj.",severity:"tip"},{icon:"flower",title:"Blommorna är ätbara",text:"Hanblommorna (de utan liten frukt vid basen) kan plockas, fyllas med ricotta och friteras. Italiensk delikatess direkt från din odling!",severity:"tip"},{icon:"warning",title:"Frostskydd",text:"Squash dör vid minsta frost. Plantera inte ut förrän nätterna håller sig över 10°C. Ha alltid fiberduk redo i juni - kalla nätter kan komma.",severity:"warning"},{icon:"leaf",title:"Vintersquash lagras i MÅNADER",text:"Butternut och andra vintersquash lagras i 3-6 månader i rumstemperatur. Härda dem i solen en vecka efter skörd - det förlänger hållbarheten rejält.",severity:"tip"}],sowing:{method:"both",label:"Direktsådd eller förodling",description:"Förodling inomhus rekommenderas i de flesta zoner - squash behöver värme och en lång säsong. I zon 1-2 kan du direktså utomhus från juni.",steps:["Så 2-3 frön per kruka, 2-3 cm djupt, i stor kruka (minst 8 cm)","Håll varmt (20-25°C) - fröna gror på 5-7 dagar","Gallra till en planta per kruka när de fått första riktiga bladen","Härda av i en vecka genom att ställa ut dagtid, in på natten","Plantera ut när natttemperaturen håller sig över 10°C","Plantera med god marginal - minst 80 cm mellan plantorna","Vattna ordentligt vid plantering och mulcha runt plantan"],tips:["Så inte för tidigt inomhus - squashplantor växer fort och blir långa och rangliga i fönstret. 3-4 veckor räcker.","Direktsådd fungerar i zon 1-2 från juni, men förodling ger alltid försprång",'Odla gärna i en "squashkulle" - höjd bädd med kompost undertill som ger extra värme och näring'],indoorWeeks:"3-4 veckor"},seedSaving:{difficulty:"Medel",type:"Korspollinerare",biennial:!1,description:"Squash korspolleras av insekter inom samma art. Sorter av samma art (C. pepo) korsar sig, men C. pepo korsar INTE med C. moschata (butternut).",steps:["Välj en fin, typisk frukt från den starkaste plantan","Låt frukten ligga kvar på plantan tills den är helt mogen (hård, gulnad zucchini, orange butternut)","Skär upp och skrapa ut fröna med en sked","Lägg fröna i en skål med vatten - de som sjunker är bra, de som flyter är tomma","Skölj och torka fröna på tidningspapper i 1-2 veckor","Förvara torrt och svalt i papperspåse"],isolation:"Korspollinerare via insekter. Odla bara en sort per art (C. pepo, C. moschata, C. maxima) för rent frö, eller handpollera och tejpa igen blommorna.",storageYears:"4-6 år",tip:"Squashfrön håller sig länge! Men dubbelkolla att du inte har F1-hybrider - deras frön ger oförutsägbara resultat."},storage:{shelfLife:"1-6 månader (beroende på typ)",methods:[{method:"Färsk i kylskåp (zucchini)",icon:"snowflake",duration:"1-2 veckor",description:"Zucchini och sommarsquash förvaras i plastpåse med hål i kylskåpet. Ät inom en vecka för bäst smak och konsistens.",best:!0},{method:"Rumstemperatur (vintersquash)",icon:"storage",duration:"3-6 månader",description:"Butternut, spagetti och andra vintersquash lagras svalt (12-15°C) på en torr plats. Härda i solen en vecka först.",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Skär i skivor/tärningar, blanchera 2 minuter, kyl och frys. Fungerar bra i soppor och grytor. Konsistensen ändras - inte för sallad.",best:!1},{method:"Riva och frysa",icon:"snowflake",duration:"6-8 månader",description:"Riv rå zucchini och frys i portionspåsar. Perfekt för plättar, bröd och gratänger. Inget behov av blanchering.",best:!1}],tips:["Zucchini har kort hållbarhet - ät den inom en vecka","Vintersquash ska härdas i solen 7-10 dagar efter skörd - det gör skalet hårdare och förlänger lagringstiden","Förvara aldrig vintersquash i kylskåp - kylan ger svampangrepp","Den enorma zucchinin du glömde i landet kan rivas och frysas - den blir utmärkt till plättar och bröd"]},harvestCalc:{minPerSqm:2,maxPerSqm:5,unit:"kg"}},Za=Object.freeze(Object.defineProperty({__proto__:null,squash:fr},Symbol.toStringTag,{value:"Module"})),jr={name:"Störböna",icon:"storbona",family:"Baljväxter",familyLatin:"Fabaceae",difficulty:"Enkel",difficultyWhy:"Direktsås, fixar sitt eget kväve och ger skörd i veckor. Det enda du behöver ordna är stöd - sen sköter hon resten själv.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:[6,7]},days:"60-80",spacing:"15-20 cm",rowSpacing:"60-80 cm",depth:"3-5 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmar sol per dag. Störbönan älskar värme och ljus - hon klättrar mot solen och belönar dig med fler baljor ju mer sol hon får."},temperature:{min:10,max:30,ideal:"18-25°C",detail:"Gror inte under 10°C i jorden - ha tålamod och vänta tills marken verkligen värmt upp sig. Hon trivs bäst i 18-25°C och slutar växa vid temperaturer under 12°C. Frost är döden - inte en chans."},wind:{level:"Skyddat",detail:"Störbönan klättrar 2-3 meter högt och behöver vindskydd. Höga plantor på störar eller spaljéer fångar vinden som segel - en ordentlig blåst kan knäcka rankor och välta stöd."}},watering:{need:"Medel",icon:"water",summary:"Störbönan klarar sig hyfsat på egen hand, men under blomning och baljesättning vill hon ha ordentligt med vatten. Torka då = tomma baljor och sega bönor.",phases:[{phase:"Groning (0-2 veckor)",need:"Medel",tip:"Vattna väl vid sådd - fröna behöver fukt för att svälla och gro. Jorden ska vara jämnt fuktig men inte dränkt."},{phase:"Tillväxt (2-5 veckor)",need:"Låg",tip:"Störbönan bygger sin rankbas nu och klarar sig bra på naturlig nederbörd. Lite lagom törst får rötterna att söka sig djupare."},{phase:"Klättring & blomning (5-8 veckor)",need:"Hög",tip:"Kritisk period! Hon växer på höjden och blommar samtidigt - vattenstress nu gör att blommorna faller av utan att sätta baljor. Vattna djupt 2-3 gånger i veckan vid torrt väder."},{phase:"Baljesättning (8+ veckor)",need:"Medel-Hög",tip:"Fortsätt vattna jämnt. Baljorna växer snabbt nu och behöver vatten för att bli spröda och saftiga istället för sega och trådiga."}],mistakes:["Sår för tidigt i kall jord - fröna ruttnar istället för att gro","Glömmer vattna under blomning - den absolut viktigaste perioden för skörd","Vattnar ovanifrån sent på dagen - fuktiga blad bjuder in svampsjukdomar"],tip:"Mulcha runt plantorna med gräsklipp eller halm. Det håller fukten jämn, jorden varm och ogräset borta - tre flugor i en smäll."},soil:"Trivs bäst i lös, varm och mullrik jord med bra dränering. Hon är inte kräsen men ger mer i en omhändertagen odlingsbädd.",soilTips:["Inget extra kväve behövs - störbönan fixar sitt eget via Rhizobium-bakterier på rötterna","Jobba in lite kompost på hösten före - det ger den mullrika, luftiga jord som bönor älskar","Undvik att gödsla med stallgödsel samma år - för mycket kväve ger massor av blad men få baljor"],timeline:{1:[{phase:"Direktså",months:"Maj",icon:"seedling"},{phase:"Klättring & blomning",months:"Jun-Jul",icon:"flower"},{phase:"Skörd",months:"Jul-Sep",icon:"harvest"}],4:[{phase:"Förså inomhus",months:"Maj",icon:"seedling"},{phase:"Direktså / plantera ut",months:"Jun",icon:"seedling"},{phase:"Blomning",months:"Jul",icon:"flower"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}],6:[{phase:"Direktså (växthus)",months:"Jun",icon:"seedling"},{phase:"Blomning",months:"Jul-Aug",icon:"flower"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Maj",N:5,P:15,K:10,label:"Groning"},{month:"Jun",N:10,P:25,K:15,label:"Tillväxt & klättring"},{month:"Jul",N:10,P:45,K:40,label:"Blomning"},{month:"Aug",N:8,P:50,K:55,label:"Baljesättning"},{month:"Sep",N:5,P:30,K:40,label:"Skörd"}],nutritionTips:[{timing:"Vid sådd",tip:"Inget kväve! Störbönan fixar sitt eget via Rhizobium-bakterier. En liten giva benmjöl eller stenfosfat för fosfor räcker gott."},{timing:"Blomning",tip:"En lätt giva kaliumrik gödsel (vedaska eller alggödsel) stärker blomningen och hjälper baljorna att fylla på."},{timing:"Under säsongen",tip:"Störbönan är anspråkslös - hon ger mer till jorden än hon tar. Övergödsla med kväve och du får en grön vägg utan baljor."},{timing:"Efter skörd",tip:"Klipp av plantan vid markytan men LÅT RÖTTERNA SITTA KVAR. Kvävebakterierna fortsätter gödsla jorden åt nästa gröda - helt gratis."}],companions:{good:[{id:"morot",name:"Morot",icon:"morot",why:"Morötter luckrar jorden på djupet medan störbönan fixar kväve - drömgrannar som hjälper varandra"},{id:"gurka",name:"Gurka",icon:"vegetable",why:"Gurkorna breder ut sig vid marken och håller fukten medan bönorna klättrar uppåt - smart samarbete i höjd och bredd"},{id:"squash",name:"Squash",icon:"vegetable",why:"Klassisk kombination - squash täcker marken med sina stora blad, bönan klättrar uppåt och fixar kväve åt alla"},{name:"Majs",icon:"vegetable",why:"De tre systrarnas metod - majs som levande bönstör, bönan fixar kväve och squash täcker marken. Urgammal och genial samplantering."}],bad:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökväxter anses kunna hämma bönans kvävefixering via sina svavelhaltiga ämnen - bäst att hålla dem åtskilda"},{id:"vitlok",name:"Vitlök",icon:"vegetable",why:"Samma problem som lök - allicin i vitlök kan påverka Rhizobium-bakterierna negativt"}]},rotation:{avoid:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"brytbona",name:"Brytböna"}],avoidWhy:"Alla baljväxter delar sjukdomar som rotröta och bönflugor. Vänta minst 4 år innan du sår baljväxter på samma plats.",goodBefore:[{id:"potatis",name:"Potatis"},{id:"lok",name:"Lök"},{id:"squash",name:"Squash"}],goodBeforeWhy:"Potatisens luckring och lökens sanering gör jorden redo. Squash bryter också sjukdomscykler bra.",goodAfter:[{id:"gronkal",name:"Grönkål",category:"grönsaker"},{id:"sallat",name:"Sallat"},{id:"squash",name:"Squash"}],goodAfterWhy:"Kvävehungriga grödor som kål, sallat och squash älskar jorden efter störböna - den är fullpumpad med kväve."},varieties:[{name:"Neckarkönigin",zones:[1,2,3,4,5],note:"Rikbärande OP-klassiker med gröna, raka baljor. Pålitlig och lättodlad - det säkra valet. Finns hos Impecta och Runåbergs."},{name:"Blauhilde",zones:[1,2,3,4,5],note:"Fantastiskt vacker OP-sort med djupt blålila baljor. Lika god som snygg - baljorna blir gröna vid tillagning. Finns hos Impecta."},{name:"Goldmarie",zones:[1,2,3,4],note:"Gul vaxböna med mild, smörig smak. Kulturarvsmärkt svensk sort som ger vackra gula baljor - fint som kontrast till gröna sorter. Finns hos Impecta."},{name:"Cobra",zones:[1,2,3,4,5],note:"Tidig och pålitlig OP-sort med gröna, trådlösa baljor. Sätter baljor rikligt och tidigt - bra val för kortare säsonger. Finns hos Impecta och Lindbloms."}],problems:[{name:"Bönflugan",symptom:"Fröna gror dåligt eller inte alls - larverna äter fröna inifrån",fix:"Så i varm jord (minst 12°C) så att fröna gror snabbt förbi det känsliga stadiet. Täck med fiberduk de första veckorna."},{name:"Gråmögel (Botrytis)",symptom:"Gråbrunt ludd på blad, stjälkar och baljor, speciellt i fuktigt väder",fix:"Luftig plantering (inte för tätt), vattna vid roten och aldrig ovanifrån. Ta bort drabbade delar direkt."},{name:"Bladlöss",symptom:"Kolonier av gröna eller svarta löss på skottspetsar och baljor",fix:"Spruta av med stark vattenstråle. Nyckelpigorna och blomflugor är dina bästa allierade - locka dem med blommande kryddväxter intill."},{name:"Bönrost",symptom:"Bruna-orange pustlar på bladens undersida, vanligast sent i säsongen",fix:"Ta bort drabbade blad. Bra luftcirkulation och växtföljd. Störbönans höjd ger bättre luftning än buske-bönor, men håll koll ändå."}],goodToKnow:[{icon:"warning",title:"Stöd är ett MÅSTE",text:"Störbönan klättrar 2-3 meter högt och BEHÖVER något att ta tag i. Sätt upp störar, spaljéer eller nät INNAN du sår. Utan stöd får du en trasslig härva på marken som ruttnar och ger minimal skörd. Klassiska bönstörar i tipiform är både snygga och funktionella.",severity:"warning"},{icon:"harvest",title:"Skörda ofta - det ger MER",text:"Störbönans bästa hemlighet: ju oftare du plockar, desto fler baljor sätter hon. Sluta plocka och hon slutar blomma. Skörda varannan till var tredje dag under högsäsong - du blir förvånad över hur mycket en enda klätterplanta kan ge.",severity:"tip"},{icon:"leaf",title:"Kvävefixerare - gratis gödsel",text:"Precis som alla baljväxter fixar störbönan kväve ur luften via Rhizobium-bakterier på rötterna. Klipp av plantan vid skörd men lämna rötterna kvar i jorden. Nästa gröda får gratis gödsling.",severity:"tip"},{icon:"warning",title:"Frost är döden",text:"Störbönan tål INGEN frost. Inte ens en lätt nattfrost. Vänta med sådden tills frostrisken verkligen är över och jorden håller minst 10°C. Bättre en vecka för sent än en dag för tidigt.",severity:"warning"},{icon:"tip",title:"Vacker som insynsskydd",text:"Störbönor på spaljé bildar en tät, grön vägg på 2-3 meter. Perfekt som sommarens insynsskydd på altanen eller för att dölja komposten. Blauhilde med sina lila baljor är extra dekorativ.",severity:"tip"},{icon:"tip",title:"Längre skörd än brytböna",text:"Medan brytbönan ger allt på några veckor, producerar störbönan baljor under hela sommaren så länge du plockar. En rad störbönor kan ge skörd från juli till första frosten.",severity:"tip"},{icon:"warning",title:"Rör inte blöta plantor",text:"Gå aldrig bland bönplantorna när de är blöta av regn eller dagg. Svampsjukdomar sprider sig via vattendroppar och dina händer blir budbärare. Vänta tills plantorna torkat upp.",severity:"warning"}],sowing:{method:"direct",label:"Direktsådd",description:"Störbönan sås helst direkt på friland vid stöden. Vänta tills jorden verkligen är varm (minst 10°C) - kalla, blöta frön ruttnar fort. I zon 4-5 kan du förså inomhus för att vinna tid.",steps:["Sätt upp stöden FÖRST - störar, spaljé eller nät, minst 2 meter högt","Vänta tills frostrisken är över och jorden håller minst 10°C","Gör hål 3-5 cm djupa vid varje stör, eller spår längs spaljén","Lägg 2-3 frön vid varje stör med 15-20 cm avstånd längs spaljé","Täck med jord och tryck till lätt","Vattna försiktigt men ordentligt","Hjälp de unga rankorna att hitta stödet de första dagarna - sen klarar de sig själva"],tips:["Lägg svart plast på såddbädden en vecka innan för att värma jorden - det ger snabbare groning","I zon 4-5: förså i torvkrukor inomhus 2-3 veckor före utplantering. Var försiktig med rötterna!","Bönstörar i tipiform (3-4 störar som möts i toppen) är stabila och vackra","Räkna med 60-80 cm mellan raderna så du kan komma åt och skörda"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Självpollinerare",biennial:!1,description:"Störbönan är självpollinerare och en av de enklaste grödorna att spara frö från. Låt ett par plantor stå orörda och låt baljorna torka helt på plantan.",steps:["Välj de friskaste och mest produktiva plantorna - märk dem tidigt och PLOCKA INTE baljor från dessa","Låt baljorna sitta kvar tills de är helt torra, gulbruna och skramlar","Plocka de torra baljorna och lägg dem inomhus på tidningspapper i en vecka","Bryt upp baljorna och plocka ut bönorna","Kontrollera att bönorna är hårda och utan fläckar eller hål","Förvara i papperspåse eller glasburk på sval, torr plats"],isolation:"Övervägande självpollinerare men viss korsbefruktning (3-5%) kan förekomma via insekter. 3-6 m avstånd mellan sorter räcker för rimlig sortrenhet.",storageYears:"3-4 år",tip:"Störbönans stora frön är perfekta att börja fröspara med. Lätta att hantera och de håller bra. Runåbergs och Impecta har fina OP-sorter att utgå ifrån."},storage:{shelfLife:"5-7 dagar (färska) / 1-2 år (torkade)",methods:[{method:"Färska i kylskåp",icon:"snowflake",duration:"5-7 dagar",description:"Lägg otvättade bönor i plastpåse i kylskåpet. Tvätta precis innan du lagar dem. Ät helst inom ett par dagar - sprödheten avtar snabbt.",best:!0},{method:"Frysa (bästa långtidslagring)",icon:"snowflake",duration:"8-12 månader",description:"Bryt bönorna i lagom bitar, blanchera 2-3 minuter, kyl i isvatten, torka och frys in på plåt. Flytta till påse. Behåller färg och smak utmärkt.",best:!1},{method:"Inläggning",icon:"storage",duration:"6-12 månader",description:"Klassiskt svenska inlagda bönor i ättikslag med senapsfrön och dill. Perfekt till husmanskost.",best:!1},{method:"Torka",icon:"sun",duration:"1-2 år",description:"Låt baljorna mogna och torka helt på plantan. De torkade bönorna blötläggs och kokas - nyttig stapelvara till soppor och grytor.",best:!1}],tips:["Unga störbönor ska vara spröda och brytas med ett knäpp - sega baljor har hängt för länge","Blanchera och frys in samma dag du skördar - det ger bäst smak och textur","Störbönans längre skörd gör att du kan frysa in i omgångar istället för allt på en gång","Inlagda bönor i ättikslag är en svensk sommarklassiker - recept finns i varenda syltbok"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3,unit:"kg"}},Xa=Object.freeze(Object.defineProperty({__proto__:null,storbona:jr},Symbol.toStringTag,{value:"Module"})),yr={name:"Svarta vinbär",icon:"svarta-vinbar",category:"bär",family:"Ripsväxter",familyLatin:"Grossulariaceae",perennial:!0,lifespan:"15-20 år",difficulty:"Enkel",difficultyWhy:"Extremt härdig buske som klarar allt svenskt klimat kan kasta mot den. Minimal skötsel utöver enkel årlig beskärning. Isbjörnen bland bären.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:null},days:"70-90",spacing:"120-150 cm",rowSpacing:"200-250 cm",depth:"Något djupare än i krukan",ph:{min:5.5,max:7,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Trivs bäst i full sol men ger bra skörd även i halvskugga. I södra Sverige kan lite skugga under eftermiddagen faktiskt vara positivt - buskarna stressar mindre."},temperature:{min:-30,max:30,ideal:"15-22°C",detail:"Isbjörnen bland bärbuskarna - tål ner till -30°C utan att blinka! Blommar tyvärr ganska tidigt på våren, så sena nattfroster kan ta blommorna. Trivs bäst i sval svensk sommar."},wind:{level:"Tålig",detail:"Klarar vind bra tack vare kompakt växtsätt. Vindskydd förbättrar dock pollinering och därmed skörd - humlorna gillar inte att jobba i storm."}},watering:{need:"Medel",icon:"water",summary:"Svarta vinbär har ganska grunda rötter och behöver jämn fukt, speciellt under blomning och bärutveckling. Men de är inte lika törstiga som hallon.",phases:[{phase:"Vår (knoppsprickning)",need:"Medel",tip:"Vattna vid torr vår - busken drar igång tidigt och behöver fukt för att driva knoppar och blommor."},{phase:"Blomning (maj-juni)",need:"Hög",tip:"Kritisk period! Vattenstress nu ger dålig fruktbildning. Bären trillar av innan de mognat. Vattna djupt 2 ggr/vecka vid torka."},{phase:"Bärmognad (juni-juli)",need:"Hög",tip:"Jämn fukt ger stora, saftiga bär. Ojämn vattning kan ge sprickta bär. Mulcha runt busken för att hålla fukten."},{phase:"Höst (efter skörd)",need:"Låg",tip:"Minska vattningen. Busken förbereder sig för vintervilka och behöver inte mycket."}],mistakes:["Vattnar för lite under blomning - bären sätter inte frukt","Ojämn vattning under mognad - ger sprickta bär","Glömmer nyplanterade buskar - de behöver extra omsorg första sommaren"],tip:"Mulcha med gräsklipp, bark eller halm runt busken. Håller fukten, matar maskar och håller ogräs borta - perfekt för den som vill odla lite mer på latsidan."},soil:"Svarta vinbär trivs i näringsrik, fukthållande men väldränerad jord. De gillar lite tyngre jord än hallon och klarar faktiskt lerjord ganska bra - bara den inte är kompakt och vattensjuk.",soilTips:["Blanda in rikligt med kompost vid plantering - de är hungriga buskar","Mulcha årligen med kompost, bark eller gräsklipp","Klarar lerjord bättre än de flesta bärväxter, men blanda i lite sand om jorden är riktigt kompakt","Undvik kalkrik jord - svarta vinbär föredrar svagt surt till neutralt pH"],timeline:{1:[{phase:"Plantering",months:"Maj-juni",icon:"seedling"},{phase:"Blomning",months:"Juni",icon:"bloom"},{phase:"Skörd",months:"Juli-aug",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (mars)",icon:"scissors"},{phase:"Vintervila",months:"Nov-apr",icon:"snowflake"}],4:[{phase:"Plantering",months:"April-maj",icon:"seedling"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Skörd",months:"Juli",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (feb-mars)",icon:"scissors"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],6:[{phase:"Plantering",months:"Mars-april",icon:"seedling"},{phase:"Blomning",months:"April-maj",icon:"bloom"},{phase:"Skörd",months:"Juni-juli",icon:"harvest"},{phase:"Beskärning",months:"Sen vinter (feb)",icon:"scissors"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:4,P:2,K:2},{month:"Maj",N:6,P:4,K:3},{month:"Jun",N:5,P:5,K:6},{month:"Jul",N:3,P:4,K:8},{month:"Aug",N:2,P:3,K:5},{month:"Sep",N:1,P:2,K:3}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge en rejäl giva brunnen gödsel eller kompost runt busken. Svarta vinbär är hungriga och tackar med riklig skörd."},{timing:"Blomning (maj)",tip:"En giva kaliumrik gödsel (typ tomatgödsel) stärker blomning och bärkvalitet. Kalium ger smak!"},{timing:"Efter skörd",tip:"Ingen gödsling efter juli - busken ska förbereda sig för vinter, inte skjuta nya skott."}],companions:{good:[{id:"ringblomma",name:"Ringblomma",icon:"flower",why:"Lockar pollinatörer till buskarna under blomning. Svarta vinbär behöver bra pollinering för full skörd."},{id:"artor",name:"Ärtor",icon:"vegetable",why:"Fixerar kväve i jorden som bärbuskarna uppskattar. Bra granne i närheten."},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Samma nytta som ärtor - kvävefixerare som matar jorden. Växer dessutom upprätt och konkurrerar inte om utrymmet."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Kan sprida svampsjukdomar som drabbar vinbärsbuskarna. Håll bra avstånd."}]},rotation:{avoid:[{id:"krusbar",name:"Krusbär"},{id:"roda-vinbar",name:"Röda vinbär"},{id:"vita-vinbar",name:"Vita vinbär"},{id:"svarta-vinbar",name:"Svarta vinbär"}],avoidWhy:"Alla Ribes-arter delar sjukdomar (mjöldagg, bladfallsjuka, gallkvalster). Plantera inte nya vinbär där gamla stått - vänta minst 5 år.",goodBefore:[{name:"Solig, öppen plats"},{name:"Baljväxter"},{name:"Gräsmatta"}],goodBeforeWhy:"En plats som legat som gräsmatta eller odlats med baljväxter ger frisk, kväverik jord - perfekt startplats för en vinbärsbuske.",goodAfter:[{name:"Gröngödsling"},{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodAfterWhy:"Efter 15-20 år med vinbär är jorden utarmad. Gröngödsling och baljväxter bygger upp den igen."},varieties:[{name:"Öjebyn",zones:[1,2,3,4,5,6],note:"Klassisk svensk sort (funnen i Norrbotten 1940-talet). Extremt härdig, pålitlig och smakar precis som svarta vinbär ska smaka. E-planta."},{name:"Ben Lomond",zones:[1,2,3,4,5,6],note:"Skotsk storsäljare (SCRI). Stora bär, hög skörd, upprätt växtsätt som gör plockning enkel."},{name:"Titania",zones:[1,2,3,4,5,6],note:"Svenskodlad, sjukdomsresistent och produktiv. Stora bär med mild smak. Bra val om mjöldagg är problem."},{name:"Ben Sarek",zones:[1,2,3,4,5],note:"Kompakt buske (ca 1,5 m) - perfekt för liten trädgård. Stora bär trots liten buske. Behöver bra jord."}],problems:[{name:"Mjöldagg",symptom:"Vitt, mjöligt belägg på blad och skottspetsar. Bladen krälar ihop sig och nya skott hämmas.",fix:"Välj resistenta sorter (Titania!). God luftcirkulation genom gallring. Klipp bort angripna skottspetsar tidigt."},{name:"Vinbärsgallkvalster",symptom:'Onormalt stora, runda knoppar på vintern/våren ("gallknoppar"). Knopparna utvecklas inte till blad.',fix:"Plocka bort och bränn svullna knoppar under senvintern. Vid kraftigt angrepp - byt till nya plantor på ny plats."},{name:"Bladfallsjuka",symptom:"Bruna fläckar på bladen som sedan faller av i förtid. Busken tappar bladen redan i juli-augusti.",fix:"Rensa bort nedfallna löv (svampen övervintrar där). God gallring ger bättre luftcirkulation. Friska buskar klarar sig."}],goodToKnow:[{icon:"tip",title:"C-vitaminbomben",text:"Svarta vinbär innehåller 3-4 gånger mer C-vitamin än apelsiner! En liten näve bär om dagen räcker gott och väl. Historiskt användes de mot skörbjugg i Sverige.",severity:"tip"},{icon:"tip",title:"Bladen doftar fantastiskt",text:"Krossa ett blad mellan fingrarna - den där kryddiga, lite kattiga doften är unik för svarta vinbär. Bladen kan också användas till te!",severity:"tip"},{icon:"tip",title:"Fryser briljant",text:"Svarta vinbär är som gjorda för frysen. Lägg bären i påsar direkt - de fryser lösa och behöver inte ens läggas ut på plåt först. Perfekt till saft, sylt och smoothies året runt.",severity:"tip"},{icon:"warning",title:"Blommar tidigt - frostfällan",text:"Trots sin extrema härdighet blommar svarta vinbär tidigt på våren. Sena nattfroster kan ta blommorna och då blir det ingen skörd. Undvik frosthål vid plantering!",severity:"warning"},{icon:"tip",title:"Klassisk svensk mångkamp",text:"Saft, sylt, gele, likör, sås till kött, glass, sorbet - svarta vinbär är den mest mångsidiga bärbusken i trädgården. En enda buske ger 3-5 kg bär per år.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Svarta vinbär planteras som barrotade buskar (höst eller tidig vår) eller krukodlade plantor (hela säsongen). Plantera gärna något djupare än i krukan - det stimulerar nya skott från basen.",steps:["Gräv en grop dubbelt så bred som rotklumpen och lika djup plus 5 cm","Blanda in rikligt med kompost i jorden","Plantera något djupare än busken stod i krukan - stimulerar basala skott","Vattna rikligt vid plantering","Klipp ner alla grenar till 2-3 knoppar ovan mark (ja, verkligen!)","Mulcha med bark eller gräsklipp runt busken"],tips:["Höstplantering (okt-nov) ger bäst etablering - rötterna jobbar hela vintern","Klipp ner busken hårt vid plantering - det känns brutalt men ger en starkare buske","Första skörden kommer år 2, full skörd från år 3-4"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Svarta vinbär förökas enklast med vedartade sticklingar på hösten. Det är nästan löjligt enkelt - sticklingar av svarta vinbär har extremt hög rotningsfrekvens.",steps:["Klipp 20-25 cm långa sticklingar av årets skott i oktober-november","Klipp snett i nedre änden, rakt i övre","Sätt sticklingarna i fuktig jord utomhus med 2-3 knoppar ovan mark","Vattna vid torka under vintern","Sticklingarna rotar sig under vintern och kan planteras ut nästa höst"],isolation:"Vegetativ förökning - kloner av moderplantan. Ingen korspollinering relevant.",storageYears:"Ej tillämpligt",tip:"Svarta vinbär är champions på sticklingsförökning - nästan varje stickling rotar sig. Passa på att göra extra när du ändå beskär på hösten. Perfekt att ge bort till grannar!"},storage:{shelfLife:"3-5 dagar (färska)",methods:[{method:"Frysning",icon:"snowflake",duration:"12+ månader",description:"Det överlägset bästa sättet. Svarta vinbär fryser briljant - bara ner med dem i påsar direkt från busken. De fryser lösa av sig själva tack vare det tjocka skalet.",best:!0},{method:"Saft",icon:"storage",duration:"1+ år",description:"Svartvinbärssaft är en svensk klassiker. Koka bären med vatten, sila och tillsätt socker. Koncentrerad saft späds med vatten - en flaska räcker länge.",best:!1},{method:"Sylt och gele",icon:"storage",duration:"1+ år",description:"Svarta vinbär har naturligt hög pektinhalt och gelerar perfekt utan extra tillsatser. Gelen är fantastisk till ost.",best:!1},{method:"Torkning",icon:"sun",duration:"6+ månader",description:"Torka i ugn på 50-60°C i 10-14 timmar. Blir intensivt söta och nästan lakritslika. Perfekt i müsli.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"3-5 dagar",description:"I en skål med hushållspapper i kylskåpet. Tvätta inte förrän du ska använda dem.",best:!1}],tips:["Plocka hela klasar - det går snabbare och bären håller sig bättre","Rensa bären från stjälkar med en gaffel - dra klasen genom gaffelns tänder","Frys i portionspåsar - perfekt att ta fram till en smoothie eller sås"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3,unit:"kg"},pruning:{label:"Beskärning",types:{maintenance:{name:"Underhållsbeskärning",when:"Tidig vår (feb-mars) innan knopparna svällt",description:"Svarta vinbär bär bäst på 1-3 år gammal ved. Äldre grenar ger mindre och sämre bär. Varje år tar du bort de äldsta grenarna och låter nya ta över. En frisk buske har 8-12 grenar av blandad ålder.",steps:["Ta bort alla grenar som är 3+ år gamla (mörkare bark, grövre) vid basen","Ta bort svaga, korsande eller skadade grenar","Spara 3-4 starka nya skott från föregående år","Sikta på 8-12 grenar totalt i busken","Klipp gärna tillbaka sidoskott till 2-3 knoppar"]},rejuvenation:{name:"Föryngringsbeskärning",when:"Tidig vår",description:"Har busken blivit gammal och risig? Ingen panik. Svarta vinbär tål att klippas ner hårt. Klipp ner hela busken till 10-15 cm ovan mark. Den skjuter nya friska skott och ger skörd igen om 2 år.",steps:["Klipp ner ALLA grenar till 10-15 cm ovan mark","Gödsla med kompost runt busken","Vattna ordentligt under våren","Gallra de nya skotten till 8-10 stycken under sommaren","Skörd igen från år 2 efter klippningen"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Vedartade sticklingar",description:"Det absolut enklaste sättet att föröka svarta vinbär. Klipp 20-25 cm bitar av årets mogna skott i oktober-november. Sätt i fuktig jord utomhus med bara 2-3 knoppar ovan mark. Rotningsfrekvensen är fantastisk - nästan 100%.",icon:"scissors"},{method:"Nedböjning (marklager)",description:"Böj ner en låg gren och fäst den mot marken med en bygel. Täck med jord. Grenen rotar sig under säsongen och kan klippas loss och planteras om nästa höst.",icon:"seedling"}],tip:"Sticklingar av svarta vinbär är löjligt enkla. Gör alltid extra när du ändå beskär - ge bort till vänner, sätt i en rad som häck, eller sälj på loppis. Alla borde ha en svartvinbärsbuske!"}},Qa=Object.freeze(Object.defineProperty({__proto__:null,svartaVinbar:yr},Symbol.toStringTag,{value:"Module"})),Sr={name:"Björnbärshallon",icon:"tayberry",category:"bär",family:"Rosväxter",familyLatin:"Rosaceae",perennial:!0,lifespan:"10-15 år",difficulty:"Enkel",difficultyWhy:"Björnbärshallon (tayberry/taybär) odlas precis som sommarhallon - rankande skott, stöd och årlig beskärning av fruktbärande skott. Lite mindre härdig än hallon men i zon 1-4 trivs hon fint. En korsning mellan hallon och björnbär som ger det bästa av båda världar.",zones:{outdoor:[1,2,3],indoor:null,greenhouse:[1,2,3,4,5]},days:"Skörd år 2+",spacing:"200-250 cm",spacingNote:"Björnbärshallon behöver mer utrymme än hallon - de rankande skotten blir långa",rowSpacing:"250-300 cm",depth:"Samma djup som i krukan",ph:{min:5.5,max:6.5,ideal:6},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Björnbärshallon vill ha full sol för sötaste bär och rikligast skörd. Lite eftermiddagsskugga tolereras men ger sämre smakutveckling. Placera gärna mot en solig sydvägg - värmen påskyndar mognaden."},temperature:{min:-20,max:30,ideal:"18-25°C",detail:"Inte riktigt lika härdig som hallon - tål ner till ca -20°C. I zon 5-6 behöver skotten vinterskydd (täck med granris eller fiberduk). I zon 1-4 klarar hon sig fint. Utvecklad i Skottland för liknande klimat som södra Sverige."},wind:{level:"Måttligt känslig",detail:"De långa, rankande skotten (2-3 meter) är känsliga för vind. Stöd och vindskydd är viktigt. Plantera gärna intill ett staket, spaljé eller sydvägg."}},watering:{need:"Medel-Hög",icon:"water",summary:"Björnbärshallon har grunda rötter precis som hallon och behöver jämn fukt under blomning och mognad. Mulcha ordentligt och vattna regelbundet under torra perioder.",phases:[{phase:"Vår (utbrytning)",need:"Medel",tip:"Busken vaknar och nya skott börjar växa. Vattna vid torr vår - bra start ger längre, starkare skott."},{phase:"Blomning (juni)",need:"Hög",tip:"Kritisk period! Torka nu ger dålig fruktsättning. Vattna djupt 2-3 ggr/vecka om det inte regnar."},{phase:"Bärmognad (juli-aug)",need:"Hög",tip:"Jämn fukt ger stora, saftiga bär. Ojämn vattning kan ge små bär som inte utvecklas fullt."},{phase:"Höst (efter skörd)",need:"Låg",tip:"Minska vattningen. Årets nya skott ska hinna mogna och förbereda sig för vintern."}],mistakes:["Vattnar för lite under blomning och mognad - ger små, torra bär","Vattnar ovanifrån under mognad - bären möglar lättare","Glömmer nyplanterade buskar första sommaren"],tip:"Dropp-bevattning eller vattenslang vid basen är perfekt. Mulcha rikligt med bark eller halm - björnbärshallon uppskattar jämn markfukt precis som hallon."},soil:"Björnbärshallon vill ha samma jord som hallon: humusrik, väldränerad och lätt sur till neutral. Hon hatar stående vatten och tung, kompakt lerjord. Blanda in rikligt med kompost vid plantering.",soilTips:["Blanda in kompost och lite sand vid plantering - dränering är viktigt","På lerjord: plantera upphöjt eller blanda in grov sand ordentligt","Mulcha årligen med bark eller halm - björnbärshallon älskar mulch","Undvik mark där det stått potatis, tomater eller hallon senaste 3 åren (verticillium-risk)"],timeline:{1:[{phase:"Plantering",months:"Okt-nov eller april-maj",icon:"seedling"},{phase:"Blomning",months:"Juni",icon:"bloom"},{phase:"Skörd",months:"Juli-aug",icon:"harvest"},{phase:"Beskärning",months:"Aug-sept (efter skörd)",icon:"scissors"},{phase:"Vintervila",months:"Nov-apr",icon:"snowflake"}],4:[{phase:"Plantering",months:"Okt eller april-maj",icon:"seedling"},{phase:"Blomning",months:"Juni",icon:"bloom"},{phase:"Skörd",months:"Juli",icon:"harvest"},{phase:"Beskärning",months:"Juli-aug (efter skörd)",icon:"scissors"},{phase:"Vintervila",months:"Okt-apr",icon:"snowflake"}],6:[{phase:"Plantering",months:"Maj",icon:"seedling"},{phase:"Blomning",months:"Juni-juli",icon:"bloom"},{phase:"Skörd",months:"Juli-aug",icon:"harvest"},{phase:"Beskärning",months:"Aug (efter skörd)",icon:"scissors"},{phase:"Vintervila",months:"Sept-maj",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:3,P:2,K:2},{month:"Maj",N:6,P:4,K:3},{month:"Jun",N:5,P:5,K:5},{month:"Jul",N:4,P:5,K:7},{month:"Aug",N:3,P:3,K:5},{month:"Sep",N:1,P:2,K:3}],nutritionTips:[{timing:"Tidig vår (april)",tip:"Ge kompost eller brunnen hästgödsel runt basen. Björnbärshallon är hungrig precis som hallon - en bra vårstart ger starka skott och stor skörd."},{timing:"Blomning (juni)",tip:"Kaliumrik gödsel (tomatgödsel fungerar) stärker blomning och bärkvalitet. Ge vid blomningens start."},{timing:"Efter skörd (aug)",tip:"Ingen gödsling efter skörd. De nya skotten ska mogna och förbereda sig för vintern, inte fortsätta växa."}],companions:{good:[{id:"vitlok",name:"Vitlök",icon:"vegetable",why:"Starka doften avskräcker bladlöss. Klassisk kompanjon till bärbuskar som fungerar lika bra med björnbärshallon som med hallon."},{id:"ringblomma",name:"Ringblomma",icon:"flower",why:"Lockar pollinatörer under blomningen. Björnbärshallon behöver bra pollinering för fulla, stora bär."},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Fixerar kväve i jorden som björnbärshallon uppskattar. Växer upprätt och konkurrerar inte om utrymmet."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Delar verticillium-svamp. Plantera aldrig björnbärshallon där det stått potatis de senaste 3-4 åren."},{id:"hallon",name:"Hallon",icon:"berry",why:"Delar sjukdomar (virus, rotröta). Håll minst 30 meters avstånd för att minska risken för virussmitta."},{id:"bjornbar",name:"Björnbär",icon:"berry",why:"Samma familj, samma sjukdomar. Björnbärshallon är en hybrid av hallon och björnbär och delar alla deras svagheter."}]},rotation:{avoid:[{id:"hallon",name:"Hallon"},{id:"bjornbar",name:"Björnbär"},{name:"Björnbärshallon"},{id:"potatis",name:"Potatis"}],avoidWhy:"Alla Rubus-arter och Solanaceae delar sjukdomar. Vänta minst 4-5 år innan du planterar björnbärshallon på samma plats igen.",goodBefore:[{name:"Gräsmatta"},{name:"Baljväxter"}],goodBeforeWhy:"Mark som legat som gräsmatta eller odlats med baljväxter ger frisk, kväverik jord.",goodAfter:[{name:"Gröngödsling"},{id:"artor",name:"Ärtor"}],goodAfterWhy:"Efter 10+ år med björnbärshallon är jorden utarmad. Gröngödsling och baljväxter bygger upp den."},varieties:[{name:"Tayberry (original)",zones:[1,2,3],note:"Originalsorten från 1979, Scottish Crop Research Institute. Stora, långsträckta mörkröda bär med intensiv, aromatisk smak. Har taggar men ger bäst skörd. Kräver stöd för de långa skotten."},{name:"Buckingham Tayberry",zones:[1,2,3],note:"Taggfri mutation upptäckt 1998 i Buckinghamshire, England. Lite mindre bär och något lägre skörd än originalet, men så mycket trevligare att skörda och beskära. Samma fantastiska smak. Rekommenderas för hemträdgården."}],problems:[{name:"Gråmögel (Botrytis)",symptom:"Gråludigt mögel på mogna bär, speciellt i fuktig väderlek. Värst under regniga somrar.",fix:"God luftcirkulation genom gallring. Plocka bär ofta - lämna inte övermogna. Vattna vid basen, inte ovanifrån. Björnbärshallon är lite mer känslig för mögel än hallon."},{name:"Hallonänger",symptom:"Larver (vita, ~5 mm) i bären. Maskhål i mogna bär.",fix:"Feromonfällor i maj. Plocka och kassera angripna bär. Finmaskigt nät under blomning. Björnbärshallon kan drabbas precis som hallon."},{name:"Vinterskador",symptom:"Skotten bryter inte ut på våren eller dör tillbaka delvis. Vanligare i zon 5-6 och efter extremt kalla vintrar.",fix:"I utsatta lägen: böj ner skotten och täck med granris, halm eller fiberduk innan vintern. Lös upp på våren. Välj en skyddad plats från början."},{name:"Skottsjuka",symptom:"Purpurfärgade fläckar på skotten som utvidgas. Skotten vissnar och dör.",fix:"Klipp bort angripna skott vid basen och bränn dem. God luftcirkulation och gallring förebygger. Ta bara förökningsmaterial från friska plantor."}],goodToKnow:[{icon:"tip",title:"Det bästa av två världar",text:"Björnbärshallon (tayberry) är en korsning mellan hallon och björnbär, framtagen vid Scottish Crop Research Institute 1979. Hon kombinerar hallonets sötma med björnbärets fyllighet och ger en helt unik, aromatisk smak som många anser vara överlägsen båda föräldrarna.",severity:"tip"},{icon:"warning",title:"Behöver stöd",text:"Björnbärshallon har långa, rankande skott (2-3 meter) som MÅSTE ha stöd. Sätt upp trådar på stolpar eller använd ett befintligt staket. Utan stöd hamnar skotten på marken och bären ruttnar.",severity:"warning"},{icon:"tip",title:"Bären mognar ojämnt",text:"Bären mognar gradvis - från gröna till röda till djupt mörkröda/purpur. Plocka när de är djupt färgade och lossnar lätt. Ät inte röda bär - de är inte mogna och smakar surt. Perfekt mogna björnbärshallon smälter på tungan.",severity:"tip"},{icon:"warning",title:"Taggarna biter",text:"Originalsorten har rejäla taggar. Använd handskar vid skörd och beskärning! Buckingham Tayberry är taggfri och betydligt trevligare att hantera - rekommenderas varmt för hemträdgården.",severity:"warning"},{icon:"tip",title:"Skördefönstret",text:"Björnbärshallon mognar mellan hallon och björnbär - oftast i juli-augusti. Det ger dig bär under en period då hallonen börjar ta slut men björnbären inte mognat. Smart planering!",severity:"tip"},{icon:"tip",title:"Beskär som sommarhallon",text:"Björnbärshallon bär frukt på fjolårets skott - precis som sommarhallon. Efter skörd klipper du bort alla skott som burit bär vid basen. Bind upp årets nya skott - de bär nästa år.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Björnbärshallon planteras som krukodlade plantor eller barrotade buskar. Höstplantering ger bäst etablering i södra Sverige, vårplantering i zon 4-5.",steps:["Välj en solig, skyddad plats - gärna mot en sydvägg eller staket","Gräv en grop dubbelt så bred som rotklumpen","Blanda in rikligt med kompost","Plantera i samma djup som busken stod i krukan","Vattna rikligt vid plantering","Mulcha med bark eller halm","Sätt upp stöd (trådar på stolpar, 3 rader: 60 cm, 120 cm och 180 cm höjd)"],tips:["Plantera mot sydvägg i zon 4-5 - extravärmen gör stor skillnad","Stödsystemet måste vara på plats INNAN skotten börjar växa på våren","Buckingham Tayberry (taggfri) rekommenderas för hemträdgården","Full skörd från år 2-3"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Björnbärshallon förökas bäst med toppavläggning (tip layering) - den klassiska metoden för rankande Rubus. Skottspetsen böjs ner i jorden och rotar sig naturligt. Enklare kan det inte bli.",steps:["Välj ett friskt, kraftigt skott i slutet av sommaren (aug-sept)","Böj ner skottspetsen och gräv ner den 5-10 cm i jorden","Fäst med en bygel eller sten så att spetsen hålls på plats","Skottet rotar sig under hösten och vintern","Klipp loss den nya plantan från moderplantan nästa vår","Plantera om på sin nya plats"],isolation:"Vegetativ förökning - kloner av moderplantan. Ingen korspollinering relevant.",storageYears:"Ej tillämpligt",tip:"Toppavläggning är den naturliga förökningsmetoden - skottet söker naturligt marken med sin spets. Hjälp den på traven genom att gräva ner spetsen i god jord."},storage:{shelfLife:"2-3 dagar (färska)",methods:[{method:"Frysning",icon:"snowflake",duration:"10-12 månader",description:"Det bästa sättet att bevara björnbärshallon. Lägg ut i ett lager på bakplåtspapper, frys, flytta till påse. Behåller smak och form bättre än hallon tack vare det fastare bäret.",best:!0},{method:"Sylt och mos",icon:"storage",duration:"1+ år",description:"Björnbärshallonsylt har en djup, komplex smak - intensivare och mer aromatisk än hallonsylt. Koka med socker och en skvätt citron. En av de godaste sylterna du kan göra.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"2-3 dagar",description:"Björnbärshallon håller sig något bättre än hallon men fortfarande kort. Lägg i en skål på hushållspapper. Tvätta inte förrän du äter.",best:!1},{method:"Saft",icon:"storage",duration:"1+ år",description:"Safta med ångsaftare för en vackert djupröd, aromatisk saft. Underbar som dessertdryck eller blandat med vatten.",best:!1}],tips:["Plocka bara fullt mogna bär (djupt mörkröda/purpur) - omogna bär smakar surt","Bären lossnar lättare från tappen än hallon - plocka försiktigt","Björnbärshallon har fastare struktur än hallon och håller sig något bättre","Björnbärshallonsylt är en riktig delikatess - gör gärna extra"]},harvestCalc:{minPerSqm:.5,maxPerSqm:1.5,unit:"kg"},pruning:{label:"Beskärning",types:{maintenance:{name:"Årlig beskärning (efter skörd)",when:"Direkt efter skörd (juli-aug)",description:"Björnbärshallon bär frukt på fjolårets skott - precis som sommarhallon. Efter skörd klipper du bort alla grenar som burit frukt vid basen. Bind upp årets nya skott mot trådarna - de bär frukt nästa sommar.",steps:["Klipp bort alla skott som burit frukt vid basen","Välj ut 4-6 starka nya skott per planta","Ta bort alla svaga, tunna eller skadade skott","Bind upp de kvarvarande nya skotten mot trådarna","Sprid ut skotten jämnt så att luft och ljus når in","I zon 4-5: lägg ner skotten och täck med granris/fiberduk före vintern"]},rejuvenation:{name:"Föryngring",when:"Tidig vår",description:"Om plantan blivit förvuxen eller producerar dåligt, kan du klippa ner alla skott vid basen och börja om. Björnbärshallon skjuter nya skott kraftigt och ger skörd igen redan året efter.",steps:["Klipp alla skott vid basen","Välj ut 4-6 av de starkaste nya skotten","Gödsla med kompost","Bind upp mot stöd när de vuxit","Skörd igen nästa sommar på de nya skotten"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Toppavläggning (tip layering)",description:"Det klassiska sättet för rankande Rubus. Böj ner en skottspets i aug-sept och gräv ner 5-10 cm. Skottet rotar sig under hösten. Klipp loss och plantera om nästa vår. Enklast och säkrast.",icon:"seedling"},{method:"Vedartade sticklingar",description:"Klipp 15-20 cm bitar av mogna skott i november. Sätt i fuktig jord utomhus. Rotar sig under vintern men lägre lyckandefrekvens än toppavläggning.",icon:"scissors"}],tip:"Toppavläggning är den naturliga metoden - skottet söker själv marken. Gräv ner spetsen i aug-sept och du har en ny planta till våren. Mycket enklare och pålitligare än sticklingar."}},$a=Object.freeze(Object.defineProperty({__proto__:null,tayberry:Sr},Symbol.toStringTag,{value:"Module"})),xr={name:"Timjan",icon:"timjan",category:"kryddor",family:"Kransblommiga",familyLatin:"Lamiaceae",perennial:!0,lifespan:"4-6 år (föryngra genom delning)",difficulty:"Enkel",difficultyWhy:"Timjan är otroligt lättskött när hon väl etablerat sig. Torktålig, härdig och självgående - den enda utmaningen är att inte ge henne för mycket omtanke. Perfekt för den som vill ha en krydda som sköter sig själv.",zones:{outdoor:[2,3,4,5,6],indoor:[1,2,3,4,5,6,7,8],greenhouse:null},days:"70-90",spacing:"15-25 cm",rowSpacing:"30 cm",depth:"0.3 cm",depthNote:"Ljusgroddare - tryck fast men täck knappt",ph:{min:6,max:8,ideal:7},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Timjan är en riktig solälskare - hon kommer från Medelhavets torra, solstekta backar. Ge henne minst 6-8 timmars sol per dag. I skugga blir hon ranglig, tappar smak och riskerar att ruttna. Söderläge vid en stenmur? Perfekt."},temperature:{min:-15,max:35,ideal:"18-25°C",detail:"Överraskande härdig trots sitt Medelhavsursprung! Etablerad timjan klarar ner till -15°C om hon står torrt och väldränerat. Kyla i kombination med väta är däremot dödlig. På sommaren trivs hon i värme och torka - ju varmare, desto starkare arom."},wind:{level:"Tålig",detail:"Timjans låga, vedartade växtsätt gör henne nästan immun mot vind. Hon växer vilt på utsatta havsklippor i Medelhavet - svensk vind är ingen match."}},watering:{need:"Låg",icon:"water",summary:"Timjan är en kamelväxt som HATAR blöta fötter. Hon är uppvuxen på Medelhavets torra stenbackar och vill ha det likadant här. Låt hellre jorden torka ut ordentligt mellan vattningarna än att ge för mycket.",phases:[{phase:"Etablering (första månaden)",need:"Medel",tip:"Vattna regelbundet den första månaden så rötterna hittar ner. Men aldrig så mycket att jorden står blöt - dränering är nyckeln. När hon börjar växa synligt har hon landat."},{phase:"Etablerad planta (sommar)",need:"Låg",tip:"Vattna bara vid långvarig torka. Timjan klarar veckors torka utan problem. Känns jorden torr 3-4 cm ner? Låt den vara. Hänger hon slappt? Då kan du ge lite."},{phase:"Vinter",need:"Låg",tip:"Vattna INTE vintertid utomhus. Timjan vilar och vill vara torr. Inomhus räcker det med en skvätt vatten varannan vecka - låt jorden torka ut helt mellan vattningarna."}],mistakes:["Övervattnar - den absolut vanligaste dödsorsaken för timjan. Rötterna ruttnar i blöt jord fortare än du tror","Planterar i tung lerjord utan dränering - det är som att sätta en ökeninvånare i ett trädgårdsdamm","Mulchar för tätt intill stammen - fukt vid basen orsakar stamröta","Vattnar på kvällen - fukten ligger kvar över natten och skapar perfekta förhållanden för svamp"],tip:"Tumregel: är du osäker på om timjan behöver vatten, vänta två dagar till. Hon klarar torka hundra gånger bättre än för mycket vatten."},soil:"Timjan vill ha mager, väldränerad jord - gärna sandig eller grusig. Tänk stenparti, inte trädgårdsrabatt. För rik jord ger visserligen mer tillväxt, men smaknagra blad och en planta som är känsligare för vinterkyla.",soilTips:["Blanda in rikligt med sand eller grus i planteringsgropen - timjan vill ha en jord som släpper igenom vatten snabbt","I kruka: blanda hälften planteringsjord, hälften perlit eller grus. Lägg ett lager grus i botten för extra dränering","Undvik att blanda in kompost - timjan trivs faktiskt bättre i mager jord. Rikare jord ger svagare arom","Ett lager grus eller småsten runt plantan håller fukten borta från stammen och ger värmeåterstrålning på kvällen"],timeline:{1:[{phase:"Förodling inomhus",months:"Mars",icon:"indoor"},{phase:"Utplantering",months:"Maj",icon:"seedling"},{phase:"Skörd löpande",months:"Maj-okt",icon:"harvest"},{phase:"Blomning",months:"Juni-juli",icon:"flower"},{phase:"Frötagning",months:"Aug-sept",icon:"seed"}],4:[{phase:"Förodling inomhus",months:"Mars-april",icon:"indoor"},{phase:"Utplantering",months:"Slutet av maj-juni",icon:"seedling"},{phase:"Skörd löpande",months:"Juni-sept",icon:"harvest"},{phase:"Blomning",months:"Juli",icon:"flower"},{phase:"Frötagning",months:"Sept",icon:"seed"}],6:[{phase:"Förodling inomhus",months:"April",icon:"indoor"},{phase:"Utplantering",months:"Juni",icon:"seedling"},{phase:"Skörd löpande",months:"Juli-sept",icon:"harvest"},{phase:"Blomning",months:"Juli-aug",icon:"flower"}]},nutritionData:[{month:"Apr",N:3,P:2,K:2},{month:"Maj",N:4,P:3,K:3},{month:"Jun",N:5,P:3,K:4},{month:"Jul",N:4,P:3,K:5},{month:"Aug",N:3,P:2,K:4},{month:"Sep",N:2,P:1,K:3}],nutritionTips:[{timing:"Tidig vår",tip:"En tunn giva kompost runt plantan när hon vaknar på våren räcker gott. Timjan är ingen storätare - hon klarar sig med lite."},{timing:"Försommar",tip:"Om plantan ser blek eller sliten ut, ge en svag giva nässelvatten. Men överdriv inte - för mycket kväve ger frodiga blad med svag smak."},{timing:"Höst",tip:"Strö lite vedaska runt plantan på hösten. Kaliumet stärker vinterhärdigheten - och timjan älskar det svagt basiska."},{timing:"Obs!",tip:"Gödsla ALDRIG med kraftig stallgödsel eller syntetisk kvävegödsel. Timjan vill ha det magert - det är i kamp och torka som de eteriska oljorna koncentreras och smaken blir fantastisk."}],companions:{good:[{id:"morot",name:"Morot",icon:"vegetable",why:"Timjans starka doft förvirrar morotsflugan som navigerar efter lukt. Plantera timjan som kant runt morotslandet - en klassisk och beprövad kombination."},{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Timjan lockar pollinerare med sina blommor och den starka doften kan hålla snigelangreppen borta från jordgubbarna. Båda vill dessutom ha väldränerad jord."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Timjan avskräcker vitfjäril och bladlöss. Plantera som marktäckare under tomaterna - hon håller ogräs borta på köpet."},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Timjans starka arom avskräcker bladlöss som annars älskar sallat. Sallaten drar nytta av timjans beskyddande doft."}],bad:[{id:"basilika",name:"Basilika",icon:"herb",why:"Basilika vill ha rik, fuktig jord. Timjan vill ha mager, torr jord. De pratar helt enkelt olika språk och ingen av dem kan kompromissa."},{id:"mynta",name:"Mynta",icon:"herb",why:"Myntan är aggressiv och sprider sig överallt via utlöpare. Hon tar över timjans plats på nolltid. Dessutom vill mynta ha fuktigare förhållanden."}]},rotation:{avoid:[{id:"timjan",name:"Timjan"},{id:"oregano",name:"Oregano"},{id:"salvia",name:"Salvia"}],avoidWhy:"Kransblommiga (Lamiaceae) delar en del jordburna sjukdomar. Men timjan är perenn och bör stå kvar på samma plats i många år - flytta bara om plantan dör eller blir för vedartad (efter 4-5 år).",goodBefore:[{name:"Baljväxter"},{id:"lok",name:"Lök"},{name:"Rotsaker"}],goodBeforeWhy:"Baljväxter berikar jorden med kväve. Lök och rotsaker lämnar ren jord. Alla dessa är bra föregångare för timjan.",goodAfter:[{id:"morot",name:"Morot"},{name:"Kål"},{id:"sallat",name:"Sallat"}],goodAfterWhy:"Timjans aromatiska rester i jorden har mild desinficerande effekt. Bra för grönsaker som är känsliga för jordburna sjukdomar."},varieties:[{name:"Thymus vulgaris (vanlig timjan)",zones:[2,3,4,5,6],note:"Klassikern. Kraftig arom, upprätt växtsätt. Det här är den timjan du känner igen från matlagning. Härdig och pålitlig i zon 2-6."},{name:"Citrontimjan (Thymus citriodorus)",zones:[1,2,3,4],note:"Ljuvlig citrusdoft och -smak! Fantastisk till fisk och i te. Lite mindre härdig än vanlig timjan - kräver vinterskydd redan i zon 3-4."},{name:"Backtimjan (Thymus serpyllum)",zones:[1,2,3,4,5,6,7],note:"Svensk vild timjan! Krypande växtsätt, perfekt som marktäckare. Extremt härdig - klarar sig även i zon 7. Mildare smak."},{name:"German Winter (Thymus vulgaris)",zones:[2,3,4,5,6],note:"Extra härdig sort med breda blad som är lättare att skörda. Stark smak och tålig - ett av de bästa valen för svenska vintrar. Finns hos bland annat Impecta."}],problems:[{name:"Rotröta (väta)",symptom:"Plantan gulnar och vissnar trots att jorden är fuktig. Stammens bas är mörk och mjuk. Rötter är bruna och luktar illa.",fix:"Tyvärr ingen bot när rotröta slagit till. Förebygg med väldränerad jord och sparsam vattning. Är det en stor planta kan du försöka ta sticklingar från friska grenar och starta om."},{name:"Mjöldagg",symptom:"Vitt, mjölaktigt pulver på bladen. Vanligast vid fuktig luft och dålig luftcirkulation.",fix:"Klipp bort angripna delar. Se till att plantan står luftigt och inte för tätt med andra växter. En blandning av vatten och lite bakpulver kan sprayas på friska blad som skydd."},{name:"Vedartade grenar (åldring)",symptom:'Plantan blir gles, vedartad och "benig" efter 3-4 år. Få blad, mest bara torr ved.',fix:"Förebygg genom att klippa tillbaka timjan kraftigt varje vår - men aldrig in i den vedartade delen, då kommer inga nya skott. När plantan är för gammal är det dags att ersätta med en ny. Ta sticklingar från den gamla först!"},{name:"Bladlöss",symptom:"Klibbiga blad, deformerade skottspetsar. Små gröna eller svarta löss synliga.",fix:"Ovanligt på timjan tack vare de eteriska oljorna, men kan hända på svaga plantor. Spola av med vatten eller behandla med såplösning. Stark och frisk timjan är sällan angripen."}],goodToKnow:[{icon:"warning",title:"Vattna med måttans hand",text:"Timjans största fiende är inte kyla - det är fukt. Nio gånger av tio när timjan dör beror det på att hon stått för blött. Plantera i väldränerad jord och vattna sparsamt, så lever hon i många år.",severity:"warning"},{icon:"warning",title:"Klipp aldrig in i det vedartade",text:"När du beskär timjan på våren, klipp bara i den gröna delen - aldrig ner i den bruna, vedartade stammen. Därifrån kommer inga nya skott. Klipper du för hårt är grenen död.",severity:"warning"},{icon:"tip",title:"Starkast smak precis före blomning",text:"Planera huvudskörden till precis innan timjan börjar blomma - då är koncentrationen av eteriska oljor som högst. Bladen är nästan dubbelt så aromatiska jämfört med efter blomning.",severity:"tip"},{icon:"tip",title:"Fantastisk i stenparti eller mur",text:"Timjan älskar att växa i springor mellan stenar, ovanpå murar och i stenpartier. Värmen från stenarna ger extra energi och den perfekta dräneringen gör henne lycklig. Dessutom ser det fantastiskt ut!",severity:"tip"},{icon:"tip",title:"Låt henne blomma - bina älskar det",text:"Timjan är en av de bästa biväxterna! Lila blommorna är fulla av nektar och lockar bin, humlor och fjärilar. Timjanhonung är en delikatess i Medelhavsländerna. Låt gärna någon del av plantan blomma.",severity:"tip"}],sowing:{method:"both",label:"Direktsådd eller förodling",description:"Timjan kan sås direkt utomhus eller förodlas inomhus. Fröna är pyttelitet små och gror långsamt (2-3 veckor), så förodling är lättast för nybörjare. Det allra enklaste sättet att börja? Köp en planta eller be någon om sticklingar - timjan rotar sig villigt.",steps:["Fyll krukor med sandblandad såjord (hälften såjord, hälften sand)","Strö fröna på ytan - TÄCK INTE. De behöver ljus för groning","Tryck försiktigt med handflatan så de får jordkontakt","Spreja med vatten - översvämma inte","Täck med plastfolie för att hålla fukt. Lufta dagligen","Ställ ljust och varmt (18-22°C). Groning tar 14-21 dagar - ha tålamod!","Gallra till 1-2 plantor per kruka vid 3-4 cm höjd","Härda av i 1 vecka innan utplantering. Plantera ut när frostrisken är över"],tips:["Sticklingar är det snabbaste sättet att få en ny planta - klipp en 10 cm gren, ta bort nedre bladen och sätt i fuktig sand. Rötter på 3-4 veckor!","Timjanfrön är otroligt små - blanda med sand för att så jämnare","Var inte orolig om groningen tar tid. Timjan är långsam i starten men desto tuffare när hon väl kommit igång"],indoorWeeks:"8-10 veckor före utplantering"},seedSaving:{difficulty:"Enkel",type:"Korspollinerare",biennial:!1,description:"Låt timjan blomma - de små blommorna producerar pyttelila frön som mognar på sensommaren. Klipp av blomstjälkarna när de torkat och skaka ut fröna. Timjan korspolleras av insekter, så olika sorter bör stå isär.",steps:["Låt en del av plantan blomma ut helt (juli-aug)","Vänta tills blommorna torkat och frökapslarna är bruna","Klipp av blomstjälkarna och lägg i en papperspåse","Låt eftertorka några dagar inomhus","Skaka och gnugga försiktigt - de pyttelila fröna faller ut","Sikta bort skräp genom ett fint såll","Förvara svalt och torrt i märkt kuvert"],isolation:"Timjan korspolleras av insekter (främst bin). För sortrena frön krävs stort avstånd (hundratals meter) mellan sorter, vilket sällan är praktiskt i hemträdgårdar. Sticklingar är det säkraste sättet att behålla en sort.",storageYears:"3-4 år",tip:"Sticklingar är ofta lättare än frö för att föröka timjan. Klipp en 8-10 cm gren på sensommaren, sätt i fuktig sand och vänta. Resultat: en identisk planta på några veckor!"},storage:{shelfLife:"7-14 dagar (färsk)",methods:[{method:"Torkning (bäst!)",icon:"storage",duration:"12+ månader",description:"Timjan är en av få kryddor som faktiskt blir BÄTTRE av torkning - smaken koncentreras. Häng knippen uppochner på en torr, luftig plats i 1-2 veckor. Eller torka i ugn på 40°C i 2-3 timmar.",best:!0},{method:"Frysning",icon:"snowflake",duration:"6+ månader",description:"Lägg hela kvistar i en fryspåse och frys. Plocka blad direkt från frysen när du lagar mat - de lossnar lättare från stjälkarna när de är frysta!",best:!1},{method:"Färsk i kyl",icon:"water",duration:"7-14 dagar",description:"Linda kvistarna i fuktigt hushållspapper och lägg i en plastpåse i kylen. Timjan håller sig överraskande länge färsk tack vare sina sega, små blad.",best:!1},{method:"Timjanolja",icon:"storage",duration:"3-6 månader",description:"Lägg färsk timjan i en flaska med god olivolja. Låt dra 2-3 veckor. Sila bort kryddorna. Fantastisk smaksatt olja för matlagning.",best:!1}],tips:["Torkad timjan är starkare än färsk - använd ungefär en tredjedel så mycket i recept","Skörda hela kvistar och låt bladen sitta kvar på stjälken under torkning - de är lättare att dra av när de är torra","Förvara torkad timjan i ett mörkt, lufttätt glas - ljus bryter ner de eteriska oljorna över tid","Timjan är en av få örter som tål att koka med - lägg i tidigt i grytan så smaken hinner infusera"]},harvestCalc:{minPerSqm:.2,maxPerSqm:.5,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp kvistar, aldrig mer än en tredjedel åt gången",description:"Skörda timjan genom att klippa av kvistar med en vass sax. Ta aldrig mer än en tredjedel av plantan åt gången - hon behöver blad för att återhämta sig. Klipp ovanför den vedartade delen så nya sidoskott kan växa ut.",uses:[{use:"Färsk i matlagning",tip:"Dra av bladen från kvisten genom att hålla i toppen och dra fingrarna nedåt mot stjälken. Lägg i grytor, såser och marinader tidigt - timjan tål långkok."},{use:"Bouquet garni",tip:"Bind ihop timjan, lagerblad och persilja till ett kryddknippe. DEN klassiska franska smaksättaren för grytor, soppor och buljonger."},{use:"Te",tip:"Häll hett vatten över färska eller torkade kvistar. Låt dra 5-10 minuter. Timjante är inte bara gott - det är ett gammalt husrådsmedel mot förkylning och halsont."},{use:"Timjanhonung",tip:"Lägg färska kvistar i en burk med honung. Låt dra i 2 veckor. Fantastisk till ost, yoghurt eller som hostmedicin."}]}},re=Object.freeze(Object.defineProperty({__proto__:null,timjan:xr},Symbol.toStringTag,{value:"Module"})),Kr={name:"Tomat",icon:"tomat",family:"Potatisväxter",familyLatin:"Solanaceae",difficulty:"Medel",difficultyWhy:"Kräver förodling inomhus (6-8 v), regelbunden gödsling, uppbindning och är känslig för bladmögel.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:[1,2,3,4,5,6,7,8]},days:"60-100",spacing:"40-50 cm",rowSpacing:"60-80 cm",depth:"0,5-1 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 8 timmar direkt sol per dag. Tomater ÄLSKAR sol - mer sol = sötare tomater. I halvskugga får du mest blad och lite frukt."},temperature:{min:10,max:35,ideal:"20-25°C",detail:"Värmekrävande. Under 10°C stannar tillväxten. Fruktsättning sker bäst mellan 18-25°C. Över 30°C försämras fruktsättningen och vid 38-39°C upphör den helt."},wind:{level:"Skyddat",detail:"Vindkänslig - stjälkar och blad skadas lätt. Plantera gärna intill en södervägg eller i växthus. Lite vind hjälper dock pollineringen."}},watering:{need:"Hög",icon:"water",summary:"Tomater är törstiga men kräsna - de vill ha JÄMN fukt, aldrig ojämnt. Vattna alltid vid basen, aldrig ovanifrån (bladmögel!).",phases:[{phase:"Plantor inomhus",need:"Låg-Medel",tip:"Håll jorden lätt fuktig men aldrig blöt. Övervatning är nybörjarmisstag #1 inomhus - rötterna ruttnar."},{phase:"Nyplanterade (vecka 1-2)",need:"Medel",tip:"Vattna vid plantering och sedan varannan dag tills plantan är etablerad. Inte för mycket - tvinga rötterna att söka sig nedåt."},{phase:"Tillväxt & blomning",need:"Hög",tip:"Vattna djupt 2-3 gånger i veckan. Tomater i växthus kan behöva vatten varje dag i högsommaren. Vattna alltid på morgonen."},{phase:"Fruktsättning & mognad",need:"Hög men jämn",tip:"Ojämn vattning nu = spruckna tomater och blomändsröta. Hellre lite vatten ofta än mycket sällan. Mulcha!"}],mistakes:["Vattna ovanifrån - våta blad = bladmögel, tomaternas största fiende","Ojämn vattning - spruckna frukter och blomändsröta (svart botten)","Övervattning av småplantor inomhus - stammen ruttnar vid basen","Vattna mitt på dagen i full sol - vatnet avdunstar innan rötterna hinner ta upp det"],tip:"Installera droppbevattning eller grävda PET-flaskor vid basen - det är det bästa du kan göra för dina tomater. Jämn fukt utan att blöta bladen."},soil:"Näringsrik, väldränerad jord. Tomater är storätare - de vill ha mycket näring genom hela säsongen.",soilTips:["Blanda in rikligt med kompost före plantering","Mulcha med gräsklipp för jämn fukt","Kalka om pH är under 6.0"],timeline:{1:[{phase:"Förodla inomhus",months:"Feb-Mar",icon:"indoor"},{phase:"Härda av",months:"Apr",icon:"hardening"},{phase:"Plantera ut",months:"Maj",icon:"seedling"},{phase:"Stödja & beskära",months:"Maj-Jul",icon:"stake"},{phase:"Gödsla regelbundet",months:"Maj-Aug",icon:"water"},{phase:"Skörd",months:"Jul-Sep",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar",icon:"indoor"},{phase:"Härda av",months:"Maj",icon:"hardening"},{phase:"Plantera ut",months:"Jun",icon:"seedling"},{phase:"Stödja & beskära",months:"Jun-Jul",icon:"stake"},{phase:"Gödsla regelbundet",months:"Jun-Aug",icon:"water"},{phase:"Skörd",months:"Jul-Sep",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Mar",icon:"indoor"},{phase:"Härda av",months:"Jun",icon:"hardening"},{phase:"Plantera ut (växthus rekm.)",months:"Jun",icon:"seedling"},{phase:"Stödja & beskära",months:"Jun-Jul",icon:"stake"},{phase:"Gödsla regelbundet",months:"Jun-Aug",icon:"water"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Mar",N:15,P:10,K:5,label:"Förodling"},{month:"Apr",N:30,P:20,K:10,label:"Tillväxt inomhus"},{month:"Maj",N:50,P:30,K:20,label:"Avhärdning"},{month:"Jun",N:70,P:50,K:35,label:"Etablering ute"},{month:"Jul",N:60,P:75,K:65,label:"Blomning & frukt"},{month:"Aug",N:40,P:80,K:85,label:"Mognad"},{month:"Sep",N:15,P:40,K:60,label:"Sen skörd"}],nutritionTips:[{timing:"Förodling (mars-april)",tip:"Svag näringslösning. Tomater som små klarar lite."},{timing:"Utplantering",tip:"Grundgödsla med kompost + benmjöl i planteringsgropen."},{timing:"Blomning",tip:"Byt till kaliumrik gödsel (tomatgödsel). Varannan vecka."},{timing:"Fruktsättning",tip:"Fortsätt med kalium. Minska kväve - annars får du blad istället för frukt."}],companions:{good:[{id:"basilika",name:"Basilika",icon:"herb",why:"Förbättrar smaken och håller bladlöss borta"},{id:"morot",name:"Morot",icon:"vegetable",why:"Luckrar jorden runt tomatrötterna"},{id:"ringblomma",name:"Ringblomma",icon:"flower",why:"Lockar pollinerare och avskräcker vita flygare"},{id:"persilja",name:"Persilja",icon:"herb",why:"Lockar nyttiga rovinsekter"}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Samma familj (potatisväxter) - delar bladmögel och andra sjukdomar"},{id:"fankal",name:"Fänkål",icon:"herb",why:"Hämmar tomatens tillväxt genom allelopati"},{name:"Kål",icon:"vegetable",why:"Konkurrerar om näring - båda är storätare"}]},rotation:{avoid:[{id:"potatis",name:"Potatis"},{id:"paprika",name:"Paprika"},{name:"Aubergine"},{id:"chili",name:"Chili"}],avoidWhy:"Alla potatisväxter - delar bladmögel, fusarium. Vänta minst 3-4 år.",goodBefore:[{name:"Baljväxter"},{id:"lok",name:"Lök"},{name:"Gröngödsling"}],goodBeforeWhy:"Kvävefixering från baljväxter + sanering från lökväxter.",goodAfter:[{name:"Rotgrönsaker"},{name:"Baljväxter"},{id:"sallat",name:"Sallat"}],goodAfterWhy:"Jorden är fortfarande näringsrik - bra för måttliga ätare."},varieties:[{name:"Sungold F1",zones:[1,2,3,4,5,6],note:"Söta cocktailtomater. Extremt populär."},{name:"Moneymaker",zones:[1,2,3,4,5,6],note:"Pålitlig klassiker. Bra för nybörjare."},{name:"Black Krim",zones:[1,2,3,4,5],note:"Mörk, komplex smak. Wow-faktor."},{name:"Sibirjak",zones:[1,2,3,4,5,6,7],note:"Köldtålig rysk sort. 62 dagar - bra för norra Sverige och kort säsong."}],problems:[{name:"Bladmögel",symptom:"Bruna fläckar på bladen, sprider sig snabbt",fix:"Luftig plantering, vattna vid basen, ta bort angripna blad direkt."},{name:"Blomändsröta",symptom:"Svart, insjunken botten på frukten",fix:"Kalciumbrist p.g.a. ojämn bevattning. Vattna jämnt, mulcha."},{name:"Vita flygare",symptom:"Små vita insekter under bladen",fix:"Gula klisterfällor. Samodla med ringblomma och tagetes."}],goodToKnow:[{icon:"scissors",title:"Tjuvskott - din viktigaste rutin",text:"Ta bort alla sidoskott (tjuvskott) som växer i bladbecken. Annars får du en stor buske med massor av blad men lite frukt. Kolla varannan dag under högsommaren.",severity:"warning"},{icon:"water",title:"Vattna jämnt - aldrig ojämnt",text:"Ojämn bevattning (torrt → blött → torrt) ger blomändsröta (svarta bottnar) och spruckna frukter. Bättre med lite vatten ofta än mycket sällan. Mulcha!",severity:"warning"},{icon:"leaf",title:"Ta bort nedre bladen",text:"Klipp bort alla blad under den lägsta fruktklassen. Det förbättrar luftcirkulationen och minskar risken för bladmögel drastiskt.",severity:"tip"},{icon:"indoor",title:"Växthus gör enorm skillnad",text:"Även ett enkelt plasttunnelväxthus förlänger säsongen med 4-6 veckor och skyddar mot bladmögel. Tomater i växthus vs utomhus i Sverige är som natt och dag.",severity:"tip"},{icon:"check",title:"Gröna tomater? Ingen panik",text:"I slutet av säsongen: plocka gröna tomater och lägg dem i en papperspåse med ett äpple. Etylen från äpplet eftermognar dem inomhus på 1-2 veckor.",severity:"tip"},{icon:"warning",title:"Plantera ALDRIG bredvid potatis",text:"Tomat och potatis är samma familj och delar bladmögel. En sjuk potatisplanta kan smitta dina tomater på några dagar. Håll dem så långt ifrån varandra som möjligt.",severity:"warning",refs:[{id:"potatis",name:"potatis"}]}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Tomater måste förodlas inomhus eftersom de behöver lång, varm säsong. Direktsådd utomhus fungerar inte i Sverige.",steps:["Fyll små krukor eller pluggbrätten med såjord","Lägg 1-2 frön per kruka, 0,5 cm djupt","Täck med plastfolie eller lock för att hålla fukt - ta bort när groddarna syns","Placera ljust och varmt (20-25°C) - fönsterbräda söderut eller växtbelysning","Omplantera till större kruka när plantan har 2-4 riktiga blad","Härda av 1-2 veckor före utplantering: ställ ut dagtid, in på natten","Plantera ut när risken för frost är över - plantera djupt (tomat bildar rötter på stjälken)"],tips:["Starta 6-8 veckor före planerad utplantering","Så inte för tidigt - utdragna, bleka plantor klarar sig sämre","Använd växtbelysning om du inte har tillräckligt med solljus"],indoorWeeks:"6-8 veckor"},seedSaving:{difficulty:"Enkel",type:"Självpollinerare",biennial:!1,description:"Tomaten är självpollinerare och ettårig - en av de enklaste grödorna att ta frö på. Perfekt att börja med!",steps:["Välj en mogen, fin frukt från din bästa planta","Skär tomaten på mitten och skrapa ut fröna med gelémassan","Lägg fröna + gelé i ett glas med lite vatten","Låt jäsa 2-3 dagar vid rumstemperatur - det bildas en hinna på ytan (det är normalt!)","Skölj bort gelémassan under rinnande vatten i en sil","Lägg fröna på hushållspapper och låt torka helt (3-5 dagar)","Förvara i märkt papperspåse, torrt och svalt"],isolation:"Självpollinerare - olika sorter kan odlas nära varandra utan korsning. Undantag: stora potatisbladiga sorter kan korsa lättare.",storageYears:"4-6 år",tip:"OBS! F1-hybrider (t.ex. Sungold F1) ger inte sortäkta frö - ta bara frö från fasta sorter som Moneymaker eller Black Krim."},storage:{shelfLife:"1-2 veckor (färsk) / 12 mån (konserverad)",methods:[{method:"Rumstemperatur (bäst för smaken!)",icon:"harvest",duration:"5-7 dagar",description:"Tomater ska ALDRIG i kylen - kylan dödar smaken och gör dem mjöliga. Förvara i rumstemperatur, stjälksidan uppåt, borta från direkt solljus.",best:!0},{method:"Eftermognad (gröna tomater)",icon:"seedling",duration:"1-3 veckor",description:"Plocka gröna tomater i slutet av säsongen. Lägg i papperspåse med ett äpple. Etylen från äpplet mognar dem. Kolla varannan dag.",best:!1},{method:"Torka",icon:"sun",duration:"6-12 månader",description:"Skär i skivor, salta lätt och torka i ugn på 70°C i 6-8 timmar (eller i mattork). Förvara i lufttät burk. Fantastiska i matlagning.",best:!1},{method:"Frysa (hela)",icon:"snowflake",duration:"8-12 månader",description:"Frys hela tomater rakt av - inget skalning behövs! Skalet lossnar av sig själv under rinnande vatten när du tinar dem. Perfekt för sås och soppa.",best:!1},{method:"Passata / inkokning",icon:"storage",duration:"12+ månader",description:"Koka ner till passata eller hela konserverade tomater. Tillsätt lite citronsyra för säker konservering. Mest tidskrävande men bästa långtidslagringen.",best:!1}],tips:["Aldrig i kylen! Det förstör cellstrukturen och smaken - det är det vanligaste misstaget","Förvara med stjälksidan uppåt - det mjuka partiet klarar sig bättre utan tryck","Övermogna tomater? Gör sås, salsa eller gazpacho samma dag","Cherry-tomater håller sig längre än stora sorter","Skörda helst med en bit stjälk kvar - håller sig bättre"]},harvestCalc:{minPerSqm:3,maxPerSqm:8,unit:"kg"}},ae=Object.freeze(Object.defineProperty({__proto__:null,tomat:Kr},Symbol.toStringTag,{value:"Module"})),Pr={name:"Tranbär",icon:"tranbar",category:"bär",family:"Ljungväxter",familyLatin:"Ericaceae",perennial:!0,lifespan:"50-100+ år",difficulty:"Avancerad",difficultyWhy:"Tranbär kräver väldigt specifika förhållanden: sur jord (pH 4.0-5.5), konstant fukt och full sol. I naturen växer de i myrmarker och mossar. Att efterlikna det i trädgården är utmaningen. Men lyckas du med jorden och vattnet är tranbär en extremt långlivad och pålitlig växt.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:null},days:"Skörd år 3-4",spacing:"30-40 cm",rowSpacing:"50-60 cm",depth:"Ytligt",depthNote:"Grunt rotsystem - plantera i samma djup som i krukan, aldrig djupare",ph:{min:4,max:5.5,ideal:4.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Tranbär vill ha full sol för bäst bärproduktion. I naturen växer de på öppna myrar utan skuggande träd. Halvskugga ger gröna plantor men betydligt färre bär. Minst 6 timmar direkt sol per dag."},temperature:{min:-35,max:30,ideal:"15-22°C",detail:"Mycket härdig - tål ner till -35°C under snötäcke. Trivs bäst i svalt klimat. Lång, varm höst ger bäst mognad. Tranbär behöver vinterkyla för att blomma ordentligt."},wind:{level:"Tålig",detail:"Låg, krypande växt som vinden blåser rakt över. Tranbär bryr sig inte om vind - de växer i öppna myrlandskap. Vindskydd behövs inte."}},watering:{need:"Hög",icon:"water",summary:"Tranbär kommer från myrmarker och vill ha KONSTANT fuktig jord. De är inte vattenväxter - de vill inte stå i vatten - men jorden ska aldrig torka ut. Det här är den största utmaningen med tranbärsodling i trädgården.",phases:[{phase:"Vår (tillväxt)",need:"Hög",tip:"Jämn fukt från start. Tranbär har mycket grunda rötter och torkar ut snabbt. Vattna dagligen vid torr vår."},{phase:"Blomning (juni-juli)",need:"Hög",tip:"Kritisk period! Uttorkning nu ger noll bär. Håll jorden konstant fuktig men inte vattendränkt."},{phase:"Bärmognad (sept-okt)",need:"Hög",tip:"Fortsätt hålla jämn fukt. Bären behöver tid att mogna - tranbär mognar sent."},{phase:"Vinter",need:"Medel",tip:"I naturen fryser myrvattnet. I trädgården: håll jorden fuktig men inte blöt. Snötäcke är det bästa vinterskyddet."}],mistakes:["Låter jorden torka ut - de extremt grunda rötterna klarar inte ens kort torka","Vattnar med kalkrikt kranvatten - höjer pH och tranbär förtvinar","Tror att tranbär ska stå i vatten - de vill ha fuktig jord, inte stående vatten"],tip:"Samla regnvatten! Tranbär vill ha mjukt, surt vatten - precis som blåbär och lingon. En upphöjd bädd med torvbaserad jord och inbyggd bevattning är det bästa sättet att odla tranbär i trädgården."},soil:"Tranbär kräver SUR, torvrik jord med konstant fukt - precis som i en myrmark. pH 4.0-5.5 är absolut nödvändigt. Vanlig trädgårdsjord fungerar inte alls. Du behöver skapa ett eget mini-myr med torvmull, barkmull och sågspån.",soilTips:["Gräv en grund bädd (20-30 cm djup, 60+ cm bred) och klä med plastfolie för att hålla fukt","Fyll med ren torvmull eller blandning: 60% torv + 20% sågspån (barrträ) + 20% sand","Testa pH - det MÅSTE vara under 5.5","Lägg perforerade droppslangssystem i bädden för jämn bevattning","Mulcha med mossa, tallbarr eller sågspån - det håller pH nere och fukt uppe","Regnvatten är bäst - kranvatten kan höja pH"],timeline:{1:[{phase:"Plantering",months:"Maj-juni",icon:"seedling"},{phase:"Blomning",months:"Juni-juli",icon:"bloom"},{phase:"Skörd",months:"Sept-okt",icon:"harvest"},{phase:"Vintervila",months:"Nov-maj",icon:"snowflake"}],4:[{phase:"Plantering",months:"Maj",icon:"seedling"},{phase:"Blomning",months:"Juni",icon:"bloom"},{phase:"Skörd",months:"Sept-okt",icon:"harvest"},{phase:"Vintervila",months:"Nov-april",icon:"snowflake"}],6:[{phase:"Plantering",months:"April-maj",icon:"seedling"},{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Skörd",months:"Sept",icon:"harvest"},{phase:"Vintervila",months:"Okt-mars",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:1,P:1,K:1},{month:"Maj",N:2,P:2,K:2},{month:"Jun",N:2,P:2,K:3},{month:"Jul",N:2,P:2,K:3},{month:"Aug",N:1,P:2,K:3},{month:"Sep",N:1,P:1,K:2}],nutritionTips:[{timing:"Tidig vår",tip:"En mycket lätt giva surgörande gödsel (rhododendrongödsel). Tranbär är INTE hungriga - de lever i naturen på utarmade myrmarker. Övergödsla inte!"},{timing:"Försommar",tip:"Toppdressing med sågspån eller torv ger långsam näring i rätt pH. Det är allt tranbär behöver."},{timing:"Höst",tip:"Ingen gödsel. Lägg på ett tunt lager sand (tradionellt i kommersiell odling) som stimulerar nya skottbildning och håller nere mossa."}],companions:{good:[{name:"Blåbär",icon:"berry",why:"Samma krav på sur jord. Kan odlas i samma surjordsbädd."},{name:"Lingon",icon:"berry",why:"Samma familj (Ericaceae) och samma pH-krav. Naturliga grannar i svenska myrar."},{name:"Ljung",icon:"flower",why:"Trivs i exakt samma förhållanden. Vackert tillsammans."}],bad:[{name:"Kalkälskande växter",icon:"flower",why:"Allt som vill ha neutral/basisk jord hör inte hemma bredvid tranbär. Helt olika världar."},{name:"Näringshungriga grödor",icon:"vegetable",why:"Tranbär vill ha mager, sur jord - motsatsen till vad grönsaker behöver."}]},rotation:{avoid:[{name:"Tranbär"},{name:"Blåbär"},{name:"Lingon"}],avoidWhy:"Ericaceae-växter delar svampsjukdomar (Phytophthora). Plantera inte nya tranbär där gamla stått utan att byta ut jorden.",goodBefore:[{name:"Obrukad mark"},{name:"Myrmark/torvmark"}],goodBeforeWhy:"Naturlig sur mark utan tidigare sjukdomshistorik är bäst.",goodAfter:[{name:"Gröngödsling"}],goodAfterWhy:"Efter tranbär (som kan leva 100+ år) är jorden extremt sur. Kalkspridning krävs för annan odling."},varieties:[{name:"Stevens",zones:[1,2,3,4],note:"Den vanligaste sorten i kommersiell odling och i svensk handel. Stora, djupröda bär. God skörd och pålitlig. Standardvalet för trädgårdsodling i Sverige."},{name:"Pilgrim",zones:[1,2,3,4],note:"Sen sort med extra stora bär. Ljusare röd färg. Ger hög skörd men behöver lång, mild höst för full mognad."},{name:"Europeiskt tranbär (Vaccinium oxycoccos)",zones:[1,2,3,4,5,6,7,8],note:"Vild svensk art! En annan art än de odlade amerikanska (V. macrocarpon). Mindre bär men klarar alla svenska zoner. Kan plockas vilt i myrar. Intensivare smak. Sällan till salu - leta i naturen istället."}],problems:[{name:"Fruktröta",symptom:"Bären blir mjuka, bruna och ruttnar. Värst i fuktigt väder under mognad.",fix:"God luftcirkulation. Undvik att plantera för tätt. Skörda i tid. Friska, välskötta plantor drabbas sällan allvarligt."},{name:"Klorosförgulning",symptom:"Bladen gulnar medan nerverna förblir gröna. Plantan växer dåligt.",fix:"Nästan alltid pH-problem! Testa jorden. Om pH är över 5.5 - sänk med svavel eller mer torvmull. Vattna med regnvatten."},{name:"Snölöss/tranbärssländor",symptom:"Larver som äter blad och blomknoppar. Tunnlikt spinn på bladen.",fix:"Plocka bort angripna delar. Biologisk bekämpning med nematoder. I liten skala: handplockning tidigt på säsongen."}],goodToKnow:[{icon:"warning",title:"Sur jord och konstant fukt - absolut krav",text:"Tranbär växer i myrmarker och kräver extremt sura (pH 4.0-5.5), ständigt fuktiga förhållanden. Det är INTE en vanlig trädgårdsväxt och du behöver bygga en specialbädd. Men gör du det rätt lever plantorna i 50-100+ år.",severity:"warning"},{icon:"warning",title:"Bären skördas SENT",text:"Tranbär mognar sent - september till oktober i de flesta zoner. Bären ska vara djupt röda och fasta. Om hösten blir kall och kort i norra Sverige hinner inte alla sorter mogna - välj tidig sort som Ben Lear.",severity:"warning"},{icon:"tip",title:"Världens mest hållbara bär",text:"Tranbär håller sig fantastiskt länge färska - 2-3 månader i kylskåp! De studsar om de är färska (det är det klassiska kvalitetstestet). Den höga bensorsyra- och C-vitaminhalten konserverar naturligt.",severity:"tip"},{icon:"tip",title:"Krypande vintergröna mattor",text:"Tranbär bildar täta, vintergröna mattor av krypande rankor. Utanför bärsäsongen är de vackra marktäckare med glänsande, små blad. Blommorna i juni liknar små orkideer - vackert!",severity:"tip"},{icon:"tip",title:"Svensk myrtradition",text:"Europeiskt tranbär (Vaccinium oxycoccos) växer vilt i svenska myrar och har plockats i århundraden. De amerikanska odlingssorterna (V. macrocarpon) ger större bär men det svenska myrbäret har mer intensiv smak.",severity:"tip"},{icon:"tip",title:"Övervintrar under snö",text:"I naturen skyddas tranbär av snö och is på myren. I trädgården: mulcha med tallbarr eller granris om snötäcket är opålitligt. Snö är det bästa vinterskyddet - låt det ligga!",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Tranbär planteras som sticklingsplantor eller krukodlade pluggplantor på våren. Bygg en specialbädd med sur, fuktig jord innan plantering.",steps:["Bygg en surjordsbädd: gräv 20-30 cm djupt, klä med genomborrad plast för att hålla fukt","Fyll med surjordsblandning: 60% torv + 20% sågspån (barrträ) + 20% sand","Testa pH - det MÅSTE vara 4.0-5.5","Lägg in droppbevattning eller genomborrad slang för jämn vattning","Plantera i samma djup som i krukan, 30-40 cm avstånd","Vattna rikligt med regnvatten","Mulcha med tallbarr, mossa eller sågspån"],tips:["En upphöjd surjordsbädd (30 cm hög, 60+ cm bred) är det smidigaste sättet","Automatisk bevattning med timer rekommenderas starkt - tranbär får aldrig torka ut","Plantera i maj-juni för bäst etablering","Förvänta dig inte skörd förrän år 3-4 - tranbär tar sin tid"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Tranbär förökas enklast med sticklingar. De krypande rankorna rotar sig naturligt vid lederna - klipp helt enkelt av en rotad bit och plantera om.",steps:["Identifiera rankor som rotat sig i marken (naturligt hos tranbär)","Klipp av 10-15 cm bitar med rötter","Plantera direkt i förberedd surjordsbädd","Alternativt: klipp 10-15 cm sticklingar av friska rankor i juni","Sätt i sur, fuktig torv under fukthuv","Sticklingar rotar sig på 4-6 veckor"],isolation:"Vegetativ förökning - kloner av moderplantan.",storageYears:"Ej tillämpligt",tip:"Tranbär rotar sig naturligt vid lederna - det är bara att klippa av och flytta. Extremt enkelt om du redan har en etablerad plantering."},storage:{shelfLife:"2-3 månader (färska i kylskåp!)",methods:[{method:"Kylskåp (färska)",icon:"snowflake",duration:"2-3 månader",description:"Tranbär har fantastisk hållbarhet färska - de håller sig 2-3 MÅNADER i kylskåp tack vare naturlig bensorsyra och C-vitamin. Förvara i perforerad påse. De studsar om de är färska - det klassiska kvalitetstestet!",best:!0},{method:"Frysning",icon:"snowflake",duration:"12+ månader",description:"Fryser utmärkt direkt i påsar. Frysta tranbär kan användas direkt i bakning, sås och smoothies utan att tinas först.",best:!1},{method:"Torkning",icon:"sun",duration:"12+ månader",description:"Torkade tranbär (cranberries) är en klassiker. Torka i ugn på 50°C i 10-14 timmar. Söta gärna med lite honung före torkning. Fantastiska i bakning, müsli och sallader.",best:!1},{method:"Sås/kompott",icon:"storage",duration:"6+ månader",description:"Tranbärssås till kalkonen! Koka bären med socker och en skvätt apelsinjuice. Bären spricker och bildar en naturlig sås. Klassiker till höstens och vinterns högtider.",best:!1},{method:"Juice",icon:"storage",duration:"6-12 månader",description:"Ren tranbärsjuice är intensivt syrlig men otroligt nyttig. Späd med vatten och söta med honung. Bra för urinvägshälsa - det är vetenskapligt bevisat.",best:!1}],tips:["Färska tranbär studsar! Om bäret inte studsar är det inte färskt - det är ett riktigt kvalitetstest","Tranbär mognar inte efter plockning - skörda bara fullt röda bär","De håller sig extremt länge i kylskåp - planera inte att processa allt direkt","Tranbärssås kräver bara bär, socker och vatten - bären spricker och gelerar naturligt"]},harvestCalc:{minPerSqm:.3,maxPerSqm:.8,unit:"kg"},pruning:{label:"Beskärning",types:{maintenance:{name:"Underhåll",when:"Tidig vår (mars-april)",description:"Tranbär kräver minimal beskärning. Klipp bort döda rankor och gallra om beståndet blivit för tätt. I kommersiell odling sandas plantorna vart 3-4 år för att stimulera ny tillväxt.",steps:["Klipp bort döda och brunfärgade rankor","Gallra om beståndet är mycket tätt - luftcirkulation förebygger svamp","Toppdress med ett tunt lager sand (0.5-1 cm) vart 3-4 år","Klipp rankor som växer utanför önskat område"]},rejuvenation:{name:"Sandning (föryngring)",when:"Tidig vår, vart 3-4 år",description:"Den traditionella föryngringsmetoden för tranbär är sandning - att lägga ett tunt lager sand (0.5-1 cm) över beståndet. Rankorna växer igenom sanden och bildar nya rötter. Det stimulerar ny tillväxt och förlänger beståndslivslängden.",steps:["Sprid 0.5-1 cm sand jämnt över beståndet på tidig vår","Använd tvättad, sur sand (inte kalksand!)","Rankorna växer igenom inom några veckor","Upprepa vart 3-4 år"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Rankdelar",description:"Klipp av 10-15 cm bitar av rankor som redan rotat sig vid lederna. Plantera direkt i surjordsbädd. Naturligt och enkelt - tranbär rotar sig själva.",icon:"seedling"},{method:"Sticklingar",description:"Klipp 10-15 cm av friska rankor i juni. Sätt i sur, fuktig torv. Håll under fukthuv. Rotning på 4-6 veckor.",icon:"scissors"}],tip:"Tranbär rotar sig naturligt vid varje led som rör marken. Dela helt enkelt upp och plantera om - det kunde inte vara enklare."}},ee=Object.freeze(Object.defineProperty({__proto__:null,tranbar:Pr},Symbol.toStringTag,{value:"Module"})),Br={name:"Valnöt",icon:"valnot",category:"frukt",family:"Valnötsväxter",familyLatin:"Juglandaceae",perennial:!0,lifespan:"200+ år",difficulty:"Medel",difficultyWhy:"Själva odlingen är inte svår - ett etablerat valnötsträd sköter sig i princip självt. Utmaningen är tålamod (ympade träd ger nötter efter 3-5 år), rätt sortval för din zon, och att senvårfrosten inte slår ut blomningen.",zones:{outdoor:[1,2,3],indoor:null,greenhouse:null},days:"Skörd år 3-5 (ympad), 8-15 (frösodd)",spacing:"8-12 m",spacingNote:"Valnötsträd blir STORA. Broadview är kompaktare (6-8 m) men ge ändå utrymme.",rowSpacing:"10-15 m",depth:"Rotklumpens djup",depthNote:"Valnöten har en kraftig pålrot - gräv djupt och brett. Plantera ALDRIG djupare än rotklumpen suttit.",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Valnöten vill ha minst 6-8 timmars direkt sol. Vindskyddat läge är minst lika viktigt som solen - senvårfrost och kall vind är de verkliga fienderna."},temperature:{min:-25,max:35,ideal:"18-25°C",detail:"Etablerade träd tål ner mot -25°C i vintervila. MEN: blomknopparna är känsliga som fjärilar på våren - en senvårfrost kan radera ut hela årets skörd på en natt. Sorter med sen bladsprickning (Fernor) minskar risken."},wind:{level:"Skyddat",detail:"Vindskyddat läge är kritiskt. Kall vind stör blomningen och torkar ut unga träd. En skyddad sydvänd plats mot byggnad eller häck är idealiskt."}},watering:{need:"Medel",icon:"water",summary:"Etablerade valnötsträd klarar sig ofta på regnvatten tack vare de djupa pålrötterna. Nyplanterade träd behöver regelbunden vattning de första åren.",phases:[{phase:"Vår (blomning)",need:"Medel",tip:"Vattna vid torka under blomning - vattenstress nu ger dålig pollination."},{phase:"Sommar (nötutveckling)",need:"Medel",tip:"Vattna jämnt under nötutvecklingen. Ojämn vattning kan ge kärnan problem att fylla skalet ordentligt."},{phase:"Höst",need:"Låg",tip:"Minska vattningen. Trädet förbereder sig för vintern."},{phase:"Vinter",need:"Ingen",tip:"Trädet vilar. Ingen vattning behövs."}],mistakes:["Glömmer att vattna nyplanterade träd - pålroten etableras de första 2-3 åren","Vattnar för mycket - valnöten tål inte vattensjuk mark"],tip:"Mulcha runt trädet med gräsklipp eller kompost - det håller fukt och minskar ogräs. Lämna 15 cm fritt runt stammen. Etablerade träd med djupa pålrötter (3-5 m!) klarar torka förvånansvärt bra."},soil:"Valnöten vill ha djup, väldränerad, näringsrik jord. Den tål de flesta jordtyper utom extrem lera eller ren sand. Djupa pålrötter (3-5 meter) gör att den trivs i jord andra träd struntar i.",soilTips:["Gräv en stor grop - minst dubbelt så bred som rotklumpen och rejält djup","Blanda in kompost i den uppgrävda jorden","Kalka om pH är under 6.0 - valnöten gillar lätt kalkrik jord","Undvik mark med högt grundvatten - stående vatten dödar rötterna"],timeline:{1:[{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Nötutveckling",months:"Juni-sept",icon:"growth"},{phase:"Skörd",months:"Sept-okt",icon:"harvest"},{phase:"Beskärning",months:"Juli-sept",icon:"scissors"},{phase:"Höstplantering",months:"Okt-nov",icon:"seedling"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],4:[{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Nötutveckling",months:"Juni-sept",icon:"growth"},{phase:"Skörd",months:"Okt",icon:"harvest"},{phase:"Beskärning",months:"Juli-aug",icon:"scissors"},{phase:"Vintervila",months:"Nov-april",icon:"snowflake"}],6:[{phase:"Blomning",months:"Juni",icon:"bloom"},{phase:"Nötutveckling",months:"Juli-sept",icon:"growth"},{phase:"Skörd",months:"Okt",icon:"harvest"},{phase:"Vintervila",months:"Nov-maj",icon:"snowflake"}]},nutritionData:[{month:"Mar",N:1,P:1,K:1},{month:"Apr",N:3,P:2,K:1},{month:"Maj",N:6,P:4,K:2,label:"Blomning"},{month:"Jun",N:7,P:5,K:4},{month:"Jul",N:5,P:4,K:6,label:"Nötfyllning"},{month:"Aug",N:3,P:3,K:7},{month:"Sep",N:1,P:2,K:4}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge kompost eller brunnen naturgödsel runt droppzonen. Valnöten är inte extremt krävande men uppskattar ett rejält mål på våren."},{timing:"Blomning (maj)",tip:"En giva vedaska (kaliumrik) stärker blomning och nötbildning."},{timing:"Sommar",tip:"Ingen extra gödsling behövs. Övergödsling med kväve ger frodigt bladverk men sämre nötproduktion."},{timing:"Höst",tip:"Ingen kvävegödsling efter midsommar. Mulcha med löv eller kompost som långsam näring."}],companions:{good:[{name:"Klöver",icon:"flower",why:"Fixerar kväve, täcker marken och stör inte valnötens djupa rötter."},{name:"Vinbär",icon:"berry",why:"Tolererar valnötens juglon. Buskar under trädkronan utnyttjar utrymmet smart."},{name:"Ringblomma",icon:"flower",why:"Tolererar juglon och lockar nyttoinsekter."}],bad:[{id:"apple",name:"Äpple",icon:"fruit",why:"Äppelträd är känsliga för valnötens juglon (naturligt växtgift). Håll minst 15-20 meters avstånd."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Nattskuggväxter (tomat, potatis, paprika) är känsliga för juglon och trivs inte nära valnötsträd."}]},rotation:{avoid:[{name:"Valnöt"}],avoidWhy:"Juglon (naturligt växtgift) anrikas i jorden under ett valnötsträd. Ett nytt träd kan påverkas, men effekten avtar efter 2-3 år utan träd.",goodBefore:[{name:"Gräsmatta"},{name:"Gröngödsling"}],goodBeforeWhy:"Mark som legat som gräsmatta eller gröngödslats ger bäst start.",goodAfter:[{name:"Gröngödsling"}],goodAfterWhy:"Gröngödsla marken i minst 3 år efter att ett valnötsträd tagits bort."},varieties:[{name:"Broadview",zones:[1,2,3],note:"Kanadensisk sort från Karpaterna. Kompakt växtsätt - passar mindre trädgårdar. Självfertil! Tunnskaliga, smakrika nötter. Ger skörd efter 3-5 år (ympad)."},{name:"Buccaneer",zones:[1,2,3],note:"Han- och honblommorna överlappar alltid - utmärkt självfertil. Stora nötter (6-8 cm). Skörd oktober-november. Bra val om du bara har plats för ett träd."},{name:"Fernor",zones:[1,2,3],note:"Sen bladsprickning - minskar risken för senvårfrost rejält. Frisk sort med god härdighet. Delvis självfertil men ger bättre skörd med partner."},{name:"Loiko",zones:[1,2,3,4],note:"Samling av fröförökade plantor från Vitryssland. Utmärkt härdighet - testade i Sundsvallstrakten med lyckad skörd. Varierar i egenskaper. Spännande för odlare i zon 4."}],problems:[{name:"Senvårfrost",symptom:"Blomknoppar och unga skott svartnar efter en frostnatt. Hela årets skörd kan gå förlorad.",fix:"Välj sort med sen bladsprickning (Fernor). Plantera i en sluttning där kall luft rinner undan - aldrig i en frostficka. Unga träd kan täckas med fiberduk vid frostrisknätter."},{name:"Bakteriebrand (Xanthomonas)",symptom:"Svarta fläckar på blad och unga skott. Blad torkar och faller. Värst i fuktigt väder.",fix:"Ta bort angripna grenar. Förbättra luftcirkulationen genom beskärning. Välj friska, certifierade plantor."},{name:"Ekorrar och kråkfåglar",symptom:"Nötterna försvinner innan du hinner skörda. Kajor, kråkor och ekorrar är otroligt snabba.",fix:"Skörda så snart det gröna skalet börjar spricka! Kontrollera trädet dagligen under skördesäsongen."}],pollination:{selfFertile:!1,description:"Valnöten har både han- och honblommor på samma träd, men de blommar ofta vid olika tidpunkter (dikogami). Vissa sorter (Broadview, Buccaneer) har bra överlappning och klarar sig ensamma. Två olika sorter ger alltid bättre skörd.",groups:[{name:"Självfertila (bra överlappning)",varieties:["Broadview","Buccaneer"]},{name:"Delvis självfertila",varieties:["Fernor"]},{name:"Fröförökade (varierar)",varieties:["Loiko"]}],tip:"Vindpollinerat - insekter spelar liten roll. Har du bara plats för ett träd: välj Buccaneer (han- och honblommorna överlappar alltid) eller Broadview (självfertil). Finns det grannar med valnöt? Då löser sig pollineringen av sig själv."},establishment:{description:"Valnöten kräver tålamod de första åren. Trädet lägger energi på att etablera sin djupa pålrot - det syns inte mycket ovan mark. Men när den väl tagit fart belönar den dig i generationer.",years:[{year:"År 1-2",tasks:["Vattna regelbundet hela sommaren - pålroten etablerar sig","Skydda stammen mot gnagare (nät eller spiral)","Stamskydd mot solbränna på sydvästra sidan vintertid","Ge kompost på våren, inte för mycket kväve"]},{year:"År 3-5",tasks:["Första nötterna dyker upp (ympade träd)!","Beskär under JAS-perioden - valnöten blöder kraftigt vid vårbeskärning","Forma kronan: öppen, luftig, ljus i mitten","Vattna vid torka men trädet blir alltmer självgående"]},{year:"År 5+",tasks:["Ökande skörd år för år","Minimal skötsel - valnöten är ett av de mest lättodlade fruktträden","Fortsätt JAS-beskärning för att hålla kronan öppen","Njut av att du planterade ett träd som dina barnbarn kommer skörda"]}],protection:["Stamskydd mot gnagare - kaniner och sorkar gnager bark på unga träd","Viltskydd om rådjur finns i området","Stamskydd mot solbränna (vit kalkmjölk) vintertid","Fiberduk vid frostrisknätter under blomning de första åren"],tip:"Valnöten planterar du för dina barnbarns skull - och det är därför det är så himla speciellt när du faktiskt får nötter! Ympade sorter (Broadview, Buccaneer) ger skörd redan efter 3-5 år."},ripeningGuide:{description:"Valnötter mognar från september till november. Det gröna skalet (hullet) spricker när nöten är mogen och nöten börjar falla. Skörda snabbt - ekorrar och kråkfåglar är ännu snabbare.",entries:[{variety:"Broadview",from:"sep",to:"okt",type:"Tidig valnöt"},{variety:"Fernor",from:"okt",to:"okt",type:"Mellansäsong"},{variety:"Buccaneer",from:"okt",to:"nov",type:"Sen valnöt"},{variety:"Loiko",from:"sep",to:"okt",type:"Varierar"}],tip:"Skörda så snart det gröna skalet börjar spricka. Bär handskar - juglon färgar händerna brunaktigt och det är svårt att tvätta bort!"},goodToKnow:[{icon:"warning",title:"Juglon - valnötens hemliga vapen",text:"Alla delar av valnöten producerar juglon, ett naturligt växtgift. Äppelträd och tomater mår dåligt nära ett valnötsträd. MEN: Fritidsodlingens Riksorganisation (FOR) konstaterar att den praktiska effekten i vanliga trädgårdar är ganska begränsad. Håll känsliga växter 15-20 m bort, men panika inte.",severity:"warning"},{icon:"tip",title:"Du planterar för generationer",text:"Ett valnötsträd kan leva i 200+ år. Carl von Linne beskrev valnötsträd i södra Sverige på 1700-talet. Det är ett av få träd du kan plantera med vetskapen att det kommer ge glädje i hundratals år.",severity:"tip"},{icon:"warning",title:"Beskär ALDRIG på våren!",text:"Valnöten blöder kraftigt vid vårbeskärning - saven rinner ur snittytorna och kan skada trädet allvarligt. Beskär under JAS-perioden (juli-aug-sept) precis som alla Prunus och stenfrukter.",severity:"warning"},{icon:"tip",title:"Manchurisk valnöt - alternativet i norr",text:"I zon 4-5 kan manchurisk valnöt (Juglans mandshurica) vara ett alternativ. Den ger mindre nötter med hårdare skal, men tål -40°C. Exotiskt vackra blad (upp till 75 cm!) som bonus.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Valnötsträd planteras som ympade eller fröförökade träd. Köp ett ungt träd och plantera det en gång för alla - valnöten har en djup pålrot och tål INTE omplantering.",steps:["Gräv en grop minst dubbelt så bred som rotklumpen och rejält djup","Slå ner en stödpåle INNAN du sätter trädet","Plantera på samma djup som trädet stått i krukan","Fyll igen med uppgrävd jord blandat med kompost","Vattna rikligt - minst 30 liter","Mulcha i 1-2 meters radie runt stammen","Montera stamskydd mot gnagare"],tips:["Vårplantering ger säkrare etablering - rötterna hinner växa under sommaren","Tänk på slutstorleken! Broadview blir 6-8 m, andra sorter 10-15 m","Juglon: plantera inte nära äppelträd, tomater eller andra känsliga växter","Köp ympade namnsorter för säkrare resultat (3-5 år till skörd istället för 10-15)"],indoorWeeks:null},seedSaving:{difficulty:"Medel",type:"Frösådd / Ympning",biennial:!1,description:"Valnötsträd kan förökas från frö (stratifiering krävs) eller genom ympning. Fröförökade träd ger inte samma egenskaper som moderträdet och tar 8-15 år till skörd.",steps:["Samla mogna nötter på hösten","Blötlägg i vatten 24-48 timmar","Stratifiera i fuktig sand i kylskåp 4-6 veckor vid 2-5°C","Alternativt: så direkt utomhus på hösten (naturen sköter stratifieringen)","Plantera på permanent plats så tidigt som möjligt (pålroten!)","Vänta 8-15 år på skörd (frösodd) eller 3-5 år (ympad)"],isolation:"Frösodd ger unika träd med okända egenskaper.",storageYears:"Färska nötter gror bäst samma höst",tip:"Vill du föröka en namnsort identiskt? Ympning är enda sättet. Men det är svårt på egen hand - valnöten blöder kraftigt. Gå en ympkurs!"},storage:{shelfLife:"3-12 månader (beroende på metod)",methods:[{method:"Torkning + svalt förvar",icon:"cellar",duration:"6-12 månader",description:"Ta bort det gröna skalet direkt. Sprid nötterna i ett lager och torka i luftigt rum i 2-3 veckor. Förvara svalt och torrt i nätpåsar eller papperskartonger.",best:!0},{method:"Kylskåp (i skal)",icon:"snowflake",duration:"1 år",description:"Torkade nötter i skal håller sig utmärkt i kylskåpet. Perfekt om du skördar mer än du hinner äta.",best:!1},{method:"Frysning (skalade)",icon:"snowflake",duration:"2+ år",description:"Skala nötterna och frys i påsar. Håller i flera år och är alltid redo att använda i bakning och matlagning.",best:!1}],tips:["Bär handskar vid skörd - juglon färgar händerna brunaktigt","Ta bort det gröna skalet DIREKT efter skörd - annars kan kärnan bli bitter","Torka ordentligt - fuktiga nötter möglar snabbt","Förvara aldrig i plastpåse - använd nätpåsar eller papperskartonger"]},harvestCalc:{minPerSqm:5,maxPerSqm:30,unit:"kg per träd (år 8+)"},pruning:{label:"Beskärning",types:{summer:{name:"JAS-beskärning (den enda rätta tiden)",when:"Juli-september",description:"Valnöten blöder kraftigt vid vårbeskärning - saven rinner okontrollerat ur snittytorna. Beskär BARA under JAS-perioden när saven är lugnare och snitten torkar snabbt.",steps:["Ta bort döda, sjuka och korsande grenar","Öppna kronan för ljus och luftcirkulation","Ta bort vattenskott som växer rakt uppåt","Begränsa höjden genom att korta in toppskottet","Ta aldrig bort mer än 1/4 av kronvolymen per år"]}}},propagation:{difficulty:"Avancerad",methods:[{method:"Ympning",description:"Det enda sättet att föröka namnsorter med garanterade egenskaper. Svårt på egen hand - valnöten blöder kraftigt. Kopulationsympning på våren.",icon:"seedling"},{method:"Frösådd",description:"Stratifiera nötterna och så utomhus. Ger unika träd med varierande egenskaper. Spännande experiment men räkna med 8-15 år till skörd.",icon:"seed"}],tip:"Ympkurser arrangeras av lokala trädgårdsföreningar. Valnötsympning är knepigare än äpple, men möjligt med rätt teknik."}},te=Object.freeze(Object.defineProperty({__proto__:null,valnot:Br},Symbol.toStringTag,{value:"Module"})),Tr={name:"Vindruva",icon:"vindruva",category:"frukt",family:"Vinväxter",familyLatin:"Vitaceae",perennial:!0,lifespan:"30-50+ år",difficulty:"Medel",difficultyWhy:"Vindruvan kräver rätt läge (sydvägg!), regelbunden beskärning och viss sjukdomskontroll. Men med rätt sort och rätt plats belönar hon dig med egna druvor i Mellansverige. Vinterbeskärning är det moment som skrämmer nybörjare mest - men det är enklare än det ser ut.",zones:{outdoor:[1,2,3,4],indoor:null,greenhouse:[1,2,3,4,5]},days:"Skörd år 3-4",spacing:"1,5-3 m",spacingNote:"Mot spaljé/sydvägg: 1,5-2 m. Fristående pergola: 2-3 m.",rowSpacing:"2-3 m",depth:"Rotklumpens djup",depthNote:"Plantera inte djupare än rotklumpen suttit. Ympade plantor: ympstället ovan jord.",ph:{min:5.5,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Vindruvan vill VERKLIGEN ha sol - minst 6-8 timmars direkt solsken per dag. Sydvägg är inte valfritt, det är ett krav. Tegelväggen lagrar värme under dagen och avger den nattetid - det ger extra odlingszoner."},temperature:{min:-35,max:40,ideal:"20-30°C",detail:"Härdigheten varierar enormt mellan sorter. Zilga tål -40°C(!), medan Vitis vinifera-sorter klarar -15 till -25°C. Blomningen (midsommartid) är känslig - nattefrost då slår ut hela skörden."},wind:{level:"Skyddat",detail:"Vindskydd är viktigt, särskilt under blomning. En varm sydvägg ger både sol, värme och vindskydd - den perfekta vinplatsen."}},watering:{need:"Medel",icon:"water",summary:"Etablerade vinrankor är relativt torktoleranta tack vare djupa rötter. Nyplanterade rankor behöver regelbunden vattning de första åren. Under mognad: minska vattning för bättre smak.",phases:[{phase:"Vår (skottillväxt)",need:"Medel",tip:"Vattna vid torka. Jämn fukt ger starkare skott och bättre blomknoppar."},{phase:"Blomning (midsommar)",need:"Låg",tip:"Undvik riklig vattning under blomning - det ger dålig pollinering."},{phase:"Fruktutveckling (juli-aug)",need:"Medel",tip:"Vattna jämnt. Ojämn vattning ger spräckta druvor och mögel."},{phase:"Mognad (aug-okt)",need:"Låg",tip:"Minska vattningen! Lite torka nu höjer sockerhalten och ger sötare druvor."}],mistakes:["Vattnar på bladen - ökar risken för mjöldagg enormt","Ojämn vattning under mognad - ger spräckta druvor som möglar","Övervattnar under blomning - dålig fruktsättning"],tip:"Vattna alltid vid rötterna, aldrig över bladverket. Droppbevattning är idealiskt. Under mognad: minska vattningen - lite stress ger sötare druvor."},soil:"Vindruvan vill ha väldränerad, lagom näringsrik jord. Vattensjuk mark är dödlig. En sandig, kalkrik jord på en sydsluttning är drömmen - precis som i Frankrike.",soilTips:["Staketdruvor (Zilga, Rondo): trivs i svagt sur jord (pH 5,5-6,0), blanda in torv/rhododendronjord","Vinodlingsdruvor (Solaris, Regent): gillar kalkrik jord (pH 6,5-7,0)","Blanda in grus eller sand för bättre dränering om jorden är tung","En sydsluttning med djup jord (60+ cm) är den perfekta platsen"],timeline:{1:[{phase:"Vinterbeskärning",months:"Dec-jan",icon:"scissors"},{phase:"Knoppsprickning",months:"April-maj",icon:"growth"},{phase:"Blomning",months:"Juni",icon:"bloom"},{phase:"Fruktmognad",months:"Aug-sept",icon:"harvest"},{phase:"Skörd",months:"Sept-okt",icon:"harvest"},{phase:"Lövfall",months:"Okt-nov",icon:"snowflake"}],4:[{phase:"Vinterbeskärning",months:"Dec-jan",icon:"scissors"},{phase:"Knoppsprickning",months:"Maj",icon:"growth"},{phase:"Blomning",months:"Juni-juli",icon:"bloom"},{phase:"Fruktmognad",months:"Sept",icon:"harvest"},{phase:"Skörd",months:"Sept-okt",icon:"harvest"},{phase:"Lövfall",months:"Okt",icon:"snowflake"}],6:[{phase:"Vinterbeskärning",months:"Dec-jan",icon:"scissors"},{phase:"Knoppsprickning",months:"Maj-juni",icon:"growth"},{phase:"Blomning",months:"Juli",icon:"bloom"},{phase:"Skörd",months:"Okt",icon:"harvest"},{phase:"Lövfall",months:"Okt",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:2,P:1,K:1},{month:"Maj",N:5,P:3,K:2,label:"Skottillväxt"},{month:"Jun",N:7,P:5,K:3,label:"Blomning"},{month:"Jul",N:5,P:5,K:5},{month:"Aug",N:3,P:3,K:7,label:"Mognad"},{month:"Sep",N:1,P:2,K:5}],nutritionTips:[{timing:"Tidig vår (april)",tip:"Ge kompost eller brunnen gödsel runt plantan. Vindruvan uppskattar en rejäl vårstart."},{timing:"Blomning (juni)",tip:"Ingen extra gödsling behövs. Övergödsling med kväve ger frodigt bladverk men dålig fruktsättning."},{timing:"Mognad (aug)",tip:"Absolut ingen kvävegödsling nu. Kalium (vedaska) stärker mognad och sockerhalt."},{timing:"Höst",tip:"Mulcha med kompost som långsam vintergödsling."}],companions:{good:[{name:"Lavendel",icon:"herb",why:"Trivs i samma varma, soliga läge. Lockar pollinatörer och avskräcker bladlöss."},{name:"Ringblomma",icon:"flower",why:"Lockar nyttoinsekter och ger vacker kontrast under vinrankan."},{name:"Klöver",icon:"flower",why:"Fixerar kväve och täcker marken. Traditionell marktäckare i vingårdar."}],bad:[{name:"Kål",icon:"vegetable",why:"Kålväxter konkurrerar om samma näring och kan sprida sjukdomar i den fuktiga miljön under bladverket."}]},rotation:{avoid:[{name:"Vindruva"}],avoidWhy:"Plantera inte nya vinrankor exakt där gamla stått - sjukdomsorganismer i jorden gör att den nya plantan inte trivs. Vänta minst 3 år.",goodBefore:[{name:"Gröngödsling"},{name:"Gräsmatta"}],goodBeforeWhy:"Väletablerad, dränerad jord ger den bästa starten.",goodAfter:[{name:"Gröngödsling"}],goodAfterWhy:"Bygg upp jordstrukturen med gröngödsling innan ny plantering."},varieties:[{name:"Zilga",zones:[1,2,3,4,5],note:"Den mest odlade sorten i Norden! Tål -40°C. Blå druvor med söt smak. Många frön. Fantastisk saft. Extremt lättodlad - ger druvor där andra ger upp."},{name:"Solaris",zones:[1,2,3],note:"Dominerar på svenska vingårdar. PIWI-sort med inbyggd svampresistens. Gröna druvor, mognar på bara 90 dagar. Utmärkt bordsdruva och vinframställning."},{name:"Rondo",zones:[1,2,3],note:"Blå druvor, tål -35°C. Bra för rödvin. Viss svampresistens. Vanlig på svenska vingårdar."},{name:"Somerset Seedless",zones:[1,2,3],note:"Kärnfri! Rödvioletta druvor. Tål -30 till -35°C. Den perfekta borddruvan - söt, kärnfri och härdig."},{name:"Boskoop Glory",zones:[1,2],note:"Klassisk trädgårdsdruva. Blå, söta druvor i augusti-september. Passar bäst mot skyddad sydvägg i zon 1-2."},{name:"Hasanski Sladki",zones:[1,2,3],note:"Ukrainskt ursprung. Blå druvor, söt smak, C-vitaminrik. Mognar 2 veckor efter Zilga. Kallas även Baltica."}],problems:[{name:"Mjöldagg (Erysiphe necator)",symptom:"Vit mjölaktig beläggning på blad och druvor. Druvorna blir bruna och korkiga. Värst i varmt, fuktigt väder.",fix:"PIWI-sorter (Solaris, Regent, Rondo) har inbyggd resistens. Håll kronan luftig genom pincering. Svavel (Kumulus) förebygger. Bikarbonat (1 tsk bakpulver + 1 liter vatten + rapsolja) fungerar som hemmafix."},{name:"Gråmögel (Botrytis cinerea)",symptom:"Druvklasarna möglar och ruttnar vid mognad. Värst i vått, kyligt väder.",fix:"God luftcirkulation kring klasarna. Gallra täta klasar tidigt. Skörda så snart druvorna är mogna - vänta inte!"},{name:"Bladlöss",symptom:"Klibbiga blad, deformerade skottspetsar.",fix:"Spola av med vattenslang. Locka nyttoinsekter med blommor intill. Sällan ett allvarligt problem utomhus."},{name:"Fåglar och getingar",symptom:"Fåglar äter de bästa druvorna precis innan du tänkt skörda. Getingar borrar hål i mogna druvor.",fix:"Fågelnät runt klasarna när de börjar färgas. Reducera vattning mot slutet (minskar spräckning som lockar getingar)."}],pollination:{selfFertile:!0,description:"De allra flesta moderna odlingssorter är självfertila - varje blomma pollinerar sig själv. Det är en stor fördel jämfört med många andra fruktträd. Två sorter ger dock ofta bättre fruktsättning.",groups:[{name:"Självfertila staketdruvor",varieties:["Zilga","Rondo","Somerset Seedless","Hasanski Sladki"]},{name:"Självfertila vinodlingsdruvor",varieties:["Solaris","Regent","Boskoop Glory"]}],tip:"Vindruvan klarar sig ensam, men odlar du två sorter sida vid sida ger de ofta bättre skörd. Blomningen sker diskret i juni - små, doftlösa blommor som pollineras av vind och insekter."},establishment:{description:"Vindruvan kräver lite investering de första åren - en stabil spaljé och regelbunden beskärning. Men från år 3-4 belönar den dig med egna druvor. Lägesmässigt är den känsligare än de flesta fruktträd.",years:[{year:"År 1",tasks:["Montera spaljé eller trådar mot sydvägg INNAN plantering","Plantera i maj-juni efter sista frosten","Vattna regelbundet (25 liter 2 gånger/vecka vid torka)","Låt huvudskottet växa fritt - beskär inte första året"]},{year:"År 2",tasks:["Första vinterbeskärningen: form systemet (Guyot eller cordon)","Bind upp årets skott mot trådarna","Plocka bort ALLA druvklasar - rankan ska bygga rötter och stomme","Pincera (klipp av toppen på) sidoskott för att styra energin"]},{year:"År 3-4",tasks:["Första skörden! Tillåt 3-5 klasar per planta","Etablera årsrutinen: vinterbeskärning, sommarpincering, skörd","Öka antalet tillåtna klasar gradvis","Rankan blir alltmer produktiv år för år"]}],protection:["Spaljé eller trådsystem - planera och bygg INNAN plantering","Sydvägg med termisk massa (tegel/betong) ger 1-2 extra odlingszoner","Fiberduk vid frostrisknätter under blomning","Fågelnät under mognad (aug-okt)"],tip:"Läget är allt. En Zilga mot en varm sydvägg i zon 4 slår en Boskoop Glory i ett öppet läge i zon 2. Sydväggen är vindruvans bästa vän i Sverige."},ripeningGuide:{description:"Druvor mognar från augusti till oktober i Sverige beroende på sort och läge. De mognar INTE vidare efter plockning - låt dem hänga så länge som möjligt för bästa smak.",entries:[{variety:"Somerset Seedless",from:"aug",to:"sep",type:"Tidig staketdruva"},{variety:"Zilga",from:"aug",to:"sep",type:"Staketdruva"},{variety:"Hasanski Sladki",from:"sep",to:"sep",type:"Staketdruva"},{variety:"Rondo",from:"sep",to:"okt",type:"Vindruva"},{variety:"Solaris",from:"sep",to:"okt",type:"Vindruva"},{variety:"Boskoop Glory",from:"aug",to:"sep",type:"Trädgårdsdruva"}],tip:"Det enda tillförlitliga mognadsprovet: smaka! En mogen druva smakar söt och aromatisk. En omogen smakar gräsig och syrlig. Klippa av hela klasen med sax - dra aldrig."},goodToKnow:[{icon:"warning",title:"Sydvägg - inte valfritt",text:"I Sverige är läget allt för vindruvan. En varm sydvägg av tegel eller betong lagrar solens värme under dagen och avger den nattetid. Det kan ge 1-2 extra odlingszoner. Utan sydvägg behöver du en extremt härdig sort som Zilga.",severity:"warning"},{icon:"tip",title:"Två sortkategorier - välj rätt",text:"Staketdruvor (Zilga, Rondo) tål -35 till -40°C och fungerar i zon 3-5. Vinodlingsdruvor (Solaris, Regent) behöver sydvägg eller kallväxthus. Blandar du ihop dem blir du besviken. Välj efter ditt läge!",severity:"tip"},{icon:"warning",title:"Vinterbeskärning - våga klippa!",text:"Det mest skrämmande momentet för nybörjare: ta bort 75% av fjolårets tillväxt i december-januari. Det SER brutalt ut. Men druvor bildas BARA på nya årsskott. Utan kraftig beskärning: ingen skörd. Våga klippa!",severity:"warning"},{icon:"tip",title:"PIWI-sorter - framtidens druvor",text:"Solaris, Regent och Rondo är PIWI-sorter (pilzwiderstandsfähig = svampresistenta). De har inbyggd resistens mot mjöldagg och falsk mjöldagg - det gör odlingen dramatiskt enklare i Sveriges fuktiga klimat.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Vinrankor planteras som rotade plantor eller sticklingar. Plantera efter sista frosten (maj-juni) mot en varm sydvägg eller i spaljé.",steps:["Montera spaljé eller trådsystem INNAN plantering","Gräv en grop dubbelt så bred som rotklumpen","Blanda in kompost och eventuellt grus för dränering","Plantera 20-30 cm från väggen (lutar rotklumpen mot väggen)","Vattna rikligt efter plantering","Bind upp huvudskottet mot spaljén"],tips:["Plantera efter sista frosten - vindruvan tål inte vårfrost","Sydvägg av tegel eller betong ger bäst resultat","Staketdruvor (Zilga) för zon 3-5, vinodlingsdruvor (Solaris) för zon 1-2","Ge ordentligt med plats - en vuxen vinranka kan väga hundratals kilo"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Sticklingar",biennial:!1,description:"Vindruvor förökas enkelt med sticklingar. Vedsticklingar på hösten är det säkraste sättet.",steps:["Ta 25-30 cm långa sticklingar efter höstbeskärning (nov-dec)","Välj penntjocka, mognade rankor med 3-4 knoppar","Förvara i plastpåse i kylskåp till februari-mars","Plantera i sandblandad jord med 1 knopp ovan jord","Håll frostfritt och ljust - rötter bildas på 4-8 veckor","Plantera ut efter sista frosten"],isolation:"Sticklingar ger exakta kloner av moderplantan.",storageYears:"Sticklingar förvaras i kylskåp 2-3 månader",tip:"Vindruvor är löjligt enkla att föröka. Varje höstbeskärning ger mängder av material. Prova att sätta några sticklingar i vatten på fönsterbrädan - det fungerar överraskande bra, särskilt med Zilga!"},storage:{shelfLife:"1-2 veckor (färska)",methods:[{method:"Kylskåp",icon:"snowflake",duration:"1-2 veckor",description:"Förvara klasar i kylskåp vid 0-2°C. Hög luftfuktighet förhindrar skrynkling.",best:!0},{method:"Flasktricket",icon:"cellar",duration:"Flera månader",description:"Gammalt knep: klipp klasen med 15-20 cm stam. Ställ stammen i en flaska med vatten. Förvara mörkt och svalt. Håller i månader!",best:!1},{method:"Saft",icon:"storage",duration:"1+ år",description:"Druvpress eller varmpress ger fantastisk saft. Zilga-saft är häpnadsväckande god. Pastörisera och fyll på flaskor.",best:!1},{method:"Sylt/gelé",icon:"storage",duration:"1+ år",description:"Druvsylt eller druvgelé - tillsätt pektin (druvor har ganska lite naturligt). Blanda gärna med äpple.",best:!1}],tips:["Druvor mognar INTE vidare efter plockning - skörda först när de smakar rätt","Klippa av klasen med sax - dra aldrig","Zilga ger fantastisk saft - det vanligaste sättet att ta hand om skörden","Homöjligt god saft av Rondo - perfekt för glogg!"]},harvestCalc:{minPerSqm:2,maxPerSqm:8,unit:"kg per planta (år 4+)"},pruning:{label:"Beskärning",types:{winter:{name:"Vinterbeskärning (den viktigaste!)",when:"December-januari (i dvala, INNAN savstigning)",description:"Druvor bildas BARA på nya årsskott. Utan beskärning: inga druvor. Ta bort 75% av fjolårets tillväxt. Det ser brutalt ut - men det är helt nödvändigt. Beskär aldrig sent på våren när saven stigit - rankan blöder och kan dö.",steps:["Identifiera systemet: Guyot (en arm) eller cordon (permanent arm med sporer)","Guyot: ta bort fjolårets fruktarm, bind ner en ny","Cordon: korta in alla sidoskott till 2-3 knoppar (sporer)","Ta bort allt dött och sjukt","Lämna aldrig mer än du planerar att bära druvor på"]},summer:{name:"Sommarbeskärning (pincering)",when:"Juni-augusti",description:"Styr energin mot druvorna istället för bladverket. Pincering är det viktigaste sommarjobbet.",steps:["Pincera (klipp av toppen på) skottet 2-3 blad ovanför druvklasen","Ta bort tjuvskott i bladvecken löpande","Gallra druvklasar: max 2-3 per skott","Plocka bort blad som skuggar druvklasarna (sen sommar)"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Vedsticklingar",description:"Det säkraste sättet. Ta 25-30 cm sticklingar vid höstbeskärning. Förvara i kylskåp till våren, plantera i sandblandad jord. Rotar sig på 4-8 veckor.",icon:"seedling"},{method:"Grönsticklingar",description:"Halvförvedade skott i juli-augusti. 10-15 cm, ta bort nedre bladen. Rotar sig i drivhus eller soligt fönster.",icon:"seedling"},{method:"Avläggning",description:"Böj en kraftig rankning ner till marken och begrav mitten. Rötter bildas under sommaren. Klipp av från moderplantan nästa vår.",icon:"seedling"}],tip:"Varje höstbeskärning ger dig gratis förökingsmaterial. Testa att sätta några sticklingar i vatten - Zilga rotar sig nästan varje gång!"}},ne=Object.freeze(Object.defineProperty({__proto__:null,vindruva:Tr},Symbol.toStringTag,{value:"Module"})),wr={name:"Vita vinbär",icon:"vita-vinbar",category:"bär",family:"Ripsväxter",familyLatin:"Grossulariaceae",perennial:!0,lifespan:"15-20 år",difficulty:"Enkel",difficultyWhy:"Exakt lika lättodlad som röda vinbär - samma buske, samma skötsel, bara bärfärgen skiljer. Extremt härdig, kräver minimal omvårdnad och ger pålitlig skörd. Vita vinbär har dessutom mildare, sötare smak som gör dem godare att äta direkt.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:null},days:"70-90",spacing:"120-150 cm",rowSpacing:"200-250 cm",depth:"Något djupare än i krukan",ph:{min:5.5,max:7,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Precis som röda vinbär - trivs bäst i full sol men klarar halvskugga utmärkt. I sol blir bären sötare och mer genomskinliga. De halvt genomskinliga, gyllene bären i solljus är en av trädgårdens vackraste syner."},temperature:{min:-30,max:30,ideal:"15-22°C",detail:"Lika härdig som röda vinbär - tål ner till -30°C. Trivs i sval svensk sommar. Blommar sent nog att undvika de flesta vårfroster."},wind:{level:"Tålig",detail:"Kompakt, stabil buske som klarar vind bra. Lite vindskydd under blomning hjälper pollineringen men är inget krav."}},watering:{need:"Medel",icon:"water",summary:"Samma vattenbehov som röda vinbär - grunda rötter som behöver jämn fukt under blomning och bärutveckling, men inte krävande i övrigt. Mulcha och slappna av.",phases:[{phase:"Vår (knoppsprickning)",need:"Medel",tip:"Vattna vid torr vår så att blommorna får en bra start. Busken vaknar tidigt och vill komma igång."},{phase:"Blomning (maj-juni)",need:"Hög",tip:"Kritisk period! Torka nu ger glesa klasar. Vattna djupt 2 gånger per vecka vid utebliven nederbörd."},{phase:"Bärmognad (juni-juli)",need:"Medel-Hög",tip:"Jämn fukt ger fina, fasta bär. Ojämn vattning kan ge sprickta bär."},{phase:"Höst (efter skörd)",need:"Låg",tip:"Busken vilar. Minimal vattning behövs."}],mistakes:["Vattnar för lite under blomning - klasarna blir glesa och sätter dåligt","Ojämn vattning under mognad - bären spricker","Vattensjuk jord - rötterna ruttnar i stående vatten"],tip:"Mulcha med gräsklipp eller bark. En mulchad vinbärsbuske klarar sig nästan helt själv - mulchen håller fukten, matar maskarna och håller ogräs borta."},soil:"Samma krav som röda vinbär - trivs i de flesta jordtyper bara dräneringen är okej. Föredrar näringsrik, fukthållande jord men är flexibel. Lite kompost vid plantering och årlig mulch är allt som behövs.",soilTips:["Blanda in kompost vid plantering för en bra start","Mulcha årligen med kompost, bark eller gräsklipp","Klarar lerjord bra om den inte är helt kompakt","Svagt surt till neutralt pH (5.5-7.0) - funkar i de flesta svenska trädgårdar"],timeline:{1:[{phase:"Plantering",months:"Okt-nov eller mars-april",icon:"seedling"},{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Skörd",months:"Juli-aug",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (mars)",icon:"scissors"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],4:[{phase:"Plantering",months:"Okt eller april-maj",icon:"seedling"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Skörd",months:"Juli",icon:"harvest"},{phase:"Beskärning",months:"Tidig vår (feb-mars)",icon:"scissors"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],6:[{phase:"Plantering",months:"Maj-juni",icon:"seedling"},{phase:"Blomning",months:"Juni",icon:"bloom"},{phase:"Skörd",months:"Juli-aug",icon:"harvest"},{phase:"Beskärning",months:"Sen vinter (mars-april)",icon:"scissors"},{phase:"Vintervila",months:"Okt-april",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:4,P:2,K:2},{month:"Maj",N:5,P:4,K:3},{month:"Jun",N:4,P:5,K:6},{month:"Jul",N:3,P:4,K:7},{month:"Aug",N:2,P:3,K:5},{month:"Sep",N:1,P:2,K:3}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge kompost eller brunnen gödsel runt busken. Vita vinbär har ungefär samma näringsbehov som röda vinbär - inte lika hungriga som svarta vinbär."},{timing:"Blomning (maj)",tip:"Kaliumrik gödsel (tomatgödsel eller vedaska) stärker blomning och bärkvalitet. Kalium ger smak och fina, genomskinliga bär."},{timing:"Höst (mulch)",tip:"Lägg ett lager kompost eller lövmull som höstmulch. Det matar busken sakta under vintern."}],companions:{good:[{id:"ringblomma",name:"Ringblomma",icon:"flower",why:"Lockar pollinatörer under blomningen. Vita vinbär gynnas av god pollinering för fulla, tunga klasar."},{id:"graslok",name:"Gräslök",icon:"herb",why:"Doften avskräcker bladlöss. Fint marktäckande under buskarna."},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Fixerar kväve i jorden. Bra granne som inte tar plats i sidled."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Risk för delad svampsjukdom. Håll bra avstånd."}]},rotation:{avoid:[{id:"vita-vinbar",name:"Vita vinbär"},{id:"roda-vinbar",name:"Röda vinbär"},{id:"svarta-vinbar",name:"Svarta vinbär"},{id:"krusbar",name:"Krusbär"}],avoidWhy:"Alla Ribes-arter delar sjukdomar (mjöldagg, bladfallsjuka, gallkvalster). Vänta minst 5 år innan du planterar nya vinbär på samma plats.",goodBefore:[{name:"Solig, öppen plats"},{name:"Baljväxter"}],goodBeforeWhy:"Frisk mark utan tidigare Ribes-växter. Baljväxter ger kväverik jord.",goodAfter:[{name:"Gröngödsling"},{id:"artor",name:"Ärtor"}],goodAfterWhy:"Efter 15-20 år med vinbär behöver jorden byggas upp igen."},varieties:[{name:"Versailles Blanche",zones:[1,2],note:"Den absoluta klassikern! Fransk sort från 1843. Stora, gyllene bär med söt smak. Långa, lättplockade klasar. Om du bara väljer en sort i södra Sverige - ta denna."},{name:"Vit Jätte",zones:[1,2,3,4],note:"Svensk sort utvecklad av Åke Truedsson, E-planta. Extra stora bär - namnet ljuger inte! Söt smak och fina klasar. Kraftig buske. Bra val om du vill ha de största bären."},{name:"White Pearl",zones:[1,2,3,4],note:"Också känd som Witte Parel. Stor buske med riklig skörd. Stora, genomskinliga bär med söt, mild smak. Vacker i trädgården tack vare de ljusa, lysande klasarna."}],problems:[{name:"Bladlöss (vinbärsbladlus)",symptom:"Bladen bubblar och krälar ihop sig. Ser dramatiskt ut men busken klarar det.",fix:"Spola av med hård vattenstråle. Locka nyckelpigor med blommande växter intill. Sällan allvarligt - busken klarar sig bra."},{name:"Mjöldagg",symptom:"Vitt, mjöligt belägg på blad och skottspetsar. Vita vinbär drabbas något lindrigare än svarta.",fix:"God luftcirkulation genom ordentlig gallring. Klipp bort angripna skottspetsar. Undvik kvävegödsling sent."},{name:"Vinbärsgallkvalster",symptom:"Uppsvällda, onormalt stora knoppar under vintern. Knopparna dör utan att utvecklas.",fix:"Plocka bort svullna knoppar i senvintern och bränn dem. Vid kraftigt angrepp - byt ut busken. Vita vinbär drabbas lindrigare än svarta."},{name:"Fåglar",symptom:"Bären försvinner. Vita bär syns mindre än röda, men fåglar hittar dem ändå.",fix:"Nät över buskarna när bären börjar mogna. Vita bär har dock en fördel - de syns sämre och lockar fåglarna något mindre än röda."}],goodToKnow:[{icon:"tip",title:"Sötare än röda",text:"Vita vinbär har mildare, sötare smak än röda och saknar den skarpa syrligheten. De är faktiskt godare att äta direkt från busken - speciellt solvarma en varm julidag. Barn älskar dem!",severity:"tip"},{icon:"tip",title:"Samma art, annan färg",text:"Vita vinbär är egentligen samma art som röda vinbär (Ribes rubrum) - bara utan det röda pigmentet. All kunskap om odling av röda vinbär gäller rakt av. Samma buske, samma skörd, samma skötsel - bara vackrare och godare.",severity:"tip"},{icon:"tip",title:"Gyllene transparens",text:"Mogna vita vinbär är halvt genomskinliga och skimrar gyllene i solljus. Det är en av trädgårdens vackraste syner. Planterar du dem i sol och låter klasarna hänga fritt ser det ut som kristallkronor.",severity:"tip"},{icon:"tip",title:"Gele med twist",text:"Vitvinbärsgele har samma fantastiska geleringsförmåga som röda vinbär (hög pektinhalt) men med en mildare, mer elegant smak. Vacker gyllene färg. Perfekt till ost och fisk - en riktig delikatess.",severity:"tip"},{icon:"warning",title:"Fåglarna hittar dem ändå",text:"Vita bär syns sämre i trädgården men fåglarna hittar dem ändå - de orienterar sig inte bara på färg. Nät behövs om du vill vara säker. Men vita vinbär lockar generellt färre fåglar än röda.",severity:"warning"}],sowing:{method:"direct",label:"Plantering",description:"Vita vinbär planteras precis som röda vinbär - barrotade buskar (höst eller tidig vår) eller krukodlade plantor. Höstplantering ger bäst etablering.",steps:["Gräv en grop dubbelt så bred som rotklumpen och lika djup plus 5 cm","Blanda in kompost i jorden","Plantera något djupare än busken stod i krukan","Vattna rikligt","Klipp ner alla grenar till ca 20 cm (3-5 knoppar per gren)","Mulcha med bark eller gräsklipp"],tips:["Höstplantering (okt-nov) ger bäst resultat","Klipp ner vid plantering - det ger en starkare buske från start","Första skörden år 2, full skörd från år 3-4","Kombinera gärna med röda vinbär - de pollinerar varandra och du får variation i bärlådan"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Vegetativ förökning",biennial:!1,description:"Vita vinbär förökas exakt som röda vinbär med vedartade sticklingar på hösten. Hög lyckandefrekvens och enkelt att göra.",steps:["Klipp 20-25 cm långa sticklingar av årets mogna skott i oktober-november","Klipp snett i nedre änden, rakt i övre","Ta bort alla knoppar utom de 3-4 översta","Sätt i fuktig jord utomhus med bara de översta knopparna ovan mark","Rotar sig under vintern och kan planteras ut nästa höst"],isolation:"Vegetativ förökning - kloner av moderplantan.",storageYears:"Ej tillämpligt",tip:"Sticklingar av vita vinbär rotar sig bra. Gör gärna extra - 7-8 av 10 lyckas vanligtvis. Nedböjning (marklager) är det säkraste alternativet."},storage:{shelfLife:"5-7 dagar (färska)",methods:[{method:"Frysning",icon:"snowflake",duration:"12+ månader",description:"Frys hela klasar - bären lösgör sig lätt när de är frysta. Perfekt för gele, saft eller garnering. Tappar lite av det vackra utseendet men behåller smaken fullt ut.",best:!0},{method:"Gele",icon:"storage",duration:"1+ år",description:"Vitvinbärsgele är en delikatess med elegant, mild smak och vacker gyllene färg. Hög pektinhalt ger perfekt gelering utan tillsatser. Fantastisk till ost, fisk och ljust kött.",best:!1},{method:"Saft",icon:"storage",duration:"1+ år",description:"Mild, söt saft med vacker ljusgyllene färg. Blanda gärna med äpple eller fläder för extra dimension.",best:!1},{method:"Kylskåp",icon:"snowflake",duration:"5-7 dagar",description:"Håller sig bra i kylen tack vare det fasta skalet. Förvara på hushållspapper. Tvätta inte förrän du äter.",best:!1}],tips:["Plocka hela klasar med sax - det går mycket snabbare","Rensa bären med en gaffel - dra klasen genom tänderna","Vita vinbär är godare direkt från busken än röda - spara gärna lite till ätning","Blanda vita och röda vinbär i gele för vacker tvåfärgad effekt"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3.5,unit:"kg"},pruning:{label:"Beskärning",types:{maintenance:{name:"Underhållsbeskärning",when:"Tidig vår (feb-mars) innan knopparna svällt",description:"Exakt samma princip som röda vinbär: bär bäst på 2-4 år gammal ved. Var inte för ivrig med saxen - de äldre grenarna är de mest produktiva. En frisk buske har 8-12 grenar av blandad ålder.",steps:["Ta bort grenar som är 4+ år gamla vid basen","Ta bort svaga, korsande eller skadade grenar","Spara 2-3 nya skott som ersättning","Sikta på 8-12 grenar totalt, blandade åldrar","Korta sidoskott till 2-3 knoppar","Håll buskens mitt öppen och luftig"]},rejuvenation:{name:"Föryngringsbeskärning",when:"Tidig vår",description:"Gammal buske? Samma föryngring som röda vinbär. Ta bort en tredjedel av de äldsta grenarna varje år i tre år, eller klipp ner allt och börja om.",steps:["Ta bort alla grenar äldre än 4 år och alla svaga skott","Behåll 4-5 starka grenar i 2-3 årsåldern","Korta dem till halva längden","Gödsla med kompost och vattna","Full skörd igen om 2 år"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Vedartade sticklingar",description:"Klipp 20-25 cm av årets mogna skott i oktober-november. Ta bort nedre knoppar, sätt i fuktig jord utomhus. Rotar sig under vintern. 7-8 av 10 lyckas - bra odds!",icon:"scissors"},{method:"Nedböjning (marklager)",description:"Böj ner en låg gren och fäst mot marken med bygel. Täck med jord. Grenen rotar sig och kan klippas loss nästa höst. Nästan garanterad framgång.",icon:"seedling"}],tip:"Sticklingar på hösten är standardmetoden. Nedböjning är säkrare om du bara vill ha en eller två nya plantor. Båda metoderna ger identiska kloner av moderplantan."}},ie=Object.freeze(Object.defineProperty({__proto__:null,vitaVinbar:wr},Symbol.toStringTag,{value:"Module"})),Mr={name:"Vitkål",icon:"vegetable",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Medel",difficultyWhy:"Vitkål kräver lite tålamod och planering - hon vill ha näringsrik jord, jämn fukt och framför allt skydd mot kålfjärilen. Men ger du henne det hon behöver belönar hon dig med kilovis av kål som håller hela vintern.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:[1,2,3,4,5,6,7,8]},days:"60-150",spacing:"40-60 cm",rowSpacing:"50-70 cm",depth:"1-2 cm",ph:{min:6.5,max:7.5,ideal:7},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmar sol per dag. I halvskugga blir huvudena mindre och lösare - vitkål vill ha ordentligt med ljus för att bygga stora, tunga huvuden."},temperature:{min:-7,max:25,ideal:"15-20°C",detail:"Vitkål är en sval norbo som trivs bäst runt 15-20°C. Hon tål frost imponerande bra - ner till -7°C för härdade plantor - och kan stå kvar långt in på hösten. Över 25°C stressar hon och tillväxten bromsas."},wind:{level:"Skyddat",detail:"Vitkål bygger tunga huvuden som kan fånga vind som ett segel. Ge henne lite vindskydd, eller kupa jord runt stambasen för extra stabilitet."}},watering:{need:"Medel-Hög",icon:"water",summary:"Vitkål vill ha jämn fukt hela säsongen. Ojämn vattning gör att huvudena kan spricka - och en sprucken kål är en ledsen kål.",phases:[{phase:"Förodling (0-6 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig men inte blöt. Kålfrön gror snabbt (5-10 dagar) vid rumstemperatur."},{phase:"Etablering (utplantering)",need:"Hög",tip:"Vattna rikligt vid utplantering och dagligen den första veckan. Nyplanterade kålplantor är törstiga damer."},{phase:"Tillväxt och bladbildning",need:"Medel-Hög",tip:"Djupvattna 2-3 gånger i veckan. Nu bygger hon bladmassa och varje bladpar som bildas blir en del av det kommande huvudet."},{phase:"Huvudbildning och mognad",need:"Hög",tip:"Kritisk period! Håll jämn fukt - plötsligt regn efter torka kan få huvudena att spricka. Hellre lite och ofta än stora svall."}],mistakes:["Ojämn vattning - torka följt av storvattning gör att huvudena spricker. Klassiskt nybörjarmisstag.","Vattna ovanifrån sent på kvällen - fuktiga blad i mörkret bjuder in svampsjukdomar","Tro att kålen klarar sig själv bara för att hon ser tålig ut - speciellt under huvudbildningen behöver hon jämn fukt","Sluta vattna för tidigt på hösten - sena sorter behöver fukt ända till skörd"],tip:"Mulcha ordentligt med gräsklipp eller halm runt plantorna. Det håller jorden fuktig och sval, och minskar risken för de där ödesdigra torrperioderna som får huvudena att spricka."},soil:'Näringsrik, kalkrik lerjord med bra struktur. Vitkål är en storätare som vill ha djup, mullrik jord - tänk "den bästa platsen i trädgården".',soilTips:["Kalka på hösten om pH är under 6.5 - vitkål ÄLSKAR kalkrik jord och det är det bästa skyddet mot klumprotsjuka","Blanda in rikligt med brunnen kompost och gärna lite hönsgödsel innan plantering. Vitkål är hungrig som en tonåring.","Undvik packad jord - luckra djupt och blanda in sand om du har tung lera. Rötterna vill ner djupt."],timeline:{1:[{phase:"Förodla inomhus",months:"Feb-Mar",icon:"seedling"},{phase:"Plantera ut",months:"Apr-Maj",icon:"leaf"},{phase:"Gödsla",months:"Maj-Jun",icon:"water"},{phase:"Skörd tidiga sorter",months:"Jun-Jul",icon:"harvest"},{phase:"Skörd sena sorter",months:"Sep-Nov",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj-Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Skörd tidiga sorter",months:"Jul-Aug",icon:"harvest"},{phase:"Skörd sena sorter",months:"Okt-Nov",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Plantera ut",months:"Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Skörd tidiga sorter",months:"Aug-Sep",icon:"harvest"},{phase:"Skörd sena sorter",months:"Sep-Okt",icon:"harvest"}]},nutritionData:[{month:"Mar",N:20,P:10,K:10,label:"Förodling"},{month:"Apr",N:30,P:15,K:10,label:"Tillväxtstart"},{month:"Maj",N:60,P:25,K:20,label:"Utplantering"},{month:"Jun",N:85,P:35,K:30,label:"Kraftig bladtillväxt"},{month:"Jul",N:90,P:40,K:45,label:"Huvudbildning"},{month:"Aug",N:70,P:35,K:50,label:"Mognad"},{month:"Sep",N:40,P:25,K:40,label:"Sena sorter mognar"},{month:"Okt",N:15,P:15,K:25,label:"Lagringskål skördas"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla med brunnen kompost och hornmjöl. Vitkål behöver en kväverik start för att bygga de stora ytterbladen som ska bli huvudet."},{timing:"Tre veckor efter utplantering",tip:"Ge flytande nässelvatten eller alggödsel. Hon ska vara i full gång nu och behöver ordentligt med bränsle."},{timing:"Vid huvudbildning",tip:"Extra giva med kaliumrik gödsel (vedaska eller alggödsel). Kalium hjälper huvudet att bli tätt och förbättrar lagringsegenskaperna."},{timing:"Sensommar (sena sorter)",tip:"En sista lätt giva med kalium stärker cellväggarna och gör kålen mer motståndskraftig mot frost och lagras bättre."}],companions:{good:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft förvirrar kålfjärilen - den hittar inte kålen bland all lökdoft. Ett beprövat försvar."},{id:"dill",name:"Dill",icon:"herb",why:"Lockar parasitsteklar som äter kålfjärilens larver. Dillen jobbar som kålens personliga livvakt."},{id:"selleri",name:"Selleri",icon:"vegetable",why:"Sellerins starka doft maskerar kålen för skadedjur. De trivs bra ihop i samma bädd."},{id:"rodbeta",name:"Rödbeta",icon:"vegetable",why:"Tar näring från ett annat djup i jorden - de konkurrerar inte utan kompletterar varandra fint."}],bad:[{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Jordgubbar hämmas av kålväxter. De trivs verkligen inte ihop - håll dem åtskilda."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Båda är storätare som slåss om samma näring. Ingen av dem blir nöjd."},{name:"Andra kålväxter",icon:"vegetable",why:"Odla inte vitkål bredvid annan kål - de delar skadedjur och sjukdomar och förstärker problemen."}]},rotation:{avoid:[{id:"gronkal",name:"Grönkål"},{id:"blomkal",name:"Blomkål"},{id:"broccoli",name:"Broccoli"},{id:"rodkal",name:"Rödkål"},{id:"brysselkal",name:"Brysselkål"},{id:"kalrabbi",name:"Kålrabbi"},{id:"radisa",name:"Rädisa"},{id:"pak-choi",name:"Pak choi"}],avoidWhy:"Alla tillhör korsblommiga och delar sjukdomar som klumprotsjuka. Vänta minst 4 år - helst 6-7 år - innan du odlar kål på samma plats igen. Klumprotsjuka lever kvar i jorden extremt länge.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"potatis",name:"Potatis"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden - gratis gödsel för hungriga vitkål! Potatis och lök lämnar ren, väl bearbetad jord.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"sallat",name:"Sallat"},{id:"rodbeta",name:"Rödbeta"}],goodAfterWhy:"Rotgrönsaker trivs i den djupt bearbetade, näringsrika restjorden efter kål. Sallat gillar kvävet som kålen lämnar efter sig."},varieties:[{name:"Golden Acre",zones:[1,2,3,4,5,6],note:"Klassisk tidig kulturarvssort med fasta, runda huvuden runt 1.5-2 kg. Snabb och pålitlig - perfekt som sommarkål. Ekofrö hos Runåbergs."},{name:"Donator",zones:[1,2,3,4,5],note:"Svenskodlad höstkål, 2-4 kg. Utmärkt för surkål och kortare lagring. Finns hos NordFrö - odlad i Tidaholm!"},{name:"Brunswijker",zones:[1,2,3,4,5],note:"Kulturarvssort från 1847! Stor, plattund lagringskål. Utvecklas fint i nordiskt klimat. Finns hos Impecta."},{name:"Premiere",zones:[1,2,3,4,5,6,7],note:"Mycket tidig sommarkål med väl samlade huvuden på 1-2 kg. Bra val för korta säsonger. Ekofrö hos Runåbergs."},{name:"Dottenfelder Dauer",zones:[1,2,3,4],note:"Sen lagringskål som håller hela vintern. Holländsk sort som trivs bäst i södra och mellersta Sverige. Ekofrö hos Runåbergs."}],problems:[{name:"Kålfjäril",symptom:"Gröna larver som tuggar stora hål i bladen. Lämnar gröna spillningshögar och kan förstöra hela plantor på kort tid.",fix:"Fiberduk från dag ett - det enda helt säkra skyddet! Handplocka larver regelbundet. Spruta med Bacillus thuringiensis (Bt) mot larverna. Samodla med dill och lök för att förvirra fjärilarna. Pudra med stenmjöl på fuktiga blad."},{name:"Kålfluga",symptom:"Plantan vissnar trots vattning. Dra upp en och titta - rötterna är fulla av vita larver som äter sig igenom rotsystemet.",fix:"Kålkragar runt stjälken vid utplantering - hindrar flugan från att lägga ägg vid stambasen. Fiberduk hjälper också. Kraftiga plantor med bra rotsystem klarar lättare angrepp."},{name:"Klumprotsjuka",symptom:"Plantan stannar i tillväxt och vissnar i värme. Rötterna har fula, klumpiga svullnader. Det här är kålodlarens mardröm.",fix:"Ingen bot - dra upp och bränn angripna plantor! Kalka jorden ordentligt (pH over 7). Odla inte kål på samma plats på minst 6-7 år. Svampen överlever i jorden extremt länge."},{name:"Spruckna huvuden",symptom:"Huvudet spricker mitt i mognadsfasen. Ibland hör man det nästan knäppa till.",fix:"Nästan alltid orsakat av ojämn vattning - torka följt av riklig bevattning eller kraftigt regn. Mulcha och håll jämn fukt. Vrid plantan ett kvarts varv för att bryta några rötter - det bromsar tillväxten om du inte hinner skörda."},{name:"Kålmal och jordloppor",symptom:"Kålmalen gör små hål i bladen, jordloppor gnager runda hål i unga plantor. Värst i varmt, torrt väder.",fix:"Fiberduk är bästa skyddet. Håll jorden fuktig - jordloppor avskyr fukt. Pudra med stenmjöl eller vedaska. Starka, välgödda plantor klarar angrepp bättre."}],goodToKnow:[{icon:"warning",title:"Kalka - klumprotsjukans fiende",text:"Det absolut viktigaste du kan göra för kål är att kalka jorden. Klumprotsjuka trivs i sur jord och finns den väl i marken stannar den i 7+ år. Kalka på hösten, sikta på pH runt 7.",severity:"warning"},{icon:"harvest",title:"Tidiga vs sena sorter - två helt olika grödor",text:"Spetskål och tidiga sorter ger sommarkål på 60-70 dagar. Sena lagringssorter tar 120-150 dagar men håller hela vintern i en sval källare. Planera för båda!",severity:"tip"},{icon:"warning",title:"Fiberduk HELA säsongen",text:"Kålfjärilen flyger från maj till september. Lägg fiberduk vid utplantering och ta inte bort den förrän du skördar. Det är irriterande, men det funkar.",severity:"warning"},{icon:"leaf",title:"Surkål - gammal svensk tradition",text:"Vitkål var en av de viktigaste vintergrönsakerna i Sverige före kylskåpets tid. Surkål (fermenterad vitkål) är enkelt att göra, fullt av nyttiga bakterier och håller hela vintern.",severity:"tip"},{icon:"seedling",title:"Frost gör henne godare",text:"Vitkål tål frost ner till -7°C och sena sorter kan stå kvar långt in på hösten. Lätt frost gör faktiskt att sockret i bladen ökar - vinterns första frostknäpp förvandlar kålen.",severity:"tip"},{icon:"warning",title:"Vrid plantan om huvudet spricker",text:"Om huvudet är färdigt men du inte kan skörda direkt - vrid plantan ett kvarts varv i marken. Det bryter några rötter och bromsar tillväxten. Ett gammalt odlartrick som räddar många kålhuvuden.",severity:"tip"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Vitkål förodlas nästan alltid inomhus för att få tillräckligt lång säsong, särskilt de sena lagringssorterna. Tidiga sorter kan direktsås i zon 1-3 men förodling ger bättre kontroll och tidigare skörd.",steps:["Så 1-2 cm djupt i krukor eller celler, 5-6 veckor före planerad utplantering","Håll jorden runt 18-20°C för snabb groning (5-10 dagar)","Flytta till svalare plats (12-15°C) och starkt ljus så snart plantorna är uppe - det ger kompakta, starka plantor","Gallra till en planta per cell om du sått flera frön","Härda av plantorna 7-10 dagar innan utplantering - ställ ut dagtid, in på natten","Plantera ut med 40-60 cm avstånd när plantan har 4-6 riktiga blad (sena sorter behöver mer plats)","Tryck till jorden ordentligt runt stammen, vattna rikligt och sätt kålkragar + fiberduk direkt"],tips:["Sena lagringssorter behöver förodlas redan i mars-april för att hinna mogna innan vintern","Tidiga sorter (spetskål) kan förodlas lite senare och ger snabb skörd redan efter 60-70 dagar","Kålkragar runt stjälken vid utplantering skyddar mot kålfluga - gör dem av kartong, filt eller köp färdiga"],indoorWeeks:"5-6 veckor"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Vitkål är tvåårig - hon sätter frö först andra året. Huvudet måste övervintras och planteras ut igen på våren. En utmaning, men för den som vill bevara gamla sorter är det guld värt.",steps:["Välj det finaste, friskaste huvudet och skörda det med roten kvar","Förvara hela plantan svalt (0-5°C) över vintern - källare eller jordkällare fungerar","Plantera ut igen på våren med intakt rot och huvudstump","Huvudet spricker upp och en blomstjälk växer upp ur mitten","Gula blommor pollineras av insekter - se till att bara EN sort av Brassica oleracea blommar","Låt fröskidorna mogna och torka på plantan tills de är bruna och spröda","Klipp av blomstjälkarna och eftertorka i papperspåse","Krossa skidorna försiktigt och blås bort agnarna. Förvara svalt och torrt."],isolation:"Korsar med ALLA andra Brassica oleracea (grönkål, broccoli, blomkål, brysselkål, kålrabbi). Odla bara en sort för frö, eller isolera med minst 1 km.",storageYears:"4-5 år",tip:"Frötagning av vitkål kräver att du kan förvara en hel kålplanta över vintern - det är inte för alla! Men för gamla kulturarvssorter som Brunswijker är det värt besväret. OP-sorter ger äkta avkomma, F1-hybrider gör det inte."},storage:{shelfLife:"1-2 veckor (färsk), 3-6 månader (källare), 12 månader (surkål/fryst)",methods:[{method:"Källarlagring",icon:"storage",duration:"3-6 månader",description:"Sena lagringssorter hängs upp och ner i en sval källare (0-4°C) med roten kvar. Hög luftfuktighet (90-95%) är nyckeln. Gammalt svenskt lagringsknep som funkar lika bra idag.",best:!0},{method:"Kylskåp",icon:"snowflake",duration:"1-3 veckor",description:"Lägg i plastpåse med några hål i grönsakslådan. Hela huvuden håller mycket längre än delad kål. Skuren kål torkar ut snabbt - täck snittytan med plastfolie.",best:!1},{method:"Surkål (fermentering)",icon:"storage",duration:"6-12 månader",description:"Strimla kålen fint, blanda med 2% salt och packa hårt i burk. Gammal svensk tradition som ger en hälsosam och smakrik konserveringsmetod. Fullt av nyttiga bakterier!",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Strimla, blanchera 1-2 minuter, kyl i isvatten och frys i portionspåsar. Perfekt för soppor, grytor och wok. Texturen ändras men smaken består.",best:!1},{method:"Torka",icon:"storage",duration:"6-12 månader",description:"Strimla tunt och torka i ugn på 50°C eller i torkmaskin. Kompakt och platssnålt. Bra i soppor och grytor under vintern.",best:!1}],tips:["Lagringssorter (Dottenfelder Dauer, Brunswijker) håller MYCKET längre än sommarkål - välj rätt sort om du vill lagra","Skörda lagringskål så sent som möjligt på hösten - gärna efter en lätt frost. Det förbättrar hållbarheten.","Häng kålhuvudena upp och ner i källaren med roten kvar - det förlänger lagringstiden rejält","Gör surkål! Det är enklare än du tror och resultatet är fantastiskt. Allt du behöver är kål, salt och en burk.","Kontrollera lagrad kål regelbundet och ta bort blad som börjar bli sladdriga - resten av huvudet är ofta helt fint under"]},harvestCalc:{minPerSqm:3,maxPerSqm:8,unit:"kg"}},le=Object.freeze(Object.defineProperty({__proto__:null,vitkal:Mr},Symbol.toStringTag,{value:"Module"})),Fr={name:"Vitlök",icon:"vitlok",family:"Lökväxter",familyLatin:"Amaryllidaceae",difficulty:"Medel",difficultyWhy:"Inte svårt att få upp - men tajmingen, torkningen och lagringen kräver lite erfarenhet. Höstplantering ger bäst resultat, och det kräver framförhållning.",zones:{outdoor:[1,2,3,4,5,6,7],indoor:null,greenhouse:[1,2,3,4,5,6,7,8]},days:"240-300",spacing:"15 cm",rowSpacing:"30 cm",depth:"4-6 cm",ph:{min:6,max:7.5,ideal:7},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Vitlöken vill ha minst 6 timmars direkt sol om dagen. I skugga blir klyvorna små och plantan lägger all energi på bladen istället. Full sol ger stora, fasta lökar med bra smak."},temperature:{min:-20,max:30,ideal:"10-20°C",detail:"Tålig dam som klarar rejäl kyla - hon BEHÖVER faktiskt en köldperiod (vernalisering) för att bilda klyftor. Därför ger höstplantering bäst resultat. Trivs i svalt väder under tillväxten och vill ha värme när lökarna mognar."},wind:{level:"Tålig",detail:"Vitlöken har låg profil och pallar vind utan problem. Inga stöd eller vindskydd behövs."}},watering:{need:"Låg-Medel",icon:"water",summary:"Vitlöken vill ha jämn fukt under våren och försommaren men HATAR blöta fötter. När bladspetsarna börjar gulna i juli - sluta vattna. Då ska hon torka och mogna ifred.",phases:[{phase:"Etablering (höst)",need:"Låg",tip:"Vattna lätt vid plantering om jorden är torr. Höstregnet sköter resten. Rötterna ska hinna etablera sig innan vintern."},{phase:"Tidig tillväxt (vår)",need:"Medel",tip:"Jämn fukt när tillväxten sätter igång. Vattna ordentligt en gång i veckan om våren är torr - men aldrig så att det står vatten."},{phase:"Lökbildning (juni)",need:"Medel",tip:"Nu bygger hon sina klyftor och behöver fukt. Men övervattna inte - dålig dränering ger röta och dålig lagring."},{phase:"Mognad (juli)",need:"Ingen",tip:"SLUTA vattna helt 2-3 veckor före skörd. Bladspetsarna gulnar? Perfekt - då är hon på väg att mogna. Vatten nu förstör lagringen."}],mistakes:["Vattna under mognadsperioden - lökarna ruttnar eller lagras dåligt","Plantera i vattensjuk jord - vitlökens rötter ruttnar snabbt i stående vatten","Övervattna på hösten - rötterna ska etablera sig, inte drunkna","Glömma att vattna under torra vårmånader - klyvorna blir små och torra"],tip:"Mulcha med halm eller löv! Det håller fukten jämn, minskar ogräs och skyddar mot frost på vintern. Tre flugor i en smäll."},soil:"Väldränderad, mullrik jord med bra struktur. Vitlöken vill ha det luftigt kring rötterna - lerjord funkar om du blandar i sand och kompost, men helst en lös, lucker jord.",soilTips:["Blanda in rikligt med kompost - vitlöken vill ha näringsrik jord","Luckra till minst 25 cm djup - hon behöver plats för rötterna","I tung lerjord: gör upphöjda bäddar med inblandad sand för bättre dränering","Strö lite trädgårdskalk om pH är under 6 - vitlöken gillar lätt kalkrik jord"],timeline:{1:[{phase:"Plantera (höst)",months:"Sep-Okt",icon:"seedling"},{phase:"Övervintring",months:"Nov-Apr",icon:"snowflake"},{phase:"Tillväxt",months:"Maj-Jun",icon:"leaf"},{phase:"Klipp vitlökspipar",months:"Jun-Jul",icon:"scissors"},{phase:"Mognad",months:"Jul",icon:"sun"},{phase:"Skörd och torkning",months:"Jul-Aug",icon:"harvest"}],4:[{phase:"Plantera (höst)",months:"Okt",icon:"seedling"},{phase:"Övervintring",months:"Nov-Mar",icon:"snowflake"},{phase:"Tillväxt",months:"Apr-Jun",icon:"leaf"},{phase:"Klipp vitlökspipar",months:"Jun-Jul",icon:"scissors"},{phase:"Mognad",months:"Jul",icon:"sun"},{phase:"Skörd och torkning",months:"Jul-Aug",icon:"harvest"}],6:[{phase:"Plantera (höst)",months:"Okt-Nov",icon:"seedling"},{phase:"Övervintring",months:"Okt-Apr",icon:"snowflake"},{phase:"Tillväxt",months:"Maj-Jun",icon:"leaf"},{phase:"Klipp vitlökspipar",months:"Jul",icon:"scissors"},{phase:"Mognad",months:"Jul-Aug",icon:"sun"},{phase:"Skörd och torkning",months:"Aug",icon:"harvest"}]},nutritionData:[{month:"Apr",N:40,P:20,K:15,label:"Vårstart"},{month:"Maj",N:65,P:30,K:25,label:"Tillväxt"},{month:"Jun",N:50,P:45,K:45,label:"Lökbildning"},{month:"Jul",N:15,P:35,K:70,label:"Mognad"},{month:"Aug",N:5,P:15,K:40,label:"Skörd"}],nutritionTips:[{timing:"Vid plantering (höst)",tip:"Grundgödsla med välbrunnen kompost. Blanda in lite benmjöl i planteringshålet - det ger fosfor för stark rotutveckling under hösten."},{timing:"Vårstart",tip:"Ge en rejäl giva kvävegödsel (hönsgödsel eller brännässelvatten) när tillväxten sätter igång. Nu ska hon bygga blast."},{timing:"Lökbildning",tip:"Byt till kaliumrik gödsel (vedaska fungerar perfekt). Kalium hjälper lökarna att bli fasta och lagra bra. Sluta med kväve."},{timing:"Mognad",tip:"Ingen gödsling alls. Låt vitlöken mogna ifred - gödsling nu förlänger tillväxten och försenar skörden."}],companions:{good:[{id:"morot",name:"Morot",icon:"vegetable",why:"Vitlökens starka doft håller morotsflugan borta. Ett av trädgårdens klassiska skyddspar."},{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Vitlökens svamphämmande ämnen skyddar jordgubbarna mot gråmögel och jordgubbsmjöldagg"},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Vitlöken avskräcker bladlöss och kvalster som annars gillar att sitta på tomaterna"},{id:"rodbeta",name:"Rödbeta",icon:"vegetable",why:"Bra markutnyttjande - rödbetans djupa rot och vitlökens grunda rot konkurrerar inte"}],bad:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Vitlöken hämmar ärtornas tillväxt och kvävefixering - de pratar helt enkelt olika språk"},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Samma problem som ärtor - alla baljväxter och lökväxter trivs dåligt ihop"}]},rotation:{avoid:[{id:"lok",name:"Lök"},{id:"purjolok",name:"Purjolök"},{id:"schalottenlok",name:"Schalottenlök"},{id:"graslok",name:"Gräslök"}],avoidWhy:"Alla tillhör lökväxter (Amaryllidaceae) och delar sjukdomar som vitröta, lökröta och lökfluga. Vänta minst 4 år - helst 5 - innan du odlar vitlök på samma plats.",goodBefore:[{name:"Kål"},{id:"squash",name:"Squash"},{id:"potatis",name:"Potatis"}],goodBeforeWhy:"Näringshungriga grödor drar nytta av den kompost du gödslat vitlöken med, och marken är ren från lökväxternas typiska sjukdomar.",goodAfter:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodAfterWhy:"Baljväxter fixerar kväve i jorden och bygger upp näringen. Perfekta efterföljare som förbereder marken för nästa omgång."},varieties:[{name:"Thermidrome",zones:[1,2,3,4,5,6],note:"Pålitlig softneck-sort (OP) med stor, fast lök. Mild smak som mjuknar vid tillagning. Flätar fint och lagrar länge."},{name:"Sprint",zones:[1,2,3,4,5,6],note:"Tidig hardneck (OP) som mognar snabbt. Bildar vitlökspipar och topplök. Stark, komplex smak."},{name:"Ivan",zones:[1,2,3,4,5,6,7],note:"Rysk hardneck (OP) som klarar brutal kyla. Perfekt för norra Sverige. Stor lök med kraftig smak."},{name:"Messidrome",zones:[1,2,3,4,5,6],note:"Tidig softneck (OP) med elegant, mild smak. Mognar bland de första och lagrar bra. Flätar fint."},{name:"Flavor",zones:[1,2,3,4,5,6],note:"Softneck (OP) med mild, söt smak och massor av klyftor. Lagrar extremt länge - upp till 10 månader."}],problems:[{name:"Vitröta (Sclerotium cepivorum)",symptom:"Gula, vissnande blad. Vit, luddig svamp vid lökens bas. Lökarna ruttnar underifrån.",fix:"Tyvärr ingen bot - svampens vilosporer lever i jorden i 20+ år. Växtföljd är enda skyddet. Ta bort angripna plantor direkt och odla ALDRIG lökväxter på samma plats igen."},{name:"Lökfluga",symptom:"Slappa, gula blad. Små larver i lökens bas som äter sig inåt.",fix:"Täck med fiberduk under maj-juni när flugan lägger ägg. Strö kalkstensmjöl eller aska runt plantorna. Samodla med morot."},{name:"Rost",symptom:"Orangea, pudriga fläckar på bladen. Bladen gulnar och vissnar i förtid.",fix:"Bra ventilation mellan plantorna - plantera inte för tätt. Ta bort angripna blad. God växtföljd minskar risken avsevärt."},{name:"Gröna klyftor (ingen lökbildning)",symptom:"Plantan växer fint men bildar bara en enda rund lök utan klyftor.",fix:"Beror nästan alltid på att vitlöken inte fått tillräcklig köldperiod (vernalisering). Höstplantera istället för vårplantering, eller välj en sort som klarar kortare kyla."}],goodToKnow:[{icon:"snowflake",title:"Höstplantering ger BÄST resultat",text:"Vitlök behöver en köldperiod (vernalisering) för att bilda klyftor. Plantera i oktober - hon etablerar rötter på hösten, vilar under vintern och exploderar i tillväxt på våren. Resultatet blir dubbelt så stora lökar jämfört med vårplantering.",severity:"tip"},{icon:"scissors",title:"Klipp vitlökspiparna!",text:"Hardneck-vitlök skickar upp lockiga blomstjälkar (scapes) i juni. Klipp av dem! Annars lägger plantan energi på blommor istället för löken. Bonus: vitlökspipar är en delikatess att steka eller göra pesto av.",severity:"tip"},{icon:"warning",title:"Köp aldrig matbutikens vitlök för odling",text:"Vitlök från matbutiken är ofta importerad (Kina/Spanien) och behandlad mot groning. Den är inte anpassad för svenska vintrar och kan bära sjukdomar. Köp alltid certifierad utsädeslök från svensk fröhandel.",severity:"warning"},{icon:"leaf",title:"Hardneck vs softneck",text:"Hardneck (styvstilade) ger stora klyftor, stark smak och vitlökspipar men lagras kortare (4-6 mån). Softneck (mjukstilade) ger fler klyftor, mildare smak och lagras längre (8-10 mån). I Sverige funkar hardneck bäst i de flesta zoner.",severity:"tip"},{icon:"warning",title:"Vitröta - den osynliga fienden",text:"Vitröta (Sclerotium) är vitlöksodlarens värsta mardröm. Svampens vilosporer överlever 20+ år i jorden. Finns den väl där är platsen körd för alla lökväxter - för alltid. Därför: köp alltid frisk utsädeslök och praktisera sträng växtföljd.",severity:"warning"},{icon:"harvest",title:"Skörd: räkna bladen",text:"Varje grönt blad motsvarar ett skyddande lager runt löken. Skörda när halva bladen gulnat (ca 5-6 gröna blad kvar). Väntar du för länge spricker skalen och lagringen förstörs. För tidigt ger små lökar.",severity:"tip"}],sowing:{method:"direct",label:"Direktplantering",description:"Vitlök odlas genom att plantera enskilda klyftor direkt i jorden. Höstplantering (oktober) rekommenderas starkt - det ger vitlöken den köldperiod hon behöver för att bilda ordentliga klyftor.",steps:["Dela försiktigt lökknölen i enskilda klyftor - skada inte basen","Välj de största, friskaste klyvorna (de yttre). Små klyftor ger små lökar","Plantera med spetsen uppåt, 4-6 cm djupt (dubbla klyvans höjd)","Avstånd 15 cm i raden, 30 cm mellan raderna","Täck med jord och mulcha med 5-10 cm halm eller löv","Vattna lätt om jorden är torr - höstregnet sköter vanligtvis resten","Vårplantering: Möjligt men kräver att klyvorna kylts i kylskåp (4°C) i 6-8 veckor innan plantering"],tips:["Köp utsädeslök i september - de bästa sorterna tar slut snabbt","Plantera 4-6 veckor före första frost så rötterna hinner etablera sig","Mulcha generöst - det skyddar mot frost OCH håller ogräs borta på våren","Spara alltid dina bästa lökar som utsäde till nästa säsong"],indoorWeeks:null},seedSaving:{difficulty:"Medel",type:"Vegetativ förökning",biennial:!1,description:"Vitlök förökas vegetativt genom att spara klyftor från skörden. Hardneck-sorter bildar även bulbiller (småklyftor) i blomställningen som kan planteras, men de tar 2 år att bli fullstora lökar.",steps:["Välj dina finaste, största och friskaste lökar vid skörd","Torka dem precis som matlök - minst 3 veckor på en luftig plats","Lagra svalt och torrt fram till planteringsdags i oktober","Dela i klyftor precis före plantering - inte innan","Hardneck-bulbiller: Låt blomställningen mogna, skörda småklyvorna","Plantera bulbillerna tätt (5 cm avstånd) - de ger lökrundlar första året","Andra året: Plantera om rundlarna med normalt avstånd - nu bildar de klyftor"],isolation:"Inte aktuellt vid vegetativ förökning - varje klyva är en genetisk kopia av moderplantan.",storageYears:"1 säsong",tip:"Spara alltid de allra bästa lökarna som utsäde, inte de sämsta. Genom att välja ut de största och friskaste varje år förbättrar du sakta din stam - husdjursavel för vitlök!"},storage:{shelfLife:"4-10 månader",methods:[{method:"Hängande i nätpåse eller fläta",icon:"storage",duration:"6-10 månader",description:"Fläta ihop softneck-vitlöken eller häng hardneck i nätpåsar. Svalt (10-15°C), torrt och mörkt. Den klassiska metoden som fungerar fantastiskt.",best:!0},{method:"Svalt förråd",icon:"storage",duration:"4-8 månader",description:"Lägg lökarna i korgar eller lådor med god ventilation. Temperatur 10-15°C och låg luftfuktighet. Kolla regelbundet efter mjuka eller mögliga lökar.",best:!1},{method:"Frysa (hackad)",icon:"snowflake",duration:"8-12 månader",description:"Hacka eller pressa vitlöken och frys in i portionsformar. Perfekt för matlagning - ta en kub direkt i grytan. Smaken bevaras bra.",best:!1},{method:"I olja",icon:"storage",duration:"2-3 veckor (kylskåp)",description:"Pressa eller hacka vitlök och lägg i olivolja. Förvara ALLTID i kylskåp och använd inom 2-3 veckor. Varning: vitlök i olja i rumstemperatur kan ge botulism.",best:!1},{method:"Torka",icon:"sun",duration:"12+ månader",description:"Skiva tunt och torka i ugn på 55°C eller i torkautomat. Mixa till vitlökspulver - hemmagjort vitlökspulver slår allt du kan köpa i butiken.",best:!1}],tips:["Torka ALLTID vitlöken ordentligt (3-4 veckor) efter skörd innan lagring - det är hela hemligheten","Förvara INTE vitlök i kylskåp - kylan och fukten triggar groning","Softneck lagras längre (8-10 mån) än hardneck (4-6 mån) - planera därefter","Vitlök i olja vid rumstemperatur = botulismrisk. Alltid kylskåp och max 2-3 veckor","Om löken börjar gro: använd den - de gröna skotten är ätbara och milda i smaken"]},harvestCalc:{minPerSqm:.5,maxPerSqm:1.5,unit:"kg"}},se=Object.freeze(Object.defineProperty({__proto__:null,vitlok:Fr},Symbol.toStringTag,{value:"Module"}));export{oa as $,Ha as A,Aa as B,La as C,Va as D,Fa as E,Ma as F,wa as G,Ta as H,Ba as I,Pa as J,Ka as K,xa as L,Sa as M,ya as N,ja as O,fa as P,ba as Q,ca as R,ha as S,va as T,ua as U,pa as V,ga as W,ka as X,ma as Y,da as Z,se as _,le as a,sa as a0,la as a1,ia as a2,na as a3,ta as a4,ea as a5,aa as a6,ra as a7,$r as a8,Qr as a9,Xr as aa,Zr as ab,Yr as ac,qr as ad,Ur as ae,Wr as af,Ir as ag,_r as ah,zr as ai,Or as aj,Cr as ak,Er as al,Rr as am,Jr as an,Nr as ao,Dr as ap,Gr as aq,Hr as ar,Ar as as,Lr as at,Vr as au,ie as b,ne as c,te as d,ee as e,ae as f,re as g,$a as h,Qa as i,Xa as j,Za as k,Ya as l,qa as m,Ua as n,Wa as o,Ia as p,_a as q,za as r,Oa as s,Ca as t,Ea as u,Ra as v,Ja as w,Na as x,Da as y,Ga as z};
